INSERT INTO `iyque_knowledge_info` (`id`, `createTime`, `delFlag`, `description`, `kname`) VALUES (2073692323514028032,'2026-07-05 16:55:51.919000',0,'查理·芒格《穷查理宝典》—— 普世智慧、多元思维模型、投资与人生哲学','穷查理宝典'),(2073692527810187264,'2026-07-05 16:56:40.630000',0,'菲利普·费雪《怎样选择成长股》—— 15 要点、闲聊法、长期持有的成长股投资经典','怎样选择成长股');
INSERT INTO `iyque_knowledge_attach` (`id`, `createTime`, `delFlag`, `docName`, `docType`, `kid`) VALUES (2073692323954429952,'2026-07-05 16:55:52.025000',0,'穷查理宝典.pdf','pdf',2073692323514028032),(2073692528221229056,'2026-07-05 16:56:40.728000',0,'怎样选择成长股.pdf','pdf',2073692527810187264);
INSERT INTO `iyque_knowledge_fragment` (`id`, `content`, `createTime`, `delFlag`, `docId`, `idx`, `kid`) VALUES (2073692328249397248,'穷查理宝典 \n \n目录 \n中文版序言 Louis Li \n鸣谢 \n序言 巴菲特论芒格 沃伦•巴菲特 \n驳辞 芒格论巴菲特 查理•芒格 \n导读 彼得•考夫曼 \n \n第一章  \n查理•芒格传略 \n歌颂长者：芒格论晚年 \n忆念：晚辈谈芒格 \n \n第二章 \n芒格的生活、学习和决策方法 \n \n第三章 \n芒格主义：查理的即席谈话 \n（2001年至2006年在伯克希尔•哈撒韦公司 \n和西科金融公司年会上的谈话摘录） \n \n第四章 查理十一讲 \n第一讲 在哈佛学校毕业典礼上的演讲 \n第二讲 论基本的、普世的智慧 \n第三讲 论基本的、普世的智慧（修正稿） \n第四讲 关于现实思维的现实思考？ \n第五讲 专业人士需要更多的跨学科技能 \n第六讲 一流慈善基金的投资实践 \n第七讲 在慈善圆桌会议早餐会上的讲话 \n第八讲 2003年的金融大丑闻 \n第九讲 论学院派经济学 ','2026-07-05 16:55:53.049000',0,2073692323954429952,0,2073692323514028032),(2073692328253591552,'第六讲 一流慈善基金的投资实践 \n第七讲 在慈善圆桌会议早餐会上的讲话 \n第八讲 2003年的金融大丑闻 \n第九讲 论学院派经济学 \n第十讲 在南加州大学GOULD法学院毕业典礼上的演讲 \n第十一讲 人类误判心理学 \n \n \n查理•芒格的推荐书目 \n文章、报道与评论 \n索引 \n查理•芒格年谱 \n \n附：1现金流量贴现法 \n 2 巴菲特教你读财报\n \n中文版序：书中自有黄金屋 \n \nLouis Li 李路 作者系比亚迪大股东 \n \n        20 多年前，作为一名年轻的学生只身来到美国，我怎么也没\n有想到后来竟然从事了投资行业，更没有想到由于种种机缘巧合有幸结识了当代\n投资大师查理•芒格先生。 2004 年，芒格先生成为我的投资合伙人，自此就成\n为我终生的良师益友。这样的机遇恐怕是过去做梦也不敢想的。 \n         像全世界成千上万的巴菲特/芒格崇拜者一样，两位老师的教','2026-07-05 16:55:53.049000',0,2073692323954429952,1,2073692323514028032),(2073692328253591553,'为我终生的良师益友。这样的机遇恐怕是过去做梦也不敢想的。 \n         像全世界成千上万的巴菲特/芒格崇拜者一样，两位老师的教\n导，伯克希尔•哈撒韦公司的神奇业绩，对我个人的投资事业起到了塑造式的影\n响。这些年受益于芒格恩师的近距离言传身教，又让我更为深刻地体会到他思想\n的博大精深。一直以来，我都希望将这些学习的心得与更多的同道分享。彼得•\n考夫曼的这本书是这方面最好的努力。彼得是查理多年的朋友，他本人又是极其\n优秀的企业家、“职业书虫”。由他编辑的《穷查理宝典》最为全面地囊括了查\n理的思想精华。彼得既是我的好友，又是我的投资合伙人，所以我一直都很关注\n这本书的整个出版过程。2005 年本书第一版问世时，我如获至宝，反复研读，\n每读一次都有新的收获。那时我就想把这本书认真地翻译介绍给中国的读者。不\n想这个愿望又过了五年才得以实现。2009 年，查理 85 岁。经一位朋友提醒，我','2026-07-05 16:55:53.049000',0,2073692323954429952,2,2073692323514028032),(2073692328253591554,'每读一次都有新的收获。那时我就想把这本书认真地翻译介绍给中国的读者。不\n想这个愿望又过了五年才得以实现。2009 年，查理 85 岁。经一位朋友提醒，我\n意识到把这本书翻译成中文应该是对恩师最好的报答，同时也完成了我多年来希\n望与同胞分享芒格智慧的心愿。  \n         现在这本书即将出版了，我也想在此奉献我个人学习、实践\n芒格思想与人格的心路历程、心得体会，以配合读者更好地领会本书所包含的智\n慧。 \n  第一次接触巴菲特／芒格的价值投资体系可以追溯到 20 年前。那时我刚到美\n国，举目无亲，文化不熟，语言不通。侥幸进入哥伦比亚大学就读本科，立刻便\n面临学费、生活费昂贵的问题。虽然有些奖学金也可以贷款，然而对一个身无分\n文的学生而言，那笔贷款是个天文数字，不知何时才能还清，对前途一片迷茫焦\n虑。相信很多来美国读书的中国学生，尤其是要靠借债和打工支付学费和生活费','2026-07-05 16:55:53.049000',0,2073692323954429952,3,2073692323514028032),(2073692328253591555,'文的学生而言，那笔贷款是个天文数字，不知何时才能还清，对前途一片迷茫焦\n虑。相信很多来美国读书的中国学生，尤其是要靠借债和打工支付学费和生活费\n的学生都有过这种经历。  \n        由于在上世纪七八十年代的中国长大，我那时对经商几乎没有概念。在那个\n年代，商业在中国还不是很要紧的事。一天，一位同学告诉我：“你要是想了解\n在美国怎么能赚钱，商学院有个演讲一定要去听。”那个演讲人的名字有点怪，\n叫巴菲特（Buffett），很像 “自助餐”（Buffet）的意思。我一听这个名字蛮有趣，\n就去了。那时巴菲特还不像今天这么出名，去的人不多，但那次演讲于我而言却\n是一次醍醐灌顶的经历。  \n        巴菲特讲的是如何在股市投资。在此之前，股市在我头脑里的印象还停留在\n曹禺的话剧《日出》里所描绘的 1930 年代上海的十里洋场，充满了狡诈、运气','2026-07-05 16:55:53.049000',0,2073692323954429952,4,2073692323514028032),(2073692328253591556,'        巴菲特讲的是如何在股市投资。在此之前，股市在我头脑里的印象还停留在\n曹禺的话剧《日出》里所描绘的 1930 年代上海的十里洋场，充满了狡诈、运气\n与血腥。然而这位据说在股市上赚了很多钱的成功的美国商人看上去却显然是一\n个好人，友善而聪明，颇有些学究气，同我想像中那些冷酷无情、投机钻营的商\n人完全不同。  \n        巴菲特的演讲措辞简洁、条理清晰、内容可信。一个多钟头的演讲把股票市\n场的道理说得清晰明了。巴菲特说，股票本质上是公司的部分所有权，股票的价\n格就是由股票的价值——也就是公司的价值所决定的。而公司的价值又是由公司\n的盈利情况及净资产决定的。虽然股票价格上上下下的波动在短期内很难预测，\n但长期而言一定是由公司的价值决定的。聪明的投资者只要在股票的价格远低于\n公司实际价值的时候买进，又在价格接近或者高于价值时卖出，就能够在风险很\n小的情况下赚很多钱。  ','2026-07-05 16:55:53.049000',0,2073692323954429952,5,2073692323514028032),(2073692328253591557,'公司实际价值的时候买进，又在价格接近或者高于价值时卖出，就能够在风险很\n小的情况下赚很多钱。  \n        听完这番演讲，我觉得好像捞到了一根救命稻草。难道一个聪明、正直、博\n学的人，不需要家庭的支持，也不需要精熟公司管理，或者发明、创造新产品，\n创立新公司，在美国就可以白手起家地成功致富吗？我眼前就有这么一位活生生\n的榜样！那时我自认为不适合做管理，因为对美国的社会和文化不了解，创业也\n没有把握。但是如果说去研究公司的价值，去研究一些比较复杂的商业数据、财\n务报告，那却是我的专长。果真如此的话，像我这样一个不名一文、举目无亲、\n毫无社会根基和经验的外国人不也可以在股票投资领域有一番作为了吗？这实\n在太诱人了。  \n        听完演讲后，我回去立刻找来了有关巴菲特的所有图书，包括他致伯克希尔\n•哈撒韦公司股东的年信及各种关于他的研究，也了解到芒格先生是巴菲特先生','2026-07-05 16:55:53.049000',0,2073692323954429952,6,2073692323514028032),(2073692328253591558,'        听完演讲后，我回去立刻找来了有关巴菲特的所有图书，包括他致伯克希尔\n•哈撒韦公司股东的年信及各种关于他的研究，也了解到芒格先生是巴菲特先生\n几十年来形影不离的合伙人，然后整整花了一两年的时间来彻底地研究他们，所\n有的研究都印证了我当时听演讲时的印象。完成了这个调研后，我便真正自信这\n个行业是可为的。  \n        一两年后，我买了有生以来的第一支股票。那时虽然我个人的净资产仍然是\n负数，但积蓄了一些现金可以用来投资。当时正逢 1990 年代初，全球化的过程\n刚刚开始，美国各行业的公司都处于一个长期上升的状态，市场上有很多被低估\n的股票。到 1996 年从哥大毕业的时候，我已经从股市投资上获取了相当可观的\n回报。  \n        毕业后我一边在投资银行工作，一边继续在股票上投资。工作的第一年，我\n有幸全程参与了一间大公司的上市，并得到了一大笔奖金。可是我并不喜欢投行','2026-07-05 16:55:53.049000',0,2073692323954429952,7,2073692323514028032),(2073692328253591559,'        毕业后我一边在投资银行工作，一边继续在股票上投资。工作的第一年，我\n有幸全程参与了一间大公司的上市，并得到了一大笔奖金。可是我并不喜欢投行\n的工作，况且我发现在投行挣的工资和奖金加在一起还不如我业余在股市上赚的\n钱多，这时我才突然意识到，投资股市对我而言不仅是一根救命稻草、一个爱好，\n甚至可以成为一个终生的事业。一年后，我辞职离开投行，开始了职业投资生涯。\n当时家人和朋友都颇为不解和担心，我自己对前途也没有十分的把握。坦白说，\n创业的勇气同样来自于巴菲特和芒格的影响。  \n        1998 年 1 月，我创立了自己的公司，支持者寡，几个老朋友友情客串投资人\n凑了一小笔钱，我自己身兼数职，既是董事长、基金经理，又是 秘书、分析员。\n全部的家当就是一部手机和一台笔记本电脑。其时适逢 1997 年的亚洲金融危机，','2026-07-05 16:55:53.049000',0,2073692323954429952,8,2073692323514028032),(2073692328253591560,'凑了一小笔钱，我自己身兼数职，既是董事长、基金经理，又是 秘书、分析员。\n全部的家当就是一部手机和一台笔记本电脑。其时适逢 1997 年的亚洲金融危机，\n石油的价格跌破了每桶 10 美元。我于是开始大量地买进一些亚洲优秀企业的股\n票，同时也买入了大量美国及加拿大的石油公司股票。但随后的股票波动令我当\n年就损失了 19%的账面价值。这使得有些投资者开始担心以后的运作情况，不敢\n再投钱了。其中一个最大的投资者第二年就撤资了。 再加上昂贵的前期营运成\n本，公司一度面临生存的危机。  \n        出师不利让我倍受压力，觉得辜负了投资人的信任。 而这些心理负担又的\n确会影响到投资决策，比如在碰到好的机会时也不敢行动。而那时恰恰又是最好\n的投资时机。这时，巴菲特和芒格的理念和榜样对我起了很大的支持作用，在\n1973—1974 年的美国经济衰退中，他们两位都有过类似的经历。在我最失落的','2026-07-05 16:55:53.049000',0,2073692323954429952,9,2073692323514028032),(2073692328253591561,'的投资时机。这时，巴菲特和芒格的理念和榜样对我起了很大的支持作用，在\n1973—1974 年的美国经济衰退中，他们两位都有过类似的经历。在我最失落的\n时候，我就以巴菲特和芒格为榜样勉励自己，始终坚持凡事看长远。  \n        随后，在 1998 年的下半年里，我顶住压力、鼓起勇气，连续作出了当时我\n最重要的三四个投资决定。恰恰是这几个投资在以后的两年里给我和我的投资者\n带来了数倍的回报。现在回头来想，在时间上我是幸运的，但巴菲特和芒格的榜\n样作用以及他们的书籍和思想，对我的确起了至关重要的影响。  \n        但是出色的业绩并没有给我带来新的投资人。那个时候直到现在， 绝大多\n数个人投资者和机构投资者在投资理念上基本上遵从一些我认为是脑子坏掉的\n理论。比如他们相信市场完全有效理论，因而相信股价的波动就等同真实的风险，','2026-07-05 16:55:53.049000',0,2073692323954429952,10,2073692323514028032),(2073692328253591562,'数个人投资者和机构投资者在投资理念上基本上遵从一些我认为是脑子坏掉的\n理论。比如他们相信市场完全有效理论，因而相信股价的波动就等同真实的风险，\n判断你的表现最看重你业绩的波动性如何。我觉得同他们说话简直是对牛弹琴。\n在我看来，投资股市最大的风险其实并不是价格的上下起伏，而是你的投资未来\n会不会出现永久性的亏损。单纯的 股价下跌不仅不是风险，简直就是机会。不\n然哪里去找便宜的股票呢？就像如果你最喜欢的餐馆里牛排的价格下跌了一半，\n你会吃得更香才对。 买进下跌的股票时是卖家难受，作为买家你应该高兴才对。\n我跟他们解释我的投资原则就是遵循巴菲特和芒格他们的投资哲学。然而这时我\n才发现，虽然巴菲特和芒格很成功，但个人投资者和机构投资者的实际做法却与\n巴菲特/芒格的投资理念完全相反。表面上那些成名的基金经理接受巴菲特/芒格\n的理论，而且对他们表现出极大的尊重，但在实际操作上却根本是南辕北辙，因','2026-07-05 16:55:53.049000',0,2073692323954429952,11,2073692323514028032),(2073692328253591563,'巴菲特/芒格的投资理念完全相反。表面上那些成名的基金经理接受巴菲特/芒格\n的理论，而且对他们表现出极大的尊重，但在实际操作上却根本是南辕北辙，因\n为他们的客户也是南辕北辙的。他们接受的还是一套“波动性就是风险”、“市场\n总是对的”这样的理论。而这在我看来完全是奇谈怪论。  \n        但为了留住并吸引更多的投资者，我也不得不作了一段时间的妥协。有两三\n年的时间内，我也不得不通过做长短仓（Long-Short）对冲去管理旗下基金的波\n动性。和做多（Long）相比，做空交易（Short）就很难被用于长期投资。原因\n有三：第一，做空的利润上限只有 100%，但损失空间几乎是无穷的，这正好同\n做多相反。第二，做空要通过借债完成，所以 即使做空的决定完全正确，但如\n果时机不对，操作者也会面临损失，甚至破产。第三，最好的做空投资机会一般','2026-07-05 16:55:53.049000',0,2073692323954429952,12,2073692323514028032),(2073692328253591564,'做多相反。第二，做空要通过借债完成，所以 即使做空的决定完全正确，但如\n果时机不对，操作者也会面临损失，甚至破产。第三，最好的做空投资机会一般\n是各种各样的舞弊情况，但舞弊作假往往被掩盖得很好，需要很长时间才会败露。\n例如麦道夫的骗局持续几十年才被发现。基于这三点原因，做空需要随时关注市\n场的起落，不断交易。  \n        这样做了几年， 投资组合的波动性倒是小了许多，在 2001—2002 年由互联\n网泡沫引发的金融危机中我们并没有账面损失，并小有斩获，管理的基金也增加\n了许多。对冲基金行业里最具传奇性的两位前辈人物之一成为我的主要投资人，\n另外一位邀我共同成立一家亚洲投资基金。表面上看起来还挺风光， 但其实我\n内心很痛苦。如果同时去做空和做多，要控制做空的风险，就必须不停地交易。\n但若是不停地交易，就根本没有时间真正去研究一些长期的投资机会。这段时期','2026-07-05 16:55:53.049000',0,2073692323954429952,13,2073692323514028032),(2073692328257785856,'内心很痛苦。如果同时去做空和做多，要控制做空的风险，就必须不停地交易。\n但若是不停地交易，就根本没有时间真正去研究一些长期的投资机会。这段时期\n的回报从波动性上而言比过去好，结果却乏善可陈。实际上，那段时间出现了许\n多一流的投资机会。 坦白的说，我职业生涯中最大的失败并不是由我错误决定\n造成的损失（当然我的这类错误也绝不在少数）， 而是在这一段时间里不能够大\n量买进我喜欢的几支最优秀的股票，我为此少挣的钱到现在还在增加。  \n         这段时间是我职业生涯的一个低潮。我甚至一度萌生了退意，花了太多的\n时间在本不是自己主业的风险投资基金上。  \n        在前行道路的十字路口，一个偶然的契机，我遇到了终生的良师益友查理•\n芒格先生。  \n         初识查理是我大学刚毕业在洛杉矶投行工作的时候，在一位共同朋友的家','2026-07-05 16:55:53.049000',0,2073692323954429952,14,2073692323514028032),(2073692328257785857,'芒格先生。  \n         初识查理是我大学刚毕业在洛杉矶投行工作的时候，在一位共同朋友的家\n里第一次见到了查理。记得他给人的第一印象是拒人于千里之外，他对谈话者常\n常心不在焉，非常专注于自己的话题。但这位老先生说话言简意赅，话语中充满\n了让你回味无穷的智慧。 初次见面，查理对我而言是高不可及的前辈，他大概\n对我也没什么印象。  \n        之后陆续见过几次，有过一些交谈，直到我们认识的第七年，在 2003 年一\n个感恩节的聚会中，我们进行了一次长时间的推心置腹的交谈。我将我投资的所\n有公司，我研究过的公司以及引起我兴趣的公司一一介绍给查理，他则逐一点评。\n我也向他请教我遇到的烦恼。 谈到最后，他告诉我，我所遇到的问题几乎就是\n华尔街的全部问题。整个华尔街的思维方式都有问题，虽然伯克希尔已经取得了\n这么大的成功，但在华尔街上却找不到任何一家真正模仿它的公司。如果我继续','2026-07-05 16:55:53.049000',0,2073692323954429952,15,2073692323514028032),(2073692328257785858,'华尔街的全部问题。整个华尔街的思维方式都有问题，虽然伯克希尔已经取得了\n这么大的成功，但在华尔街上却找不到任何一家真正模仿它的公司。如果我继续\n这样走下去的话，我的那些烦恼永远也不会消除。但我如果愿意放弃现在的路子，\n想走出与华尔街不同的道路，他愿意给我投资。这真让我受宠若惊。  \n        在查理的帮助下，我把公司进行了彻底的改组。在结构上完全改变成早期巴\n菲特的合伙人公司和芒格的合伙人公司（注：巴菲特和芒格早期各自有一个合伙\n人公司来管理他们自己的投资组合）那样的结构，同时也除去了典型对冲基金的\n所有弊端。愿意留下的投资者作出了长期投资的保证，而我们也不再吸收新的投\n资人。新的基金也保留了原基金的部分投资组合，包括我们在比亚迪的投资。  \n        我于是进入到投资生涯的又一个黄金时期。我无须再受华尔街那些投资者各','2026-07-05 16:55:53.049000',0,2073692323954429952,16,2073692323514028032),(2073692328257785859,'资人。新的基金也保留了原基金的部分投资组合，包括我们在比亚迪的投资。  \n        我于是进入到投资生涯的又一个黄金时期。我无须再受华尔街那些投资者各\n式各样的限制，而完成机构改造之后的投资结果本身也证实了这一决定的正确\n性。虽然数字依然上上下下波动，但最终的结果却是大幅度的增长。新的基金从\n2004 年第四季度至 2009 年底，除去营运成本外，每年的复合回报率超过 36%。\n而自 1998 年 1 月原基金创建开始计算，每年的复合回报率则超过 29%。12 年间，\n回报增长超过 20 倍。  \n        撇开数字不谈，这些年的工作顺畅了许多。我无需纠缠于股市沉浮，无需不\n断交易，不断做空。相反，我可以把所有的时间都花在对公司的研究和了解上。\n我的投资经历已经清楚地证明：按照巴菲特/芒格的体系来投资必定会使各方受','2026-07-05 16:55:53.049000',0,2073692323954429952,17,2073692323514028032),(2073692328257785860,'断交易，不断做空。相反，我可以把所有的时间都花在对公司的研究和了解上。\n我的投资经历已经清楚地证明：按照巴菲特/芒格的体系来投资必定会使各方受\n益。但因为投资机构本身的限制，绝大部分的机构投资者不采用这种方式，因此，\n它给了那些用这种方式的投资者一个绝好的竞争优势。而这个优势在未来很长的\n一段时间内都不会消失。 \n二 \n \n        巴菲特说他一生遇人无数，从来没有遇到过像查理这样的人。\n在同查理交往的这些年里，我有幸能近距离了解查理，也对这一点深信不疑。甚\n至在我所阅读过的古今中外人物传记中也没有发现类似的人。查理就是如此独特\n的人，他的独特性既表现在他的思想上，也表现在他的人格上。  \n        比如说，查理思考问题总是从逆向开始。如果要明白人生如何\n才能得到幸福，查理首先会研究人生如何才能变得痛苦；要研究企业如何做强做','2026-07-05 16:55:53.049000',0,2073692323954429952,18,2073692323514028032),(2073692328257785861,'        比如说，查理思考问题总是从逆向开始。如果要明白人生如何\n才能得到幸福，查理首先会研究人生如何才能变得痛苦；要研究企业如何做强做\n大，查理首先研究企业是如何衰败的；大部分人更关心如何在股市投资上成功，\n查理最关心的却是为什么在股市投资上大部分人都失败了。他的这种思考方法来\n源于下面这句农夫谚语中所蕴含的哲理：我只想知道将来我会死在什么地方，这\n样我就永远不去那儿了。  \n        查理在他漫长的一生中，持续不断地收集并研究关于各种各样\n的人物、各行各业的企业以及政府管治、学术研究等各领域中的著名失败案例，\n并把那些失败的原因排列成作出正确决策前的检查清单，这使他在人生、事业的\n决策上几乎从不犯重大错误。这点对巴菲特及伯克希尔 50 年业绩的重要性是再\n强调也不为过的。  \n         查理的头脑是原创性的，从来不受任何条条框框的束缚，也','2026-07-05 16:55:53.049000',0,2073692323954429952,19,2073692323514028032),(2073692328257785862,'强调也不为过的。  \n         查理的头脑是原创性的，从来不受任何条条框框的束缚，也\n没有任何教条。他有儿童一样的好奇心，又有第一流科学家所具备的研究素质和\n科学研究方法，一生都有强烈的求知欲，几乎对所有的问题都感兴趣。任何一个\n问题在他看来都可以使用正确的方法通过自学完全掌握，并可以在前人的基础上\n进行创新。在这点上他和富兰克林非常相似，类似于一位 18、19 世纪百科全书\n式的人物。  \n         近代很多第一流的专家学者能够在自己狭小的研究领域内做\n到相对客观，但一旦离开自己的领域不远，就开始变得主观、教条、僵化，或者\n干脆就失去了自我学习的能力，所以大都免不了瞎子摸象的局限。查理的脑子就\n从来没有任何学科的条条框框。他的思想辐射到事业、人生、知识的每一个角落。\n在他看来，世间宇宙万物都是一个相互作用的整体，人类所有的知识都是对这一','2026-07-05 16:55:53.049000',0,2073692323954429952,20,2073692323514028032),(2073692328257785863,'从来没有任何学科的条条框框。他的思想辐射到事业、人生、知识的每一个角落。\n在他看来，世间宇宙万物都是一个相互作用的整体，人类所有的知识都是对这一\n整体研究的部分尝试，只有把这些知识结合起来，并贯穿在一个思想框架中，才\n能对正确的认知和决策起到帮助作用。所以他提倡要学习在所有学科中真正重要\n的理论，并在此基础上形成所谓的“普世智慧”，以此为利器去研究商业投资领\n域的重要问题。查理在本书中详细地阐述了如何才能获得这样的“普世智慧”。  \n        查理这种思维方式是基于对知识的诚实。他认为，这个世界复\n杂多变，人类的认知永远存在着限制，所以你必须使用所有的工具，同时要注重\n收集各种新的可以证否的证据，并随时修正，即所谓“知之为知之，不知为不\n知”。事实上，所有的人都存在思想上的盲点。我们对于自己的专业、旁人或是\n某一件事情或许能够做到客观，但是对于天下万事万物都秉持客观的态度却是很','2026-07-05 16:55:53.049000',0,2073692323954429952,21,2073692323514028032),(2073692328257785864,'知”。事实上，所有的人都存在思想上的盲点。我们对于自己的专业、旁人或是\n某一件事情或许能够做到客观，但是对于天下万事万物都秉持客观的态度却是很\n难的，甚至可以说是有违人之本性的。但是查理却可以做到凡事客观。在这本书\n里，查理也讲到了通过后天的训练是可以培养客观精神的。而这种思维方式的养\n成将使你看到别人看不到的东西，预测到别人预测不到的未来，从而过上更幸福、\n自由和成功的生活。  \n        但即使这样，一个人在一生中真正可以得到的真见卓识仍然非\n常有限，所以正确的决策必须局限在自己的“能力圈”以内。一种不能够界定其\n边界的能力当然不能称为真正的能力。怎么才能界定自己的能力圈呢？查理说，\n如果我要拥有一种观点，如果我不能够比全世界最聪明、最有能力、最有资格反\n驳这个观点的人更能够证否自己，我就不配拥有这个观点。所以当查理真正地持','2026-07-05 16:55:53.049000',0,2073692323954429952,22,2073692323514028032),(2073692328257785865,'如果我要拥有一种观点，如果我不能够比全世界最聪明、最有能力、最有资格反\n驳这个观点的人更能够证否自己，我就不配拥有这个观点。所以当查理真正地持\n有某个观点时，他的想法既原创、独特，又几乎从不犯错。  \n        一次，查理邻座一位漂亮的女士坚持让查理用一个词来总结他\n的成功，查理说是“理性”。然而查理讲的“理性”却不是我们一般人理解的理\n性。查理对理性有更苛刻的定义。正是这样的“理性”，让查理具有敏锐独到的\n眼光和洞察力，既使对于完全陌生的领域，他也能一眼看穿事物的本质。巴菲特\n把查理的这个特点称作“两分钟效应”——他说查理比世界上任何人更能在最\n短时间之内把一个复杂商业的本质说清楚。伯克希尔投资比亚迪的经过就是一个\n例证。记得 2003 年我第一次同查理谈到比亚迪时，他虽然从没有见过王传福本\n人，也从未参观过比亚迪的工厂，甚至对中国的市场和文化也相对陌生，可是他','2026-07-05 16:55:53.049000',0,2073692323954429952,23,2073692323514028032),(2073692328257785866,'例证。记得 2003 年我第一次同查理谈到比亚迪时，他虽然从没有见过王传福本\n人，也从未参观过比亚迪的工厂，甚至对中国的市场和文化也相对陌生，可是他\n当时对比亚迪提出的问题和评论，今天看来仍然是投资比亚迪最实质的问题。  \n         人人都有盲点，再优秀的人也不例外。巴菲特说：“本杰明•\n格拉汉姆曾经教我只买便宜的股票，查理让我改变了这种想法。这是查理对我真\n正的影响。要让我从格拉汉姆的局限理论中走出来，需要一股强大的力量。查理\n的思想就是那股力量，他扩大了我的视野。”对此，我自己也有深切的体会。至\n少在两个重大问题上，查理帮我指出了我思维上的盲点，如果不是他的帮助，我\n现在还在从猿到人的进化过程中慢慢爬行 ā。巴菲特 50 年来在不同的场合反复\n强调，查理对他本人和伯克希尔的影响完全无人可以取代。  \n        查理一辈子研究人类灾难性的错误，对于由于人类心理倾向引','2026-07-05 16:55:53.049000',0,2073692323954429952,24,2073692323514028032),(2073692328257785867,'强调，查理对他本人和伯克希尔的影响完全无人可以取代。  \n        查理一辈子研究人类灾难性的错误，对于由于人类心理倾向引\n起的灾难性错误尤其情有独钟。最具贡献的是他预测到，金融衍生产品的泛滥和\n会计审计制度的漏洞即将给人类带来灾难。早在 1990 年代末期，他和巴菲特先\n生已经提出了金融衍生产品可能造成灾难性的影响，随着金融衍生产品的泛滥愈\n演愈烈，他们的警告也不断升级，甚至指出金融衍生产品是金融式的大规模杀伤\n武器，如果不能得到及时有效的制止，将会给现代文明社会带来灾难性的影响。\n2008 年和 2009 年的金融海啸及全球经济大萧条不幸验证了查理的远见。从另一\n方面讲，他对这些问题的研究也为防范类似灾难的出现提供了宝贵的经验和知\n识，特别值得政府、金融界、企业界和学术界重视。  \n        与巴菲特相比，查理的兴趣更为广泛。比如他对科学和软科学','2026-07-05 16:55:53.049000',0,2073692323954429952,25,2073692323514028032),(2073692328261980160,'识，特别值得政府、金融界、企业界和学术界重视。  \n        与巴菲特相比，查理的兴趣更为广泛。比如他对科学和软科学\n几乎所有的领域都有强烈的兴趣和广泛的研究，通过融会贯通，形成了原创性的、\n独特的芒格思想体系。相对于任何来自象牙塔内的思想体系，芒格主义完全为解\n决实际问题而生。比如说，据我所知，查理最早提出并系统研究人类心理倾向在\n投资和商业决策中的巨大影响。十几年后的今天，行为金融学已经成为经济学中\n最热门的研究领域，行为经济学也获得了诺贝尔经济学奖的认可。而查理在本书\n最后一讲“人类误判心理学”中所展现出的理论框架，在未来也很可能得到人们\n更广泛的理解和应用。  \n        查理的兴趣不仅限于思考，凡事也喜欢亲历亲为，并注重细节。\n他有一艘世界上最大的私人双体游艇，而这艘游艇就是他自己设计的。他还是个\n出色的建筑师。他按自己的喜好建造房子，从最初的图纸设计到之后的每一个细','2026-07-05 16:55:53.049000',0,2073692323954429952,26,2073692323514028032),(2073692328261980161,'他有一艘世界上最大的私人双体游艇，而这艘游艇就是他自己设计的。他还是个\n出色的建筑师。他按自己的喜好建造房子，从最初的图纸设计到之后的每一个细\n节，他都全程参与。比如他捐助的所有建筑物都是他自己亲自设计的，这包括了\n斯坦福大学研究生院宿舍楼、哈佛—西湖学校科学馆以及亨廷顿图书馆与园林的\n稀有图书研究馆。  \n        查理天生精力充沛。我认识查理是在 1996 年，那时他 72 岁。 \n到今年查理 86 岁，已经过了十几年了。在这十几年里，查理的精力完全没有变\n化。他永远是精力旺盛，很早起身。早餐会议永远是七点半开始。同时由于某些\n晚宴应酬的缘故，他的睡眠时间可能要比常人少，但这些都不妨碍他旺盛的精力。\n而且他记忆力惊人，我很多年前跟他讲的比亚迪的营运数字，我都已经记忆模糊\n了，他还记得。86 岁的他记性比我这个年轻人还好。这些都是他天生的优势，','2026-07-05 16:55:53.049000',0,2073692323954429952,27,2073692323514028032),(2073692328261980162,'而且他记忆力惊人，我很多年前跟他讲的比亚迪的营运数字，我都已经记忆模糊\n了，他还记得。86 岁的他记性比我这个年轻人还好。这些都是他天生的优势，\n但使他异常成功的特质却都是他后天努力获得的。  \n        查理对我而言，不仅是合伙人，是长辈，是老师，是朋友，是\n事业成功的典范，也是人生的楷模。我从他的身上不仅学到了价值投资的道理，\n也学到了很多做人的道理。他让我明白，一个人的成功并不是偶然的，时机固然\n重要，但人的内在品质更重要。  \n        查理喜欢与人早餐约会，时间通常是七点半。记得第一次与查\n理吃早餐时，我准时赶到，发现查理已经坐在那里把当天的报纸都看完了。虽然\n离七点半还差几分钟，但让一位德高望重的老人等我让我心里很不好受。第二次\n约会时，我大约提前了一刻钟到达，发现查理还是已经坐在那里看报纸了。到第','2026-07-05 16:55:53.049000',0,2073692323954429952,28,2073692323514028032),(2073692328261980163,'离七点半还差几分钟，但让一位德高望重的老人等我让我心里很不好受。第二次\n约会时，我大约提前了一刻钟到达，发现查理还是已经坐在那里看报纸了。到第\n三次约会，我提前半小时到达，结果查理还是在那里看报纸，仿佛他从未离开过\n那个座位，终年守候。直到第四次，我狠狠心提前一个钟头到达，六点半坐那里\n等候，到六点四十五的时候，查理悠悠地走进来了，手里拿着一摞报纸，头也不\n抬地坐下，完全没有注意到我的存在。以后我逐渐了解到，查理与人约会一定早\n到。到了以后也不浪费时间，会拿出准备好的报纸翻阅。自从知道查理的这个习\n惯后，以后我俩再约会，我都会提前到场，也拿一份报纸看，互不打扰，等七点\n半之后在一起吃早餐聊天。  \n        偶然查理也会迟到。有一次我带一位来自中国的青年创业者去\n见查理。查理因为从一个午餐会上赶来而迟到了半个小时。一到之后，查理先向','2026-07-05 16:55:53.049000',0,2073692323954429952,29,2073692323514028032),(2073692328261980164,'        偶然查理也会迟到。有一次我带一位来自中国的青年创业者去\n见查理。查理因为从一个午餐会上赶来而迟到了半个小时。一到之后，查理先向\n我们两个年轻人郑重道歉，并详细解释他迟到的原因，甚至提出午餐会的代客泊\n车（valet park）应如何改进才不会耽误客人 45 分钟的等候时间。那位中国青\n年既惊讶又感动，因为在全世界恐怕找不到一位地位如查理一般的长者会因迟到\n而向小辈反复道歉。  \n        在跟查理的交往中，另有一件事对我影响很大。有一年查理和\n我共同参加了一个外地的聚会。活动结束后，我要赶回纽约，没想到却在机场的\n候机厅遇见查理。他庞大的身体在过安检检测器的时候，不知什么原因导致检测\n器不断鸣叫示警。而查理就一次又一次地折返接受安检，如此折腾半天，好不容\n易过了安检，他的飞机已经起飞了。  \n        可查理也不着急，他抽出随身携带的书坐下来阅读，静等下一','2026-07-05 16:55:53.049000',0,2073692323954429952,30,2073692323514028032),(2073692328261980165,'易过了安检，他的飞机已经起飞了。  \n        可查理也不着急，他抽出随身携带的书坐下来阅读，静等下一\n班飞机。那天正好我的飞机也误点了，我就陪他一起等。  \n        我问查理：“你有自己的私人飞机，伯克希尔也有专机，你为\n什么要到商用客机机场去经受这么多的麻烦呢？”  \n        查理答：“第一，我一个人坐专机太浪费油了。第二，我觉得\n坐商用飞机更安全。”但查理想说的真正理由是第三条：“我一辈子想要的就是\n融入生活（engage life），我不希望自己被孤立（isolated）。”  \n        查理最受不了的就是因为拥有了钱财而失去与世界的联系，把\n自己隔绝在一个单间，隔绝在占地一层的巨型办公室里，见面要层层通报，过五\n关斩六将，谁都不能轻易接触到。这样就与现实生活脱节了。  \n        “手里只要有一本书，我就不会觉得浪费时间。”查理任何时','2026-07-05 16:55:53.049000',0,2073692323954429952,31,2073692323514028032),(2073692328261980166,'关斩六将，谁都不能轻易接触到。这样就与现实生活脱节了。  \n        “手里只要有一本书，我就不会觉得浪费时间。”查理任何时\n候都随身携带一本书，即使坐在经济舱的中间座位上，他只要拿着书，就安之若\n素。有一次他去西雅图参加一个董事会，依旧按惯例坐经济舱，他身边坐着一位\n中国小女孩，飞行途中一直在做微积分的功课。他对这个中国小女孩印象深刻，\n因为他很难想像同龄的美国女孩能有这样的定力，在飞机的嘈杂声中专心学习。\n如果他乘坐私人飞机，他就永远不会有机会近距离接触这些普通人的故事。  \n        查理虽然严于律己，却非常宽厚地对待他真正关心和爱的人，\n他不吝金钱，总希望他人能多受益。他一个人的旅行，无论公务私务都搭乘经济\n舱，但与太太和家人一起旅行时，查理便会乘搭自己的私人飞机。他解释说：太\n太一辈子为我抚育这么多孩子，付出甚多，身体又不好，我一定要照顾好她。  ','2026-07-05 16:55:53.049000',0,2073692323954429952,32,2073692323514028032),(2073692328261980167,'舱，但与太太和家人一起旅行时，查理便会乘搭自己的私人飞机。他解释说：太\n太一辈子为我抚育这么多孩子，付出甚多，身体又不好，我一定要照顾好她。  \n        查理虽不是斯坦福大学毕业的，但因他太太是斯坦福校友，又\n是大学董事会成员，查理便向斯坦福大学捐款 6000 多万美金。  \n        查理一旦确定了做一件事情，他可以做一辈子。比如说他在哈\n佛—西湖学校及洛杉矶一间慈善医院的董事会任职长达 40 年之久。对于他所参\n与的慈善机构而言，查理是非常慷慨的赞助人。而且查理投入的不只是钱，他还\n投入了大量的时间和精力，以确保这些机构的成功运行。  \n        查理一生研究人类失败的原因，所以对人性的弱点有着深刻的\n理解。基于此，他认为人对自己要严格要求，一生不断提高修养，以克服人性本\n身的弱点。这种生活方式对查理而言是一种道德要求。在外人看来，查理可能像','2026-07-05 16:55:53.049000',0,2073692323954429952,33,2073692323514028032),(2073692328261980168,'理解。基于此，他认为人对自己要严格要求，一生不断提高修养，以克服人性本\n身的弱点。这种生活方式对查理而言是一种道德要求。在外人看来，查理可能像\n个苦行僧，但在查理看来，这个过程却是既理性又愉快的，能够让人过上成功、\n幸福的人生。  \n        查理就是这么独特。但是想想看，如果芒格和巴菲特不是如此\n独特的话，他们也不可能一起在 50 年间为伯克希尔创造出在人类投资史上前无\n古人、后无来者的业绩。近 20 年来，全世界范围内对巴菲特、芒格研究的兴趣\n愈发地强烈，将来可能还会愈演愈烈，中英文的书籍汗牛充栋，其中也不乏独到\n的见解。说实话，由我目前的能力来评价芒格的思想其实为时尚早，因为直到今\n天，我每次和查理谈话，每次重读他的演讲，都会有新的收获。这另一方面也说\n明，我对他的思想理解还是不够。但这些年来查理对我的言传身教，使我有幸对','2026-07-05 16:55:53.049000',0,2073692323954429952,34,2073692323514028032),(2073692328261980169,'天，我每次和查理谈话，每次重读他的演讲，都会有新的收获。这另一方面也说\n明，我对他的思想理解还是不够。但这些年来查理对我的言传身教，使我有幸对\n查理的思想和人格有更直观的了解，我这里只想跟读者分享我自己近距离的观察\n和亲身体会。我衷心希望读者在仔细地研读了本书之后，能够比我更深地领会芒\n格主义的精要，从而对自己的事业和人生有更大的帮助。  \n        我知道查理本人很喜欢这本书，认为它收集了他一生的思想精\n华和人生体验。晚年的查理时常引用下面这句出自《天路历程》中真理剑客的话\n来结束他的演讲：“我的剑留给能够挥舞它的人。”通过这本书的出版，我希望\n更多的读者能有机会学习和了解芒格的智慧和人格，我相信每位读者都有可能通\n过学习实践成为幸运的剑客。 \n三 \n \n        与查理交往的这些年，我常常会忘记他是一个美国人。','2026-07-05 16:55:53.049000',0,2073692323954429952,35,2073692323514028032),(2073692328261980170,'过学习实践成为幸运的剑客。 \n三 \n \n        与查理交往的这些年，我常常会忘记他是一个美国人。\n他更接近于我理解的中国传统士大夫。旅美的 20 年间，作为一个华人，\n我常常自问：中国文化的灵魂和精华到底是什么？客观地讲，作为“五\n四”之后成长起来的中国人，我们对于中国的传统基本上是持否定态度\n的。 到了美国之后，我先是有幸在哥大求学期间系统地学习了对西方文\n明史起到塑造性作用的 100 多部原典著作，其中涵盖文学、哲学、科学、\n宗教与艺术等各个领域，以希腊文明为起点，延伸到欧州，直至现代文\n明。后来又得益于哥大同时提供的一些关于儒教文化和伊斯兰文明的课\n程，而对中国的儒教文化有了崭新的了解和认识。只是当时的阅读课本\n都是英文的，我古文修养不够，很多索求原典的路途便只能由阅读英文\n的翻译来达成，这也是颇为无奈的一件事。  ','2026-07-05 16:55:53.049000',0,2073692323954429952,36,2073692323514028032),(2073692328261980171,'都是英文的，我古文修养不够，很多索求原典的路途便只能由阅读英文\n的翻译来达成，这也是颇为无奈的一件事。  \n        在整个阅读与思考的过程中，我愈发觉得，中国文明\n的灵魂其实就是士大夫文化，士大夫的价值观所体现的就是一个如何提\n高自我修养，实现自我超越的过程。《大学》曰：正心，修身，齐家，\n治国，平天下。 这套价值系统在儒家各派中都得到了广泛的阐述，这应\n该说是中国文明最核心的灵魂价值所在。士大夫文明的载体是科举制度。\n科举制度不仅帮助儒家的追随者塑造自身的人格，而且还提供了他们发\n挥才能的平台，使得他们能够通过科举考试进入政府为官，乃至到达社\n会的最上层，从而学有所用，实现自我价值。  \n        而科举制度结束后，在过去的上百年里，士大夫精神\n失去了具体的现实依托，变得无所适从，尤其到了今天商业高度发展的\n社会，具有士大夫情怀的中国读书人，对于自身的存在及其价值理想往','2026-07-05 16:55:53.049000',0,2073692323954429952,37,2073692323514028032),(2073692328261980172,'失去了具体的现实依托，变得无所适从，尤其到了今天商业高度发展的\n社会，具有士大夫情怀的中国读书人，对于自身的存在及其价值理想往\n往更加困惑。在一个传统尽失的商业社会，士大夫的精神是否仍然适用\n呢？晚明时期，资本主义开始在中国萌芽，当时的商人曾经提出过“商\n才士魂”以彰显其理想。今天，商业市场力量已经成为社会的主导，我\n以为这种理想更有可能成为现实了。  \n        查理可以说是“商才士魂”的最好典范。首先，查理\n在商业领域极为成功，他和巴菲特所取得的成就可以说是前无古人，后\n无来者。然而在与查理的深度接触中，我却发现查理本质上是一个道德\n哲学家，一个学者。他阅读广泛，知识渊博，真正关注的是自身道德的\n修养与对社会的终极关怀。与孔子一样，查理的价值系统内渗而外，倡\n导通过自身的修行以达到圣人的境界，从而帮助他人。  \n        正如前面所提到的，查理对自身要求很严。他虽然十','2026-07-05 16:55:53.049000',0,2073692323954429952,38,2073692323514028032),(2073692328261980173,'导通过自身的修行以达到圣人的境界，从而帮助他人。  \n        正如前面所提到的，查理对自身要求很严。他虽然十\n分富有，但过的却是苦行僧般的生活。他现在居住的房子还是几十年前\n买的一套普通房子，外出旅行时永远只坐经济舱，而约会总是早到 45 分\n钟，还会为了偶尔的迟到而专门致歉。在取得事业与财富的巨大成功之\n后，查理又致力于慈善事业，造福天下人。  \n        查理是一个完全凭借智慧取得成功的人，这对于中国\n的读书人来讲无疑是一个令人振奋的例子。他的成功完全靠投资，而投\n资的成功又完全靠自我修养和学习，这与我们在当今社会上所看到的权\n钱交易、潜规则毫无关系。作为一个正直善良的人，他用最干净的方法，\n充分运用自己的智慧，取得了这个商业社会中的巨大成功。在市场经济\n下的今天，满怀士大夫情怀的中国读书人是否也可以通过学习与自身修','2026-07-05 16:55:53.049000',0,2073692323954429952,39,2073692323514028032),(2073692328266174464,'充分运用自己的智慧，取得了这个商业社会中的巨大成功。在市场经济\n下的今天，满怀士大夫情怀的中国读书人是否也可以通过学习与自身修\n养的提升来取得世俗社会的成功并实现自身的价值理想呢？  \n        我衷心地希望中国的读者能够对查理感兴趣，对这本\n书感兴趣。查理很欣赏孔子，尤其是孔子授业解惑的为师精神。查理本\n人很乐于也很善于教导别人，诲人不倦。这本书汇集了查理的一生所学\n与智慧，并将之毫无保留地与大家分享。查理对中国的未来充满信心，\n对中国的文化也很钦佩。近几十年来儒教文明在亚洲取得的巨大的商业\n成就也让越来越多的人对中国文明的复兴更具信心。在“五四”近百年\n之后，今天的我们也许不必再纠缠于“中学”“西学”的“体用”之争，\n只需要一方面坦然地学习和接受全世界所有有用的知识，另一方面心平\n气和地将吾心归属于中国人数千年来共敬共守、以之安身立命的道德价\n值体系之内。  ','2026-07-05 16:55:53.049000',0,2073692323954429952,40,2073692323514028032),(2073692328266174465,'只需要一方面坦然地学习和接受全世界所有有用的知识，另一方面心平\n气和地将吾心归属于中国人数千年来共敬共守、以之安身立命的道德价\n值体系之内。  \n        我有时会想，若孔子重生在今天的美国，查理大概会\n是其最好的化身。若孔子返回到 2000 年后今天的商业中国，他倡导的大\n概会是：正心，修身，齐家，致富，助天下吧！  \n四 \n \n        本书第一至第三章介绍了查理的生平、著名的语录，并总结\n了他关于生活、事业和学习的主要思想，第四章则收录了查理最有代表性的十\n一篇演讲。其中大多数读者最感兴趣的演讲可能包含下面四篇：第一篇演讲用\n幽默的方式概述了人生当如何避免过上痛苦的生活；第二、三篇演讲阐述了如\n何获得普世智慧，如何将这些普世智慧应用到成功的投资实践中；最后一篇演\n讲则记录了查理最具有原创性的心理学体系，详细阐述了造成人类误判的 23 个\n最重要的心理学成因。  ','2026-07-05 16:55:53.049000',0,2073692323954429952,41,2073692323514028032),(2073692328266174466,'讲则记录了查理最具有原创性的心理学体系，详细阐述了造成人类误判的 23 个\n最重要的心理学成因。  \n        在过去的一年中，很多朋友为本书中文版的出版作出了贡献。\n中文译者李继宏先生承担了主要的工作，他的敬业精神和高超的文笔给我留下\n了深刻的印象。我长期的好友常劲先生为本书的校对、翻译和注解倾注了大量\n心血，没有他的帮助，我很难想像本书能够按时完成。我因为比较熟悉查理的\n思想和语言风格，自然担当起了最后把关的工作，如果本书翻译中出现各种错\n误也理应由本人最后承担。上海世纪出版集团的施宏俊先生儒雅、耐心、尽职、\n慷慨，实在是一位不可多得的合作伙伴。张辛女士在推动本书的翻译、校对、\n编辑和出版上起了至关重要的作用。与这些杰出同事合作，使得本书的翻译出\n版成为一次既有意义、又愉快的经历。另外，本书的出版还获得了国内很多朋\n友，尤其是价值投资界朋友的鼓励和支持，在此一并感谢。 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,42,2073692323514028032),(2073692328266174467,'版成为一次既有意义、又愉快的经历。另外，本书的出版还获得了国内很多朋\n友，尤其是价值投资界朋友的鼓励和支持，在此一并感谢。 \n \n2010 年 3 月 \n \n \n序言：巴菲特论芒格 \n \n沃伦·巴菲特 \n \n        从 1733 年到 1758 年，本杰明•富兰克林借由《穷理查年鉴》\n传播了许多有用且永恒的建议。他赞扬的美德包括节俭、负责、勤奋和简朴。  \n        在随后的两个世纪里，人们总是把本杰明关于这些美德的思想\n当成终极真理。然后查理•芒格站出来了。  \n        查理原初只是本杰明的信徒，但很快开辟了新的境界。本杰明\n建议做的，到查理这儿变成必须做到的。如果本杰明建议节省几分钱，查理会要\n求节省几块钱。如果本杰明说要及时，查理会说要提前。和芒格苛刻的要求相比，\n依照本杰明的建议来过日子显得太容易了。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,43,2073692323514028032),(2073692328266174468,'求节省几块钱。如果本杰明说要及时，查理会说要提前。和芒格苛刻的要求相比，\n依照本杰明的建议来过日子显得太容易了。 \n        此外，查理还始终身体力行他所鼓吹的道理（对了，喔，他是\n这么卖力地鼓吹）。在本杰明的遗嘱中，他设立了两个小型慈善基金，这两个基\n金的目的是要向人们传授复利的魔力。查理很早就决定这是一项如此重要的课题\n而绝不能在死后才通过项目来传授。所以他选择自己来做复利的活教材，避免（任\n何）可能削弱他的榜样力量的那些铺张的开支。结果是，查理的家庭成员体会到\n坐巴士长途旅行的乐趣，而他们那些被囚禁在私人飞机里的富裕朋友则错过了这\n些丰富多彩的体验。  \n        当然，在有些领域，查理则无意改善本杰明的看法。例如，本\n杰明那篇“选择情人的建议”的文章，就会让查理说出他在伯克希尔年会上常说\n的口头禅：“我没有什么要补充的。”  ','2026-07-05 16:55:53.049000',0,2073692323954429952,44,2073692323514028032),(2073692328266174469,'杰明那篇“选择情人的建议”的文章，就会让查理说出他在伯克希尔年会上常说\n的口头禅：“我没有什么要补充的。”  \n        至于我自己，我想提供几条“选择合伙人的建议”。请注意。  \n        首先，要找比你更聪明、更有智慧的人。找到他之后，请他别\n炫耀他比你高明，这样你就能够因为许多源自他的想法和建议的成就而得到赞\n扬。你要找这样的合伙人，在你犯下损失惨重的错误时，他既不会事后诸葛亮，\n也不会生你的气。他还应该是个慷慨大方的人，会投入自己的钱并努力为你工作\n而不计报酬。最后，这位伙伴还会在漫漫长路上结伴同游时能不断地给你带来快\n乐。  \n        上述这些都是很英明的建议（在自我评分的测验中，我从来没\n有拿过甲等以下的成绩）。实际上，这些建议是如此之英明，乃至我早在 1959\n年就决定完全遵守。而全部符合我这些特殊要求的人只有一个，他就是查理。  ','2026-07-05 16:55:53.049000',0,2073692323954429952,45,2073692323514028032),(2073692328266174470,'有拿过甲等以下的成绩）。实际上，这些建议是如此之英明，乃至我早在 1959\n年就决定完全遵守。而全部符合我这些特殊要求的人只有一个，他就是查理。  \n        在本杰明那篇著名的文章中，他说男人应该选择年纪较大的情\n人，他为此列举了八个非常好的理由。他最关键的理由是：“……最后，她们会\n感激不尽。”  \n        查理和我成为合伙人已经有 45 年。我不知道他是否由于其他\n七个标准而选择了我。但我绝对符合本杰明的第八个标准：我对他的感激无以言\n表。 \n \n驳辞：芒格论巴菲特 \n \n查理 • 芒格 \n \n        我想那些认为我是沃伦的伟大启蒙者的想法里有好些神话的\n成分。他不需要什么启蒙。坦白说，我觉得我有点名不副实。沃伦确实有过发蒙\n的时候，因为他曾在本杰明•格拉汉姆手下工作过，而且赚了那么多的钱。从如','2026-07-05 16:55:53.049000',0,2073692323954429952,46,2073692323514028032),(2073692328266174471,'成分。他不需要什么启蒙。坦白说，我觉得我有点名不副实。沃伦确实有过发蒙\n的时候，因为他曾在本杰明•格拉汉姆手下工作过，而且赚了那么多的钱。从如\n此成功的经验中跳出来确实很难。但如果世上未曾有过查理•芒格这个人，巴菲\n特的业绩依然会像现在这么漂亮。  \n \n        人们很难相信他的业绩一年比一年好。这种情况不会永久地持\n续下去，但沃伦的境界确实有所提高。这是很罕见的：绝大多数人到古稀之年便\n停滞不前了，但沃伦依然在进步。伯克希尔钱多成灾——我们拥有许多不断产生\n现金的伟大企业。等到沃伦离开的时候，伯克希尔的收购业务会受到影响，但其\n他部门将会运转如常。收购业务应该也还行。  \n \n        我想到那时伯克希尔的最高领导人应该没有沃伦那么聪明。但\n别抱怨：“天啊，给我沃伦•巴菲特 40 年之后，怎么能给我一个比他差的混蛋\n呢？”那是很愚蠢的。 \n \n导读 \n \n彼得 • 考夫曼 ','2026-07-05 16:55:53.049000',0,2073692323954429952,47,2073692323514028032),(2073692328266174472,'别抱怨：“天啊，给我沃伦•巴菲特 40 年之后，怎么能给我一个比他差的混蛋\n呢？”那是很愚蠢的。 \n \n导读 \n \n彼得 • 考夫曼 \n        你将要踏上通往更好的投资和决策的非凡旅程。你也可能因此\n而对生活有更深的理解，这一切都要感谢查理•芒格——当代的本杰明•富兰克林\n——的风趣、智慧、演讲和作品。查理的世界观很独特，他用“跨学科的”方法\n让自己养成了清晰而简单的思维模式——可是他的观点和思想却绝不简单。请注\n意查理的思想是怎样地经受了时间的考验：本书中最早的讲稿发表于 20 年前，\n然而在今天，它的现实意义和当初并无二致。正如你很快将要发现的，查理进行\n观察和作出推论的基础是根本的人性、基本的真理和许多学科的核心原理。  \n \n        贯穿全书的是芒格展示出来的聪慧、机智、价值观和深不可测\n的修辞天赋。他拥有百科全书般的知识，所以从古代的雄辩家到 18、19 世纪的','2026-07-05 16:55:53.049000',0,2073692323954429952,48,2073692323514028032),(2073692328266174473,' \n        贯穿全书的是芒格展示出来的聪慧、机智、价值观和深不可测\n的修辞天赋。他拥有百科全书般的知识，所以从古代的雄辩家到 18、19 世纪的\n欧洲文豪，再到当代的流行文化偶像，这些人的名言他都能信手拈来。其他人哪\n会让德摩斯梯尼、西塞罗和约翰尼•卡森平起平坐，或者将当今的投资经理和尼\n采、伽利略、“踢屁股比赛中的独腿人”相提并论呢？或者让本杰明•富兰克林\n和伯尼•康非德进行普世智慧竞赛？把自嘲和想像力发挥得淋漓尽致的查理把自\n己比喻为一匹会数数的马，提议用“格罗兹的咖啡因糖水”作为可口可乐新的宣\n传口号以使之彻底失去市场，甚至证明“至少我年轻时并不是一个彻头彻尾的笨\n蛋”。  \n \n        在一次演讲（“关于现实思维的现实思考？”）中，查理甚至\n接受了如何白手起家建立一个 2万亿美元的企业的挑战，然后动用他那多元思维\n模型，告诉我们如何才能完成这样的丰功伟绩。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,49,2073692323514028032),(2073692328266174474,'接受了如何白手起家建立一个 2万亿美元的企业的挑战，然后动用他那多元思维\n模型，告诉我们如何才能完成这样的丰功伟绩。  \n \n        在这里出现的引语、谈话和演讲均源自老派的美国中西部价值\n观，查理正是以这种价值观闻名的：活到老学到老，对知识抱有好奇心，遇事冷\n静镇定，不心生妒忌和仇恨，言出必行，能从别人的错误中吸取教训，有毅力恒\n心，拥有客观的态度，愿意检验自己的信念等等。但他的建议并不以大叫大嚷的\n警告的形式出现，查理利用幽默、逆向思维（遵从伟大的代数学家雅各比的指示，\n“反过来想，总是反过来想”）和悖论来提供睿智的忠告，引导人们应付最棘手\n的生活难题。  \n \n        查理还非常有效地应用了历史和企业案例研究。在这些讲话\n中，他往往通过讲故事而非抽象说教的方法，巧妙地、有条不紊地表达出他的观\n点。他用来款待听众的是趣闻轶事，而非干巴巴的数据和图表。他清楚地认识并','2026-07-05 16:55:53.049000',0,2073692323954429952,50,2073692323514028032),(2073692328270368768,'中，他往往通过讲故事而非抽象说教的方法，巧妙地、有条不紊地表达出他的观\n点。他用来款待听众的是趣闻轶事，而非干巴巴的数据和图表。他清楚地认识并\n明智地利用了传统的讲故事人的角色作为复杂和详细信息的传递者。所以我们为\n他的讲稿配上了许多“花边”知识，以助读者加深记忆，或在需要时使用。  \n \n        从这些谈话和演讲中可以清晰地看到，查理认为生活的决定比\n投资的决定重要。他那来自各种学科的思维模型反复地出现，却从不关注“企业\n组合投资策略”、“beta 系数”或者“资产定价模型”，而是以基本的公理、\n人类的成就、人性的弱点和通往智慧的崎岖道路为中心。查理曾经说：“就像约\n翰•梅纳德•凯恩斯男爵那样，我想通过发财致富来变得独立。”对于查理而言，\n独立是赚钱的目的，而不是倒过来。 \n \n关于本书 \n \n \n        本书的开篇是查理的简略传记，它逐年记录了查理从普通的奥','2026-07-05 16:55:53.049000',0,2073692323954429952,51,2073692323514028032),(2073692328270368769,'独立是赚钱的目的，而不是倒过来。 \n \n关于本书 \n \n \n        本书的开篇是查理的简略传记，它逐年记录了查理从普通的奥\n马哈孩童变为成功的金融大亨的过程。接着是第二版没有的新内容，查理受到西\n塞罗的《论老年》的启发，写下了他对晚年的思考，并交给了我们。随后，我们\n归纳了芒格的生活、学习、决策和投资方法。这部分的内容详细介绍了查理出乎\n其类的思考方法和拔乎其萃的工作伦理——这是他获得惊人成功的两大原因。\n“芒格主义：查理的即席谈话”收录的是他在以往的伯克希尔•哈撒韦公司和西\n科金融公司年会上的犀利评论。  \n \n        本书的后半部分是查理在过去 20 年来的谈话稿和演讲稿。本\n书是经过增订的第三版，我们添加了一篇新的文章，那是 2007 年 5 月 13 日查理\n在南加州大学 GOULD 法学院毕业典礼上的演讲。所以原本的“查理十讲”变成了','2026-07-05 16:55:53.049000',0,2073692323954429952,52,2073692323514028032),(2073692328270368770,'在南加州大学 GOULD 法学院毕业典礼上的演讲。所以原本的“查理十讲”变成了\n没那么圆整的“查理十一讲”。这些演讲和谈话囊括了许多查理感兴趣的领域，\n从如何获得普世的智慧，到如何将他的“多元思维模型”应用于做生意，再到如\n何改进慈善基金所采纳的投资策略等等，这一切无所不包。第十一讲“人类误判\n心理学”是查理专门为本书而写的。每篇讲稿都值得你花时间好好品读，因为你\n不仅能够从阅读中得到乐趣，还能够从查理所笃信的大量观念和行为中吸取精\n华。你很可能不会有更好的机会向某个如此聪明、如此坦诚的人学习。在演讲中，\n查理敞开心扉，毫无保留地说出他的想法。要特别指出的是，查理会反复地使用\n一些用语和例子，他是有意的：他知道对于要达到他所倡导的那种有深度的“熟\n练”来说，重复是教导的核心。  \n \n        简单说下本书的风格和版式：查理对他在生活中遇到的几乎一','2026-07-05 16:55:53.049000',0,2073692323954429952,53,2073692323514028032),(2073692328270368771,'练”来说，重复是教导的核心。  \n \n        简单说下本书的风格和版式：查理对他在生活中遇到的几乎一\n切事物都有极强的好奇心。由于我们自己也曾遇到查理在他的讲话中提及的人\n物、地点和其他内容，所以我们为他的讲稿配上了相关的信息、照片和其他图画。\n例如，讲稿部分每页都加插了“边栏”，用来解释概念，增添支持的声音，或者\n强调芒格某个重要的观念。我们希望这些边栏不仅能够提供信息，而且还能让你\n觉得好玩，甚至能够鼓励你亲自去寻找更多的相关内容。我们希望你阅读愉快，\n也希望你会欣赏查理•芒格的智慧和幽默——那是我们这些认识他的人都很珍惜\n和期待从他那里得到的。 \n \n第三章 第二章 \n芒格的生活、学习和决策方法 \n \n \n        凡事往简单处想，往认真处行。  \n——查理·芒格 \n \n        虽然主要是靠自学，本杰明·富兰克林在新闻、出版、印刷、','2026-07-05 16:55:53.049000',0,2073692323954429952,54,2073692323514028032),(2073692328270368772,' \n \n        凡事往简单处想，往认真处行。  \n——查理·芒格 \n \n        虽然主要是靠自学，本杰明·富兰克林在新闻、出版、印刷、\n慈善、公共服务、科学、外交和发明等不同领域都取得了惊人的成功。富兰克林\n的成功主要归功于他的性格——尤其是他勤奋工作的劲头，还有他永不满足的求\n知欲望和从容不迫的行为方式。除此之外，他头脑聪明，乐于接受新事物，所以\n每当选择新的钻研领域，他很快就能融会贯通。查理·芒格将富兰克林视为最大\n的偶像并不奇怪，因为芒格主要也是靠自学成材，而且也拥有许多富兰克林的独\n特品格。就像富兰克林那样，查理本人也是一个未雨绸缪、富有耐心、律己严厉\n和不偏不倚的超级大师。他充分利用这些特性，在个人生活和生意场上——尤其\n是在投资领域——都取得了巨大的成功。  \n \n        对查理来说，成功的投资只是他小心谋划、专注行事的生活方','2026-07-05 16:55:53.049000',0,2073692323954429952,55,2073692323514028032),(2073692328270368773,'是在投资领域——都取得了巨大的成功。  \n \n        对查理来说，成功的投资只是他小心谋划、专注行事的生活方\n式的副产品。沃伦•巴菲特曾经说：“查理能够比任何活着的人更快、更准确地\n分析任何种类的交易。他能够在 60 秒之内找出令人信服的弱点。他是一个完美\n的合伙人。”巴菲特为什么会给他这么高的评价呢？答案就在于芒格独创的生\n活、学习和决策方法——这也是本章的主题。本章正式开始之前，请允许我们作\n点简单的介绍：考虑到查理的方法十分复杂，我们无意将接下来的内容编成“怎\n么做”课程，以供有抱负的投资者参考，而是对“他看上去是怎么做的”进行概\n述。我们在这里的目标是展示查理方法的基本轮廓，让你能够更好地理解本书剩\n下篇章中的大量细节。如果你急于了解具体的方法，“芒格主义：查理的即席谈\n话”和“查理十一讲”——这两章包含了大量出自查理自己手笔的文字——就','2026-07-05 16:55:53.049000',0,2073692323954429952,56,2073692323514028032),(2073692328270368774,'下篇章中的大量细节。如果你急于了解具体的方法，“芒格主义：查理的即席谈\n话”和“查理十一讲”——这两章包含了大量出自查理自己手笔的文字——就\n各种各样的领域提出了“怎么做”的具体建议。在本章，能做到呈现查理在考虑\n投资时运用的思维过程，然后再扼要地指明他的投资指导方针，我们就很满足了。  \n \n \n        （插文）作为生态系统的商业世界  \n \n        如果我们试图理解一样看似独立存在的东西，我们将会发现它\n和宇宙间的其他一切都有联系。  \n——约翰·缪尔 \n \n \n        “我发现把自由的市场经济——或者部分自由的市场经济\n——当做某种生态系统是很有用的思维方式。动物在合适的地方能够繁衍，同样\n地，人只要在社会上找到了专属于自己的位置，也能够做得很成功。  \n \n        “可惜能这么想的人不多，因为早在达尔文时代以来，工业大','2026-07-05 16:55:53.049000',0,2073692323954429952,57,2073692323514028032),(2073692328270368775,'地，人只要在社会上找到了专属于自己的位置，也能够做得很成功。  \n \n        “可惜能这么想的人不多，因为早在达尔文时代以来，工业大\n亨之类的人就认为，适者生存的法则证明他们确实拥有过人的能力。但实际上，\n经济确实很像生态系统，它们之间有很多相似之处。  \n \n        “在商业世界，我们往往会发现，取胜的系统在最大化或者最\n小化一个或几个变量上走到近乎荒谬的极端——比如说好市多仓储超市。” \n芒格进行商业分析和评估的“多元思维模型” \n \n        “你必须知道重要学科的重要理论，并经常使用它们——要全\n部都用上，而不是只用几种。大多数人都只使用学过的一个学科的思维模型，比\n如说经济学，试图用一种方法来解决所有问题。你知道谚语是怎么说的：‘在手\n里拿着铁锤的人看来，世界就像一颗钉子。’这是处理问题的一种笨办法。”  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,58,2073692323514028032),(2073692328270368776,'如说经济学，试图用一种方法来解决所有问题。你知道谚语是怎么说的：‘在手\n里拿着铁锤的人看来，世界就像一颗钉子。’这是处理问题的一种笨办法。”  \n \n        查理的投资方法和大多数投资者所用的较为粗陋的系统完全\n不同。查理不会对一家公司的财务信息进行肤浅的独立评估，而是对他打算要投\n资的公司的内部经营状况及其所处的、更大的整体“生态系统”作出全面的分\n析。他将他用来作出这种评估的工具称为“多元思维模型”。他在几篇讲稿（尤\n其是第二、第三和第四讲）中详细地讨论了这些模型，它们是一个收集和处理信\n息、并依照信息行动的框架。它们借用并完美地糅合了许多来自各个传统学科的\n分析工具、方法和公式，这些学科包括历史学、心理学、生理学、数学、工程学、\n生物学、物理学、化学、统计学、经济学等。查理采用“生态”投资分析法的无\n懈可击的理由是：几乎每个系统都受到多种因素的影响，所以若要理解这样的系','2026-07-05 16:55:53.049000',0,2073692323954429952,59,2073692323514028032),(2073692328270368777,'生物学、物理学、化学、统计学、经济学等。查理采用“生态”投资分析法的无\n懈可击的理由是：几乎每个系统都受到多种因素的影响，所以若要理解这样的系\n统，就必须熟练地运用来自不同学科的多元思维模式。正如约翰·缪尔谈到自然\n界万物相互联系的现象时所说的：“如果我们试图理解一样看似独立存在的东\n西，我们将会发现它和宇宙间的其他一切都有联系。”  \n \n        查理试图发现与他的每个投资项目相关的宇宙，他所用的方法\n是牢牢地掌握全部——或者至少大部分——候选待投资公司内部及外部环境相\n关的因素。只要得到正确的收集和组织，他的多元思维模型（据他估计，大概有\n100 种）便能提供一个背景或者框架，使他具有看清生活本质和目标的非凡洞察\n力。我们在本章中更想指出的是，他的模型提供的分析结构使他能把纷繁复杂的\n投资问题简化为一些清楚的基本要素。这些模型中最重要的例子包括工程学的冗','2026-07-05 16:55:53.049000',0,2073692323954429952,60,2073692323514028032),(2073692328274563072,'力。我们在本章中更想指出的是，他的模型提供的分析结构使他能把纷繁复杂的\n投资问题简化为一些清楚的基本要素。这些模型中最重要的例子包括工程学的冗\n余备份模型，数学的复利模型，物理学和化学的临界点、倾覆力矩、自我催化模\n型，生物学的现代达尔文综合模型，以及心理学的认知误判模型。  \n \n        这种广谱分析法能够让人更好地理解许多和候选投资公司相\n关的因素是怎样相互影响、相互联系的。有时候，这种理解会揭示出更隐秘的情\n况，也就是会产生“波浪效应”或者“溢出效应”。在其他时候，这些因素联合\n起来可能会创造出或好或坏的巨大“lollapalooza 效应”。通过应用这个框架，\n查理得到了与绝大多数投资者不同的投资分析方法。他的方法接受了投资问题本\n质上非常复杂的现实，他不知疲倦地对投资问题进行科学的探讨，而不是传统的\n“调查”，他为它们进行充分的准备和广泛的研究。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,61,2073692323514028032),(2073692328274563073,'质上非常复杂的现实，他不知疲倦地对投资问题进行科学的探讨，而不是传统的\n“调查”，他为它们进行充分的准备和广泛的研究。  \n \n        查理在进行投资评估时采用的“重要学科的重要理论”方法\n在商业世界中肯定是独一无二的，因为这种方法是他原创的。查理找不到现成的\n方法来解决这个任务，所以他费劲地自创了大部分通过自学得来的系统。说他\n“自学”并非夸大其辞，他曾经说：“直到今天，我从来没在任何地方上过任何\n化学、经济学、心理学或者商学的课程。”然而这些学科——特别是心理学——\n却构成了他的系统赖以立足的基础。 \n   正是这种通过惊人的才智、耐心和数十年的相关经验支撑起来的这种标志\n性方法，使得查理成为备受巴菲特看重的商业模式识别大师。他就像一名国际象\n棋特级大师，通过逻辑、本能和直觉决定最具前景的投资“棋步”，同时又给人','2026-07-05 16:55:53.049000',0,2073692323954429952,62,2073692323514028032),(2073692328274563074,'性方法，使得查理成为备受巴菲特看重的商业模式识别大师。他就像一名国际象\n棋特级大师，通过逻辑、本能和直觉决定最具前景的投资“棋步”，同时又给人\n一种幻觉，似乎他的洞察力是轻易得来的。但请别弄错了：这种“简单”惟有在\n到达理解的漫长旅途的终点——而非起点——才会到来。他独到的眼光得来不\n易：那是他毕生钻研人类行为模式、商业系统和许多其他科学学科的产物。 \n（插文）L·O·L·L·A·P·A·L·O·O·Z·A效应 \n \n        当然，芒格为那些相互强化并极大地放大彼此效应的因素而发\n明的词组就是“lollapalooza 效应”。  \n——亨利·爱默生，《杰出投资者文摘》 \n \n \n \n        最重要的事情是要牢牢记住，这 100 种模型往往能够带来特别\n大的力量。当几个模型联合起来，你就能得到 lollapalooza 效应；这是两种、','2026-07-05 16:55:53.049000',0,2073692323954429952,63,2073692323514028032),(2073692328274563075,'大的力量。当几个模型联合起来，你就能得到 lollapalooza 效应；这是两种、\n三种或四种力量共同作用于同一个方向，而且你得到的通常不仅仅是几种力量之\n和。那就像物理学里面的临界质量，当你达到一定程度的质量，你就能引发核爆\n炸——而如果你没有达到那种质量，你将什么也得不到。有时候各种力量只是简\n单地相加，有时候它们会在临界点或者临界质量的基础上联合起来。  \n \n        更为常见的情形是，这 100 种模型带来的各种力量在某种程度\n上是相互冲突的。所以你将会面临鱼和熊掌不可兼得的境况。如果你不明白有舍\n才有得的道理，如果你以为鱼与熊掌可以兼得，那么你就太傻了。对于需要高级\n思维的活动，你这种头脑不清对于旁人而言就变成了一种风险。你必须辨认出这\n些事情之间的关系。你必须意识到生物学家朱利安·赫胥黎的那句话是千真万确','2026-07-05 16:55:53.049000',0,2073692323954429952,64,2073692323514028032),(2073692328274563076,'思维的活动，你这种头脑不清对于旁人而言就变成了一种风险。你必须辨认出这\n些事情之间的关系。你必须意识到生物学家朱利安·赫胥黎的那句话是千真万确\n的——他说：“生活无非就是一个接一个的联系。”所以你必须拥有各种模型，\n你必须弄清楚各种模型的相互关系以及它们的效应。  \n——《杰出投资者文摘》，1997 年 12 月 29 日 \n 查理认为未雨绸缪、富有耐心、律己严厉和不偏不倚是最基本的指导原则。不\n管周围的人怎么想，不管自己的情绪有什么波动，他永不背离这些原则，尽管许\n多人都认为“做人要懂得随机应变”。这些原则若是得到坚定不移的遵守，便能\n产生最著名的芒格特征之一：不要非常频繁地进行买卖。和巴菲特相同，芒格认\n为，只要几次决定便能造就成功的投资生涯。所以当查理喜欢一家企业的时候，\n他会下非常大的赌注，而且通常会长时间地持有该企业的股票。查理称之为“坐','2026-07-05 16:55:53.049000',0,2073692323954429952,65,2073692323514028032),(2073692328274563077,'为，只要几次决定便能造就成功的投资生涯。所以当查理喜欢一家企业的时候，\n他会下非常大的赌注，而且通常会长时间地持有该企业的股票。查理称之为“坐\n等投资法”，并点明这种方法的好处：“你付给交易员的费用更少，听到的废话\n也更少，如果这种方法生效，税务系统每年会给你 1%—3%的额外回报。”在他\n看来，只要购买三家公司的股票就足够了。所以呢，查理愿意将大比例的资金投\n给个别“受关注”的机会。没有哪家华尔街机构、哪个理财顾问或者哪个开放式\n基金的经理会作出这样的宣言！  \n \n        既然查理取得了成功，而且也得到巴菲特的称赞，为什么其他\n人并没有更多地使用他的投资技巧呢？也许答案是这样的：对大多数人来说，查\n理的跨学科方法真的太难了。此外，很少投资者能够做到像查理那样，宁愿显得\n愚蠢，也不愿随“大流”。查理坚持不偏不倚的客观态度，他能够冷静地逆流行','2026-07-05 16:55:53.049000',0,2073692323954429952,66,2073692323514028032),(2073692328274563078,'理的跨学科方法真的太难了。此外，很少投资者能够做到像查理那样，宁愿显得\n愚蠢，也不愿随“大流”。查理坚持不偏不倚的客观态度，他能够冷静地逆流行\n观点的潮流而上，一般投资者很少拥有这种素质。尽管这种行为往往会显得固执\n或反叛，但查理的为人决不是这样的。查理只是相信他自己的判断，即使那与大\n多数人的看法相左。很少有人看得出查理这种“独狼”性格是他在投资界取得优\n异业绩的原因。但实际上，性格主要是天生的，一个人如果没有这种性格，那么\n他再怎么努力，再怎么聪明，阅历再丰富，也未必能够成为像查理·芒格这么伟\n大的投资家。我们在本书其他的篇章中将会看到，先天的性格也是查理成功的决\n定性因素之一。 \n \n（插文）纪律和耐心 泰德·威廉姆斯的 77 格击球区 \n \n        有性格的人才能拿着现金坐在那里什么事也不做。我能有今\n天，靠的是不去追逐平庸的机会。  \n——查理·芒格 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,67,2073692323514028032),(2073692328274563079,' \n        有性格的人才能拿着现金坐在那里什么事也不做。我能有今\n天，靠的是不去追逐平庸的机会。  \n——查理·芒格 \n \n        在进行投资时，我向来认为，当你看到某样你真正喜欢的东西，\n你必须依照纪律去行动。为了解释这种哲学，巴菲特或芒格喜欢用棒球来打比方，\n我觉得特别受启发，虽然我本人根本不算棒球专家。泰德·威廉姆斯是过去 70\n年来惟一一个单个赛季打出 400 次安打的棒球运动员。在《击球的科学》中，他\n阐述了他的技巧。他把击打区划分为 77 个棒球那么大的格子。只有当球落在他\n的“最佳”格子时，他才会挥棒，即使他有可能因此而三振出局，因为挥棒去打\n那些“最差”格子会大大降低他的成功率。作为一个证券投资者，你可以一直观\n察各种企业的证券价格，把它们当成一些格子。在大多数时候，你什么也不用做，\n只要看着就好了。每隔一段时间，你将会发现一个速度很慢、线路又直，而且正','2026-07-05 16:55:53.049000',0,2073692323954429952,68,2073692323514028032),(2073692328274563080,'察各种企业的证券价格，把它们当成一些格子。在大多数时候，你什么也不用做，\n只要看着就好了。每隔一段时间，你将会发现一个速度很慢、线路又直，而且正\n好落在你最爱的格子中间的“好球”，那时你就全力出击。这样呢，不管你的天\n分如何，你都能极大地提高你的上垒率。许多投资者的共同问题是他们挥棒太过\n频繁。无论是个人投资者，还是受“机构行为铁律”所驱使的专业投资者，他们\n都有这种倾向；这种“机构行为铁律”的某一变种也是让我离开同时做长线和短\n线投资的对冲基金的原因。然而，另外一个与挥棒太过频繁相对立的问题也同样\n有害于长期的结果：你发现一个“好球”，却无法用全部的资本去出击。  \n——Louis Li，LL 投资合伙公司 \n   在 2004 年的伯克希尔·哈撒韦年会上，有个年轻的股东问巴菲特怎样才能在生\n活中取得成功。巴菲特分享了他的想法之后，查理插话说：“别吸毒。别乱穿马','2026-07-05 16:55:53.049000',0,2073692323954429952,69,2073692323514028032),(2073692328274563081,'   在 2004 年的伯克希尔·哈撒韦年会上，有个年轻的股东问巴菲特怎样才能在生\n活中取得成功。巴菲特分享了他的想法之后，查理插话说：“别吸毒。别乱穿马\n路。避免染上艾滋病。”许多人以为他这个貌似调侃的回答只是一句玩笑话而已\n（这句话确实很幽默），但实际上它如实反映了查理在生活中避免麻烦的普遍观\n点和他在投资中避免失误的特殊方法。  \n \n        查理一般会先注意应该避免什么，也就是说，先弄清楚应该别做什么事情，\n然后才会考虑接下来要采取的行动。“我只想知道我将来会死在什么地方，这样\n我就可以永远不去那里啦。”这是查理很喜欢的一句妙语。无论是在生活中，还\n是在生意场上，查理避开了“棋盘”上那些无益的部分，把更多的时间和精力用在\n有利可图的区域，从而获得了巨大的收益。查理努力将各种复杂的情况简化为一\n些最基本、最客观的因素。然而，在追求理性和简单的时候，查理也小心翼翼地','2026-07-05 16:55:53.049000',0,2073692323954429952,70,2073692323514028032),(2073692328274563082,'有利可图的区域，从而获得了巨大的收益。查理努力将各种复杂的情况简化为一\n些最基本、最客观的因素。然而，在追求理性和简单的时候，查理也小心翼翼地\n避免他所说的“物理学妒忌”，就是人类那种将非常复杂的系统（比如说经济系统）\n简化为几道牛顿式普遍公式的倾向。他坚定地拥护阿尔伯特·爱因斯坦的本杰\n明·格拉汉姆的影响告诫：“科学理论应该尽可能简单，但不能过于简单。”查理自\n己也说过：“我最反对的是过于自信、过于有把握地认为你清楚你的某次行动是\n利大于弊的。你要应付的是高度复杂的系统，在其中，任何事物都跟其他一切事\n物相互影响。”  \n \n        另外一个本杰明——格拉汉姆，不是富兰克林——也对查理的投资观念的形\n成产生了重要的影响。格拉汉姆的《聪明的投资者》中最具生命力的观念之一是\n“市场先生”。在一般情况下，市场先生是一个脾气温和、头脑理智的家伙，但有','2026-07-05 16:55:53.049000',0,2073692323954429952,71,2073692323514028032),(2073692328274563083,'成产生了重要的影响。格拉汉姆的《聪明的投资者》中最具生命力的观念之一是\n“市场先生”。在一般情况下，市场先生是一个脾气温和、头脑理智的家伙，但有\n时候他也会受到非理性的恐惧或贪婪的驱使。格拉汉姆提醒投资者，对于股票的\n价值，要亲自去作出客观的判断，不能依赖金融市场常见的躁狂抑郁的行为。同\n样地，查理认为，即使是那些最有能力、最有干劲的人，他们的决定也并不总是\n基于理性作出的。正因为如此，他把人类作出错误判断的某些心理因素当做能用\n于判断投资机会的最重要的思维模型：  \n \n        “从个人的角度来讲，我已经养成了使用双轨分析的习惯。首先，理性地看，\n哪些因素真正控制了涉及的利益；其次，当大脑处于潜意识状态时，有哪些潜意\n识因素会使大脑自动以各种方式形成虽然有用但往往失灵的结论？前一种做法\n是理性分析法——就是你在打桥牌时所用的方法，认准真正的利益，找对真正的','2026-07-05 16:55:53.049000',0,2073692323954429952,72,2073692323514028032),(2073692328274563084,'识因素会使大脑自动以各种方式形成虽然有用但往往失灵的结论？前一种做法\n是理性分析法——就是你在打桥牌时所用的方法，认准真正的利益，找对真正的\n机会，等等。后一种做法是评估那些造成潜意识结论——大多数是错误的——的\n心理因素。”（关于这个问题，更详细的讨论请参考第十一篇讲稿，查理在讲稿\n中用心理学的思维模型阐明了人类作出错误判断的 25 种常见诱因。）  \n        很明显，到目前为止描述过的各种方法都不可能在大学课堂或者华尔街学\n到。它们是查理为了满足他自己独特的要求而凭空创造出来的。如果给它们起一\n个共同的名字，那应该是这样的：“迅速歼灭不该做的事情，接着对该做的事情\n发起熟练的、跨学科的攻击，然后，当合适的机会来临——只有当合适的机会来\n临——就采取果断的行动。”努力去培养和坚持这种方法值得吗？查理是这么想\n的：“如果你把自己训练得更加客观，拥有更多学科的知识，那么你在考虑事情','2026-07-05 16:55:53.049000',0,2073692323954429952,73,2073692323514028032),(2073692328278757376,'临——就采取果断的行动。”努力去培养和坚持这种方法值得吗？查理是这么想\n的：“如果你把自己训练得更加客观，拥有更多学科的知识，那么你在考虑事情\n的时候，就能够超越那些比你聪明得多的人，我觉得这是很好玩的。再说了，那\n样还能赚到很多钱，我本人就是个活生生的证据。” \n芒格的投资评估过程 \n \n        “最重要的观念是把股票当成企业的所有权，并根据它的竞争\n优势来判断该企业的持有价值。如果该企业未来的贴现现金流比你现在购买的股\n票价格要高，那么这个企业就具有投资价值。当你占据优势的时候才采取行动，\n这是非常基本的。你必须了解赔率，要训练你自己，在赔率有利于你时才下赌注。\n我们只是低下头，尽最大努力去对付顺风和逆风，每隔几年就摘取结果而已。”  \n \n        正如我们已经看到的，查理投资的项目并不多。也许 IBM 的创','2026-07-05 16:55:53.049000',0,2073692323954429952,74,2073692323514028032),(2073692328278757377,'我们只是低下头，尽最大努力去对付顺风和逆风，每隔几年就摘取结果而已。”  \n \n        正如我们已经看到的，查理投资的项目并不多。也许 IBM 的创\n始人老托马斯·沃森的话最好地概括了查理的方法。托马斯·沃森说：“我不是\n天才。我有几点聪明，我只不过就留在这几点里面。”查理最清楚他的“点”：\n他小心翼翼地划出他的能力圈。为了停留在这些圈子之内，他首先进行了基本的、\n全面的筛选，把他的投资领域局限在“简单而且好理解的备选项目”之内。正如\n他所说的：“关于投资，我们有三个选项：可以投资，不能投资，太难理解。”\n为了确定“可以投资”的潜在项目，查理先选定一个容易理解的、有发展空间的、\n能够在任何市场环境下生存的主流行业。不难理解，能通过这第一道关卡的公司\n很少。例如，许多投资者偏爱的制药业和高科技行业就直接被查理归为“太难理','2026-07-05 16:55:53.049000',0,2073692323954429952,75,2073692323514028032),(2073692328278757378,'能够在任何市场环境下生存的主流行业。不难理解，能通过这第一道关卡的公司\n很少。例如，许多投资者偏爱的制药业和高科技行业就直接被查理归为“太难理\n解”的项目，那些大张旗鼓宣传的“交易”和公开招股则立即被划入“不能投\n资”的项目。那些能够通过第一道关卡的公司还必须接受查理思维模型方法的筛\n选。这个优胜劣汰的过程很费劲，但也很有效果。查理讨厌“披沙拣金”，也就\n是从一大堆沙子里淘洗出几粒小小的金子。他要用“重要学科的重要理论”的方\n法，去寻找别人尚未发现的、有时候躺在一眼就能看见的平地上的大金块。  \n \n        在整个详尽的评估过程中，查理并非数据资料的奴隶：他将各\n种相关因素都考虑在内，包括企业的内部因素和外部因素，以及它所处的行业情\n况，即使这些因素很难被识别、测量或者化约为数字。不过呢，查理的缜密并没\n有让他忘记他的整体的“生态系统观”：有时候最大化或者最小化某个因素（他','2026-07-05 16:55:53.049000',0,2073692323954429952,76,2073692323514028032),(2073692328278757379,'况，即使这些因素很难被识别、测量或者化约为数字。不过呢，查理的缜密并没\n有让他忘记他的整体的“生态系统观”：有时候最大化或者最小化某个因素（他\n最喜欢举好市多仓储超市为例子）能够使那单个因素变得具有与其自身不相称的\n重要性。  \n \n        对待那些财务报告和它们的会计工作，查理总是持中西部特有\n的怀疑态度。它们至多是正确地计算企业真实价值的起点，而不是终点。他要额\n外检查的因素似乎有无穷多，包括当今及未来的制度大气候，劳动力、供应商和\n客户关系的状况，技术变化的潜在影响，竞争优势和劣势，定价威力，环境问题，\n还有很重要的潜在风险变为现实的可能性（查理知道没有无风险的投资项目这种\n东西，他寻找的是那些风险很小、而且容易理解的项目）。他会根据他自己对现\n实的认识，重新调整财务报表上所有的数字，包括实际的自由现金或“所有者”','2026-07-05 16:55:53.049000',0,2073692323954429952,77,2073692323514028032),(2073692328278757380,'东西，他寻找的是那些风险很小、而且容易理解的项目）。他会根据他自己对现\n实的认识，重新调整财务报表上所有的数字，包括实际的自由现金或“所有者”\n现金、产品库存和其他经营性资本资产、固定资产，以及诸如品牌声誉等通常被\n高估的无形资产。他也会评估股票期权、养老金计划、退休医疗福利对现今和将\n来的真实影响。他会同样严格地审查资产负债表中负债的部分。例如，在适当的\n情况下，他也许会认为像保险浮存金——可能许多年也无需赔付出去的保费收入\n——这样的负债更应该被视为资产。他会对公司管理层进行特别的评估，那可不\n是传统的数字运算所能囊括的——具体来说，他会评估他们的“能干、可靠和为\n股东考虑”的程度。例如，他们如何分配现金？他们是站在股东的角度上聪明地\n分配它吗？还是付给他们自己太多的酬劳？或是为了增长而盲目地追求增长？ \n（插文）沃伦和查理论“护城河” \n \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,78,2073692323514028032),(2073692328278757381,'分配它吗？还是付给他们自己太多的酬劳？或是为了增长而盲目地追求增长？ \n（插文）沃伦和查理论“护城河” \n \n \n        巴菲特：“那么，让我们来把护城河、保持它的宽度和保持它\n不被跨越作为一个伟大企业的首要标准。我们告诉我们的经理，我们想要护城河\n每年变宽。那并不意味着今年的利润将会比去年的多，因为有时候这是不可能的。\n然而，如果护城河每年都变宽，企业的经营将会非常好。当我们看到的是一条很\n狭窄的护城河——那就太危险了。我们不知道如何评估那种情况，因此，我们就\n不考虑它了。我们认为我们所有的生意——或者大部分生意——都有挖得很深的\n护城河。我们认为那些经理正在加宽它们。查理你说呢？”  \n        芒格：“你还能讲得比这更好吗？”  \n        巴菲特：“当然。请给这位先生来点花生糖。”  \n——录自 2000 年伯克希尔·哈撒韦年会 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,79,2073692323514028032),(2073692328278757382,'        巴菲特：“当然。请给这位先生来点花生糖。”  \n——录自 2000 年伯克希尔·哈撒韦年会 \n \n        除此之外，他还试图从方方面面——包括产品、市场、商标、\n雇员、分销渠道、社会潮流等等——评估和理解企业的竞争优势以及这种优势的\n持久性。查理认为，一个企业的竞争优势是该企业的“护城河”，是保护企业免\n遭入侵的无形沟壕。优秀的公司拥有很深的护城河，这些护城河不断加宽，为公\n司提供长久的保护。持有这种独特观点的查理谨慎地权衡那些长期围困大多数公\n司的“竞争性毁灭”力量。芒格和巴菲特极其关注这个问题：在漫长的经商生涯\n中，他们了解到，有时是很痛苦地了解到，能够历经数代而不衰的企业非常少。\n因此，他们努力识别而且只购买那些有很大机会击败这些围攻力量的企业。  \n \n        最后，查理会计算整个企业的真正价值，并在考虑到未来股权','2026-07-05 16:55:53.049000',0,2073692323954429952,80,2073692323514028032),(2073692328278757383,'因此，他们努力识别而且只购买那些有很大机会击败这些围攻力量的企业。  \n \n        最后，查理会计算整个企业的真正价值，并在考虑到未来股权\n稀释的情况下，去确定和市场的价格相比，每股的价值大约是多少。后面这种比\n较是整个过程的目标——对比价值（你得到的）和价格（你付出的）。关于这方\n面，他有个著名的观点：“（购买）股价公道的伟大企业比（购买）股价超低的\n普通企业好。”巴菲特经常说，是查理让他更加坚信这种方法的智慧：“查理很\n早就懂得这个道理，我是后来才明白的。”查理的睿见帮助巴菲特摆脱纯粹的本\n杰明·格拉汉姆式投资，转而关注一些伟大的企业，比如《华盛顿邮报》、政府\n职员保险公司（GEIGO）、可口可乐、吉列等等。  \n \n        查理虽然极其仔细，但不会像其他人那样，有时候深受无关紧\n要的细节和旁骛之害。查理在分析的过程中会逐步排除一些投资变量，就像他排','2026-07-05 16:55:53.049000',0,2073692323954429952,81,2073692323514028032),(2073692328278757384,' \n        查理虽然极其仔细，但不会像其他人那样，有时候深受无关紧\n要的细节和旁骛之害。查理在分析的过程中会逐步排除一些投资变量，就像他排\n除其他变量那样。等到分析结束时，他已经将候选投资项目简化为一些最显著的\n要素，也完全有信心决定到底要不要对其进行投资。价值评估到最后变成了一种\n哲学的评估，而不是数学的衡量。在分析本身和查理毕生积累的经验及其在认知\n模型方面的技巧的共同作用之下，他最终能够得到一种投资“感觉”。  \n \n        到了这个时候，剩下的必定是一家极其优秀的候选投资公司。\n但查理并不会立刻冲出去购买它的股票。他知道在正确地评估股票的价值之后，\n还必须在正确的时间买入，所以他会进行更精细的筛选，也就是“扣动扳机之\n前”的检查。当需要短时间内完成评估（他称之为“急诊”）的时候，这种方法\n特别有用。检查清单上的项目如下：目前的价格和成交量是多少？交易行情如','2026-07-05 16:55:53.049000',0,2073692323954429952,82,2073692323514028032),(2073692328278757385,'前”的检查。当需要短时间内完成评估（他称之为“急诊”）的时候，这种方法\n特别有用。检查清单上的项目如下：目前的价格和成交量是多少？交易行情如\n何？经营年报何时披露？是否存在其他敏感因素？是否存在随时退出投资的策\n略？用来买股票的钱现在或将来有更好的用途吗？手头上有足够的流动资金\n吗？或者必须借贷？这笔资金的机会成本是多少？诸如此类。 \n \n \n \n \n \n        在稀有的“黄金时机”，如果所有条件都刚刚好，查\n理决定要投资，那么他很可能会决心下很大的赌注。他绝不会小打小闹，\n或者进行“小额的投机性的投资”。这类行为包含着不确定性，然而查\n理为数极少的投资行为却绝不是不确定的。正如他说过的，他的投资行\n为“结合了极度的耐心和极度的决心”。查理自信的来源并非谁或者多\n少人同意或反对他的观点，而是客观地看待和衡量自己的能力。这种自','2026-07-05 16:55:53.049000',0,2073692323954429952,83,2073692323514028032),(2073692328278757386,'为“结合了极度的耐心和极度的决心”。查理自信的来源并非谁或者多\n少人同意或反对他的观点，而是客观地看待和衡量自己的能力。这种自\n知之明使他在衡量他的实际知识、经验和思维的正确性时，能够拥有一\n种罕见的客观态度。在这里，我们再次看到，良好的个性素质——自律、\n耐心、冷静、独立——扮演了重要角色。如果缺乏这些品质，查理恐怕\n不可能取得如此杰出的投资业绩。 \n 查理这种伟大的商业模式是怎么来的呢？我们可以从他推荐的阅读书目（见附\n录）中看出一些端倪。《枪炮、病菌与钢铁》《自私的基因》《冰河世纪》和《达\n尔文的盲点》都有一个共同的主题：关注前面提到的“竞争性毁灭”问题，研究\n为什么有些事物能够适应环境，存活下来，甚至在经过很长的时间之后占据统治\n地位。当这个主题被应用于投资选择时，芒格偏爱的企业就出现了：有些是通过\n消灭竞争对手而达到繁荣的企业（就像《自私的基因》里面描绘的），有些是通','2026-07-05 16:55:53.049000',0,2073692323954429952,84,2073692323514028032),(2073692328282951680,'地位。当这个主题被应用于投资选择时，芒格偏爱的企业就出现了：有些是通过\n消灭竞争对手而达到繁荣的企业（就像《自私的基因》里面描绘的），有些是通\n过合作而兴旺的企业（《达尔文的盲点》）。我们再次看到，查理能够熟练地应\n用许多学科的知识：有多少投资者能够像查理经常做的那样，考虑到如此之多、\n如此之复杂的因素呢？简要举几个例子，他经常思考的因素包括“转换”——比\n如热力学的定律跟经济学的定律有何相似之处（例如纸张和石油如何变成一份投\n递到门口的报纸），心理倾向和激励因素（尤其是它们创造的极端行为压力，无\n论是好的压力还是坏的压力），以及基本的长期可持续发展性（诸如“护城河”\n之类的正面因素和竞争性毁灭的破坏之间持续不断而且往往非常致命的相互影\n响）。查理极其熟练地掌握了各种不同的学科，所以能够在投资时考虑到许多普\n通人不会考虑的因素，就这方面而言，也许没有人可以和他相提并论。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,85,2073692323514028032),(2073692328282951681,'响）。查理极其熟练地掌握了各种不同的学科，所以能够在投资时考虑到许多普\n通人不会考虑的因素，就这方面而言，也许没有人可以和他相提并论。 \n（插文）价格是你付出的，价值是你得到的 \n \n \n        价值投资者往往会招致别人的怀疑，美国几次精明的土地收购\n就是这样的。1803 年，托马斯·杰弗逊政府花费 1500 万美元和拿破仑的法国政\n府达成了路易斯安那交易，平均每英亩土地的价格是 2.9 美分。1867 年，美国\n政府用价值 720 万美元的黄金向俄罗斯收购了阿拉斯加地区，每英亩土地的价格\n大约是 2.5 美分，这在当时被称为“锡瓦德的愚蠢交易”。相比之下，在 2006\n年，阿拉斯加交易所涉及土地的价格等于 16700 亿美元，根据美国获得的石油、\n矿产价值和战略优势来衡量的话，这桩交易当然不是愚蠢的。 \n投资原则检查清单 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,86,2073692323514028032),(2073692328282951682,'年，阿拉斯加交易所涉及土地的价格等于 16700 亿美元，根据美国获得的石油、\n矿产价值和战略优势来衡量的话，这桩交易当然不是愚蠢的。 \n投资原则检查清单 \n \n        我们现在已经了解了查理的总体思维方式和他的投资思维方\n式。为了继续关注“他是如何做到的”，我们将会使用他推崇的“检查清单”检\n验法来再次展现他的方法（若要了解查理本人关于价值和检查清单的重要性的说\n法，请参见第四章的第五讲和第 320 页）。然而，要注意的是，查理当然不会按\n照清单上的次序逐一应用下面这些原则，这些原则出现的先后也跟它们的重要性\n无关。每个原则都必须被视为整个复杂的投资分析过程的一部分，就像整幅马赛\n克图案中每个单独的小块那样。  \n \n        我们现在已经了解了查理的总体思维方式和他的投资思维方\n式。为了继续关注“他是如何做到的”，我们将会使用他推崇的“检查清单”检','2026-07-05 16:55:53.049000',0,2073692323954429952,87,2073692323514028032),(2073692328282951683,' \n        我们现在已经了解了查理的总体思维方式和他的投资思维方\n式。为了继续关注“他是如何做到的”，我们将会使用他推崇的“检查清单”检\n验法来再次展现他的方法（若要了解查理本人关于价值和检查清单的重要性的说\n法，请参见第四章的第五讲和第 320 页）。然而，要注意的是，查理当然不会按\n照清单上的次序逐一应用下面这些原则，这些原则出现的先后也跟它们的重要性\n无关。每个原则都必须被视为整个复杂的投资分析过程的一部分，就像整幅马赛\n克图案中每个单独的小块那样。  \n风险——所有投资评估应该从测量风险（尤其是信用的风险）开始  \n• 测算合适的安全边际  \n• 避免和道德品质有问题的人交易  \n• 坚持为预定的风险要求合适的补偿  \n• 永远记住通货膨胀和利率的风险  \n• 避免犯下大错；避免资本金持续亏损  \n独立——“惟有在童话中，皇帝才会被告知自己没穿衣服”  ','2026-07-05 16:55:53.049000',0,2073692323954429952,88,2073692323514028032),(2073692328282951684,'• 永远记住通货膨胀和利率的风险  \n• 避免犯下大错；避免资本金持续亏损  \n独立——“惟有在童话中，皇帝才会被告知自己没穿衣服”  \n• 客观和理性的态度需要独立思考  \n• 记住，你是对是错，并不取决于别人同意你还是反对你——惟一重要的是\n你的分析和判断是否正确  \n• 随大流只会让你往平均值靠近（只能获得中等的业绩）  \n准备——“惟一的获胜方法是工作、工作、工作、工作，并希望拥有一点\n洞察力。”  \n• 通过广泛的阅读把自己培养成一个终生自学者；培养好奇心，每天努力使\n自己聪明一点点  \n• 比求胜的意愿更重要的是做好准备的意愿  \n• 熟练地掌握各大学科的思维模型  \n• 如果你想要变得聪明，你必须不停地追问的问题是“为什么，为什么，为\n什么”  \n谦虚——承认自己的无知是智慧的开端  \n• 只在自己明确界定的能力圈内行事  \n• 辨认和核查否定性的证据  ','2026-07-05 16:55:53.049000',0,2073692323954429952,89,2073692323514028032),(2073692328282951685,'什么”  \n谦虚——承认自己的无知是智慧的开端  \n• 只在自己明确界定的能力圈内行事  \n• 辨认和核查否定性的证据  \n• 抵制追求虚假的精确和错误的确定性的欲望  \n• 最重要的是，别愚弄你自己，而且要记住，你是最容易被自己愚弄的人  \n严格分析——使用科学方法和有效的检查清单能够最大限度地减少错误\n和疏忽  \n• 区分价值和价格、过程和行动、财富和规模  \n• 记住浅显的好过掌握深奥的  \n• 成为一名商业分析家，而不是市场、宏观经济或者证券分析家  \n• 考虑总体的风险和效益，永远关注潜在的二阶效应和更高层次的影响  \n• 要朝前想、往后想——反过来想，总是反过来想  \n耐心——克制人类天生爱行动的偏好  \n• “复利是世界第八大奇迹”（爱因斯坦），不到必要的时候，别去打断它  \n• 避免多余的交易税和摩擦成本，永远别为了行动而行动  \n• 幸运来临时要保持头脑清醒  ','2026-07-05 16:55:53.049000',0,2073692323954429952,90,2073692323514028032),(2073692328282951686,'• 避免多余的交易税和摩擦成本，永远别为了行动而行动  \n• 幸运来临时要保持头脑清醒  \n• 享受结果，也享受过程，因为你活在过程当中  \n决心——当合适的时机出现时，要坚决地采取行动  \n• 当别人贪婪时，要害怕；当别人害怕时，要贪婪  \n• 机会来临的次数不多，所以当它来临时，抓住它  \n• 机会只眷顾有准备的人：投资就是这样的游戏  \n改变——在生活中要学会改变和接受无法消除的复杂性  \n• 认识和适应你身边的世界的真实本质，别指望它来适应你  \n• 不断地挑战和主动地修正你“最爱的观念”  \n• 正视现实，即使你并不喜欢它——尤其当你不喜欢它的时候  \n专注——别把事情搞复杂，记住你原来要做的事  \n• 记住，声誉和正直是你最有价值的财产——而且能够在瞬间化为乌有  \n• 避免妄自尊大和厌倦无聊的情绪  \n• 别因为过度关心细节而忽略了显而易见的东西  ','2026-07-05 16:55:53.049000',0,2073692323954429952,91,2073692323514028032),(2073692328282951687,'• 记住，声誉和正直是你最有价值的财产——而且能够在瞬间化为乌有  \n• 避免妄自尊大和厌倦无聊的情绪  \n• 别因为过度关心细节而忽略了显而易见的东西  \n• 千万要排除不需要的信息：“千里之堤，溃于蚁穴”  \n• 直面你的大问题，别把它们藏起来  \n•  \n        自从人类开始投资以来，他们就一直在寻找能够快速致\n富的神奇公式或者捷径。正如你已经看到的，查理的优异业绩并非来自一\n道神奇公式或者某些商学院教导的体系，它来自查理所说的“不停地寻找\n更好的思维方式的追求”，通过一丝不苟的准备进行“预付”的意愿，以\n及他跨学科研究模式的非凡后果。总而言之，它来自查理最基本的行为守\n则，最根本的人生哲学：准备、纪律、耐心、决心。每个因素都是互不相\n干的，但它们加起来就变成了威力强大的临界物质，能够催化那种因芒格\n而闻名的 lollapalooza 效应。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,92,2073692323514028032),(2073692328282951688,'干的，但它们加起来就变成了威力强大的临界物质，能够催化那种因芒格\n而闻名的 lollapalooza 效应。  \n \n        最后，简单来讲一下这篇概述芒格投资哲学的文章极其\n关注“买什么”而极少关注“何时卖”的原因。芒格亲自对这个问题作出\n了回答，下面这段话很好地概述了高度集中专注的“芒格学派”的投资哲\n学：  \n \n        “我们偏向于把大量的钱投放在我们不用再另外作决\n策的地方。如果你因为一样东西的价值被低估而购买了它，那么当它的价\n格上涨到你预期的水平时，你就必须考虑把它卖掉。那很难。但是，如果\n你能购买几个伟大的公司，那么你就可以安坐下来啦。那是很好的事情。”  \n \n        如同他的偶像本杰明·富兰克林那样，查理·芒格努力\n培养并完善了他独特的生活和经商方法。通过这些方法以及终生培养和维\n护的良好习惯，他取得了非凡的成功。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,93,2073692323514028032),(2073692328282951689,'培养并完善了他独特的生活和经商方法。通过这些方法以及终生培养和维\n护的良好习惯，他取得了非凡的成功。  \n \n• （插文）查理的总结 \n•  \n        “为什么有些人会比其他人聪明呢？这跟与生俱来的\n性格有部分的关系。有些人的性格并不适合投资。他们总是按捺不住，或\n者总是忧心忡忡。但如果你拥有好的性格，在这里主要是指非常有耐心，\n又能够在你知道该采取行动时主动出击，那么你就能通过实践和学习逐渐\n了解这种游戏。很明显，你吸取教训的来源越广泛，而不仅仅从你自己的\n糟糕经验中吸取教训，你就能变得越好。  \n \n        “我还没发现有谁能够很快做到这一点。作为投资者，\n沃伦·巴菲特比我第一次遇到他时好得太多了，我也是这样的。如果我们\n在某个阶段停滞不前，满足于已经拥有的知识，我们的业绩会比现在差得\n多。所以诀窍就在于不断学习，而且我不认为那些不享受学习过程的人能\n够不断地学习。” ','2026-07-05 16:55:53.049000',0,2073692323954429952,94,2073692323514028032),(2073692328282951690,'在某个阶段停滞不前，满足于已经拥有的知识，我们的业绩会比现在差得\n多。所以诀窍就在于不断学习，而且我不认为那些不享受学习过程的人能\n够不断地学习。” \n• 诚实是最好的策略 \n \n        由于深受故乡（美国中西部）文化的影响，查理·芒格向来是\n诚实和正直的同义词。正如查理曾经说过的：“做正确的事情能给个人的品格和\n事业带来很大的好处。”查理有多么诚实和正直，他的女儿温蒂最有发言权。温\n蒂说，在水门事件发生之后，她很同情理查德·尼克松的女儿，因为大家都知道\n她们的父亲品行有亏。“我完全相信我爸爸不会让我们陷入相同的处境。我无法\n告诉你那给我的感觉有多么好。”  \n \n        我们曾经找到传奇的债券投资专家比尔·格罗斯（太平洋投资\n管理公司），问他如何评价查理的诚实。他的回答是这样的：“如果东海岸和西\n海岸同时被海水淹没，不管是由于风暴、地震还是道德沦丧，芒格的奥马哈将依','2026-07-05 16:55:53.049000',0,2073692323954429952,95,2073692323514028032),(2073692328282951691,'管理公司），问他如何评价查理的诚实。他的回答是这样的：“如果东海岸和西\n海岸同时被海水淹没，不管是由于风暴、地震还是道德沦丧，芒格的奥马哈将依\n然会存在。应该用卫星将查理的道德标准播送到世界各地的金融中心，以便防止\n未来再出现安然或世通之类的丑闻。  \n \n        “查理和沃伦是极好的榜样和教师，对青年人来说更是如此。\n阿尔伯特·施威策尔说：‘榜样在教学中不是主要的东西——它是惟一的东\n西。’在持续终生的商业‘赛跑’中，查理和沃伦不但处于领先地位，而且沿途\n还从来不抄近道。  \n \n        “人们无法在金融界找出比沃伦·巴菲特和查理·芒格更具\n榜样意义的诚实人物。他们的年报就像传奇，不仅讲述了真正的投资智慧，而且\n在有必要时也不惮于自责。”  \n \n        瑞克·格伦是查理的老友和商业伙伴，他补充说：  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,96,2073692323514028032),(2073692328287145984,'在有必要时也不惮于自责。”  \n \n        瑞克·格伦是查理的老友和商业伙伴，他补充说：  \n \n        “我曾有两次看到查理在商业交易中付出了比他需要支付的\n金额更多的钱。第一次是在我们收购一家企业的时候，当时有两位老太太持有该\n企业发行的债券，我们本来很容易以远低于面值的价格收购这些债券——但是查\n理却按照面值给她们钱。第二次是在我需要一些现金去做另外一项投资的时候。\n当时我想要把我们合资成立的公司的一半股权卖给他，他说你开个价——我说\n13 万美元，他说不行，23 万美元才对，他真给了我那么多钱。这给查理抓到机\n会说出一句他非常喜欢的台词：‘我是对的，你很聪明，迟早你将会明白我是对\n的。’当然啦，他这两点都说对了——他给出的价格确实更准确，而我最终也确\n实明白了这一点。  \n \n        “在股票交易所占价格低廉的股票便宜是一回事，但是占合伙','2026-07-05 16:55:53.049000',0,2073692323954429952,97,2073692323514028032),(2073692328287145985,'实明白了这一点。  \n \n        “在股票交易所占价格低廉的股票便宜是一回事，但是占合伙\n人或者老太太便宜是另外一回事——这是查理绝对不会做的事。”  \n \n        查理论诚实： \n在 2004 年西科年会上的讲话 \n•  \n        “过去坐在我今天所坐椅子上的是路易斯·文森狄，他\n以前曾经说：‘如果你说真话，你就不用记住你的谎言啦。’我们不想搞\n得太复杂，所以总是说实话。由于拥有如此之多长期以来不离不弃的股东，\n我们无需为哪个季度的盈利上涨或下跌而烦恼——至少我们无需在乎它\n们给股东造成的影响。我们显然喜欢盈利多过喜欢亏损，但我们并不愿意\n操控任何东西来让某些季度的业绩显得更好看一些，那么做和我们的道德\n标准相差太远了。  \n \n        “就过往的情况来看，我认为这个地方比绝大多数地方\n都更加努力地争取做到理性。而且我认为它比绝大多数地方更加努力地去','2026-07-05 16:55:53.049000',0,2073692323954429952,98,2073692323514028032),(2073692328287145986,'标准相差太远了。  \n \n        “就过往的情况来看，我认为这个地方比绝大多数地方\n都更加努力地争取做到理性。而且我认为它比绝大多数地方更加努力地去\n争取做到有道德——这意味着说真话，不乱搞。现在伯克希尔·哈撒韦有\n175000 名员工，大概有这么多人，我坐在这里，我敢打赌，他们之中至\n少有一个人正在做让我感到非常懊恼的事情。然而，尽管有些人会乱来，\n我们公司在过去几十年里很少遇到什么诉讼或者丑闻之类的事情。人们注\n意到了这一点。  \n \n        “我们认为，有些事情就算你能做，而且做了不会受到\n法律的制裁，或者不会造成损失，你也不应该去做。你应该有一条底线。\n你心里应该有个指南针。所以有很多事情你不会去做，即使它们完全是合\n法的。这就是我们试图做到的经营方式。  \n \n        “我觉得我们不应该由此而得到太多的赞誉，因为我们','2026-07-05 16:55:53.049000',0,2073692323954429952,99,2073692323514028032),(2073692328287145987,'法的。这就是我们试图做到的经营方式。  \n \n        “我觉得我们不应该由此而得到太多的赞誉，因为我们\n很早就知道，这种经营方式能让我们赚更多的钱。而由于我们对此十分了\n解，我不确定我们是否有资格被视为道德高尚的人。  \n \n        “当然，要了解自己的动机是很难的。但我愿意相信，\n就算这种经营方式并没有给我们带来许多经济上的好处，我们也会这样做\n好。而且每隔一段时间，我们就会有机会证明这一点。但更多的时候，我\n们由于固守道德而赚到更多的钱。在我们看来，本杰明·富兰克林是对的。\n他并没有说诚实是最好的道德品质，他说诚实是最好的策略。” \n• “我没有什么要补充的”第一篇 \n•  \n        有时候，查理会向他的听众提出一个很难回答的问题，\n或者在被问到很难回答的问题时置之不理。他说他这么做是为了鼓励听众\n亲自去“寻找”答案，从而更好地了解和掌握他们发现的信息。查理说他','2026-07-05 16:55:53.049000',0,2073692323954429952,100,2073692323514028032),(2073692328287145988,'或者在被问到很难回答的问题时置之不理。他说他这么做是为了鼓励听众\n亲自去“寻找”答案，从而更好地了解和掌握他们发现的信息。查理说他\n父亲从前常常对他使用这种技巧，让他到今天还受用不尽。  \n•  \n•  \n        为了履行通过这本书来展现查理的智慧和妙语的承诺，\n我们觉得有责任和义务来回答查理长久以来留给我们去“寻找”答案然\n而我们又未能彻底掌握的谜团和问题。  \n \n        我们先从1994年10月6日查理在哈佛教职员俱乐部发\n表题为“人类误判心理学”的演讲时的一个问题开始：  \n \n        问：你提到沃伦·巴菲特对待公开竞拍的原则——“别\n去”。然后你还说：“我们也不参加封闭式投标拍卖（亦即招标），不过\n那是出于另外一个原因，一个萨克豪瑟会理解的原因。”  \n \n        萨克豪瑟——他是哈佛教授，也是桥牌高手。封闭式投','2026-07-05 16:55:53.049000',0,2073692323954429952,101,2073692323514028032),(2073692328287145989,'那是出于另外一个原因，一个萨克豪瑟会理解的原因。”  \n \n        萨克豪瑟——他是哈佛教授，也是桥牌高手。封闭式投\n标拍卖的问题与公开竞拍不同，赢得拍卖的往往是那些犯了技术错误的\n人，壳牌花两倍价钱买下贝尔里奇石油公司的情况就是如此。在公开竞拍\n的拍卖会上，你付的价钱不可能是你击败的对手的两倍。你不会遇到这样\n的问题，你会遇到别的问题。但封闭式投标拍卖使人们容易犯下定错价的\n大错。  \n \n        （你可以在全书各章找到更多的“我没有什么要补充\n的”的时刻。） \n \n第三章 \n芒格主义：查理的即席谈话 \n \n \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        智者的聪慧和长者的经验，也许能够通过语录得以保存。  \n——埃萨克·狄斯雷利 \n \n        沃伦·巴菲特和查理·芒格毫无疑问是有史以来最伟大的投','2026-07-05 16:55:53.049000',0,2073692323954429952,102,2073692323514028032),(2073692328287145990,'——埃萨克·狄斯雷利 \n \n        沃伦·巴菲特和查理·芒格毫无疑问是有史以来最伟大的投\n资二人组，所以如果有投资者不去尽可能多地了解这两个人，尽可能多地学习他\n们如何取得成功，那么这个投资者就是——用查理很喜爱的一个词来说——“疯\n子”。  \n \n        但是向沃伦和查理学习的真正乐趣并不在于人们能够了解大\n量关于如何在长时间内让金钱以很高的复利增长的知识——尽管这当然是一种\n很不错的额外收获——而是在于通过听取他们的教导，人们将能够更加深刻地理\n解人类的本性、世界的现状、如何理性思考，以及最重要的，如何更好地过上一\n种正直、幸福、善良的生活（提示：这三种要素是相辅相成的）。向沃伦学习并\n不难——写他的书有很多本；他经常发表演讲，撰写文章，出席公众场合；几十\n年来，他每年都会发表一篇很长的信件（你可以在伯克希尔·哈撒韦网站上免费','2026-07-05 16:55:53.049000',0,2073692323954429952,103,2073692323514028032),(2073692328287145991,'不难——写他的书有很多本；他经常发表演讲，撰写文章，出席公众场合；几十\n年来，他每年都会发表一篇很长的信件（你可以在伯克希尔·哈撒韦网站上免费\n阅读最近的 30 封信，网址是 www.berkshirehathaway.com；如果你还没去看过，\n那你还在等什么呢？！）但查理就神秘多了：关于他的书只有两本，和沃伦相比，\n他发表的演讲和撰写的文章要少得多。  \n \n \n        由于这个原因，许多人并不知道查理本人是个天才，而\n且他对沃伦的投资哲学产生了深刻的影响，这一点沃伦是公开承认的。他\n们之间的互动会让观者忍俊不禁。在伯克希尔年会的主席台上，沃伦一般\n会率先回答提问，但然后往往会转过身说：“查理，你说呢？”查理的典\n型反应是一动不动、面无表情地（人们很容易用一个假人来代替他，在大\n多数情况下保管没有人会发现）说：“我没有什么要补充的。”这九个字','2026-07-05 16:55:53.049000',0,2073692323954429952,104,2073692323514028032),(2073692328287145992,'型反应是一动不动、面无表情地（人们很容易用一个假人来代替他，在大\n多数情况下保管没有人会发现）说：“我没有什么要补充的。”这九个字\n已经变成了查理的标志，通常让沃伦和听众会心一笑。（实际上，1998\n年 9 月，在为收购通用再保险公司而召开的特别大会上，沃伦真的用一个\n硬纸板做成的查理人像和一段查理说“我没有什么要补充的”的录音出\n现在主席台上。我的一个朋友参加了该大会，据他说，“沃伦大概播了六\n次这段录音，每次都会露出顽皮的神色。”）这几个字也反映了查理古怪\n的脾气——至少他的公众形象是这样的——以及这两个心灵相通的杰出\n生意人“合二为一”的关系。  \n \n        但每当查理确实有话要补充，那么他说的话往往很尖\n锐、很深刻，而且他也不会拐弯抹角。用他自己的话来说，查理是一个“古\n怪的、老派的”人，而且从来不为政治正确而担忧——他想到什么就说什\n么。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,105,2073692323514028032),(2073692328287145993,'锐、很深刻，而且他也不会拐弯抹角。用他自己的话来说，查理是一个“古\n怪的、老派的”人，而且从来不为政治正确而担忧——他想到什么就说什\n么。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        但每当查理确实有话要补充，那么他说的话往往很尖锐、很深\n刻，而且他也不会拐弯抹角。用他自己的话来说，查理是一个“古怪的、老派的”\n人，而且从来不为政治正确而担忧——他想到什么就说什么。  \n \n        因为在伯克希尔年会上，大多数讲话都是由沃伦来发表，所以\n我总是喜欢参加几天后在帕萨迪纳举行的西科年会，去领略查理深邃的思想（他\n是西科金融公司的主席，西科是一家结构和伯克希尔相同的控股公司，后者拥有\n西科 80.1%的股份）。人们不用是股东也可以参加；查理——就像他和沃伦在伯','2026-07-05 16:55:53.049000',0,2073692323954429952,106,2073692323514028032),(2073692328287145994,'是西科金融公司的主席，西科是一家结构和伯克希尔相同的控股公司，后者拥有\n西科 80.1%的股份）。人们不用是股东也可以参加；查理——就像他和沃伦在伯\n克希尔年会上那样——欢迎所有来到格拉汉姆、多德、巴菲特和芒格教堂的朝圣\n者。我从来不曾后悔从奥马哈回来没几天就长途奔波，横跨大半个美国去听查理\n演讲，因为他的思维依然处在巅峰状态。在 2003 年的会议上，查理作出一个又\n一个充满睿见的点评，我有个朋友侧过身来，低声对我说：“真难相信他已经\n80 岁了！”确实如此！  \n \n        作为导师和思想家，查理同沃伦旗鼓相当，我从他那里学到了\n很多知识，所以当我听到彼得·考夫曼正在编撰这本书时，我感到特别高兴，马\n上就同意为此尽绵薄之力！  \n \n        查理的正式文章和讲稿遍布全书，本章的目的是对它们进行补\n充。这部分内容是从过去五年我在伯克希尔和西科的年会上所作的记录中抽取出','2026-07-05 16:55:53.049000',0,2073692323954429952,107,2073692323514028032),(2073692328287145995,' \n        查理的正式文章和讲稿遍布全书，本章的目的是对它们进行补\n充。这部分内容是从过去五年我在伯克希尔和西科的年会上所作的记录中抽取出\n来的，包括了查理在这些会议上说过的最有洞察力、最发人深思、最抒发胸臆、\n最好玩有趣的话。由于他的大多数发言都是为了回应股东的提问，所以他广泛地\n谈论了伯克希尔·哈撒韦的情况，还有许多和商业、投资相关的话题。  \n \n        为了让查理的教诲更加容易被接受，我依照话题对它们进行了\n组织，也稍微做了些编辑工作，但目的是让他亲自说出他的话。请尽情享受吧！  \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n我们成功的关键 \n \n        1. 如果乌龟能够吸取它那些最棒前辈的已经被实践所证明的\n洞见，有时候它也能跑赢那些追求独创性的兔子或者跑赢宁愿跻身那些忽略前人','2026-07-05 16:55:53.049000',0,2073692323954429952,108,2073692323514028032),(2073692328291340288,' \n        1. 如果乌龟能够吸取它那些最棒前辈的已经被实践所证明的\n洞见，有时候它也能跑赢那些追求独创性的兔子或者跑赢宁愿跻身那些忽略前人\n最优秀的工作的蠢货之列的兔子。乌龟若能找到某些特别有效的方法来应用前人\n最伟大的工作，或者只要能避免犯下常见的错误，这种情况就会发生。我们赚钱，\n靠的是记住浅显的，而不是掌握深奥的。我们从来不去试图成为非常聪明的人，\n而是持续地试图别变成蠢货，久而久之，我们这种人便能获得非常大的优势。  \n \n        2. 我们并不自称是道德高尚的人，但至少有很多即便合法的\n事情，也是我们不屑去做的。我们不会去做那些事情。目前美国有种文化认为，\n所有不会把你送进监狱的事情都是可以做的事情。  \n \n        我们认为，在你应该做的事情和就算你做了也不会受到法律制\n裁的事情之间应该有一条巨大的鸿沟。我想你应该远离那条线。我觉得我们不应','2026-07-05 16:55:53.049000',0,2073692323954429952,109,2073692323514028032),(2073692328291340289,' \n        我们认为，在你应该做的事情和就算你做了也不会受到法律制\n裁的事情之间应该有一条巨大的鸿沟。我想你应该远离那条线。我觉得我们不应\n该由此而得到太多的赞誉。这样做事的原则帮我们赚到更多的钱。我相信就算这\n种经营方式没有给我们赚这么多钱，我们也不会做坏事。但更多的时候，我们由\n于做正确的事情而赚到更多的钱。  \n \n \n        记住路易斯·文森狄的规则：说真话，你将无须记住你\n的谎言。就是这么简单的一个概念。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n论伯克希尔·哈撒韦 \n \n伯克希尔是一家极好的企业 \n \n        我们就像（伯林教授所讲的）刺猬，只知道一个大道理：如果\n你能够用 3%的利率吸取浮存金（指理赔之前伯克希尔能够用于投资的现金保费','2026-07-05 16:55:53.049000',0,2073692323954429952,110,2073692323514028032),(2073692328291340290,' \n        我们就像（伯林教授所讲的）刺猬，只知道一个大道理：如果\n你能够用 3%的利率吸取浮存金（指理赔之前伯克希尔能够用于投资的现金保费\n收入），然后将其投资给某家能够带来 13%的收益的企业，那么这就是一桩很好\n的生意。  \n \n        伯克希尔收购的企业能够给我们带来的税前回报率是 13%，也\n许还要更多一点。由于资本成本利率只有 3%——这些资本金是别人的钱，以浮\n存金的形式得到的——这就是非常棒的生意。所以伯克希尔的股东完全不必感到\n绝望。就复合回报率而言，伯克希尔是没以前那么好，但它仍然是一家极好的企\n业。  \n \n        我不喜欢当乐观主义者，但过去几年，我们确实为伯克希尔增\n加了好多很棒的企业。 \n伯克希尔以前的回报 \n \n        伯克希尔以往的业绩好到几近荒谬。如果伯克希尔愿意举债经','2026-07-05 16:55:53.049000',0,2073692323954429952,111,2073692323514028032),(2073692328291340291,'加了好多很棒的企业。 \n伯克希尔以前的回报 \n \n        伯克希尔以往的业绩好到几近荒谬。如果伯克希尔愿意举债经\n营，比如说吧，就算负债率只有鲁珀特·默多克（新闻集团）的一半，它的规模\n也应该是现在的 5倍。 \n伯克希尔的未来展望 \n \n        一个人可以做的最聪明的事之一是调低投资预期，尤其\n是调低对伯克希尔的收益的预期。那是成熟而负责任的表现。我喜欢我们\n的模式，我们应该做得不错。  \n \n        伯克希尔的未来不容乐观，原因有两点：  \n \n        1. 我们的规模太大了。这迫使我们只能投资那些竞争\n更为激烈的领域，一些非常聪明的人也在研究这些领域，比如说爱丽\n丝·施罗德（她是保险分析专家，曾先后供职于普惠和摩根士丹利，当时\n正坐在听众席上）。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,112,2073692323514028032),(2073692328291340292,'正坐在听众席上）。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        2. 从当前的大气候来看，在未来 15 到 20 年里，普通的股票\n市场不会像我们在过去 15 到 20 年中体验到的那么景气。请参看沃伦发表在《财\n富》杂志上的文章——我完全赞同那篇文章的观点。（“巴菲特先生论股票市\n场”，1999 年 11 月 22 日）  \n \n        在未来 20 年里，伯克希尔·哈撒韦的市值将会增加，但可以\n肯定的是，每年的增长率将会比以前低得多。  \n \n        但这并不是悲剧。我们很满意。伯克希尔·哈撒韦和西科的现\n金每年都在增加，我们的结构使我们拥有很大的回旋余地。虽然我们规模太大，\n不可能去购买小公司的股票，但我们在收购整体出售给我们的公司时占有优势。','2026-07-05 16:55:53.049000',0,2073692323954429952,113,2073692323514028032),(2073692328291340293,'金每年都在增加，我们的结构使我们拥有很大的回旋余地。虽然我们规模太大，\n不可能去购买小公司的股票，但我们在收购整体出售给我们的公司时占有优势。\n我们总是能够遇到很好的机会。我不感到丧气，但我认为你们放在这里的钱，不\n会用于你们以前习惯看到的事情。  \n \n        这个世界是有限的，竞争非常激烈。所有资金庞大的企业最终\n都会发现增长变得越来越难，从而将会发现回报率变得越来越低。  \n \n        我个人认为伯克希尔将来会比现在大得多，强得多。至于这支\n股票未来会不会是一个好的投资，那是另外一个问题。我们总是能够保证的事情\n是，未来将会比过去差很多。  \n \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        在未来，伯克希尔和西科的收益将不会像过去那么好。（所有','2026-07-05 16:55:53.049000',0,2073692323954429952,114,2073692323514028032),(2073692328291340294,'录） \n \n        在未来，伯克希尔和西科的收益将不会像过去那么好。（所有\n大型成功企业的情况都是这样的。）惟一的区别是我们会告诉你们。 \n伯克希尔·哈撒韦的文化 \n \n        我们的文化是非常老派的，像本杰明·富兰克林或安德鲁·卡\n内基的文化。你能想像卡内基聘请公司顾问吗？！让人吃惊的是，这种方法现在\n仍然非常有效。我们收购的企业有许多都像我们这样古怪而老派。  \n \n        对于我们的许多股东而言，我们的股票是他们拥有的一切，我\n们非常清楚这一点。我们的（保守主义）文化发挥的作用非常深远。  \n \n        这里是个非常可靠的地方。我们比绝大多数其他地方更能抵御\n灾难。我们不会像别人那样盲目扩张。  \n \n        我很高兴我有 90%的净资产是在伯克希尔的股票里。我们将会\n在避免不合理的风险和负债的前提下，努力使它保持合理的增长率。如果我们做','2026-07-05 16:55:53.049000',0,2073692323954429952,115,2073692323514028032),(2073692328291340295,' \n        我很高兴我有 90%的净资产是在伯克希尔的股票里。我们将会\n在避免不合理的风险和负债的前提下，努力使它保持合理的增长率。如果我们做\n不到这一点，那就真的太糟糕了。 \n伯克希尔和西科的股票价格 \n \n        我们希望伯克希尔和西科的股票价格和我们认为它们的固有\n价值相差不要太远。如果股价升得太高，我们就会呼吁它降下来。并非所有的美\n国企业都这么做，但这是我们的做事方式。  \n \n        我可不想回到 GO（起点）。我是从 GO 走过来的。我们的许多\n股东把大部分净资产都投在伯克希尔了，他们也不希望回到 GO。  \n \n        现在很多人似乎认为企业 CEO 的责任就是让股票价格上涨。这\n种观点导致了各种各样的愚蠢行为。我们会实话实说，值多少就说多少。  \n伯克希尔股东 \n \n        我们喜欢现在的股东，不想诱惑谁来成为我们的股东。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,116,2073692323514028032),(2073692328291340296,'种观点导致了各种各样的愚蠢行为。我们会实话实说，值多少就说多少。  \n伯克希尔股东 \n \n        我们喜欢现在的股东，不想诱惑谁来成为我们的股东。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        考虑到这个企业的复杂性，我认为就向股东披露他们需要的信\n息而言，我们的年报比我知道的任何一家公司都要好。我们是凭着良心这么做的。  \n伯克希尔的收购策略 \n \n        三分之二的收购是失败的。而我们的收购很成功，那是因为我\n们从来不试图为收购而收购——我们等着那些不用多想也知道会成功的机会。  \n收购竞争 \n \n        长久以来，许多私募股权投资公司一直与我们展开竞争，但不\n管怎么样，我们还是设法收购了一些企业。  \n \n        一般的假设是，最好是坐在办公桌后面，然后人们会带来一个','2026-07-05 16:55:53.049000',0,2073692323954429952,117,2073692323514028032),(2073692328291340297,'管怎么样，我们还是设法收购了一些企业。  \n \n        一般的假设是，最好是坐在办公桌后面，然后人们会带来一个\n又一个的好机会——这是早期风险投资者的态度，直到最近几年才有所改变。但\n我们从来不这么做——我们到处寻找值得收购的公司。20 年来，我们每年购买\n的企业只有一家或者两家。  \n \n        可以说，我们不停在找。我们不跟上门推销的人打交道。如果\n你只是坐着，等交易上门，那么你坐的位子就会非常危险。  \n被兼并公司的管理人员 \n \n        我们收购一家又一家的企业，是因为我们敬佩它们的创\n办人和这些创办人在生活中取得的成就。在绝大多数情况下，他们会留下\n来，而且从来不曾让我们失望。  \n \n        激情和天分，哪个更重要呢？伯克希尔充满了对他们自\n己的事业特别有激情的人。我认为激情比头脑的能力更加重要。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,118,2073692323514028032),(2073692328291340298,' \n        激情和天分，哪个更重要呢？伯克希尔充满了对他们自\n己的事业特别有激情的人。我认为激情比头脑的能力更加重要。  \n \n        我认为我们的管理人员来参加这个会议（股东大会），\n并不是为了学习管理技巧——他们精通所有跟他们的企业相关的技巧\n——而是因为这是个有趣的地方，而且每年都变得更加有趣，他们愿意成\n为它的一部分。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n管理附属企业 \n \n        基本上，我们会选择那些我们非常钦佩的人来管理我们的附属\n公司。一般来说，我们跟他们很容易相处，因为我们喜爱并敬佩他们。他们的企\n业中应该有什么样的企业文化，都由他们自行决定，我们并不会干预。他们总是\n能够积极进取，及时更正以往的错误。  \n \n        如果让伯克希尔管理的附属公司的那些 CEO 来发言，可能对现','2026-07-05 16:55:53.049000',0,2073692323954429952,119,2073692323514028032),(2073692328291340299,'能够积极进取，及时更正以往的错误。  \n \n        如果让伯克希尔管理的附属公司的那些 CEO 来发言，可能对现\n在的股东会有帮助，但我们向他们承诺过，他们可以把 100%的时间花在他们的\n企业上。我们对他们管理他们的企业不设置任何障碍。许多人对我说他们很高兴，\n因为不用把 25%的时间浪费在各种他们不喜欢的活动上。  \n \n        有些美德是所有伯克希尔的附属公司都有的。我们并不创造这\n些美德——我们选择那些已经拥有这些美德的公司。我们只是不把它搞坏。我们\n把权力分散到几乎全面退位的程度。  \n合力 \n \n        我们不说“合力”这个词，因为人们总是宣称兼并之后会产生\n合力作用。是的，合力确实存在，但有太多关于合力的不实承诺了。伯克希尔充\n满了合力——我们并不回避合力，只是回避那些对合力的宣称。  \n作出正确的人事决定 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,120,2073692323514028032),(2073692328291340300,'合力作用。是的，合力确实存在，但有太多关于合力的不实承诺了。伯克希尔充\n满了合力——我们并不回避合力，只是回避那些对合力的宣称。  \n作出正确的人事决定 \n \n        过去几十年来，我们解雇职员的次数少得令人吃惊——远远少\n于其他企业。这并不是因为我们太心软或者太愚蠢，这是因为我们更加聪明和更\n加幸运。很多人会回过头来看，并说他们最大的错误是没有及早地解聘某个人（我\n们从来不这么说）。我们的纪录惊人的好。我们是老派的企业。例如，在收购\nCORT 商业服务公司（西科收购的一家从事家具出租的企业）的时候，沃伦对我\n说：“你会喜欢保罗·阿诺德（CORT 的 CEO）的。”他说得没错。保罗自还在法\n学院念书的时候就管理这家企业了，并且热爱它。  \n伯克希尔的保险业务 \n \n        表面上看，再保险是一种过度竞争的生意，但其实不是这样的。','2026-07-05 16:55:53.049000',0,2073692323954429952,121,2073692323514028032),(2073692328295534592,'学院念书的时候就管理这家企业了，并且热爱它。  \n伯克希尔的保险业务 \n \n        表面上看，再保险是一种过度竞争的生意，但其实不是这样的。\n保险合同的签署和赔付之间有很大的时间差，所以投保人必须评估保险公司未来\n的支付意愿和支付能力。在这方面，我们信誉良好，拥有一定的优势，不过这种\n优势本来应该更大的。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        我认为我们在再保险行业拥有某些优势，是因为人们信任我们\n的支付意愿和支付能力，所以再保险并不是价格低就能卖得好的无特性商品。我\n认为我们拥有一些特殊的才能。这么说吧，我觉得依靠特殊的才能是很危险的\n——最好是拥有许多价格不受管制的垄断性企业。但这在今天的世界是不可能\n的，我们从前依靠才能赚钱，未来也将继续如此。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,122,2073692323514028032),(2073692328295534593,'——最好是拥有许多价格不受管制的垄断性企业。但这在今天的世界是不可能\n的，我们从前依靠才能赚钱，未来也将继续如此。  \n \n        我很高兴我们拥有保险业务，但我要提醒你们，它不是一门简\n单的生意。我们必须很聪明，才能把它做好。  \n \n        总的来讲，我们做得相当不错——意味着位于（整个行业的）\n前 10%，因为我们做得与众不同，而且我们愿意做一些不那么令人愉快的事情。  \n \n        总而言之，我们对我们的保险业务感到中等的乐观。  \n \n        用很低的成本让浮存金以可观的速度增长几乎是不可能的任\n务——但不管怎么样，我们想要做到这一点。  \n \n        我曾经为我们的浮存金的增长和成本感到惊讶。我们得到了几\n十亿美元的浮存金，而所支付的利率比国债的利息还要低，这真的太好了。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,123,2073692323514028032),(2073692328295534594,' \n        我曾经为我们的浮存金的增长和成本感到惊讶。我们得到了几\n十亿美元的浮存金，而所支付的利率比国债的利息还要低，这真的太好了。  \n \n        波动的业绩以及在市场不景气时愿意少签保单……是我们作\n为保险公司的优势之一，我们并不在意业绩的波动，而其他人都试图讨好华尔街。\n这个优势可不算小了。  \n \n        别人都不这么做，但在我看来，这（别总是想着要取悦华尔街）\n明显是惟一可行的道路。伯克希尔基本上是这样的。关键是控股股东能够说了算\n——如果要让董事会来作这样的决定就难了。  \n伯克希尔·哈撒韦回购股票 \n \n        在过去，当伯克希尔的股价变得便宜时，我们会去买比它更便\n宜的股票。（相比回购股票）我总是更喜欢这么做。拥有一家声名狼藉的公司，\n得通过收购某些股东的股份来让其他股东赚钱，这可不好玩。  \n分割伯克希尔的股票以创造出更多的流动性 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,124,2073692323514028032),(2073692328295534595,'得通过收购某些股东的股份来让其他股东赚钱，这可不好玩。  \n分割伯克希尔的股票以创造出更多的流动性 \n \n        有人认为可交易的普通股票的流动性对资本主义贡献极大，我\n觉得这种观念大多是胡说八道。流动性给我们带来了这些疯狂的泡沫，所以它的\n问题和好处一样多。  \n \n        （巴菲特插话说：“伯克希尔股票平均每天的成交额为 5000\n万美元，所以如果人们想把它卖掉，根本不会遇到问题。”）  \n \n        但我们正在努力让更多的人拥有这只价格如此高昂乃至流动\n性成了问题的股票。  \n为什么没有更多的公司和投资者效仿伯克希尔·哈撒韦 \n \n        这是一个好问题。我们的方法让我们取得了成功。看看我们、\n我们的管理人员和股东有多么开心就知道啦。大多数人应该效仿我们。我们的投\n资方法并不难学，但表面上看起来很难，因为它跟一般的投资方法不同——它不','2026-07-05 16:55:53.049000',0,2073692323954429952,125,2073692323514028032),(2073692328295534596,'我们的管理人员和股东有多么开心就知道啦。大多数人应该效仿我们。我们的投\n资方法并不难学，但表面上看起来很难，因为它跟一般的投资方法不同——它不\n是常见的方法。我们的管理费用很低，没有季度目标和预算，也没有一套标准的\n人事体系，我们的投资集中度比一般企业高得多。就这么简单而且合情合理。  \n \n        最近我跟杰克·麦克唐纳聊天，他在斯坦福商学院上一门以我\n们的原则为基础的投资课。他说那很孤独——他觉得自己像是那个美泰克家电维\n修员。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n对巴菲特的评论 \n \n        人们很难相信他的业绩一年比一年好。这种情况不会永久地持\n续下去，但沃伦的确在进步。这是很罕见的：绝大多数人到了 72 岁就停滞不前\n了，但沃伦依然在进步。  \n查理对沃伦的影响 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,126,2073692323514028032),(2073692328299728896,'续下去，但沃伦的确在进步。这是很罕见的：绝大多数人到了 72 岁就停滞不前\n了，但沃伦依然在进步。  \n查理对沃伦的影响 \n \n        我认为那些作者言过其实地夸大了我对沃伦的影响。沃伦确实\n有过发蒙的时候，因为他曾在本杰明·格拉汉姆手下工作过，而且赚了那么多的\n钱。从如此成功的经验中跳出来确实很难。但如果世上未曾有过查理·芒格这个\n人，巴菲特的业绩依然会像现在这么漂亮。  \n \n        我想那些认为我是沃伦的伟大启蒙者的想法里有好些神话的\n成分。他不需要什么启蒙。但我们现在比五年前更能明白这个道理。  \n沃伦走后会怎样？ \n \n        关键是拥有许多优秀的企业。优秀的企业能给伯克希尔的发展\n带来很多动力。（然而，）我认为我们的继任者在资本配置方面将不会像沃伦这\n么出色。  \n \n        伯克希尔钱多成灾——我们拥有许多不断产生现金的伟大企','2026-07-05 16:55:53.049000',0,2073692323954429952,127,2073692323514028032),(2073692328299728897,'带来很多动力。（然而，）我认为我们的继任者在资本配置方面将不会像沃伦这\n么出色。  \n \n        伯克希尔钱多成灾——我们拥有许多不断产生现金的伟大企\n业。如果股价下跌，伯克希尔可以把它买回来。没有理由认为它会很快完蛋，而\n且我觉得有理由认为它将会继续运转良好。如果伯克希尔没有随着时间的流逝\n——就算是在沃伦去世之后——而变得更大、更强，我会感到非常吃惊。  \n \n        等到沃伦离开的时候，伯克希尔的收购业务会受到影响，但其\n他部门将会运转如常。收购业务应该也还行。反正我们可以向你们保证的是，从\n前那种增长速度将会下降，我们可不想在这个问题上说谎。  \n \n        我想到那时伯克希尔的最高领导人应该没有沃伦那么聪明。但\n别抱怨：“天啊，给我沃伦·巴菲特 40 年之后，怎么能给我一个比他差的混蛋\n呢？”那是很愚蠢的。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,128,2073692323514028032),(2073692328299728898,'别抱怨：“天啊，给我沃伦·巴菲特 40 年之后，怎么能给我一个比他差的混蛋\n呢？”那是很愚蠢的。  \n \n        如果说谁有理由担忧的话，那个人应该是我，但我认识巴菲特\n家族几十年了，我可以告诉你：“别担心这件事。你应该感到非常幸运。” \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n \n \n要是查理去世了呢？ \n \n        正如你能看到的，我们打算永远在这里待下去。（但就算我去\n世了，）你拥有大量的现金，还有巴菲特坐镇总公司——还有什么好担心的呢？  \n查理是可恶的“说不大师” \n \n        巴菲特：你千万要学会如何校准他的答案。如果你问查理某个\n项目，他说“不”，那么我们会用所有的钱来投资它。如果他说“这是我听过的\n最愚蠢的事情”，那么我们就会适当地做一点投资。如果你能够校准他的答案，\n你就能获得很多智慧。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,129,2073692323514028032),(2073692328303923200,'最愚蠢的事情”，那么我们就会适当地做一点投资。如果你能够校准他的答案，\n你就能获得很多智慧。  \n \n查克·瑞克斯豪瑟 \n芒格、托尔斯&奥尔森律师事务所前合伙人，1964 年以来的朋友  \n        “沃伦曾经告诉我一个故事，他们刚认识的时候，还没有一起\n做生意，各自拥有一家合伙投资公司，沃伦经常给查理打电话说‘我想做某件\n事’，并对这件事加以描绘，查理会说：‘天啊，你在开玩笑吗？有这种风险和\n那种风险。’他们将会仔细考虑查理看到的这些风险，然而沃伦通常会说：‘我\n想你是对的。’但有时候他也会说：‘查理，你说的我都听进去了，但我还是想\n做这件事。’沃伦说他直到那一刻才能知道查理的真正想法，因为查理有时会说：\n‘沃伦，如果你要做这件事，我能不能参股？’人们通常认为查理的价值在于识\n别风险和说‘不’，但其实查理最有价值的地方，在于他能够识别那些可以参股\n的时机。” ','2026-07-05 16:55:53.049000',0,2073692323954429952,130,2073692323514028032),(2073692328303923201,'‘沃伦，如果你要做这件事，我能不能参股？’人们通常认为查理的价值在于识\n别风险和说‘不’，但其实查理最有价值的地方，在于他能够识别那些可以参股\n的时机。” \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n投资建议 \n \n性格、耐心和求知欲的重要性” \n \n        （成功投资的关键因素之一就是拥有良好的）性格——大多数\n人总是按捺不住，或者总是担心过度。成功意味着你要非常有耐心，然而又能够\n在你知道该采取行动时主动出击。你吸取教训的来源越广泛，而不是仅仅从你自\n己的糟糕经验中吸取教训，你就能变得越好。  \n \n        我想说说怎样才能培养那种毫不焦躁地持有股票的性情。光靠\n性格是不行的。你需要在很长很长的时间内拥有大量的求知欲望。  \n \n        你必须有浓厚的兴趣去弄明白正在发生的事情背后的原因。如','2026-07-05 16:55:53.049000',0,2073692323954429952,131,2073692323514028032),(2073692328303923202,'性格是不行的。你需要在很长很长的时间内拥有大量的求知欲望。  \n \n        你必须有浓厚的兴趣去弄明白正在发生的事情背后的原因。如\n果你能够长期保持这种心态，你关注现实的能力将会逐渐得到提高。如果你没有\n这种心态，那么即使你有很高的智商，也注定会失败。  \n集中投资 \n \n        我们的投资风格有一个名称——集中投资，这意味着我们投资\n的公司有 10 家，而不是 100 家或者 400 家。  \n \n        我们的游戏是，当好项目出现时，我们必须能够认出来，因为\n好项目并不会经常出现。机会只眷顾有准备的人。  \n \n        好的投资项目很难得，所以要把钱集中投在少数几个项目上，\n这在我看来是很好的主意。投资界有 98%的人并不这么想。而我们一直以来都是\n那么做的，这给我们——也给你们——带来了许多好处。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,132,2073692323514028032),(2073692328303923203,'这在我看来是很好的主意。投资界有 98%的人并不这么想。而我们一直以来都是\n那么做的，这给我们——也给你们——带来了许多好处。  \n \n        好玩的是，绝大多数大型投资机构的想法不是这样的。他们聘\n请了许多人，比较默克制药公司和辉瑞制药公司到底哪个价值高，分析标准普尔\n500 指数的每只成份股，以为他们能够打败市场。你这样做是无法打败市场的。  \n \n        我们的投资规矩是等待好球的出现。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        如果我有机会进入某个企业工作，而那里的人用各种指数标准\n来衡量我，逼我把钱都投出去，聚集在周围监视我，那么我会讨厌这家企业。我\n会有戴上脚镣手铐的感觉。  \n \n        很少人借鉴我们的方法。采用集中投资策略的公司略有增加，','2026-07-05 16:55:53.049000',0,2073692323954429952,133,2073692323514028032),(2073692328303923204,'会有戴上脚镣手铐的感觉。  \n \n        很少人借鉴我们的方法。采用集中投资策略的公司略有增加，\n但真正增加的是无限制使用投资顾问来建议资产如何配置、分析评估其他顾问等\n等做法。也许有 2%的人会走进我们的阵营，剩下 98%的人将会信奉他们听来的道\n理（比如说市场是完全有效的）。  \n错误的投资课程 \n \n        Beta 系数、现代组合投资理论等等——这些在我看来都没什\n么道理。我们想要做到的是，用低廉的价格，甚至是合理的价格，来购买那些拥\n有可持续竞争优势的企业。  \n \n        大学教授怎么可以散播这种无稽之谈（股价波动是衡量风险的\n尺度）呢？几十年来，我一直都在等待这种胡言乱语结束。现在这样乱讲的人少\n了一些，但还是有。  \n \n        沃伦曾经对我说：“我对学术界的总体看法可能是错的（把它','2026-07-05 16:55:53.049000',0,2073692323954429952,134,2073692323514028032),(2073692328303923205,'了一些，但还是有。  \n \n        沃伦曾经对我说：“我对学术界的总体看法可能是错的（把它\n看得这么糟糕），因为那些跟我打交道的人都有一套疯狂的理论。”  \n分散投资 \n \n        认为投资应该越分散越好是一种发疯的观念。  \n \n        我们并不认为分散程度很高的投资能够产生好结果。我们认为\n几乎所有好投资的分散程度都是相对较低的。  \n \n        如果你把我们 15 个最好的决策剔除，我们的业绩将会非常平\n庸。你需要的不是大量的行动，而是极大的耐心。你必须坚持原则，等到机会来\n临，你就用力去抓住它们。  \n \n        这些年来，伯克希尔就是通过把赌注押在有把握的事情上而赚\n钱的。  \n坐等投资法 \n \n        如果你因为一样东西的价值被低估而购买了它，那么当它的价\n格上涨到你预期的水平时，你就必须考虑把它卖掉。那很难。但是，如果你能购','2026-07-05 16:55:53.049000',0,2073692323954429952,135,2073692323514028032),(2073692328303923206,'坐等投资法 \n \n        如果你因为一样东西的价值被低估而购买了它，那么当它的价\n格上涨到你预期的水平时，你就必须考虑把它卖掉。那很难。但是，如果你能购\n买几个伟大的公司，那么你就可以安坐下来啦。那是很好的事情。  \n \n        我们偏向于把大量的钱投在我们不用再另作决策的地方。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n优秀企业是什么？ \n \n        有这么两类企业：第一类每年赚 12%，你到年底可以把利润拿\n走。第二类每年赚 12%，但所有多余的现金必须进行再投资——它总是没有分红。\n这让我想起了那个卖建筑设备的家伙——他望着那些从购买新设备的客户手里\n吃进的二手机器，并说：“我所有的利润都在那里了，在院子里生锈。”我们讨\n厌那种企业。  \n喜诗糖果：优秀企业的个案研究 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,136,2073692323514028032),(2073692328303923207,'吃进的二手机器，并说：“我所有的利润都在那里了，在院子里生锈。”我们讨\n厌那种企业。  \n喜诗糖果：优秀企业的个案研究 \n \n        如果喜诗糖果（在我们收购它的时候）再多要 10 万美元（巴\n菲特插口说：“1万美元”），沃伦和我就会走开——我们那时就是那么蠢。  \n \n        伊拉·马歇尔说你们这两个家伙疯啦——有些东西值得你们\n花钱买的呀，比如说优质的企业和优质的人。你们低估了优质的价值啦。我们听\n进了他的批评，改变了我们的想法。这对每个人来说都是很好的教训：要有能力\n建设性地接受批评，从批评中吸取教训。如果你间接地吸取我们从喜诗糖果学到\n的教训，那么你将会说，伯克希尔是建立在建设性的批评之上的。  \n \n \n错误 \n \n        伯克希尔历史上最严重的错误是坐失良机的错误。我们看到了\n许多好机会，却没有采取行动。这些是巨大的错误——我们为此损失了几十亿美','2026-07-05 16:55:53.049000',0,2073692323954429952,137,2073692323514028032),(2073692328303923208,' \n错误 \n \n        伯克希尔历史上最严重的错误是坐失良机的错误。我们看到了\n许多好机会，却没有采取行动。这些是巨大的错误——我们为此损失了几十亿美\n元。到现在还在不断地犯这样的错误。我们正在改善这个缺陷，但还没有完全摆\n脱它。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        这样的错误可以分为两类：1. 什么也不做，沃伦称之为“吮\n吸我的大拇指”；2. 有些股票本来应该买很多，但是只买了一点。  \n \n        在差点犯下没有购买喜诗糖果的大错之后，我们有很多次犯了\n相同的错误。很显然，我们吸取教训很慢。这些机会成本并没有反映在财务报表\n上，但却让我们失去了几十亿美元。  \n        由于坐失良机的错误（是无形的），绝大多数人并不会注意到','2026-07-05 16:55:53.049000',0,2073692323954429952,138,2073692323514028032),(2073692328303923209,'上，但却让我们失去了几十亿美元。  \n        由于坐失良机的错误（是无形的），绝大多数人并不会注意到\n它们。我们会主动说出我们犯下哪些坐失良机的错误——就像我们刚才所做的那\n样。（刚刚在讨论的是，他们因为沃尔玛的股价上涨了一点点而没有买进，结果\n犯下了少赚 100 亿美元的错误。）  \n \n \n当股价下跌时买进 \n \n        过去几十年来，我们经常这么做：如果某家我们喜欢的企业的\n股票下跌，我们会买进更多。有时候会出现一些情况，你意识到你错了，那么就\n退出好了。但如果你从自己的判断中发展出了正确的自信，那么就趁价格便宜多\n买一些吧。  \n \n        诱人的机会总是转瞬即逝的。  \n \n        真正好的投资机会不会经常有，也不会持续很长的时间，所以\n你必须做好行动的准备。要有随时行动的思想准备。  \n小投资者的机会 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,139,2073692323514028032),(2073692328303923210,' \n        真正好的投资机会不会经常有，也不会持续很长的时间，所以\n你必须做好行动的准备。要有随时行动的思想准备。  \n小投资者的机会 \n \n        如果你今天只有很少的资本，年纪尚轻，那么你的机会比我年\n轻时要少一些。当年我们刚走出大萧条。当时人们认为资本主义很糟糕。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        20 世纪 20 年代出现了许多弊端。当时有个笑话是这样的，一\n个家伙说：“我买股票是为了晚年，这种方法很灵验——不到六个月，我就觉得\n自己像个老头了！”  \n \n        你遇到的困难更大，但这并不意味着你没办法做得好——只是\n需要更多时间而已。但那有什么关系呢，你能活得更长久啊。  \n \n        如果我是你，我就会买些很小的股票，寻找一些罕见的错误定','2026-07-05 16:55:53.049000',0,2073692323954429952,140,2073692323514028032),(2073692328303923211,'需要更多时间而已。但那有什么关系呢，你能活得更长久啊。  \n \n        如果我是你，我就会买些很小的股票，寻找一些罕见的错误定\n价的机会，但这类机会的确是很少。  \n股票卖空 \n \n        卖空股票，却又看到股价因为某些因素而上涨，是很苦恼的事\n情。你在生活中不应该去做这么苦恼的事情。 \n \n \n护城河和持续的竞争优势 \n \n        旧的护城河正在被填平，而新的护城河比以前更难预测，所以\n事情变得越来越难。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n学习过程 \n \n        我还没发现有谁能够很快做到（成为一名伟大的投资者）。作\n为投资者，沃伦·巴菲特比我第一次遇到他时好得太多了，我也是这样的。所以\n诀窍就在于不断学习。你应该喜欢学习的过程。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,141,2073692323514028032),(2073692328303923212,'为投资者，沃伦·巴菲特比我第一次遇到他时好得太多了，我也是这样的。所以\n诀窍就在于不断学习。你应该喜欢学习的过程。  \n \n        我观察沃伦几十年了。沃伦学习了很多东西，这使他得以（拓\n展他的能力圈，所以他能够投资像中国石油这样的企业）。  \n \n        如果你打算成为一名投资者，那么总会有些投资领域不是你完\n全了解的。但如果你努力学习，不断进步，那么你就能够保证你的投资都会产生\n好的结果。关键是自律、勤奋和练习。那就像打高尔夫球——你必须努力练习。  \n \n        如果你没有不停地学习，其他人将会超过你。  \n能力圈及其边界 \n \n        我们接触过的事情有很多。我们有三个选项：可以，不行，太\n难。除非我们对某个项目特别看好，否则就会把它归为“太难”的选项。你需要\n做的，只是寻找一块特殊的能力领域，并把精力放在那里面就可以了。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,142,2073692323514028032),(2073692328303923213,'难。除非我们对某个项目特别看好，否则就会把它归为“太难”的选项。你需要\n做的，只是寻找一块特殊的能力领域，并把精力放在那里面就可以了。  \n \n        如果你确有能力，你就会非常清楚你能力圈的边界在哪里。没\n有边界的能力根本不能称之为能力。（如果你问自己是否过了能力圈的范围，）\n那这个问题本身就是答案。  \n资本成本和机会成本 \n \n        （巴菲特：查理和我不知道我们的资本成本。商学院有教，但\n我们持怀疑态度。我们只是用我们拥有的资本尽量去做最聪明的事情而已。我们\n会拿一切跟其他选择作比较。我从来没觉得那个资本成本的计算对我来说有什么\n意义。查理，你呢？）  \n \n        我也不觉得。如果你拿起最好的经济学教材，那是曼昆写的，\n他说人们作出决定的依据是机会成本——也就是说，真正重要的是否有其他选','2026-07-05 16:55:53.049000',0,2073692323954429952,143,2073692323514028032),(2073692328303923214,' \n        我也不觉得。如果你拿起最好的经济学教材，那是曼昆写的，\n他说人们作出决定的依据是机会成本——也就是说，真正重要的是否有其他选\n择。我们决策的时候也是这样的。其他人却不这么认为——甚至还有人提出了股\n本成本的说法。这些人真是脑子坏掉了。 \n \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n谈市场 \n \n股票、伦勃朗和泡沫 \n \n        股票有点像债券，对其价值的评估，大略以合理地预测未来产\n生的现金为基础。但股票也有点像伦勃朗的画作，人们购买它们，是因为它们的\n价格一直都在上涨。这种情况，再加上股票涨跌所产生的巨大“财富效应”，可\n能会造成许多祸害。  \n \n        （2001 年 4 月）这是资本主义最极端的时期。20 世纪 30 年代，','2026-07-05 16:55:53.049000',0,2073692323954429952,144,2073692323514028032),(2073692328303923215,'能会造成许多祸害。  \n \n        （2001 年 4 月）这是资本主义最极端的时期。20 世纪 30 年代，\n我们遭遇了过去 600 年来最严重的大萧条。而今天几乎是过去 600 年来最兴旺的\n时期……我们使用了“悲惨繁荣”这个词汇来描绘它，因为它产生的后果是悲惨\n的。  \n \n        债券比股票理性得多。没有人会以为债券的价值会上升到月球\n去。  \n未来的市场回报率 \n \n        （2000 年 11 月）如果股市未来的回报率能够达到 15%，那肯\n定是因为一种强大的“伦勃朗效应”。这不是什么好事。看看日本以前的情况就\n知道了。当年日本股市的市盈率高达 50 到 60 倍。这导致了长达十年的经济衰退。\n不过我认为日本的情况比较特殊。我的猜测是，美国不会出现极端的“伦勃朗\n化”现象，今后的回报率将会是 6%。如果我错了，那可能是因为一个糟糕的原','2026-07-05 16:55:53.049000',0,2073692323954429952,145,2073692323514028032),(2073692328308117504,'不过我认为日本的情况比较特殊。我的猜测是，美国不会出现极端的“伦勃朗\n化”现象，今后的回报率将会是 6%。如果我错了，那可能是因为一个糟糕的原\n因。如果未来股票交易更像伦勃朗作品的买卖，那么股市将会上涨，但缺乏坚实\n的支撑。如果出现这种情况，那就很难预测它会发展到什么程度、股价将会上涨\n多高，以及会持续到什么时候。  \n \n        （2001 年 4 月）总的来说，我认为美国投资者应该调低他们\n的预期。人们不是有点蠢，而是非常蠢。没有人愿意说出这一点。  \n \n        （2001 年 5 月）我们并没有处在一个猪猡也能赚钱的美好时\n代。投资游戏的竞争变得越来越激烈。  \n \n        我不认为我们将会看见大多数股票像 1973-1974 年，甚至是\n1982 年那样，价格跌到令人流口水的低位。我觉得沃伦和我非常有可能再也看','2026-07-05 16:55:53.049000',0,2073692323954429952,146,2073692323514028032),(2073692328308117505,' \n        我不认为我们将会看见大多数股票像 1973-1974 年，甚至是\n1982 年那样，价格跌到令人流口水的低位。我觉得沃伦和我非常有可能再也看\n不到这些机会了，但那并不是坏事。我们只要继续努力就好啦。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        （巴菲特：不过也不是完全没有可能。你无法预测市场将会怎\n样。在日本，十年期债券的利率只有 0.625%。以前谁能想得到呢？）  \n \n        就算日本发生了那样的事情，美国的情况也不会那么糟糕。在\n接下来这段日子里，那些普通的高薪投资顾问将不会有非常好的表现。  \n \n        垃圾债的短暂崩溃（2002 年底）是很奇怪的事情，当时它们\n的收益率高达 35%到 40%。垃圾债市场绝对是一片混乱。如果股市也遭遇这种情','2026-07-05 16:55:53.049000',0,2073692323954429952,147,2073692323514028032),(2073692328308117506,' \n        垃圾债的短暂崩溃（2002 年底）是很奇怪的事情，当时它们\n的收益率高达 35%到 40%。垃圾债市场绝对是一片混乱。如果股市也遭遇这种情\n况——那么不难想像，很快就会大崩盘。  \n当前的市场环境 \n \n        （2004 年 5 月）说到大环境，我认为它会令那些想要很容易、\n很有把握地赚到钱的人感到非常痛苦。普通股的估值可能相当合理，但它们不算\n特别便宜。  \n \n        我们的现金就足以说明问题了。如果我们有很多好主意，我们\n就不会拥有这么多现金。  \n        伯克希尔和西科有大量我们不知道用来干什么的现金。如果你\n算上债券的话，伯克希尔有 700 亿美元，西科的现金也是多得不得了。我们的现\n金是有史以来最多的。要是在以前，我们只要沉住气就可以了，我们能够把现金\n派上用场。 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,148,2073692323514028032),(2073692328308117507,'金是有史以来最多的。要是在以前，我们只要沉住气就可以了，我们能够把现金\n派上用场。 \n \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n“我没有什么要补充的”第二篇 \n \n \n \n        接下来，我们来看查理如何监控宏观的经济趋势和变化：  \n \n        问：为了理解宏观的经济环境，你通常关注哪些宏观的统计数\n据呢？或者说你觉得哪些数据比较有用呢？  \n \n        我觉得都没有用。我只是密切关注伯克希尔的各家子公司，常\n常阅读商业报纸和杂志而已，由此我能接触到大量宏观层面的东西。我发现我只\n要这么做，就足以了解宏观层面正在发生什么情况了。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n对企业管理层的批评 \n \n篡改盈利数字和做假账 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,149,2073692323514028032),(2073692328308117508,'（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n对企业管理层的批评 \n \n篡改盈利数字和做假账 \n \n        有那么多钱压在财报数据上，有人想要篡改它们也是很正常\n的。很多人都这么做，所以出现了谢皮科效应（Serpico Effects）（注：谢皮\n科是一名纽约的退休警察，1970 年代因对警察腐败作证而出名。其经历于 1973\n年被拍成电影《谢皮科》，由好莱坞著名男演员艾尔·帕西诺主演），也就是说，\n每个人都觉得自己的做法没有错，因为其他人也那么做。事情总是这样的。  \n \n        （现在，它的机制类似于连锁信。由于和诸如风险投资之类的\n合法活动混在一起，这种做法看起来似乎很体面。但我们正在混淆体面的活动和\n可耻的活动——所以我在伯克希尔·哈撒韦的年会上说，如果你把葡萄干和大便','2026-07-05 16:55:53.049000',0,2073692323954429952,150,2073692323514028032),(2073692328308117509,'合法活动混在一起，这种做法看起来似乎很体面。但我们正在混淆体面的活动和\n可耻的活动——所以我在伯克希尔·哈撒韦的年会上说，如果你把葡萄干和大便\n搅在一起，你得到的仍然是大便。会计学没有办法阻止那些道德败坏的管理人员\n从事那种连锁信式的骗局。  \n逮到行为不轨的管理人员 \n \n        伯纳德·埃伯斯和肯·拉伊就像漫画中的小丑——他们很容\n易被逮到。他们几乎是变态狂。但是要逮到荷兰皇家壳牌公司的问题，就难多了。  \n \n        但我们不需要吸取他们的教训，因为我仍然相信埃克森的数据\n是正常的。  \n \n        我想向大家道歉。昨晚提到某些当代的商业巨头时，我说当他\n们说话时，他们就是在说谎；当他们沉默时，他们就是在偷窃。这句话不是我独\n创的，（很多年前） 就有人用它来描绘那些工业大亨。  \n美国企业对特别费的痴迷 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,151,2073692323514028032),(2073692328308117510,'们说话时，他们就是在说谎；当他们沉默时，他们就是在偷窃。这句话不是我独\n创的，（很多年前） 就有人用它来描绘那些工业大亨。  \n美国企业对特别费的痴迷 \n \n        你说这笔费用每年总是会出现，它还有什么特别的呢？  \n公司治理 \n \n        有个热衷于改革的积极分子说沃伦担任可口可乐公司的董事\n有悖于可口可乐公司的利益，这种白痴说法对改革事业毫无帮助，反而伤害了它。\n那些人的傻冒行为破坏了他们的事业。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n对基金管理企业的批评 \n \n有缺陷的激励机制 \n \n        现在一般基金的管理系统要求人们假装去做他们做不了的事\n情，假装喜欢他们其实不喜欢的事情。这种生活方式很可怕，但它能得到很多薪\n水。  \n没有增加价值 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,152,2073692323514028032),(2073692328308117511,'情，假装喜欢他们其实不喜欢的事情。这种生活方式很可怕，但它能得到很多薪\n水。  \n没有增加价值 \n \n        开放式基金每年收取 2%的费用，然后那些经纪商让人们在不\n同基金之间转来转去，多付 3%到 4%的费用。可怜的普通基民们把钱交给专业人\n士，却得到糟糕的结果。我觉得这很恶心。本来人们买你的产品，你应该让他们\n的资产增值。但在这个国家，基金管理人员却只顾着自己赚钱。  \n \n        这个行业很滑稽，因为从净收益来看，整个投资管理行业加起\n来并没有对全部客户的资产提供附加值。这就是这个行业的运作方式。  \n股票经纪人 vs 指数基金 \n \n        这次年会坐满了许多聪明的、值得尊敬的股票经纪人，他们为\n客户提供了很好的服务，在这里很难指责他们。但总的来说，股票经纪人的表现\n太差了，甚至还比不上指数基金。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,153,2073692323514028032),(2073692328308117512,'客户提供了很好的服务，在这里很难指责他们。但总的来说，股票经纪人的表现\n太差了，甚至还比不上指数基金。  \n \n        我认为对于一般基金来说，投资指数是比现在通行的无借贷股\n票投资更为聪明的投资策略——尤其是在现行做法每年的管理费用超过 1%的情\n况下。指数基金的表现不可能永远都这么好，如果几乎所有人都转而投资它的话。\n但它的良好表现可以持续很长一般时间。  \n共同基金丑闻 \n \n        选择投资管理人员这件事最近变得更难了，因为人们发现，有\n不少共同基金的管理人员接受贿赂，出卖了他们自己股东的利益。  \n \n        这就像一个人走过来说：“我们为什么不把你母亲杀死，然后\n瓜分她的保险金呢？”很多人说：“好啊，我正需要那笔保险金呢。”  \n \n        他们有许多人觉得自己被冤枉了。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,154,2073692323514028032),(2073692328308117513,'瓜分她的保险金呢？”很多人说：“好啊，我正需要那笔保险金呢。”  \n \n        他们有许多人觉得自己被冤枉了。  \n \n        如果共同基金的监事是独立的，那么我就是俄罗斯波尔修芭蕾\n舞团的首席男明星。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n对华尔街的批评 \n \n华尔街的道德缺失 \n \n        华尔街的平均道德水准永远至多只能说是中等……这并不意\n味着华尔街没有一些正直的聪明人，其实是有的，像今天在座的各位，但我认识\n的每个人都不得不和他自己的公司对抗（为了做正确的事情）。  \n \n        过去这些年来，投资银行业的道德风气逐渐败坏。许多年前，\n我们花 600 万美元收购多元零售公司（Diversified Retailing），银行对我们','2026-07-05 16:55:53.049000',0,2073692323954429952,155,2073692323514028032),(2073692328308117514,'我们花 600 万美元收购多元零售公司（Diversified Retailing），银行对我们\n进行了严格而聪明的审查。那些银行家关心他们的客户，想要保护他们的客户。  \n \n        现在的风气是，只要能赚钱，什么都可以卖。你能把东西卖掉，\n你就道德高尚。但这个标准可不够。  \n \n \n所罗门个案研究 \n \n        现在的情况真令人吃惊。所罗门的自律和理性程度至少不比其\n他投资银行差，但到头来，所罗门居然求爷爷告奶奶地想要得到罗伯特·麦克斯\n韦尔这种人的投资业务，这人的绰号可是“跳来跳去的捷克人”啊。他既然有这\n个花名，投资银行就不应该去抢着做他的生意。  \n \n        （ 巴菲特： 就在人们发现他跳海的那天（由于丑行败露，他\n跳海自杀了），我们（所罗门）把钱汇给他，以交换他正要汇给我们的钱，但他','2026-07-05 16:55:53.049000',0,2073692323954429952,156,2073692323514028032),(2073692328308117515,' \n        （ 巴菲特： 就在人们发现他跳海的那天（由于丑行败露，他\n跳海自杀了），我们（所罗门）把钱汇给他，以交换他正要汇给我们的钱，但他\n没有付款。所以，我们去英国找他的几个儿子收账，那真是一团糟。我们收回了\n应得的钱。）（编者注：和其他大多数债权人不同，所罗门最终确实收回了款项。\n正如查理所说的：“这是个小小的奇迹——我们不配要回这笔钱。”）  \n \n        如果有个投资银行家多开几张交易单给麦克斯韦尔，那么他的\n收入将会显著增长。你得防止人们为了挣钱将不三不四的人带入。 \n（2001年至2006年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘录） \n \n诺曼底美国的个案研究 \n \n        （在谈起所罗门和一家他们没有点名的不良企业有交易时，沃\n伦和查理自顾自地笑了起来。然而，在 2002 年的年会上，查理点明那家企业就','2026-07-05 16:55:53.049000',0,2073692323954429952,157,2073692323514028032),(2073692328312311808,' \n        （在谈起所罗门和一家他们没有点名的不良企业有交易时，沃\n伦和查理自顾自地笑了起来。然而，在 2002 年的年会上，查理点明那家企业就\n是诺曼底美国公司。所罗门发现这家公司公开招股的材料全是伪造的，所以在尚\n未发生交易的时候及时地取消了它的首次公开募股。根据美国证券交易委员会网\n站上的一份报告，“1995 年 8 月 15 日，诺曼底的股票被推荐在纳斯达克全国市\n场系统上交易。一天之后，诺曼底取消了新股发行，并宣布所有的交易无效。”）  \n \n        这件事是一个很好的（又充满讽刺的）经历。沃伦、路易斯·辛\n普森和我都是（所罗门的）董事，我们还是最大的股东，我们说：“别跟这个家\n伙做生意。”但他们不听我们的话，还说承销委员会已经批准了那次新股发行。  \n \n        （沃伦：“他身上挂着一个霓虹灯牌写着‘骗子’。他确实坐','2026-07-05 16:55:53.049000',0,2073692323954429952,158,2073692323514028032),(2073692328312311809,'伙做生意。”但他们不听我们的话，还说承销委员会已经批准了那次新股发行。  \n \n        （沃伦：“他身上挂着一个霓虹灯牌写着‘骗子’。他确实坐\n牢了。碰巧的是，他宣称拥有大量伯克希尔的股票，并从中获利不菲，但我检查\n了股东名录，并没有看到他的名字。他的名字也许很普通，跟他重名的人很多，\n但如果他真有那么多股份，我想我应该能够找出来（所以他很可能在持有伯克希\n尔股份这件事上说了谎）。”） \n对会计的批评 \n \n大型会计师事务所的道德沦丧 \n \n        在我年轻的时候，大型的会计师事务所是非常正派的地方，没\n有人赚脏钱。但在过去的 25 年来，它们逐渐做出一些糟糕的行为。你一旦开始\n做坏事，那么第二次做就容易多了，到最后，你就会成为道德败坏的人。这个国\n家的大型会计师事务所居然为了钱而明目张胆地做假账，帮助客户逃税……  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,159,2073692323514028032),(2073692328312311810,'做坏事，那么第二次做就容易多了，到最后，你就会成为道德败坏的人。这个国\n家的大型会计师事务所居然为了钱而明目张胆地做假账，帮助客户逃税……  \n \n        太多的律师和会计师事务所参与了不可告人的事情。例如，它\n们收取应变费和保密费，提供逃税服务，这绝对是令人厌恶的事情。  \n \n        为了让你更好地理解那些顶尖的伪造避税用的财务报表的审\n计师事务所坏到什么程度，我想告诉你一件事，有个人曾经跟我说，他们比其他\n事务所做得更好，因为他们只为最大的 20 家客户提供这项服务，所以没有人会\n发现。 \n（2001年至2006年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘录） \n \n激进会计法 \n \n        我们被（在美国企业界泛滥的）激进会计法吓坏了，所以尽量\n采用保守的会计法。保守的会计法有助于我们的生意决策和保护伯克希尔。我们','2026-07-05 16:55:53.049000',0,2073692323954429952,160,2073692323514028032),(2073692328312311811,'激进会计法 \n \n        我们被（在美国企业界泛滥的）激进会计法吓坏了，所以尽量\n采用保守的会计法。保守的会计法有助于我们的生意决策和保护伯克希尔。我们\n怎么可能去做那些可能有悖于我们的道德准则的事情呢？  \n \n        创造性会计（伪造账目）绝对是对文明的诅咒。人们可以说复\n式簿记法是历史的一大进步。可是利用会计来造假和骗人是可耻的行为。在民主\n国家里，往往需要丑闻才能撬动改革。安然是企业文化长期出毛病的最典型例子。  \nEBITDA 的误用 \n \n        我认为，你每次看到 EBITDA（即未计利息、税项、折旧及摊\n销前的利润）这个词汇，你都应该用“狗屁利润”来代替它。  \n安达信 \n \n        我认为（所发生的一切对安达信那些无辜职员来讲）是非常不\n公平的，但没有失败的资本主义，就像没有地狱的宗教。当事情糟糕到这种地步，','2026-07-05 16:55:53.049000',0,2073692323954429952,161,2073692323514028032),(2073692328312311812,'安达信 \n \n        我认为（所发生的一切对安达信那些无辜职员来讲）是非常不\n公平的，但没有失败的资本主义，就像没有地狱的宗教。当事情糟糕到这种地步，\n又缺乏内部控制体系——安达信就没有（内控体系）——也许应该有个事务所要\n倒掉。  \n \n        我们不会做任何有可能导致伯克希尔垮台的事情。安达信特别\n脆弱，因为它是合伙制企业。合伙制企业在采取举动和选择客户等方面必须额外\n谨慎。  \n美国养老基金的会计丑闻 \n \n        当前这种（假设养老基金能够获得高得脱离现实的回报率）做\n法是愚蠢而且不正当的。但如果你跟管理人员提出来，他们的眼睛在敌意来临之\n前就已经瞪上你了。  \n \n        养老基金的会计由于利用了脱离现实的假设而陷入了丑闻。以\n最近的事情推断未来是人类的本性，但要是公司管理者们也这么想，那就太糟糕\n了。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,162,2073692323514028032),(2073692328312311813,' \n        养老基金的会计由于利用了脱离现实的假设而陷入了丑闻。以\n最近的事情推断未来是人类的本性，但要是公司管理者们也这么想，那就太糟糕\n了。  \n \n        IBM 刚刚将它对养老基金回报率的预期调高到 10%。绝大多数\n公司（在 2000 年）的回报率是 9%。我们认为 6%更为现实一些。该公司的领导也\n许相信这个数字是可以达到的——他们都是诚实的人——但从潜意识层面来说，\n他们相信它，是因为他们想要相信它。它能让盈利显得很好，这样他们就能推动\n股价上涨了。 \n（2001年至2006年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘录） \n \n        下面这句谚语很好地总结了那些会计人员什么话也不说的原\n因：“谁给我面包吃，我就给谁唱歌。”我认为你正从美国的会计系统得到一些\n非常愚蠢的数据。我觉得他们可能不是故意要撒谎，但也有可能是。  ','2026-07-05 16:55:53.049000',0,2073692323954429952,163,2073692323514028032),(2073692328312311814,'因：“谁给我面包吃，我就给谁唱歌。”我认为你正从美国的会计系统得到一些\n非常愚蠢的数据。我觉得他们可能不是故意要撒谎，但也有可能是。  \n糟糕的会计法导致道德沦丧 \n \n        有着宽松会计标准的人会引来其他人做出极其可怕的举动。那\n是造孽，绝对是造孽。如果你携带几大桶钞票经过贫民窟，又不好好看管它们，\n那么你就犯了很严重的罪行，因为你会惹来许多糟糕的行为，而糟糕的行为是会\n传染的。同样地，命令会计师草率地做账是一种真正的罪孽，也是一种愚蠢的经\n商方法。  \n对股票期权的批评 \n \n作为报酬的股票期权 \n \n        如果你瞧瞧股票期权的后果，你将会看到许多可怕的行为。给\n一个亲手创办公司、已经六十几岁的 CEO 大量的期权，试图以此刺激他对该公司\n的忠诚，这是一种精神错乱的想法。玛约医疗中心（Mayo Clinic）的医生或者','2026-07-05 16:55:53.049000',0,2073692323954429952,164,2073692323514028032),(2073692328312311815,'一个亲手创办公司、已经六十几岁的 CEO 大量的期权，试图以此刺激他对该公司\n的忠诚，这是一种精神错乱的想法。玛约医疗中心（Mayo Clinic）的医生或者\n克拉法斯律所（Cravath）的律师在六十几岁时还会为了期权而更加努力地工作\n吗？  \n \n        我们的股东也知道，我们的体系不同于绝大多数大型的公司。\n我们认为它不那么变化无常。股票期权体系可能会使某些什么事情都没做的人得\n到大量的回报，而应该得到很多报酬的人却什么都没有。除非我们收购的公司原\n来就实行了（股票期权制度），否则我们不会使用它。  \n期权估值和布莱克—舒尔斯模型 \n \n        布莱克—舒尔斯模型对短期的期权而言是有效的，但如果期权\n是长期的，而且你认为你（对期权涉及的资产）有所了解，那么使用布莱克—舒\n尔斯模型是一种很神经的做法。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,165,2073692323514028032),(2073692328312311816,'是长期的，而且你认为你（对期权涉及的资产）有所了解，那么使用布莱克—舒\n尔斯模型是一种很神经的做法。  \n \n        布莱克—舒尔斯模型是一套“一无所知”的系统。如果你对价\n值毫不了解，只了解价格，那么利用布莱克—舒尔斯模型，你能够很准确地猜出\n为期 90 天的期权到底值多少钱。但如果期权比 90 天更长久，那么使用这个模型\n就有点神经啦。  \n \n        举例说吧，我们在好市多发行了执行价分别为 30 美元和 60\n美元的股票期权，而布莱克—舒尔斯模型认为 60 美元的期权价值更高。这简直\n是疯了。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n股票期权的会计法 \n \n        那种认为期权没有成本的理论导致大量的公司滥用期权，这种\n情况对美国来说是很糟糕的，因为人们会认为公司的薪酬是不公平的。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,166,2073692323514028032),(2073692328312311817,' \n        那种认为期权没有成本的理论导致大量的公司滥用期权，这种\n情况对美国来说是很糟糕的，因为人们会认为公司的薪酬是不公平的。  \n \n        我已经厌倦了这个话题。这个话题我已经讲了很久啦。用错误\n的会计法来经营一个文明世界实在是很糟糕的。这就好比修建桥梁的时候，把工\n程设计搞错了。当那些颇有声望的人也说股票期权不应该算为成本支出的话，这\n就太过分了。  \n \n        股票期权不但会增加企业的成本，还会稀释股权。任何反对这\n种看法的人都是神经病。股票期权不但会增加企业的成本，还会稀释股权。任何\n反对这种看法的人都是神经病。  \n \n        这些人（投票支持不将股票期权算为成本的 88 名参议员）是\n愚蠢而可耻的。他们知道那是错误的，偏偏还那么做。  \n \n \n        这件事从头到尾都让人恶心。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,167,2073692323514028032),(2073692328312311818,'愚蠢而可耻的。他们知道那是错误的，偏偏还那么做。  \n \n \n        这件事从头到尾都让人恶心。  \n \n        我宁愿在妓院弹钢琴谋生， 也不愿像约翰·多尔（注：著名\n硅谷风险投资家，但因强烈反对将股票期权算作成本而广受诟病）推荐的那样，\n靠股票期权来赚钱。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n对金融机构和衍生品的警告 \n金融机构的风险 \n \n        金融机构的本质决定了它很容易阴沟里翻船。你有可能放贷太\n多，进行了愚蠢的收购，或者过度借贷——不仅仅是衍生品（才会让你倒闭）。  \n \n        也许没有人像我们这样，但我们对金融风险特别敏感。当金融\n机构想努力表现时，我们就会感到紧张。  \n \n        我们尤其害怕那些大量举债的金融机构。如果他们开始说起风','2026-07-05 16:55:53.049000',0,2073692323954429952,168,2073692323514028032),(2073692328312311819,'机构想努力表现时，我们就会感到紧张。  \n \n        我们尤其害怕那些大量举债的金融机构。如果他们开始说起风\n险管理有多么好，我们就会很紧张。  \n \n        我们比其他人更加警惕。如果感到不安，我们很快就会把大量\n的钱抽出来。这是我们的经营方式——你必须适应它。 \n衍生品 \n \n        衍生品系统简直是神经病，它完全不负责任。人们以为的固定\n资产并不是真正的固定资产。它太复杂了，我在这里没办法说清楚——但你无法\n相信涉及的金额达到几万亿美元那么多。你无法相信它有多么复杂。你无法相信\n衍生品的会计工作有多难。你无法相信人们对企业的价值和清算能力的一厢情愿\n的想法会产生多大的激励作用。  \n \n        人们不去考虑后果的后果。人们开始只想对冲利率变化带来的\n风险，这是非常困难和复杂的事情。然后呢，对冲操作导致了（公布的盈利）波','2026-07-05 16:55:53.049000',0,2073692323954429952,169,2073692323514028032),(2073692328316506112,' \n        人们不去考虑后果的后果。人们开始只想对冲利率变化带来的\n风险，这是非常困难和复杂的事情。然后呢，对冲操作导致了（公布的盈利）波\n动。所以他们用新的衍生品来抹平。这个时候你就不得不说谎了。这就变成了“疯\n帽匠的茶话会”。那些庞大的、复杂的公司会出现这种情况。  \n \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        必须有人站出来说：“我们不做这种事情——因为这太难\n了。”  \n \n        我认为， 要测试任何（ 有显著衍生品风险的）大型机构的管\n理人员的智力和道德水准，最好的方法是问他们：“你真的能理解你的衍生品账\n目吗？”如果有人说是，那这个人要么疯掉了，要么是在说谎。  \n \n        说起能源衍生品（的情况），你会更容易理解（这种危险）——','2026-07-05 16:55:53.049000',0,2073692323954429952,170,2073692323514028032),(2073692328316506113,'目吗？”如果有人说是，那这个人要么疯掉了，要么是在说谎。  \n \n        说起能源衍生品（的情况），你会更容易理解（这种危险）——\n它们全部完蛋了。当（那些公司）想要动用他们的账本上写着的财产时，钱并不\n在那里。而说到金融资产，这样的结局还没有出现，会计规则也还没变，所以这\n种结局会在将来出现。  \n \n        衍生品有很多条款说如果一方的信用被调低，那么它必须增加\n抵押金。那就像股票账户的贷款保证金一样——你将会（由于增加更多的保证金\n而）破产。为了保护自己，他们引入了不稳定的因素。似乎没有人意识到他们创\n造的系统是一个大灾难。那是一个疯狂的系统。  \n        在工程领域，人们拥有很大的安全边际。但在金融界，人们根\n本不考虑安全。他们只是追求扩张扩张扩张。做假账为此推波助澜。对此我比沃\n伦更加悲观。 \n \n衍生品的会计法 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,171,2073692323514028032),(2073692328316506114,'本不考虑安全。他们只是追求扩张扩张扩张。做假账为此推波助澜。对此我比沃\n伦更加悲观。 \n \n衍生品的会计法 \n \n        我非常讨厌将 GAAP（公认会计准则）应用于衍生品和掉期协\n议。摩根大通为了虚报的前端收入将自己彻底出卖给了这种会计准则。我觉得这\n种做法很无耻。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        这种做法很疯狂，会计人员出卖了自己的职业操守。每个人都\n屈服了，采用了宽松的（会计）标准，创造出和各种理论模型相关的怪异衍生品。\n结果就是，产生了大量由会计人员捏造出来的利润，而不是真实的收益。当你想\n动用那笔钱的时候，它就消失不见了。它从来就不曾存在过。  \n \n        它（衍生品的会计法）就是这么恶心。它像阴沟那么臭，如果\n我猜得没错，那些公司将会付出沉重的代价。你所能做的就是想好当账本上那些','2026-07-05 16:55:53.049000',0,2073692323954429952,172,2073692323514028032),(2073692328316506115,' \n        它（衍生品的会计法）就是这么恶心。它像阴沟那么臭，如果\n我猜得没错，那些公司将会付出沉重的代价。你所能做的就是想好当账本上那些\n衍生品破灭时该怎么办。  \n \n        说美国衍生品的会计法像阴沟是对阴沟的侮辱。  \n衍生品破灭的可能性 \n \n        我们试图卖掉通用再保险公司的衍生品业务，但没有成功，所\n以我们开始清算它。我们不得不大幅削减价格。我非常有把握地预测（美国的）\n主要银行无法以账本上的价格清算它们持有的衍生品。结局什么时候出现，会有\n多么糟糕，我现在说不准。但我担心后果会很可怕。我认为将会出现比能源领域\n更大的问题，你看看能源领域被破坏成什么样就知道了。  \n \n        在未来五到十年里，如果美国没有遇到（和衍生品相关的）大\n问题，我将会非常吃惊。  \n \n        我认为我们是美国惟一甩掉衍生品账本的大型公司。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,173,2073692323514028032),(2073692328316506116,'问题，我将会非常吃惊。  \n \n        我认为我们是美国惟一甩掉衍生品账本的大型公司。  \n \n        对于已经很有钱的公司而言，比如说伯克希尔，去从事这种业\n务是很神经的想法。对大银行来讲，衍生品是一桩疯狂的生意。  \n \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n对律师、律师事务所和诉讼的批评 \n \n律师事务所的道德沦丧 \n \n        对于为恶棍辩护并帮助他们逃脱法律的制裁，我从来没有哪怕\n一丁点的兴趣。但很多人认为，约翰尼·科克兰做得很漂亮（帮助 O. J. 辛普\n森开脱）。  \n律师搞砸了玛莎·斯图亚特的案件 \n \n        玛莎·斯图亚特的情况就是她听到了某些消息，吓坏了，于是\n赶紧把股票卖掉。结果表明，如果她当时说出真相，那就没事了。但因为她隐隐','2026-07-05 16:55:53.049000',0,2073692323954429952,174,2073692323514028032),(2073692328316506117,' \n        玛莎·斯图亚特的情况就是她听到了某些消息，吓坏了，于是\n赶紧把股票卖掉。结果表明，如果她当时说出真相，那就没事了。但因为她隐隐\n约约觉得她做的事情是错误的，当检察官前来调查时，她编了虚假的故事欺骗他\n们，那可是重罪。而她这些行为居然是在聘请了那些著名的大律师之后做出的！\n我敢肯定他们收了很多律师费。这些事可不是我编出来的。  \n        如果我是她的律师，我将会说：“你知道吗，玛莎，你说的故\n事很有趣，我是你的律师，我必须相信你，可是其他人没有这样的义务。所以，\n你要么跟我说另外一个故事，要么把这个故事告诉另外一个律师，因为我不喜欢\n打输官司。”这样就行了。就是这么简单。准确地说，她是因为请了律师之后的\n行为才进的监狱！  \n \n \n侵权赔偿制度 \n \n        尤其有害的是原告方律师协会的权力越来越大。州最高法院的','2026-07-05 16:55:53.049000',0,2073692323954429952,175,2073692323514028032),(2073692328316506118,'行为才进的监狱！  \n \n \n侵权赔偿制度 \n \n        尤其有害的是原告方律师协会的权力越来越大。州最高法院的\n法官通常都是终身任职的。但如果严重得罪某些重要的团体，比如说原告方律师\n协会，他们的地位就会岌岌可危。因此，法官允许垃圾科学之类的东西存在。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        由于侵权赔偿制度，已经富裕的公司要避开很多领域。比如说，\n有家公司研发了一种新的警察头盔，它的安全性更高，质量更好；但这家公司把\n产品卖给了一家具有抗判决性的公司（因为头盔开发公司害怕法律责任风险）。\n如果伯克希尔从事为机场提供保安的业务，那将是很疯狂的。侵权赔偿制度不利\n于一些最好的企业进入某些行业。  \n石棉和侵权制度改革 \n \n        石棉事件就演变成了有大量欺诈行为的情况。严重受伤的人正','2026-07-05 16:55:53.049000',0,2073692323954429952,176,2073692323514028032),(2073692328316506119,'于一些最好的企业进入某些行业。  \n石棉和侵权制度改革 \n \n        石棉事件就演变成了有大量欺诈行为的情况。严重受伤的人正\n在继续受伤害（因为越来越多的钱流向了原告律师和那些目前没有受伤的索赔\n者）。最高法院确实有请国会干预，但国会受到出庭律师的影响，拒绝了最高法\n院的请求。未来五年如果出现什么有建设性的解决办法，我将会非常吃惊。我预\n测未来这种乱七八糟的情况会越来越多。  \n \n        石棉事件是这样的，有一群人患上了间皮瘤—— 这是一种可\n怕的癌症，只有长期接触石棉才会罹患，它能致人死亡。然后，有另外一群人每\n天吸两包香烟，肺部出现了一些阴影，他们也要求索赔。那么你请一名律师，律\n师找个医生来证明每一处阴影都是由石棉引起的。只要你有效地贿赂医生，那么\n你就能让几百万个人因害怕得肺癌而提出诉讼。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,177,2073692323514028032),(2073692328316506120,'师找个医生来证明每一处阴影都是由石棉引起的。只要你有效地贿赂医生，那么\n你就能让几百万个人因害怕得肺癌而提出诉讼。  \n \n        但是钱不够（支付给所有的索赔者），所以那些确实受到伤害\n的人并没有得到足够的赔偿。在美国南部某个州的法官仇视所有的大公司（原告\n得到一大笔赔偿金），但律师把钱从受伤者那里偷走了，把钱给了那些没有资格\n获得赔偿的人。这是个很神经的系统，但由于美国实行的是联邦制，没有办法阻\n止这样的事情发生。最高法院拒绝干预。  \n \n        试图靠花钱来息事宁人，就像试图用汽油来灭火一样。有了文\n字处理程序，律师能够轻而易举地捏造无穷多的索赔者。但只有 25%的钱给到索\n赔者手里——其他的都被律师、医生等等拿走了。  \n \n        如果对此不以为然，请你看看他们是怎么做伪证的。现在只剩','2026-07-05 16:55:53.049000',0,2073692323954429952,178,2073692323514028032),(2073692328316506121,'赔者手里——其他的都被律师、医生等等拿走了。  \n \n        如果对此不以为然，请你看看他们是怎么做伪证的。现在只剩\n下三家（面临因石棉致癌而遭到起诉的）溶剂公司，所以原告方（当回忆起几十\n年前他们接触过哪家公司的产品时）只需要记住这三家公司的名字。这是在执业\n律师教唆下做假证的案例。  \n \n        惟一能够解决这个问题的是最高法院或者国会。最高法院拒绝\n干预，有些人可能会说这是对的，（但我觉得）他们没胆量干预。至于国会，由\n于政治方面的原因，到目前尚未插手。 \n \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n        这里有个重要的教训：坏人一旦变得有钱，他们将会获得巨大\n的政治力量，你就无法阻止他们干坏事了，所以关键是把这类事情扼杀在萌芽状\n态。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,179,2073692323514028032),(2073692328316506122,' \n        这里有个重要的教训：坏人一旦变得有钱，他们将会获得巨大\n的政治力量，你就无法阻止他们干坏事了，所以关键是把这类事情扼杀在萌芽状\n态。  \n \n        解决这个问题的方法很简单：正确的方法是申明我们不会为所\n有这些小额赔偿要求买单。 \n美国政府对微软的诉讼 \n \n        （2000 年 4 月）有些人拿着美国纳税人支付的薪水，却兴高\n采烈地想要削弱我们取得很大领先优势的领域！  \n \n        每个企业都试图把今年的成功转换成明年更大的成功。我很难\n理解微软这么做何罪之有。如果这是一种罪，那么我希望伯克希尔·哈撒韦所有\n的子公司都是罪人。  \n \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n思维模型 \n \n多元思维模型的重要性 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,180,2073692323514028032),(2073692328316506123,' \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n思维模型 \n \n多元思维模型的重要性 \n \n        你必须知道重要学科的重要理论，并经常使用它们——要全部\n都用上，而不是只用几种。大多数人都只养成一个学科——比如说经济学——的\n思维模型，试图用一种方法来解决所有问题。你知道谚语是怎么说的：“在手里\n拿着铁锤的人看来，世界就像一颗钉子。”这是一种处理问题的笨方法。  \n \n        遇到不同的公司，你需要检查不同的因素，应用不同的思维模\n型。我无法简单地说：“就是这三点。”你必须自己把它（投资技巧）总结出来，\n一辈子深种在你的大脑中。  \n \n        如果你用的是许多学生使用的那种学习方法，那你将无法掌握\n你需要的那 100 种思想——那些学生学得很好，接着把知识丢回给他们的教授，','2026-07-05 16:55:53.049000',0,2073692323954429952,181,2073692323514028032),(2073692328316506124,' \n        如果你用的是许多学生使用的那种学习方法，那你将无法掌握\n你需要的那 100 种思想——那些学生学得很好，接着把知识丢回给他们的教授，\n拿到一个分数，然后就把知识清空，就好像放掉浴缸里的水，以便下次装更多水\n那样。如果这是你用来学习那 100 种思维模型的方法，在生活中你将会一无所获。\n你必须认真学习这些模型，让它们变成你随时能够使用的本领。  \n \n        顺便说一下，没有规则要求你不能增加一两个新的模型，即使\n你已经步入晚年。实际上，我现在还在不断学习。不过大多数有用的模型是在年\n轻时学到的。  \n \n        我推荐的这些精神领域是非常快乐的，没有人愿意从那里离\n开。离开就像砍断自己的双手。  \n \n \n \n        查理通常会对知识面狭窄作出如下的诊断：“在手里拿着铁锤\n的人看来，世界就像一颗钉子。” \n不自欺的精神 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,182,2073692323514028032),(2073692328316506125,' \n \n \n        查理通常会对知识面狭窄作出如下的诊断：“在手里拿着铁锤\n的人看来，世界就像一颗钉子。” \n不自欺的精神 \n \n        大量的人很荒唐地死抱着错误的观念不放。凯恩斯说：“介绍\n新观念倒不是很难，难的是清除那些旧观念。”  \n \n        不自欺的精神是你能拥有的最好的精神。它非常强大，因为它\n太少见了。  \n \n \n大地是平的还是圆的？ \n \n        早在公元 140 年，托勒密绘制了一张将大地描绘成球体的地\n图。中世纪的教会拒绝这种希腊思想，称之为邪教：大地是平的——大地之上是\n天堂，之下是地狱，两者之间生活着男人和女人。在数百年里，水手害怕看不到\n陆地，海上航行都紧紧靠着海岸线。但从 14 世纪开始，海洋探险活动此起彼伏\n——众多岛屿、国家和大陆都被发现了。许多探险家——马可·波罗、克里斯托','2026-07-05 16:55:53.049000',0,2073692323954429952,183,2073692323514028032),(2073692328320700416,'陆地，海上航行都紧紧靠着海岸线。但从 14 世纪开始，海洋探险活动此起彼伏\n——众多岛屿、国家和大陆都被发现了。许多探险家——马可·波罗、克里斯托\n弗·哥伦布、瓦斯科·达·伽马——完成了发现之旅。已知世界随着每次远航而\n扩张，直到每个愿意直面证据的人都能明白大地确实是圆的。最终，麦哲伦舰队\n惟一幸存的轮船维多利亚号环绕世界一圈，终结了这个争议。  \n \n        未知的地界，丹尼尔·布尔斯廷的著作《发现者》的封面插图，\n出自贝特曼档案馆收藏的 16 世纪木刻画。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n常（非常）识 \n \n        得到系统的常（非常）识——非常基础的知识——是一种威力\n巨大的工具。电脑带来的危险非常多。人们计算得太多，思考得太少。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,184,2073692323514028032),(2073692328320700417,' \n        得到系统的常（非常）识——非常基础的知识——是一种威力\n巨大的工具。电脑带来的危险非常多。人们计算得太多，思考得太少。  \n \n        拥有常识不但意味着有能力辨认智慧，也意味着有能力拒绝愚\n蠢。如果排除了许多事情，你就不会把自己搞得一团糟。  \n \n        我们看很多书。我认识的聪明人没有不看很多书的。但光看书\n还不够：你必须拥有一种能够掌握思想和做合理事情的性格。大多数人无法掌握\n正确的思想，或者不知道该怎么应用它们。  \n \n        你拥有的基本知识越多，你需要吸取的新知识就越少。那个蒙\n上眼睛下棋的家伙（他是个象棋大师，在伯克希尔·哈撒韦开年会那个周末赶到\n奥马哈展示他的棋技，蒙上眼睛同时跟好几个人对弈）——他拥有关于棋盘的知\n识，这使他能够那么做。  \n经商和象棋大师 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,185,2073692323514028032),(2073692328320700418,'奥马哈展示他的棋技，蒙上眼睛同时跟好几个人对弈）——他拥有关于棋盘的知\n识，这使他能够那么做。  \n经商和象棋大师 \n \n        辛格尔顿是 Teledyne 公司的联合创办人，担任这家位于洛杉\n矶的跨国公司总裁长达 30 年之久。他原先读的是海军学院，后来转学到麻省理\n工学院，在那里得到了学士、硕士和博士学位，专业是电子工程学。他是极其优\n秀的棋手，距离特级大师只差 100 个积分，能够不看棋盘跟人对弈。  \n \n        从 1963 年到 1990 年，Teledyne 每年给股东的复合回报率达\n到了令人震惊的20.4%——同期标准普尔的回报率是8%。在1972年到1984年间，\n辛格尔顿聪明地回购了 90%的 Teledyne 流通股，他是现代商业史上罕有其匹的\n管理人员和资产配置大师。  \n \n        和沃伦·巴菲特一样敬佩亨利·辛格尔顿的查理问：“考虑到','2026-07-05 16:55:53.049000',0,2073692323954429952,186,2073692323514028032),(2073692328320700419,'管理人员和资产配置大师。  \n \n        和沃伦·巴菲特一样敬佩亨利·辛格尔顿的查理问：“考虑到\n这个人的才华和业绩，我们很好地吸取了他的经验了吗？” \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n对高等教育的批评 \n \n致命的无关联性 \n \n        （美国的大学）有很多毛病。要是我的话，我会砍掉四分之三\n的院系——除了自然科学，一个都不留。但没有人会这么做，所以我们不得不忍\n受那些毛病。（高等教育）错误程度让人吃惊。学科之间毫无关联，这是致命的。\n大学里每个系都有些看不见大环境的古怪家伙。  \n \n        我认为美国各所主要大学的人文社科教授的观点都经不起推\n敲，至少他们的公共政策理论是这样的。（不过呢，）他们可能对法语了解蛮多\n的。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,187,2073692323514028032),(2073692328320700420,' \n        我认为美国各所主要大学的人文社科教授的观点都经不起推\n敲，至少他们的公共政策理论是这样的。（不过呢，）他们可能对法语了解蛮多\n的。  \n \n        怀特海（注：阿尔弗雷德·诺斯·怀特海，1861—1947，英国\n数学家、哲学家和教育理论家，“过程哲学”创始人，与伯特兰·罗素合著《数\n学原理》）曾经指出，学科各自孤立的情况是致命的，每个教授并不了解其他学\n科的思维模型，将其他学科和他自己的学科融会贯通就更别提了。我想怀特海讨\n厌的这种研究方法有一个现代的名字，那个名字叫做神经研究法。 \n \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n怎样变得幸福、富裕，以及其他建议 \n \n如何获得幸福和成功 \n \n        如果你在生活中惟一的成功就是通过买股票发财，那么这是一\n种失败的生活。生活不仅仅是精明地积累财富。  ','2026-07-05 16:55:53.049000',0,2073692323954429952,188,2073692323514028032),(2073692328320700421,' \n如何获得幸福和成功 \n \n        如果你在生活中惟一的成功就是通过买股票发财，那么这是一\n种失败的生活。生活不仅仅是精明地积累财富。  \n \n        生活和生意上的大多数成功来自于你知道应该避免哪些事情：\n过早死亡、糟糕的婚姻等等。  \n \n        避免染上艾滋病、在路口和火车抢道以及吸毒。培养良好的心\n理习惯。  \n \n        避免邪恶之人，尤其是那些性感诱人的异性。  \n \n        如果因为你的特立独行而在周围人中不受欢迎……那你就随\n他们去吧。  \n满足于你已经拥有的 \n \n        这里是一句你的投资顾问可能会反对的真话：如果你已经相当\n富裕，而别人的财富增长速度比你更快，比如说，在投资高风险的股票上赚了钱，\n那又怎样呢？！总是会有人的财富增长速度比你快。这并不可悲。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,189,2073692323514028032),(2073692328320700422,'富裕，而别人的财富增长速度比你更快，比如说，在投资高风险的股票上赚了钱，\n那又怎样呢？！总是会有人的财富增长速度比你快。这并不可悲。  \n \n        看看斯坦利· 德鲁肯米勒（ 他管理乔治·索罗斯的基金，由\n于投机高科技股票和生物科技股票而蒙受惨重的损失）吧：他总是必须成为最好\n的，无法容忍其他人在这些投资领域击败他。  \n \n        索罗斯无法忍受其他人从科技产业赚钱而自己没有赚到，他亏\n得一塌糊涂。我们根本就不在意（别人在科技产业赚了钱）。  \n提防妒忌 \n \n        关注别人赚钱（比你）更快的想法是一种致命的罪行。妒忌真\n的是一种愚蠢的罪行，因为它是仅有的一种你不可能得到任何乐趣的罪行。它只\n会让你痛苦不堪，不会给你带来任何乐趣。你为什么要妒忌呢？ \n \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n如何致富 ','2026-07-05 16:55:53.049000',0,2073692323954429952,190,2073692323514028032),(2073692328320700423,' \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n如何致富 \n \n        （有个年轻的股东问查理要怎样才能追随他的足迹，查理的回\n答折服了在场的所有人。）  \n \n        许多年轻的生意人都问我们这个问题。这是一个聪明的问题：\n你看见某个有钱的老头，然后问他：“我要怎样才能变得像你一样呢？”  \n \n        每天起床的时候，争取变得比你从前更聪明一点。认真地、出\n色地完成你的任务。慢慢地，你会有所进步，但这种进步不一定很快。但你这样\n能够为快速进步打好基础……每天慢慢向前挪一点。到最后——如果你足够长寿\n的话——大多数人得到了他们应得的东西。  \n如何找到好配偶 \n \n        找到好配偶的最佳方法是什么呢？惟一的最佳方法是你首先\n必须值得拥有好配偶，因为从定义上来说，好配偶可绝不是傻瓜。  \n阅读的重要性 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,191,2073692323514028032),(2073692328320700424,' \n        找到好配偶的最佳方法是什么呢？惟一的最佳方法是你首先\n必须值得拥有好配偶，因为从定义上来说，好配偶可绝不是傻瓜。  \n阅读的重要性 \n \n        我这辈子遇到的聪明人（来自各行各业的聪明人）没有不每天\n阅读的——没有，一个都没有。沃伦读书之多，我读书之多，可能会让你感到吃\n惊。我的孩子们都笑话我。他们觉得我是一本长了两条腿的书。  \n \n        我本人是个传记书迷。我觉得你要是想让人们认识有用的伟大\n概念，最好是将这些概念和提出它们的伟人的生活和个性联系起来。我想你要是\n能够和亚当·斯密交朋友，那你的经济学肯定可以学得更好。和“已逝的伟人”\n交朋友，这听起来很好玩，但如果你确实在生活中与已逝的伟人成为朋友，那么\n我认为你会过上更好的生活，得到更好的教育。这种方法比简单地给出一些基本\n概念好得多。  \n减少物质需求 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,192,2073692323514028032),(2073692328320700425,'我认为你会过上更好的生活，得到更好的教育。这种方法比简单地给出一些基本\n概念好得多。  \n减少物质需求 \n \n        大多数人将会发现回报率下降了（由于通货膨胀）。如果你担\n心通货膨胀，最好的预防手段之一就是在你的生活中别拥有大量愚蠢的需求——\n你不需要很多物质的商品。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n慈善 \n \n        （（沃伦和我）觉得我们这些非常幸运的人有责任反馈社会。\n至于是像我这样在活着的时候捐赠大量的钱，还是像沃伦那样，先捐一点，（等\n去世之后）再捐很多，那是个人喜好的问题。我恐怕不会喜欢人们整天问我要钱。\n沃伦更无法忍受这种情况。  \n \n \n避免欠债 \n \n        你一旦走进负债的怪圈，就很难走出来。千万别欠信用卡的钱。\n你无法在支付 18%的利息的情况下取得进展。  \n公立学校的衰落 ','2026-07-05 16:55:53.049000',0,2073692323954429952,193,2073692323514028032),(2073692328320700426,' \n避免欠债 \n \n        你一旦走进负债的怪圈，就很难走出来。千万别欠信用卡的钱。\n你无法在支付 18%的利息的情况下取得进展。  \n公立学校的衰落 \n \n        你完全可以说这（公立学校的衰落）是我们时代的主要灾难之\n一。我们将地球史上最大的成功之一变成了地球史上最大的灾难之一。  \n日本的经济衰退 \n \n        日本的经济衰退足以令每个人大惊失色，它持续了十年，尽管\n利率低于 1%。政府把所有的货币政策游戏都玩过了，但毫无用处。如果你向哈\n佛大学的经济学家描绘这种情况，他们会说这是不可能的。然而与此同时，香港\n却出现了资产泡沫。为什么？因为日本和中国拥有两种非常不同的文化。中国人\n喜欢赌博。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n幽默 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,194,2073692323514028032),(2073692328320700427,'喜欢赌博。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n幽默 \n \n        ※（我宁愿将毒蛇丢进我的衬衣里，也不愿聘用一名薪酬顾问。  \n \n        ※（在鸡尾酒会上，有人问查理是否会弹钢琴，查理回答说：）\n“我不知道，我从来没试过。”  \n \n        ※如果某个吸引我的人同意我的观点，我就会很高兴，所以我\n对菲尔·费舍尔（见第 62 页注释）有很多美好的回忆。  \n \n        ※当然，自我表扬起到的积极作用一般来说比别人的表扬要\n大。实际上，今天在这里为你们演讲的人可能就会遇到这样的问题。  \n \n        如果你把葡萄干和大便搅在一起，你得到的仍然是大便。（这\n是他在将互联网与科技给社会带来的好处和这些行业的股票投机的恶果进行对\n比时所说的话。）  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,195,2073692323514028032),(2073692328320700428,'是他在将互联网与科技给社会带来的好处和这些行业的股票投机的恶果进行对\n比时所说的话。）  \n \n        ※在企业界，如果你聘请了分析师，在并购时进行了尽职调查，\n却不具备常识，那么你遇到的将会是地狱。  \n \n        ※我们很久没有进行收购啦，所以那（问我们当我们交易时对\n市场造成的影响）就像问瑞普·凡·温克尔 20 年前的事情一样。  \n \n        ※当年我刚到加利福尼亚州的时候，那里的议会尚不健全，受\n到赌场老板、马会所有者和卖酒商人的控制，这些人请议员们吃喝嫖赌。和今天\n健全的议会相比，我想我更喜欢当时的情况。  \n \n        ※（关于《深奥的简洁》那本书）想要理解万物是非常困难的，\n但如果你无穷查理宝典法理解它，你可以把问题交给一位比你聪明的朋友呀。  \n \n        ※如果你取得了很高的地位，那么你必须遵守某些行为规则。','2026-07-05 16:55:53.049000',0,2073692323954429952,196,2073692323514028032),(2073692328324894720,'但如果你无穷查理宝典法理解它，你可以把问题交给一位比你聪明的朋友呀。  \n \n        ※如果你取得了很高的地位，那么你必须遵守某些行为规则。\n如果你是一个喜欢酗酒的铲沙工人，你可以去脱衣舞俱乐部；但如果你是波士顿\n的主教，那你就不应该去了。  \n \n        ※我想那些喜欢当监狱看守的人不会是天生品德高尚的人。  \n \n        ※你不会想成为那个电影制片人的。很多人出席了他的葬礼，\n但人们只是想确定他已经死了。你也不会想成为另外一个家伙，在那人的葬礼上，\n神父说：“有人愿意站起来，对死者说点好话吗？”最后有个人说：“好吧，他\n的兄弟更糟糕。”  \n \n        ※（在 1999 年伯克希尔·哈撒韦的年会上，有人问查理 2000\n年千年虫的问题，他回答说：）我觉得很有趣竟然有这样一个问题。你知道吗，\n可以预测，2000 年将会到来。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,197,2073692323514028032),(2073692328324894721,'年千年虫的问题，他回答说：）我觉得很有趣竟然有这样一个问题。你知道吗，\n可以预测，2000 年将会到来。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n辛普森谈芒格 \n \n        到对他有更深的了解之后，我才发现他有多么特别。我和查理\n相识到现在已经 25 年了，我有机会看到他在许多情况之下的表现，包括 1990\n年代初期发生的所罗门债券危机，当时我们都是该公司董事会的成员。  \n \n        查理身上某些性格特点组合，我可以肯定我从未在其他人身上\n看到过。他聪明绝顶，兴趣广泛，似乎从来不会忘记任何事情，哪怕是很深奥或\n者很细小的事情。他最大的优点是诚实、道德和正直的绝对坚持——查理从来不\n为自己“攫取”非分之物，值得毫无保留地信任。如果这些还不够，他还拥有一','2026-07-05 16:55:53.049000',0,2073692323954429952,198,2073692323514028032),(2073692328324894722,'者很细小的事情。他最大的优点是诚实、道德和正直的绝对坚持——查理从来不\n为自己“攫取”非分之物，值得毫无保留地信任。如果这些还不够，他还拥有一\n种最适合投资的理想性格：毫不妥协的耐心，自律，自控——无论遭受多大的压\n力，查理从来不会动摇或者改变他的原则。  \n \n        这么多年来，我们非常幸运地拥有查理·芒格和沃伦·巴菲特\n这对天才来做我们的合伙人、导师和典范。这两位真的是非常罕见的人。  \n芒格谈辛普森 \n \n        。我很高兴在今年（2005 年）写给股东的公开信里，沃伦打\n印了路易斯过去 25 年来的投资业绩记录。连续两年、五年甚至十年打败市场平\n均收益率的事情并不是没有听过。但谁能想得到居然有人连续 25 年的年均回报\n率高于标准普尔 500 指数的增长率 6.8 个百分点！这份非凡的业绩记录足以说明','2026-07-05 16:55:53.049000',0,2073692323954429952,199,2073692323514028032),(2073692328324894723,'均收益率的事情并不是没有听过。但谁能想得到居然有人连续 25 年的年均回报\n率高于标准普尔 500 指数的增长率 6.8 个百分点！这份非凡的业绩记录足以说明\n问题——路易斯是我们这个时代最伟大的投资者之一。正如沃伦说的，他是“投\n资名人堂里的常胜将军”。  \n \n        我非常清楚地记得 1990 年代末期路易斯是怎么处理互联网经\n济泡沫的。你无法想像他承受了多大的压力，年复一年，整个世界似乎获得大丰\n收，而他正确地、彻底地避开了那个泡沫，坚守基本的投资原则。在那些年，路\n易斯是一个了不起的楷模——聪明、可敬，坚守他的原则。 \n（2001 年至 2006 年在伯克希尔·哈撒韦公司和西科金融公司年会上的谈话摘\n录） \n \n塞内加尔谈芒格 \n \n        八年前，查理同意在洛杉矶的加州俱乐部和我共进午餐，于是','2026-07-05 16:55:53.049000',0,2073692323954429952,200,2073692323514028032),(2073692328324894724,'录） \n \n塞内加尔谈芒格 \n \n        八年前，查理同意在洛杉矶的加州俱乐部和我共进午餐，于是\n我非常愉快地认识了他。我的目的是说服他加入好市多，成为我们的董事。刚见\n面时，查理说他非常喜欢在好市多购物，我一下子就喜欢他了；我们的对话不断\n被打断——当天去吃饭的还有另外 500 个人，每个人都想跟查理寒暄几句，而查\n理几乎能叫出他们所有人的名字——尽管如此，我们还是聊得很好。查理首先敏\n锐地指出好市多的会员制非常有价值。当然，后来我听说查理以节俭闻名，而省\n钱正是好市多吸引顾客的地方。但是，最重要的是，我更加清楚地认识到他的直\n率和基于常识的敏锐商业触觉。  \n \n        后来他打电话给我，说同意担任董事，他称自己为古稀老人。\n他居然会跟从事仓储业的人说起这么文雅的词汇；他觉得我能听懂，这让我的虚\n荣心得到很大的满足。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,201,2073692323514028032),(2073692328324894725,'他居然会跟从事仓储业的人说起这么文雅的词汇；他觉得我能听懂，这让我的虚\n荣心得到很大的满足。  \n \n        自那以后，他尽到了董事的责任和义务。他的洞见、质询和支\n持使好市多的管理和运营都得到了改善。  \n \n        除此之外，我们还常常能够学到芒格的智慧——我们真是幸运\n的人啊！  \n芒格谈塞内加尔 \n \n        。芒格谈塞内加尔你肯定无法相信好市多的仓储业务是多么高\n效和复杂。吉姆·塞内加尔是传奇式的企业经营者——就像卡内基、洛克菲勒或\n者詹姆斯·希尔。我认为他是 20 世纪最出色的五名零售商之一。他有那么好。  \n \n        他每周工作 80 个小时，并在职业操守、正直、忠诚和无私方\n面为整个企业树立起杰出的榜样。他既是行动上的领袖，也是道德上的领袖。这\n些可不是微不足道的优点。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,202,2073692323514028032),(2073692328324894726,'面为整个企业树立起杰出的榜样。他既是行动上的领袖，也是道德上的领袖。这\n些可不是微不足道的优点。  \n \n        我们在好市多公司拥有属于我们自己的活着的、会呼吸的山\n姆·沃尔顿。 \n \n第四章 查理十一讲 \n第一讲：在哈佛学校毕业典礼上的演讲 \n \n \n1986 年 6 月 13 日 \n \n        既然贝里斯福德校长在最老、服务年限最长的董事中挑选出一\n人来作毕业典礼演讲，那么演讲者有必要向大家交待两个问题：  \n \n        1. 为什么作出这种选择？  \n        2. 演讲有多长？  \n \n        凭着我与贝里斯福德多年交往的经验，我先回答第一个问题。\n就像有人很自豪地向人们展示自己的马可以数到七，他正是以这种方式为我们学\n校寻求更高的声誉。马主人知道能数到七并非什么数学壮举，但是他期待得到首\n肯，因为马能够如此表现是值得炫耀一番的。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,203,2073692323514028032),(2073692328324894727,'校寻求更高的声誉。马主人知道能数到七并非什么数学壮举，但是他期待得到首\n肯，因为马能够如此表现是值得炫耀一番的。  \n \n        第二个问题，关于演讲有多长，我并不想预先透露答案。我怕\n说了之后，你们仰起的脸庞将不再充满好奇和满怀期待的神色，而你们现在的表\n情，正好是我喜欢看到的。  \n \n        但我会告诉你们，我是怎样在考虑讲多久的过程中想到这次演\n讲的主题的。接到邀请的时候，我有点飘飘然。虽然缺乏在重要的场合公开发表\n演讲的经验，但我的胆量倒是练得炉火纯青；我立刻想到要效仿德摩斯梯尼和西\n塞罗，而且还期待得到西塞罗所给予的赞誉。当问到最喜欢德摩斯梯尼的哪一次\n演讲时，西塞罗回答：“最长的那次。”  \n \n        不过，在座的各位很幸运，因为我也考虑到塞缪尔·约翰逊的\n那句著名评语，当问及弥尔顿的《失乐园》时，他说得很对：“没有谁希望它更','2026-07-05 16:55:53.049000',0,2073692323954429952,204,2073692323514028032),(2073692328324894728,' \n        不过，在座的各位很幸运，因为我也考虑到塞缪尔·约翰逊的\n那句著名评语，当问及弥尔顿的《失乐园》时，他说得很对：“没有谁希望它更\n长。”这促使我思考，我听过的 20 次哈佛学校的毕业演讲中，哪次曾让我希望\n它再长些呢？这样的演讲只有约翰尼·卡森的那一次，他详述了保证痛苦人生的\n卡森药方。所以呢，我决定重复卡森的演讲，但以更大的规模，并加上我自己的\n药方。毕竟，我比卡森演讲时岁数更大，同一个年轻的有魅力的幽默家相比，我\n失败的次数更多，痛苦更多，痛苦的方式也更多。我显然很有资格进一步发挥卡\n森的主题。  \n \n        那时卡森说他无法告诉毕业的同学如何才能得到幸福，但能够\n根据个人经验，告诉他们如何保证自己过上痛苦的生活。卡森给的确保痛苦生活\n的处方包括：  \n \n        1. 为了改变心情或者感觉而使用化学物质；  \n        2. 妒忌，以及  ','2026-07-05 16:55:53.049000',0,2073692323954429952,205,2073692323514028032),(2073692328324894729,'的处方包括：  \n \n        1. 为了改变心情或者感觉而使用化学物质；  \n        2. 妒忌，以及  \n        3. 怨恨。 \n  我现在还能想起来当时卡森用言之凿凿的口气说，他一次又一次地尝试了这些\n东西，结果每次都变得很痛苦。  \n \n        要理解卡森为痛苦生活所开处方的第一味药物（使用化学物质）比较容易。\n我想补充几句。我年轻时最好的朋友有四个，他们非常聪明、正直和幽默，自身\n条件和家庭背景都很出色。其中两个早已去世，酒精是让他们早逝的一个因素；\n第三个人现在还醉生梦死地活着——假如那也算活着的话。  \n \n        那时卡森说他无法告诉毕业的同学如何才能得到幸福，但能够根据个人经\n验，告诉他们如何保证自己过上痛苦的生活。  \n \n        虽然易感性因人而异，我们任何人都有可能通过一个开始时难以察觉直到堕','2026-07-05 16:55:53.049000',0,2073692323954429952,206,2073692323514028032),(2073692328324894730,'验，告诉他们如何保证自己过上痛苦的生活。  \n \n        虽然易感性因人而异，我们任何人都有可能通过一个开始时难以察觉直到堕\n落之力强大到无法冲破的细微过程而染上恶瘾。不过呢，我活了 60 年，倒是没\n有见过有谁的生活因为害怕和避开这条诱惑性的毁灭之路而变得更加糟糕。  \n \n        妒忌，和令人上瘾的化学物质一样，自然也能获得导致痛苦生活的大奖。早\n在遭到摩西戒律的谴责之前，它就已造成了许多大灾难。如果你们希望保持妒忌\n对痛苦生活的影响，我建议你们千万别去阅读塞缪尔·约翰逊的任何传记，因为\n这位虔诚基督徒的生活以令人向往的方式展示了超越妒忌的可能性和好处。  \n \n        就像卡森感受到的那样，怨恨对我来说也很灵验。如果你们渴望过上痛苦的\n生活，我找不到比它更灵的药方可以推荐给你们了。约翰逊说得好，他说生活本','2026-07-05 16:55:53.049000',0,2073692323954429952,207,2073692323514028032),(2073692328324894731,' \n        就像卡森感受到的那样，怨恨对我来说也很灵验。如果你们渴望过上痛苦的\n生活，我找不到比它更灵的药方可以推荐给你们了。约翰逊说得好，他说生活本\n已艰辛得难以下咽，何必再将它塞进怨恨的苦涩果皮里呢。  \n \n        约翰逊说得好，他说生活本已艰辛得难以下咽，何必再将它塞进怨恨的苦涩\n果皮里呢。  \n \n        对于你们之中那些想得到痛苦生活的人，我还要建议你们别去实践狄斯雷利\n的权宜之计，它是专为那些无法彻底戒掉怨恨老习惯的人所设计的。在成为伟大\n的英国首相的过程中，狄斯雷利学会了不让复仇成为行动的动机，但他也保留了\n某种发泄怨恨的办法，就是将那些敌人的名字写下来，放到抽屉里。然后时不时\n会翻看这些名字，自得其乐地记录下世界是怎样无须他插手就使他的敌人垮掉\n的。  \n \n        我们任何人都有可能通过一个开始时难以察觉直到堕落之力强大到无法冲','2026-07-05 16:55:53.049000',0,2073692323954429952,208,2073692323514028032),(2073692328324894732,'的。  \n \n        我们任何人都有可能通过一个开始时难以察觉直到堕落之力强大到无法冲\n破的细微过程而染上恶瘾。 \n好啦，卡森开的处方就说到这里。接下来是芒格另开的四味药。  \n \n        第一，要反复无常，不要虔诚地做你正在做的事。只要养成这个习惯，你们\n就能够绰绰有余地抵消你们所有优点共同产生的效应，不管那种效应有多么巨\n大。如果你们喜欢不受信任并被排除在对人类贡献最杰出的人群之外，那么这味\n药物最适合你们。养成这个习惯，你们将会永远扮演寓言里那只兔子的角色，只\n不过跑得比你们快的不再只是一只优秀的乌龟，而是一群又一群平庸的乌龟，甚\n至还有些拄拐杖的平庸乌龟。  \n \n        我必须警告你们，如果不服用我开出的第一味药，即使你们最初的条件并不\n好，你们也可能会难以过上痛苦的日子。我有个大学的室友，他以前患有严重的','2026-07-05 16:55:53.049000',0,2073692323954429952,209,2073692323514028032),(2073692328324894733,' \n        我必须警告你们，如果不服用我开出的第一味药，即使你们最初的条件并不\n好，你们也可能会难以过上痛苦的日子。我有个大学的室友，他以前患有严重的\n阅读障碍症，现在也是。但他算得上我认识的人中最可靠的。他的生活到目前为\n止很美满，拥有出色的太太和子女，掌管着某个数十亿美元的企业。如果你们想\n要避免这种传统的、主流文化的、富有成就的生活，却又坚持不懈地做到为人可\n靠，那么就算有其他再多的缺点，你们这个愿望恐怕也会落空。  \n \n        说到“到目前为止很美满”这样一种生活，我忍不住想在这里引用克洛伊斯的\n话来再次强调人类生存状况那种“到目前为止”的那一面。克洛伊斯曾经是世界上\n最富裕的国王，后来沦为敌人的阶下囚，就在被活活烧死之前，他说：“哎呀，\n我现在才想起历史学家梭伦说过的那句话，‘在生命没有结束之前，没有人的一\n生能够被称为是幸福的。’”  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,210,2073692323514028032),(2073692328329089024,'我现在才想起历史学家梭伦说过的那句话，‘在生命没有结束之前，没有人的一\n生能够被称为是幸福的。’”  \n \n        我为痛苦生活开出的第二味药是，尽可能从你们自身的经验获得知识，尽量\n别从其他人成功或失败的经验中广泛地吸取教训，不管他们是古人还是今人。这\n味药肯定能保证你们过上痛苦的生活，取得二流的成就。  \n \n        只要看看身边发生的事情，你们就能明白拒不借鉴别人的教训所造成的后\n果。人类常见的灾难全都毫无创意——酒后驾车导致的身亡，鲁莽驾驶引起的残\n疾，无药可治的性病，加入毁形灭性的邪教的那些聪明的大学生被洗脑后变成的\n行尸走肉，由于重蹈前人显而易见的覆辙而导致的生意失败，还有各种形式的集\n体疯狂等等。你们若要寻找那条通往因为不小心、没有创意的错误而引起真正的\n人生麻烦的道路，我建议你们牢牢记住这句现代谚语：“人生就像悬挂式滑翔，\n起步没有成功就完蛋啦。”  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,211,2073692323514028032),(2073692328329089025,'人生麻烦的道路，我建议你们牢牢记住这句现代谚语：“人生就像悬挂式滑翔，\n起步没有成功就完蛋啦。”  \n \n        避免广泛吸取知识的另一种做法是，别去钻研那些前辈的最好成果。这味药\n的功效在于让你们得到尽可能少的教育。  \n \n        如果我再讲一个简短的历史故事，或许你们可以看得更清楚，从而更有效地\n过上与幸福无缘的生活。从前有个人，他勤奋地掌握了前人最优秀的成果，尽管\n开始研究分析几何的时候他的基础并不好，学得非常吃力。最终，他本人取得的\n成就引起了众人的瞩目，他是这样评价他自己的成果的： \n  “如果说我比其他人看得更远，那是因为我站在巨人的肩膀上。”  \n \n        这人的骨灰如今埋在西敏斯特大教堂里，他的墓碑上有句异乎寻常的墓志\n铭：“这里安葬着永垂不朽的艾萨克·牛顿爵士。”  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,212,2073692323514028032),(2073692328329089026,' \n        这人的骨灰如今埋在西敏斯特大教堂里，他的墓碑上有句异乎寻常的墓志\n铭：“这里安葬着永垂不朽的艾萨克·牛顿爵士。”  \n \n        我为你们的痛苦生活开出的第三味药是，当你们在人生的战场上遭遇第一、\n第二或者第三次严重的失败时，就请意志消沉，从此一蹶不振吧。因为即使是最\n幸运、最聪明的人，也会遇到许许多多的失败，这味药必定能保证你们永远地陷\n身在痛苦的泥沼里。请你们千万要忽略爱比克泰德亲自撰写的、恰如其分的墓志\n铭中蕴含的教训：“此处埋着爱比克泰德，一个奴隶，身体残疾，极其穷困，蒙\n受诸神的恩宠。”  \n \n        “反过来想，总是反过来想。”雅各比说。他知道事物的本质决定了许多难题\n只有在逆向思考的时候才能得到最好的解决。  \n \n        为了让你们过上头脑混乱、痛苦不堪的日子，我所开的最后一味药是，请忽','2026-07-05 16:55:53.049000',0,2073692323954429952,213,2073692323514028032),(2073692328329089027,'只有在逆向思考的时候才能得到最好的解决。  \n \n        为了让你们过上头脑混乱、痛苦不堪的日子，我所开的最后一味药是，请忽\n略小时候人们告诉我的那个乡下人故事。曾经有个乡下人说：“要是知道我会死\n在哪里就好啦，那我将永远不去那个地方。”大多数人和你们一样，嘲笑这个乡\n下人的无知，忽略他那朴素的智慧。如果我的经验有什么借鉴意义的话，那些热\n爱痛苦生活的人应该不惜任何代价避免应用这个乡下人的方法。若想获得失败，\n你们应该将这种乡下人的方法，也就是卡森在演讲中所用的方法，贬低得愚蠢之\n极、毫无用处。  \n \n        卡森采用的研究方法是把问题反过来想。就是说要解出 X，得先研究如何才\n能得到非 X。伟大的代数学家雅各比用的也是卡森这种办法，众所周知，他经常\n重复一句话：“反过来想，总是反过来想。”雅各比知道事物的本质是这样的，许','2026-07-05 16:55:53.049000',0,2073692323954429952,214,2073692323514028032),(2073692328329089028,'能得到非 X。伟大的代数学家雅各比用的也是卡森这种办法，众所周知，他经常\n重复一句话：“反过来想，总是反过来想。”雅各比知道事物的本质是这样的，许\n多难题只有在逆向思考的时候才能得到最好的解决。例如，当年几乎所有人都在\n试图修正麦克斯韦的电磁定律，以便它能够符合牛顿的三大运动定律，然而爱因\n斯坦却转了个 180 度大弯，修正了牛顿的定律，让其符合麦克斯韦的定律，结果\n他发现了相对论。  \n \n        作为一个公认的传记爱好者，我认为假如查尔斯·罗伯特·达尔文是哈佛学校\n1986 届毕业班的学生，他的成绩大概只能排到中等。然而现在他是科学史上的\n大名人。如果你们希望将来碌碌无为，那么千万不能以达尔文为榜样。  \n \n        达尔文能够取得这样的成就，主要是因为他的工作方式；这种方式有悖于所\n有我列出的痛苦法则，而且还特别强调逆向思考：他总是致力于寻求证据来否定','2026-07-05 16:55:53.049000',0,2073692323954429952,215,2073692323514028032),(2073692328329089029,' \n        达尔文能够取得这样的成就，主要是因为他的工作方式；这种方式有悖于所\n有我列出的痛苦法则，而且还特别强调逆向思考：他总是致力于寻求证据来否定\n他已有的理论，无论他对这种理论有多么珍惜，无论这种理论是多么得之不易。\n与之相反，大多数人早年取得成就，然后就越来越拒绝新的、证伪性的信息，目\n的是让他们最初的结论能够保持完整。他们变成了菲利普·威利所评论的那类人：\n“他们固步自封，满足于已有的知识，永远不会去了解新的事物。” \n \n \n        达尔文的生平展示了乌龟如何可以在极端客观的态度的帮助\n下跑到兔子前面去。这种态度能够帮助客观的人最后变成“蒙眼拼驴尾”游戏中\n惟一那个没有被遮住眼睛的玩家。  \n \n        达尔文的生平展示了乌龟如何可以在极端客观态度的帮助下\n跑到兔子前面去。这种态度能够帮助客观的人最后变成“蒙眼拼驴尾”游戏中惟','2026-07-05 16:55:53.049000',0,2073692323954429952,216,2073692323514028032),(2073692328329089030,' \n        达尔文的生平展示了乌龟如何可以在极端客观态度的帮助下\n跑到兔子前面去。这种态度能够帮助客观的人最后变成“蒙眼拼驴尾”游戏中惟\n一那个没有被遮住眼睛的玩家。  \n \n        如果你们认为客观态度无足轻重，那么你们不但忽略了来自达\n尔文的训诲，也忽略了来自爱因斯坦的教导。爱因斯坦说他那些成功的理论来自\n“好奇、专注、毅力和自省”。他所说的自省，就是不停地试验与推翻他自己深\n爱的想法。  \n \n \n        最后，尽可能地减少客观性，这样会帮助你减少获得世俗好处\n所需作出的让步以及所要承受的负担，因为客观态度并不只对伟大的物理学家和\n生物学家有效。它也能够帮助伯米吉地区的管道维修工更好地工作。因此，如果\n你们认为忠实于自己就是永远不改变你们年轻时的所有观念，那么你们不仅将会\n稳步地踏上通往极端无知的道路，而且还将走向事业中不愉快的经历给你带来的\n所有痛苦。  ','2026-07-05 16:55:53.049000',0,2073692323954429952,217,2073692323514028032),(2073692328329089031,'你们认为忠实于自己就是永远不改变你们年轻时的所有观念，那么你们不仅将会\n稳步地踏上通往极端无知的道路，而且还将走向事业中不愉快的经历给你带来的\n所有痛苦。  \n \n        这次类似于说反话的演讲应该以类似于说反话的祝福来结束。\n这句祝语的灵感来自伊莱休·鲁特引用过的那首讲小狗去多佛的儿歌：“一步又\n一步（，才能到多佛）。”我祝福 1986 届毕业班的同学：  \n \n        在座各位，愿你们在漫长的人生中日日以避免失败为目标而成\n长。 \n重读第一讲 \n \n \n        2006 年，我重读了 1986 年的这篇讲稿，发现没有要修改的地\n方。如果说我产生了新想法的话，我现在更加坚定地认为：1. 在生活中，可靠\n是至关重要的；2. 虽然量子力学对于绝大多数人而言是学不会的，但可靠却是\n几乎每个人都能很好地掌握的。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,218,2073692323514028032),(2073692328329089032,'是至关重要的；2. 虽然量子力学对于绝大多数人而言是学不会的，但可靠却是\n几乎每个人都能很好地掌握的。  \n \n        实际上，我常常发现自己因为总是强调这个可靠的主题而不受\n各所名牌大学的学生欢迎。我只不过是说麦当劳是最值得我们尊敬的机构，然后\n周围那些大学生便会露出震惊的表情，我解释说，这么多年来，麦当劳为数百万\n少年提供了第一份工作，包括许多问题少年，它成功地教会他们中的大多数人最\n需要的一课：承担工作的责任，做可靠的人。接下来我往往会说，如果名牌大学\n能够像麦当劳这样提供有用的教育，我们的世界将会更美好。  \n \n如果 \n避开生活的圈套 以吉卜林的方式 \n        如果你能保持冷静，当你身边的人们 \n        都变得疯狂，纷纷指责你，  \n        如果你能相信自己，当所有人怀疑你 \n        但且让他们怀疑去吧，  ','2026-07-05 16:55:53.049000',0,2073692323954429952,219,2073692323514028032),(2073692328329089033,'        都变得疯狂，纷纷指责你，  \n        如果你能相信自己，当所有人怀疑你 \n        但且让他们怀疑去吧，  \n        如果你遭等待，却不因等待而疲倦，  \n        或者遭受欺骗，却不用谎言回敬，  \n        或者遭到憎恨，却不用憎恨反击，  \n        能够不得意忘形，也能够不巧言令色……  \n        如果你能与凡人交谈，且彬彬有礼，  \n        或与国王同行——而不奴颜婢膝，  \n        如果仇敌和密友都无法伤害你；  \n        如果你在乎每个人，但不会缺了谁就不行，  \n        如果你在想发泄愤怒的那一分钟  \n        去进行六十秒的跑步，  \n        大地以及大地上的万物都将属于你，  \n        而更重要的是，你将是真正的男人，我的孩子！  ','2026-07-05 16:55:53.049000',0,2073692323954429952,220,2073692323514028032),(2073692328329089034,'        去进行六十秒的跑步，  \n        大地以及大地上的万物都将属于你，  \n        而更重要的是，你将是真正的男人，我的孩子！  \n        ——摘自查理向来欣赏的诗歌《如果》  \n \n        本文因曾经刊登在 1995 年 5 月 5 日的《杰出投资者文摘》上\n而享有极高的知名度。该篇演讲是 1994 年查理在南加州大学吉尔福德·巴伯科\n克教授的商务课上发表的。查理在这次演讲中谈到了许多话题，从教育系统到心\n理学，再到拥有常识和非常识的重要性，几乎无所不谈。在解剖企业管理的过程\n中，他精辟地描述了各种心理效应给企业带来的利弊。他还为投资、企业管理以\n及日常生活中的决策——查理认为这才是最重要的——提供了一套杰出的原则。  \n \n        你阅读这篇文章的时间投资将会很快因文本对你决策力的影\n响而获得回报。 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,221,2073692323514028032),(2073692328329089035,' \n        你阅读这篇文章的时间投资将会很快因文本对你决策力的影\n响而获得回报。 \n \n第二讲：论基本的、普世的智慧，及其与投资管理和商业的关系  \n \n \n1994 年 4 月 14 日，南加州大学马歇尔商学院 \n \n        今天，我想对你们的学习课题做点小小的变动——今天的主题\n是选股艺术，它是普世智慧艺术的一个小分支。这让我可以从普世智慧谈起——\n我感兴趣的是更为广泛的普世智慧，因为我觉得现代的教育系统很少传授这种智\n慧，就算有传授，效果也不是很明显。  \n \n        所以呢，这次演讲展开的方式将会有点像心理学家所说的“祖\n母的规矩”——这个规矩来自于祖母的智慧，她说你们必须先吃完胡萝卜，然后\n才准吃甜点。  \n \n        这次演讲的胡萝卜部分涉及的是普世智慧的广义课题，这是个\n很好的切入点。毕竟，现代教育的理论是，你应该先接受一般的教育，再专门钻','2026-07-05 16:55:53.049000',0,2073692323954429952,222,2073692323514028032),(2073692328329089036,' \n        这次演讲的胡萝卜部分涉及的是普世智慧的广义课题，这是个\n很好的切入点。毕竟，现代教育的理论是，你应该先接受一般的教育，再专门钻\n研某个领域。我认为，从某种程度上而言，在你成为一个伟大的选股人之前，你\n需要一些基础教育。  \n \n        这次演讲展开的方式将会有点像心理学家所说的“祖母的规\n矩”——这个规矩来自于祖母的智慧，她说你们必须先吃完胡萝卜，然后才准吃\n甜点。  \n \n        因此，为了强调我有时候会开玩笑地称之为灵丹妙药的普世智\n慧，我想先来灌输给你们几个基本的概念。  \n \n        基本的、普世的智慧是什么？嗯，第一条规则是，如果你们只\n是记得一些孤立的事物，试图把它们硬凑起来，那么你们无法真正地理解任何东\n西。如果这些事物不在一个理论框架中相互联系，你们就无法把它们派上用场。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,223,2073692323514028032),(2073692328329089037,'是记得一些孤立的事物，试图把它们硬凑起来，那么你们无法真正地理解任何东\n西。如果这些事物不在一个理论框架中相互联系，你们就无法把它们派上用场。  \n \n        你们必须在头脑中拥有一些思维模型。你们必须依靠这些模型\n组成的框架来安排你的经验，包括间接的和直接的。你们也许已经注意到，有些\n学生试图死记硬背，以此来应付考试。他们在学校中是失败者，在生活中也是失\n败者。你必须把经验悬挂在头脑中的一个由许多思维模型组成的框架上。  \n \n        思维模型是什么呢？这么说吧，第一条规则是，你必须拥有多\n元思维模型——因为如果你只能使用一两个，研究人性的心理学表明，你将会扭\n曲现实，直到它符合你的思维模型，或者至少到你认为它符合你的模型为止。你\n将会和一个脊椎按摩师一样——这种医师对现代医学当然是毫无所知的。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,224,2073692323514028032),(2073692328329089038,'曲现实，直到它符合你的思维模型，或者至少到你认为它符合你的模型为止。你\n将会和一个脊椎按摩师一样——这种医师对现代医学当然是毫无所知的。  \n \n        那就像谚语所说的：“在手里拿着铁锤的人看来，每个问题都\n像钉子。”当然，脊椎按摩师也是这样治病的。但这绝对是一种灾难性的思考方\n式，也绝对是一种灾难性的处世方式。所以你必须拥有多元思维模型。 \n  这些模型必须来自各个不同的学科——因为你们不可能在一个小小的院系里面\n发现人世间全部的智慧。正是由于这个原因，诗歌教授大体上不具备广义上的智\n慧。他们的头脑里没有足够的思维模型。所以你必须拥有横跨许多学科的模型。  \n \n        你们也许会说：“天哪，这太难做到啦。”但是，幸运的是，这没有那么难——\n因为掌握八九十个模型就差不多能让你成为拥有普世智慧的人。而在这八九十个\n模型里面，非常重要的只有几个。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,225,2073692323514028032),(2073692328329089039,'因为掌握八九十个模型就差不多能让你成为拥有普世智慧的人。而在这八九十个\n模型里面，非常重要的只有几个。  \n \n        诗歌教授大体上不具备广义上的智慧。他们的头脑里没有足够的思维模型。\n所以你必须拥有横跨许多学科的模型。  \n \n        所以让我们来简单地看看哪些模型和技巧构成了每个人必须拥有的基础知\n识，有了这样的基础知识之后，他们才能够精通某项专门的艺术，比如说选股票。 \n \n        首先要掌握的是数学。很明显，你必须能够处理数字和数量问题，也就是基\n本的数学问题。  \n        除了复利原理之外，一个非常有用的思维模型是基本的排列组合原理。在我\n年轻的时候，高中二年级就会学到这些。目前在比较好的私立学校，我想应该八\n年级左右就开始学了吧。  \n \n        大脑的神经系统是经过长期的基因和文化进化而来的。它并不是费马—帕斯','2026-07-05 16:55:53.049000',0,2073692323954429952,226,2073692323514028032),(2073692328333283328,'年级左右就开始学了吧。  \n \n        大脑的神经系统是经过长期的基因和文化进化而来的。它并不是费马—帕斯\n卡的系统。它使用的是非常粗略而便捷的估算。  \n \n        这是非常简单的数学知识。帕斯卡（1623-1662）和费马（1601-1665）在一\n年的通信中完全解决了这个问题。他们在一系列书信中就随便把它给解决了。  \n \n        要掌握排列组合原理并不难。真正困难的是你在日常生活中习惯于几乎每天\n都应用它。费马—帕斯卡的系统与世界运转的方式惊人地一致。它是基本的公理。\n所以你真的必须得拥有这种技巧。  \n \n        许多——可惜还是不够——教育机构已经意识到这一点。在哈佛商学院，所\n有一年级学生都必须学习的定量分析方法是他们所谓的“决策树理论”。他们所做\n的只是把高中代数拿过来，用它来解决现实生活中的问题。那些学生很喜欢这门','2026-07-05 16:55:53.049000',0,2073692323954429952,227,2073692323514028032),(2073692328333283329,'有一年级学生都必须学习的定量分析方法是他们所谓的“决策树理论”。他们所做\n的只是把高中代数拿过来，用它来解决现实生活中的问题。那些学生很喜欢这门\n课程。他们为高中代数能够在生活中发挥作用而感到惊奇。  \n \n        总的来讲，事实已经证明，人们不能自然、自动地做到这一点。如果你们懂\n得基本的心理学原理，就能理解人们做不到这一点的原因，其实很简单：大脑的\n神经系统是经过长期的基因和文化进化而来的。它并不是费马—帕斯卡的系统。\n它使用的是非常粗略而便捷的估算。在它里面有费马—帕斯卡系统的元素。但是，\n它不好用。 \n \n \n        所以你们必须掌握这种非常基础的数学知识，并在生活中经常\n使用它——就好比你们想成为高尔夫球员，你们不能使用长期的进化赋予你的挥\n杆方式。你们必须掌握一种不同的抓杆和挥杆方法，这样才能把你打高尔夫的潜\n力全部发挥出来。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,228,2073692323514028032),(2073692328333283330,'杆方式。你们必须掌握一种不同的抓杆和挥杆方法，这样才能把你打高尔夫的潜\n力全部发挥出来。  \n \n        如果你没有把这个基本的、但有些不那么自然的基础数学概率\n方法变成你生活的一部分，那么在漫长的人生中，你们将会像一个踢屁股比赛中\n的独腿人。  \n \n        诗歌教授大体上不具备广义上的智慧。他们的头脑里没有足够\n的思维模型。所以你必须拥有横跨许多学科的模型。  \n \n        如果你没有把这个基本的但有些不那么自然的基础数学概率\n方法变成你生活的一部分，那么在漫长的人生中，你们将会像一个踢屁股比赛中\n的独腿人。这等于将巨大的优势拱手送给了他人。  \n \n        这么多年来，我一直跟巴菲特同事；他拥有许多优势，其中之\n一就是他能够自动地根据决策树理论和基本的排列组合原理来思考问题。  \n        而且它也并不难理解。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,229,2073692323514028032),(2073692328333283331,'一就是他能够自动地根据决策树理论和基本的排列组合原理来思考问题。  \n        而且它也并不难理解。  \n \n        但你必须对会计有足够的理解，才能明白它的局限——因为会\n计虽然是（商业活动的）出发点，但它只是一种粗略的估算。要明白它的局限不\n是很难。例如，每个人都知道，你们能够大概地估算出一架喷气式飞机或者其他\n东西的使用寿命。可是光用漂亮的数字来表达折旧率，并不意味着你对实际情况\n有真正的了解。  \n \n        为了说明会计的局限，我常常举一个跟卡尔·布劳恩有关的例\n子。布劳恩是一个非常伟大的商人，他创建了 C. F. 布劳恩工程公司。该公司\n设计和建造炼油厂——那是很难的事情。而布劳恩能够准时造好炼油厂，让它们\n顺利而高效地投产。这可是一门了不起的艺术。  \n \n        布劳恩是个地道的德国人，他有许多趣闻轶事。据说他曾经看','2026-07-05 16:55:53.049000',0,2073692323954429952,230,2073692323514028032),(2073692328333283332,'顺利而高效地投产。这可是一门了不起的艺术。  \n \n        布劳恩是个地道的德国人，他有许多趣闻轶事。据说他曾经看\n了一眼炼油厂的标准会计报表，然后说：“这是狗屁。”  \n \n        于是他把所有会计都赶走了，召集手下的工程师，对他们说：\n“我们自己来为我们的商业流程设计一个会计系统吧。”后来炼油厂的会计工作\n吸取了卡尔·布劳恩的许多想法。布劳恩是一个非常坚毅、非常有才华的人，他\n的经历体现了会计的重要性，以及懂得标准会计局限性的重要性。  \n \n        他还有个规矩，来自心理学；如果你对智慧感兴趣，那么应该\n记住这个规矩——就像记住基本的排列组合原理一样。 \n他要求布劳恩公司所有的交流必须遵守“五何”原则——你必须说明何人因何故\n在何时何地做了何事。如果你在布劳恩公司里面写一封信或指示某人去做某事，','2026-07-05 16:55:53.049000',0,2073692323954429952,231,2073692323514028032),(2073692328333283333,'他要求布劳恩公司所有的交流必须遵守“五何”原则——你必须说明何人因何故\n在何时何地做了何事。如果你在布劳恩公司里面写一封信或指示某人去做某事，\n但没有告诉他原因，那么你可能会被解雇。实际上，你只要犯两次这种错误，就\n会被解雇。  \n \n        你们也许会问，这有那么重要吗？嗯，这也跟心理学的原理有关。如果你能\n够将一堆模式的知识组合起来，回答一个又一个为什么，你就能够更好地思考；\n同样道理，如果你告诉人们事情的时候，总是告诉他们原因，他们就能更深刻地\n理解你说的话，就会更加重视你说的话，也会更倾向于听从你说的话。就算他们\n不理解你的理由，他们也会更倾向于听你的话。  \n \n        如果你告诉人们事情的时候，总是告诉他们原因，他们就能更深刻地理解你\n说的话，就会更加重视你说的话，也会更倾向于听从你说的话。就算他们不理解\n你的理由，他们也会更倾向于听你的话。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,232,2073692323514028032),(2073692328333283334,'说的话，就会更加重视你说的话，也会更倾向于听从你说的话。就算他们不理解\n你的理由，他们也会更倾向于听你的话。  \n \n        正如你想要从问一个又一个的“为什么”开始获得普世的智慧一样，你在跟别\n人交流沟通时，也应该把原因讲清楚。就算答案很浅显，你把“为什么”讲清楚仍\n是一种明智的做法。  \n \n        哪些思维模型最可靠呢？答案很明显，那些来自硬科学和工程学的思维模型\n是地球上最可靠的思维模型。而工程学的质量控制理论——至少对你我这样的非\n专业工程师来说也是很重要的核心部分——其基础恰好是费马和帕斯卡的基础\n数学理论。  \n        一项工程的成本这么高，如果你付出这么高的成本，你就不会希望它垮掉。\n这全是基本的高中数学知识。德明带到日本的质量控制理论，无非就是利用了这\n些基础的数学知识。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,233,2073692323514028032),(2073692328333283335,'这全是基本的高中数学知识。德明带到日本的质量控制理论，无非就是利用了这\n些基础的数学知识。  \n \n        我认为大多数人没有必要精通统计学。例如，我虽然不能准确地说出高斯分\n布的细节，不过我知道它的分布形态，也知道现实生活的许多事件和现象是按照\n那个方式分布的。所以我能作一个大致的计算。  \n \n        但如果你们要我算出一道高斯分布方程，要求精确到小数点后 10 位，那我\n可算不出来。我就像一个虽然不懂帕斯卡可是打牌打得很好的扑克牌手。  \n \n        顺便说一声，这样也够用了。但你们必须像我一样，至少能粗略地理解那道\n钟形曲线。  \n \n        当然，工程学里面的后备系统是一种非常有用的思想，断裂点理论也是一种\n非常强大的思维模型。物理学里面的临界质量概念是一种非常强大的思维模型。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,234,2073692323514028032),(2073692328333283336,'非常强大的思维模型。物理学里面的临界质量概念是一种非常强大的思维模型。  \n \n        所有这些理论都能在日常生活中派上很大的用场。所有这些成本—收益分析\n——见鬼了，又全是基本的高中代数知识——只不过是被一些吓唬人的术语打扮\n得漂亮一点而已 \n \n \n        你们可以轻而易举地证明这一点：在座各位只要看过一个非\n常普通的职业魔术师的表演，就肯定曾经看见许多其实并没有发生的事情正在发\n生，也肯定曾经看不见其实正在发生的事情。  \n \n        我认为第二种可靠的思维模型来自生物学/生理学，因为我们\n大家毕竟在基因构造方面都是相同的。  \n \n        接下来当然就是心理学啦，它更加复杂。但如果你想拥有任何\n普世的智慧，心理学是太过重要了。  \n \n        原因在于，人类的感知器官有时候会短路。大脑的神经线路并','2026-07-05 16:55:53.049000',0,2073692323954429952,235,2073692323514028032),(2073692328333283337,'普世的智慧，心理学是太过重要了。  \n \n        原因在于，人类的感知器官有时候会短路。大脑的神经线路并\n非总是畅通无阻的，也不拥有无穷多的线路。所以那些懂得如何利用这种缺点、\n让大脑以某种错误方式运转的人能够使你看到根本不存在的东西。  \n \n        这又涉及认知功能，它和感知功能不同。你们的认知功能同样\n容易受误导——实际上是比感知功能更加容易受误导。同样的，你的大脑缺乏足\n够的神经线路等等——于是出现各式各样的自动短路问题。  \n        所以当外部因素以某些方式结合起来——或者更常见的是，有\n个人像魔术师那样有意地操控你，让你发生认知错乱——你就成了任人摆布的蠢\n货啦。  \n \n        一个使用工具的人应该了解它的局限，同样道理，一个使用认\n知工具的人也应该了解它的局限。顺便说一声，这种知识可以用来操控和激励别\n人。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,236,2073692323514028032),(2073692328333283338,' \n        一个使用工具的人应该了解它的局限，同样道理，一个使用认\n知工具的人也应该了解它的局限。顺便说一声，这种知识可以用来操控和激励别\n人。  \n \n        人类的头脑既是宇宙的光荣，也是宇宙的耻辱。  \n \n        所以心理学最有用、最具实践价值的部分——我个人认为聪明\n人一个星期就能被教会——是极其重要的。可惜没有人教过我。我不得不自己在\n后来的生活中一点一点地学习。那可是相当辛苦的。这个道理十分简单，全学到\n手之后，我觉得自己（从前）是个十足的傻子。  \n \n        没错，我曾经在加州理工学院和哈佛法学院受过教育。所以名\n牌大学为你们和我这样的人提供了错误的教育。  \n \n        心理学的基础部分——我称之为误判心理学——是极其重要\n的知识。它包括了大约 20 个小原则。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,237,2073692323514028032),(2073692328333283339,' \n        心理学的基础部分——我称之为误判心理学——是极其重要\n的知识。它包括了大约 20 个小原则。  \n \n        而且它们还相互影响，所以有点复杂。但它的核心内容重要得\n让人难以置信。 \n   有些聪明绝顶的人由于忽略了它而犯下了非常神经的错误。实际上，过去两\n三年我就犯了几次这样的大错。人不可能完全避免犯愚蠢的错误。  \n \n        帕斯卡还说过一句话，我觉得那是思想史上最精确的论断之一了。帕斯卡说：\n“人类的头脑既是宇宙的光荣，也是宇宙的耻辱。”  \n \n        确实如此。人类的大脑拥有这种巨大的力量。然而它也经常出毛病，作出各\n种错误的判断。它还使人们极其容易受其他人操控。例如，阿道夫·希特勒的军\n队有大约一半是由虔诚的天主教徒组成的。若是受到足够高明的心理操控，人类\n会做出各种匪夷所思的事情。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,238,2073692323514028032),(2073692328333283340,'队有大约一半是由虔诚的天主教徒组成的。若是受到足够高明的心理操控，人类\n会做出各种匪夷所思的事情。  \n \n        我现在使用一种双轨分析。  \n \n        从个人的角度来讲，我已经养成了使用一种双轨分析的习惯。首先，理性地\n看，哪些因素真正控制了涉及的利益？其次，当大脑处于潜意识状态时，会自动\n形成哪些潜意识因素——这些潜意识因素总的来讲有用但（在具体情况下）却又\n常常失灵？  \n \n        接下来我们要谈到的是另外一种不那么可靠的人类智慧——微观经济学。我\n发现把自由的市场经济——或者部分自由的市场经济——当做某种生态系统是\n很有用的思维方式。  \n \n        动物在合适生长的地方能够繁衍，同样地，那些在商业世界中专注于某个领\n域——并且由于专注而变得非常优秀——的人，往往能够得到他们无法以其他方\n式获得的良好经济回报。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,239,2073692323514028032),(2073692328333283341,'域——并且由于专注而变得非常优秀——的人，往往能够得到他们无法以其他方\n式获得的良好经济回报。  \n \n        可惜能这么想的人不多，因为早在达尔文时代以来，工业大亨之类的人认为\n适者生存的法则证明他们确实拥有过人的能力——你们也知道的，他们会这么\n想：“我最富有。所以，我是最好的。真是老天有眼。”  \n \n        人们对工业大亨的这种反应很反感，所以很不愿把经济想成一种生态系统。\n但实际上，经济确实很像生态系统。它们之间有很多相似之处。  \n \n        跟生态系统的情况一样，有狭窄专长的人能够在某些狭窄领域中做得特别\n好。动物在合适生长的地方能够繁衍，同样地，那些在商业世界中专注于某个领\n域——并且由于专注而变得非常优秀——的人，往往能够得到他们无法以其他方\n式获得的良好经济回报。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,240,2073692323514028032),(2073692328333283342,'域——并且由于专注而变得非常优秀——的人，往往能够得到他们无法以其他方\n式获得的良好经济回报。  \n \n        一旦开始谈论微观经济学，我们就会遇到规模优势这个概念。现在我们更为\n接近投资分析了——因为规模优势在商业的成败中扮演了至关重要的角色。 \n \n \n        例如，全世界所有商学院都教学生说，一个巨大的规模优势\n是成本会沿着所谓的经验曲线下降。那些受到资本主义的激励和想要改善生产的\n人们只要加大产量，就能够让复杂的生产变得更有效率。  \n \n        规模优势理论的本质是，你生产的商品越多，你就能更好地生\n产这种商品。那是个巨大的优势。它跟商业的成败有很大的关系。  \n \n        让我们看看规模优势都有哪些——尽管这会是一个不完整的\n清单。有些优势可以通过简单的几何学得以说明。如果你打算建造一个油罐，很','2026-07-05 16:55:53.049000',0,2073692323954429952,241,2073692323514028032),(2073692328333283343,' \n        让我们看看规模优势都有哪些——尽管这会是一个不完整的\n清单。有些优势可以通过简单的几何学得以说明。如果你打算建造一个油罐，很\n明显，随着油罐的增大，油罐表面所需的钢铁将会以平方的速率增加，而油罐的\n容量将会以立方的速率增加。也就是说，当你扩建油罐时，你能用更少的钢铁得\n到更多的容积。  \n \n        有许多事情是这样的，简单的几何学——简单的现实——能够\n给你一种规模优势。  \n \n        例如，你能够从电视广告中得到规模优势。在电视广告最早出\n现的时候——也就是在彩色电视机第一次走进我们的客厅的时候，它是一种强大\n得令人难以置信的东西。早期三家电视网络公司拥有大概 90%的观众。  \n \n        我会为了区区五分钱而把某样我不了解的东西放到嘴巴里去\n吗？——这毕竟是非常私人的地方。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,242,2073692323514028032),(2073692328333283344,' \n        我会为了区区五分钱而把某样我不了解的东西放到嘴巴里去\n吗？——这毕竟是非常私人的地方。  \n \n        嗯，如果你们是宝洁公司，你们有足够的财力使用这种新的广\n告手段。你们能够承担起非常高昂的电视广告费用，因为你们卖出的产品多得不\n得了。有些势单力薄的家伙就做不到。因为他付不起那笔钱，所以他无法使用电\n视广告。实际上，如果你们的产量不够大，你们也用不起电视广告——那是当时\n最有效的宣传技巧。  \n \n        所以当电视出现的时候，那些规模已经很大的名牌公司获得了\n巨大的推动力。实际上，它们生意蒸蒸日上，发了大财，直到其中有些变得脑满\n肠肥，这是发财后会出现的情况——至少对有些人来说是这样。  \n \n        你的规模优势可能是一种信息优势。如果我去到某个偏远的地\n方，我可能会看到绿箭的口香糖和格罗兹的口香糖摆在一起。我知道绿箭是一种','2026-07-05 16:55:53.049000',0,2073692323954429952,243,2073692323514028032),(2073692328333283345,' \n        你的规模优势可能是一种信息优势。如果我去到某个偏远的地\n方，我可能会看到绿箭的口香糖和格罗兹的口香糖摆在一起。我知道绿箭是一种\n令人满意的产品，可是对格罗兹毫不了解。如果绿箭卖四十美分，格罗兹卖三十\n五美分，你们觉得我会为了区区五分钱而把某样我不了解的东西放到嘴巴里去\n吗？——这毕竟是非常私人的地方。  \n \n        所以绿箭只是因为拥有了很高的知名度而获得了规模优势\n——你们也可以称之为信息优势。 \n 另外一种规模优势来自心理学。心理学家使用的术语是“社会认同”（Social \nProof）。我们会——潜意识地，以及在某种程度上有意识地——受到其他人的认\n同的影响。因此，如果大家都在买一样东西，我们会认为这样东西很好。我们不\n想成为那个落伍的家伙。  \n \n        这种情况有时候是潜意识的，有时候是有意识的。有时候，我们清醒而理智','2026-07-05 16:55:53.049000',0,2073692323954429952,244,2073692323514028032),(2073692328333283346,'想成为那个落伍的家伙。  \n \n        这种情况有时候是潜意识的，有时候是有意识的。有时候，我们清醒而理智\n地想：“哇，我对这东西不熟悉。他们比我了解得更多。那么，为什么我不跟着\n他们呢？”  \n \n        由于人类心理而产生的社会认同现象使商家可以极大地拓宽产品的销售渠\n道，这种优势自然是很难获得的。可口可乐的优势之一就是它的产品几乎覆盖了\n全世界各个角落。  \n \n        喏，假设你们拥有一种小小的软饮料商品。要怎样才能让它遍布地球各个角\n落呢？全球性的销售渠道——这是大企业慢慢建立的——是非常大的优势……你\n们不妨想一下，如果你们在这方面拥有足够的优势，别人想要动摇你们的地位是\n很难做到的。  \n \n        规模优势还有另外一种。有些行业的情况是这样的，经过长期的竞争之后，\n有一家企业取得了压倒性的优势。最明显的例子就是日报。在美国，除了少数几','2026-07-05 16:55:53.049000',0,2073692323954429952,245,2073692323514028032),(2073692328333283347,' \n        规模优势还有另外一种。有些行业的情况是这样的，经过长期的竞争之后，\n有一家企业取得了压倒性的优势。最明显的例子就是日报。在美国，除了少数几\n个大城市之外，所有城市都只有一家日报。  \n \n        这同样跟规模有关。如果我的发行量占到绝大多数的份额，我就能拿到绝大\n多数的广告。如果我拥有了大量的广告和发行量，还有谁想看那份更薄、信息量\n更少的报纸呢？所以会慢慢出现赢家通吃的局面。那是一种独特的规模优势现\n象。  \n \n        同样的，所有这些巨大的规模优势使企业内部能够进行更为专门的分工。每\n个员工因此能够把本职工作做得更好。  \n \n        这些规模优势非常强大，所以当杰克·韦尔奇到通用电气时，他说：“让它见\n鬼去吧。我们必须在每个我们涉足的领域做到第一或者第二，否则我们就退出。','2026-07-05 16:55:53.049000',0,2073692323954429952,246,2073692323514028032),(2073692328333283348,' \n        这些规模优势非常强大，所以当杰克·韦尔奇到通用电气时，他说：“让它见\n鬼去吧。我们必须在每个我们涉足的领域做到第一或者第二，否则我们就退出。\n我不会在乎要解雇多少人，卖掉哪些业务。如果做不到第一或者第二，我们宁可\n不做。”  \n \n        《星期六晚报》和其他所有那些刊物都消失了。我们现在拥有的是《越野摩\n托》——它的读者是一群喜欢参加巡回比赛、在比赛时开着摩托车翻跟头的傻子。  \n \n        韦尔奇那么做显得铁面无情，但我认为那是非常正确的决定，能够使股东的\n财富最大化。我也不认为这种做法有什么不文明的，因为我认为自从有了杰克·韦\n尔奇之后，通用电气变得更加强大了。 \n 当然，规模太大也有劣势。例如，我们——我说的是伯克希尔·哈撒韦——是美\n国广播公司（ABC）最大的股东。我们旗下有很多刊物都倒闭了——被竞争对手','2026-07-05 16:55:53.049000',0,2073692323954429952,247,2073692323514028032),(2073692328337477632,' 当然，规模太大也有劣势。例如，我们——我说的是伯克希尔·哈撒韦——是美\n国广播公司（ABC）最大的股东。我们旗下有很多刊物都倒闭了——被竞争对手\n打败了。它们之所以能够打败我们，是因为它们更加专业。  \n \n        那么，他们的效率比我们高得多。他们能够告诉更多负责企业差旅部门的人。\n另外，他们不用浪费墨水和纸张把材料寄给那些没有兴趣阅读的差旅部门。那是\n一个更有效的系统。由于我们没他们专业，所以一败涂地。  \n \n        《星期六晚报》和其他所有那些刊物的下场都是这样的。它们消失了。我们\n现在拥有的是《越野摩托》——它的读者是一群喜欢参加巡回比赛、在比赛时开\n着摩托车翻跟头的傻子。但他们关注它。对他们来说，它就是生活的主要意义。\n一份叫做《越野摩托》的杂志完全是这些人的必需品。它的利润率会让你们流口\n水。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,248,2073692323514028032),(2073692328337477633,'着摩托车翻跟头的傻子。但他们关注它。对他们来说，它就是生活的主要意义。\n一份叫做《越野摩托》的杂志完全是这些人的必需品。它的利润率会让你们流口\n水。  \n \n        只要想想这些刊物的读者群体有多专就知道了。所以缩小规模、加强专业化\n程度能够给你带来巨大的优势。大未必就是好。  \n \n        当然，规模大的缺陷是……这使竞争变得更有趣，因为大公司并非总是赢家\n——企业变大之后，就会出现官僚机构的作风，而这种作风会造成敷衍塞责的情\n况——这也是人类的本性。  \n \n        大公司并非总是赢家……企业变大之后，就会出现官僚机构的作风。  \n \n        这时企业内部的激励机制会失灵。例如，如果你们在我年轻时为 AT&T 工作，\n当时它是个很大的官僚机构。谁会真的在乎股东利益或别的什么事呢？而且在官','2026-07-05 16:55:53.049000',0,2073692323954429952,249,2073692323514028032),(2073692328337477634,'当时它是个很大的官僚机构。谁会真的在乎股东利益或别的什么事呢？而且在官\n僚机构里面，当工作从你手上转到别人手上时，你会认为工作已经完成了。但是，\n当然了，它实际上当然尚未完成。在 AT&T 把它应该发送的电讯发送出去之前，\n它是尚未完成的。所以，这种大型、臃肿、笨拙、麻木的官僚机构就是这样的。  \n \n        它们还会导致某种程度的腐败。换句话说，如果我管一个部门，你管一个部\n门，我们都有权力处理这件事，那么就会出现一种潜规则：“如果你不找我麻烦，\n我也不会找你麻烦，这样我们都高兴。”于是就出现了多重管理层，以及不必要\n的相关成本。然后呢，在人们没法证明这些管理层是有必要存在的情况下，任何\n事情都要花很长时间才能办成。他们反应迟钝，做不了决定，头脑灵活的人只能\n围着他们打转。  \n \n        电视刚出现的时候，整个市场由一家公司主导——哥伦比亚广播公司（CBS）。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,250,2073692323514028032),(2073692328337477635,'围着他们打转。  \n \n        电视刚出现的时候，整个市场由一家公司主导——哥伦比亚广播公司（CBS）。  \n \n        大规模的弊端向来在于它会导致庞大、笨拙的官僚机构——最糟糕的、弊病\n最多的官僚机构当然是各种政府部门，它们的激励机制真的很差劲。这并不意味\n着我们不需要政府——因为我们确实需要。但要让这些大型的官僚机构办点事是\n让人非常头疼的问题。 \n 所以人们开始找对策。他们设立了分散的小单位以及很棒的激励和培训计划。\n例如，大企业通用电气就用惊人的技巧和官僚作风斗争。但那是因为通用电气的\n领袖是个天才和激情的结合体。他们在他还够年轻的时候就扶他上位，所以他能\n掌权很久。当然，这个人就是杰克·韦尔奇。  \n \n        但官僚作风很可怕……随着企业变得非常庞大和有影响力，可能会出现一些\n失控的行为。看看西屋电器就知道了。他们愚蠢地放出几十亿美元的贷款给房地','2026-07-05 16:55:53.049000',0,2073692323954429952,251,2073692323514028032),(2073692328337477636,' \n        但官僚作风很可怕……随着企业变得非常庞大和有影响力，可能会出现一些\n失控的行为。看看西屋电器就知道了。他们愚蠢地放出几十亿美元的贷款给房地\n产开发商。他们让某个从基层爬上来的人——我不知道他是做什么起家的，可能\n是电冰箱之类的——来当领袖，突然之间，他借了大量的钱给房地产开发商盖酒\n店。这是以己之短，攻人之长。没隔多久，他们就把几十亿美元输光了。  \n \n        哥伦比亚广播公司是个有趣的例子，它印证了另外一条心理学原则——巴甫\n洛夫联想。如果人们说了你确实不想听的话——也就是让你不高兴的话——你会\n自然而然地生出抵触情绪。你必须训练自己摆脱这种反应。倒不是说你一定会这\n样。但如果你不加以注意，就很可能会这样。  \n \n        电视刚出现的时候，整个市场由一家公司主导——哥伦比亚广播公司。佩利','2026-07-05 16:55:53.049000',0,2073692323954429952,252,2073692323514028032),(2073692328337477637,'样。但如果你不加以注意，就很可能会这样。  \n \n        电视刚出现的时候，整个市场由一家公司主导——哥伦比亚广播公司。佩利\n（注：哥伦比亚广播公司前董事长和奠基人，美国著名企业家，被称为哥伦比亚\n广播公司之父）就像神一样。但他听不得逆耳忠言，他的手下很快就发现了这一\n点。所以他们只跟佩利说他喜欢听的话。结果没隔多久，他就生活在一个谎言编\n织的世界里，而公司的其他一切都败坏了——虽然它还是一个伟大的企业。  \n \n        哥伦比亚广播公司的各种蠢事都是由这种风气造成的。比尔·佩利掌权的最后\n十年真像是疯帽匠的茶话会。  \n \n        这绝对不是惟一的例子。企业高层严重失控的情况是很普遍的。当然，如果\n你们是投资人的话，情况可能会大不相同。可是如果你们像巴里那样，在得到\nCBS 之后，进行那么多的收购，聘请那么多的愚蠢顾问——投资银行家、管理顾','2026-07-05 16:55:53.049000',0,2073692323954429952,253,2073692323514028032),(2073692328337477638,'你们是投资人的话，情况可能会大不相同。可是如果你们像巴里那样，在得到\nCBS 之后，进行那么多的收购，聘请那么多的愚蠢顾问——投资银行家、管理顾\n问之类的人，这些人都拿着非常高的薪水——那么情况就会极其糟糕。  \n \n        所以生活就是两种力量之间无休无止的斗争，一边是获得上面提到的那些规\n模优势，另一边是变得像美国农业部那样人浮于事——农业部的人只是坐在那\n里，什么也不做。我不知道他们到底干了些什么，但我知道他们没干几件有用的\n事。  \n \n        就规模经济的优势这个话题而言，我觉得连锁店非常有趣。想想就知道啦。\n连锁店的概念是一个迷人的发明。你得到了巨大的采购能力——这意味着你能够\n降低商品的成本。那些连锁店就像大量的实验室，你可以用它们来做实验。你变\n得专门化了。  \n \n        如果有个小商店的老板试图在上门推销的供货商影响下选购 27 类不同的产','2026-07-05 16:55:53.049000',0,2073692323954429952,254,2073692323514028032),(2073692328337477639,'得专门化了。  \n \n        如果有个小商店的老板试图在上门推销的供货商影响下选购 27 类不同的产\n品，他肯定会作出很多愚蠢的决定。但是如果你的采购工作是在总部完成的，旗\n下有大量的商店，那么你可以请一些精通冰箱等等商品的聪明人来完成采购工\n作。 \n \n \n        那些只有一个人负责全部采购的小商店会出现糟糕的局面。\n曾经有个故事，故事里一家小商店堆满了食盐。一个陌生人走进去，对店主说：\n“哇，你肯定卖掉很多盐。”店主的回答是：“没有啦。卖给我盐的那个人才卖\n掉了很多盐。”  \n \n        所以连锁店在采购上有巨大的优势。此外还有一套完善的制\n度，规定每个人应该做些什么。所以连锁店可以成为很棒的企业。  \n \n        阿肯色州本顿威尔市一个身无分文的家伙如何打败西尔\n斯·罗巴克呢？他用一生的时间完成了这项伟业——实际上，他只用了半生的时','2026-07-05 16:55:53.049000',0,2073692323954429952,255,2073692323514028032),(2073692328337477640,' \n        阿肯色州本顿威尔市一个身无分文的家伙如何打败西尔\n斯·罗巴克呢？他用一生的时间完成了这项伟业——实际上，他只用了半生的时\n间，因为当他开出第一家小商店时，他已经相当老了……  \n \n        沃尔玛的历史很有意思，它最初只有一家店，在阿肯色州，而\n当时最具声望的百货商店是坐拥数十亿美元资产的罗巴克·西尔斯。阿肯色州本\n顿威尔市一个身无分文的家伙如何打败罗巴克·西尔斯呢？他用一生的时间完\n成了这项伟业——实际上，他只用了半生的时间，因为当他开出第一家小商店时，\n他已经相当老了……  \n \n        连锁店这个游戏，他玩得比谁都努力，玩得比谁都好。实际上\n沃尔顿并没有什么创新。他只是照搬其他人做过的所有聪明事——他更为狂热地\n去做这些事，更有效地管理下属的员工。所以他能够把其他对手都打败。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,256,2073692323514028032),(2073692328337477641,'沃尔顿并没有什么创新。他只是照搬其他人做过的所有聪明事——他更为狂热地\n去做这些事，更有效地管理下属的员工。所以他能够把其他对手都打败。  \n \n        他在早期采用了一种非常有趣的竞争策略。他就像一个为奖牌\n而奋斗的拳手，想弄到一份辉煌的战绩，以便跻身决赛，成为电视的焦点。他是\n怎么做的呢？他出去找了 42 个不堪一击的对手，对吧？结果当然是胜出、胜出、\n胜出——连赢 42 次。  \n \n        精明的沃尔顿基本上打败了早期美国小城镇的其他零售商。虽\n然他的系统效率更高，但他可能无法给那些大商店当头一棒。但由于他的系统更\n好，他当然能够摧毁这些小城镇的零售商。他一而再、再而三地这么做。然后，\n等到规模变大之后，他开始摧毁那些大企业。  \n \n        嗯，这真是一种非常、非常精明的策略。  \n \n        你们也许会问：“这种做法好吗？”嗯，资本主义是非常残酷','2026-07-05 16:55:53.049000',0,2073692323954429952,257,2073692323514028032),(2073692328337477642,' \n        嗯，这真是一种非常、非常精明的策略。  \n \n        你们也许会问：“这种做法好吗？”嗯，资本主义是非常残酷\n的。但我个人认为，世界因为有了沃尔玛而变得更加美好。我想说的是，你们可\n以把小城镇的生活想得很美好。但我曾经在小城镇生活过很多年。让我告诉你们\n吧——你们不应该把那些被沃尔玛摧毁的小企业想得太美好。 \n 此外，沃尔玛的许多员工都是优秀能干的人，他们需要养家糊口。我并没有低\n级文化打败高级文化的感觉。我认为那种感觉无非是怀旧和幻觉。但不管怎么说，\n沃尔玛这个有趣的模式让我们看到了当规模和狂热结合起来能够产生多大的威\n力。  \n \n        这个有趣的模式也向我们说明了另外一个问题——罗巴克·西尔斯虽然拥有\n很大的规模优势，但那种人浮于事的官僚作风却给它造成了可怕的损失。西尔斯\n有许许多多的冗员。它的官僚习气非常严重。它的思维很慢，而且它思考问题的','2026-07-05 16:55:53.049000',0,2073692323954429952,258,2073692323514028032),(2073692328337477643,'很大的规模优势，但那种人浮于事的官僚作风却给它造成了可怕的损失。西尔斯\n有许许多多的冗员。它的官僚习气非常严重。它的思维很慢，而且它思考问题的\n方式很僵化。如果你的头脑出现了新的想法，这种系统会反对你。它拥有一切你\n能想像得到的大型官僚机构的弊端。  \n \n        平心而论，西尔斯也有大量的优点。但是它不如山姆·沃尔顿那么精简、苛刻、\n精明和有效率。所以没隔多久，西尔斯所有的规模优势就都抵挡不住沃尔玛和其\n他零售商同行的猛烈进攻了。  \n \n        自从雏鹰号首航以来，这些航空公司的股东净收益却是负数——非常可观的\n负数。  \n \n        这里有个模式一直让我们很困惑。也许你们能够更好地解决它。许多市场最\n终会变成两三个——或者五六个——大型竞争对手的天下。在一些那样的市场里\n面，没有哪家公司能赚到钱。但在其他市场中，每家公司都做得很好。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,259,2073692323514028032),(2073692328337477644,'终会变成两三个——或者五六个——大型竞争对手的天下。在一些那样的市场里\n面，没有哪家公司能赚到钱。但在其他市场中，每家公司都做得很好。  \n \n        这些年来，我们总是试图弄清楚一个问题，为什么某些市场的竞争在投资者\n看来比较理性，能给股东带来很多收益，而有些市场的竞争却是破坏性的，摧毁\n了股东的财富。  \n \n        如果是像机票这样的纯粹商品，你们能够理解为什么没人能赚钱。我们坐在\n这里也能想像得到航空公司给世界带来的好处——安全的旅游、更丰富的体验、\n和爱人共度的美好时光，等等。然而，自从雏鹰号首航（注：世界上第一次成功\n载人飞行）以来，这些航空公司的股东净收益却是负数——非常可观的负数。航\n空业的竞争太过激烈，一旦政府管制放松，就会严重损害股东的财富。  \n \n        然而，在其他领域，比如说麦片行业，几乎所有大公司都赚钱。如果你是一','2026-07-05 16:55:53.049000',0,2073692323954429952,260,2073692323514028032),(2073692328337477645,'空业的竞争太过激烈，一旦政府管制放松，就会严重损害股东的财富。  \n \n        然而，在其他领域，比如说麦片行业，几乎所有大公司都赚钱。如果你是一\n家中等规模的麦片制造商，你也许能够赚到 15%的利润；如果你非常厉害，也许\n就能够赚到 40%。在我看来，麦片厂商之间的竞争非常激烈，它们有很多促销活\n动，派发优惠券什么的，但为什么还能赚那么多钱呢？我无法完全理解。  \n \n        很明显，麦片行业里存在着品牌认同的因素，这是航空业所缺乏的。这肯定\n是（麦片行业如此赚钱的）主要原因。 \n   也有可能是大多数麦片制造商已经学到了教训，不会那么疯狂地去争夺市场\n份额——因为如果有某个厂家拼命想要抢占更多市场份额的话……例如，假使我\n是家乐氏，我觉得我必须占有 60%的市场，我认为我能够拿走麦片制造业的大多','2026-07-05 16:55:53.049000',0,2073692323954429952,261,2073692323514028032),(2073692328341671936,'份额——因为如果有某个厂家拼命想要抢占更多市场份额的话……例如，假使我\n是家乐氏，我觉得我必须占有 60%的市场，我认为我能够拿走麦片制造业的大多\n数利润。那么我会在扩张过程中毁了家乐氏。但我认为我能抢到那么多市场份额。  \n \n        在某些行业里，商家的行为像发神经的家乐氏，而其他行业则不会出现那种\n情况。可惜我并没有一个完美的模型来预测那种情况怎样就会发生。  \n \n        平例如，如果你观察瓶装饮料市场，你会发现，在许多市场，百事可乐和可\n口可乐能赚很多钱，而在其他许多市场，它们毁掉了两家特许经营商的大多数利\n润。这肯定跟每个特许经营商对市场资本主义的适应性有关。我想你们必须认识\n牵涉其中的人，才能完全理解这是怎么回事。  \n \n        当然，在微观经济学里，你们会看到专利权、商标权、特许经营权等概念。','2026-07-05 16:55:53.049000',0,2073692323954429952,262,2073692323514028032),(2073692328341671937,'牵涉其中的人，才能完全理解这是怎么回事。  \n \n        当然，在微观经济学里，你们会看到专利权、商标权、特许经营权等概念。\n专利权非常有趣。在我年轻时，我觉得专利权很不划算，投入的钱比得到的钱多。\n法官倾向于否认专利权——因为很难判断哪些是真正的创新，哪些是仿制原来的\n产品。那可不是一下子就能全部说清楚的事情。  \n \n        但现在情况发生了变化。法律没有变，但是管理部门变了——现在专利诉讼\n都由专利法庭来解决。而专利法庭非常支持专利权。所以我觉得现在那些拥有专\n利权的人开始能够赚大钱了。  \n \n        当然，商标向来给人们赚很多钱。如果有个很著名的商标，对一个大企业来\n讲那可是件很棒的事情。  \n \n        特许经营也可以是很棒的。如果某个大城市里只有三个电视频道，而你拥有\n其中一个，每天你只能放那么多小时的节目。所以在有线电视出现之前，你拥有','2026-07-05 16:55:53.049000',0,2073692323954429952,263,2073692323514028032),(2073692328341671938,' \n        特许经营也可以是很棒的。如果某个大城市里只有三个电视频道，而你拥有\n其中一个，每天你只能放那么多小时的节目。所以在有线电视出现之前，你拥有\n自然的寡头垄断优势。  \n \n        如果你获得了特许经营权，在机场开设了惟一的一家食品店，还有专属的客\n户，那么你就拥有了某种小小的垄断。  \n \n        微观经济学的伟大意义在于让人能够辨别什么时候技术将会帮助你，什么时\n候它将会摧毁你。大多数人并没有想通这个问题。但像巴菲特这样的家伙就想通\n了。  \n \n        微观经济学的伟大意义在于让人能够辨别什么时候技术将会帮助你，什么时\n候它将会摧毁你。  \n \n        例如，以前我们做过纺织品生意，那是个非常糟糕的无特性商品行业，我们\n当时生产的是低端的纺织品——那是真正的无特性商品。有一天，有个人对沃伦','2026-07-05 16:55:53.049000',0,2073692323954429952,264,2073692323514028032),(2073692328341671939,' \n        例如，以前我们做过纺织品生意，那是个非常糟糕的无特性商品行业，我们\n当时生产的是低端的纺织品——那是真正的无特性商品。有一天，有个人对沃伦\n说：“有人发明了一种新的纺织机，我们认为它的效率是旧纺织机的两倍。”沃伦\n说：“天哪，我希望这种新机器没这么厉害——因为如果它确实这么厉害的话，\n我就要把工厂关掉了。”他并不是在开玩笑。 \n \n \n        他是怎么想的呢？他的想法是这样的：“这是很糟糕的生\n意。我们的利润率很低，我们让它开着，是为了照顾那些年纪大的工人。但我们\n不会再投入巨额的资本给一家糟糕的企业了。”  \n \n        他知道，更好的机器能极大地提高生产力，但最终受益的是那\n些购买纺织品的人。厂家什么好处也得不到。  \n \n        他们并没有进行第二步分析——也就是弄清楚有多少钱会落\n在你手里，多少钱会流向消费者。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,265,2073692323514028032),(2073692328341671940,'些购买纺织品的人。厂家什么好处也得不到。  \n \n        他们并没有进行第二步分析——也就是弄清楚有多少钱会落\n在你手里，多少钱会流向消费者。  \n \n        这个道理很浅显——有好些各式新发明虽然很棒，但只会让你\n们花冤枉钱，你们的企业就算采用了它们也改变不了江河日下的命运。因为钱不\n会落到你手里。改善生产带来的所有好处都流向消费者了。  \n \n        与之相反，如果你拥有奥斯科什惟一的报纸，有人发明了更为\n有效的排版技术，然后你甩掉旧的技术，买进花哨的新电脑之类的，那么你的钱\n不会白花，节约下来的成本还是会回到你手上。  \n \n        总之，那些推销机器的人——甚至是企业内部那些催促你购买\n设备的员工——会跟你说使用新技术将会为你节省多少成本。然而，他们并没有\n进行第二步分析——也就是弄清楚有多少钱会落在你手里，多少钱会流向消费','2026-07-05 16:55:53.049000',0,2073692323954429952,266,2073692323514028032),(2073692328341671941,'设备的员工——会跟你说使用新技术将会为你节省多少成本。然而，他们并没有\n进行第二步分析——也就是弄清楚有多少钱会落在你手里，多少钱会流向消费\n者。我从来没有见到有哪个人提出过这第二步分析。我总是遇到这些人，他们总\n是说：“你只要购买这些新技术，三年之内就能把成本收回来。”  \n \n        所以你不断地购买一些三年内可以收回成本的新玩意，这么做\n了 20 年之后，你获得的年均回报率只有不到 4%。这就是纺织业。  \n \n        并不是说那些机器不好，只是节省下来的钱没有落到你手里。\n成本确实降低了，但那个购买设备的家伙并没有得到成本降低带来的好处。这个\n道理很简单，很初级，可是却经常被人忘记。  \n \n        微观经济学里面还有个模型我也觉得非常有趣。在现代文明社\n会，科学技术突飞猛进，所以出现了一种我称之为竞争性毁灭的现象。假设你拥','2026-07-05 16:55:53.049000',0,2073692323954429952,267,2073692323514028032),(2073692328341671942,' \n        微观经济学里面还有个模型我也觉得非常有趣。在现代文明社\n会，科学技术突飞猛进，所以出现了一种我称之为竞争性毁灭的现象。假设你拥\n有一家最好的马鞭厂，突然之间，社会上出现了不用马的汽车。过不了几年，你\n的马鞭生意就完蛋了。你要么去做另外一种不同的生意，要么从此关门大吉——\n你被摧毁了。这种事情总是反复地发生。  \n \n        收款机是对文明社会的重大贡献。  \n \n        当新的行业出现时，先行者会获得巨大的优势。如果你是先行\n者，你会遇到一种我称之为“冲浪”的模型——当冲浪者顺利冲上浪尖，并停留\n在那里，他能够冲很长很长一段时间。但如果他没冲上去，就会被海浪吞没。 \n    但如果人们能够站稳在海浪的前沿，他们就能够冲很久，无论是微软、英特\n尔或者其他公司，包括早期的国民收款机公司（NCR），都是如此。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,268,2073692323514028032),(2073692328341671943,'    但如果人们能够站稳在海浪的前沿，他们就能够冲很久，无论是微软、英特\n尔或者其他公司，包括早期的国民收款机公司（NCR），都是如此。  \n \n        收款机是对文明社会的重大贡献。它是一个很有意思的故事。帕特森是个小\n零售商，没赚到什么钱。有一天，有人卖给他一台早期的收款机，他把它放到商\n店的收银台。这台收款机立刻让他扭亏为盈，因为有了它之后，店里的职员想偷\n钱就难多了。  \n \n        但帕特森是个聪明人， 他并没有想：“这对我的零售店有帮助。”他的想法\n是：“我要做收款机的生意。”自然，他创办了国民收款机公司。  \n \n        他冲上了浪尖。他拥有最好的销售系统，最多的专利，其他一切也都是最好\n的。他狂热地致力于一切与此有关的技术改进。我的档案里还有一份早年国民收\n款机公司的年报，帕特森在年报中阐述了他的经营方法和目标。一只受过良好教','2026-07-05 16:55:53.049000',0,2073692323954429952,269,2073692323514028032),(2073692328341671944,'的。他狂热地致力于一切与此有关的技术改进。我的档案里还有一份早年国民收\n款机公司的年报，帕特森在年报中阐述了他的经营方法和目标。一只受过良好教\n育的大猩猩也能明白，在当时入股帕特森的公司完全是百分百赚钱的事情。  \n \n        当然，这正是投资者寻找的良机。在漫长的人生中，你只要培养自己的智慧，\n抓住一两次这样的好机会，就能够赚许许多多的钱。总而言之，“冲浪”是一个非\n常强大的模式。  \n \n        然而，伯克希尔·哈撒韦一般并不投资这些在复杂的科技行业“冲浪”的人。毕\n竟我们既古怪又老派——这一点你们可能已经注意到啦。  \n \n        沃伦和我都不觉得我们在高科技行业拥有任何大的优势。实际上，我们认为\n我们很难理解软件、电脑芯片等科技行业的发展的实质。所以我们尽量避开这些\n东西，正视我们个人的知识缺陷。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,270,2073692323514028032),(2073692328341671945,'我们很难理解软件、电脑芯片等科技行业的发展的实质。所以我们尽量避开这些\n东西，正视我们个人的知识缺陷。  \n \n        这同样是一个非常非常有用的道理。每个人都有他的能力圈。要扩大那个能\n力圈是非常困难的。如果我不得不靠当音乐家来谋生……假设音乐是衡量文明的\n标准，那么我不知道必须把标准降到多低，我才能够有演出的机会。  \n \n        所以你们必须弄清楚你们有什么本领。如果你们要玩那些别人玩得很好而你\n们一窍不通的游戏，那么你们注定会一败涂地。那是必定无疑的事情。你们必须\n弄清楚自己的优势在哪里，必须在自己的能力圈之内竞争。  \n \n        沃伦和我都不觉得我们在高科技行业拥有任何大的优势。  \n \n        如果你们想要成为世界上最好的网球球员，你们可以开始努力，然后没多久\n就发现这是痴人说梦——其他人的球技是你们望尘莫及的。然而，如果你们想要','2026-07-05 16:55:53.049000',0,2073692323954429952,271,2073692323514028032),(2073692328341671946,' \n        如果你们想要成为世界上最好的网球球员，你们可以开始努力，然后没多久\n就发现这是痴人说梦——其他人的球技是你们望尘莫及的。然而，如果你们想要\n变成伯米吉地区最好的管道工程承包商，你们之中大概有三分之二的人能够做\n到。这需要下定决心，也需要智慧。但不久之后，你们将会逐渐了解有关伯米吉\n管道生意的一切，掌握这门艺术。只要有足够的训练，那是个可以达到的目标。\n有些人虽然无法在国际象棋大赛上获胜，也无缘站在网球大赛的球场上与对手比\n试高低，但却可以通过慢慢培养一个能力圈而在生活中取得很高的成就——个人\n成就既取决于天资，也取决于后天的努力。 \n   有些优势是可以通过努力获取的。我们大多数人在生活中所能做到的无非就\n是成为一个伯米吉的优秀管道工程承包商之类的人物。毕竟能够赢得国际象棋世\n界大赛的人是很少的。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,272,2073692323514028032),(2073692328341671947,'是成为一个伯米吉的优秀管道工程承包商之类的人物。毕竟能够赢得国际象棋世\n界大赛的人是很少的。  \n \n        所以你们必须弄清楚你们有什么本领。如果你们要玩那些别人玩得很好而你\n们一窍不通的游戏，那么你们注定会一败涂地。  \n \n        你们当中有些人也许会有机会在新兴的高科技领域——英特尔、微软等公司\n——“冲浪”。虽然我们自认为对该行业并不精通，完全不去碰它，但这并不意味\n着你们去做的话是不理智的行为。  \n \n        好啦，关于基本的微观经济学模型就说这么多了，加上一点心理学，再加上\n一点数学，就构成了我所说的普世智慧的普遍基础。现在，如果你们想要从胡萝\n卜转到甜点的话，我就来谈谈如何选择股票——在此过程中，我将会应用这种普\n世智慧。  \n \n        我不想谈论新兴市场、债券投机之类的东西。我只想简单地说说如何挑选股','2026-07-05 16:55:53.049000',0,2073692323954429952,273,2073692323514028032),(2073692328341671948,'世智慧。  \n \n        我不想谈论新兴市场、债券投机之类的东西。我只想简单地说说如何挑选股\n票。相信我，这已经够复杂的了。而且我要谈论的是普通股的选择。  \n \n        第一个问题是：“股市的本质是什么？”这个问题把你们引到我从法学院毕业\n之后很久才流行起来——甚至是肆虐横行——的有效市场理论。  \n \n        生活的铁律就是，只有 20%的人能够取得比其他 80%的人优秀的成绩。  \n \n        相当有意思的是，世界上最伟大的经济学家之一竟然是伯克希尔·哈撒韦的大\n股东，自从巴菲特掌管伯克希尔之后不久，他就开始投钱进来。他的教科书总是\n教导学生说股市是极其有效率的，没有人能够打败它。但他自己的钱却流进了伯\n克希尔，这让他发了大财。所以就像帕斯卡在那次著名的赌局中所做的一样，这\n位经济学家也对冲了他的赌注。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,274,2073692323514028032),(2073692328341671949,'克希尔，这让他发了大财。所以就像帕斯卡在那次著名的赌局中所做的一样，这\n位经济学家也对冲了他的赌注。  \n \n        股市真的如此有效，乃至没有人能打败它吗？很明显，有效市场理论大体上\n是正确的——市场确实十分有效，很难有哪个选股人能够光靠聪明和勤奋而获得\n比市场的平均回报率高出很多的收益。  \n \n        确实，平均的结果必定是中等的结果。从定义上来说，没有人能够打败市场。\n正如我常常说的，生活的铁律就是，只有 20%的人能够取得比其他 80%的人第四\n章 第二讲：论基本的、普世的智慧 195 优秀的成绩。事情就是这样的。所以答\n案是：市场既是部分有效的，也是部分低效的。  \n \n        顺便说一声，我给那些信奉极端的有效市场理论的人取了个名字——叫做“神\n经病”。那是一种逻辑上自洽的理论，让他们能够做出漂亮的数学题。所以我想','2026-07-05 16:55:53.049000',0,2073692323954429952,275,2073692323514028032),(2073692328341671950,' \n        顺便说一声，我给那些信奉极端的有效市场理论的人取了个名字——叫做“神\n经病”。那是一种逻辑上自洽的理论，让他们能够做出漂亮的数学题。所以我想\n这种理论对那些有很高数学才华的人非常有吸引力。可是它的基本假设和现实生\n活并不相符。 \n   还是那句老话，在拿着铁锤的人看来，每个问题都像钉子。如果你精通高等\n数学，为什么不弄个能让你的本领得到发挥的假设呢？  \n \n        我所喜欢的模式——用来把普通股市场的概念简化——是赛马中的彩池投注\n系统。如果你停下来想一想，会发现彩池投注系统其实就是一个市场。每个人都\n去下注，赔率则根据赌注而变化。股市的情形也是这样的。  \n \n        一匹负重较轻、胜率极佳、起跑位置很好等等的马，非常有可能跑赢一匹胜\n率糟糕、负重过多等等的马，这个道理就算是傻子也能明白。但如果该死的赔率','2026-07-05 16:55:53.049000',0,2073692323954429952,276,2073692323514028032),(2073692328341671951,' \n        一匹负重较轻、胜率极佳、起跑位置很好等等的马，非常有可能跑赢一匹胜\n率糟糕、负重过多等等的马，这个道理就算是傻子也能明白。但如果该死的赔率\n是这样的：劣马的赔率是 1 赔 100，而好马的赔率是 2 赔 3。那么利用费马和帕\n斯卡的数学，很难清清楚楚地算出押哪匹马能赚钱。股票价格也以这种方式波动，\n所以人们很难打败股市。  \n \n        然后马会还要收取 17%的费用。所以你不但必须比其他投注者出色，而且还\n必须出色很多，因为你必须将下注金额的 17%上缴给马会，剩下的钱才是你的赌\n本。  \n \n        如果你停下来想一想，会发现彩池投注系统其实就是一个市场。每个人都去\n下注，赔率则根据赌注而变化。股市的情形也是这样的。  \n \n        给出这些数据之后，有人能够光靠聪明才智打败那些马匹吗？聪明的人应该','2026-07-05 16:55:53.049000',0,2073692323954429952,277,2073692323514028032),(2073692328341671952,'下注，赔率则根据赌注而变化。股市的情形也是这样的。  \n \n        给出这些数据之后，有人能够光靠聪明才智打败那些马匹吗？聪明的人应该\n拥有一些优势，因为大多数人什么都不懂，只是去押宝在幸运号码上等等诸如此\n类的做法。因此，如果不考虑马会收取的交易成本，那些确实了解各匹马的表现、\n懂得数学而又精明的人拥有相当大的优势。  \n \n        可惜的是，一个赌马的人再精明，就算他每个赛马季能够赢取 10%的利润，\n扣除上缴的 17%的成本之后，他仍然是亏损的。不过确实有少数人在支付了 17%\n的费用之后仍然能够赚钱。  \n \n        我年轻的时候经常玩扑克，跟我一起玩的那个家伙什么事情都不做，就靠赌\n轻驾车赛马为生，而且赚了许多钱。轻驾车赛马是一种相对低效的市场。它不像\n普通赛马，你不需要很聪明也能玩得好。我的牌友所做的就是把轻驾车赛马当做','2026-07-05 16:55:53.049000',0,2073692323954429952,278,2073692323514028032),(2073692328345866240,'轻驾车赛马为生，而且赚了许多钱。轻驾车赛马是一种相对低效的市场。它不像\n普通赛马，你不需要很聪明也能玩得好。我的牌友所做的就是把轻驾车赛马当做\n他的职业。他投注的次数不多，只在发现定错价格的赌注时才会出手。通过这么\n做，在全额支付了马会的费用——我猜差不多是 17%——之后，他还是赚了许多\n钱。  \n \n        你们肯定会说那很少见。然而，市场并非是完全有效的。如果不是因为这 17%\n的管理费用，许多人都能够在赌马中赢钱。它是有效的，这没错，但它并非完全\n有效。有些足够精明、足够投入的人能够得到比其他人更好的结果。  \n \n        股市的情况是相同的——只不过管理费用要低得多。股市的交易费用无非就\n是买卖价差加上佣金，而且如果你的交易不是太频繁的话，交易费用是相当低的。\n所以呢，有些足够狂热、足够自律的精明人将会比普通人得到更好的结果。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,279,2073692323514028032),(2073692328345866241,'是买卖价差加上佣金，而且如果你的交易不是太频繁的话，交易费用是相当低的。\n所以呢，有些足够狂热、足够自律的精明人将会比普通人得到更好的结果。  \n \n        聪明人在发现这样的机会之后会狠狠地下注。他们碰到好机会就下重注，其\n他时间则按兵不动。就是这么简单。 \n  那不是轻而易举就能做到的。显然，有 50%的人会在最差的一半里，而 70%\n的人会在最差的 70%里。但有些人将会占据优势。在交易成本很低的情况下，他\n们挑选的股票将会获得比市场平均回报率更好的成绩。  \n \n        要怎样才能成为赢家——相对而言——而不是输家呢？  \n \n        我们再来看看彩池投注系统。昨晚我非常碰巧地和圣塔安妮塔马会的主席一\n起吃晚饭。他说有两三个赌场跟马会有信用协议，现在他们开设了场外投注，这\n些赌场实际上做得比马会更好。马会在收取了全额的管理费后把钱付出去——顺','2026-07-05 16:55:53.049000',0,2073692323954429952,280,2073692323514028032),(2073692328345866242,'起吃晚饭。他说有两三个赌场跟马会有信用协议，现在他们开设了场外投注，这\n些赌场实际上做得比马会更好。马会在收取了全额的管理费后把钱付出去——顺\n便说一下，大量的钱被送到拉斯维加斯——给那些虽然缴纳了全额管理费但还是\n能赢钱的人。那些人很精明，连赛马这么不可预料的事情也能赌赢。  \n \n        上天并没有赐予人类在所有时刻掌握所有事情的本领。但如果人们努力在世\n界上寻找定错价格的赌注，上天有时会让他们找得到。  \n \n        聪明人在发现这样的机会之后会狠狠地下注。他们碰到好机会就下重注，其\n他时间则按兵不动。就是这么简单。  \n \n        成为赢家的方法是工作、工作、工作、再工作，并期待能够看准几次机会。  \n \n        这个道理非常简单。而且根据我对彩池投注系统的观察和从其他地方得来的\n经验，这么做明显是正确的。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,281,2073692323514028032),(2073692328345866243,' \n        这个道理非常简单。而且根据我对彩池投注系统的观察和从其他地方得来的\n经验，这么做明显是正确的。  \n \n        然而在投资管理界，几乎没有人这么做。我们是这么做的——我说的我们是\n巴菲特和芒格。其他人也有这么做的。但大多数人头脑里面有许多疯狂的想法。\n他们不是等待可以全力出击的良机，而是认为只要更加努力地工作，或者聘请更\n多商学院的学生，就能够在商场上战无不胜。在我看来，这种想法完全是神经病。  \n \n        你需要看准多少次呢？我认为你们一生中不需要看准很多次。只要看看伯克\n希尔·哈撒韦及其累积起来的数千亿美元就知道了，那些钱大部分是由十个最好\n的机会带来的。而那是一个非常聪明的人——沃伦比我能干多了，而且非常自律\n——毕生努力取得的成绩。我并不是说他只看准了十次，我想说的是大部分的钱\n是从十个机会来的。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,282,2073692323514028032),(2073692328345866244,'——毕生努力取得的成绩。我并不是说他只看准了十次，我想说的是大部分的钱\n是从十个机会来的。  \n \n        所以如果能够像彩池投注的赢家那样思考，你们将能够得到非常出色的投资\n结果。股市就像一场充满胡话和疯狂的赌博，偶尔会有定错价格的良机。你们可\n能没有聪明到一辈子能找出 1000 次机会的程度。当你们遇到好机会，就全力出\n击。就是这么简单。  \n \n        当沃伦在商学院讲课时，他说：“我用一张考勤卡就能改善你最终的财务状\n况；这张卡片上有 20 格，所以你只能有 20 次打卡的机会——这代表你一生中所\n能拥有的投资次数。当你把卡打完之后，你就再也不能进行投资了。” \n   他说：“在这样的规则之下，你才会真正慎重地考虑你做的事情，你将不得不\n花大笔资金在你真正想投资的项目上。这样你的表现将会好得多。”  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,283,2073692323514028032),(2073692328345866245,'   他说：“在这样的规则之下，你才会真正慎重地考虑你做的事情，你将不得不\n花大笔资金在你真正想投资的项目上。这样你的表现将会好得多。”  \n \n        在我看来，这个道理是极其明显的。沃伦也认为这个道理极其明显。但它基\n本上不会在美国商学院的课堂上被提及。因为它并非传统的智慧。  \n \n        在我看来很明显的是，赢家下注时必定是非常有选择的。我很早就明白这个\n道理，我不知道为什么许多人到现在还不懂。  \n \n        我想人们在投资管理中犯错的原因可以用一个故事来解释：我曾遇到一个卖\n鱼钩的家伙。我问他：“天哪，你这些鱼钩居然是绿色和紫色的。鱼真的会上钩\n吗？”他说：“先生，我又不是卖给鱼的。”  \n \n        许多投资经理的做法跟这个鱼钩销售员是相同的。他们就像那个把盐卖给已\n经有太多盐的店主的家伙。只要那个店主继续购买食盐，他们就能把盐卖出去。','2026-07-05 16:55:53.049000',0,2073692323954429952,284,2073692323514028032),(2073692328345866246,' \n        许多投资经理的做法跟这个鱼钩销售员是相同的。他们就像那个把盐卖给已\n经有太多盐的店主的家伙。只要那个店主继续购买食盐，他们就能把盐卖出去。\n但这对于购买投资建议的人来说是行不通的。  \n \n        如果你们的投资风格像伯克希尔·哈撒韦，那么你们很难得到现在这些投资经\n理所获取的报酬，因为那样的话，你们将会持有一批沃尔玛股票、一批可口可乐\n股票、一批其他股票，别的什么都不用做。 你们只要坐等就行了。客户将会发\n财。不久之后，客户将会想：“这家伙只是买了一些好股票，又不需要做什么，\n我干嘛每年给他千分之五的报酬呢？”  \n \n        投资者考虑的跟投资经理考虑的不同。决定行为的是决策者的激励机制，这\n是人之常情。  \n \n        然而在投资管理界，几乎没有人这么做。我们是这么做的——我说的我们是','2026-07-05 16:55:53.049000',0,2073692323954429952,285,2073692323514028032),(2073692328345866247,'是人之常情。  \n \n        然而在投资管理界，几乎没有人这么做。我们是这么做的——我说的我们是\n巴菲特和芒格。其他人也有这么做的。但大多数人头脑里面有许多疯狂的想法。\n他们不是等待可以全力出击的良机，而是认为只要更加努力地工作，或者聘请更\n多商学院的学生，就能够在商场上战无不胜。在我看来，这种想法完全是神经病。  \n \n        决定行为的是决策者的激励机制，这是人之常情。所以制定正确的激励机制\n是非常、非常重要的教训。  \n \n        说到激励机制，在所有企业中，我最欣赏的是联邦快递。联邦快递系统的核\n心和灵魂是保证货物按时送达——这点成就了它产品的完整性，它必须在三更半\n夜让所有的飞机集中到一个地方，然后把货物分发到各架飞机上。如果哪个环节\n出现了延误，联邦快递就无法把货物及时地送到客户手里。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,286,2073692323514028032),(2073692328345866248,'夜让所有的飞机集中到一个地方，然后把货物分发到各架飞机上。如果哪个环节\n出现了延误，联邦快递就无法把货物及时地送到客户手里。 \n 以前它的派送系统总是出问题。那些职员从来没有及时完成工作。该公司的管\n理层想尽办法——劝说、威胁等等，只要你们能想到的手段，他们都用了。但是\n没有一种生效。  \n \n        最后，有人想到了好主意：不再照小时计薪，而是按班次计薪——而且职员\n只要工作做完就可以回家。他们的问题一夜之间就全都解决了。  \n \n        所以制定正确的激励机制是非常、非常重要的教训。联邦快递曾经不太明白\n这个道理。但愿从今以后，你们都能很快记住。  \n \n        好啦，现在我们已经明白，市场的有效性跟彩池投注系统是一样的——热门\n马比潜力马更可能获胜，但那些把赌注押在热门马身上的人未必会有任何投注优\n势。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,287,2073692323514028032),(2073692328345866249,'马比潜力马更可能获胜，但那些把赌注押在热门马身上的人未必会有任何投注优\n势。  \n \n        在股票市场上，有些铁路公司饱受更优秀的竞争对手和强硬的工会折磨，它\n们的股价可能是账面价值的三分之一。与之相反，IBM 在市场火爆时的股价可能\n是账面价值的六倍。所以这就像彩池投注系统。任何白痴都明白 IBM 这个企业\n的前景比铁路公司要好得多。但如果你把价格考虑在内，那么谁都很难讲清楚买\n哪只股票才是最好的选择了。所以说股市非常像彩池投注系统，它是很难被打败\n的。  \n \n        如果让投资者来挑选普通股，他应该用什么方式来打败市场——换句话说，\n获得比长期的平均回报率更好的收益呢？许多人看中的是一种叫做“行业轮换”\n的标准技巧。你只要弄清楚石油业什么时候比零售业表现得更好就行了，诸如此\n类的。你只要永远在市场上最火爆的行业里打转，比其他人做出更好的选择就可','2026-07-05 16:55:53.049000',0,2073692323954429952,288,2073692323514028032),(2073692328345866250,'的标准技巧。你只要弄清楚石油业什么时候比零售业表现得更好就行了，诸如此\n类的。你只要永远在市场上最火爆的行业里打转，比其他人做出更好的选择就可\n以。依照这个假定，经过一段漫长的时间之后，你的业绩就会很出色。  \n \n        然而，我不知道有谁通过行业轮换而真正发大财。也许有些人能够做到。我\n并不是说没有人能做到。我只知道，我认识的富人——我认识的富人非常多——\n并不那么做。  \n \n        第二个基本方法是本杰明·格拉汉姆使用的方法——沃伦和我十分欣赏这种\n方法。作为其中一个元素，格拉汉姆使用了私人拥有价值的概念，也就是说，应\n该考虑如果整个企业出售（给私人拥有者）的话，能够卖多少钱。在很多情况下，\n那是可以计算出来的。  \n \n        然后，你再把股价乘以股票的份数，如果你得到的结果是整个售价的三分之','2026-07-05 16:55:53.049000',0,2073692323954429952,289,2073692323514028032),(2073692328345866251,'那是可以计算出来的。  \n \n        然后，你再把股价乘以股票的份数，如果你得到的结果是整个售价的三分之\n一或更少，他会说你买这样的股票是捡了大便宜。即使那是一家烂企业，管理者\n是个酗酒的老糊涂，每股的真实价值比你支付的价格高出那么多，这意味着你能\n得到各种各样的好处。你如果得到这么多额外的价值，用格拉汉姆的话来说，就\n拥有了巨大的安全边际。  \n \n        但总的来说，他购买股票的时候，世界仍未摆脱 20 世纪 30 年代经济大萧条\n的影响——英语世界600年里最严重的经济衰退。我相信扣除通货膨胀因素之后，\n英国利物浦的小麦价格大概是 600 年里最低的。人们很久才摆脱大萧条带来的恐\n慌心理，而本杰明·格拉汉姆早就拿着盖格探测器在 20 世纪 30 年代的废墟中寻\n找那些价格低于价值的股票。 \n  而且在那个时代，流动资金确实属于股东。如果职员不再有用，你完全可以','2026-07-05 16:55:53.049000',0,2073692323954429952,290,2073692323514028032),(2073692328345866252,'找那些价格低于价值的股票。 \n  而且在那个时代，流动资金确实属于股东。如果职员不再有用，你完全可以\n解雇他们，拿走流动资金，把它装进股东的口袋里。当时的资本主义就是这样的。  \n \n        当然，现在的会计报表上的东西是当不得真的——因为企业一旦开始裁员，\n大量的资产就不见啦。按照现代文明的社会制度和新的法律，企业的大量资产属\n于职员，所以当企业走下坡路时，资产负债表上的一些资产就消失了。  \n \n        如果你自己经营一家小小的汽车经销店，情况可能不是这样的。你可以不需\n要为员工缴纳医疗保险之类的福利金，如果生意变得很糟糕，你可以收起你的流\n动资金回家去。但 IBM 不能或者不去这么做。看看当年 IBM 由于世界上主流科\n技发生变化，加上它自身的市场地位下降，决定削减员工的规模时，它的资产负\n债表上失去了什么吧。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,291,2073692323514028032),(2073692328345866253,'技发生变化，加上它自身的市场地位下降，决定削减员工的规模时，它的资产负\n债表上失去了什么吧。  \n \n        在摧毁股东财富方面 IBM 算得上是模范了。它的管理人员非常出色，训练有\n素。但科学技术发生了很大的变化，导致 IBM 成功地“冲浪”60 年之后被颠下了\n浪尖。这算是溃败吧——是一堂生动的课，让人明白经营科技企业的难处，这也\n是沃伦和芒格不很喜欢科技行业的原因之一。我们并不认为我们精通科技，这个\n行业会发生许多稀奇古怪的事情。  \n \n        总而言之，这个我称之为本杰明·格拉汉姆经典概念的问题在于，人们逐渐变\n得聪明起来，那些显而易见的便宜股票消失了。你们要是带着盖格探测器在废墟\n上寻找，它将不再发出响声。  \n \n        但由于那些拿着铁锤的人的本性——正如我说过的那样，在他们看来，每个','2026-07-05 16:55:53.049000',0,2073692323954429952,292,2073692323514028032),(2073692328345866254,'上寻找，它将不再发出响声。  \n \n        但由于那些拿着铁锤的人的本性——正如我说过的那样，在他们看来，每个\n问题都像钉子——本杰明·格拉汉姆的信徒们作出的反应是调整他们的盖格探测\n器的刻度。实际上，他们开始用另一种方法来定义便宜股票。他们不断地改变定\n义，以便能够继续原来的做法。他们这么做效果居然也很好，可见本杰明·格拉\n汉姆的理论体系是非常优秀的。  \n \n        当然，他的理论最厉害的部分是“市场先生”的概念。格拉汉姆并不认为市场\n是有效的，他把市场当成一个每天都来找你的躁狂抑郁症患者。有时候，“市场\n先生”说：“你认为我的股票值多少？我愿意便宜卖给你。”有时候他会说：“你的\n股票想卖多少钱？我愿意出更高的价钱来买它。”所以你有机会决定是否要多买\n进一些股票，还是把手上持有的卖掉，或者什么也不做。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,293,2073692323514028032),(2073692328345866255,'股票想卖多少钱？我愿意出更高的价钱来买它。”所以你有机会决定是否要多买\n进一些股票，还是把手上持有的卖掉，或者什么也不做。  \n \n        在格拉汉姆看来，能够和一个永远给你这一系列选择的躁狂抑郁症患者做生\n意是很幸运的事情。这种思想非常重要。例如，它让巴菲特在其成年之后的一生\n中受益匪浅。  \n \n        然而，如果我们只是原封不动地照搬本杰明·格拉汉姆的经典做法，我们不可\n能拥有现在的业绩。那是因为格拉汉姆并没有尝试去做我们做过的事情。  \n \n        例如，格拉汉姆甚至不愿意跟企业的管理人员交谈。他这么做是有原因的。\n最好的教授用通俗易懂的语言来表达自己的思想，格拉汉姆也一样，他想要发明\n一套每个人都能用的理论。他并不认为随便什么人都能够跑去跟企业的管理人员\n交谈并学到东西。他还认为企业的管理人员往往会非常狡猾地歪曲信息，用来误','2026-07-05 16:55:53.049000',0,2073692323954429952,294,2073692323514028032),(2073692328345866256,'一套每个人都能用的理论。他并不认为随便什么人都能够跑去跟企业的管理人员\n交谈并学到东西。他还认为企业的管理人员往往会非常狡猾地歪曲信息，用来误\n导人们。所以跟管理人员交谈是很困难的。当然，现在仍然如此——人性就是这\n样的。 \n \n \n        我们起初是格拉汉姆的信徒，也取得了不错的成绩，但慢慢\n地，我们培养起了更好的眼光。我们发现，有的股票虽然价格是其账面价值的两\n三倍，但仍然是非常便宜的，因为该公司的市场地位隐含着成长惯性，它的某个\n管理人员可能非常优秀，或者整个管理体系非常出色等等。  \n \n        一旦我们突破了格拉汉姆的局限性，用那些可能会吓坏格拉汉\n姆的定量方法来寻找便宜的股票，我们就开始考虑那些更为优质的企业。  \n \n        顺便说一声，伯克希尔·哈撒韦数千亿美元资产的大部分来自\n这些更为优质的企业。最早的两三亿美元的资产是我们用盖格探测器四处搜索赚','2026-07-05 16:55:53.049000',0,2073692323954429952,295,2073692323514028032),(2073692328345866257,' \n        顺便说一声，伯克希尔·哈撒韦数千亿美元资产的大部分来自\n这些更为优质的企业。最早的两三亿美元的资产是我们用盖格探测器四处搜索赚\n来的，但绝大多数钱来自那些伟大的企业。  \n \n        大多数投资经理的情况是，客户都要求他们懂得许许多多的事\n情。而在伯克希尔·哈撒韦，没有任何客户能够解雇我们。  \n \n        即使在早年，有些钱也是通过短暂地投资优质企业赚来的。比\n如说，巴菲特合伙公司（注：巴菲特 1957—1969 年经营的合伙投资私募基金）\n就曾经在美国运通和迪斯尼股价大跌的时候予以购进。  \n \n        大多数投资经理的情况是，客户都要求他们懂得许许多多的事\n情。而在伯克希尔·哈撒韦，没有任何客户能够解雇我们，所以我们不需要讨好\n客户。我们认为，如果发现了一次定错价格的赌注，而且非常有把握会赢，那么','2026-07-05 16:55:53.049000',0,2073692323954429952,296,2073692323514028032),(2073692328345866258,'情。而在伯克希尔·哈撒韦，没有任何客户能够解雇我们，所以我们不需要讨好\n客户。我们认为，如果发现了一次定错价格的赌注，而且非常有把握会赢，那么\n就应该狠狠地下注，所以我们的投资没那么分散。我认为我们的方法比一般投资\n经理好得多得多。  \n \n        然而，平心而论，我觉得许多基金管理人就算采用我们的方法，\n也未必能够成功地销售他们的服务。但如果你们投资的是养老基金，期限为 40\n年，那么只要最终的结果非常好，过程有点波折或者跟其他人有点不同又怎么样\n呢？所以业绩波动有点大也没关系的。  \n \n        在当今的投资管理界，每个人不仅都想赢，而且都希望他们的\n投资之路跟标准道路相差不要太远。这是一种非常造作、疯狂的臆想。投资管理\n界这种做法跟中国女人裹脚的陋习差不多。那些管理者就像尼采所批评的那个以\n瘸腿为荣的人。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,297,2073692323514028032),(2073692328350060544,'界这种做法跟中国女人裹脚的陋习差不多。那些管理者就像尼采所批评的那个以\n瘸腿为荣的人。  \n \n        那真的是自缚手脚。那些投资经理可能会说：“我们不得不那\n么做呀。人们就是以那种方式评价我们的。”就目前的商界而言，他们的说法可\n能是正确的。但在理智的客户看来，这个系统整个是很神经的，导致许多有才华\n的人去从事毫无社会意义的活动。  \n \n        如果从一开始就做一些可行的事情，而不是去做一些不可行的\n事情，你成功的几率要大得多。这难道不是显而易见的吗？ \n    伯克希尔的系统就不神经。道理就这么简单，即便非常聪明的人，在如此激\n烈竞争的世界里，在与其他聪明而勤奋的人竞争时，也只能得到少数真正有价值\n的投资机会。  \n \n        好好把握少数几个看准的机会比永远假装什么都懂好得多。如果从一开始就','2026-07-05 16:55:53.049000',0,2073692323954429952,298,2073692323514028032),(2073692328350060545,'的投资机会。  \n \n        好好把握少数几个看准的机会比永远假装什么都懂好得多。如果从一开始就\n做一些可行的事情，而不是去做一些不可行的事情，你成功的几率要大得多。这\n难道不是显而易见的吗？  \n \n        你们有谁能够非常自信地认为自己看准了 56 个好机会呢？请举手。有多少\n人能够比较有把握地认为自己看准了两三个好机会呢？陈词完毕。  \n \n        我想说的是，伯克希尔·哈撒韦的方法是依据现实的投资问题而不断调整变化\n的。  \n \n        我们的确从许多优质企业上赚了钱。有时候，我们收购整个企业；有时候呢，\n我们只是收购它的一大部分股票。但如果你去分析的话，就会发现大钱都是那些\n优质企业赚来的。其他赚许多钱的人，绝大多数也是通过优质企业来获利的。  \n \n        长远来看，股票的回报率很难比发行该股票的企业的年均利润高很多。如果','2026-07-05 16:55:53.049000',0,2073692323954429952,299,2073692323514028032),(2073692328350060546,'优质企业赚来的。其他赚许多钱的人，绝大多数也是通过优质企业来获利的。  \n \n        长远来看，股票的回报率很难比发行该股票的企业的年均利润高很多。如果\n某家企业 40 年来的资本回报率是 6%，你在这 40 年间持有它的股票，那么你得\n到的回报率不会跟 6%有太大的差别——即使你最早购买时该股票的价格比其账\n面价值低很多。相反地，如果一家企业在过去二三十年间的资本回报率是 18%，\n那么即使你当时花了很大的价钱去买它的股票，你最终得到的回报也将会非常可\n观。  \n \n        所以窍门就在于买进那些优质企业。这也就买进了你可以设想其惯性成长效\n应的规模优势。  \n \n        你们要怎样买入这些伟大公司的股票呢？有一种方法是及早发现它们——\n在它们规模很小的时候就买进它们的股票。例如，在山姆·沃尔顿第一次公开募','2026-07-05 16:55:53.049000',0,2073692323954429952,300,2073692323514028032),(2073692328350060547,' \n        你们要怎样买入这些伟大公司的股票呢？有一种方法是及早发现它们——\n在它们规模很小的时候就买进它们的股票。例如，在山姆·沃尔顿第一次公开募\n股的时候买进沃尔玛。许多人都努力想要这么做。这种方法非常有诱惑性。如果\n我是年轻人，我也会这么做的。  \n \n        但这种（投资起步阶段公司的）方法对伯克希尔·哈撒韦来讲已经没有用了，\n因为我们有了太多的钱。（采用这种方法的话，）我们找不到适合我们的投资规模\n的企业。此外，我们有我们的投资方法。但我认为，对于那些初出茅庐的人来说，\n要是配以自律，投资有发展潜力的小公司是一种非常聪明的办法。只不过我没那\n么做过而已。  \n \n        等到优秀企业明显壮大之后，想要再参股就很困难了，因为竞争非常激烈。\n到目前为止，伯克希尔还是设法做到了。但我们能够继续这么做吗？哪个项目才','2026-07-05 16:55:53.049000',0,2073692323954429952,301,2073692323514028032),(2073692328350060548,' \n        等到优秀企业明显壮大之后，想要再参股就很困难了，因为竞争非常激烈。\n到目前为止，伯克希尔还是设法做到了。但我们能够继续这么做吗？哪个项目才\n是我们的下一次可口可乐投资呢？嗯，我不知道答案。我认为我们现在越来越难\n以找到那么好的投资项目了。 \n 理想的情况是——我们遇到过很多这种情况——你买入的伟大企业正好有一位\n伟大的管理者，因为管理人员很重要。例如，通用电气的管理者是杰克·韦尔奇，\n而不是那个掌管西屋电气的家伙，这就造成了极大的不同。所以管理人员也很重\n要。  \n \n        而这有时候是可以预见的。我并不认为只有天才能够明白杰克·韦尔奇比其他\n公司的管理者更具远见和更加出色。我也不认为只有非常聪明的人才能理解迪斯\n尼的发展潜力非常大，艾斯纳（注：迈克尔·艾斯纳，1942-，迪斯尼公司时任董','2026-07-05 16:55:53.049000',0,2073692323954429952,302,2073692323514028032),(2073692328350060549,'公司的管理者更具远见和更加出色。我也不认为只有非常聪明的人才能理解迪斯\n尼的发展潜力非常大，艾斯纳（注：迈克尔·艾斯纳，1942-，迪斯尼公司时任董\n事会主席兼首席执行官）和威尔斯（注：弗兰克·威尔斯，1932-1994，迪斯尼公\n司的时任总裁兼首席营运官）是非常罕见的管理者。  \n \n        所以你们偶尔会有机会可以投资一家有着优秀管理者的优秀企业。当然啦，\n这是非常幸运的事情。如果有了这些机会却不好好把握，那你们就犯了大错。  \n \n        你们偶尔会发现有些管理者非常有才能，能够做普通人做不到的事情。我认\n为西蒙·马克斯——英国玛莎百货的第二代掌门——是这样的人，国民收款机公司\n的帕特森是这样的人，山姆·沃尔顿也是这样的人。  \n \n        这些人并不少见——而且在许多时候，他们也不难被辨认出来。如果他们采','2026-07-05 16:55:53.049000',0,2073692323954429952,303,2073692323514028032),(2073692328350060550,'的帕特森是这样的人，山姆·沃尔顿也是这样的人。  \n \n        这些人并不少见——而且在许多时候，他们也不难被辨认出来。如果他们采\n取合理的举措——再加上这些人通常会让员工变得更加积极和聪明——那么管\n理人员就能够发挥更重要的作用。  \n \n        然而一般来说，把赌注押在企业的质量上比押在管理人员的素质上更为妥\n当。换句话说，如果你们必须作选择的话，要把赌注押在企业的发展前景上，而\n不是押在管理者的智慧上。  \n \n        在非常罕见的情况下，你会找到一个极其出色的管理者，哪怕他管理的企业\n平平无奇，你们对他的企业进行投资也是明智的行为。  \n \n        另外有一种非常简单的效应，无论是投资经理还是其他人都很少提及，那就\n是税收的效应。如果你们打算进行一项为期 30 年、年均复合收益为 15%的投资，','2026-07-05 16:55:53.049000',0,2073692323954429952,304,2073692323514028032),(2073692328350060551,'是税收的效应。如果你们打算进行一项为期 30 年、年均复合收益为 15%的投资，\n并在最后缴纳 35%的所得税，那么你们的税后年均复合收益是 13.3%。  \n \n        过度地追求减少纳税额是企业犯下大错的常见原因之一。  \n \n        与之相反， 如果你们投资了同样的项目， 但每年赚了 15%之后缴纳 35%的\n所得税，那么你们的复合回报率将会是 1 5%减去 1 5%的 3 5 %——也就是每年的\n复合回报率为.75%（15%-15%×35%=9.75%）。所以两者相差超过了 3.5%。而对于\n为期 30 年的长期投资而言，每年多 3.5%的回报率带来的利润绝对会让你们瞠目\n结舌。如果你们长期持有一些伟大公司的股票，光是少交的所得税就能让你增添\n很多财富。 \n   即使是年均回报率 10%的 30 年期投资项目，在最后支付 35%的所得税之后，','2026-07-05 16:55:53.049000',0,2073692323954429952,305,2073692323514028032),(2073692328350060552,'很多财富。 \n   即使是年均回报率 10%的 30 年期投资项目，在最后支付 35%的所得税之后，\n也能给你带来 8.3%的税后年均收益率。相反，如果你每年支付 35%的税收，而\n不是在最后才支付，那么你的年均收益率就下降到 6.5%。所以就算你投资的股\n票的历史回报率只与整个股市的回报率持平，分红派息又很低，你也能多得到差\n不多两个百分点的年均税后收益。  \n \n        我活了这么久，见识过许多企业所犯的错误，我认为过度地追求减少纳税额\n是企业犯下大错的常见原因之一。我见过许多人因为太想避税而犯下可怕的错\n误。  \n \n        沃伦和我个人从不钻油井（注：一种大规模避税的方法）。我们依法纳税。\n到目前为止，我们做得非常好。从今以后，无论什么时候，只要有人要卖给你避\n税的服务，我的建议是别买。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,306,2073692323514028032),(2073692328350060553,'到目前为止，我们做得非常好。从今以后，无论什么时候，只要有人要卖给你避\n税的服务，我的建议是别买。  \n \n        实际上，无论什么时候，只要有人拿着一份 200 页的计划书并收一大笔佣金\n要卖给你什么，别买下它。如果采用这个“芒格的规矩”，你偶尔会犯错误。然而\n从长远来看，你将会远远领先于其他人——你将会避开许多可能会让你仇视你的\n同类的不愉快经验。  \n \n        对于个人而言，做到长期持有几家伟大公司的股票而什么都不用做的地步有\n许多巨大的优势：你付给交易员的费用更少，听到的废话也更少，如果这种方法\n生效，税务系统每年会给你 1%到 3%的额外回报。  \n \n        你认为你们大多数人通过聘请投资顾问，花 1%的收益支付他们的薪水，让\n他们想尽办法避税，这样就能获得很大的优势吗？祝你好运。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,307,2073692323514028032),(2073692328350060554,' \n        你认为你们大多数人通过聘请投资顾问，花 1%的收益支付他们的薪水，让\n他们想尽办法避税，这样就能获得很大的优势吗？祝你好运。  \n \n        这种投资哲学危险吗？是的。生活中的一切都有风险。由于投资伟大的公司\n能够赚钱的道理太过明显，所以它有时被做过头了。在 1950 年代的大牛市，每\n个人都知道哪些公司是优秀的。所以这些公司的市盈率飞涨到 50 倍、60 倍、70\n倍。就像 IBM 从浪尖掉落那样，许多公司也好景不再。因此，虚高的股价导致\n了巨大的投资灾难。你们必须时刻注意这种危险。  \n \n        所以风险是存在的。没有什么顺理成章和轻而易举的事。但如果你们能够找\n到某个价格公道的伟大公司的股票，买进它，然后坐下来，这种方法将会非常非\n常有效——尤其是对个人投资者而言。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,308,2073692323514028032),(2073692328350060555,'到某个价格公道的伟大公司的股票，买进它，然后坐下来，这种方法将会非常非\n常有效——尤其是对个人投资者而言。  \n \n        在成长股票模式中，有这样一个子模式：在你们的一生当中，你们能够找到\n少数几家企业，它们的管理者仅通过提高价格就能极大地提升利润——然而他们\n还没有这么做。所以他们拥有尚未利用的提价能力。人们不用动脑筋也知道这是\n好股票。  \n \n        迪斯尼就是这样的。带你们的孙子去迪斯尼乐园玩是非常独特的体验。你们\n不会经常去。全国有许许多多的人口。迪斯尼发现它可以把门票的价格提高很多，\n而游客的人数依然会稳定增长。 \n \n     所以迪斯尼公司的伟大业绩固然是因为艾斯纳和威尔斯极其出色，但也应该\n归功于迪斯尼乐园和迪斯尼世界的提价能力，以及其经典动画电影的录像带销\n售。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,309,2073692323514028032),(2073692328350060556,'     所以迪斯尼公司的伟大业绩固然是因为艾斯纳和威尔斯极其出色，但也应该\n归功于迪斯尼乐园和迪斯尼世界的提价能力，以及其经典动画电影的录像带销\n售。  \n \n        在伯克希尔·哈撒韦，沃伦和我很早就提高了喜诗糖果的价格。当然，我们投\n资了可口可乐——它也有一些尚未利用的提价能力。可口可乐也有出色的管理人\n员。除了提高价格之外，可口可乐的高层郭思达（Goizueta）和柯欧孚（Keough）\n还做了其他许多事情。那是很完美的（投资）。  \n \n        你会发现一些定价过低的赚钱机会。确有人不会把商品价格定到市场能够轻\n易接受的高位。你们要是发现这样的情况，那就像在马路上看到钱一样——前提\n是你们有勇气相信自己的判断。  \n \n        如果你们看看伯克希尔那些赚大钱的投资项目，并试图从中寻找模式的话，','2026-07-05 16:55:53.049000',0,2073692323954429952,310,2073692323514028032),(2073692328350060557,'是你们有勇气相信自己的判断。  \n \n        如果你们看看伯克希尔那些赚大钱的投资项目，并试图从中寻找模式的话，\n你们将会发现，我们曾经两次在有两份报纸的城市中买了其中一家，两个城市之\n后都变成了只剩一家报纸的市场。所以从某种程度上来讲，我们是在赌博。  \n \n        当时我们看准了该报会成为最后的赢家，而且其管理人员非常正直和聪明。\n那真是一家梦幻般美好的企业。它的管理人员是非常高尚的人——凯瑟琳·格拉汉\n姆的家族。所以这项投资就像一场美梦——绝佳的美梦。  \n \n        当然，那是 1973 年到 1974 年间的事情。那次股灾跟 1932 年的很像。那可\n能是 40 年一遇的大熊市。那次投资为我们赚了 50 倍的收益（注：至 1994 年演\n讲时）。如果我是你们，我可不敢指望你们这辈子能够得到像 1973 年到 1974 年','2026-07-05 16:55:53.049000',0,2073692323954429952,311,2073692323514028032),(2073692328350060558,'讲时）。如果我是你们，我可不敢指望你们这辈子能够得到像 1973 年到 1974 年\n的《华盛顿邮报》那么好的投资项目。  \n \n        让我来谈谈另外一个模型。当然，吉列和可口可乐都生产价格相当低廉的产\n品，在世界各地占有巨大的市场优势。就吉列而言，他们的技术仍然是领先的。\n当然，和微型芯片相比，剃须刀的技术相当简单。但它的竞争对手却很难做到这\n一点。  \n \n        所以他们在剃须刀改进方面处于领先地位。吉列在许多国家的剃须刀市场的\n占有率超过 90%。  \n \n        政府职员保险公司（GEIGO）是个非常有趣的模型。它是你们应该记住的大\n概 100 种模型之外的一种。我有许多终生都在挽救濒临倒闭企业的朋友。他们不\n约而同地使用了下面的方法——我称之为癌症手术法。  \n \n        他们望着这团乱麻，看是否把某些业务砍掉，剩下的健康业务会值得保留下','2026-07-05 16:55:53.049000',0,2073692323954429952,312,2073692323514028032),(2073692328350060559,'约而同地使用了下面的方法——我称之为癌症手术法。  \n \n        他们望着这团乱麻，看是否把某些业务砍掉，剩下的健康业务会值得保留下\n来。如果他们发现确实有，就会把其他的都砍掉。当然，如果这种方法行不通，\n他们就会让该企业破产。但它往往是奏效的。 \n政府职员保险公司的主业非常好——虽被公司其他的一片混乱所埋没，但仍然\n能够运转。由于被成功冲昏了头脑，政府职员保险公司做了一些蠢事。他们错误\n地认为，因为他们赚了很多钱，所以什么都懂，结果蒙受了惨重的损失。  \n \n        他们不得不砍掉所有愚蠢的业务，回到原来那极其出色的老本行。如果你们\n仔细思考，就会明白这是一种非常简单的模型。并且它被人们一次又一次地反复\n应用。  \n \n        至于政府职员保险公司，它让我们不费吹灰之力就赚了很多钱。它是一家很\n棒的企业，有一些可以轻易砍掉的愚蠢业务。政府职员保险公司聘请了一些性格','2026-07-05 16:55:53.049000',0,2073692323954429952,313,2073692323514028032),(2073692328350060560,' \n        至于政府职员保险公司，它让我们不费吹灰之力就赚了很多钱。它是一家很\n棒的企业，有一些可以轻易砍掉的愚蠢业务。政府职员保险公司聘请了一些性格\n和智力都很杰出的人，他们对它进行了大刀阔斧的改革。那是一个你们想要寻找\n的模型。  \n \n        你们在一生中也许能够找到一种、两种或三种这样绝好的模型。至于足够好\n到能用得上的模型，你们也许能够找到 20 种或者 30 种。  \n \n        最后，我想再次谈谈投资管理。这门生意特别好玩——因为在净值的水平上，\n整个投资管理业加起来并没有给所有客户创造附加值。这就是它的运转方式。  \n \n        在净值的水平上，整个投资管理业加起来并没有给所有客户创造附加值。这\n就是它的运转方式。  \n \n        当然，水管安装业不是这样的，医疗行业也不是这样的。如果你们打算在投','2026-07-05 16:55:53.049000',0,2073692323954429952,314,2073692323514028032),(2073692328354254848,'就是它的运转方式。  \n \n        当然，水管安装业不是这样的，医疗行业也不是这样的。如果你们打算在投\n资管理业开展你们的职业生涯，那么你们便面临着一种非常特殊的情况。大多数\n投资经理就像脊椎按摩师，他们对付这种情况的方式是打心底予以否认。这是常\n见的对付投资管理行业局限的方法。但如果你们想要过上最好的生活，我劝你们\n别采用这种心理否认的模式。  \n \n        我认为少数人——为数极少的投资经理——能够创造附加值。但我认为光靠\n聪明是做不到这一点的。我认为你们还必须接受一点训练，一旦瞄准机会就倾囊\n出击——如果你们想要尽力为客户提供高于市场平均回报率的长期收益的话。  \n \n        但我刚刚谈的只限于那些选择普通股的投资经理。我并没有包括其他人。也\n许有人精通外汇或者其他业务，能够以那种方式取得极佳的长期业绩，但那不是\n我了解的领域。我说的是如何挑选美国的股票。  ','2026-07-05 16:55:53.049000',0,2073692323954429952,315,2073692323514028032),(2073692328354254849,'许有人精通外汇或者其他业务，能够以那种方式取得极佳的长期业绩，但那不是\n我了解的领域。我说的是如何挑选美国的股票。  \n \n        我认为投资管理人员很难为客户提供许多附加值，但那并非不可能的任务。 \n重读第二讲 \n \n \n        2006 年，我重读了第二篇讲稿，我认为可以增加如下内容来\n加以提高：（1）解释哈佛大学和耶鲁大学近些年极为成功的投资；（2）现在有\n许多基金试图通过模仿或延续哈佛和耶鲁的投资方法来复制它们过去的成功，对\n其结果进行预测；（3）威廉·庞德斯通在其 2005 年的著作《财富方程式》中提\n出了有效市场假设，简单地对其进行评论。  \n \n        在我看来，情况是这样的，哈佛和耶鲁传统上并不强调在不借\n钱的情况下持有分散化的美国普通股，所以它们近些年来投资成功可能受到如下\n四种因素的推动：  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,316,2073692323514028032),(2073692328354254850,'钱的情况下持有分散化的美国普通股，所以它们近些年来投资成功可能受到如下\n四种因素的推动：  \n \n        （1）哈佛和耶鲁投资了债务杠杆收购（LBO）基金，这使它们\n持有的美国股票的收益产生了杠杆效应。债务杠杆收购基金的结构使得它们借债\n投资比在普通股票账户抵押借债更加安全，因为后一种借债在市场恐慌时常常被\n迫平仓。在大市表现良好的情况下，这种做法往往能够产生较为漂亮的结果。当\n然，如果除去各种基金费用，仅仅通过投资美国标普指数，再加上一点借债，也\n能够得到同样的结果。  \n \n        （2）在各个投资领域，哈佛和耶鲁选择或直接聘请那些能力\n出众的投资经理，这让我们再次看到，市场并不是完全有效的，而且有些好的投\n资结果来自异常的技巧或者其他异常的优势。就拿哈佛和耶鲁来说吧，由于它们\n自身的声望，它们能够进入一些利润最丰厚的高科技风险投资基金，而其他投资','2026-07-05 16:55:53.049000',0,2073692323954429952,317,2073692323514028032),(2073692328354254851,'资结果来自异常的技巧或者其他异常的优势。就拿哈佛和耶鲁来说吧，由于它们\n自身的声望，它们能够进入一些利润最丰厚的高科技风险投资基金，而其他投资\n者则不得其门而入。这些基金以往都很成功，这使它们比那些较为逊色的风险投\n资机构更能吸引到好的投资项目，非常合乎逻辑的是，最好的创业家都会早早选\n择那些声誉最好的基金。  \n \n        （3）哈佛和耶鲁明智而及时地模仿投资银行公司的做法，进\n行了几种当时不常见的投资活动，比如说投资低迷的美国公司债、高收益的外国\n债券和杠杆式的“固定收益套利”（Fixed Income Arbitrage），当时这些投资\n领域有许许多多的好机会。。  \n \n        （4）最后，哈佛和耶鲁近些年之所以能够通过杠杆投资和非\n常规投资获得不菲的收益，利率日益下降和股票市盈率逐渐上升共同起到了推波\n助澜的作用。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,318,2073692323514028032),(2073692328354254852,'常规投资获得不菲的收益，利率日益下降和股票市盈率逐渐上升共同起到了推波\n助澜的作用。  \n \n        哈佛和耶鲁极其成功的投资让我既喜且忧。喜的是，这证明学\n术在世俗事务中往往是有用的。像我这样喜爱学术然而却走进商界的人，对这种\n世俗成就的反应就像那些对米利都的泰勒斯津津乐道的现代科学家那样。泰勒斯\n是古代的科学家，他预见到来年橄榄会大丰收，于是就把当地的橄榄压榨机都租\n下来，发了一笔大财。  \n \n        忧的是：（1）受到妒忌心的驱使和推销员的怂恿，其他名牌\n大学热衷于模仿哈佛和耶鲁，它们未来恐怕会蒙受惨重的损失；（2）那些效仿\n跟风的推销者获得成功的可能性很小。我现在的感觉跟高科技泡沫即将破灭时的\n恐惧差不多。当时许多机构眼红起步早的成功风险投资者，比如说斯坦福大学，\n许多风险资本家采用了居心不良的推销方法，大约 900 亿美元因此投向了低质','2026-07-05 16:55:53.049000',0,2073692323954429952,319,2073692323514028032),(2073692328354254853,'恐惧差不多。当时许多机构眼红起步早的成功风险投资者，比如说斯坦福大学，\n许多风险资本家采用了居心不良的推销方法，大约 900 亿美元因此投向了低质\n的、不成熟的项目，到目前为止，那些后来跟进的投资者蒙受了多达 450 亿美元\n的净亏损。  \n \n        此外，哈佛和耶鲁现在可能需要展现与它们之前展现出来的不\n同的非常规智慧。让人们抛弃最近大获成功的做法是有悖人类本能的。但这往往\n是个好主意。减少欲望，而不是为了满足欲望而增加风险也同样是个好主意。  \n \n        我发表第二次演讲的时间是1994年，到现在已经12年过去了。\n在这 12 年里，大量有用的思想和资料都支持了我的观点：证券市场和赛马场的\n彩池投注系统都无法阻止某些投机者利用异乎寻常的技巧获得令人非常满意的、\n极其出众的回报。威廉·庞德斯通的著作《财富方程式》收集了许多现代资料，','2026-07-05 16:55:53.049000',0,2073692323954429952,320,2073692323514028032),(2073692328354254854,'彩池投注系统都无法阻止某些投机者利用异乎寻常的技巧获得令人非常满意的、\n极其出众的回报。威廉·庞德斯通的著作《财富方程式》收集了许多现代资料，\n以十分有趣的方式证明了这个道理。此外，那本书还记录了信息理论领域的前沿\n科学家克劳德·香农非凡的投资业绩，那使香农的方法看起来跟查理·芒格的方\n法差不多。 \n最新的普世智慧：查理答问录 \n \n \n        你和沃伦如何评估待收购的企业？  \n \n        我们不太用财务标尺；我们也使用许多主观的标准：我们能够\n信赖管理层吗？它会损害我们的声誉吗？会出现什么问题？我们理解这个行业\n吗？这家企业需要注资才能继续运转吗？预期的现金流是多少？我们并不期待\n它会直线增长，只要价格适中，周期性增长我们也能接受。  \n \n        年轻人在工作中应该追求什么？  \n \n        我有三个基本原则。同时满足这三个原则几乎是不可能的，但','2026-07-05 16:55:53.049000',0,2073692323954429952,321,2073692323514028032),(2073692328354254855,' \n        年轻人在工作中应该追求什么？  \n \n        我有三个基本原则。同时满足这三个原则几乎是不可能的，但\n你应该努力去尝试：  \n \n        ·别兜售你自己不会购买的东西。  \n        ·别为你不尊敬和钦佩的人工作。  \n        ·只跟你喜欢的人同事。  \n        我这一生真是非常幸运：由于和沃伦同事，这三个原则我都做\n到了。  \n \n        你对年轻人有什么人生建议吗？  \n \n        每天起床的时候，争取变得比你从前更聪明一点。认真地、出\n色地完成你的任务。慢慢地，你会有所进步，但这种进步不一定很快。但你这样\n能够为快速进步打好基础……每天慢慢向前挪一点。到最后——如果你足够长寿\n的话——像大多数人那样，你将会得到你应得的东西。  \n \n        人生在不同阶段会遇到不同的难题，非常棘手的难题。我认为','2026-07-05 16:55:53.049000',0,2073692323954429952,322,2073692323514028032),(2073692328354254856,'的话——像大多数人那样，你将会得到你应得的东西。  \n \n        人生在不同阶段会遇到不同的难题，非常棘手的难题。我认为\n有三点有助于应付这些困难：  \n        ·期望别太高。  \n        ·拥有幽默感。  \n        ·让自己置身于朋友和家人的爱之中。  \n        最重要的是，要适应生活的变化。如果世界没有改变，我现在\n身上仍然会有 12 个缺陷。 \n \n第三讲：论基本的、普世的智慧（修正稿） \n \n \n斯坦福法学院 1996 年 4 月 19 日 \n \n        在今天的演讲中，我想进一步发挥两年前我在南加州大学商学\n院所讲的内容⋯⋯你们手头有我在南加大演讲的讲稿。里面没有哪一点是我今天不\n会重复的。但我想扩展我当时说过的话。显而易见，如果沃伦·巴菲特从哥伦比\n亚大学商学院毕业之后没有吸取新的知识，伯克希尔将不可能取得现在的成就。','2026-07-05 16:55:53.049000',0,2073692323954429952,323,2073692323514028032),(2073692328354254857,'会重复的。但我想扩展我当时说过的话。显而易见，如果沃伦·巴菲特从哥伦比\n亚大学商学院毕业之后没有吸取新的知识，伯克希尔将不可能取得现在的成就。\n沃伦将会变成富人——因为他从哥伦比亚的格拉汉姆那里学到的知识足以让任\n何人变得富裕。但如果他没有继续学习，他将不会拥有伯克希尔·哈撒韦这样的\n企业。  \n \n        你们要怎样才能得到普世智慧呢？使用哪种方法能够让你们\n跻身于世上极少数拥有基本实践智慧的人士之列呢？  \n \n        长久以来，我相信有某种方法——它是几乎所有聪明人都能掌\n握的——比绝大多数人所用的方法都有效。正如我在南加大商学院说过的，你们\n需要的是在头脑里形成一个由各种思维模型构成的框架。然后将你们的实际经验\n和间接经验（通过阅读等手段得来的经验）悬挂在这个强大的思维模型架上。使\n用这种方法可以让你们将各种知识融会贯通，加深对现实的认知。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,324,2073692323514028032),(2073692328354254858,'和间接经验（通过阅读等手段得来的经验）悬挂在这个强大的思维模型架上。使\n用这种方法可以让你们将各种知识融会贯通，加深对现实的认知。  \n \n        你们今天的阅读作业包括杰克·韦尔奇和沃伦·巴菲特分别\n为通用电气和伯克希尔·哈撒韦股东撰写的最新年度股东信。杰克·韦尔奇拥有\n工程学博士学位。而沃伦如果愿意，能够取得任何学科的博士学位。这两位先生\n也都是资深的教师。  \n \n        如果你们认真研究的话，会发现普世智慧是一门相当高深的学\n问。不信你们看看通用电气取得的成就，看看伯克希尔·哈撒韦已有的业绩。  \n \n        当然，沃伦有一位教授或者说导师，那就是本杰明·格拉汉姆，\n他对沃伦的影响很大。格拉汉姆的学问很好，当他从哥伦比亚毕业时，有三个不\n同学科的系邀请他去攻读它们的博士课程，并要求他一入学就开始授课：（那三\n个系分别是）文学系、希腊和拉丁古典系、数学系。  ','2026-07-05 16:55:53.049000',0,2073692323954429952,325,2073692323514028032),(2073692328354254859,'同学科的系邀请他去攻读它们的博士课程，并要求他一入学就开始授课：（那三\n个系分别是）文学系、希腊和拉丁古典系、数学系。  \n \n        格拉汉姆的性格非常适合做学问。我认识他。他特别像亚\n当·斯密——非常专注、非常聪慧。甚至他的外表也像个学者。而且他是个好人。\n格拉汉姆对赚钱这回事并不那么用心，但去世时家财万贯——即使他总是非常慷\n慨。他在哥伦比亚当了 30 年穷教书匠，并独力或合作撰写了许多后来成为他那\n个学科最好教材的著作。  \n \n        所以我认为，学术蕴含了许多普世智慧，而且最好的学术观念\n确实是有用的。  \n \n        当然，当我谈到跨学科方法——你们应该掌握各个学科的主要\n模型，并将它们统统派上用场——时，我是真的呼吁你们不要理会学科的法定界\n限。 \n   这个世界并不是按照跨学科的方法组织起来的。它反对跳出学科的法定范围。','2026-07-05 16:55:53.049000',0,2073692323954429952,326,2073692323514028032),(2073692328354254860,'模型，并将它们统统派上用场——时，我是真的呼吁你们不要理会学科的法定界\n限。 \n   这个世界并不是按照跨学科的方法组织起来的。它反对跳出学科的法定范围。\n大规模的企业也是这样。当然，学术界本身也反对这么做。就这一点来说，我认\n为学术界错得有些离谱，功能失调。  \n \n        许多企业之所以会出现那些最糟糕的毛病，功能失调，是因为人们将现实分\n割为各自为政、互不相干的独立部门。所以如果你们想要成为好的思想家，就必\n须养成跳出法定界限的思维习惯。  \n \n        你们不需要了解所有的知识，只要吸取各个学科最杰出的思想就行了。那并\n不难做到。  \n \n        我打算用定约桥牌（的比喻）来证明这一点。假定你想要成为定约桥牌的高\n手。嗯，你们知道约定——你们知道要怎样才能赢牌。如果你手里有大牌或者最\n大的王牌，那么你肯定能够成为赢家。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,327,2073692323514028032),(2073692328354254861,'手。嗯，你们知道约定——你们知道要怎样才能赢牌。如果你手里有大牌或者最\n大的王牌，那么你肯定能够成为赢家。  \n \n        但如果你们手里有一套墩或者两张短套花牌，要怎样才能得到其他你需要的\n牌墩呢？喏，标准的方法有六七种。你可以做长套花牌，可以飞牌，可以扔牌，\n可以交叉将吃，可以挤牌，还可以用各种方式误导防守方犯错。这些方法并不算\n多。  \n \n        但如果你们只懂得其中的一两种，那么你们肯定会一败涂地。  \n \n        此外，这些方法相互之间也有联系。因此，你必须懂得它们之间是怎样相互\n影响的。否则你就无法把牌打好。  \n \n        同样，我曾建议你们正反两面都要考虑到。优秀的桥牌庄家会想：“我要怎\n样才能抓到好牌呢？”但他们也会反过来想。（他们会想：）“犯哪些错误会导致我\n手里全是烂牌？”这两种思考方式都很有用。所以，要想在人生的赌局中获胜，','2026-07-05 16:55:53.049000',0,2073692323954429952,328,2073692323514028032),(2073692328354254862,'样才能抓到好牌呢？”但他们也会反过来想。（他们会想：）“犯哪些错误会导致我\n手里全是烂牌？”这两种思考方式都很有用。所以，要想在人生的赌局中获胜，\n你们应该掌握各种必要的模型，然后反复地思考。桥牌的哲理在生活中同样有效。  \n \n        定约桥牌在你们这代人里不流行了，这真是悲剧。中国人的桥牌玩得比我们\n好。他们现在从小学就开始教桥牌。要是他们也实行资本主义，天知道他们该发\n展得多好。如果我们美国人不懂桥牌，却和一群精通桥牌的人竞争，那么我们就\n又多了一个没必要的劣势。  \n \n        由于你们的学术结构大体上并不鼓励你们的思想跳出法定的学科界限，你们\n处于一种不利的地位，因为从某种意义上来说，虽然学术对你们来讲非常有用，\n但是你们的老师没有教对。 \n  我为你们设想的对策是我很小的时候在保育院学到的：小红母鸡的故事。当','2026-07-05 16:55:53.049000',0,2073692323954429952,329,2073692323514028032),(2073692328354254863,'但是你们的老师没有教对。 \n  我为你们设想的对策是我很小的时候在保育院学到的：小红母鸡的故事。当\n然，故事里最重要的一句话是：“‘那我就自己来吧’，小红母鸡说。”  \n \n        “那我就自己来吧”，小红母鸡说。  \n \n        所以如果你们的教授并没有教给你们正确的跨学科方法——如果每个教授\n都想过度地使用他自己的模式，对其他学科的重要模型弃之不用——你们可以自\n己改正那种愚蠢的做法。他是个笨蛋，并不意味着你们也要成为笨蛋。你们可以\n向其他学科学习能够更好地解决问题的模型。只要养成正确的思维习惯你们就能\n做到这一点。  \n \n        如果你把自己训练得更加客观，拥有更多学科的知识，那么你在考虑事情的\n时候，就能够比那些比你聪明得多的人更厉害，我觉得这还满有意思的……  \n \n        再说了，那样还能赚到很多钱，我本人就是个活生生的证据。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,330,2073692323514028032),(2073692328354254864,'时候，就能够比那些比你聪明得多的人更厉害，我觉得这还满有意思的……  \n \n        再说了，那样还能赚到很多钱，我本人就是个活生生的证据。  \n \n        我最喜欢的商业案例之一是好时公司的故事。好时巧克力的味道很独特，因\n为他们用来制造可可脂的石磨非常古老，是他们 19 世纪在宾夕法尼亚州开业时\n传下来的。他们的巧克力含有少量的可可豆的外皮。因此好时巧克力的味道很棒，\n人们都很喜欢。  \n \n        好时清楚地知道，如果他们想要把业务拓展到加拿大，那么就不应该改变那\n种无往不胜的味道。  \n \n        好时清楚地知道，如果他们想要把业务拓展到加拿大，那么就不应该改变那\n种无往不胜的味道。因此，他们依照原样制造了新的石磨。光是复制原来的味道，\n他们就花了整整五年的时间。所以你们可以看到，味道是非常重要和关键的。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,331,2073692323514028032),(2073692328354254865,'种无往不胜的味道。因此，他们依照原样制造了新的石磨。光是复制原来的味道，\n他们就花了整整五年的时间。所以你们可以看到，味道是非常重要和关键的。  \n \n        现在还有一家叫做国际香料香精公司的企业。这是一家产品并没有获得版权\n或者专利权、却又能够收取永久授权费的公司，据我所知仅有这一家。这是怎样\n做到的呢？他们帮助其他许多公司，为它们的各种品牌产品——比如说刮胡膏\n——添加香料和香味。刮胡膏淡淡的香味能够极大地促进消费。所以味道是极其\n重要的。  \n \n        我的朋友纳特·梅尔沃德（Nat Myhrvold）是微软的首席技术官。他是物理学\n博士，懂得许多数学知识。生物学可帮助我们生成一种能够自动以光速计算微积\n分方程的神经系统——可是他放眼四顾，到处是那些对普通的概率问题和普通的\n加减乘除束手无策的人，这使他感到困惑。 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,332,2073692323514028032),(2073692328358449152,'分方程的神经系统——可是他放眼四顾，到处是那些对普通的概率问题和普通的\n加减乘除束手无策的人，这使他感到困惑。 \n \n        顺便说一声，我认为梅尔沃德不该对此感到十分惊讶。我们的祖先经过长久\n的适者生存的进化，首先学会的是如何投掷长矛，如何逃命，如何逢凶化吉，直\n到很久很久以后，才有人需要像梅尔沃德那样的正确思维。所以我认为他没必要\n大惊小怪。然而，这两者的区别实在是太大了，所以我能明白他为何感到无法理\n解。  \n \n        人类发明了一种东西，以便弥补我们天生不擅长处理数字的缺陷，这种东西\n叫做图表。  \n \n        总之，人类发明了一种东西，以便弥补我们天生不擅长处理数字的缺陷，这\n种东西叫做图表。奇怪的是，它居然是在中世纪期间出现的。在中世纪的修道士\n发明的东西里，我认为惟一有价值的就是图表。图表以图形的方式把数字表现出','2026-07-05 16:55:53.049000',0,2073692323954429952,333,2073692323514028032),(2073692328358449153,'种东西叫做图表。奇怪的是，它居然是在中世纪期间出现的。在中世纪的修道士\n发明的东西里，我认为惟一有价值的就是图表。图表以图形的方式把数字表现出\n来。它利用了你们的神经系统来帮助你们理解它。所以价值线公司（Value Line）\n的图表是非常有用的。  \n \n        我发给你们的是一张用对数线做的图表——它是根据对数的运算法则制成\n的。你们可以用它来查复利——而复利是地球上最重要的模型之一。所以图表要\n制作成这个样子。  \n \n        如果你在这张表上画一根直线，将表上的数据点连起来，它就会告诉你能够\n得到的复利率是多少。所以这些图表是非常有用的……  \n \n        我并不使用价值线公司的预测，因为对我们来说，我们的系统比他们的管用\n——实际上，管用得多。但我无法想像如果没有他们的图表和数据会怎样。那是\n一种非常、非常棒的产品……  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,334,2073692323514028032),(2073692328358449154,'——实际上，管用得多。但我无法想像如果没有他们的图表和数据会怎样。那是\n一种非常、非常棒的产品……  \n \n        从前有个人卖的鱼肉叫卡奈森鱼肉。老天爷，他的商标就叫卡奈森，所以卡\n奈森公司想收购他的品牌。别问我为什么。每次卡奈森公司的人跑去跟那个家伙\n说：“我们愿意给你 25 万美元。”他说：“我要 40 万美元。”四年之后，他们说：\n“我们愿意给你 100 万。”他说：“我要 200 万。”他们就这样一直讨价还价。卡奈\n森公司一直没有把那商标买下来——至少我上次查看的时候他们还没有买到。  \n \n        最后，卡奈森公司的人无奈地去跟那个人说：“我们打算派遣我们的质量检\n查员到你的鱼肉厂，以便确保你生产的鱼肉都是完美的，所有的费用我们来出。”\n那人笑逐颜开，很快就点头同意了。所以他的鱼肉厂得到了免费的质量管理服务\n——卡奈森公司的款待。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,335,2073692323514028032),(2073692328358449155,'那人笑逐颜开，很快就点头同意了。所以他的鱼肉厂得到了免费的质量管理服务\n——卡奈森公司的款待。  \n \n        这段历史让我们明白，如果你给某个家伙一个（他能够保护的）商标，你就\n创造了巨大的激励机制。这种激励机制对文明社会来说是非常有用的。正如你们\n看到的，卡奈森公司为了顾惜自己的声誉，甚至不惜去保护那些并不属于它的产\n品。  \n \n        这种结果（对整个社会）非常、非常有好处。所以从非常基本的微观经济学\n原理来看，哪怕是共产主义国家，也应该保护商标。它们并没有都这么做，但有\n非常充分的理由表明它们应该对商标采取保护措施。总的来讲，世界上大多数国\n家对商标的保护还是很周全的。 \n   然而，如果缺乏这些基本模型以及可以利用这样的基本模型的思维方法，你\n们只能坐在那里，一边看着价值线公司的图表，一边不知所措。但你们原本不必','2026-07-05 16:55:53.049000',0,2073692323954429952,336,2073692323514028032),(2073692328358449156,'   然而，如果缺乏这些基本模型以及可以利用这样的基本模型的思维方法，你\n们只能坐在那里，一边看着价值线公司的图表，一边不知所措。但你们原本不必\n如此。你们应该不断学习，争取掌握近 100 种模型和一些思维技巧。那并不是很\n难的事情。  \n \n        这么做的好处在于绝大多数人不会这么做——部分原因是他们接受了错误\n的教育。在这里，我想要帮助你们避开错误的教育可能给你们造成的危害。  \n \n        好啦。在寻找普世智慧的过程中，我们已经讨论了几种主要的思想。现在我\n想回头来谈谈一种比刚才谈到的更加极端和特殊的模型。在所有人们应该掌握却\n没有掌握的模型中，最重要的也许来自于心理学……  \n \n        最近有件事让我获益匪浅：我刚从香港回来。我有个朋友在香港一所名牌中\n学当校长。他送给我这本叫作《语言本能》的书，作者是史蒂芬·平克（StevePinker）。','2026-07-05 16:55:53.049000',0,2073692323954429952,337,2073692323514028032),(2073692328358449157,'学当校长。他送给我这本叫作《语言本能》的书，作者是史蒂芬·平克（StevePinker）。\n平克是一个语义学教授，他的名气没有诺姆·乔姆斯基（Noam Chomsky）那么大。\n乔姆斯基是麻省理工学院的语言学教授，可能是世上最伟大的语义学家。  \n \n        平克说，人类的语言能力不仅仅是后天学来的——从很大程度上来说，它还\n跟先天的遗传有关。其他动物，包括黑猩猩，都缺乏真正有用的语言基因。语言\n是上天赐给人类的礼物。平克很漂亮地证明了他的观点。  \n \n        当然，乔姆斯基也已经证明这一点。只有非常愚蠢的人才不明白语言能力大\n部分来自人类基因的道理。虽然你们必须通过教育才能提高语言能力，但语言能\n力很大程度上还是由你们的基因决定的。  \n \n        平克无法理解为什么乔姆斯基这样的天才居然还认为语言能力是否基于人','2026-07-05 16:55:53.049000',0,2073692323954429952,338,2073692323514028032),(2073692328358449158,'力很大程度上还是由你们的基因决定的。  \n \n        平克无法理解为什么乔姆斯基这样的天才居然还认为语言能力是否基于人\n类的基因尚无定论。实际上，平克是这么说的：“什么尚无定论，活见鬼了！人\n类得到语言本能的途径跟得到其他本能的途径完全一样——那就是达尔文的自\n然选择。”  \n \n        人类得到语言本能的途径跟得到其他本能的途径完全一样——那就是达尔\n文的自然选择。  \n \n        嗯，这位资历较浅的教授明显是对的——乔姆斯基的犹豫确实有点不可理\n喻。  \n \n        如果这位资历较浅的教授和我都是正确的，那么，为什么乔姆斯基这样的天\n才会犯明显的错误？在我看来，答案非常清楚——乔姆斯基的意识形态太过强\n烈。他虽然是个天才，却是个极端的平等主义左翼分子。他非常聪明，知道如果\n他承认这个达尔文理论，他的左翼意识形态就会受到威胁。所以他的结论自然受','2026-07-05 16:55:53.049000',0,2073692323954429952,339,2073692323514028032),(2073692328358449159,'烈。他虽然是个天才，却是个极端的平等主义左翼分子。他非常聪明，知道如果\n他承认这个达尔文理论，他的左翼意识形态就会受到威胁。所以他的结论自然受\n到他的意识形态偏见的影响。 \n \n        从这里我们得到了普世智慧的另一个教训：如果意识形态能够让乔姆斯基变\n得糊涂，那么想像一下它会给你们和我这样的人造成什么影响。  \n \n        严重的意识形态是最能扭曲人类认知的因素之一。看看这些宗教激进分子就\n知道了，他们用枪扫射一群希腊游客，嘴里还不停地大喊：“真主的杰作！”  \n \n        意识形态会让人做出一些古怪的举动，也能严重扭曲人们的认知。如果你们\n年轻时深受意识形态影响，然后开始传播这种意识形态，那么你们无异于将你们\n的大脑禁锢在一种非常不幸的模式之中。你们的普遍认知将会受到扭曲。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,340,2073692323514028032),(2073692328358449160,'年轻时深受意识形态影响，然后开始传播这种意识形态，那么你们无异于将你们\n的大脑禁锢在一种非常不幸的模式之中。你们的普遍认知将会受到扭曲。  \n \n        如果你们年轻时深受意识形态影响，然后开始传播这种意识形态，那么你们\n无异于将你们的大脑禁锢在一种非常不幸的模式之中。  \n \n        如果把沃伦·巴菲特看做普世智慧的典范，那么有个故事非常有趣：沃伦敬爱\n他的父亲——那是一个了不起的人。但沃伦的父亲有强烈的意识形态偏见（正好\n是右翼的意识形态），所以跟他交往的都是些意识形态偏见非常严重的人（自然\n都是右翼分子）。  \n \n        沃伦在童年时就观察到这一点。他认为意识形态是危险的东西，决定离它远\n远的。他终生都离意识形态远远的。这极大地提高了他认知的准确性。  \n \n        我通过另外一种方式得到了同样的教训。我的父亲仇恨意识形态。因此，我','2026-07-05 16:55:53.049000',0,2073692323954429952,341,2073692323514028032),(2073692328358449161,'远的。他终生都离意识形态远远的。这极大地提高了他认知的准确性。  \n \n        我通过另外一种方式得到了同样的教训。我的父亲仇恨意识形态。因此，我\n只要模仿我的父亲、别离开那条我认为正确的道路就好了。像多南（注：罗伯特\n“鲍勃”·多南，曾任美国共和党国会议员，以保守言论著称）那样的右翼分子和纳\n德（注：拉尔夫·纳德，美国著名左翼民粹主义政治活动家，曾多次以绿党和独\n立候选人身份参选美国总统）那样的左翼分子显然有点头脑不清。他们是极端的\n例子，表明意识形态会让人变成什么样——尤其是那种以非常激烈的方式表达出\n来的意识形态。由于它只给人灌输一些观念，而不是让人心悦诚服地接受一些道\n理，所以信奉意识形态是很危险的。  \n \n        因此，除了要利用来自不同学科的多元思维模型之外，我还想补充的是，你\n们应该警惕严重的意识形态偏见。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,342,2073692323514028032),(2073692328358449162,' \n        因此，除了要利用来自不同学科的多元思维模型之外，我还想补充的是，你\n们应该警惕严重的意识形态偏见。  \n \n        如果你把准确、勤奋和客观当成你笃信的意识形态，那倒不要紧。但如果你\n们因为受到意识形态的影响，而确凿无疑地相信最低工资应该提高或者不该提\n高，并认为这种神圣的想法是正确的，那么你们就变成了傻子。  \n \n        这是一个非常复杂的系统。生活总是环环相扣的。如果综合考虑，你们猜想\n提高或者降低最低工资会让整个社会变得更加文明，那是没有问题的。这两种想\n法都对。但如果你们带着强烈的意识形态把自己的观点当做不可动摇的真理，那\n么我认为你们的想法是很愚蠢的。所以要警惕意识形态造成的思维紊乱。 \n  我提及平克的另外一个原因是，这位写了刚才我告诉你们的那本书的语义学\n家在那本书的结尾这么写道：“我看过许多心理学教材。都很烂。”他说：“整个','2026-07-05 16:55:53.049000',0,2073692323954429952,343,2073692323514028032),(2073692328358449163,'  我提及平克的另外一个原因是，这位写了刚才我告诉你们的那本书的语义学\n家在那本书的结尾这么写道：“我看过许多心理学教材。都很烂。”他说：“整个\n学科被搞得乱七八糟，教得也不对。”  \n \n        说到心理学，我的资格远不如平克。实际上，我从来没上过一节心理学课。\n然而，我的结论跟他的差不多——许多心理学教材虽然不乏闪光之处，但大体上\n都是垃圾。  \n \n        实际上，只要看看心理否认就够了。大约在基督出生之前三个世纪，德摩斯\n梯尼（注：古希腊伟大的演说家）就说过：“一个人想要什么，就会相信什么。”\n嗯，德摩斯梯尼是对的。  \n \n        我们家有个熟人，他深爱的儿子——非常聪明，还是个足球明星——失足坠\n海，再也没有回来。他母亲认为他仍然活着。她有时候会精神失常，表现得好像\n她儿子真的在她身边。这种心理效应的轻重程度有所不同。每个人受心理否认的','2026-07-05 16:55:53.049000',0,2073692323954429952,344,2073692323514028032),(2073692328358449164,'海，再也没有回来。他母亲认为他仍然活着。她有时候会精神失常，表现得好像\n她儿子真的在她身边。这种心理效应的轻重程度有所不同。每个人受心理否认的\n影响都不一样，但这种否认造成的错误认知则会极大地混淆你们将不得不面对的\n现实。然而，各种心理学教材对这种简单的心理否认并没有足够的重视。  \n \n        所以你们不能依照你们教授传授的方法来学习心理学。你们应该学习他们传\n授的一切。但你们还应该学习许多他们没有教的知识——因为他们并没有正确地\n对待他们自己的学科。  \n \n        在我看来，当今的心理学有点像法拉第之后、麦克斯韦之前的电磁学——发\n现了许多原理，但没有人把它们以正确的方式综合起来。早该有人来做这样的事\n情，因为这件事并不难完成——而且它还非常重要。  \n \n        随便打开一本心理学教材，翻到索引，查找“妒忌”这个词。连十诫里面都有','2026-07-05 16:55:53.049000',0,2073692323954429952,345,2073692323514028032),(2073692328358449165,'情，因为这件事并不难完成——而且它还非常重要。  \n \n        随便打开一本心理学教材，翻到索引，查找“妒忌”这个词。连十诫里面都有\n两三条谈到妒忌。摩西完全了解妒忌。古老的犹太人早在放羊的年代就了解妒忌。\n可是心理学教授对妒忌一无所知。  \n \n        那些厚厚的心理学教材居然没有谈到妒忌？！居然没有谈到简单的心理否\n认？居然没有谈到激励机制引起的偏见？！  \n \n        心理学教材也没有给予多因素组合效应足够的重视。以前我提醒过你们，当\n两三种因素产生合力时，会造成 lollapalooza 效应。  \n \n        嗯，有史以来最著名的心理学实验是米尔格拉姆（Milgram）实验——他们要\n求人们清醒地对一些无辜的人进行电刑。在他们的操控之下，这些正派的志愿者\n大多数执行了酷刑。 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,346,2073692323514028032),(2073692328358449166,'求人们清醒地对一些无辜的人进行电刑。在他们的操控之下，这些正派的志愿者\n大多数执行了酷刑。 \n \n        所以你们不能依照你们教授的教学方法来学习心理学。你们应该学习他们传\n授的一切。但你们还应该学习许多他们没有教的知识——因为他们并没有正确地\n对待他们自己的学科。  \n \n        米尔格拉姆开展这个实验，是在希特勒命令许多虔诚的路德教徒、天主教徒\n去做他们明知道不对的事情之后不久。他想要发现权威在多大程度上可以被用来\n操控品德高尚的人，迫使人们去做一些明显错得很离谱的事情。  \n \n        他得到了非常具有戏剧性的实验效果。他设法让那些品德高尚的人做了许多\n可怕的事情。  \n \n        但是许多年来，心理学教材把这个实验当做是对权威的作用的证明——权威\n如何被用来说服人们去做可怕的事情。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,347,2073692323514028032),(2073692328358449167,'可怕的事情。  \n \n        但是许多年来，心理学教材把这个实验当做是对权威的作用的证明——权威\n如何被用来说服人们去做可怕的事情。  \n \n        当然，这是个似是而非的结论。这不是一种完整和正确的解释。权威发挥了\n一定作用。然而，还有其他几种朝同一个方向发挥作用的心理因素，它们造成了\n那种 lollapalooza 效应，原因恰恰在于它们发挥了组合作用。  \n \n        在我看来，当今的心理学有点像法拉第之后、麦克斯韦之前的电磁学——发\n现了许多原理，但没有人把它们以正确的方式综合起来。早该有人来做这样的事\n情，因为这件事并不难完成——而且它还非常重要。  \n \n        人们逐渐明白了这个道理。如果翻开像斯坦福这样的学校使用的心理学教\n材，你们将会看到他们努力答对了三分之二。然而，这可是心理学领域的重要实','2026-07-05 16:55:53.049000',0,2073692323954429952,348,2073692323514028032),(2073692328358449168,' \n        人们逐渐明白了这个道理。如果翻开像斯坦福这样的学校使用的心理学教\n材，你们将会看到他们努力答对了三分之二。然而，这可是心理学领域的重要实\n验。即便在斯坦福，那里的教授都尚未能完全理解米尔格拉姆的实验结果的重要\n意义。  \n \n        聪明人怎么会犯错呢？答案是他们没有做我正要让你们去做的事情——掌\n握所有主要的心理学模型，把它们当做检查清单，用来审视各种复杂系统的结果。  \n \n        没有哪个飞行员在起飞前不核对他的检查清单：A、B、C、D……没有牌手在\n需要另外两张墩的时候不迅速地查对他的检查清单，看看有什么办法可以把它们\n弄到手。  \n \n        但这些心理学教授认为他们聪明到不需要检查清单。可他们其实没那么聪\n明。几乎没有人那么聪明。或者换句话说，可能没有人那么聪明。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,349,2073692323514028032),(2073692328358449169,'弄到手。  \n \n        但这些心理学教授认为他们聪明到不需要检查清单。可他们其实没那么聪\n明。几乎没有人那么聪明。或者换句话说，可能没有人那么聪明。 \n   没有哪个飞行员在起飞前不核对他的检查清单：A、B、C、D……但这些心理学\n教授认为他们聪明到不需要检查清单。  \n \n        如果他们使用检查清单，他们将会意识到米尔格拉姆实验利用的心理学原理\n至少有六种——而不是三种。他们必须去看检查清单，才能发现他们漏掉了什么。  \n \n        同样道理，如果缺乏这种获得各种主要模型并以组合的方式使用它们的方\n法，你们也将会一而再、再而三地失败。  \n \n        心理学教授回避心理否认问题的原因之一在于，如果要做有关心理否认的实\n验，他们肯定会违反道德规范。要证明痛苦如何导致人类精神失常，你们想想看，','2026-07-05 16:55:53.049000',0,2073692323954429952,350,2073692323514028032),(2073692328358449170,' \n        心理学教授回避心理否认问题的原因之一在于，如果要做有关心理否认的实\n验，他们肯定会违反道德规范。要证明痛苦如何导致人类精神失常，你们想想看，\n这种实验必须对你们的同类做些什么，而且你们还不能告诉他们将会受到什么伤\n害。所以很明显，道德规范导致这种实验行不通，尽管做实验是展示痛苦如何导\n致人类头脑失常的最佳方法。  \n \n        大多数教授用一个假定来解决这个问题：“如果我不能用实验来证明它，它\n就是不存在的。”然而，他们的假定明显是愚蠢的。如果有些东西非常重要，但\n由于道德约束，你们无法完美而准确地证明它，那么你们也不应该把它当做是不\n存在的。你们必须尽力而为，利用现有的证据去证明它。  \n \n        巴甫洛夫本人在他生命的最后十年里一直在做对狗的酷刑实验。他发表了论\n文。因而，我们拥有了翔实的资料，知道痛苦如何导致狗的精神失常。然而，你','2026-07-05 16:55:53.049000',0,2073692323954429952,351,2073692323514028032),(2073692328358449171,' \n        巴甫洛夫本人在他生命的最后十年里一直在做对狗的酷刑实验。他发表了论\n文。因而，我们拥有了翔实的资料，知道痛苦如何导致狗的精神失常。然而，你\n在任何心理学教材中都看不到巴甫洛夫这次研究的成果。  \n \n        我不知道这是因为他们不喜欢巴甫洛夫折磨狗，还是由于 B. F. 斯金纳（B. \nF.Skinner）因为过度渲染而使用动物行为来推断人类行为的方法不受欢迎。总之，\n由于某些疯狂的原因，心理学教材对痛苦引起的精神失常着墨甚少。  \n \n        你们可能会说：“心理学是否忽视这个有关系吗？”如果我的理论没有错，这\n种忽视抹杀了几个你们需要的模型。此外，你们对思想模型的掌握应该是这样的，\n如果有 20 个，那么你们就应该掌握 20 个。换句话说，你们不应该只用 10 个。\n你们要把它们当做一张检查清单。所以你们必须了解各种导致人类作出错误判断','2026-07-05 16:55:53.049000',0,2073692323954429952,352,2073692323514028032),(2073692328362643456,'如果有 20 个，那么你们就应该掌握 20 个。换句话说，你们不应该只用 10 个。\n你们要把它们当做一张检查清单。所以你们必须了解各种导致人类作出错误判断\n的心理因素，把所有模型组织起来，以便需要的时候能够用得上。  \n \n        如果有四五种来自这些模型的因素共同发挥作用，那么你们就更需要它们\n了。在这种情况中，你们通常会遇到各种 lollapalooza 效应——它们要么让你发\n大财，要么会毁了你。所以你们非常有必要注意 lollapalooza 效应。  \n \n        要做到这一点，办法只有一个：你们必须全面掌握各种主要模型，把它们当\n做一张检查清单。再强调一下，你们必须注意那些能够产生 lollapalooza 后果的\n多因素组合效应。 \n你们还可以学到，当你们在玩说服游戏的时候——（我希望）不是叫人去干坏','2026-07-05 16:55:53.049000',0,2073692323954429952,353,2073692323514028032),(2073692328362643457,'多因素组合效应。 \n你们还可以学到，当你们在玩说服游戏的时候——（我希望）不是叫人去干坏\n事——如何将这些因素综合起来，以便让你们更好地达到目的。  \n \n        让我来给你们举个例子，看看古人是怎样巧妙地利用心理学的。库克（James \nCook）船长生前经常进行远航。在那个年代，远洋航行途中最怕遇到坏血病。要\n是得了坏血病，你们的牙龈会在嘴巴里烂掉——然后这种病就会变得让你们极不\n舒服，致你们于死命。  \n \n        和一群垂死的水手共处在一艘原始的航船上是非常不妙的事情。所以每个人\n都非常想 知道怎样才能治好坏血病，但他们并不了解维生素 C。库克船长很聪\n明，也掌握了类似跨学科的方法。他发现同样是进行了远航，荷兰船上的坏血病\n就没有英国船上那么严重。所以他问：“荷兰人是怎么做到的呢？”  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,354,2073692323514028032),(2073692328362643458,'明，也掌握了类似跨学科的方法。他发现同样是进行了远航，荷兰船上的坏血病\n就没有英国船上那么严重。所以他问：“荷兰人是怎么做到的呢？”  \n \n        他发现荷兰船只上有许多装满酸泡菜的木桶。所以他想：“我就要远航了，\n远航是非常危险的，酸泡菜也许会有用。”所以他把大量的酸泡菜搬到船上，而\n酸泡菜正好含有维生素 C。  \n \n        但在当年，英国水手是十分粗鲁、古怪和危险的，他们讨厌“泡菜”，他们吃\n惯了英国的食物和饮料。所以你们要怎样才能让英国水手吃泡菜呢？  \n \n        库克并不想告诉他们，吃酸泡菜是为了防治坏血病——因为如果他们知道这\n是一次远航，而且非常有可能染上坏血病，他们可能会起来造反，控制那艘船。  \n \n        他是这么做的：所有官员聚集起来，并让普通水手都能看到他们。他让那些','2026-07-05 16:55:53.049000',0,2073692323954429952,355,2073692323514028032),(2073692328362643459,' \n        他是这么做的：所有官员聚集起来，并让普通水手都能看到他们。他让那些\n官员吃酸泡菜，但不让普通水手吃。经过很长一段时间之后，库克最终说：“嗯，\n普通水手每周有一天可以吃酸泡菜。”  \n \n        他如愿以偿地让船上所有人都吃上了酸泡菜。我认为这是基本心理学的一次\n非常有建设性的应用。它拯救了许多人的生命，取得了惊人的成就。然而，如果\n你们不掌握那些正确的技巧，你们就无法适当地运用它们。  \n \n        普世智慧大体上非常、非常简单。如果你们有决心去做，我在这里要求你们\n做的事情其实并没有那么难，而回报是非常高的——绝对非常高。  \n \n        但你们可能对很高的回报不感兴趣，对避免许多悲惨遭遇不感兴趣，对过上\n更好的生活也不感兴趣，如果你们的态度是这样的，那么请别听我的建议——因\n为你们已经走在正确的道路上啦。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,356,2073692323514028032),(2073692328362643460,'更好的生活也不感兴趣，如果你们的态度是这样的，那么请别听我的建议——因\n为你们已经走在正确的道路上啦。 \n道德和涉及心理学的普世智慧考量的关系之密切，是再怎么强调也不为过的。\n以偷窃为例。如果（A）偷窃非常容易，而且（B）被抓住了也不用受惩罚，那\n么世界上有许多人将会变成小偷。  \n \n        一旦他们开始偷窃，一贯性原则——这也是心理学的重要内容——将会很快\n和有利偷窃的环境结合起来，促使他们养成偷窃的习惯。所以如果你们经营一家\n公司，由于你们的管理不善，导致人们可以轻而易举地盗窃公司的财产，那么你\n们就给那些替你们工作的人造成了极大的道德伤害。  \n \n        道德和涉及心理学的普世智慧考量的关系之密切，是再怎么强调也不为过\n的。  \n \n        这个道理也很明显。创建一套严密防止欺诈的管理系统是非常、非常重要的。','2026-07-05 16:55:53.049000',0,2073692323954429952,357,2073692323514028032),(2073692328362643461,'的。  \n \n        这个道理也很明显。创建一套严密防止欺诈的管理系统是非常、非常重要的。\n不然的话，你们就会亲手毁掉你们的公司，因为人们既然能够不受惩罚地偷窃，\n就会拥有一种激励机制引起的偏见，认为糟糕的行为是没有问题的。  \n \n        那么，如果别人那么做了，你就知道至少有两种心理学原则产生了作用：激\n励机制引起的偏见和社会认同。不仅如此，发挥作用的还有谢皮科效应：假如总\n体的社会风气很坏，许多人因此而获得利益，你们要是想对此吹响警笛，他们就\n会反对你们，变成危险的敌人。  \n \n        漠视这些原则、容许作恶是非常危险的。强大的心理力量会造成很多恶果。  \n \n        这跟司法行业有什么关系呢？许多人从斯坦福法学院这样的地方毕业，进入\n我们国家的司法机构，带着最好的愿望和动机，然后制定一些让人有漏洞可钻的\n法律。没有什么比这更加糟糕的事情了。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,358,2073692323514028032),(2073692328362643462,'我们国家的司法机构，带着最好的愿望和动机，然后制定一些让人有漏洞可钻的\n法律。没有什么比这更加糟糕的事情了。  \n \n        比如说，你们有为公众服务的愿望。你们应该反过来想：“我要怎样才能对\n文明社会造成破坏呢？”那是很容易的。如果你们想要破坏这个文明社会，只要\n到司法机关供职，然后通过一些有很多漏洞的法律就可以啦。这种方法将会非常\n有效。  \n \n        以加利福尼亚州的工伤赔偿制度为例。工伤是有的，因工受伤确实很惨，所\n以你们想要为那些在工作场所受伤的人提供赔偿。这看起来是一件高尚的事情。  \n \n        但这种赔偿制度的问题在于，它根本不可能防止诈骗。而你们一旦开始赔偿\n那些弄虚作假的人，就会有许多狡猾的律师、狡猾的医生、狡猾的工会等参与到\n诈伤骗保中来。你们将会引发大量灾难性的行为，尝到甜头的人将会变本加厉。','2026-07-05 16:55:53.049000',0,2073692323954429952,359,2073692323514028032),(2073692328362643463,'那些弄虚作假的人，就会有许多狡猾的律师、狡猾的医生、狡猾的工会等参与到\n诈伤骗保中来。你们将会引发大量灾难性的行为，尝到甜头的人将会变本加厉。\n所以你们的本意是帮助你们的文明社会，但结果却是给它造成了巨大的损失。 \n所以与其创立一种有漏洞的制度，还不如就不要赔偿了——就让生活艰辛一些。  \n \n        让我来给你们举个例子：我有个朋友，他在得克萨斯州离边境线不远的地方\n有一座制造工业产品的工厂。他的工厂利润微薄，度日艰难。他遇到了许多诈伤\n骗保的事情——每年支付的赔偿金达到了总薪酬支出的一成多。而在他的厂里工\n作根本就没什么危险。他从事的不是拆迁之类的危险行业。  \n \n        所以他哀求工会：“你们不能再这么做了。这种产品赚的利润还没你们骗到\n手的钱多。”  \n \n        但那时每个人都习惯了那么做。“那是额外的收入，那是额外的钱，每个人','2026-07-05 16:55:53.049000',0,2073692323954429952,360,2073692323514028032),(2073692328362643464,'手的钱多。”  \n \n        但那时每个人都习惯了那么做。“那是额外的收入，那是额外的钱，每个人\n都这么做。这不可能是错误的。杰出的律师、杰出的医生、杰出的脊椎按摩师——\n假如有这种东西的话——都在诈骗。”  \n \n        没有人能够告诉他们，说：“你们不能再这么做了。”这恰好也跟心理学上的\n巴甫洛夫联想有关。当人们听到坏消息，他们会讨厌带来消息的人。因此，工会\n代表很难告诉所有人这种容易到手的钱再也没有了。工会代表是不会那么做的。  \n \n        所以我的朋友关闭了工厂，在犹他州一个信仰摩门教的社区重振旗鼓。  \n \n        所以我的朋友关闭了工厂，在犹他州一个信仰摩门教的社区重振旗鼓。摩门\n教徒不会诈伤骗保——至少他们在我朋友的工厂没有那么做。你们猜猜看，他现\n在的工伤赔偿支出是多少？只有总薪酬支出的 2%（从一成多下降到 2%）。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,361,2073692323514028032),(2073692328362643465,'教徒不会诈伤骗保——至少他们在我朋友的工厂没有那么做。你们猜猜看，他现\n在的工伤赔偿支出是多少？只有总薪酬支出的 2%（从一成多下降到 2%）。  \n \n        这种悲剧是由容许作恶的态度引起的。你们必须及早制止作恶。如果你们不\n及时采取行动，那么制止人们继续作恶和道德败坏是很难的。  \n \n        当然，正如我从前说过的，在使用那些装备了基本的心理学力量的技巧之前，\n有一点需要引起特别的关注：当你们知道该怎么做之后，你们必须依据道德规范\n来调整自己的行为。并不是你们懂得如何操控人们之后，就可以随心所欲地去操\n控他们。  \n \n        如果你们跨过了道德的界线，而你们试图操控的那个人因为也懂得心理学，\n所以明白你们的用意，那么他就会恨你们。劳资关系中就有这种效应的铁证——\n有一些发生在以色列。所以这么做不仅会遭到良心的谴责，还会引发行动的抗议','2026-07-05 16:55:53.049000',0,2073692323954429952,362,2073692323514028032),(2073692328362643466,'所以明白你们的用意，那么他就会恨你们。劳资关系中就有这种效应的铁证——\n有一些发生在以色列。所以这么做不仅会遭到良心的谴责，还会引发行动的抗议\n——有时候是非常严重的抗议…… \n   正如我在南加大说过的，投资之所以困难，是因为人们很容易看出来有些公\n司的业务比其他公司要好。但它们股票的价格升得太高了，所以突然之间，到底\n应该购买哪只股票这个问题变得很难回答。  \n \n        问：你如何在投资决策中应用心理学？我认为投资决策肯定没有那么简单，\n只要挑选每个人都看好的产品——比如可口可乐的股票——就行。毕竟投资界的\n聪明人很多，他们的思维方法明显跟你今天告诉我们的一样。当你在挑选成功企\n业的时候，你有考虑其他投资者在其投资思维中的失败吗？  \n \n        正如我在南加大说过的，投资之所以困难，是因为人们很容易看出来有些公','2026-07-05 16:55:53.049000',0,2073692323954429952,363,2073692323514028032),(2073692328362643467,'业的时候，你有考虑其他投资者在其投资思维中的失败吗？  \n \n        正如我在南加大说过的，投资之所以困难，是因为人们很容易看出来有些公\n司的业务比其他公司要好。但它们股票的价格升得太高了，所以突然之间，到底\n应该购买哪只股票这个问题变得很难回答。  \n \n        我们从来没有解决这个难题。在 98%的时间里，我们对待股市的态度是……\n保持不可知状态。我们不知道。通用汽车的股价跟福特比会怎样？我们不知道。  \n \n        我们总是寻找某些我们看准了的、觉得有利可图的东西。我们看准的依据有\n时候来自心理学，更多时候来自其他学科。并且我们看准的次数很少——每年可\n能只有一两次。我们并没有一套万试万灵、可以用来判断所有投资决策的方法。\n我们使用的是一种与此完全不同的方法。  \n \n        我们只是寻找那些不用动脑筋也知道能赚钱的机会。正如巴菲特和我经常说','2026-07-05 16:55:53.049000',0,2073692323954429952,364,2073692323514028032),(2073692328362643468,'我们使用的是一种与此完全不同的方法。  \n \n        我们只是寻找那些不用动脑筋也知道能赚钱的机会。正如巴菲特和我经常说\n的，我们跨不过七英尺高的栏。我们寻找的是那些一英尺高的、对面有丰厚回报\n的栏。所以我们成功的诀窍是去做一些简单的事情，而不是去解决难题。  \n \n        问：你们的投资决策靠的是统计分析和眼光吗？  \n \n        当我们作出一项决策的时候，我们当然认为我们的眼光不错。有时候我们确\n实是因为统计分析才看好某个投资项目。不过，再说一遍，我们只发现了几个这\n样的机会。  \n \n        我们只是寻找那些不用动脑筋也知道能赚钱的机会。正如巴菲特和我经常说\n的，我们跨不过七英尺高的栏。。  \n \n        光有好机会是不够的，它们必须处在我们能看明白的领域，所以得在我们能\n看明白的领域出现定错价的机会。这种机会不会经常出现。 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,365,2073692323514028032),(2073692328362643469,' \n        光有好机会是不够的，它们必须处在我们能看明白的领域，所以得在我们能\n看明白的领域出现定错价的机会。这种机会不会经常出现。 \n \n        但它不需要经常出现，如果你们等待好机会，并有勇气和力量在它出现的时\n候好好把握，你们需要多少个呢？以伯克希尔·哈撒韦最成功的 10 个投资项目为\n例。我们就算不投资其他项目，也会非常富裕——那些钱两辈子都花不完。  \n \n        所以，再说一次，我们并没有一套万试万灵、可以用来判断所有投资决策的\n方法。如果有，那就荒唐了。我只是给你们一种用来审视现实、以便获取少数可\n以作出理性反应的机会的方法而已。  \n \n        如果你们用这种方法去从事竞争很激烈的活动，比如说挑选股票，那么你们\n将会遇到许多出色的竞争对手。所以我们即使拥有这种方法，得到的机会也很少。\n幸运的是，那么少的机会也足够了。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,366,2073692323514028032),(2073692328362643470,'将会遇到许多出色的竞争对手。所以我们即使拥有这种方法，得到的机会也很少。\n幸运的是，那么少的机会也足够了。  \n \n        问：你是否成功地创造出一种氛围，让你的手下也能够做你说你自己一直在\n做的事情？例如，你刚才说到人类心理有追求一贯性的倾向……  \n \n        我主要是说这种倾向会让人犯一些糟糕的错误。  \n \n        问：你如何创造出一种轻松的氛围，（足够）让人们放弃那种倾向，并承认\n他们犯下错误呢？  \n \n        例如，今年早些时候，英特尔的某个人谈起了他们的奔腾芯片遇到的问题。\n他们遇到的最大困难之一是意识到他们做错了，于是从头再来。在一个复杂的企\n业里面，这么做是很困难的。请问你是怎么做的呢？  \n \n        英特尔及其同行创造了一种协调的企业文化，便于各个团队解决前沿的科学','2026-07-05 16:55:53.049000',0,2073692323954429952,367,2073692323514028032),(2073692328362643471,'业里面，这么做是很困难的。请问你是怎么做的呢？  \n \n        英特尔及其同行创造了一种协调的企业文化，便于各个团队解决前沿的科学\n问题。那跟伯克希尔·哈撒韦有很大的不同。伯克希尔是一家控股公司。我们的\n权力很分散，只有最重要的资本配置才由公司的高层来拍板。  \n \n        基本上，我们会选择那些我们非常钦佩的人来管理我们的附属公司。一般来\n说，我们跟他们很容易相处，因为我们喜爱和钦佩他们。他们的企业中应该有什\n么样的企业文化，都由他们自行决定，我们并不会干预。他们总是能够积极进取，\n及时更正以往的错误。  \n \n        但我们是一家完全不同的公司。我完全不清楚沃伦或者我是否擅长安迪·格鲁\n夫的老本行，我们在那个领域毫无竞争力。我们相当善于团结我们敬爱的杰出人\n士，但我们也有缺点。例如，有人觉得我总是心不在焉，而且很顽固。要是在英\n特尔，我可能会干得一团糟。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,368,2073692323514028032),(2073692328362643472,'士，但我们也有缺点。例如，有人觉得我总是心不在焉，而且很顽固。要是在英\n特尔，我可能会干得一团糟。  \n \n        然而，沃伦和我都非常善于改变我们先前的论断。我们致力于提高这种本事，\n因为，如果没有它的话，灾难就常常找上门来。 \n    问：你似乎对投资高科技公司不那么感冒，你本人和伯克希尔·哈撒韦都是如\n此，你能稍微谈谈为什么吗？我发现有件事情让我很吃惊，那就是经营一家低科\n技企业的难度和经营一家高科技企业的难度竟然是差不多的。  \n \n        这两种都很难。但要发财哪有那么容易呢？这个世界竞争这么激烈，难道每\n个人都不可能轻易发财有什么不对吗？这两种公司当然都很难经营。  \n \n        是的——低科技企业可能会难很多。不信你们去开一家餐厅，看看能否取得\n成功。  \n \n        问：你似乎认为高科技行业更难经营——因为你说经营高科技企业需要特殊','2026-07-05 16:55:53.049000',0,2073692323954429952,369,2073692323514028032),(2073692328362643473,'成功。  \n \n        问：你似乎认为高科技行业更难经营——因为你说经营高科技企业需要特殊\n才能。但它们难道不是一样的吗？  \n \n        对我们来说，低科技企业的优势在于，我们认为我们对它的理解很充分。对\n高科技企业则不是这样的。我们宁愿与我们熟悉的企业打交道。  \n \n        我们怎么会放弃一种我们有很大优势的游戏，而去玩一种竞争激烈而我们又\n毫无优势，甚至可能处于劣势地位的游戏呢？  \n \n        你们每个人都必须搞清楚你们有哪方面的才能。你们必须发挥自己的优势。\n但如果你们想在较不擅长的领域取得成功，那你们的生活可能会过得一团糟。这\n一点我可以保证。如果不是这样的话，那你们肯定是中了彩票或者遇到其他非常\n走运的事情。  \n \n        问：沃伦·巴菲特说伯克希尔对一家航空公司的投资是一次典型的失败。你们\n怎么会作出那个错误的决定呢？  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,370,2073692323514028032),(2073692328366837760,'走运的事情。  \n \n        问：沃伦·巴菲特说伯克希尔对一家航空公司的投资是一次典型的失败。你们\n怎么会作出那个错误的决定呢？  \n \n        基于普通股东的人数必然会膨胀，我们没有购买美国航空（USAir）的股票——\n因为在照顾普通股东的权益方面，航空业的历史很糟糕。我们购买的是有强制性\n赎回权的优先股。实际上，我们当时借钱给美国航空，所以得到了这种债转股选\n择权。  \n \n        我们并没有猜想它对股东来说是不是个好地方。我们只是猜想它能不能够保\n持兴隆，从而有足够的财力偿还贷款——除了强制赎回权之外，还有固定的分红。\n我们预计这家公司不会变得那么糟糕，不至于我们得承受我们所得到的高利率也\n不够补偿的风险。但结果是，美国航空公司很快就处于破产边缘，它挣扎了几个\n月，后来又恢复了正常，将来我们也许能够收回全部本金和利息。但它是一个错','2026-07-05 16:55:53.049000',0,2073692323954429952,371,2073692323514028032),(2073692328366837761,'不够补偿的风险。但结果是，美国航空公司很快就处于破产边缘，它挣扎了几个\n月，后来又恢复了正常，将来我们也许能够收回全部本金和利息。但它是一个错\n误。（编者注：伯克希尔后来确实全部收回了它对美国航空的全部投资。） \n \n        在照顾普通股东的权益方面，航空业的历史很糟糕。  \n \n        我可不希望你们误以为我们拥有任何可以使你们不犯很多错误的学习或行\n事方式。我只是说你们可以通过学习，比其他人少犯一些错误——也能够在犯了\n错误之后，更快地纠正错误。但既要过上富足的生活又不犯很多错误是不可能的。  \n \n        实际上，生活之所以如此，是为了让你们能够处理错误。那些破产的人的通\n病是无法正确地处理心理否认。你们对某样东西投入了巨大的精力，对它倾注了\n心血和金钱。你们投入的越多，一贯性原理就越会促使你们想：“现在它必须成\n功。如果我再投入一点，它就会成功。”  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,372,2073692323514028032),(2073692328366837762,'心血和金钱。你们投入的越多，一贯性原理就越会促使你们想：“现在它必须成\n功。如果我再投入一点，它就会成功。”  \n \n        如何对付错误和那些改变赢面的新情况，也是你们必须掌握的知识之一。生\n活有时候就像扑克游戏，有时候你们即使拿到一把非常喜欢的牌，但也必须学会\n放弃。  \n \n        这时候，“剥夺性超级反映综合症”也会出现：如果不再投入一点，你们就要\n前功尽弃啦。人们就是这样破产的——因为他们不懂停下来反思，然后说：“我\n可以放弃这个，从头再来。我不会执迷不悟下去——那样的话我会破产的。”  \n \n        问：迪斯尼收购大都会美国广播公司（Capital Cities）的时候，你们并没有套\n现，而是把大都会的股票换成了迪斯尼的股票，能谈谈你是怎么考虑的吗？媒体\n上有报道说你曾经考虑收取现金。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,373,2073692323514028032),(2073692328366837763,'现，而是把大都会的股票换成了迪斯尼的股票，能谈谈你是怎么考虑的吗？媒体\n上有报道说你曾经考虑收取现金。  \n \n        迪斯尼是个非常棒的公司，但它的股票价格也太高了。它有部分业务是拍摄\n普通电影——这种生意对我毫无吸引力。然而，迪斯尼有些业务比一个大金矿更\n好。我的孙儿孙女们——我是说，那些录像带……  \n \n        迪斯尼是自我催化的完美典范……他们拍摄了许多电影。他们拥有版权。电\n冰箱的出现极大地促进了可口可乐的发展，同样道理，当录像带被发明出来之后，\n迪斯尼不需要发明任何新东西，它只要把摄制好的电影灌录成录像带就够了。每\n个父母和祖父母都希望自己的后代坐在家里看这些录像带。  \n \n        迪斯尼是自我催化的完美典范……他们拍摄了许多电影。他们拥有版权。电\n冰箱的出现极大地促进了可口可乐的发展，同样道理，当录像带被发明出来之后，','2026-07-05 16:55:53.049000',0,2073692323954429952,374,2073692323514028032),(2073692328366837764,' \n        迪斯尼是自我催化的完美典范……他们拍摄了许多电影。他们拥有版权。电\n冰箱的出现极大地促进了可口可乐的发展，同样道理，当录像带被发明出来之后，\n迪斯尼不需要发明任何新东西，它只要把摄制好的电影灌录成录像带就够了。每\n个父母和祖父母都希望自己的后代坐在家里看这些录像带。所以普通人的家庭生\n活对迪斯尼的发展起到了推波助澜的作用。这里面的市场高达数千亿美元。  \n \n        很明显，如果你们能够找得到，这是个非常好的模型。你们不用发明什么东\n西。你们只要稳坐不动，世界就会抬着你前进…… \n  迪斯尼后来作了许多正确的决定。别误会我的意思。但迪斯尼的成功，确实\n很像我有个朋友在评论他一位无知却又获得成功的学友时说的话：“他是一只坐\n在池塘里的鸭子。人们抬高了池塘的水位。”  \n \n        艾斯纳和威尔斯对迪斯尼的管理是很出色的。但当他们上任的时候，那些老','2026-07-05 16:55:53.049000',0,2073692323954429952,375,2073692323514028032),(2073692328366837765,'在池塘里的鸭子。人们抬高了池塘的水位。”  \n \n        艾斯纳和威尔斯对迪斯尼的管理是很出色的。但当他们上任的时候，那些老\n电影的录像带对迪斯尼的推动作用已经出现了，所以他们能够轻而易举地对管理\n进行革新。  \n \n        平心而论，他们也很出色，创造了不少风靡市场的新产品，比如说《风中奇\n缘》和《狮子王》。到最后，光是《狮子王》就能带来几十亿美元的收益。我说\n的“最后”，是指差不多 50 年以后。时间是有点长，但光靠一部电影就能赚几十\n亿美元。  \n \n        问：你能谈谈你为什么离开律师业吗？  \n \n        我家里人很多。南希和我养了八个孩子……我当时也没想到当律师会突然变\n得那么好赚。我离开之后，律师业就开始赚大钱了。到了 1962 年，我差不多不\n干了，而完全不干是在 1965 年。所以那是很久之前的事情了。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,376,2073692323514028032),(2073692328366837766,'得那么好赚。我离开之后，律师业就开始赚大钱了。到了 1962 年，我差不多不\n干了，而完全不干是在 1965 年。所以那是很久之前的事情了。  \n \n        另外，我比较喜欢独立自主，用自己的钱去（投资）赌博。我常常想，反正\n我了解的比客户还要多，我干嘛要替他办事呢？所以部分原因是我比较自大，部\n分原因是我想要能够让我独立自主的资源。  \n \n        还有就是，我的客户大多数都很好，但有一两个我不是很喜欢。此外我还喜\n欢资本家的独立性。我的性格向来有好赌的一面。我喜欢算清楚事情，喜欢下赌\n注。所以我就顺其自然了。  \n \n        问：你会去拉斯维加斯赌钱吗？  \n \n        我从现在到离世都不会去赌场赌 100 美元。我不会那么做。我怎么会去赌场\n呢？我偶尔会跟朋友娱乐性地小赌一把，偶尔会跟一个比我高明得多的对手玩桥','2026-07-05 16:55:53.049000',0,2073692323954429952,377,2073692323514028032),(2073692328366837767,'        我从现在到离世都不会去赌场赌 100 美元。我不会那么做。我怎么会去赌场\n呢？我偶尔会跟朋友娱乐性地小赌一把，偶尔会跟一个比我高明得多的对手玩桥\n牌，比如说鲍勃·哈曼（注：鲍勃·哈曼，1938-，美国桥牌手，被认为是世界上最\n伟大的桥牌手之一，曾获得 12 次世界冠军，50 次北美冠军），他可能是世界上\n打牌打得最好的人。但我知道我跟他是打着玩的。那是娱乐活动。  \n \n        至于那种简单机械的赌场拥有永久优势的赌博，我怎么可能去玩——我特别\n讨厌合法赌场那种操纵（大众心理）的文化。所以我不喜欢将赌博合法化。 \n  我也不喜欢拉斯维加斯，即使它现在设有很多适合全家大小一起玩的娱乐项\n目。我不喜欢跟很多在牌桌上混的人在一起。  \n \n        另外一方面，坦白讲，我确实喜欢能体现男子气概的打赌艺术。我喜欢跟朋','2026-07-05 16:55:53.049000',0,2073692323954429952,378,2073692323514028032),(2073692328366837768,'目。我不喜欢跟很多在牌桌上混的人在一起。  \n \n        另外一方面，坦白讲，我确实喜欢能体现男子气概的打赌艺术。我喜欢跟朋\n友们社交性小赌一下。但我不喜欢那种专业的赌博环境。  \n \n        问：你能说说自从你入行以来，共同基金和资金管理行业发生了什么变化\n吗？还有资本市场的增长。  \n \n        实际上，我并没有真正地入行。我曾开过一家小小的私人合伙公司，经营了\n14 年，二十几年前关掉了。然而，按照现在投资管理业的标准，我从投资者那\n里得到的费用还远远不够格。所以我确实不曾进入共同基金这个行业。  \n \n        但资金管理业是美国近年来增长最快的行业之一。它创造了许多富裕的专业\n人士和许多亿万富翁。对于那些入行早的人来说，它是个大金矿。养老基金、美\n国公司市值和全世界财富的增长为许多人创造了一个利润丰厚的行业，并让其中\n许多人发了大财。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,379,2073692323514028032),(2073692328366837769,'国公司市值和全世界财富的增长为许多人创造了一个利润丰厚的行业，并让其中\n许多人发了大财。  \n \n        我们跟这些人有各种往来。不过，我们很多年没有涉足这个行业了。在很长\n很长的时间里，我们基本上只用自己的钱来做投资。  \n \n        问：你认为这次牛市将会持续下去吗？  \n \n        如果 25 年后，所有美国公司的市值没有比现在高很多，那我会非常吃惊。\n如果人们继续相互交易，将这些小纸片炒来炒去，那么货币管理业仍将会是一个\n热门行业。但除了用可以说是我们自己的钱来投资之外，我们真的不在这个行业\n里。  \n \n        问：我对你们投资策略的转变很感兴趣，你们开始采用的是本杰明·格拉汉姆\n的模型，现在是伯克希尔·哈撒韦模型。你认为刚入门的投资者应该采用哪种模\n型呢？比如说把大部分或者全部资金投在一个我们认为很好的机会，然后几十年','2026-07-05 16:55:53.049000',0,2073692323954429952,380,2073692323514028032),(2073692328366837770,'的模型，现在是伯克希尔·哈撒韦模型。你认为刚入门的投资者应该采用哪种模\n型呢？比如说把大部分或者全部资金投在一个我们认为很好的机会，然后几十年\n都不去动它？或者这种策略只适合一个更为成熟的投资者？  \n \n        每个人都必须根据他自己的资金状况和心理素质来玩这个游戏。如果亏损会\n让你变得很惨——有些亏损是不可避免的，你最好采用一种非常保守的投资模\n式，多存点钱。所以你必须根据自己的实际状况和才能来调整投资策略。我并不\n认为我能给你一种万金油式的投资策略。  \n \n        我的策略对我来说是有效的，但这部分是因为我善于接受亏损。我的心理承\n受得了亏损。此外，我亏的次数并不多。这两种因素加起来，使得我的策略很有\n效。 \n  问：你和巴菲特都说伯克希尔的股价太高了，你不推荐人们买它。  \n \n        我们没有这么说（倒有这么认为过）。我们只是说，当时价格那么高，我们','2026-07-05 16:55:53.049000',0,2073692323954429952,381,2073692323514028032),(2073692328366837771,'  问：你和巴菲特都说伯克希尔的股价太高了，你不推荐人们买它。  \n \n        我们没有这么说（倒有这么认为过）。我们只是说，当时价格那么高，我们\n不会买，也不会推荐朋友去买。但这只跟伯克希尔在当时的内在价值有关。  \n \n        问：如果我有钱，我会买它的——因为你们说过你们的高回报率可以继续保\n持 20 年……  \n \n        但愿你的乐观是对的。但我不会改变我的观点。毕竟，我们今天遇到的情况\n是前所未有的。有时我会跟朋友说：“我正在尽最大努力啦。可是，我以前又没\n经历过老年生活。我这是第一次过呢。我不知道是否能过得好。”  \n \n        有时我会跟朋友说：“我正在尽最大努力啦。可是，我以前又没经历过老年\n生活。我这是第一次过呢。我不知道是否能过得好。”  \n \n        沃伦和我从来没有遇到过这种情况——估值非常高，资本数额非常惊人。我','2026-07-05 16:55:53.049000',0,2073692323954429952,382,2073692323514028032),(2073692328366837772,'生活。我这是第一次过呢。我不知道是否能过得好。”  \n \n        沃伦和我从来没有遇到过这种情况——估值非常高，资本数额非常惊人。我\n们从来没有遇到过，所以我们正在学习。  \n \n        问：你和巴菲特说的每句话似乎都很有道理，但听起来跟本杰明·格拉汉姆\n30 年前说过的话差不多，他说股市的价值被高估了——当时道指只有 900 点。  \n \n        世界的财富不可能以这种速度增长。  \n \n        哦，我并不认为我们的看法跟他是一样的。格拉汉姆虽然很了不起，但是他\n特别喜欢预测整体市场的走势。与之相反，沃伦和我总是认为市场是不可知的。  \n \n        从另外一方面来说，许多年来，扣除通货膨胀因素之后，大部分股票的年均\n回报率达到了 10%到 11%，我们说过这些回报率不可能持续一段非常长的时期。','2026-07-05 16:55:53.049000',0,2073692323954429952,383,2073692323514028032),(2073692328366837773,'回报率达到了 10%到 11%，我们说过这些回报率不可能持续一段非常长的时期。\n它们做不到。那完全是不可能的。世界的财富不可能以这种速度增长。不管斯坦\n福大学持有的证券组合过去 15 年来取得了什么样的业绩，未来的收益肯定会比\n过去的糟糕。也许会还可以。但过去 15 年是投资者的快乐时光，如此惊人的富\n矿效应（Bonanza Effects）不可能永远持续下去。 \n \n        问：伯克希尔的年报引起了媒体的广泛关注，因为它表达的悲观看法认为，\n公司的规模越来越大，导致投资机会越来越少。这种情况对你们未来 10 年有什\n么影响？  \n \n        我们反复地说过，跟过去相比，未来股东财富的复合增长率将会下降——我\n们的规模将会拖业绩的后腿。我们反复地说过这不是一种观点，而是一种承诺。  \n \n        然而，不妨假定从现在开始，我们能够让账面价值以每年 15%的比例复合增','2026-07-05 16:55:53.049000',0,2073692323954429952,384,2073692323514028032),(2073692328366837774,' \n        然而，不妨假定从现在开始，我们能够让账面价值以每年 15%的比例复合增\n长。这个回报率不算太糟糕，对于长期持有我们的股票的股东来说，应该是可以\n接受的。我只是说我们能够承受增长放慢，因为我们的收益肯定会降下来，但对\n长期股东来讲仍是不错的。  \n \n        顺便说一句，我并没有承诺我们的账面价值每年会有 15%的复合增长率。  \n \n        问：你刚才说避免拥有极端的意识形态是很重要的。你认为商界和法律界有\n责任帮助城市的贫民，让他们走上致富的道路吗？  \n \n        我完全赞成解决社会问题。我完全赞成对穷人解囊相助。  \n \n        我完全赞成解决社会问题。我完全赞成对穷人解囊相助。我完全赞成在经过\n深思熟虑之后，去做一些你认为利多于弊的事情。  \n \n        我反对的是非常自信、非常有把握地认为你的干预必定是利多于弊，因为你','2026-07-05 16:55:53.049000',0,2073692323954429952,385,2073692323514028032),(2073692328366837775,'深思熟虑之后，去做一些你认为利多于弊的事情。  \n \n        我反对的是非常自信、非常有把握地认为你的干预必定是利多于弊，因为你\n要对付的是一个非常复杂的系统，在这个系统里面，每件事情相互牵连，相互影\n响。  \n \n        问：那么（你的意思）就是要确定你做的事情（利多于弊）……  \n \n        你没办法确定。这就是我的看法……  \n \n        但从另外一方面来说，我最近确实推翻了两组工程师提出的方案。我怎么会\n有足够的自信在一个如此复杂的领域做这样的判读呢？嗯，你也许会想：“这个\n家伙只是个有钱的自大狂罢了，他以为他什么都懂呢。”  \n \n        我可能是个自大狂，但我并不认为我什么都懂。不过我发现那两组工程师都\n很可能存在偏见，他们提出的结论都对他们自己有利。每一派所说的都与他们的','2026-07-05 16:55:53.049000',0,2073692323954429952,386,2073692323514028032),(2073692328371032064,' \n        我可能是个自大狂，但我并不认为我什么都懂。不过我发现那两组工程师都\n很可能存在偏见，他们提出的结论都对他们自己有利。每一派所说的都与他们的\n天然偏见相合，这让我产生了怀疑。此外，也许我掌握了足够多的工程学知识，\n所以能够知道（他们的结论）并无道理。  \n \n        最后，我找到第三个工程师，他提出的方案我很认可。后来第二个工程师跑\n来对我说：“查理，我怎么就没想到呢？”——他能这么说还是值得赞扬的。第三\n种方案更好，不但更安全，造价也更低。  \n \n        有些人虽然比你更有学问，但在他的认知明显受到激励机制引起的偏见或者\n某些相同的心理因素影响时，你必须有自信推翻他的结论。但有时你不得不承认\n自己的能力有限——你最好的办法就是信任某位专家。  \n \n      实际上，你应该弄清楚你知道什么，不知道什么。在生活中，还有什么比这\n个更有用的呢？ ','2026-07-05 16:55:53.049000',0,2073692323954429952,387,2073692323514028032),(2073692328371032065,'自己的能力有限——你最好的办法就是信任某位专家。  \n \n      实际上，你应该弄清楚你知道什么，不知道什么。在生活中，还有什么比这\n个更有用的呢？ \n    问：你讨论过可口可乐的失败。你认为苹果犯了哪些错误呢？  \n \n        让我来给你一个非常好的答案——这个答案是我从通用电气的 CEO 杰克·韦\n尔奇那里抄来的。韦尔奇是一位工程学博士。他是商界巨星。是个非常了不起的\n人。最近，有人问他：“杰克，苹果到底做错了什么？”当时巴菲特也在场。  \n \n        韦尔奇是怎么回答的呢？他说：“我没有足够的能力来回答这个问题。”我想\n给你相同的答案。在这个领域我没有能力给你任何特殊的见解。  \n \n        从另一个方面来说，我照搬韦尔奇的答案，是为了教你一个道理。当你不了\n解、也没有相关的才能时，不要害怕说出来。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,388,2073692323514028032),(2073692328371032066,' \n        从另一个方面来说，我照搬韦尔奇的答案，是为了教你一个道理。当你不了\n解、也没有相关的才能时，不要害怕说出来。  \n \n        有些人不是这样的，我想用一个生物学的例子来说明。当蜜蜂发现蜜源的时\n候，它会回到蜂窝，跳起一种舞蹈，告诉同类蜜源在哪个方向，有多远，这是蜜\n蜂的基因决定的。四五十年前，有个聪明的科学家把蜜源放得很高，蜜蜂从来没\n有遇到过这样的情况。所以蜜蜂发现了蜜源，回到蜂窝。但它的基因里没有编排\n好表达蜜源太高的舞蹈。它是怎么做的呢？  \n \n        如果它是韦尔奇，它就会坐下来。但实际上它跳起了一种不知所谓的舞蹈。\n许多人就像那只蜜蜂。他们试图以那种方式回答问题，那是一种巨大的错误。没\n有人期望你什么都懂。  \n \n        有些人总是很自信地回答他们其实并不了解的问题，我不喜欢跟他们在一','2026-07-05 16:55:53.049000',0,2073692323954429952,389,2073692323514028032),(2073692328371032067,'有人期望你什么都懂。  \n \n        有些人总是很自信地回答他们其实并不了解的问题，我不喜欢跟他们在一\n起。在我看来，他们就像那只乱跳舞的蜜蜂，只会把整个蜂窝搞得乱哄哄的。  \n \n        问：你曾经在律师事务所干过，请问你当时是如何利用这些模型的？效果怎\n么样？现在的律师事务所好像并不采用这些模型。  \n \n        它们也采用这些模型。但跟学术界的情况相同，律师事务所也有一些不正常\n的激励机制。实际上，从某些方面来说，律师事务所的情况更加糟糕。  \n \n        我来说说律师业的另外一种模型：我很小的时候，我父亲是个律师。他有个\n好朋友叫格兰特·麦克费登，奥马哈的福特汽车经销商，这人也是父亲的客户。\n麦克费登先生是个非常了不起的人——他是个白手起家的爱尔兰人。  \n \n        他小时候经常挨父亲毒打，于是从农场逃出来，自己开创了一片天地。他是','2026-07-05 16:55:53.049000',0,2073692323954429952,390,2073692323514028032),(2073692328371032068,'麦克费登先生是个非常了不起的人——他是个白手起家的爱尔兰人。  \n \n        他小时候经常挨父亲毒打，于是从农场逃出来，自己开创了一片天地。他是\n个聪明人，极其正直，极其有魅力——反正是个非常、非常了不起的人。  \n \n        我父亲有另外一个客户跟他正好相反，那人是个吹牛大王，自视极高，处事\n不公，夸夸其谈，难以相处。当时我大概只有 14 岁，我问：“爸爸，你为什么替\nX 先生——那个自视极高的吹牛大王——做那么多工作，而不是花更多精力在格\n兰特·麦克费登这样的好人身上呢？”  \n \n        我父亲说：“格兰特·麦克费登正确地对待他的员工，正确地对待他的客户，\n正确地处理他的问题。如果他遇到一个神经病，他会赶紧远离那神经病，尽快给\n自己找条出路。因此，我要是只做格兰特·麦克费登的生意，就没钱给你喝可口\n可乐啦。但 X 先生就不同了，他在生活中遇到许多法律纠纷。” ','2026-07-05 16:55:53.049000',0,2073692323954429952,391,2073692323514028032),(2073692328371032069,'自己找条出路。因此，我要是只做格兰特·麦克费登的生意，就没钱给你喝可口\n可乐啦。但 X 先生就不同了，他在生活中遇到许多法律纠纷。” \n 在生活中，为了养家糊口，你不妨偶尔替那些丧失理智的自大狂服务。但你应\n该像格兰特·麦克费登那样为人处世。那是个很好的道理。  \n \n        这个例子表明从事律师业的问题之一。在很大程度上，你不得不跟一些非常\n低劣的人打交道。当律师能够赚很多钱，大部分归功于他们。就算你的客户是个\n品德高尚的人，你要帮他应付的对手也往往是非常低劣的家伙。这是我不再当律\n师的一个原因。  \n \n        另外一个原因是我的私欲，但也是因贪欲带来的成功，我才能够更容易去做\n一个值得尊敬和理性的人。就像本杰明·富兰克林说过的：“空袋子很难竖起来。”  \n \n        我认为当我问起那两位客户时，我父亲的回答方式是非常正确的。他教给我','2026-07-05 16:55:53.049000',0,2073692323954429952,392,2073692323514028032),(2073692328371032070,' \n        我认为当我问起那两位客户时，我父亲的回答方式是非常正确的。他教给我\n一个道理。什么道理呢？在生活中，为了养家糊口，你不妨偶尔替那些丧失理智\n的自大狂服务。但你应该像格兰特·麦克费登那样为人处世。那是个很好的道理。  \n \n        而且他用的教学方式非常巧妙——因为他不是把这个道理直接灌输给我，而\n是让我自己通过思考去体会。我必须自己动脑筋，才能明白我应该学习格兰特·麦\n克费登。他认为如果这个道理是我自己摸索出来的，我会记得更牢。确实是这样\n的，我到今天还牢牢地记住它——尽管已经过去几十年了。这是一种非常巧妙的\n教育方式。  \n \n        这种方式也跟基本的心理学有关，跟基本的文学道理也有关系。优秀的文学\n作品需要读者略加思索才能理解，那样它对读者的影响会很深，你会更牢固地记\n住它。这就是承诺和保持一贯性的倾向。如果你动脑筋才懂得某个道理，你就会','2026-07-05 16:55:53.049000',0,2073692323954429952,393,2073692323514028032),(2073692328371032071,'作品需要读者略加思索才能理解，那样它对读者的影响会很深，你会更牢固地记\n住它。这就是承诺和保持一贯性的倾向。如果你动脑筋才懂得某个道理，你就会\n更好地记住它。  \n \n        优秀的文学作品需要读者略加思索才能理解。如果你动脑筋才懂得某个道\n理，你就会更好地记住它。  \n \n        如果你是律师或者企业领导，也许会想让他人明白我父亲告诉我的道理，或\n者其他你想让他们学到的事情。你可以通过这种方式对他们进行教育。难道用这\n种方法来教孩子不是很好吗？我父亲故意使用了间接的方法。你看它的效果多么\n好——就像库克船长巧妙地运用心理学一样。自那以后，我一直都在模仿格兰\n特·麦克费登——终生如此。我可能有些地方做得不够好，但至少我一直以他为榜\n样。  \n \n        问：你在《杰出投资者文摘》发表的文章结尾提到，只有少数投资经理能够','2026-07-05 16:55:53.049000',0,2073692323954429952,394,2073692323514028032),(2073692328371032072,'样。  \n \n        问：你在《杰出投资者文摘》发表的文章结尾提到，只有少数投资经理能够\n创造附加值。你现在的听众将来都会成为律师，你认为我们应该怎样为司法业创\n造附加值呢？  \n \n        只要成为能够正确思考的人，你们就可以创造附加值。只要很好地掌握正确\n的思考方式，能够见义勇为，当仁不让，你们就能够创造很大的附加值。只要能\n够防止或者阻止某些足以毁掉你们的事务所、客户或者你所在乎的某些东西的蠢\n事，你们就能创造很大的附加值。  \n \n        你们可以使用一些有效的妙招。例如，我的老同学，斯卡登 ·阿普斯\n（SkaddenArps）律师事务所的乔伊·弗洛姆（Joe Flom），是个十分成功的律师，\n原因就在于他非常善于用一些精妙的比喻来有效地传达他的观点。如果你们想为\n客户服务，或者想要说服别人，用点幽默的比喻是非常有帮助的。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,395,2073692323514028032),(2073692328371032073,'原因就在于他非常善于用一些精妙的比喻来有效地传达他的观点。如果你们想为\n客户服务，或者想要说服别人，用点幽默的比喻是非常有帮助的。  \n \n        这是一种很了不起的本事。你们可以说乔伊·弗洛姆的本领是天生的，但他经\n常磨练这种天赋。你们或多或少都拥有这种天赋，你们也可以磨练它。  \n \n        有时候你们会遇到一些不能做的事。例如，假设你有个客户非常想要逃税。\n他要是不逃税，就会觉得浑身不舒服。如果他认为有些漏洞可以钻但是他没有钻，\n他每天早上会连胡子都刮不干净。有些人就是这样的。他们就是不愿意安分守规\n矩。  \n \n        你们可以用两种方法来解决这个问题：（A）你们可以说，“老子不给他干啦”，\n然后撒手不管，或者（B）你们可以说：“哎呀，生活所迫，我必须为他工作呀。\n我只是替他作假，不代表我自己作假。所以，我还是做吧。” ','2026-07-05 16:55:53.049000',0,2073692323954429952,396,2073692323514028032),(2073692328371032074,'然后撒手不管，或者（B）你们可以说：“哎呀，生活所迫，我必须为他工作呀。\n我只是替他作假，不代表我自己作假。所以，我还是做吧。” \n    如果发现他真的想要做一些非常愚蠢的事情，你们这么对他说可能是没用\n的：“你这么做不对。我的道德比你高尚多啦。”  \n \n        那会得罪他的。你们是年轻人，他年纪比较大，因此，他不会被你们说服，\n而是会作出这样的反应：“你以为你是谁，凭什么给整个世界设立道德标准？”  \n \n        但你们可以这样对他说：“你做这件事情，不可能不让你的手下知道。所以\n呢，你这么做很容易遭到敲诈勒索。你这是在拿你的声誉冒险，拿你的家人和金\n钱冒险。”  \n \n        这样做可能会有效。而且你们对他说的是实话。如果必须使用这样的方法才\n能让人们做正确的事情，你愿意在这种地方工作吗？我想答案是否定的。但如果','2026-07-05 16:55:53.049000',0,2073692323954429952,397,2073692323514028032),(2073692328371032075,' \n        这样做可能会有效。而且你们对他说的是实话。如果必须使用这样的方法才\n能让人们做正确的事情，你愿意在这种地方工作吗？我想答案是否定的。但如果\n你们只能在这样的地方待下去，从他的利益出发去说服他，很可能比从其他方面\n出发去说服他更有效。这也是一种有着极深的生物学根源的强大心理学原则。  \n \n        我亲眼看到那种心理学原则是如何使所罗门倒掉的。所罗门的法律总顾问知\n道 CEO 古特福伦德应该尽快将所罗门公司的违法交易统统告诉联邦政府部门，\n古特福伦德并没有参与那些不法交易，不是主犯。总顾问要求古特福伦德那么做。\n实际上，他对古特福伦德说：“虽然法律可能不要求你这么做，但那是正确的。\n你真的应该说出来。”  \n \n        但那没有用。这个任务很容易被推掉——因为它令人不愉快。那正是古特福\n伦德的选择——他把它推掉了。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,398,2073692323514028032),(2073692328371032076,'你真的应该说出来。”  \n \n        但那没有用。这个任务很容易被推掉——因为它令人不愉快。那正是古特福\n伦德的选择——他把它推掉了。  \n \n        除了 CEO，总顾问在所罗门公司并没有什么靠山。如果 CEO 下台，总顾问也\n会跟着下台。因此，他整个职业生涯岌岌可危。所以为了拯救他的职业生涯，他\n需要说服这位拖拉的 CEO 赶快去做正确的事情。  \n \n        这件任务简单得小孩子都能完成。总顾问只要这样对他老板说：“约翰，你\n再这样下去，你的生活就毁了。你会身败名裂的。”这么说就可以了。没有 CEO\n愿意自毁前途、声名扫地。  \n \n        没有 CEO 愿意自毁前途、声名扫地。 \n   这位所罗门的前总顾问为人聪明大度——他的想法也是正确的。然而，他丢\n了工作，因为他没有应用一点基本的心理学知识。他并不知道，在大多数情况下，','2026-07-05 16:55:53.049000',0,2073692323954429952,399,2073692323514028032),(2073692328371032077,'   这位所罗门的前总顾问为人聪明大度——他的想法也是正确的。然而，他丢\n了工作，因为他没有应用一点基本的心理学知识。他并不知道，在大多数情况下，\n要说服一个人，从这个人的利益出发是最有效的。  \n \n        但就算遇到相同的情况，你们应该不会得到相同的糟糕结果。只要记住古特\n福伦德和他的总顾问的下场就好了。如果你们用心学，正确的道理是很容易掌握\n的。如果你们掌握了，在遇到其他人无法解决的关键问题时，你们就能够表现得\n游刃有余。只要你们变得明智、勤奋、公正，而且特别擅长说服别人去做正确的\n事，你们就能够创造附加值。  \n \n        问：你能谈谈诉讼的威胁——股东的官司等等——和一般法律的复杂性如何\n影响到大型企业的决策吗？  \n \n        嗯，每个大企业都为法律成本叫苦，为规章制度之多叫苦，为公司事务的复','2026-07-05 16:55:53.049000',0,2073692323954429952,400,2073692323514028032),(2073692328371032078,'影响到大型企业的决策吗？  \n \n        嗯，每个大企业都为法律成本叫苦，为规章制度之多叫苦，为公司事务的复\n杂性叫苦，为控方律师——尤其是集体诉讼的控方律师——叫苦。所以你完全可\n以把一家公司的叫苦单照搬给另外一家公司，一个字都不用改。  \n \n        但对于律师事务所来说，让它们叫苦的这些情况实在是好消息。多年以来，\n大型律师事务所的业务一直处于上升通道。它们根本忙不过来，就像大瘟疫中的\n收尸人。当然，如果在瘟疫期间，收尸人一边手舞足蹈，一边拉小提琴，那会显\n得非常怪异。所以律师事务所的合伙人会说：“唉呀，真叫人悲伤——这么多复\n杂的问题，这么多的官司，这么多的司法不公。”  \n \n        当然，如果在瘟疫期间，收尸人一边手舞足蹈，一边拉小提琴，那会显得非\n常怪异。  \n \n        但说真的，他们多少有点精神分裂才会抱怨这种情况，因为这实际上对他们','2026-07-05 16:55:53.049000',0,2073692323954429952,401,2073692323514028032),(2073692328371032079,'常怪异。  \n \n        但说真的，他们多少有点精神分裂才会抱怨这种情况，因为这实际上对他们\n非常有利。最近加利福尼亚州出现了一些有趣的事。部分辩方律师想让公民投票\n否决某个议案，但是这么做有害于他们客户的利益，所以他们只能偷偷摸摸地进\n行游说，免得被他们的客户发现。他们这么做的原因是，那个法案使得控方律师\n更难提出诉讼。  \n \n        如果你是辩方律师，靠的就是和这些极端分子斗智斗勇，以此来为孩子交学\n费——那个法案无异于将他们的饭碗打破。所以身为成年人，他们只能作出这种\n成年人的选择。  \n \n        所以大公司适应了。他们遇到更多的官司，不得不设立规模更大的法务部门。\n他们为他们不喜欢的东西叫苦，但他们适应了。 \n \n        问：可是在过去几十年里，这种法律的复杂性消耗了企业大量的资源，是吧？  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,402,2073692323514028032),(2073692328375226368,'他们为他们不喜欢的东西叫苦，但他们适应了。 \n \n        问：可是在过去几十年里，这种法律的复杂性消耗了企业大量的资源，是吧？  \n \n        是的。几乎所有美国公司的诉讼费用和为了遵守各种规章制度而支出的费用\n都比 20 年前高出了一大截。确实，有些新的法规是很愚蠢的。但有些则是不可\n缺少的。这种情况将会一直延续下去，只不过轻重程度会有所不同。  \n \n        问：是否有些企业由于担心失败或负法律责任而不太可能去投资那些风险较\n高的项目？您有看到或经历过企业决策上任何这样的变化吗？  \n \n        我曾经和朋友——不是沃伦，是另外一个朋友——一起碰到过这种情况。我\n们控股的一家子公司发明了一种更好的警察头盔。那是用凯夫拉尔（注：即对位\n芳纶，美国杜邦公司于 1960 年代研制出的一种具有低密度、高强度性能的新型','2026-07-05 16:55:53.049000',0,2073692323954429952,403,2073692323514028032),(2073692328375226369,'们控股的一家子公司发明了一种更好的警察头盔。那是用凯夫拉尔（注：即对位\n芳纶，美国杜邦公司于 1960 年代研制出的一种具有低密度、高强度性能的新型\n复合材料）之类的原料制成的。他们把这种头盔带给我们看，要我们生产它。  \n \n        就意识形态而言，我们非常支持警察。我认为文明社会需要警察队伍——虽\n然我并不认为每年牺牲的警察很多，给社会带来了太多的孤儿寡母，但我们赞成\n警察该有更好的头盔用。  \n \n        然而，我们看了一下头盔，然后对那个发明它的人说：“我们公司很有钱，\n可是我们造不起这种更好的警察头盔。现在的文明社会就是这样的。考虑到各种\n风险因素，我们不能生产这种头盔。但我们希望有人愿意生产。”  \n \n        因此，我们并没有试图阻止警察获得这种新头盔，但我们决定我们自己不要\n制造头盔。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,404,2073692323514028032),(2073692328375226370,' \n        因此，我们并没有试图阻止警察获得这种新头盔，但我们决定我们自己不要\n制造头盔。  \n \n        考虑到文明社会的发展方式，有些行业的情况是这样的，如果你是该行业最\n有钱的人，那么它会是一个糟糕的行业。比如说，在高中的橄榄球比赛中，难免\n会有球员因头部受伤而导致半身麻痹或者四肢麻痹。除了那家最有钱的头盔制造\n商，伤者还能找到更好的起诉对象吗？每个人都为伤者感到遗憾，都觉得那些伤\n病非常严重，所以制造商输掉官司的概率很大……  \n \n        我认为在我们这样的文明社会，富裕的大公司生产橄榄球头盔是不明智的行\n为。也许法律不应该让那些起诉头盔制造商的人轻易胜诉。  \n \n        我认为在我们这样的文明社会，富裕的大公司生产橄榄球头盔是不明智的行\n为。 \n  我认识两个医生——他们的婚姻都很美满。后来医疗责任险的保费升得太高，','2026-07-05 16:55:53.049000',0,2073692323954429952,405,2073692323514028032),(2073692328375226371,'为。 \n  我认识两个医生——他们的婚姻都很美满。后来医疗责任险的保费升得太高，\n他们就都离婚了，把绝大部分的财产转移到他们的妻子名下。他们继续执业——\n只是没有投保医疗责任险而已。  \n \n        他们对文明制度不满。他们需要适应。他们信任他们的妻子。所以就出现了\n那种情况。自那之后，他们再也没有为医疗责任投保。  \n \n        人们能够适应不断变化的司法气候。他们有各自的办法。从前是这样，将来\n也仍会是这样。  \n \n        我喜欢海军的制度……如果船长在恶劣的环境中把船交给非常有能力的大\n副，而大副把船弄搁浅，那么船长的海军生涯就结束了。  \n \n        我个人最讨厌的是那些让欺诈变得容易的制度。加利福尼亚州那些脊椎按摩\n师的收入也许有一大半是纯粹通过欺骗得来的。例如，我有个朋友在一个糟糕的','2026-07-05 16:55:53.049000',0,2073692323954429952,406,2073692323514028032),(2073692328375226372,' \n        我个人最讨厌的是那些让欺诈变得容易的制度。加利福尼亚州那些脊椎按摩\n师的收入也许有一大半是纯粹通过欺骗得来的。例如，我有个朋友在一个糟糕的\n社区发生了一起小小的车祸。他甚至还没来得及把车驶离那个交叉路口，就收到\n了两个脊椎按摩师和一个律师的名片。他们专门从事伪造受伤报告的勾当。  \n \n        兰德公司的数据显示，我们加利福尼亚州平均每次车祸的受伤人数是其他许\n多州的两倍，但实际上我们每次车祸的受伤人数并没有比别的州高出一倍。所以\n有一半是伪造的。这已经成了一种社会风气，人们认为每个人都这么做，所以自\n己诈伤也完全没有问题。我认为这样的社会风气是很糟糕的。  \n \n        如果制度由我来制定，那么对工作压力的工伤赔偿金将会是零——不是因为\n工作造成的压力并不存在，而是我认为如果允许因工作压力就能够得到赔偿，那','2026-07-05 16:55:53.049000',0,2073692323954429952,407,2073692323514028032),(2073692328375226373,' \n        如果制度由我来制定，那么对工作压力的工伤赔偿金将会是零——不是因为\n工作造成的压力并不存在，而是我认为如果允许因工作压力就能够得到赔偿，那\n么社会受到的损害，将会比少数人真的因工作压力受伤而得不到赔偿的情况糟糕\n得多。  \n \n        我喜欢海军的制度。如果你是海军的船长，接连工作了 24 小时，需要去睡\n觉，所以在恶劣的环境中把船交给非常有能力的大副，而他把船弄搁浅了——这\n显然不是你的错——他们不会把你送到军事法庭，但你的海军生涯就结束了。  \n \n        你们也许会说：“那太严厉了。法学院可不是这样的。那不是合法的诉讼程\n序。”嗯，海军的模式比法学院的模式好多了。海军的模式确实能够促使人们在\n环境恶劣的时候全神贯注——因为他们知道，如果出事绝对不会获得原谅。 \n \n        拿破仑说他喜欢更幸运的将领——他不会支持败军之将。同样地，海军喜欢','2026-07-05 16:55:53.049000',0,2073692323954429952,408,2073692323514028032),(2073692328375226374,'环境恶劣的时候全神贯注——因为他们知道，如果出事绝对不会获得原谅。 \n \n        拿破仑说他喜欢更幸运的将领——他不会支持败军之将。同样地，海军喜欢\n更幸运的船长。  \n \n        不管你的船是因为什么原因搁浅的，反正你的生涯结束了。没有人对你的错\n误（原因）感兴趣。那就是海军的规则——从方方面面来说，这对所有人都好。  \n \n        我喜欢那样的规则。我认为如果有几条这种不追究过错原因的规则，我们的\n文明社会将变得更好。但这种提议很容易在法学院引起争议：“那不是合理的诉\n讼程序，你没有真的追求正义。”  \n \n        我赞成海军的规定，那就是在追求正义——追求让更少船只触礁的正义。考\n虑到这些规则带来的好处，我不会在乎有位船长受到不公平的对待。毕竟，那又\n不是把他送到军事法庭。他只需要另外找份工作而已，他从前缴纳的养老金依然','2026-07-05 16:55:53.049000',0,2073692323954429952,409,2073692323514028032),(2073692328375226375,'虑到这些规则带来的好处，我不会在乎有位船长受到不公平的对待。毕竟，那又\n不是把他送到军事法庭。他只需要另外找份工作而已，他从前缴纳的养老金依然\n归他所有，诸如此类的。所以那对他来说也不会是世界末日。  \n \n        我喜欢这样的规则。可惜像我这样的人不多。  \n \n        问：我想听你再谈谈如何作判断。在你的演讲中，你说过我们应该阅读心理\n学教材，然后掌握十五六个最有道理的原则……  \n \n        掌握那些明显很重要和明显很正确的原则。没错……然后你还得钻研那些明\n显很重要然而教材上又没有的原则——这样你就能得到一个系统。  \n \n        问： 是的。我的问题跟第一步有关， 怎样确定哪些原则是明显正确的呢？\n对我来说，这才是更重要的问题。  \n \n        嗯，如果你像我一样，你就会觉得有点复杂才有意思。如果你想要毫不费力','2026-07-05 16:55:53.049000',0,2073692323954429952,410,2073692323514028032),(2073692328375226376,'对我来说，这才是更重要的问题。  \n \n        嗯，如果你像我一样，你就会觉得有点复杂才有意思。如果你想要毫不费力\n就能明白，也许你应该加入某种宣称能够解答一切问题的邪教。  \n \n        不，不。没你说的那么难，你言过其实了。人们很容易受到他人的思维和行\n为的严重影响，有时候这种受影响的情况是发生在潜意识层面上的，你觉得这很\n难理解吗？ \n     问：没有啦。这个我能理解。  \n \n        那就对了。那你就完全能够弄懂那些原则。慢慢来，一个一个掌握。没有你\n说的那么难……  \n \n        你觉得操作性条件反射的原理——也就是人们会重复他们上一次成功的活\n动——很难理解吗？  \n \n        问：我觉得要掌握的东西很多，有道理的内容也很多。我觉得这个系统很快\n就会变得很复杂——因为各种各样的原则太多了。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,411,2073692323514028032),(2073692328375226377,' \n        问：我觉得要掌握的东西很多，有道理的内容也很多。我觉得这个系统很快\n就会变得很复杂——因为各种各样的原则太多了。  \n \n        嗯，如果你像我一样，你就会觉得有点复杂才有意思。如果你想要毫不费力\n就能明白，也许你应该加入某种宣称能够解答一切问题的邪教。我可不认为那是\n一种好办法。我想你必须接受这个世界——它就是这么复杂。爱因斯坦曾经很好\n地总结过这一点：“一切应该尽可能简单，但不能过于简单。”  \n \n        我想学习心理学也是这样的。如果有 20 种因素，并且它们相互影响，你必\n须学会处理它们——因为世界就是这么复杂。但如果你能够像达尔文那样，带着\n好奇心逐步解决问题，你就不会觉得很难。你会惊讶地发现，原来你能够学得很\n好。  \n \n        问：你刚才给了我们三个你使用的模型。我想知道你是从哪里找到其他模型','2026-07-05 16:55:53.049000',0,2073692323954429952,412,2073692323514028032),(2073692328375226378,'好。  \n \n        问：你刚才给了我们三个你使用的模型。我想知道你是从哪里找到其他模型\n的。第二个问题，你能教给我们一种更轻松地阅读心理学教材的方法吗？我倒不\n反对去读心理学教材，可是那样很费时间。  \n \n        学科的种类并不多，真正有用的思想也不多。把它们统统弄清楚会给你带来\n很多乐趣。此外，如果你通过亲自摸索去把它们搞清楚，而不是通过别人的转述\n死记硬背，你对那些思想的掌握会比较牢固。  \n \n        更重要的是，这种乐趣永远不会枯竭。我以前接受的教育错误得很离谱。我\n根本没有看过所谓的现代达尔文主义的著作。我看的书也很杂，但我就是没看过\n这类书。去年我突然意识到自己真是个白痴，居然连现代达尔文主义都没看过，\n所以我倒了回去，在牛津大学伟大的生物学家道金斯（Dawkins）和其他人的帮\n助之下，我补充了这个流派的知识。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,413,2073692323514028032),(2073692328375226379,'所以我倒了回去，在牛津大学伟大的生物学家道金斯（Dawkins）和其他人的帮\n助之下，我补充了这个流派的知识。  \n \n        我七十几岁啦，对我来说，理解现代达尔文综合理论绝对是很快乐的事情。\n这种理论极其漂亮，极其正确。一旦掌握它之后，它就变得很简单。所以我这种\n方法吸引人的地方就在于它带来的乐趣永不枯竭。如果你患上老年痴呆症，最终\n被送到疗养院，那么我想这种乐趣确实会枯竭。但就算是那样，它至少也持续了\n很长的时间。 \n如果我是法学院的沙皇——不过法学院当然不会允许沙皇的存在（它们甚至不\n希望院长拥有太多的权力）——我会开设一门叫做“补救式普世智慧”的课程，它\n将会提供许多有用的东西，包括大量得到正确传授的心理学知识。这门课可能只\n持续三个星期或者一个月……  \n \n        我认为你们应该开设一门有趣的课程——采用一些有说服力的例子，传授一','2026-07-05 16:55:53.049000',0,2073692323954429952,414,2073692323514028032),(2073692328375226380,'持续三个星期或者一个月……  \n \n        我认为你们应该开设一门有趣的课程——采用一些有说服力的例子，传授一\n些有用的原理——那将会很有趣。我认为这门课程将有助于你们发挥从法学院学\n到的知识。  \n \n        人们会对这个想法不以为然。“大家不做这样的事情。”他们可能不喜欢课程\n名称——“补救式普世智慧”——所含的讽刺意味。不过我这个名称的含义其实是\n“每个人都应该知道”。如果你管它叫补救式的，难道你的意思不是这样的吗？“这\n些道理真的非常基础，每个人都应该知道。”  \n \n        这样一门课将会非常有趣。可以援引的例子太多了。我不明白人们为什么不\n开设。也许是因为他们不想开，所以就没有开；但也许是他们不知道该怎么开；\n也许他们不懂这门课是什么。  \n \n        但如果你们在接受传统的法学院教育之前，有那么一个月的时间来学习这些','2026-07-05 16:55:53.049000',0,2073692323954429952,415,2073692323514028032),(2073692328375226381,'也许他们不懂这门课是什么。  \n \n        但如果你们在接受传统的法学院教育之前，有那么一个月的时间来学习这些\n通过生动的例子得到传授的基本道理，你们在法学院的整个求学过程将会有趣得\n多。我认为整个教育系统的效果将会好得多。但没有人对开设这样的课程感兴趣。  \n \n        有些法学院确实传授教材之外的知识，但在我看来，他们的方法往往显得非\n常笨拙。其实美国大学的心理学课算上得不错的了，不信你看看那些企业金融课\n程。现代的组合投资理论？那完全是乱来！真叫人吃惊。  \n \n        我不知道怎么会这样。自然科学的工程学都教得很好。但除了这些领域，其\n他学科的情况完全是莫名其妙——尽管有些学科的研究人员智商非常高。  \n \n        可是，孩子们，学校应该如何改变这种愚蠢的局面呢？正确的做法不是请一','2026-07-05 16:55:53.049000',0,2073692323954429952,416,2073692323514028032),(2073692328375226382,'他学科的情况完全是莫名其妙——尽管有些学科的研究人员智商非常高。  \n \n        可是，孩子们，学校应该如何改变这种愚蠢的局面呢？正确的做法不是请一\n个七十几岁的老资本家来告诉高年级的学生：“这是一点补救式普世智慧。”这不\n是解决问题的办法。  \n \n        许多法学原理是跟其他原理联系在一起的。它们的关系密不可分。然而，在\n教学中，他们并没有指出这些法学原理跟其他重要原理有密切的关系。这种做法\n很荒谬——绝对很荒谬。 \n    从另外一方面来说，法学院在学生刚入学的第一个月就灌输一些基本的原\n理……许多法学原理是跟其他原理联系在一起的，它们的关系密不可分。然而，\n在教学中，他们并没有指出这些法学原理跟其他重要原理有密切的关系。这种做\n法很荒谬——绝对很荒谬。  \n \n        我们为什么规定法官不能对未经他们之手的案件发表评论呢？当我上法学','2026-07-05 16:55:53.049000',0,2073692323954429952,417,2073692323514028032),(2073692328375226383,'法很荒谬——绝对很荒谬。  \n \n        我们为什么规定法官不能对未经他们之手的案件发表评论呢？当我上法学\n院的时候，老师们在课堂上谈到这个规定，但没有联系到本科课程中的重要内容\n加以说明。不把那些理由说出来真的很荒唐。人类的大脑需要理由才能更好地理\n解事情。你们应该把现实悬挂在附带理由的理论结构之上。只有那样，你们才能\n成为一个有效的思考者。  \n \n        至于老师们教给学生一些原理，却不给理由，或者很少解释理由，那是错误\n的做法！  \n \n        我之所以想要设立一门课来传授补救式普世智慧，原因还在于它会迫使教授\n们去反省。要是这些教授传授的知识明显有误，而我们在一门叫做“补救式普世\n智慧”的课程中予以更正和强调，那么他们会感到难为情。那些传授错误知识的\n教授真的必须为自己辩护。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,418,2073692323514028032),(2073692328375226384,'智慧”的课程中予以更正和强调，那么他们会感到难为情。那些传授错误知识的\n教授真的必须为自己辩护。  \n \n        这个想法是不是很疯狂？期待有人设立一门这样的课，可能是一个疯狂的想\n法。不过，如果有人真的开了这样的课，难道你们不觉得它会很有用吗？  \n \n        问：我认为要是有一门这样的课那就太好了。可惜等到这门课开出来的时候，\n我们早就毕业啦。你的建议是，可以通过设置一门课程来教我们。但除此之外，\n我们还有什么办法可以学到普世智慧吗？  \n \n        一直以来，总有人问我学习是否有捷径。今天我也尝试给你们提供一些学习\n的窍门，但光靠这样一次演讲是不够的。正确的做法应该是写一本书。  \n \n        我希望我说的话能够帮助你们成为更有效率和更优秀的人。至于你们是否会\n发财，那不是我要考虑的。但总有人要求我：“把你知道的都喂给我吧。”当然，','2026-07-05 16:55:53.049000',0,2073692323954429952,419,2073692323514028032),(2073692328375226385,' \n        我希望我说的话能够帮助你们成为更有效率和更优秀的人。至于你们是否会\n发财，那不是我要考虑的。但总有人要求我：“把你知道的都喂给我吧。”当然，\n他们说的话往往是这样的：“教我如何不费力气地快速致富。不但要让我快速致\n富，你还要快速地教会我。”  \n \n        我并没有兴趣自己写一本书。再说了，写书要花很多精力，那不是我这样七\n十几岁的人应该做的。我还有其他许多事情要处理，所以我不会去写书。但对别\n人来说是绝好的机会。如果我发现有聪明人愿意正确地完成这项任务，我会为他\n的写作提供资助。 \n \n        总是有人要求我：“把你知道的都喂给我吧。”当然，他们说的话往往是这样\n的：“教我如何不费力气地快速致富。不但要让我快速致富，你还要快速地教会\n我。”  \n \n        让我来解释一下为什么现在的教育如此糟糕。部分原因在于不同学科之间老','2026-07-05 16:55:53.049000',0,2073692323954429952,420,2073692323514028032),(2073692328379420672,'我。”  \n \n        让我来解释一下为什么现在的教育如此糟糕。部分原因在于不同学科之间老\n死不相往来的现状。例如，心理学只有和其他学科的原理结合起来才是最有用的。\n但如果你们的教授并不了解其他学科的原理，那么他就无法完成这种必要的整\n合。  \n \n        可是，如果有个人精通其他学科，致力于将其他学科的原理和心理学结合起\n来，他怎么能够成为心理学教授呢？这样的心理学教授往往会激怒他的同行和上\n级。  \n \n        世界历史上有过几个非常了不起的心理学教授。亚利桑那州立大学的罗伯\n特·西奥迪尼（Robert Cialdini）对我非常有启发，B. F. 斯金纳也是——不是说他\n的偏执性格和乌托邦倾向，而是说他的实验结果。但总的来讲，我并不认为美国\n的心理学教授如果改行研究物理学，也能够成为教授。这可能就是他们没能把心\n理学教好的原因。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,421,2073692323514028032),(2073692328379420673,'的心理学教授如果改行研究物理学，也能够成为教授。这可能就是他们没能把心\n理学教好的原因。  \n \n        许多教育学院，甚至有些优秀大学的教育学院，都兴起了心理学的热潮。它\n们简直是知识界的耻辱。有些院系——甚至在有些杰出的研究机构中——有时也\n会存在某些重要的缺陷，开设许多名为心理学的课程也并非包治百病的灵丹妙\n药。  \n \n        考虑到学术界的惯性，所有学术界的缺陷都是非常难以解决的。你们知道芝\n加哥大学是如何解决心理学系问题的吗？该系拥有终身教职的教授都很糟糕，校\n长实际上废除了整个心理学系。  \n \n        假以时日，芝加哥大学将会拥有一个全新的、截然不同的心理学系。实际上，\n现在它也许已经拥有了，也许情况比以前好得多了。我必须承认，我对一个如此\n有魄力的大学校长是极其钦佩的。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,422,2073692323514028032),(2073692328379420674,'现在它也许已经拥有了，也许情况比以前好得多了。我必须承认，我对一个如此\n有魄力的大学校长是极其钦佩的。  \n \n        我并不希望你们听了我的批评之后，就以为大学心理学教育的糟糕情况完全\n是因为心理学系的教职员工能力都很低下。相反，造成这种情况的原因跟心理学\n的本质有关——这个学科有许多难以消除的、令人着恼的特性。  \n \n        让我通过一个包括几个问题的“思维实验”来证明这一点：是否有些学科需要\n一个像詹姆斯·克拉克·麦克斯韦那样的集大成者，却从未吸引到这样的人才？学\n院心理学的本质是否决定了这个学科对天才毫无吸引力？我认为这两个问题的\n答案都是肯定的。 \n   原因不难理解，每代人中能够准确地解决热力学、电磁学和物理化学的各种\n难题的人只有少数几个，用一只手就可以数得过来。这样的人往往会被活着的最\n杰出的人乞求从事尖端的自然科学研究。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,423,2073692323514028032),(2073692328379420675,'难题的人只有少数几个，用一只手就可以数得过来。这样的人往往会被活着的最\n杰出的人乞求从事尖端的自然科学研究。  \n \n        这样的天才会选择从事心理学研究吗？心理学的尴尬之处在于：（A）就社会\n心理学而言，人们对它揭示的各种倾向了解得越多，这些倾向的作用就会变得越\n弱；（B）就临床（治疗）心理学而言，它必须面临一个尴尬的问题：相信虚幻的\n东西往往能够提高幸福感。所以我认为答案显然是否定的。非常聪明的人不愿意\n从事心理学研究，正如诺尔贝物理学奖得主马克斯·普朗克不愿意从事经济学研\n究一样：他认为他的方法无法解决经济学的问题。  \n \n        问：我们谈论了许多生活质量和专业追求之间的关系。除了学习这些模型之\n外，你还有时间做其他感兴趣的事情吗？除了学习之外，你还有时间去做好玩的\n事情吗？  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,424,2073692323514028032),(2073692328379420676,'外，你还有时间做其他感兴趣的事情吗？除了学习之外，你还有时间去做好玩的\n事情吗？  \n \n        我总是用相当一部分的时间来做我真正想做的事情——比如说只是钓鱼、玩\n桥牌或者打高尔夫球。  \n \n        我们每个人都必须想清楚自己要过什么样的生活。你们也许想要每周工作 70\n个小时，接连工作 10 年，以便成为克拉法斯律师事务所（注：美国著名律师事\n务所）的合伙人，然后更加卖命地工作。你们也许会说：“我不愿意付出那么大\n的代价。”这两种方式完全是因人而异，你们必须自己弄清楚。  \n \n        但无论你们选择了哪种生活方式，我认为你们应该尽量去吸收基本的普世智\n慧，否则就是犯了大错，因为世俗智慧可以让你更好地服务别人，可以让你更好\n地服务自己，可以给生活带来更多的乐趣。所以如果你们有能力去掌握它却不去','2026-07-05 16:55:53.049000',0,2073692323954429952,425,2073692323514028032),(2073692328379420677,'慧，否则就是犯了大错，因为世俗智慧可以让你更好地服务别人，可以让你更好\n地服务自己，可以给生活带来更多的乐趣。所以如果你们有能力去掌握它却不去\n掌握，我认为那是很荒唐的。如果你们掌握了普世智慧，你们的生活将会变得很\n丰富——不仅是金钱方面，其他方面也将会变得很丰富。  \n \n        这次演讲是非常特殊的，一个商人跑到法学院来作演讲——这个家伙从来没\n有上过一节心理学的课程，却告诉你们所有的心理学教材都是错的。这是很奇怪\n的。但我只能告诉你们，我是很诚恳的。  \n \n        有许多简单的东西是你们之中许多人都能够学会的。如果你们学会了，你们\n的生活将会得到改善。此外，学习它是很有趣的。所以我敦促你们去学习它。 \n  问：这些年来，你实际上是在完成与他人分享智慧的任务吗？  \n \n        问：这些年来，你实际上是在完成与他人分享智慧的任务吗？当然。你们看','2026-07-05 16:55:53.049000',0,2073692323954429952,426,2073692323514028032),(2073692328379420678,'  问：这些年来，你实际上是在完成与他人分享智慧的任务吗？  \n \n        问：这些年来，你实际上是在完成与他人分享智慧的任务吗？当然。你们看\n看伯克希尔·哈撒韦就知道啦。我认为它是最具有教育意义的企业。沃伦不打算\n花钱。他准备把钱统统回馈给社会。他只是建立起一个讲台，以便人们聆听他的\n教诲而已。不消说，他的教诲都是很好的。那个讲台也不算差。你可以说沃伦和\n我都是我们自己意义上的学者。  \n \n        问：你说的话大多数很有说服力。你对知识、改善人类生存状况和金钱的追\n求都是值得称道的目标。  \n \n        我不知道对金钱的追求是否值得称道。  \n \n        问：那么，追求金钱应该算是可以理解的目标吧？  \n \n        这我倒是同意的。反正我不会瞧不起那些搞电话推销或者校对债务合约的','2026-07-05 16:55:53.049000',0,2073692323954429952,427,2073692323514028032),(2073692328379420679,' \n        问：那么，追求金钱应该算是可以理解的目标吧？  \n \n        这我倒是同意的。反正我不会瞧不起那些搞电话推销或者校对债务合约的\n人。如果你需要钱，赚钱就是乐趣。如果你在你的职业生涯中必须更换许多份工\n作，那也没什么好说的。你终究得做点赚钱的事情。许多工作只要能够让你赚钱，\n就是体面的工作。  \n \n        问：我知道你对那些太受意识形态影响的人有所保留。但你的所作所为就没\n有受到意识形态的影响吗？难道就没有什么让你为之醉心的东西吗？  \n \n        有啊，我醉心于智慧，我为追求准确和满足好奇心而醉心。也许我天生高尚，\n愿意为那些超越我的短暂生命的价值观念服务。但也许我只是在这里自吹自擂。\n谁知道呢？  \n \n        我认为人们应该掌握其他人已经弄清楚的道理。我并不认为人们只要坐下来\n空想就能掌握普世智慧。没人有那么聪明…… \n重读第三讲 ','2026-07-05 16:55:53.049000',0,2073692323954429952,428,2073692323514028032),(2073692328379420680,'谁知道呢？  \n \n        我认为人们应该掌握其他人已经弄清楚的道理。我并不认为人们只要坐下来\n空想就能掌握普世智慧。没人有那么聪明…… \n重读第三讲 \n \n \n \n        1996 年发表这篇演讲的时候，我认为人们应该避免强烈的政\n治偏见，因为它使许多人精神失常，甚至包括一些非常聪明的人。自那以后，无\n论左翼还是右翼，它们的政治偏见都变本加厉，正如我早已料到的，这种情况造\n成的结果是很多人无法正确地认识现实。  \n \n        我自然不喜欢这种结果。按照我的性格，我会像阿基米德有可\n能的那样质问上帝：“你怎么可以在我提出那些公式之后让中世纪这样的黑暗年\n代出现呢？”或者像马克·吐温曾经抱怨的那样：“现在的文坛真是萧条啊。荷\n马已经去世。莎士比亚死了。我觉得我好像也快不行了。”  \n \n        幸好我仍然能够控制我自己别发出马克·吐温那样的浩叹。毕','2026-07-05 16:55:53.049000',0,2073692323954429952,429,2073692323514028032),(2073692328379420681,'马已经去世。莎士比亚死了。我觉得我好像也快不行了。”  \n \n        幸好我仍然能够控制我自己别发出马克·吐温那样的浩叹。毕\n竟我从来不曾幻想我的观点能够让世界发生很大的变化。相反，我向来认为做人\n要低调谦虚，所以我要追求的是：（1）向比我优秀的人学习几种有用的思维方\n法，帮助我自己避免犯一些我这个年龄段的人容易犯的大错；（2）将这些思维\n方法传授给少数几个由于已经差不多了解了我说的内容而能够轻松地向我学习\n的人。这两个小小的目标我算是完成得很好了，所以看到世人如此不智，倒也没\n什么好抱怨的。我把用来对付失望的最佳方法称为犹太人的方法：那就是幽默。  \n \n        当我 2006 年 3 月重读第三篇演讲稿的时候，我仍然喜欢我在\n演讲中强调的一点：应该尽可能地设计各种防止欺诈的制度，哪怕有些人的悲惨\n遭遇将会因此而得不到补偿。毕竟，一种让欺诈得到回报的制度将给社会造成很','2026-07-05 16:55:53.049000',0,2073692323954429952,430,2073692323514028032),(2073692328379420682,'演讲中强调的一点：应该尽可能地设计各种防止欺诈的制度，哪怕有些人的悲惨\n遭遇将会因此而得不到补偿。毕竟，一种让欺诈得到回报的制度将给社会造成很\n大的破坏，因为糟糕的行为会成为被效仿的榜样，形成一种非常难以消除的社会\n风气。  \n \n        我很温馨地回想起我在第三篇演讲稿中强调的另外两点：从我\n父亲的朋友格兰特·麦克费登身上学到的为人处世之道，以及从我父亲身上学到\n的一种教学方法。对这两位谢世已久的先人，我欠他们很多，如果你们喜欢《穷\n查理宝典》，那么你们也是。  \n \n        在这篇演讲稿中， 查理逐步向我们解释如何通过各种“思维\n模型”进行决策和解决问题。他巧妙地问听众如何白手起家，创办一个资产高达\n2万亿美元的财富，并用可口可乐作为经典案例给出了答案。当然，他的方法很\n独特，它的巧妙和明智将会让你们震惊。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,431,2073692323514028032),(2073692328379420683,'2万亿美元的财富，并用可口可乐作为经典案例给出了答案。当然，他的方法很\n独特，它的巧妙和明智将会让你们震惊。  \n \n        谈完这个案例之后， 查理接着讨论了高等教育的失败，以及\n它在培养决策者方面不尽如人意的历史。关于这个问题，他有其他解决方法。  \n \n        这次演讲是于 1996 年在一个不对外公开的场合发表的。  \n \n        查理建议编者提醒你们： 大多数人并不理解这篇讲稿。查理\n说这次演讲极其失败，而且人们之后发现这篇演讲很难懂，甚至将演讲稿仔细读\n过两遍之后还是觉得很费解。在查理看来， 这些结果有着“微妙的教育意义”。 \n \n第十一讲：人类误判心理学 \n \n \n查理将三次演讲的内容合并起来，写成一篇从来没有发布过的讲稿，2005 年又\n进行了修订，增加了大量新的材料。 \n \n       这三次演讲分别是：  ','2026-07-05 16:55:53.049000',0,2073692323954429952,432,2073692323514028032),(2073692328379420684,' \n \n查理将三次演讲的内容合并起来，写成一篇从来没有发布过的讲稿，2005 年又\n进行了修订，增加了大量新的材料。 \n \n       这三次演讲分别是：  \n       1. 1992 年 2 月 2日，在加州理工学院教职员俱乐部布雷（Bray）\n讲座上的演讲；  \n       2. 1994 年 10 月 6 日，受剑桥行为研究中心邀请，在哈佛大学\n教职员俱乐部发表的演讲；  \n       3. 1995 年 4 月 24 日，受剑桥行为研究中心邀请，在波士顿港\n酒店发表的演讲。  \n \n        2005 年，在没有任何研究助理的情况下，查理全凭记忆，对\n这篇讲稿作了大刀阔斧的修改。查理认为 81 岁的他能够比 10 年前做得更好，原\n因有两个：1. 当时他的知识没有如今丰富，而且当时因为生活的忙碌而过于匆','2026-07-05 16:55:53.049000',0,2073692323954429952,433,2073692323514028032),(2073692328379420685,'这篇讲稿作了大刀阔斧的修改。查理认为 81 岁的他能够比 10 年前做得更好，原\n因有两个：1. 当时他的知识没有如今丰富，而且当时因为生活的忙碌而过于匆\n忙定稿；2. 当时他是依据粗略的笔记进行演讲，而现在是对讲稿进行修改。 \n前言 \n \n \n       当我阅读我在 15 年前做过的心理学讲座的讲稿时，我觉得我\n现在可以写一篇逻辑性更强但是篇幅也更长的“讲稿”，将我以前讲过的大部分\n内容都囊括在内。  \n \n        但我立刻发现这么做有四个缺点。  \n \n        第一，由于我在撰写这篇更长的“讲稿”时更为追求逻辑的完\n整性，所以在许多人看来，和早前的讲稿相比，它会显得更加枯燥和难懂。这是\n因为我给那些心理倾向所下的定义会让人想起心理学教科书和欧几里德。谁会在\n阅读教科书或者重读欧几里德中找到乐趣呢？  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,434,2073692323514028032),(2073692328379420686,'因为我给那些心理倾向所下的定义会让人想起心理学教科书和欧几里德。谁会在\n阅读教科书或者重读欧几里德中找到乐趣呢？  \n \n        第二，我只在 15 年前浏览过三本心理学教材，我对正式的心\n理学的了解就这么多，所以后来学院派心理学取得了什么进展我基本上是不了解\n的。然而，在这篇更长的讲稿中，我将会对学院派心理学提出许多批评。这种班\n门弄斧的做法肯定会引起许多心理学教授的反感， 若是发现我有错误之处， 他\n们将会非常高兴，说不定还会写文章来批评我，以此回应我对他们的批评。我为\n什么会在意新的批评呢？嗯，谁喜欢与那些拥有信息优势的尖锐批评家结下新的\n梁子呢？  \n \n        第三，这篇更长的文章肯定会让某些本来喜欢我的人感到不\n满。他们不但会对我的文风和内容提出异议，而且还会觉得我是个目中无人的老\n头，对传统的智慧不够尊敬，“大言不惭”地谈论一门他从来没有上过课的学科。','2026-07-05 16:55:53.049000',0,2073692323954429952,435,2073692323514028032),(2073692328379420687,'满。他们不但会对我的文风和内容提出异议，而且还会觉得我是个目中无人的老\n头，对传统的智慧不够尊敬，“大言不惭”地谈论一门他从来没有上过课的学科。\n我在哈佛大学法学院的老同学艾德·罗思柴尔德（Ed Rothschild）总是把这种\n大言不惭称为“鞋扣情结”。这个名字来自他的一位世交，那人在鞋扣行业取得\n领先地位之后，不管聊到什么话题总是一副无所不知的口气。  \n \n        第四，我也许会让自己显得像个傻瓜。  \n \n        尽管考虑到这四个缺点，我还是决定发表这篇内容增加甚多的\n文章。这几十年来，我基本上只做那些我有把握能够做好的工作和事情，而现在\n我却选择了这样的行动，它非但不会给我个人带来重大的好处，而且有可能让我\n的亲人和朋友感到痛苦，更有可能让我自己丢人现眼。我到底为什么要这样做\n呢？  \n \n        这也许跟我的性格有关，我向来喜欢指出和谈论传统智慧中的','2026-07-05 16:55:53.049000',0,2073692323954429952,436,2073692323514028032),(2073692328379420688,'的亲人和朋友感到痛苦，更有可能让我自己丢人现眼。我到底为什么要这样做\n呢？  \n \n        这也许跟我的性格有关，我向来喜欢指出和谈论传统智慧中的\n错误。虽然这些年来我因为这种脾气而吃了不少苦头，但是江山易改，本性难移，\n我并没有因为吃了生活中的苦头而改掉自以为是的性格。  \n \n        我作出这个决定的第二个原因是，我赞成第欧根尼（Diogenes）\n的说法。第欧根尼说过：“从来不得罪人的哲学家有什么用呢？”  \n \n        第三个原因是最重要的。我爱上了我这种编排心理学知识的方\n法，因为它一直以来对我很有用。所以呢，在去世之前，我想在某种程度上效仿\n三位人物，给世人留点东西。这三位人物分别是：约翰·班扬的《天路历程》的\n主角、本杰明·富兰克林，以及我的第一位雇主恩尼斯特·巴菲特。班扬笔下的\n人物，也就是那位外号“真理剑客”的骑士，在临终时留下了这样的遗嘱：“我','2026-07-05 16:55:53.049000',0,2073692323954429952,437,2073692323514028032),(2073692328379420689,'主角、本杰明·富兰克林，以及我的第一位雇主恩尼斯特·巴菲特。班扬笔下的\n人物，也就是那位外号“真理剑客”的骑士，在临终时留下了这样的遗嘱：“我\n的剑留给能挥舞它的人。”跟这个人一样，只要我曾经试图正确地对待我的剑，\n我并不在乎我对它的赞美是对还是错，也不在乎许多人并不愿意使用它，或者使\n用之后发现它对他们来讲完全没有用。对我帮助极大的本杰明·富兰克林给世人\n留下了他的自传——《穷理查年鉴》——和其他许多东西。恩尼斯特·巴菲特也\n尽他最大的努力，同样留下了“如何经营杂货店（的知识），以及我了解的一些\n垂钓知识”。他的遗赠发挥的作用是不是最大，我在这里就不说啦。但我想告诉\n大家的是，我认识恩尼斯特·巴菲特的四代后裔，我对他们的了解促使我决定效\n仿他们的先人。 \n人类误判心理学 \n \n \n       我早就对标准的思维错误非常感兴趣。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,438,2073692323514028032),(2073692328379420690,'仿他们的先人。 \n人类误判心理学 \n \n \n       我早就对标准的思维错误非常感兴趣。  \n \n        然而，在我受教育的年代，非临床心理学在理解错误判断方面\n的贡献完全遭到了主流社会精英的漠视。当时对心理学进行研究的人非常少，只\n有一群自娱自乐的教授。这种固步自封的情况自然会造成许多缺陷。  \n \n        所以呢，当我从加州理工学院和哈佛大学法学院毕业的时候，\n我对心理学是完全无知的。这些教育机构并没有要求学生掌握这门学科。它们根\n本就不了解心理学，当然更无法将心理学和其他学科整合起来。此外，这些机构\n就像尼采笔下那个以瘸腿为傲的人物，它们为能刻意避开“混乱的”心理学和\n“混乱的”心理学教授而感到光荣。  \n \n        在很长一段时间里，我也持有这种无知的想法。其他许多人也\n是。例如，加州理工学院常年只有一位心理学教授，他自称“心理分析研究教','2026-07-05 16:55:53.049000',0,2073692323954429952,439,2073692323514028032),(2073692328379420691,' \n        在很长一段时间里，我也持有这种无知的想法。其他许多人也\n是。例如，加州理工学院常年只有一位心理学教授，他自称“心理分析研究教\n授”，为学生开设“变态心理学”和“文学中的心理分析”，看到这样的情况，\n我们会怎么想呢？  \n \n        离开哈佛不久，我开始了漫长的奋斗，努力去掌握一些最有用\n的心理学知识。今天，我想要描述我这次追求基本智慧的漫长奋斗，并简要地说\n出我最终的心得。之后，我将会举例——其中许多例子在我看来是形象而有趣的\n——说明心理学知识的用处，以及如何解决那些跟人类的心理相关的问题。最后\n我将针对我讲过的内容提出一些普遍问题，并进行回答。这将会是一次很长的演\n讲。  \n \n        当我开始当律师的时候，我很相信基因进化论，也知道人类与\n认知能力较为低下的动物和昆虫之间有许多相似之处，这是物种进化造成的。我','2026-07-05 16:55:53.049000',0,2073692323954429952,440,2073692323514028032),(2073692328379420692,'讲。  \n \n        当我开始当律师的时候，我很相信基因进化论，也知道人类与\n认知能力较为低下的动物和昆虫之间有许多相似之处，这是物种进化造成的。我\n明白人是“社会动物”，他会观察周围人们的各种行为，并自动地受到他们的影\n响。我还知道人类就像被驯养的动物和猴子，也生活在一种等级结构中，他倾向\n于尊重当权者，喜欢和同阶层的成员合作，同时对处于下层并与之竞争的人表现\n出极大的不信任和不喜欢。  \n \n        但这种以进化论为基础的理论结构太过粗略，不足以让我正确\n地应付我在现实生活中遇到的问题。很快，我发现自己身边出现了各种我无法理\n解的现象。于是我终于明白，若要顺利地解决我在生活中遇到的各种问题，我必\n须拥有更好的理论结构，这样才能够解释我的所见和经验。那时，我渴望更多理\n论的历史已经很长了。这部分是因为，我总是喜欢把理论当作破解难题的工具和','2026-07-05 16:55:53.049000',0,2073692323954429952,441,2073692323514028032),(2073692328379420693,'须拥有更好的理论结构，这样才能够解释我的所见和经验。那时，我渴望更多理\n论的历史已经很长了。这部分是因为，我总是喜欢把理论当作破解难题的工具和\n满足我那像猴子般的好奇心的手段；部分是因为，我发现理论结构非常有用，能\n够帮助人们得到他们想要的东西。这个道理是我小时候在学校发现的，当时我在\n理论的指导之下，轻轻松松地取得了好成绩，而其他许多人由于没有掌握理论，\n花了很大力气去学习，却总是不及格。我认为更好的理论对我来说总是有用的，\n如果我能掌握它，就能够更快地获得财富和独立，能够更好地帮助我所热爱的一\n切。所以我慢慢地培养了我自己的心理学体系。在这个过程当中，我靠的是自学，\n这多少有点像本杰明·富兰克林，还有那个保育院故事展现出来的决心：“‘那\n我就自己来吧。’小红母鸡说。”  \n \n        在我追求知识的过程中，有两种思维习惯起到了很大的作用。','2026-07-05 16:55:53.049000',0,2073692323954429952,442,2073692323514028032),(2073692328383614976,'我就自己来吧。’小红母鸡说。”  \n \n        在我追求知识的过程中，有两种思维习惯起到了很大的作用。\n第一，我总是试图通过伟大的代数学家雅各比提倡的逆向思维来考虑问题。雅各\n比说：“反过来想，总是反过来想。”我得到正确判断的办法，通常是先收集各\n种错误判断的例子，然后仔细考虑该怎样避免得到这些下场。第二，我非常热衷\n于收集错误判断的例子，所以我完全无视不同行业、不同学科之间的界线。毕竟，\n既然其他行业有许多重大的、容易发现的愚蠢事例，我为什么还要在自己的领地\n上搜寻某些无足轻重的、难以发现的新蠢事呢？除此之外，我已经明白，现实世\n界的问题不会恰好落在某个学科的界线之内。它们跨越了界线。如果两种事物存\n在密不可分的相互关系，我认为那种试图考虑其中一种事物而无视另一种事物的\n方法是很值得怀疑的。我担心的是，如果我试图用这种方法去解决问题，最终我','2026-07-05 16:55:53.049000',0,2073692323954429952,443,2073692323514028032),(2073692328383614977,'在密不可分的相互关系，我认为那种试图考虑其中一种事物而无视另一种事物的\n方法是很值得怀疑的。我担心的是，如果我试图用这种方法去解决问题，最终我\n将会——用约翰·刘易斯（John L. Lewis）的不朽名言来说——“没有脑袋，\n只有一个顶上长着头发的脖子。”  \n \n        后来，纯粹的好奇心驱使我去思考邪教的问题，那些毁形灭性\n的邪教通常只需要一个长周末就能够将完全正常的人转变为被洗过脑的行尸走\n肉，并永远让他们保持那种状态，它们是怎么做到的呢？原因是什么呢？我觉得\n如果我通过大量的阅读和反复的思考，应该能够完满地解决这个关于邪教的问\n题。 \n  我也对社会性的昆虫很好奇。有生育能力的雌蜂和有生育能力的雌收获蚁的\n寿命相差很多，但它们只要在空中进行一次群交，就都能将寿命延长整整 20 倍。\n我对这样的事情感到着迷。蚂蚁的极大成功也让我着迷——蚂蚁的进化极其成','2026-07-05 16:55:53.049000',0,2073692323954429952,444,2073692323514028032),(2073692328383614978,'寿命相差很多，但它们只要在空中进行一次群交，就都能将寿命延长整整 20 倍。\n我对这样的事情感到着迷。蚂蚁的极大成功也让我着迷——蚂蚁的进化极其成\n功，它们形成了几种简单的行为规范：繁殖群体之内的蚂蚁精诚无间地合作，而\n对繁殖群体之外的蚂蚁，哪怕是同类的蚂蚁，则几乎总是表现出致命的敌意。  \n \n        像我这么热爱学习的人，到了中年本来应该翻开心理学教材，但是我没有，\n这证明了那句德国谚语所言非虚：“我们老得太快，聪明得太迟。”后来我发现，\n没有接触到当时大多数教科书上记载的学院派心理学，对我来说可能是件幸运的\n事情。那些教科书无助于我理解邪教，而那些收集心理实验的教科书作者就像收\n集蝴蝶标本的小男孩——他只想收集更多的蝴蝶，和其他收集者有更多的接触，\n根本不想对已经拥有的标本进行综合研究。当我最终看到那些心理学教科书的时','2026-07-05 16:55:53.049000',0,2073692323954429952,445,2073692323514028032),(2073692328383614979,'集蝴蝶标本的小男孩——他只想收集更多的蝴蝶，和其他收集者有更多的接触，\n根本不想对已经拥有的标本进行综合研究。当我最终看到那些心理学教科书的时\n候，我想起了伟大的经济学家雅各布·维纳（Jacob Viner）说过的一句话。他说许\n多学者就像寻菇犬，人们喂养和训练这种动物来寻找地下的块菌，除了这项专长，\n它别的什么都不会。那些教科书花了长达数百页的篇幅来探讨先天因素和后天因\n素对人的影响，可是它们所用的思考方式是极其不科学的，这也让我很吃惊。我\n发现大多数入门级的心理学教科书并没有正确地处理一个基本问题：心理倾向为\n数众多，而且它们在生活中会产生相互影响。但那些入门级教材的作者通常对如\n何弄清楚相互交织的心理倾向造成的复杂后果避而不谈。这有可能是因为那些作\n者不希望把教材写得太复杂，以免没有新人敢投身于他们的学科。他们做得不够','2026-07-05 16:55:53.049000',0,2073692323954429952,446,2073692323514028032),(2073692328383614980,'何弄清楚相互交织的心理倾向造成的复杂后果避而不谈。这有可能是因为那些作\n者不希望把教材写得太复杂，以免没有新人敢投身于他们的学科。他们做得不够\n好，也有可能是出于塞缪尔·约翰逊说过的原因。曾经有位女士问约翰逊，是什\n么原因导致他的词典把“pastern”（马蹄腕）这个词的定义给弄错了。  \n \n        约翰逊的回答是：“纯粹的无知。”最后，那些教科书作者也没有兴趣去描写\n该用哪些标准的办法去对付由心理因素造成的标准蠢事，所以他们恰恰避开了我\n最感兴趣的话题。  \n \n        学院派心理学虽然有许多缺点，但也有一些非常重要的优点。我在博览群书\n的过程中看到一本叫做《影响力》（Influence）的书。这是一本通俗读物，作者\n是一位杰出的心理学教授，罗伯特·西奥迪尼（Robert Cialdini），他在规模很大的','2026-07-05 16:55:53.049000',0,2073692323954429952,447,2073692323514028032),(2073692328383614981,'是一位杰出的心理学教授，罗伯特·西奥迪尼（Robert Cialdini），他在规模很大的\n亚利桑那州立大学任教。西奥迪尼设计大量巧妙的实验，在实验中，人们利用人\n类思维中内在的缺陷，操纵别人做出了损害自身利益的事情。西奥迪尼对这些实\n验进行了描述和解释，并因此在非常年轻的时候就荣任终身董事讲座教授。  \n \n        我立刻给我的每个孩子寄了一本西奥迪尼的著作。我还送给西奥迪尼一股伯\n克希尔的 A 级股票（2010 年 3 月的市值大约为 12 万 2000 美元——译者注），感\n谢他为我和公众作出的贡献。西奥迪尼这本社会心理学著作卖出了几十万册，这\n是很了不起的，因为西奥迪尼并没有宣称他的书将会改善你的性生活或者让你发\n财。  \n \n        许多读者购买西奥迪尼这本书是因为他们跟我一样，也想知道怎样才能不经','2026-07-05 16:55:53.049000',0,2073692323954429952,448,2073692323514028032),(2073692328383614982,'财。  \n \n        许多读者购买西奥迪尼这本书是因为他们跟我一样，也想知道怎样才能不经\n常被推销员和环境欺骗。然而，令非常正直的西奥迪尼意想不到的是，大量的销\n售员也买了他的书，他们想要了解怎样才能更有效地误导顾客。下面我会讲到激\n励机制引起的偏见，我希望不会有人将我的理论用于变态的目的。  \n \n        在西奥迪尼这本书的驱动之下，我很快浏览了三本最流行的心理学入门教\n材。在此期间，我还进行了周全的考虑，想把我以前的训练和经验综合起来。芒\n格的非临床、非先天后天对立的非发展心理学就这样诞生了。许多理论是从它们\n的发现者（其中大多数人的名字我甚至还不知道）那里借用来的，但我通常会给\n它们配上新的表述和标题。因为我没有去查证资料，而是怎样容易回忆起来就怎\n么写，然后再进行修改，以便我能够很方便地使用这些理论来避免错误。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,449,2073692323514028032),(2073692328383614983,'它们配上新的表述和标题。因为我没有去查证资料，而是怎样容易回忆起来就怎\n么写，然后再进行修改，以便我能够很方便地使用这些理论来避免错误。  \n \n        在开始综述我的理论之前，我想先来讲一个有助于理解以下内容的普遍观\n点。这个观点是从我们对社会性昆虫的了解中提炼出来的。这些昆虫很漂亮地证\n明了神经系统细胞在进化过程中固有的局限，它们整个神经系统通常只有 10 万\n个左右的细胞，而人类光是大脑的细胞就有上百亿个。  \n \n        蚂蚁和人类相同，都是由活体结构加上神经细胞中的行为程序组成的。就蚂\n蚁而言，其行为程序只有少数几种，而且几乎完全来自遗传。蚂蚁能够根据经验\n学到新的行为，但大多数时候，它只能根据遗传的神经系统中设定好的程序，对\n十种左右的神经刺激作出几个简单的反应。 \n  蚂蚁简单的行为系统自然有很大的局限，因为它的神经系统的功能很有限。','2026-07-05 16:55:53.049000',0,2073692323954429952,450,2073692323514028032),(2073692328383614984,'十种左右的神经刺激作出几个简单的反应。 \n  蚂蚁简单的行为系统自然有很大的局限，因为它的神经系统的功能很有限。\n例如，有一种蚂蚁，当它在巢穴里嗅到蚂蚁尸体散发出的外激素时，它就会和其\n他蚂蚁合作把尸体运出巢穴。伟大的哈佛大学教授 E. O. 威尔逊（E. O.Wilson）\n做过一个非常出色的心理学实验，他将死蚂蚁分泌的外激素涂在一只活蚂蚁身\n上。很自然，其他蚂蚁把这只有用的活蚂蚁拖出了巢穴，尽管它在整个过程中不\n断地踢腿和挣扎。这就是蚂蚁的大脑。它拥有的反应程序特别简单，平时运转是\n没有问题的，但在许多情况下，蚂蚁只会生搬硬套地根据这个程序作出机械反应。  \n \n        另一种蚂蚁证明，蚂蚁有限的大脑不但容易受环境欺骗，而且还会遭到其他\n生物的操控。这种蚂蚁的大脑里面包含了一种简单的行为程序，引导蚂蚁在爬行\n的时候跟着前方的蚂蚁走。如果在这种蚂蚁爬行时把它们弄成一个圆圈，它们有','2026-07-05 16:55:53.049000',0,2073692323954429952,451,2073692323514028032),(2073692328383614985,'生物的操控。这种蚂蚁的大脑里面包含了一种简单的行为程序，引导蚂蚁在爬行\n的时候跟着前方的蚂蚁走。如果在这种蚂蚁爬行时把它们弄成一个圆圈，它们有\n时候会不停地走啊走，直到死亡为止。  \n \n        有一个我看来很明显的道理是：由于存在许多过度简化的思维程序，人类大\n脑的运转必定常常出现问题，就像蚂蚁的大脑那样，尽管它试图解决的问题通常\n比那些无需设计飞机的蚂蚁面对的问题困难得多。  \n \n        人类的知觉系统清楚地证明了大脑确实会失灵。人是很容易受到愚弄的，无\n论是人类精心设计的骗局，还是偶然出现的环境因素，抑或人们刻苦练习而掌握\n的非常有效的控制术，都能够轻而易举地让人们上当。导致这种结果的原因之一\n是人类感知中的微量效应。如果刺激被维持在一定水平之下，人类便察觉不到它\n的存在。由于这个原因，魔术师能够在黑暗中做一通虚张声势的动作之后让自由','2026-07-05 16:55:53.049000',0,2073692323954429952,452,2073692323514028032),(2073692328383614986,'是人类感知中的微量效应。如果刺激被维持在一定水平之下，人类便察觉不到它\n的存在。由于这个原因，魔术师能够在黑暗中做一通虚张声势的动作之后让自由\n女神像消失。观众并不知道他们坐在一个慢慢旋转的平台之上。这个平台转得非\n常慢，没有人能够察觉出来。当平台上的帘幕在原来自由女神像出现的地方掀开\n时，它看起来像是不见了。  \n \n        人类的大脑即使在有所知觉的时候，也会错误地估量它感知到的东西，因为\n大脑只能感知到鲜明的对比，而无法像精密的科学仪器那样以科学的单位来估算\n感知的变化。  \n \n        魔术师证明人类神经系统确实会因为这种对比而出现错误。魔术师能够在你\n毫不察觉的情况下摘掉你的手表。他摘你的手表时，如果他只跟你的手腕发生接\n触，那么你肯定会感知到手表被他摘掉了。但他同时还触碰了你身体的其他地方，','2026-07-05 16:55:53.049000',0,2073692323954429952,453,2073692323514028032),(2073692328383614987,'毫不察觉的情况下摘掉你的手表。他摘你的手表时，如果他只跟你的手腕发生接\n触，那么你肯定会感知到手表被他摘掉了。但他同时还触碰了你身体的其他地方，\n而且通过施加更大的力道把你手腕感受到的力道给“淹没”了。这种高对比让你感\n觉不到手腕受到的力道。  \n \n        有些教授喜欢用实验来证明对比引起的感知缺陷。他们会让学生把一只手放\n在一桶热水里，另外一只手伸进一桶冷水。然后他们会突然要求学生把双手放进\n一桶常温的水中。学生虽然两只手是放在同一桶水里面，但一只手感觉好像刚放\n进冷水，一只手感觉好像刚放进热水。当人们发现在温度计不会出错的地方，单\n纯的对比就能轻易地让感知受骗，并意识到认知和感知是相同的，也会受到单纯\n的反差的欺骗，那么他不但能够懂得魔术师是如何愚弄人们的，还能明白生活是\n如何作弄人的。人类的感知和认知系统中那些总体上很有用的倾向往往会出错，','2026-07-05 16:55:53.049000',0,2073692323954429952,454,2073692323514028032),(2073692328383614988,'的反差的欺骗，那么他不但能够懂得魔术师是如何愚弄人们的，还能明白生活是\n如何作弄人的。人类的感知和认知系统中那些总体上很有用的倾向往往会出错，\n如果不对此加以小心提防，就会很容易受到别人故意的操控。  \n \n        人类的——经常出错但总体上很有用——心理倾向相当多，而且相当不同。\n大量的心理倾向的自然结果就是社会心理学的重要原理：认知往往取决于情景，\n所以不同的情景通常会引起不同的结论，哪怕是同一个人在思考同一个问题的时\n候也是如此。  \n \n        有了蚂蚁、魔术师和这条社会心理学的重要原理做铺垫，接下来我想简单地\n列出那些虽然总体上很有用但经常误导人的心理倾向。后面我们再来详细讨论每\n种倾向引发的错误，同时描述如何防止犯这样的错误，并进行一些总体的讨论。\n以下是这些倾向：  \n一、奖励和惩罚 超级反应倾向 \n二、喜欢/热爱倾向 \n三、讨厌/憎恨倾向 ','2026-07-05 16:55:53.049000',0,2073692323954429952,455,2073692323514028032),(2073692328383614989,'以下是这些倾向：  \n一、奖励和惩罚 超级反应倾向 \n二、喜欢/热爱倾向 \n三、讨厌/憎恨倾向 \n四、避免怀疑倾向 \n五、避免不一致性倾向 \n六、好奇心倾向 \n七、康德式公平倾向 \n八、艳羡/妒忌倾向 \n九、回馈倾向 \n十、受简单联想影响的倾向 \n十一、简单的、避免痛苦的心理否认 \n十二、自视过高的倾向 \n十三、过度乐观倾向 \n十四、被剥夺超级反应倾向 \n十五、社会认同倾向 \n十六、对比错误反应倾向 \n十七、压力影响倾向 \n十八、错误衡量易得性倾向 \n十九、不用就忘倾向 \n二十、化学物质错误影响倾向 \n二十一、衰老—错误影响倾向 \n二十二、权威—错误影响倾向 \n二十三、废话倾向 \n二十四、重视理由倾向 \n二十五、lollapalooza 倾向——数种心理倾 \n向共同作用造成极端后果的倾向 \n一 奖励和惩罚 超级反应倾向 \n \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,456,2073692323514028032),(2073692328383614990,'二十四、重视理由倾向 \n二十五、lollapalooza 倾向——数种心理倾 \n向共同作用造成极端后果的倾向 \n一 奖励和惩罚 超级反应倾向 \n \n \n       我最先讨论这个倾向，是因为每个人都以为自己完全明白激励\n机制和惩罚机制在改变认知和行为方面有多么重要。但其实往往不是这样子的。\n例如，我觉得自我成年以来，在理解激励机制的威力方面，我比 95%的同龄人要\n好，然而我总是低估那种威力。每年总会有些意想不到的事情，促使我对激励机\n制的超级威力有更深的体会。  \n \n        说到激励机制的威力，在所有案例中，我最欣赏的是联邦快递\n的案例。联邦快递系统的核心和灵魂是保证货物按时送达，它必须在三更半夜让\n所有的飞机集中到一个地方，然后把货物快速转发到各架飞机上。如果哪个环节\n出现了延误，联邦快递就无法把货物及时地送到客户手里。曾经有一段时间，联','2026-07-05 16:55:53.049000',0,2073692323954429952,457,2073692323514028032),(2073692328383614991,'所有的飞机集中到一个地方，然后把货物快速转发到各架飞机上。如果哪个环节\n出现了延误，联邦快递就无法把货物及时地送到客户手里。曾经有一段时间，联\n邦快递的夜班工人总是不能按时完成工作。他们对工人动之以情、晓之以理。他\n们尝试了各种各样的方法，但就是没效果。最后有个人终于想通了：公司并不希\n望职员工作的时间越长越好，而是希望他们快速地、无差错地完成某项任务，所\n以按照小时来支付夜班薪水的做法是很傻的。也许，这个人想，如果他们按照班\n次来支付薪水，并允许夜班工人在把所有货物装上飞机之后提前回家，那么这个\n系统会运转得更好。你瞧，这种方法果然奏效了。  \n \n        施乐公司（Xerox Corporation）早期的时候，乔·威尔逊（注：\n乔·威尔逊，1909—1971，美国施乐公司创办人、慈善家）也遇到了相同的问题。','2026-07-05 16:55:53.049000',0,2073692323954429952,458,2073692323514028032),(2073692328383614992,'乔·威尔逊，1909—1971，美国施乐公司创办人、慈善家）也遇到了相同的问题。\n他那时已离开公司进入政府部门，但不得不辞职又回到施乐公司，因为他无法理\n解为什么施乐的新机器总是卖得不如那些性能低下的旧机器好。回到施乐之后，\n他发现根据公司和销售员签署的销售提成协议，把旧机器卖给客户，销售员能得\n到很高的提成；在这种变态激励机制的推动下，劣等的旧机器当然卖得更好。  \n \n        然后还有马克·吐温那只猫的案例。那只猫被热火炉烫过之\n后，再也不愿意坐在火炉上了，不管火炉是热的还是冷的。  \n \n        我们还应该听取本杰明·富兰克林的建议。富兰克林在《穷理\n查年鉴》中说过：“如果你想要说服别人，要诉诸利益，而非诉诸理性。”这句\n睿智的箴言引导人们在生活中掌握一个重要而简单的道理：当你该考虑动用激励\n机制的威力时，千万千万别考虑其他的。我认识一个非常聪明的法律顾问，他在','2026-07-05 16:55:53.049000',0,2073692323954429952,459,2073692323514028032),(2073692328383614993,'睿智的箴言引导人们在生活中掌握一个重要而简单的道理：当你该考虑动用激励\n机制的威力时，千万千万别考虑其他的。我认识一个非常聪明的法律顾问，他在\n一家大型投资银行任职，从来没犯错，却丢失了工作，因为他忽略了富兰克林这\n句箴言中蕴含的教训。这位顾问没能成功地说服其客户。这位顾问对客户说，你\n有道德责任去做某件事，在这一点上，顾问是正确的。可是他没有告诉客户的是，\n如果不按照他的建议去做，客户将会陷入万劫不复之地。结果，这位顾问和他的\n客户都丢掉了工作。  \n \n        我们还应该记得苏联共产党得到的下场。苏联共产党对激励机\n制的超级威力完全无知，结果造成什么情况呢？有个苏联工人这么说：“他们假\n装给薪水，我们假装在工作。”也许最重要的管理原则就是，“制定正确的激励\n机制。”  \n \n        但是太过强调激励机制的超级威力也有缺陷。哈佛大学的心理','2026-07-05 16:55:53.049000',0,2073692323954429952,460,2073692323514028032),(2073692328383614994,'装给薪水，我们假装在工作。”也许最重要的管理原则就是，“制定正确的激励\n机制。”  \n \n        但是太过强调激励机制的超级威力也有缺陷。哈佛大学的心理\n学教授 B. F. 斯金纳就因为过度强调激励机制而闹了笑话。斯金纳曾经是世界\n上最著名的心理学教授。他能够取得这种如日中天的地位，部分原因在于，他早\n年别出心裁地利用老鼠和鸽子做实验，得出了令人意外的重要结果。和其他方法\n相比，他利用的激励法能够引发更多的行为变化，也能够更有成效地让他的老鼠\n和鸽子养成条件反射。他揭示，奖励儿童或者员工已经厌倦的行为是极其愚蠢的。\n利用食物作奖励，他甚至如愿以偿地让他的鸽子养成了强烈的迷信。他再三证明\n自然界存在一种重复出现的、普遍的伟大行为算法：“重复有效的行为”。他还\n证明即时的回报在改变和延续行为方面远远比延后的回报有效。他的老鼠和鸽子','2026-07-05 16:55:53.049000',0,2073692323954429952,461,2073692323514028032),(2073692328383614995,'自然界存在一种重复出现的、普遍的伟大行为算法：“重复有效的行为”。他还\n证明即时的回报在改变和延续行为方面远远比延后的回报有效。他的老鼠和鸽子\n在食物奖励的作用下养成条件反射之后，他发现了那种能够使反射行为保持最长\n时间的奖励撤销模式：随机分布模式。得到这个研究结果的斯金纳认为他已经完\n全能够解释人类明知道十赌九输却还是忍不住要赌博的原因了。但是，正如我们\n在后面讨论其他导致滥赌行为的心理倾向时将会发现的，斯金纳只说对了一部\n分。斯金纳的个人声誉后来江河日下，是因为一来，他过度地强调了激励机制的\n超级威力，乃至认为利用激励机制就能够创建出一个人间乌托邦；二来，他几乎\n没有认识到心理学其他部分的威力。因而他就像雅各布·维纳的寻菇犬，只会用\n激励效应来解释一切。但话又说回来，斯金纳的主要观点是正确的：激励机制是\n超级有用的。他那些基本实验的结果将会在实验科学的史册上流芳千古。在他死','2026-07-05 16:55:53.049000',0,2073692323954429952,462,2073692323514028032),(2073692328383614996,'激励效应来解释一切。但话又说回来，斯金纳的主要观点是正确的：激励机制是\n超级有用的。他那些基本实验的结果将会在实验科学的史册上流芳千古。在他死\n后数十年里，他那种完全依赖奖励的方法在治疗儿童自闭症方面比其他任何疗法\n都有效。  \n \n        当我在哈佛大学法学院念书的时候，教授们有时会谈起耶鲁大\n学法学院某个像斯金纳那么死心眼的教授。他们常常说：“埃迪·布兰夏德这老\n兄真可怜，他还认为宣告式判决能够治疗癌症呢。”嗯，极其强调激励机制的超\n级威力的斯金纳跟这位耶鲁法学院的教授差不多。我总是把这种降低了斯金纳声\n誉的思维习惯称为“铁锤人倾向”，因为有句谚语说：“在只有铁锤的人看来，\n所有问题都特别像钉子。”“铁锤人倾向”并没有放过布兰夏德和斯金纳这么聪\n明的人。如果你们不注意的话，它也不会放过你们。在这篇讲稿中，我将会好几','2026-07-05 16:55:53.049000',0,2073692323954429952,463,2073692323514028032),(2073692328383614997,'所有问题都特别像钉子。”“铁锤人倾向”并没有放过布兰夏德和斯金纳这么聪\n明的人。如果你们不注意的话，它也不会放过你们。在这篇讲稿中，我将会好几\n次提到“铁锤人倾向”，因为正好有一些办法能够有效地减少这种令斯金纳教授\n声名扫地的心理倾向所造成的破坏。  \n \n        激励机制的超级威力所造成的一个重要后果就是我所说的\n“激励机制引起的偏见”。有的人因为受过教育而变得道德高尚，然而在激励机\n制的驱动之下，他可能会有意或者无意地做出一些不道德的行为，以便得到他想\n要的东西，而且他还会为自己的糟糕行为寻找借口，就像施乐公司那些为了得到\n最高提成而不惜损害顾客利益的销售员。  \n \n        我很早就学到这个道理。故事发生在我祖父的故乡，内布拉斯\n加州的林肯市。当地有个外科医生，他年复一年地将大量的正常胆囊送到该市最','2026-07-05 16:55:53.049000',0,2073692323954429952,464,2073692323514028032),(2073692328383614998,' \n        我很早就学到这个道理。故事发生在我祖父的故乡，内布拉斯\n加州的林肯市。当地有个外科医生，他年复一年地将大量的正常胆囊送到该市最\n好的医院的病理学实验室。众所周知，社区医院的管理体系很糟糕，所以这位医\n生如此乱来了许多年才被革除职务。那位负责开除这个人的医生是我们家的世\n交，我问他：“难道这名外科医生心里想，‘这么做能够展示我的医术很高\n明？’——这家伙手术做得非常好——‘而且每年通过把正常胆囊切掉来谋害\n几个病人能让我过上高质量的生活？’”我的朋友说：“不是这样子的啦，查理。\n他认为胆囊是所有疾病的祸根，而且如果你真的爱护病人，就应该尽快把这个器\n官切除掉。”  \n \n        这个例子很极端，但每个专业人士和每个普通人身上或多或少\n都会有这名外科医生的认知倾向。它能引发极其可怕的行为。就拿那些推销商业','2026-07-05 16:55:53.049000',0,2073692323954429952,465,2073692323514028032),(2073692328383614999,' \n        这个例子很极端，但每个专业人士和每个普通人身上或多或少\n都会有这名外科医生的认知倾向。它能引发极其可怕的行为。就拿那些推销商业\n地产和企业的经纪人来说吧。我从来没有见过一个哪怕稍稍客观的经纪人。在我\n这漫长的一生中，我遇到过的管理顾问没有不在他们的报告结束时写上这个相同\n的建议的：“这个问题需要更多的管理顾问服务。”由于激励机制引起的偏见非\n常普遍，所以人们往往必须怀疑或者有保留地接受其专业顾问的建议，哪怕这个\n顾问是一名工程师。一般的对策如下：（1）如果顾问提出的专业建议对他本身\n特别有利，你就应该特别害怕这些建议；（2）在和顾问打交道时，学习和使用\n你的顾问所在行业的基本知识；（3）复核、质疑或者更换你得到的建议，除非\n经过客观考虑之后这些建议看起来是合适的。  \n \n        激励机制能够导致人们在做坏事的时候觉得自己是正当的，国','2026-07-05 16:55:53.049000',0,2073692323954429952,466,2073692323514028032),(2073692328383615000,'经过客观考虑之后这些建议看起来是合适的。  \n \n        激励机制能够导致人们在做坏事的时候觉得自己是正当的，国\n防部的采购历史也证明了这一点。从前国防部采购时签署的都是成本保利合同\n（以成本再加一个比例的利润作价），而产生了许多贪污受贿的事情，这促使美\n国政府作出决定，国防部负责采购的官员签署这样的合同是违法的，而且犯的不\n是轻罪，是重罪。  \n \n        顺便说一声，虽然政府部门签署成本保利合同已经被正确地定\n为重罪，但其他地方，包括许多律师事务所和大量的企业，依然采用了一种成本\n保利的奖励系统。在这种普遍的激励模式之下，有些人受到激励机制引起的偏见\n的驱使，做出了许多极其可怕的事情。而这些行为不轨的人当中有许多原本正派\n得足让你们会很乐意和他们成为亲家。  \n \n        人类大脑就是以这种方式运转的，这里面蕴含着几个大道理。','2026-07-05 16:55:53.049000',0,2073692323954429952,467,2073692323514028032),(2073692328383615001,'得足让你们会很乐意和他们成为亲家。  \n \n        人类大脑就是以这种方式运转的，这里面蕴含着几个大道理。\n比如，收款机的发明能够使不诚实的行为难以得逞，所以它对文明社会作出了杰\n出的贡献。正如斯金纳十分清楚地知道的，得到奖励的坏行为特别容易形成习惯。\n所以收款机是一种伟大的道德工具。顺便说一下，收款机的发明者帕特森（John \nHenryPatterson）对此深有体会。他曾经拥有一家小商店，店里的员工经常趁他\n不注意的时候偷钱，所以他从来没赚到什么钱。后来有人卖给他两台收款机，他\n的商店马上开始盈利。他很快把商店关掉，进入了收款机行业。他创办的公司就\n是那家在当时叱咤风云的国民收款机公司。帕特森把“重复有效的行为”作为行\n为指南，获得了巨大的成功。帕特森的道德也很高尚。他脾气很古怪，但热衷于\n做善事（不过他对竞争对手冷酷无情，他把所有竞争对手都看做是潜在的专利盗','2026-07-05 16:55:53.049000',0,2073692323954429952,468,2073692323514028032),(2073692328383615002,'为指南，获得了巨大的成功。帕特森的道德也很高尚。他脾气很古怪，但热衷于\n做善事（不过他对竞争对手冷酷无情，他把所有竞争对手都看做是潜在的专利盗\n窃者）。帕特森的口头禅是“寿衣没有口袋”，他和卡内基一样，在离开人世之\n前，把大量的财产都捐作善款了。帕特森的收款机对文明的贡献非常巨大，他在\n改善和推广收款机方面所做的工作也非常有效，所以他很可能配得起罗马诗人贺\n拉斯（Horace）自撰的墓志铭：“我并没有彻底地死去。”  \n \n        由于职员存在这种为了获取回报而给糟糕的行为寻找正当理\n由的强烈倾向，所以除了帕特森发明的控制现金的手段之外，企业还需要其他许\n多对策。也许最重要的对策是采用合理的会计理论和会计实践。西屋电器\n（Westinghouse）的案例很好地证明了这一点。西屋电器属下有一家信贷公司，\n这家子公司放出了许多和西屋电气其他业务毫无关联的贷款。西屋电器的管理人','2026-07-05 16:55:53.049000',0,2073692323954429952,469,2073692323514028032),(2073692328383615003,'（Westinghouse）的案例很好地证明了这一点。西屋电器属下有一家信贷公司，\n这家子公司放出了许多和西屋电气其他业务毫无关联的贷款。西屋电器的管理人\n员也许是因为妒忌通用电气，所以想要从对外贷款中获取更多利润。西屋电器的\n会计实践是这样的，它主要根据从前为下属子公司提供贷款的经验来为这些对外\n贷款提取未来的贷款坏账准备金，而它原来贷款给子公司则不太可能出现巨额的\n贷款损失。  \n \n        有两类特殊的贷款理所当然地会给借款人造成大麻烦。第一类\n是面向房地产开发商的、贷款额为建设费用的 95%的贷款，第二类是面向酒店的\n建筑贷款。正常来讲呢，如果有人愿意按照酒店实际建筑成本的 95%贷款给开发\n商，那么贷款利率应该比一般利率高很多，因为贷款损失的风险比一般贷款高出\n很多。所以按照合理的会计方法，在发放大量占到实际建筑成本 95%的贷款给酒','2026-07-05 16:55:53.049000',0,2073692323954429952,470,2073692323514028032),(2073692328383615004,'商，那么贷款利率应该比一般利率高很多，因为贷款损失的风险比一般贷款高出\n很多。所以按照合理的会计方法，在发放大量占到实际建筑成本 95%的贷款给酒\n店开发商时，西屋电器应该在财务报表中将所有这些贷款记为零利润，甚至记为\n损失，直到许多年后把贷款收回来为止。但是西屋电器并没有这么做，而是把大\n量发放给酒店开发商的贷款等同于以前那些很少产生损失的贷款，把账做得很漂\n亮。这让负责放贷的管理人员显得很优秀，因为财务报表显示出那些对外贷款带\n来了极高的收入。国际和外部的会计师认可了西屋电器这种糟糕的做账方法，因\n为他们的所作所为就像那首老歌所唱的：“谁给我面包吃，我就给谁唱歌。”  \n \n        结果西屋电器损失了数十亿美元。这该怪谁呢？怪那个从电冰\n箱部门调到公司高层并突然决定贷款给酒店开发商的家伙吗？还是怪那些会计\n和其他高层管理人员？（他们对一种几乎肯定会使信贷管理人员产生偏激行为的','2026-07-05 16:55:53.049000',0,2073692323954429952,471,2073692323514028032),(2073692328383615005,'箱部门调到公司高层并突然决定贷款给酒店开发商的家伙吗？还是怪那些会计\n和其他高层管理人员？（他们对一种几乎肯定会使信贷管理人员产生偏激行为的\n激励机制坐视不管。）我认为最应该受到指责的是那些创造出这种会计系统的会\n计人员和其他高层管理人员。这些人的所作所为无异于运钞公司突然决定不用武\n装车辆押运现金，而改让手无寸铁的侏儒用敞开的篮子提着现金走过贫民窟。  \n \n        我希望我能够告诉你们，这种事情以后再也不会发生，但实际\n情况并非如此。在西屋电器东窗事发之后，通用电气旗下的投资银行基德尔·皮\n博迪（Kidder Peabody）采用了一种愚蠢的电脑程序，致使债券交易员能够利用\n这种程序虚构出巨额利润。从此以后，许多公司的会计工作变得更加糟糕了，也\n许最糟糕的例子就是安然（Enron）。  \n \n        所以激励机制引起的偏见是非常重要的，（我们也有很重要的','2026-07-05 16:55:53.049000',0,2073692323954429952,472,2073692323514028032),(2073692328383615006,'许最糟糕的例子就是安然（Enron）。  \n \n        所以激励机制引起的偏见是非常重要的，（我们也有很重要的\n对策），比如说收款机和合理的会计系统。但是当我在几年前翻阅心理学教科书\n的时候，我发现那些教科书虽然有 1000 页那么厚，却很少谈到激励机制引起的\n偏见，对帕特森或者合理的会计系统更是只字不提。反正不知道怎么回事，心理\n学的概论课程完全没有提到激励机制引起的偏见及其对策，尽管世界各地许多伟\n大的文学作品早就出色地描绘了激励机制引起的偏见，尽管企业界早就有了应付\n这种偏见的对策。到最后，我得出的结论是，如果有的事情在生活中极为明显，\n但很难通过容易做的、可重复的学术实验得到证明，那些心理学的寻菇犬就会忽\n略它。  \n \n        有时候，其他学科对各种心理倾向表现出的兴趣，至少比心理\n学教科书中体现的要浓厚。例如，那些站在雇主的立场考虑问题的经济学家早就','2026-07-05 16:55:53.049000',0,2073692323954429952,473,2073692323514028032),(2073692328383615007,'略它。  \n \n        有时候，其他学科对各种心理倾向表现出的兴趣，至少比心理\n学教科书中体现的要浓厚。例如，那些站在雇主的立场考虑问题的经济学家早就\n为激励机制引起的偏见所产生的后果取了一个名字：“代理成本”。从这个名字\n就能看出来，经济学家知道，就像稻谷总是被老鼠吃掉一样，雇主的利益总是因\n为雇员不正当地把他们自己的利益摆在第一位而受损。雇主可以采用的对策包括\n制定严格的内部审计制度，对败露的不轨行为进行严厉的公开惩处，使用防止钻\n营的规章制度和收款机等机器。而站在雇员的立场来看，激励机制引起的偏见自\n然会促使雇主对他们进行压迫：血汗工厂、危险的工作场所等等。若要解决职员\n遇到的这些糟糕问题，不但工会要给雇主施加压力，政府也要采取行动，包括制\n定关于工资和工作时间的法律、工作场所安全规章制度，采取一些便于工人组织','2026-07-05 16:55:53.049000',0,2073692323954429952,474,2073692323514028032),(2073692328383615008,'遇到的这些糟糕问题，不但工会要给雇主施加压力，政府也要采取行动，包括制\n定关于工资和工作时间的法律、工作场所安全规章制度，采取一些便于工人组织\n工会的措施，还有完善工人的薪酬系统。考虑到劳资双方由于激励机制引起的偏\n见而相互对峙，我们就不会奇怪中国人为什么会提出阴阳对立的理论了。  \n \n        激励机制引起的偏见无所不在，这造成了一些普遍而巨大的后\n果。例如，与有底薪的销售员相比，单纯靠提成过日子的销售员更难保证不做不\n道德的事情。从另一方面来说，无底薪的销售员的工作绩效会更加突出。因此，\n企业在制定销售员的薪酬制度时往往会面临两难的选择。  \n \n        自由市场资本主义这种经济体系取得极大成功的原因之一是，\n它防止了许多由激励机制引起的偏见造成的不良影响。在自由市场经济活动的巨\n网中，绝大多数能够在残酷竞争中幸存下来的资本家均非等闲之辈，他们会防止','2026-07-05 16:55:53.049000',0,2073692323954429952,475,2073692323514028032),(2073692328383615009,'它防止了许多由激励机制引起的偏见造成的不良影响。在自由市场经济活动的巨\n网中，绝大多数能够在残酷竞争中幸存下来的资本家均非等闲之辈，他们会防止\n企业中出现任何浪费的行为，因为这是生死攸关的事情。毕竟，他们要靠竞争性\n价格和他们的总体成本之间的利差来过日子，如果总体成本超过了销售额，他们\n就难逃灭亡的厄运。如果用那些从政府支取薪水的职员来取代这些资本家，那么\n市场经济的总体效率将会大大降低，因为每个取代资本家的职员在考虑为领取他\n的薪水应该提供什么样的服务，以及在多大程度上屈服于其他不希望自己表现得\n更好的同事的压力时会受到激励机制引起的偏见的影响。  \n \n        激励机制引起的偏见的另外一个常见后果是，人们倾向于钻各\n种制度的空子，他们往往在损人利己方面表现得极有创意。因此，几乎所有制度\n设计都必须具备防止钻空子的重要属性。制度设计还需要遵守如下的原则：尽量','2026-07-05 16:55:53.049000',0,2073692323954429952,476,2073692323514028032),(2073692328383615010,'种制度的空子，他们往往在损人利己方面表现得极有创意。因此，几乎所有制度\n设计都必须具备防止钻空子的重要属性。制度设计还需要遵守如下的原则：尽量\n避免奖励容易作假的事情。然而我们的议员和法官，通常包括许多在优秀大学受\n过教育的律师，往往会忽略这个原则。社会因此而付出了巨大的代价：道德风气\n败坏，效率下降，出现的不公平的成本转嫁和财富转移。如果高等学府提高教育\n质量，传授更多的心理学知识，而学生也能吸收更多心理学知识，那么我们的立\n法机构和法院将会设计出更好的制度。  \n \n        当然，现在驱使人们行动的主要奖励是金钱。只要一个毫无实\n质价值的筹码能够固定换到一根香蕉，那么人们就可以对猴子进行训练，让它为\n了筹码而工作，仿佛筹码就是香蕉一样。同样道理，人类也会为了钱而工作——\n而且会为了钱而更加卖命地工作，因为人类的金钱除了可以换到食物之外，还能','2026-07-05 16:55:53.049000',0,2073692323954429952,477,2073692323514028032),(2073692328383615011,'了筹码而工作，仿佛筹码就是香蕉一样。同样道理，人类也会为了钱而工作——\n而且会为了钱而更加卖命地工作，因为人类的金钱除了可以换到食物之外，还能\n换到许许多多美好的东西，拥有或花掉金钱通常也会让人显得有身份。此外，富\n人往往会出于习惯，更加努力地为金钱而工作，尽管他们早就不需要更多的钱。\n总的来说，金钱是现代文明的主要驱动力，这在非人类动物的行为中是没有先例\n的。金钱奖励也跟其他形式的奖励混合在一起。例如，有些人花钱买身份，有些\n人靠身份捞钱，而有些人同时做这两件事。  \n \n        虽然在各种奖励中金钱是最主要的，但它并非是惟一有效的奖\n励。人们也会为了性、友谊、伴侣、更高的地位和其他非金钱因素而改变他们的\n行为和认知。  \n \n        “祖母的规矩”也证实了奖励是非常有用的。它的效果特别突\n出，所以我在这里必须提到它。你可以用这个规矩来成功地控制自己的行为，哪','2026-07-05 16:55:53.049000',0,2073692323954429952,478,2073692323514028032),(2073692328387809280,' \n        “祖母的规矩”也证实了奖励是非常有用的。它的效果特别突\n出，所以我在这里必须提到它。你可以用这个规矩来成功地控制自己的行为，哪\n怕你使用的奖励品是你已经拥有的！实际上，许多拥有心理学博士学位的顾问经\n常要求商业组织教会管理人员用“祖母的规矩”来管理他们自己的日常行为，借\n此改善它们的奖励系统。具体来说，祖母的规矩就是要求孩子在吃甜点之前先把\n他们的胡萝卜吃掉。把它应用到商界，就是要求管理人员每天强迫他们自己先完\n成他们不喜欢然而必要的任务，再奖励他们自己去处理那些他们喜欢的任务。考\n虑到奖励的超级威力，这种做法是明智而合理的。此外，这个规矩也可以被用于\n生活中非商业的部分。那些顾问强调在日常生活中采用这种做法并不是无意的。\n根据斯金纳的教导，他们知道即时的奖励是最有效的。  \n \n        当然，惩罚也强烈地影响到行为和认知，尽管它的弹性和效果','2026-07-05 16:55:53.049000',0,2073692323954429952,479,2073692323514028032),(2073692328387809281,'根据斯金纳的教导，他们知道即时的奖励是最有效的。  \n \n        当然，惩罚也强烈地影响到行为和认知，尽管它的弹性和效果\n不像奖励那么好。例如，非法操纵物价的行为以前在美国很常见，因为遇到这种\n行为，政府往往是罚款了事。后来有几个重要的企业高管被革职还被送往联邦监\n狱服刑。此后，操纵价格的行为就大大减少了。  \n \n        陆军和海军部队在利用惩罚来改变行为方面做得很极端，这可\n能是因为它们需要士兵的绝对服从。大约在恺撒的年代，欧洲有个部落，每当集\n结号角吹响时，最后一个到达的士兵就会被杀死，于是没有人愿意跟这个部落打\n仗。乔治·华盛顿则把那些当逃兵的农场少年吊死在 40 英尺高的地方，以此来\n警示其他那些可能想要逃跑的士兵。 \n二 喜欢/热爱倾向 \n \n \n       在遗传因素的作用之下，刚孵出来的小鹅在破壳而出后将会','2026-07-05 16:55:53.049000',0,2073692323954429952,480,2073692323514028032),(2073692328387809282,'警示其他那些可能想要逃跑的士兵。 \n二 喜欢/热爱倾向 \n \n \n       在遗传因素的作用之下，刚孵出来的小鹅在破壳而出后将会\n“热爱”并跟随第一个对它和善的生物，那几乎总是它的母亲。但是，如果小鹅\n孵出来那一刻，出现的并不是母鹅，而是一个人，那么小鹅将会“热爱”并跟随\n这个人，把他当做自己的母亲。  \n \n        类似的是，刚出生的人类也会“天生就喜欢和热爱”对他好的\n人。也许最强烈的天生的爱——随时准备好被诱发——就是人类的母亲对其孩子\n的爱。从另外一方面来说，老鼠同样也有“爱护孩子”的行为，但只要删除某个\n基因，老鼠的这种行为就会消失。这意味着母老鼠和小鹅一样，体内都有某种诱\n发基因。  \n \n        就像小鹅一样，每个孩子不仅会受天性的驱使去喜欢和爱，而\n且也会在其亲生父母或者养父母的家庭之外的社会群体中去喜欢和爱。现在这些','2026-07-05 16:55:53.049000',0,2073692323954429952,481,2073692323514028032),(2073692328387809283,'发基因。  \n \n        就像小鹅一样，每个孩子不仅会受天性的驱使去喜欢和爱，而\n且也会在其亲生父母或者养父母的家庭之外的社会群体中去喜欢和爱。现在这些\n极端的罗曼蒂克之爱在人类的远古时代是不可能出现的。我们早期的人类祖先肯\n定会更像猿类，以一种非常原始的方式来挑选伴侣。  \n \n        除了父母、配偶和孩子之外，还有什么是人类天生就喜欢和热\n爱的呢？人类喜欢和热爱被喜欢和被热爱。许多在情场上的胜负皆因他/她能否\n表现出额外的关怀和爱护，而一般来讲，人类终身都会渴望得到许多和他毫无关\n系的他人的怜惜和欣赏。  \n \n        喜欢/热爱倾向造成的一个非常具有现实意义的后果就是，它\n是一种心理调节工具，促使人们：（1）忽略其热爱对象的缺点，对其百依百顺；\n（2）偏爱那些能够让自己联想起热爱对象的人、物品和行动（这一点我们将会','2026-07-05 16:55:53.049000',0,2073692323954429952,482,2073692323514028032),(2073692328387809284,'是一种心理调节工具，促使人们：（1）忽略其热爱对象的缺点，对其百依百顺；\n（2）偏爱那些能够让自己联想起热爱对象的人、物品和行动（这一点我们将会\n在“受简单联想影响的倾向”中讨论）；（3）为了爱而扭曲其他事实。  \n \n        喜欢/热爱会引发倾慕，反之亦然。倾慕也会引起并且强化喜\n欢/热爱倾向。这种“反馈模式”一旦形成，通常会造成极端的后果，有时候会\n促使人们为了帮助自己心爱的人而不惜故意自我毁灭。  \n \n        喜欢/热爱和倾慕交织在一起并相互作用往往在许多和男女情\n感无关的领域具有巨大的现实意义。例如，一个天生热爱值得敬仰的人和思想的\n人在生活中拥有巨大的优势。巴菲特和我自己在这方面就很幸运，有时候让我们\n受益的是相同的人或者思想。有一个人对我们两人都起到激励作用，他就是沃伦\n的叔叔，弗雷德·巴菲特（Fred Buffett）。他在杂货店有干不完的活，但干活','2026-07-05 16:55:53.049000',0,2073692323954429952,483,2073692323514028032),(2073692328387809285,'受益的是相同的人或者思想。有一个人对我们两人都起到激励作用，他就是沃伦\n的叔叔，弗雷德·巴菲特（Fred Buffett）。他在杂货店有干不完的活，但干活\n的时候总是很快乐，沃伦和我对他特别佩服。即使到今天，在我认识了这么多人\n之后，我仍然认为弗雷德·巴菲特是最好的人，他让我变得更好。  \n \n        那些有可能引起极度的热爱和倾慕的人往往能够发挥榜样的\n作用，造成非常好的效果，这对社会政策有极大的借鉴意义。例如，吸引许多令\n人敬爱、值得倾慕的人进入教育行业就是很明智的做法。 \n三 讨厌/憎恨倾向 \n \n \n       在一种与“喜欢/热爱倾向”相反的模式中，刚出生的人类也\n会“天生就讨厌和憎恨”对他很坏的人。猿类和猴类的情况也是如此。  \n \n        因此，战争在人类漫长的历史中几乎是持续不断的。例如，大','2026-07-05 16:55:53.049000',0,2073692323954429952,484,2073692323514028032),(2073692328387809286,'会“天生就讨厌和憎恨”对他很坏的人。猿类和猴类的情况也是如此。  \n \n        因此，战争在人类漫长的历史中几乎是持续不断的。例如，大\n多数美洲印第安人部落曾无休止地相互征伐，有些部落偶尔会把俘虏带到家里的\n妇女面前，让她们也享受把俘虏折磨致死的乐趣。尽管有了广为流布的宗教和发\n达先进的文明制度，现代社会的战争依然非常野蛮。但我们也观察到，在当今的\n瑞士和美国，人类巧妙的政治制度将个体和群体的讨厌与仇恨“引导”到包括选\n举在内的非致命模式当中。  \n \n        但讨厌和仇恨并没有彻底消失。这些心理倾向是天生的，它们\n依然很强烈。所以英国有这样的格言：“政治是正确地处理仇恨的艺术。”我们\n还看到美国非常流行那些对政敌进行诋毁的广告。  \n \n        就家庭的层面而言，我们经常可以看到这样的情况：有的人憎','2026-07-05 16:55:53.049000',0,2073692323954429952,485,2073692323514028032),(2073692328387809287,'还看到美国非常流行那些对政敌进行诋毁的广告。  \n \n        就家庭的层面而言，我们经常可以看到这样的情况：有的人憎\n恨自己的兄弟姐妹，只要负担得起相关费用，他就会不停地起诉他们。有个很风\n趣的人叫做巴菲特，他反复地向我解释，“穷人和富人的主要区别是，富人能够\n一辈子起诉他们的亲戚。”我父亲在奥马哈当律师的时候也处理了许多这种家庭\n内部的仇恨。我在哈佛大学法学院念书时，那里的教授教我“物权法”，然而丝\n毫没有提及家庭内部的兄弟争端。那时我就称这所法学院是一个非常脱离现实的\n地方，它像古代拉牛奶车的马那样蒙上了“眼罩”。我估计现在哈佛大学法学院\n在上物权法课程的时候依然没有提到兄弟之争。  \n \n        讨厌/憎恨倾向也是一种心理调节工具，它能促使深陷其中的\n人们：（1）忽略其讨厌对象的优点；（2）讨厌那些能够让自己联想起讨厌对象','2026-07-05 16:55:53.049000',0,2073692323954429952,486,2073692323514028032),(2073692328387809288,' \n        讨厌/憎恨倾向也是一种心理调节工具，它能促使深陷其中的\n人们：（1）忽略其讨厌对象的优点；（2）讨厌那些能够让自己联想起讨厌对象\n的人、物品和行动；（3）为了仇恨而扭曲其他事实。  \n \n        这种扭曲往往很极端，导致人们的认知出现了极大的偏差。当\n世贸中心被摧毁的时候，许多巴基斯坦人立刻认为是印度人干的，而许多穆斯林\n则认为是犹太人干的。这种致命的扭曲通常使得相互仇视的双方很难或者不可能\n握手言和。以色列和巴勒斯坦之间很难和解，因为一方历史中记载的事实与另外\n一方历史中记载的事实大相径庭，很少有相同之处。 \n四 避免怀疑倾向 \n \n \n       人类的大脑天生就有一种尽快作出决定，以此消除怀疑的倾\n向。  \n \n        这很容易理解，进化在漫长的岁月中促使动物倾向于尽快清除\n怀疑。毕竟，对于一只受到进攻者威胁的猎物来说，花很长时间去决定该怎么做','2026-07-05 16:55:53.049000',0,2073692323954429952,487,2073692323514028032),(2073692328387809289,'向。  \n \n        这很容易理解，进化在漫长的岁月中促使动物倾向于尽快清除\n怀疑。毕竟，对于一只受到进攻者威胁的猎物来说，花很长时间去决定该怎么做\n肯定是一件不妙的事情。人类的远祖也是动物，这种避免怀疑倾向与其远祖的历\n史是很相符的。  \n \n        人类通过尽快作出决定来消除怀疑的倾向十分明显，所以法官\n和陪审团必须采用抵制这种倾向的行为。他们不能立刻作出判决，而是必须经过\n慎重的考虑。人们在做决定之前，必须让自己习惯于戴上一个客观的“面具”。\n这个“面具”能够让人们客观地看待问题，这一点我们将会在下面讨论“避免不\n一致性倾向”时看出来。  \n \n        当然，明白人类具有强烈的避免怀疑倾向之后，逻辑上我们可\n以理解，至少在某些方面，人们对宗教信仰的接受必然受到这种倾向的驱使。即\n使有人认为他自己的信仰来自神的启示，他仍然需要思考其他人与此不一样的信','2026-07-05 16:55:53.049000',0,2073692323954429952,488,2073692323514028032),(2073692328387809290,'以理解，至少在某些方面，人们对宗教信仰的接受必然受到这种倾向的驱使。即\n使有人认为他自己的信仰来自神的启示，他仍然需要思考其他人与此不一样的信\n仰。几乎可以肯定地说，避免怀疑倾向是最重要的答案之一。  \n \n        是什么引发了避免怀疑倾向呢？如果一个人没有受到威胁，又\n无需考虑任何问题，他是不会急于通过作出决定来消除怀疑的。正如我们在后面\n谈到“社会认可倾向”和“压力影响倾向”时将会看到的，引发避免怀疑倾向的\n因素通常是：（1）困惑；（2）压力。在面对宗教问题的时候，这两种因素当然\n都存在。  \n \n        因而，大多数人的自然状态就是需要有某种宗教信仰。这是我\n们观察到的事实。 \n五 避免不一致性倾向 \n \n \n       为了节省运算空间，人类的大脑会不愿意作出改变。这是一种\n避免不一致性的形式。在所有的人类习惯中，无论是好习惯还是坏习惯，我们都','2026-07-05 16:55:53.049000',0,2073692323954429952,489,2073692323514028032),(2073692328387809291,' \n \n       为了节省运算空间，人类的大脑会不愿意作出改变。这是一种\n避免不一致性的形式。在所有的人类习惯中，无论是好习惯还是坏习惯，我们都\n能看到这种情况。没几个人能够列出许多他们已经改掉的坏习惯，而有些人哪怕\n连一个都列举不出来。与此相反，几乎每个人都有大量持续很久的坏习惯，尽管\n他们自己也知道这些习惯不好。考虑到这种情况，在许多时候我们说三岁看老不\n是没有道理的。在狄更斯的《圣诞欢歌》中，可怜的雅各布·马里的鬼魂说：“我\n戴着我在生活中锻造的锁链。”他说的锁链就是那些起初轻微得难以察觉，在察\n觉之后又牢固得无法打破的习惯。  \n \n        在生活中维持许多好习惯，避免或者戒除许多坏习惯，这样的\n生活才是明智的。能够帮助人们过上明智生活的伟大原则同样来自富兰克林的\n《穷理查年鉴》：“一盎司的预防比一磅的治疗更值钱。”富兰克林这句话的部','2026-07-05 16:55:53.049000',0,2073692323954429952,490,2073692323514028032),(2073692328387809292,'生活才是明智的。能够帮助人们过上明智生活的伟大原则同样来自富兰克林的\n《穷理查年鉴》：“一盎司的预防比一磅的治疗更值钱。”富兰克林这句话的部\n分含义是，由于避免不一致性倾向的存在，防止一种习惯的养成要比改变它容易\n得多。  \n \n        大脑的抗改变倾向还使得人们倾向于保留如下几种东西的原\n样：以前的结论、忠诚度、身份、社会认可的角色等等。人类大脑在进化的过程\n中为什么会产生出这种伴随着快速消除怀疑倾向的抗改变模式，现在还不是很清\n楚。我猜想这种抗改变模式主要是由如下几种因素的共同作用引起的：  \n \n        （1）当人类的远祖还是动物的时候，迅速作出决定对生存来\n说是至关重要的，而这种抗改变的模式有助于更快地作出决定。  \n \n        （2）它使得我们的远祖能够通过群体协作而获得生存优势，\n因为如果每个人的反应总是不停地改变，那么群体协作就会变得很困难。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,491,2073692323514028032),(2073692328387809293,' \n        （2）它使得我们的远祖能够通过群体协作而获得生存优势，\n因为如果每个人的反应总是不停地改变，那么群体协作就会变得很困难。  \n \n        （3）从人类刚开始识字到今天拥有复杂的现代生活，中间的\n时间并不是很长，它是进化在这么短的时间内所能得到的最好的办法。  \n \n        我们很容易可以看出来，如果任由避免怀疑倾向引发的快速决\n定和拒绝改变这种决定的倾向相结合，将会使现代人的认知出现大量的错误。而\n且实际情况也确实如此。我们所有人都曾和许多冥顽不灵的人打过交道，那些人\n死抱着他们在小时候形成的错误观念，直到进了坟墓还不肯放手。  \n \n        由于避免不一致性倾向引起的糟糕决定所造成的问题特别严\n重，所以我们的法院采用了一些重要措施来对付它。例如，在作出决定之前，法\n官和陪审团必须先聆听辩方的长篇大论，让辩方列举证据为自身辩护。这有助于','2026-07-05 16:55:53.049000',0,2073692323954429952,492,2073692323514028032),(2073692328387809294,'重，所以我们的法院采用了一些重要措施来对付它。例如，在作出决定之前，法\n官和陪审团必须先聆听辩方的长篇大论，让辩方列举证据为自身辩护。这有助于\n防止法官和陪审团在判决的时候犯“第一结论偏见”的错误。同样地，其他现代\n决策者通常要求各种团体在作出决定之前考虑反方的意见。  \n \n        正确的教育应该是一个提高认知能力的漫长过程，以便我们变\n得足够有足够的智慧，能够摧毁那些因拒绝改变倾向而被保留的错误想法。正如\n在世界顶尖大学任教的凯恩斯爵士（John Keynes）谈及他那些高级知识分子同\n事时指出的，新思想之所以很难被接受，并不是因为它们本身太过复杂。新思想\n不被接受，是因为它们与原有的旧思想不一致。凯恩斯教授的言下之意，就是人\n类头脑和人类卵子的运作方式非常相似。当一个精子进入卵子，卵子就会自动启\n动一种封闭机制，阻止其他精子的进入。人类头脑强烈地趋向于与此相同的结果。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,493,2073692323514028032),(2073692328387809295,'类头脑和人类卵子的运作方式非常相似。当一个精子进入卵子，卵子就会自动启\n动一种封闭机制，阻止其他精子的进入。人类头脑强烈地趋向于与此相同的结果。  \n \n        所以人们倾向于积累大量僵化的结论和态度，而且并不经常去\n检查，更不会去改变，即便有大量的证据表明它们是错误的。  \n \n        社会科学院系就会发生这样的情况，比如说，曾经有人认为弗\n洛伊德应该是加州理工学院心理学教授的惟一人选。但自然科学院系也有人坚持\n错误的旧观点，不过这种情况比较少见，也没那么严重。在这方面，诺贝尔奖得\n主、普朗克常数的发现者马克斯·普朗克最有发言权。普朗克不但以科学研究闻\n名，而且他还说过一句著名的话，他说，甚至在物理学领域，激进的新思想也很\n少被旧卫士所接受。与此相反，普朗克说，惟有新的一代成长起来，较少受到旧\n理论毒害的他们才能接受新理论。实际上，这种“脑梗阻”的情况也曾经在某种','2026-07-05 16:55:53.049000',0,2073692323954429952,494,2073692323514028032),(2073692328387809296,'少被旧卫士所接受。与此相反，普朗克说，惟有新的一代成长起来，较少受到旧\n理论毒害的他们才能接受新理论。实际上，这种“脑梗阻”的情况也曾经在某种\n程度上发生于爱因斯坦身上。处在巅峰期的爱因斯坦非常善于摧毁他自己的思\n想，但是爱因斯坦晚年却从没有完全接受量子力学。  \n \n        查尔斯·达尔文是最成功地化解第一结论偏见的人之一。他很\n早就训练自己努力考虑任何有可能证伪他的假说的证据，尤其是在他认为他的假\n说特别出色时更是如此。与达尔文相反的做法现在被称为“确认偏见”，这是一\n个贬义词。达尔文采用这样的做法，是因为他清楚地认识到人类会由于天生的避\n免不一致性倾向而犯认知错误。他本身是一个伟大的例子，证明了心理学洞见一\n旦被正确地使用，就能够对人类历史上最优秀的思想有所贡献。  \n \n        避免不一致性倾向给文明社会带来了许多良好的影响。例如，','2026-07-05 16:55:53.049000',0,2073692323954429952,495,2073692323514028032),(2073692328387809297,'旦被正确地使用，就能够对人类历史上最优秀的思想有所贡献。  \n \n        避免不一致性倾向给文明社会带来了许多良好的影响。例如，\n大多数人在生活中不会表现出与他们的公共责任、新的或旧的公共认同等不一致\n的行动，而是会忠于职守，扮演好牧师、医生、公民、士兵、配偶、教师、职员\n等角色。  \n \n        避免不一致性倾向造成的结果之一是，人们在获取新身份的过\n程中作出的重大牺牲将会提高他们对这种新身份的忠诚度。毕竟，如果他们认为\n某样东西并不好，却又为之作出重大牺牲，那他们的行为将会显得和他们的思想\n很不一致。所以文明社会发明了许多庄严肃穆的入会仪式，这些仪式通常是公开\n举行的，能够让新成员更加忠心。  \n \n        庄严的仪式能够强化好的关系，也能够强化坏的关系。黑手党\n新成员因为“投名状”而对组织更加忠诚，德国军官因为“血誓”而对希特勒更','2026-07-05 16:55:53.049000',0,2073692323954429952,496,2073692323514028032),(2073692328387809298,' \n        庄严的仪式能够强化好的关系，也能够强化坏的关系。黑手党\n新成员因为“投名状”而对组织更加忠诚，德国军官因为“血誓”而对希特勒更\n加忠心，这些都是避免不一致性倾向引发的后果。  \n \n        此外，这种倾向通常会使人们成为被某些有心机的人所操控的\n“受害者”，那些人能够通过激发别人潜意识中的避免不一致性倾向而博取对方\n的好感。很少有人比本杰明·富兰克林更精于此道。本杰明·富兰克林原本是费\n城一个默默无闻的小人物，当时他想得到某个重要人物的垂青，于是经常设法请\n那个人帮他一些无关紧要的小忙，比如说借一本书给他之类的。从那以后，那个\n大人物就更加欣赏和信任富兰克林了，因为一个不值得欣赏、不值得信任的富兰\n克林与他借书给富兰克林的行为中暗示的赞许并不一致。  \n \n        富兰克林这种操纵别人帮自己忙、从而令别人对自己产生好感','2026-07-05 16:55:53.049000',0,2073692323954429952,497,2073692323514028032),(2073692328387809299,'克林与他借书给富兰克林的行为中暗示的赞许并不一致。  \n \n        富兰克林这种操纵别人帮自己忙、从而令别人对自己产生好感\n的做法如果反过来使用，也会产生非常变态的效果。如果有个人受到操控，故意\n不停地去伤害另外一个人，那么他就会倾向于贬低甚至憎恨那个人。这种避免不\n一致性倾向造成的效应解释了那句谚语所含的道理：“人永远不会忘记自己做过\n的坏事。”这种效应也解释了监狱中的看守和囚犯势不两立的现象。许多看守会\n虐待囚犯，这种做法使他们更加讨厌和憎恨囚犯，而那些被当做畜牲一样的囚犯\n又会反过来仇视看守。若要消除监狱中囚犯和看守之间相互敌视的心理，狱方应\n该持续不断地致力于：（1）从一开始就防止虐待囚犯；（2）虐囚现象出现时要\n立刻予以制止，因为它会像瘟疫那样蔓延扩散。如果在更有远见的教育的帮助下，\n我们对这个问题能够获得更多的心理学认知，那么我们也许能够提高美国军队的\n整体效率。  ','2026-07-05 16:55:53.049000',0,2073692323954429952,498,2073692323514028032),(2073692328387809300,'立刻予以制止，因为它会像瘟疫那样蔓延扩散。如果在更有远见的教育的帮助下，\n我们对这个问题能够获得更多的心理学认知，那么我们也许能够提高美国军队的\n整体效率。  \n \n        避免不一致性倾向是如此强大，乃至一个人只要假装拥有某种\n身份、习惯或者结论，他自己通常就会信以为真。因而，许多扮演哈姆雷特的演\n员会在某种程度上相信自己就是那位丹麦王子。许多装好人的伪善者的道德水平\n确实得到了提高；许多假装公正无私的法官和陪审团确实会做到公正无私；许多\n辩护律师或者其他观点的鼓吹者最后会相信他们从前只是假装相信的东西。  \n \n        避免不一致性倾向造成了“维持现状倾向”，给合理的教育造\n成了巨大的伤害，但它也带来了许多好处。避免不一致性倾向导致教师不太可能\n把自己不相信的知识教给学生。所以临床医学教育要求学生必须遵守“先看，后','2026-07-05 16:55:53.049000',0,2073692323954429952,499,2073692323514028032),(2073692328387809301,'成了巨大的伤害，但它也带来了许多好处。避免不一致性倾向导致教师不太可能\n把自己不相信的知识教给学生。所以临床医学教育要求学生必须遵守“先看，后\n做，再教”的原则，只有自己看过和做过的，才能教给别人。当然，教育过程有\n能力影响教师认知，这未必总是对社会有益。当这种能力流入政见传播和邪教教\n义传播时，通常会给社会造成糟糕的影响。  \n \n        例如，当年轻的学生被灌输了值得怀疑的政治理念，然后热诚\n地将这些理念推销给我们其他人时，现代教育就会给社会造成很大的破坏。这种\n推销很少能使其他人信服。但是学生会把他们所推销的东西变成他们自己的思维\n习惯，从而受到了永久的伤害。我认为那些有这种风气的教育机构是很不负责任\n的。在一个人心智尚未完全成熟之前，不能给他的头脑套上一些锁链，这是很重\n要的。 \n六 好奇心倾向 \n \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,500,2073692323514028032),(2073692328387809302,'的。在一个人心智尚未完全成熟之前，不能给他的头脑套上一些锁链，这是很重\n要的。 \n六 好奇心倾向 \n \n \n       哺乳动物天生就具有好奇心，但在所有非人类的哺乳动物里面，\n好奇心最强烈的是猿类和猴类。而人类的好奇心又比他的这些近亲强烈得多。在\n发达的人类文明中，文化极大地提高了好奇心在促进知识发展方面的效率。例如，\n雅典（及其殖民地亚历山德里亚）人的纯粹好奇心推动了数学和科学的发展，而\n罗马人则对数学或科学几乎没有贡献。罗马人更专注于矿藏、道路和水利等“实\n用”工程。最好的现代教育机构（这样的机构在许多地方都为数甚少）能够增强\n人们的好奇心，而好奇心则能帮助人们防止或者减少其他心理倾向造成的糟糕后\n果。好奇心还能让人们在正式教育结束很久之后依然拥有许多乐趣和智慧。  \n \n \n七 康德式公平倾向 \n \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,501,2073692323514028032),(2073692328387809303,'果。好奇心还能让人们在正式教育结束很久之后依然拥有许多乐趣和智慧。  \n \n \n七 康德式公平倾向 \n \n \n       康德以其“ 绝对命令” （ categorical imperative，又译\n为定言令式）而闻名。所谓绝对命令是某种“黄金法则”，它要求人们遵守某些\n行为方式，如果所有人都遵守这些方式，那么就能够保证社会制度对每个人来说\n都是最好的。应该说，在现代社会，每个有文化的人都表现出并期待从别人那里\n得到康德所定义的这种公平。  \n \n       美国一些规模不大的小区里面通常会有只能供一辆车通过的桥\n梁或者地道，在这些小区里面，我们可以看到很多相互礼让的情况，尽管那里并\n没有交通标志或者信号灯。许多在高速公路上开车的司机，包括我自己在内，通\n常会让其他想要超车的司机开到自己前面，因为那是一种当他们想超车时也希望','2026-07-05 16:55:53.049000',0,2073692323954429952,502,2073692323514028032),(2073692328387809304,'没有交通标志或者信号灯。许多在高速公路上开车的司机，包括我自己在内，通\n常会让其他想要超车的司机开到自己前面，因为那是一种当他们想超车时也希望\n得到的礼貌行为。此外，在现代的文明社会中，陌生人之间有文明排队的习惯，\n这样所有人都能按照“先来后到”的规矩得到服务。  \n \n       此外，陌生人往往会自愿平分飞来横财，或者平摊意外损失。作\n为这种“公平分配”行为的自然后果，当人们期待然而没有得到公平分配时，往\n往会表现出不满的情绪。  \n \n       过去 300 年来，奴隶制度在世界各地基本上被废除了，这是很有\n意思的事情，因为在此之前，奴隶制度已经和各大宗教共存了几千年。我认为康\n德式公平倾向是促成这种结果的主要因素。 \n八 艳羡/妒忌倾向 \n \n \n       如果某个物种在进化过程中经常挨饿，那么这个物种的成员在','2026-07-05 16:55:53.049000',0,2073692323954429952,503,2073692323514028032),(2073692328387809305,'德式公平倾向是促成这种结果的主要因素。 \n八 艳羡/妒忌倾向 \n \n \n       如果某个物种在进化过程中经常挨饿，那么这个物种的成员在\n看到食物时，就会产生占有那食物的强烈冲动。如果被看到的食物实际上已经被\n同物种的另外一个成员占有，那么这两个成员之间往往会出现冲突的局面。这可\n能就是深深扎根在人类本性中的艳羡/妒忌倾向的进化起源。  \n \n       兄弟姐妹之间的妒忌明显是非常强大的，并且儿童往往比成年更\n容易妒忌自己的兄弟姐妹。这种妒忌通常比因陌生人而发的妒忌更加强烈。这种\n结果也许是康德式公平倾向造成的。  \n \n       各种神话、宗教和文学作品用一个又一个的事例来描写极端的艳\n羡/妒忌是如何引起仇恨和伤害的。犹太文明认为这种心理倾向是极其邪恶的，\n摩西诫律一条又一条明令禁止妒忌。这位先知甚至警告人们不要去贪图邻人的驴\n子。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,504,2073692323514028032),(2073692328387809306,'羡/妒忌是如何引起仇恨和伤害的。犹太文明认为这种心理倾向是极其邪恶的，\n摩西诫律一条又一条明令禁止妒忌。这位先知甚至警告人们不要去贪图邻人的驴\n子。  \n \n       现代生活中的妒忌也无所不在。例如，当某些大学的资金管理人\n员或者外科手术教授拿到远远超过行业标准的薪水时，校园里会一片哗然。而现\n代的投资银行、律师事务所等地方的艳羡/妒忌效应通常比大学教职员工中的此\n效应更加极端。许多大型律师事务所担心艳羡/妒忌会造成混乱，所以它们历来\n给所有高级合伙人提供的薪酬都是差不多的，完全不管他们对事务所的贡献有多\n大的差别。我同沃伦·巴菲特一起工作，分享对生活的观察已经几十年了，听到\n他不止一次明智地指出：“驱动这个世界的不是贪婪，而是妒忌。”  \n \n       由于这句话基本上是正确的，人们可能会认为心理学教科书会用','2026-07-05 16:55:53.049000',0,2073692323954429952,505,2073692323514028032),(2073692328387809307,'他不止一次明智地指出：“驱动这个世界的不是贪婪，而是妒忌。”  \n \n       由于这句话基本上是正确的，人们可能会认为心理学教科书会用\n大量的篇幅来谈论艳羡/妒忌。但我翻读那三本心理学教科书的时候，并没有看\n到这样的内容。实际上，那些教科书的索引上根本就找不到“艳羡”和“妒忌”\n这两个词。  \n \n       毫不提及艳羡/妒忌的这种现象并不局限于心理学教科书。在你\n们参加过的大型学术研讨会上，有人把成年人的艳羡/妒忌心理视为某些观点的\n原因吗？似乎存在一条普遍的禁忌，禁止人们做出这样的声明。如果确实如此的\n话，是什么导致这条禁忌的出现呢？  \n \n       我的猜想是，这是因为人们普遍认为，说某种立场是由艳羡/妒\n忌促成的，是对采取那种立场的人的极大侮辱，如果那个人所持的看法是正确的，\n而不是错误的，那就更是如此。说某种立场受到妒忌的驱动被视为等同于说采取','2026-07-05 16:55:53.049000',0,2073692323954429952,506,2073692323514028032),(2073692328392003584,'忌促成的，是对采取那种立场的人的极大侮辱，如果那个人所持的看法是正确的，\n而不是错误的，那就更是如此。说某种立场受到妒忌的驱动被视为等同于说采取\n那种立场的人像儿童般不成熟，那么这种对妒忌避而不谈的禁忌就完全可以理解\n了。  \n \n       但这种普遍的禁忌就应该影响心理学教科书，导致心理学无法对\n一种普遍的重要现象作出正确的解释吗？我的答案是否定的。 \n九 回馈倾向 \n \n \n       人们早就发现，和猿类、猴类、狗类和其他许多认知能力较为\n低下的动物相同，人类身上也有以德报德、以牙还牙的极端倾向。这种倾向明显\n能够促进有利于成员利益的团体合作。从这方面来讲，它跟许多社会性动物的基\n因程序很相似。  \n \n       我们知道，在有些战争中，以牙还牙的心理倾向是很厉害的，它\n会让仇恨上升到很高的程度，引发非常野蛮的行为。许多战争中没有活的俘虏，','2026-07-05 16:55:53.049000',0,2073692323954429952,507,2073692323514028032),(2073692328392003585,' \n       我们知道，在有些战争中，以牙还牙的心理倾向是很厉害的，它\n会让仇恨上升到很高的程度，引发非常野蛮的行为。许多战争中没有活的俘虏，\n交战双方非把敌人置于死地不可，而且有时候光是把敌人杀死还不够，比如说成\n吉思汗，他就不满足于只把敌人变成尸体。他坚持要把敌人的尸体剁得粉碎。  \n \n       拿成吉思汗和蚂蚁来作对比是很有意思的。成吉思汗对别人残暴\n无度，动辄加以杀戮，而蚂蚁对其繁殖群体之外的同种类蚂蚁也表现出极端的、\n致命的敌意。如果和蚂蚁相比，成吉思汗简直太和蔼可亲了。蚂蚁更加好斗，而\n且在打斗中更加残忍。实际上，E.O.威尔逊曾经开玩笑地说，如果蚂蚁突然得到\n原子弹，所有蚂蚁将会在 18 个小时之内灭亡。人类和蚂蚁的历史给我们的启发\n是：（1）大自然并没有普遍的法则使得物种内部以德报怨的行为能够推动物种','2026-07-05 16:55:53.049000',0,2073692323954429952,508,2073692323514028032),(2073692328392003586,'原子弹，所有蚂蚁将会在 18 个小时之内灭亡。人类和蚂蚁的历史给我们的启发\n是：（1）大自然并没有普遍的法则使得物种内部以德报怨的行为能够推动物种\n的繁荣；（2）如果一个国家对外交往时放弃以牙还牙的做法，这个国家是否有\n好的前景是不确定的；（3）如果国与国之间都认为以德报怨是最好的相处之道，\n那么人类的文化将要承担极大的重任，因为人类的基因是帮不上多少忙的了。  \n \n       接下来我要谈谈战场之外的以牙还牙。现代有许多“路怒”（注：\n英文为 road rage，是指汽车驾驶人在行车时对别的汽车驾驶人所做出的攻击性\n的或过激的行为）事件，或者运动场上也有因为受伤而引起的情绪失控事件，从\n这些事件可以看出来，在和平时代，人们之间的敌意也可能非常极端。  \n \n       化解过激的敌意的标准方法是，人们可以延迟自己的反应。我有','2026-07-05 16:55:53.049000',0,2073692323954429952,509,2073692323514028032),(2073692328392003587,'这些事件可以看出来，在和平时代，人们之间的敌意也可能非常极端。  \n \n       化解过激的敌意的标准方法是，人们可以延迟自己的反应。我有\n个聪明的朋友叫做托马斯·墨菲（注：托马斯·默菲，首都城市/美国广播公司\n前董事长和 CEO），他经常说：“如果你觉得骂人是很好的主意，你可以留到明\n天再骂。”  \n \n       当然，以德报德的心理倾向也是非常强烈的，所以它有时能够扭\n转以牙还牙的局面。有时候，在战火正酣时，交战双方会莫名其妙地停止交火，\n因为有一方先做出了细微的友善的举动，另外一方则投桃报李，就这样往复下去，\n最后战斗会停止很长一段时间。第一次世界大战期间，开战双方在前线的战壕不\n止一次地这样停战，这令那些将军感到非常恼火。  \n \n       很明显，作为现代社会繁荣的主要推动因素，商业贸易也得到人\n类投桃报李的天性的很大帮助。利己利人的原则和回馈倾向相结合，会引起许多','2026-07-05 16:55:53.049000',0,2073692323954429952,510,2073692323514028032),(2073692328392003588,' \n       很明显，作为现代社会繁荣的主要推动因素，商业贸易也得到人\n类投桃报李的天性的很大帮助。利己利人的原则和回馈倾向相结合，会引起许多\n有建设性的行为。婚姻生活中的日常交流也得到回馈倾向的帮助，如果没有回馈\n倾向的帮助，婚姻会丧失大部分的魅力。  \n \n       回馈倾向不但能够和激励机制的超级威力结合起来产生好的结\n果，它还跟避免不一致性倾向共同促成了以下结果：（1）人们履行在交易中作\n出的承诺，包括在婚礼上作出的忠于对方的承诺；（2）牧师、鞋匠、医生和其\n他所有职业人士恪守职责，做出正确的行为。  \n \n       与其他心理倾向和人类翻跟斗的能力相同，回馈倾向很大程度上\n是在潜意识层面发挥作用的。所以有些人能够把这种倾向变成强大的力量，用来\n误导他人。这种情况一直都有发生。  \n \n       例如，当汽车销售员慷慨地把你请到一个舒服的地方坐下，并端','2026-07-05 16:55:53.049000',0,2073692323954429952,511,2073692323514028032),(2073692328392003589,'误导他人。这种情况一直都有发生。  \n \n       例如，当汽车销售员慷慨地把你请到一个舒服的地方坐下，并端\n给你一杯咖啡时，你非常有可能因为这个细小的礼节性行为当了一回冤大头，买\n车的时候多付了 500 美元。这远远不是销售员用小恩小惠所取得的最成功的销售\n案例。然而，在这个买车的场景中，你将会处于劣势，你将会从自己口袋里额外\n掏出 500 美元。这种潜在的损失多少会让你对销售员的示好保持警惕。  \n \n       但假如你是采购员，花的钱来自别人——比如说某个有钱的雇\n主，那么你就不太会因为要额外付钱而反感销售员的小恩小惠，因为多付出的成\n本是别人的。在这样的情况下，销售员通常能够将他的优势最大化，尤其是当采\n购方是政府时。  \n \n       因此，聪明的雇主试图压制从事采购工作的职员的回馈倾向。最\n简单的对策最有效：别让他们从供应商那里得到任何好处。山姆·沃尔顿（注：','2026-07-05 16:55:53.049000',0,2073692323954429952,512,2073692323514028032),(2073692328392003590,' \n       因此，聪明的雇主试图压制从事采购工作的职员的回馈倾向。最\n简单的对策最有效：别让他们从供应商那里得到任何好处。山姆·沃尔顿（注：\n山姆·沃尔顿，1918—1992，美国零售商沃尔玛公司的创办人）赞同这种彻底禁\n止的思想。他不允许采购员从供应商那里接受任何东西，哪怕是一个热狗也不行。\n考虑到大多数回馈倾向是在潜意识层面发挥作用，沃尔顿的政策是非常正确的。\n如果我是国防部的负责人，我会在国防部实行沃尔顿的政策。  \n \n       在一个著名的心理学实验中，西奥迪尼出色地证明“实验员”有\n能力通过诱发人们潜意识的回馈倾向来误导他们。  \n \n       展开实验的西奥迪尼吩咐他的实验员在他所在的大学校园里闲\n逛，遇到陌生人就请他们帮忙带领一群少年犯去动物园参观。因为这是在大学校\n园里发生的，所以在他们抽中的大量样本中，每六个人有一个真的同意这么做。','2026-07-05 16:55:53.049000',0,2073692323954429952,513,2073692323514028032),(2073692328392003591,'逛，遇到陌生人就请他们帮忙带领一群少年犯去动物园参观。因为这是在大学校\n园里发生的，所以在他们抽中的大量样本中，每六个人有一个真的同意这么做。\n得到这个 1/6 的统计数据之后，西奥迪尼改变了实验的程序。他的实验员接下来\n又在校园里闲逛，遇到陌生人就要求他们连续两年每周花大量时间去照顾少年\n犯。这个荒唐的请求得到了百分之百的拒绝。但实验员跟着又问：“那么你愿意\n至少花一个下午带那些少年犯去参观动物园吗？”这将西奥迪尼原来的接受率\n从 1/6 提高到了 50%——整整 3倍。  \n \n       西奥迪尼的实验员所做的是作出小小的让步，于是对方也作出了\n小小的让步。由于西奥迪尼的实验对象在潜意识中作出了这种回馈式的让步，所\n以有更多的人非理性地答应带领少年犯去参观动物园。这位教授发明了如此巧妙\n的实验，如此强有力地证明了某个如此重要的道理，他理应得到更广泛的认可。','2026-07-05 16:55:53.049000',0,2073692323954429952,514,2073692323514028032),(2073692328392003592,'以有更多的人非理性地答应带领少年犯去参观动物园。这位教授发明了如此巧妙\n的实验，如此强有力地证明了某个如此重要的道理，他理应得到更广泛的认可。\n实际上，西奥迪尼确实得到了这种认可，因为许多大学向他学习了大量知识。  \n \n       回馈倾向为什么如此重要呢？假如有许多法学院学生毕业后走\n进社会，代表客户到处去谈判，却完全不了解西奥迪尼的实验所展现的潜意识思\n维过程的本质，那该是多么愚蠢的事。然而这种蠢事在世界各地的法学院已经发\n生了好几十年，实际上，是好几个世代。这些法学院简直就是在误人子弟。它们\n不知道也不愿意去传授山姆·沃尔顿了解得十分清楚的东西。  \n \n       回馈倾向的重要性和效用也可以从西奥迪尼对美国司法部长批\n准偷偷进入水门大厦的愚蠢决定的解释中看出来。当时有个胆大包天的下属提议\n为了谋取共和党的利益，不妨使用妓女和豪华游艇相结合的手段。这个荒唐的请','2026-07-05 16:55:53.049000',0,2073692323954429952,515,2073692323514028032),(2073692328392003593,'准偷偷进入水门大厦的愚蠢决定的解释中看出来。当时有个胆大包天的下属提议\n为了谋取共和党的利益，不妨使用妓女和豪华游艇相结合的手段。这个荒唐的请\n求遭到拒绝之后，那下属作出了很大的让步，只要求得到批准，以便偷偷摸摸地\n去盗窃，于是司法部长默许了。西奥迪尼认为，潜意识的回馈倾向是导致美国总\n统在水门丑闻中下台的重要因素。我也持相同的观点。回馈倾向微妙地造成了许\n多极端而危险的结果，并且这种情况绝不少见，而是一直以来都有很多。  \n \n       人类对回馈倾向的认识，在被付诸实践数千年之后，已经在宗教\n领域干了许多令人毛骨悚然的坏事。特别令人发指的例子来自腓尼基人\n（Phoenicians）和阿兹台克人（Aztecs），他们会在宗教仪式上将活人杀死，\n作为牺牲品供奉给他们的神灵。我们不应该忘记近如在迦太基之战（注：英文为','2026-07-05 16:55:53.049000',0,2073692323954429952,516,2073692323514028032),(2073692328396197888,'（Phoenicians）和阿兹台克人（Aztecs），他们会在宗教仪式上将活人杀死，\n作为牺牲品供奉给他们的神灵。我们不应该忘记近如在迦太基之战（注：英文为\nPunicWars，也称布匿战争，是罗马人在向地中海扩张中于公元前 264 年—公元\n前 146 年同迦太基人之间的三次战役）中，文明的罗马人由于担心战败，重操了\n几次杀人献祭的旧业。从另外一方面来说，人们基于回馈心理，认为只要行为端\n正，就能从上帝那里得到帮助，这种观念有可能一直以来都是非常具有建设性的。  \n \n       总的来说，我认为无论是在宗教之内还是在宗教之外，回馈倾向\n给人类带来的贡献远远比它造成的破坏要多。而就利用心理倾向来抵消或者防止\n其他一种或多种心理倾向引起的糟糕后果而言，比如说，就利用心理干预来终止\n化学药物依赖（戒毒或酒）而言，回馈倾向往往能够起到很大的帮助作用。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,517,2073692323514028032),(2073692328396197889,'其他一种或多种心理倾向引起的糟糕后果而言，比如说，就利用心理干预来终止\n化学药物依赖（戒毒或酒）而言，回馈倾向往往能够起到很大的帮助作用。  \n \n       人类生活中最美好的部分也许就是情感关系，情感关系中的双方\n更感兴趣的是如何取悦对方，而非如何被取悦——在回馈倾向的作用之下，这样\n的情况并不算罕见。  \n \n       在结束离开回馈倾向的讨论之前，我们最后要讨论的是人类普遍\n受到负罪感折磨的现象。如果说负罪感有其进化基础的话，我相信最有可能引起\n负罪感的因素是回馈倾向和奖励超级反应倾向之间的精神冲突。奖励超级反应倾\n向是一种推动人们百分百地去享受好东西的心理倾向。当然，人类的文化通常极\n大地促使这种天生的倾向受到负罪感的折磨。具体地说，宗教文化通常给人们提\n出一些很难做到的道德要求和奉献要求。我家附近住着一位很有个人魅力的爱尔','2026-07-05 16:55:53.049000',0,2073692323954429952,518,2073692323514028032),(2073692328396197890,'大地促使这种天生的倾向受到负罪感的折磨。具体地说，宗教文化通常给人们提\n出一些很难做到的道德要求和奉献要求。我家附近住着一位很有个人魅力的爱尔\n兰天主神父，他经常说：“负罪感可能是那些犹太人发明的，但我们天主教徒完\n善了它。”如果你们像我和这位神父一样，都认为负罪感总体上是利多于弊的，\n那么你们就会和我一样对回馈倾向存有感激之心，无论你们觉得负罪感是多么地\n令人不愉快。 \n十 受简单联想影响的倾向 \n \n \n       斯金纳研究过的标准条件反射是世界上最常见的条件反射。在\n这种条件反射中，创造出新习惯的反射行为是由以前得到的奖励直接引起的。例\n如，有个人买了一罐名牌鞋油，发现这种鞋油能把鞋擦得特别亮，由于这种“奖\n励”，下次他需要再买鞋油时，还是买了这个牌子。  \n \n       但条件反射还有另外一种，反射行为是由简单的联想引发的。例','2026-07-05 16:55:53.049000',0,2073692323954429952,519,2073692323514028032),(2073692328396197891,'励”，下次他需要再买鞋油时，还是买了这个牌子。  \n \n       但条件反射还有另外一种，反射行为是由简单的联想引发的。例\n如，许多人会根据从前的生活经验得到这样的结论：如果有几种同类产品同时在\n出售，价格最高的那种质量最好。有的普通工业品销售商明白这个道理，于是他\n通常会改变产品的外包装，把价格提得很高，希望那些追求高质量的顾客会因此\n而上当，纯粹由于他的产品及其高价格引起的联想而成为购买者。这种做法通常\n对促进销量很有帮助，甚至对提高利润也很有作用。例如，长期以来，定价很高\n的电动工具就取得了很好的销售业绩。如果要销售的产品是油井底下用的油泵，\n那么这种高定价的做法起到的作用会更大。提高价格的销售策略对奢侈品而言尤\n其有效，因为那些付出更高价格的顾客因此而展现了他们的良好品味和购买力，\n所以通常能够获得更高的地位。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,520,2073692323514028032),(2073692328396197892,'其有效，因为那些付出更高价格的顾客因此而展现了他们的良好品味和购买力，\n所以通常能够获得更高的地位。  \n \n       即使是微不足道的联想，只要加以仔细的利用，也能对产品购买\n者产生极端的特殊影响。鞋油的目标购买者或许很喜欢漂亮女孩。所以他选择了\n那种外包装上印着漂亮女孩的鞋油，或者他最近看到由漂亮女孩做广告的那种鞋\n油。  \n \n       广告商了解单纯联想的威力。所以你们不会看到可口可乐的广告\n中有儿童死亡的场面；与之相反，可口可乐广告画面中的生活总是比现实生活更\n加快乐。  \n \n       同样地，军乐团演奏的音乐那么动听也绝对不是偶然的。人们听\n到那种音乐，就会联想起部队生活，所以它有助于吸引人们入伍，并让士兵留在\n军队里。大多数军队懂得如何用这种成功的方法来使用简单联想。  \n \n       然而，简单联想造成的最具破坏性的失算往往并不来自广告商和','2026-07-05 16:55:53.049000',0,2073692323954429952,521,2073692323514028032),(2073692328396197893,'军队里。大多数军队懂得如何用这种成功的方法来使用简单联想。  \n \n       然而，简单联想造成的最具破坏性的失算往往并不来自广告商和\n音乐提供者。  \n \n       有的东西碰巧能让人联想起他从前的成功，或者他喜欢和热爱的\n事物，或者他讨厌和憎恨的事物（包括人们天生就讨厌的坏消息）。有些最严重\n的失算是由这样的东西引起的。  \n \n       若要避免受到对从前之成功的简单联想误导，请记住下面这段历\n史。拿破仑和希特勒的军队在其他地方战无不胜，于是他们决定侵略俄罗斯，结\n果都是一败涂地。现实生活中有许多事例跟拿破仑和希特勒的例子差不多。例如，\n有个人愚蠢地去赌场赌博，竟然赢了钱。这种虚无缥缈的关联促使他反复去那个\n赌场，结果自然是输得一塌糊涂。也有些人把钱交给资质平庸的朋友去投资，碰\n巧赚了大钱。尝到甜头之后，他决定再次尝试这种曾经取得成功的方法——结果\n很糟糕。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,522,2073692323514028032),(2073692328396197894,'赌场，结果自然是输得一塌糊涂。也有些人把钱交给资质平庸的朋友去投资，碰\n巧赚了大钱。尝到甜头之后，他决定再次尝试这种曾经取得成功的方法——结果\n很糟糕。  \n \n       避免因为过去的成功而做蠢事的正确对策是：（1）谨慎地审视\n以往的每次成功，找出这些成功里面的偶然因素，以免受这些因素误导，从而夸\n大了计划中的新行动取得成功的概率；（2）看看新的行动将会遇到哪些在以往\n的成功经验中没有出现的危险因素。  \n \n       喜欢和热爱会给人们的思想带来伤害，这可以从下面的事例看出\n来。在某桩官司中，被告人的妻子原本是一名非常值得尊敬的女性，可是却做出\n了明显错误的证词。那位著名的控方律师不忍心攻击这位如此可敬的女士，然而\n又想摧毁其证词的可信性。于是他摇摇头，悲伤地说：“我们该如何看待这样的\n证词呢？答案就在那首老歌里面：  \n丈夫是什么样， \n妻子就会是什么样。 \n她嫁给了小丑， ','2026-07-05 16:55:53.049000',0,2073692323954429952,523,2073692323514028032),(2073692328396197895,'证词呢？答案就在那首老歌里面：  \n丈夫是什么样， \n妻子就会是什么样。 \n她嫁给了小丑， \n小丑的卑鄙无耻， \n拖累了她。  \n \n       法官因此没有采信这位女士的证词。他们轻而易举地看出她的认\n知已经受到爱情的强烈影响。我们常常看到，有些母亲受到爱的误导，在电视镜\n头面前声泪俱下，发自内心地认为她们那些罪孽深重的儿子是清白无辜的。  \n \n       关于这种被称之为爱的联想在多大程度上会令人盲目，人们的意\n见不尽相同。在《穷理查年鉴》中，富兰克林提议：“结婚前要睁大双眼看清楚，\n结婚后要睁一只眼闭一只眼。”也许这种“睁一只眼闭一只眼”的方法是正确\n的，但我喜欢一种更难做到的办法：“实事求是地看清现实，可还是去爱。”  \n \n       憎恨和讨厌也会造成由简单联想引起的认知错误。在企业界，我\n常常看到人们贬低他们讨厌的竞争对手的能力和品德。这是一种危险的做法，通','2026-07-05 16:55:53.049000',0,2073692323954429952,524,2073692323514028032),(2073692328396197896,' \n       憎恨和讨厌也会造成由简单联想引起的认知错误。在企业界，我\n常常看到人们贬低他们讨厌的竞争对手的能力和品德。这是一种危险的做法，通\n常不易察觉，因为它是发生在潜意识层面的。  \n \n       有关某个人或者某个讨厌结果的简单联想也会造成另外一种常\n见的恶果，这可以从“波斯信使综合症”中看出来。古代波斯人真的会把信使杀\n掉，而这些信使惟一的过错是把真实的坏消息（比如说战败）带回家。对于信使\n来说，逃跑并躲起来，真的要比依照上级的心愿完成使命安全得多。  \n \n       波斯信使综合症在现代生活中仍然很常见，尽管不再像原来那样\n动辄出人命。在许多职业里，成为坏消息传递者真的是很危险的。工会谈判专家\n和雇主代表通常懂得这个道理，它在劳资关系中引发了许多悲剧。有时候律师知\n道，如果他们推荐一种不受欢迎然而明智的解决方案，将会招来客户的怨恨，所','2026-07-05 16:55:53.049000',0,2073692323954429952,525,2073692323514028032),(2073692328396197897,'和雇主代表通常懂得这个道理，它在劳资关系中引发了许多悲剧。有时候律师知\n道，如果他们推荐一种不受欢迎然而明智的解决方案，将会招来客户的怨恨，所\n以他们会继续把官司打下去，乃至造成灾难性的后果。即使在许多以认知程度高\n而著称的地方，人们有时候也会发现波斯信使综合症。例如，几年前，两家大型\n石油公司在得克萨斯的审判庭打起了官司，因为它们合作开发西半球最大油田的\n协议中有含糊的地方。我猜想他们打官司的起因是某位法律总顾问先前发现合同\n有问题，却不敢把坏消息告诉一位刚愎自用的 CEO。  \n \n       哥伦比亚广播公司（CBS）在其巅峰期行将结束的时候就以波斯\n信使综合症闻名，因为董事会主席佩利（注：William Samuel Paley，1901—1990，\nCBS 前董事长及执行长，他将 CBS 从一个小广播公司发展成为美国三大广播电视','2026-07-05 16:55:53.049000',0,2073692323954429952,526,2073692323514028032),(2073692328396197898,'CBS 前董事长及执行长，他将 CBS 从一个小广播公司发展成为美国三大广播电视\n网之一）特别讨厌那些告诉他坏消息的人。结果是，佩利生活在谎言的壳子之中，\n一次又一次地作出了错误的交易，甚至用大量哥伦比亚广播公司的股票去收购一\n家后来很快被清盘的公司。  \n \n       要避免像哥伦比亚广播公司那样因波斯信使综合症而自食其果，\n正确的对策是有意识地，养成欢迎坏消息的习惯。伯克希尔有一条普遍的规矩：\n“有坏消息要立刻向我们汇报。只有好消息是我们可以等待的。”还有就是要保\n持明智和消息灵通，那就是让人们知道你有可能从别处听说坏消息，这样他们就\n不敢不把坏消息告诉你了。  \n \n       受简单联想影响的倾向通常在消除以德报德的自然倾向方面有\n惊人的效果。有时候，当某个人接受恩惠时，他所处的境况可能很差，比如说穷\n困潦倒、疾病缠身、饱受欺凌等等。除此之外，受惠者可能会妒忌施惠者优越的','2026-07-05 16:55:53.049000',0,2073692323954429952,527,2073692323514028032),(2073692328396197899,'惊人的效果。有时候，当某个人接受恩惠时，他所处的境况可能很差，比如说穷\n困潦倒、疾病缠身、饱受欺凌等等。除此之外，受惠者可能会妒忌施惠者优越的\n处境，从而讨厌施惠者。在这样的情况下，由于施惠的举动让受惠者联想起自身\n的不幸遭遇，受惠者不但会讨厌那个帮助他的人，还会试图去伤害他。这解释了\n那个著名反应（有人认为是亨利·福特说的）：“这人为什么如此憎恨我呢？我\n又没有为他做过什么事情。”我有个朋友，现在姑且叫他“格罗兹”吧，乐善好\n施的他有过一次啼笑皆非的遭遇。格罗兹拥有一座公寓楼，他先前买下来，准备\n将来用那块地来开发另外一个项目。考虑到这个计划，格罗兹对房客非常大方，\n向他们收取的租金远远低于市场价。后来格罗兹准备拆掉整座大楼，在举行公开\n听证会的时候，有个欠了许多租金没有交的房客表现得特别气愤，并在听证会上\n说：“这个计划太让人气愤了。格罗兹根本就不需要更多的钱。我清楚得很，因','2026-07-05 16:55:53.049000',0,2073692323954429952,528,2073692323514028032),(2073692328396197900,'听证会的时候，有个欠了许多租金没有交的房客表现得特别气愤，并在听证会上\n说：“这个计划太让人气愤了。格罗兹根本就不需要更多的钱。我清楚得很，因\n为我就是靠格罗兹的奖学金才念完大学的。”  \n \n       最后一类由简单联想引起的严重思维错误出现在人们经常使用\n的类型化思考中。因为彼得知道乔伊今年 90 岁，也知道绝大多数 90 岁的老头脑\n袋都不太灵光，所以彼得认为老乔伊是个糊涂蛋，即使老乔伊的脑袋依然非常好\n使。或者因为阿珍是一位白发苍苍的老太太，而且彼得知道没有老太太精通高等\n数学，所以彼得认为阿珍也不懂高等数学，即使阿珍其实是数学天才。这种思考\n错误很自然，也很常见。要防止犯这种错误，彼得的对策并非去相信 90 岁的人\n脑袋总的来说跟 40 岁的人一样灵活，或者获得数学博士学位的女性和男性一样\n多。与之相反，彼得必须认识到趋势未必能够正确地预测终点，彼得必须认识到','2026-07-05 16:55:53.049000',0,2073692323954429952,529,2073692323514028032),(2073692328396197901,'脑袋总的来说跟 40 岁的人一样灵活，或者获得数学博士学位的女性和男性一样\n多。与之相反，彼得必须认识到趋势未必能够正确地预测终点，彼得必须认识到\n他未必能够依据群体的平均属性来准确地推断个体的特性。否则彼得将会犯下许\n多错误，就像某个在一条平均水深 18 英寸的河流中被淹死的人那样。 \n十一简单的、避免痛苦的心理否认 \n \n \n       我最早遇到这种现象，是在二战期间。当时我们家有位世交的\n儿子学习成绩非常出色，在体育运动方面也非常有天赋，可惜他乘坐的飞机在\n大西洋上空失事，再也没有回来。他母亲的头脑十分正常，但她拒绝相信他已\n经去世。那就是简单的、避免痛苦的心理否认。现实太过痛苦，令人无法承受，\n所以人们会扭曲各种事实，直到它们变得可以承受。我们或多或少都有这种毛\n病，而这经常会引发严重的问题。这种倾向造成的最极端的后果经常跟爱情、','2026-07-05 16:55:53.049000',0,2073692323954429952,530,2073692323514028032),(2073692328396197902,'所以人们会扭曲各种事实，直到它们变得可以承受。我们或多或少都有这种毛\n病，而这经常会引发严重的问题。这种倾向造成的最极端的后果经常跟爱情、\n死亡和对化学物质（酒精、毒品等）的依赖有关。  \n \n       当否认是被用来让死亡更容易接受时，这种行为不会遭到任何\n批评。在这样的时刻，谁会忍心落井下石呢？但有些人希望在生活中坚持下面\n这条铁律：“未必要有希望才能够坚持。”能够做到这一点的人是非常可敬的。  \n \n       对化学物质的依赖通常会导致道德沦丧，成瘾的人倾向于认为\n他们的处境仍然很体面，仍然会有体面的前途。因此，他们在越来越堕落的过\n程中，会表现得极其不现实，对现实进行极端的否认。在我年轻的时代，弗洛\n伊德式疗法对逆转化学物质依赖性完全没有效用，但现在酒瘾戒除组织通过造\n成数种心理倾向一起来对抗酒瘾，能够把戒除率稳定在 95%。然而整个治疗过程','2026-07-05 16:55:53.049000',0,2073692323954429952,531,2073692323514028032),(2073692328396197903,'伊德式疗法对逆转化学物质依赖性完全没有效用，但现在酒瘾戒除组织通过造\n成数种心理倾向一起来对抗酒瘾，能够把戒除率稳定在 95%。然而整个治疗过程\n都很难，很耗费精力，而且 50%的成功率也意味着 50%的失败率。人们应该避免\n任何有可能养成化学物质依赖性的行为。由于这种依赖性会造成极大的伤害，\n所以哪怕只有很少的概率会染上，也应该坚决避免。 \n十二 自视过高的倾向 \n \n \n       自视过高的人比比皆是。这种人会错误地高估自己，就好像瑞\n典有 90%的司机都认为他们的驾驶技术在平均水平之上。这种误评也适用于人们\n的主要“私人物品”。人们通常会过度称赞自己的配偶。人们通常不会客观地看\n待自己的孩子，而是会给出过高的评价。甚至人们的细小私人物品也一般会得到\n过度的称赞。人们一旦拥有某件物品之后，对该物品的价值评估就会比他们尚未','2026-07-05 16:55:53.049000',0,2073692323954429952,532,2073692323514028032),(2073692328396197904,'待自己的孩子，而是会给出过高的评价。甚至人们的细小私人物品也一般会得到\n过度的称赞。人们一旦拥有某件物品之后，对该物品的价值评估就会比他们尚未\n拥有该物品之前对其的价值评估要高。这种过度高估自己的私人物品的现象在心\n理学里面有个名称：“禀赋效应”。人们作出决定之后，就会觉得自己的决定很\n好，甚至比没作出这种决定之前所认为的还要好。  \n \n       当自视过高的倾向往往会使人们偏爱那些和自己相似的人。有些\n心理学教授们用很好玩的“丢钱包”实验证明了这种效应。他们的实验全都表\n明，如果捡到钱包的人根据钱包里的身份线索发现失主跟自己很相似，那么他把\n钱包还给失主的可能性是最高的。由于人类的这种心理特性，相似的人组成的派\n系群体总是人类文化中非常有影响的一部分，甚至在我们明智地试图消除其最糟\n糕的效果之后仍是如此。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,533,2073692323514028032),(2073692328396197905,'系群体总是人类文化中非常有影响的一部分，甚至在我们明智地试图消除其最糟\n糕的效果之后仍是如此。  \n \n       现代生活中有一些非常糟糕的派系群体，它们被一群自视过高的\n人把持，并只从那些和他们非常相似的人中挑选新成员，现代生活可能就会出现\n一些非常糟糕的结果。因此，如果某个名牌大学的英语学系学术水平变得很低下，\n或者某家经纪公司的销售部门养成了经常诈骗的习惯，那么这些问题将会有一种\n越来越糟糕的自然倾向，而且这种倾向很难被扭转。这种情况也存在于那些变得\n腐败的警察部门、监狱看守队伍或者政治群体中，以及无数其他充满了坏事和蠢\n事的地方，比如说美国有些大城市的教师工会就很糟糕，它们不惜伤害我们的儿\n童，力保那些本该被开除的低能教师。因此，我们这个文明社会中最有用的成员\n就是那些发现他们管理的机构内部出问题时愿意“清理门户”的负责人。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,534,2073692323514028032),(2073692328396197906,'童，力保那些本该被开除的低能教师。因此，我们这个文明社会中最有用的成员\n就是那些发现他们管理的机构内部出问题时愿意“清理门户”的负责人。  \n \n       自然了，各种形式的自视过高都会导致错误。怎么能不会呢？  \n \n       让我们以某些愚蠢的赌博投注为例。在买彩票时，如果号码是随\n机分配的，下的赌注就会比较少，而如果号码是玩家自己挑选的，下的赌注就会\n比较多。这是非常不理性的。这两种选号法中奖的概率几乎是完全相同的，玩家\n中奖的机会都是微乎其微的。现代人本来不会买那么多彩票的，但国家彩票发行\n机构利用了人们对自选号码的非理性偏好，所以他们每次都很愚蠢地买了更多的\n彩票。  \n \n       那种过度称赞自己的私人物品的“禀赋效应”强化了人们对自\n己的结论的热爱。你们将会发现，一个已经在商品交易所购买了五花肉期货的人','2026-07-05 16:55:53.049000',0,2073692323954429952,535,2073692323514028032),(2073692328400392192,'彩票。  \n \n       那种过度称赞自己的私人物品的“禀赋效应”强化了人们对自\n己的结论的热爱。你们将会发现，一个已经在商品交易所购买了五花肉期货的人\n现在愚蠢地相信，甚至比以前更加强烈地相信，他的投机行为具有许多优点。  \n \n       有些人热爱体育运动，自以为对各个队伍之间的相对优势十分了\n解，这些人会愚蠢地去买体育彩票。和赛马博彩相比，体育彩票更容易上瘾——\n部分原因就在于人们会自动地过度赞赏他自己得出的复杂结论。  \n \n       在讲究技巧的比赛——比如说高尔夫球赛或者扑克赌牌比赛\n——中，人们总是一次又一次地挑选那些水平明显比自己高得多的玩家作对手，\n这种倾向同样会产生极端的事与愿违的后果。自视过高的倾向降低了这些赌徒在\n评估自己的相对能力时的准确性。  \n \n       然而更具有负面作用的是，人们通常会高估自己未来为企业提供','2026-07-05 16:55:53.049000',0,2073692323954429952,536,2073692323514028032),(2073692328400392193,'评估自己的相对能力时的准确性。  \n \n       然而更具有负面作用的是，人们通常会高估自己未来为企业提供\n的服务质量。他们对这些未来贡献的过度评价常常会造成灾难性的后果。  \n \n       自视过高往往会导致糟糕的雇佣决定，因为大部分雇主高估了他\n们根据面试印象所得结论的价值。防止这种蠢事的正确对策是看轻面试的印象，\n看重求职者以往的业绩。  \n \n       我曾经正确地选择了这种做法，当时我担任某个学术招聘委员会\n的主席。我说服其他委员别再对求职者进行面试，只要聘用那个书面申请材料比\n其他求职者优秀很多的人就可以了。有人对我说，我没有尊重“学术界的正常程\n序”，我说我才是真正尊重学术的人，因为学术研究表明，从面试中得来的印象，\n其预测价值很低，我正在应用这个成果。  \n \n       人们非常有可能过度地受到当面印象的影响，因为从定义上来','2026-07-05 16:55:53.049000',0,2073692323954429952,537,2073692323514028032),(2073692328400392194,'其预测价值很低，我正在应用这个成果。  \n \n       人们非常有可能过度地受到当面印象的影响，因为从定义上来\n讲，当面印象包括了人们的主动参与。由于这个原因，现代企业在招聘高层管理\n人员时，如果遇到的求职者能说会道，那么就有可能遭遇很大的危险。依我之见，\n惠普当年面试口齿伶俐的卡莉·菲奥里纳（注：卡莉·菲奥里纳，1954—，1999\n年至 2005 年期间担任惠普公司 CEO），想任命她为新总裁时，就面临着这样的\n危险。我认为：（1）惠普选择菲奥里纳女士是一个糟糕的决定；（2）如果惠普\n懂得更多的心理学知识，采取了相应的预防措施，它就不会作出这个糟糕的决定。  \n \n       托尔斯泰的作品中有一段著名的文字显示了自视过高的威力。在\n托尔斯泰看来，那些恶贯满盈的罪犯并不认为他们自己有那么坏。他们或者认为\n（1）他们从来没有犯过罪；或（2）考虑到他们在生活中遭遇的压力和种种不幸，','2026-07-05 16:55:53.049000',0,2073692323954429952,538,2073692323514028032),(2073692328400392195,'托尔斯泰看来，那些恶贯满盈的罪犯并不认为他们自己有那么坏。他们或者认为\n（1）他们从来没有犯过罪；或（2）考虑到他们在生活中遭遇的压力和种种不幸，\n他们做出他们所做过的事，变成他们所成为的人，是完全可以理解和值得原谅的。  \n \n       “托尔斯泰效应”的后半部分，也就是人们不去改变自己，而是\n为自己那些可以改变的糟糕表现寻找借口，是极其重要的。由于绝大多数人都会\n为可以改变的糟糕表现寻找太多荒唐的理由，以此来试图让自己心安理得，所以\n采用个人和机构的对策来限制这种愚蠢的观念造成的破坏是非常有必要的。从个\n人层面来说，人们应该试图面对两个事实：（1）如果一个人能够改正糟糕的表\n现，却没有去改正，而是给自己找各种各样的借口，那他就是品德有问题，而且\n将会遭受更多的损失；（2）在要求严格的地方，比如说田径队或者通用电气，','2026-07-05 16:55:53.049000',0,2073692323954429952,539,2073692323514028032),(2073692328400392196,'现，却没有去改正，而是给自己找各种各样的借口，那他就是品德有问题，而且\n将会遭受更多的损失；（2）在要求严格的地方，比如说田径队或者通用电气，\n如果一个人不做出应有的表现，而是不停地找借口，那么他迟早肯定会被开除。\n而机构化解这种“托尔斯泰效应”的对策是：（1）建设一种公平的、唯才是用\n的、要求严格的文化，外加采用能够提升士气的人力资源管理方法；（2）开除\n最糟糕的不守规矩者。当然啦，如果你不能开除，比如说你不能“开除”你的孩\n子，你必须尽最大努力去帮助这个孩子解决问题。我听过一个教育孩子的故事特\n别有效，那个孩子过了 50 年还对学到的教训念念不忘。那孩子后来变成了南加\n州大学音乐学院的院长。他小时候曾经从他父亲的老板的仓库里偷糖果吃，被他\n父亲发现之后辩解说，他打算过会就放回去。他父亲说：“儿子，你还不如想要\n什么就拿什么，然后在每次这么做的时候，都把自己称为小偷。”  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,540,2073692323514028032),(2073692328400392197,'父亲发现之后辩解说，他打算过会就放回去。他父亲说：“儿子，你还不如想要\n什么就拿什么，然后在每次这么做的时候，都把自己称为小偷。”  \n \n       避免因为自视过高而做傻事的最佳方法是，当你评价你自己、你\n的亲人朋友、你的财产和你过去未来的行动的价值时，强迫自己要更加客观。这\n是很难做到的，你也无法做到完全客观，但比起什么都不做，放任天生的心理倾\n向不受约束地发展，却又好得多。  \n \n       虽然自视过高通常会给认知带来负面的影响，但也能引起某些离\n奇的成功，因为有时过度自信刚好促成了某项成功。这个因素解释了下面这句格\n言：“千万别低估那些高估自己的人。”  \n \n       当然，有时候高度的自我称赞是正确的，而且比虚伪的谦虚要好\n得多。此外，如果人们因为出色地完成了任务，或者拥有美好的人生而感到骄傲，','2026-07-05 16:55:53.049000',0,2073692323954429952,541,2073692323514028032),(2073692328400392198,' \n       当然，有时候高度的自我称赞是正确的，而且比虚伪的谦虚要好\n得多。此外，如果人们因为出色地完成了任务，或者拥有美好的人生而感到骄傲，\n那么这种自我赞赏是一种非常有建设性的力量。如果没有这种自豪感，会有更多\n的飞机坠毁。“骄傲”是另外一个被大多数心理学教科书漏掉的词汇，这种疏漏\n并不是一个好主意。把《圣经》中那个关于法利赛人和税吏的寓言解读为对骄傲\n的谴责也并不是一个好主意。  \n \n       在所有有益的骄傲中，也许最值得钦佩的是因为自己值得信赖而\n产生的骄傲。此外，一个人只要值得信赖，哪怕他选的道路崎岖不平，他的生活\n也会比那些不值得信赖的人要好得多。 \n十三 过度乐观倾向 \n \n \n       大约在基督出生之前 300 年，古希腊最著名的演说家德摩斯梯\n尼说：“一个人想要什么，就会相信什么。”  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,542,2073692323514028032),(2073692328400392199,'十三 过度乐观倾向 \n \n \n       大约在基督出生之前 300 年，古希腊最著名的演说家德摩斯梯\n尼说：“一个人想要什么，就会相信什么。”  \n \n       从语法上来分析，德摩斯梯尼这句话的含义是，人们不但会表现\n出简单的、避免痛苦的心理否认，而且甚至在已经做得非常好的时候，还会表现\n出过度的乐观。  \n \n       看到人们兴高采烈地购买彩票，或者坚信那些刷卡支付、快递上\n门的杂货店将会取代许多现金付款、自提货物的高效超市，我认为那位希腊演说\n家是正确的。人们就算并不处在痛苦之中，或者遭到痛苦的威胁，也确实会有过\n度乐观的心理。  \n \n       解决愚蠢的乐观主义的正确方法是通过学习，习惯性地应用费马\n和帕斯卡的概率论。在我年轻时，高二的学生就会学到这种数学知识。自然进化\n为你们的大脑提供的经验法则是不足以应付危机的。就好比你们想成为高尔夫球','2026-07-05 16:55:53.049000',0,2073692323954429952,543,2073692323514028032),(2073692328400392200,'和帕斯卡的概率论。在我年轻时，高二的学生就会学到这种数学知识。自然进化\n为你们的大脑提供的经验法则是不足以应付危机的。就好比你们想成为高尔夫球\n员，你们不能使用长期的进化赋予你的挥杆方式，而必须掌握一种不同的抓杆和\n挥杆方法，这样才能成为好的高尔夫球员。 \n十四 被剥夺超级反应倾向 \n \n \n       一个人从 10 美元中得到的快乐的分量，并不正好等于失去 10\n美元给他带来的痛苦的分量。也就是说，失去造成的伤害比得到带来的快乐多得\n多。除此之外，如果有个人即将得到某样他非常渴望的东西，而这样东西却在最\n后一刻飞走了，那么他的反应就会像这件东西他已经拥有了很久却突然被夺走一\n样。我用一个名词来涵括人类对这两种损失经验（损失已有的好处和损失即将拥\n有的好处）的自然反应，那就是被剥夺超级反应倾向。  \n \n       人们在表现出被剥夺超级反应倾向的过程中，经常会因为小题大','2026-07-05 16:55:53.049000',0,2073692323954429952,544,2073692323514028032),(2073692328400392201,'有的好处）的自然反应，那就是被剥夺超级反应倾向。  \n \n       人们在表现出被剥夺超级反应倾向的过程中，经常会因为小题大\n作而惹来麻烦。他往往会对眼前的损失斤斤计较，而不会想到那损失也许是无关\n紧要的。例如，一个股票账户里有 1000 万美元的人，通常会因为他钱包里的 300\n美元不小心损失了 100 美元而感到极端的不快。  \n \n       芒格夫妇曾经养过一条温顺而善良的狗，这条狗会表现出犬类的\n被剥夺超级反应倾向。只有一种办法能让这条狗咬人，那就是在给它喂食的时候，\n把食物从它嘴里夺走。如果你那么做的话，这条友善的狗会自动地咬你。它忍不\n住。对于狗来说，没有什么比咬主人更愚蠢的事情。但这条狗没办法不愚蠢，它\n天生就有一种自动的被剥夺超级反应倾向。  \n \n       人类和芒格家的狗差不多。人们在失去——或者有可能失去——','2026-07-05 16:55:53.049000',0,2073692323954429952,545,2073692323514028032),(2073692328400392202,'天生就有一种自动的被剥夺超级反应倾向。  \n \n       人类和芒格家的狗差不多。人们在失去——或者有可能失去——\n财产、爱情、友谊、势力范围、机会、身份或者其他任何有价值的东西时，通常\n会做出不理性的激烈反应，哪怕只失去一点点时也是如此。因此，因为势力范围\n受到威胁而发生的内耗往往会给整个组织造成极大的破坏。正是由于这个因素和\n其他因素的存在，杰克·韦尔奇长期致力于扫荡通用电气中的官僚作风是很明智\n的行为。很少企业领袖在这方面做得比杰克·韦尔奇更好。  \n \n       被剥夺超级反应倾向通常能够保护意识形态观点或者宗教观点，\n因为它能够激发直接针对那些公开质疑者的讨厌/憎恨心理倾向。这种情况会发\n生，部分原因在于，这些观点现在高枕无忧，并拥有强大的信念维护体系，而质\n疑者的思想若是得到扩散，将会削弱它们的影响力。大学的人文社科院系、法学','2026-07-05 16:55:53.049000',0,2073692323954429952,546,2073692323514028032),(2073692328400392203,'生，部分原因在于，这些观点现在高枕无忧，并拥有强大的信念维护体系，而质\n疑者的思想若是得到扩散，将会削弱它们的影响力。大学的人文社科院系、法学\n院和各种商业组织都表现出这种以意识形态为基础的团体意识，他们拒绝几乎所\n有和它们自身的知识有矛盾的外来知识。当公开批评者是一位从前的信徒，那么\n敌意会更加强烈，原因有两个：（1）遭到背叛会激发额外的被剥夺超级反应倾\n向，因为失去了一名同志；（2）担心那些矛盾的观点会特别有说服力，因为它\n们来自一个先前的同志。前面提到的这些因素有助于我们理解古代人对异教徒的\n看法。数百年来，正统教会基于这样的理由杀害了许许多多异教徒，而且在杀死\n他们之前通常还会施以酷刑，或者干脆就将他们活活烧死。  \n \n       极端的意识形态是通过强烈的方式和对非信徒的极大敌意得到\n维护的，这造成了极端的认知功能障碍。这种情况在世界各地屡见不鲜。我认为','2026-07-05 16:55:53.049000',0,2073692323954429952,547,2073692323514028032),(2073692328400392204,' \n       极端的意识形态是通过强烈的方式和对非信徒的极大敌意得到\n维护的，这造成了极端的认知功能障碍。这种情况在世界各地屡见不鲜。我认为\n这种可悲的结果往往是由两种心理倾向引起的：（1）避免不一致性倾向；（2）\n被剥夺超级反应倾向。  \n \n       有一种办法能够化解这种受到刻意维护的团体意识，那就是建设\n一种极端讲礼貌的文化，哪怕双方的意识形态并不相同，但彼此之间要保持彬彬\n有礼，就像现在美国最高法院的行为那样。另外一种方法是刻意引进一些对现在\n的团体意识抱怀疑态度而又能力突出、能言善辩的人。德雷克·伯克（注：德雷\n克·伯克，1930—，美国律师和教育家，哈佛大学前校长）曾经成功地改变了一\n种造成糟糕后果的团体思维。他在担任哈佛大学校长期间，否决了不少由哈佛法\n学院那些意识形态很强的教授所推荐的终身教职人选。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,548,2073692323514028032),(2073692328400392205,'种造成糟糕后果的团体思维。他在担任哈佛大学校长期间，否决了不少由哈佛法\n学院那些意识形态很强的教授所推荐的终身教职人选。  \n \n       一个一百八十度的景观哪怕损失了一度，有时候也足够引起让邻\n居反目成仇的被剥夺超级反应倾向。我买过一座房子，原来的房东和他的邻居因\n为他们之中一人新种了一颗小树苗而结下深仇大恨。  \n \n       正如这两个邻居的事例所展现的，在某些规划听证会上，有些邻\n居为了某些细枝末节的事情而吵得不可开交，表现出非理性的、极端的被剥夺超\n级反应，看到这样的事情可不会令人愉快。这种糟糕的行为促使有些人离开了政\n府规划部门。我曾经向一位工匠买过高尔夫球杆，他原本是个律师。当我问他以\n前从事哪方面的法律工作时，我以为我会听到他说“婚姻法”，但他的答案是\n“规划法”。  \n \n       被剥夺超级反应倾向对劳资关系的影响是巨大的。第一次世界大','2026-07-05 16:55:53.049000',0,2073692323954429952,549,2073692323514028032),(2073692328400392206,'“规划法”。  \n \n       被剥夺超级反应倾向对劳资关系的影响是巨大的。第一次世界大\n战之前发生的劳资纠纷中的死亡事件，绝大多数是在雇主试图削减工资时造成\n的。现在出人命的情况比较少见，但更多的公司消失了，因为激烈的市场竞争只\n提供两种选择，要么工资降低——而这是不会得到同意的——要么企业死掉。被\n剥夺超级反应倾向促使许多工人抵制降薪计划，而往往工人接受降薪对他们本身\n更有好处。  \n \n       在劳资关系以外的地方，剥夺人们原本拥有的好处也是很难的。\n因此，若是人们能够更加理性地思考，在潜意识层面上更少受到被剥夺超级反应\n倾向的驱使，许多已经发生的悲剧是完全可以避免的。  \n \n       被剥夺超级反应倾向也是导致某些赌徒倾家荡产的重要原因之\n一。首先，它使得赌徒输钱之后急于扳平，输得越多，这种不服输的心理就越严','2026-07-05 16:55:53.049000',0,2073692323954429952,550,2073692323514028032),(2073692328400392207,' \n       被剥夺超级反应倾向也是导致某些赌徒倾家荡产的重要原因之\n一。首先，它使得赌徒输钱之后急于扳平，输得越多，这种不服输的心理就越严\n重。其次，最容易让人上瘾的赌博形式就是设计出许多差点就赢的情况，而这些\n情况会激发被剥夺超级反应倾向。有些老虎机程序设计者恶毒地利用了这个人性\n弱点。电子技术允许这些设计者制造出大量无意义的“BARBAR-柠檬”结果，这\n些结果会促使那些以为自己差点赢得大奖的蠢货拼命地继续加注。  \n \n       被剥夺超级反应倾向常常给那些参加公开竞拍的人带来很多损\n失。我们下面就要讨论到的“社会认可”倾向促使竞买者相信其他竞买者的最新\n报价是合理的，然后被剥夺超级反应倾向就会强烈地驱使他去报一个更高的价\n格。要避免因此而在公开报价拍卖会上付出愚蠢的价格，最佳的办法是巴菲特的\n简单做法：别去参加这些拍卖会。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,551,2073692323514028032),(2073692328400392208,'格。要避免因此而在公开报价拍卖会上付出愚蠢的价格，最佳的办法是巴菲特的\n简单做法：别去参加这些拍卖会。  \n \n       被剥夺超级反应倾向和避免不一致性倾向通常会联合造成一种\n形式的经营失败。在这种形式的失败中，一个人会耗尽他所有的优质资产，只为\n徒劳地试图去挽救一个变得很糟糕的投资项目。要避免这种蠢事，最佳的办法之\n一是趁年轻的时候好好掌握打扑克牌的技巧。扑克牌的教育意义在于，并非全部\n有效的知识都来自正规的学校教育。  \n \n       在这里，我本人的教训可能很有示范意义。几十年前，我曾犯过\n一个大错误，而犯错的部分原因就是我在潜意识中受到被剥夺超级反应倾向的影\n响。当时我有个股票经纪人朋友给我打电话，说要以低得离谱的价格卖给我 300\n股交易率极低的贝尔里奇石油（Belridge）公司的股票，每股只要 115 美元。我','2026-07-05 16:55:53.049000',0,2073692323954429952,552,2073692323514028032),(2073692328400392209,'响。当时我有个股票经纪人朋友给我打电话，说要以低得离谱的价格卖给我 300\n股交易率极低的贝尔里奇石油（Belridge）公司的股票，每股只要 115 美元。我\n用手头的现金买下了这些股票。第二天，他又想以同样的价格再卖给我 1500 股。\n这次我谢绝了，部分原因是我没那么多现金，只能卖掉某些东西或者举债才能筹\n到所需的 173000 美元。这是个非常不理性的决定。当年我生活很好，也不欠债，\n买这只股票没有赔本的风险，而同样没有风险的机会并不是经常有的。不到两年\n之后，壳牌收购了贝尔里奇石油公司，价格是大约每股 3700 美元。如果我当时\n懂得更多心理学知识，买下那些股票，我就能多赚 540 万美元。正如这个故事所\n展示的，人们可能会由于对心理学的无知而付出昂贵的代价。  \n \n       有些人可能会觉得我对被剥夺超级反应倾向的定义太宽泛，把人','2026-07-05 16:55:53.049000',0,2073692323954429952,553,2073692323514028032),(2073692328400392210,'展示的，人们可能会由于对心理学的无知而付出昂贵的代价。  \n \n       有些人可能会觉得我对被剥夺超级反应倾向的定义太宽泛，把人\n们失去即将得到的好处的反应也包括在内，比如说那些老虎机玩家的反应。然而，\n我认为我对这个倾向的定义还应该更加宽泛一些。我提议为这种倾向下更宽泛定\n义的理由是，我知道有许多伯克希尔·哈撒韦的股东在公司市值获得巨大增长之\n后从来不卖掉或者送掉哪怕一股股票。这种反应有些是由理性的计算引起的，而\n有些肯定是由如下几种因素引起的：（1）奖励超级反应；（2）避免不一致性倾\n向造成的“维持现状偏见”；（3）自视过高倾向造成的“禀赋效应”。但我相\n信他们这么做最主要的非理性原因是受到某种被剥夺超级反应倾向的驱使。这些\n股东之中有许多人无法忍受减持伯克希尔·哈撒韦股票的想法。部分原因在于，\n他们认为这只股票是身份和地位的象征，减持它无异于自贬身份；但更重要的原','2026-07-05 16:55:53.049000',0,2073692323954429952,554,2073692323514028032),(2073692328400392211,'股东之中有许多人无法忍受减持伯克希尔·哈撒韦股票的想法。部分原因在于，\n他们认为这只股票是身份和地位的象征，减持它无异于自贬身份；但更重要的原\n因在于，他们担心把股票卖掉或者送掉之后，他们就无法分享未来的收益。 \n十五 社会认同倾向 \n \n \n       如果一个人自动依照他所观察到的周围人们的思考和行动方\n式去思考和行动，那么他就能够把一些原本很复杂的行为进行简化。而且这种从\n众的做法往往是有效的。例如，如果你在陌生城市想去看一场盛大的足球比赛，\n跟着街道上的人流走是最简单的办法。由于这样的原因，进化给人类留下了社会\n认同倾向，也就是一种自动根据他看到的周边人们的思考和行动方式去思考和行\n动的倾向。  \n \n       心理学教授喜欢研究社会认同倾向，因为在他们的实验中，这种\n倾向造成了许多可笑的结果。例如，如果一名教授安排 1 0 名实验员静静地站在','2026-07-05 16:55:53.049000',0,2073692323954429952,555,2073692323514028032),(2073692328400392212,' \n       心理学教授喜欢研究社会认同倾向，因为在他们的实验中，这种\n倾向造成了许多可笑的结果。例如，如果一名教授安排 1 0 名实验员静静地站在\n电梯里，并且背对着电梯口，那么当陌生人走进电梯时，通常也会转过身去，摆\n出相同的姿势。心理学教授还能利用社会认同倾向促使人们在测量东西时出现很\n大、很荒唐的误差。  \n \n       当然，家有儿女的父母经常无奈地了解到，青少年特别容易由于\n社会认同倾向而出现认知错误。最近，朱迪丝·瑞奇·哈里斯（Judith Rich \nHarris）对这种现象的研究取得了突破性的成果。朱迪丝证明，年轻人最尊重的\n是他们的同龄人，而不是他们的父母或者其他成年人，这种现象在很大程度上是\n由年轻人的基因决定的。所以对于父母来说，与其教训子女，毋宁控制他们交往\n朋友的质量。后者是更明智的做法。哈里斯女士在新发现的理由支持之下，提供','2026-07-05 16:55:53.049000',0,2073692323954429952,556,2073692323514028032),(2073692328400392213,'由年轻人的基因决定的。所以对于父母来说，与其教训子女，毋宁控制他们交往\n朋友的质量。后者是更明智的做法。哈里斯女士在新发现的理由支持之下，提供\n了一种如此优秀和有用的见解，像她这样的人，真是没白活。  \n \n       在企业的高管层中，像青少年一样有从众心理的领导人也并不少\n见。如果有家石油公司愚蠢地买了一个矿场，其他石油公司通常会很快地加入收\n购矿场的行列。如果被收购的是一家化肥厂，情况也是如此。实际上，石油公司\n的这两种收购曾经蔚然成风，而它们收购的结果都很糟糕。  \n \n       当然，对于石油公司来说，找到和正确地评估各种可以用来使用\n现金的项目是很困难的。所以和每个人一样，石油公司的高管人员也因为迟疑不\n决而感到烦躁，所以匆匆作出了许多错误的决定。跟随其他石油公司的行动所提\n供的社会认同自然能够终止这种迟疑不决。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,557,2073692323514028032),(2073692328400392214,'决而感到烦躁，所以匆匆作出了许多错误的决定。跟随其他石油公司的行动所提\n供的社会认同自然能够终止这种迟疑不决。  \n \n       社会认同倾向在什么时候最容易被激发呢？许多经验给出了下\n面这个明显的答案：人们在感到困惑或者有压力的时候，尤其是在既困惑又有压\n力的时候，最容易受社会认同倾向影响。  \n \n       由于压力能够加强社会认同倾向，有些卑鄙的销售机构会操纵目\n标群体，让他们进入封闭和充满压力的环境，进行一些像把沼泽地卖给中小学教\n师之类的销售活动。封闭的环境强化了那些骗子和率先购买者的社会认同效应，\n而压力（疲惫通常会增加压力）则使目标群体更容易受到社会认同的影响。当然，\n有些邪教组织模仿了这些欺诈性的销售技巧。有个邪教组织甚至还使用响尾蛇来\n增强目标群体的压力，威逼他们加入该组织。  \n \n       由于坏行为和好行为都会通过社会认同倾向而得到传播，所以对','2026-07-05 16:55:53.049000',0,2073692323954429952,558,2073692323514028032),(2073692328404586496,'增强目标群体的压力，威逼他们加入该组织。  \n \n       由于坏行为和好行为都会通过社会认同倾向而得到传播，所以对\n于人类社会而言，下面两种措施是非常重要的：（1）在坏行为散播之前阻止它；\n（2）倡导和展现所有的好行为。  \n \n       我父亲曾经对我说，他刚在奥马哈当上律师之后不久，和一大帮\n人从内布拉斯加州去南达科他州猎杀野鸡。当时南达科他州的打猎许可证是要收\n钱的，比如说南达科他州本地居民要缴纳两美元，而非本地居民要缴纳五美元。\n在我父亲之前，所有内布拉斯加居民都用伪造的南达科他州地址去申领南达科他\n州打猎许可证。我父亲说，轮到他的时候，他禁止自己仿效其他人从某种程度上\n来讲是违法的做法。  \n \n       并非所有人都能抵制坏行为的社会传染。因此，我们往往会遇到\n“谢皮科综合症”：它指的是弗兰克·谢皮科所加入的那个纽约警察局极其腐败','2026-07-05 16:55:53.049000',0,2073692323954429952,559,2073692323514028032),(2073692328404586497,' \n       并非所有人都能抵制坏行为的社会传染。因此，我们往往会遇到\n“谢皮科综合症”：它指的是弗兰克·谢皮科所加入的那个纽约警察局极其腐败\n的情况。谢皮科因为拒绝和警察局的同事同流合污，差点遭到枪杀。这种腐败现\n象是由社会认同倾向和激励机制引起的，这两种因素共同造成了“塞皮科综合\n症”。我们应该多多宣讲谢皮科的故事，因为这个可怕的故事向人们展示了社会\n认可倾向这种非常重要的因素会造成一种非常严重的邪恶现象。  \n \n       而就社会认同而言，人们不仅会受到别人行动的误导，而且也会\n受到别人的不行动的误导。当人们处在怀疑状态时，别人的不行动变成了一种社\n会证据，证明不行动是正确的。因而，许多旁观者的不行动导致了凯蒂·季诺维\n斯（注：凯蒂·季诺维斯，1935—1964，全名为 Catherine Susan Genovese，','2026-07-05 16:55:53.049000',0,2073692323954429952,560,2073692323514028032),(2073692328404586498,'斯（注：凯蒂·季诺维斯，1935—1964，全名为 Catherine Susan Genovese，\n因在纽约皇后区，她所住的公寓附近被暴徒刺死时邻居反应冷漠而引起美国社会\n对“旁观者效应”社会心理现象的广泛关注）之死——这是一个心理学入门课程\n中讨论的著名的故事。  \n \n       在社会认同的范围之内，企业的外部董事通常不会采取任何行\n动。他们不会反对任何比拿斧头杀人程度轻的事情，只有出现了某些令董事会在\n公众面前难堪的情况他们才会干预。我的朋友乔伊·罗思柴尔德（注：乔伊·罗\n思柴尔德，1904—2000，美国律师、商人和慈善家）曾经很好地描述了这种典型\n的董事会文化。他说：“他们问我是否愿意担任西北贝尔公司（Northwest Bell）\n的董事，那是他们问我的最后一个问题。”  \n \n       而在广告和商品促销中，社会认同发挥的重要作用简直超乎人们','2026-07-05 16:55:53.049000',0,2073692323954429952,561,2073692323514028032),(2073692328404586499,'的董事，那是他们问我的最后一个问题。”  \n \n       而在广告和商品促销中，社会认同发挥的重要作用简直超乎人们\n的想像。“有样学样”是一句老话，它指的是这种情况：约翰看到乔伊做了某件\n事，或者拥有某样东西，于是强烈地希望自己也去做那件事，或者拥有那样东西。\n这造成的有趣结果就是，广告商愿意支付大量的钱，就为电影某个一闪而过的喝\n汤镜头中出现的汤罐头是其生产的牌子，而非其他厂家生产的牌子。  \n \n       社会认同倾向通常以一种变态的方式和艳羡/妒忌倾向、被剥夺\n超级反应倾向结合在一起。在这些因素的共同作用之下，许多年前曾发生了一件\n让我们家里人后来想起来就忍俊不禁的事情。当时我的表弟罗斯三岁，我四岁，\n我们俩为了一块小木板而争夺和喊叫，而实际上周围有许多同样的小木板。  \n \n       但是如果成年人在维护意识形态的心理倾向的影响之下做出类','2026-07-05 16:55:53.049000',0,2073692323954429952,562,2073692323514028032),(2073692328404586500,'我们俩为了一块小木板而争夺和喊叫，而实际上周围有许多同样的小木板。  \n \n       但是如果成年人在维护意识形态的心理倾向的影响之下做出类\n似的举动，那就一点都不好笑了，而且将会给整个文明社会造成极大的破坏。中\n东现在的情况就有这样的危险。犹太人、阿拉伯人和所有其他人为了一小块有争\n议的土地而浪费了大量的资源，其实他们随便把那块地分掉对每个人都好，而且\n还能大大降低爆发战争——可能是核战争——的危险。  \n \n       现在人们很少用包括讨论心理倾向造成的影响在内的技巧来解\n决家庭以外的纠纷。考虑到这样做会让人觉得太过天真，而且目前学校传授的心\n理学知识也有许多不足，所以这种结果也许是合情合理的。但由于当今世界存在\n核战争的危险，而有些重要的谈判持续十几年仍未取得进展，我经常想，也许在\n将来的某天，人们会以某种形式采用更多的心理学理论，从而得到更好的结果。','2026-07-05 16:55:53.049000',0,2073692323954429952,563,2073692323514028032),(2073692328404586501,'核战争的危险，而有些重要的谈判持续十几年仍未取得进展，我经常想，也许在\n将来的某天，人们会以某种形式采用更多的心理学理论，从而得到更好的结果。\n如果真的是这样，那么正确的心理学教育将会发挥非常重要的作用。如果年纪大\n的心理学教授比年纪大的物理学教授更难以接受新的知识（这一点几乎是肯定\n的），那么我们也许会像马克斯·普朗克预言的那样，需要等待思想开放的新一\n代的心理学教授成长起来。  \n \n       如果我们只能从各种涉及社会认同倾向的教训中挑选出一个，并\n将其用于自我提高的话，我会选择下面这个教训：学会如何在其他人犯错的时候\n别以他们为榜样，因为很少有比这个更值得掌握的技能。 \n十六 对比错误反应倾向 \n \n \n       因为人类的神经系统并不是精密的科学仪器，所以它必须依靠\n某些更为简单的东西。比如说眼睛，它只能看到在视觉上形成对比的东西。和视','2026-07-05 16:55:53.049000',0,2073692323954429952,564,2073692323514028032),(2073692328404586502,' \n \n       因为人类的神经系统并不是精密的科学仪器，所以它必须依靠\n某些更为简单的东西。比如说眼睛，它只能看到在视觉上形成对比的东西。和视\n觉一样，其他感官也是依靠对比来捕捉信息的。更重要的是，不但感知如此，认\n知也是如此。结果就造成了人类的对比错误反应倾向。  \n \n       很少有其他心理倾向能够比这种倾向对正确思维造成更大的破\n坏。小规模的破坏如下面的例子：一个人花 1000 美元的高价购买了皮质仪表盘，\n仅仅是因为这个价格和他用来购买轿车的 65000 美元相比很低。大规模的破坏经\n常会毁掉终身的幸福，比如说有的女性很优秀，可是她的父母特别糟糕，结果她\n可能会嫁给一个只有跟她父母比起来才算不错的男人。或者说有的男性娶的第二\n位妻子只有跟第一位妻子比起来才算过得去。  \n \n       某些房地产经纪公司采用的推销方法尤其应该受到谴责。买家是','2026-07-05 16:55:53.049000',0,2073692323954429952,565,2073692323514028032),(2073692328404586503,'位妻子只有跟第一位妻子比起来才算过得去。  \n \n       某些房地产经纪公司采用的推销方法尤其应该受到谴责。买家是\n外地的，也许急于把家搬到这座城市，于是匆匆来到房地产经纪公司。经纪人故\n意先带着这位顾客看了三套条件十分糟糕而且价格贵得离谱的房子，然后他又带\n着顾客去看一套条件一般糟糕、价格也一般贵的房子。这样一来，经纪人通常很\n容易就能达成交易。  \n \n       对比错误反应倾向常常被用于从购买商品和服务的顾客身上赚\n取更多的钱。为了让正常的价格显得很低，商家通常会瞎编一个比正常价格高很\n多的虚假价格，然后在广告中把他的标准价格显示为其伪造价格的折扣价。人们\n即使对这种操纵消费者的伎俩心知肚明，也往往忍不住会上当。这种现象部分地\n解释了报纸上有那么多广告的原因。它还证明了这个道理：了解心理操纵伎俩并\n非就是一种完美的防御措施。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,566,2073692323514028032),(2073692328404586504,'解释了报纸上有那么多广告的原因。它还证明了这个道理：了解心理操纵伎俩并\n非就是一种完美的防御措施。  \n \n       当一个人逐步逐步走向灭亡时，如果他每一步都很小，大脑的对\n比错误反应倾向通常会任由这个人走向万劫不复的境地。这种情况会发生，是因\n为每一步和他当前位置的对比太小了。  \n \n       我有个牌友曾经告诉我，如果把青蛙丢到热水里，青蛙会立刻跳\n出来，但如果把青蛙放到常温的水里，然后用很慢很慢的速度来烧这些水，那么\n这只青蛙最终会被烫死。虽然我的生理学知识不多，但我还是怀疑这种说法是不\n是真实。但不管怎么样，有许多企业就像我朋友提到的青蛙那样死去。在前后对\n比度细微的变化误导之下，人们经常无法认识到通往终点的趋势。  \n \n       我们最好记住本杰明·富兰克林那句最有用的格言：“小小纰\n漏，能沉大船。”这句格言的功效是很大的，因为大脑经常会错失那些类似于沉','2026-07-05 16:55:53.049000',0,2073692323954429952,567,2073692323514028032),(2073692328404586505,' \n       我们最好记住本杰明·富兰克林那句最有用的格言：“小小纰\n漏，能沉大船。”这句格言的功效是很大的，因为大脑经常会错失那些类似于沉\n大船的小纰漏之类的东西。 \n十七 压力影响倾向 \n \n \n       每个人都知道，突然的压力，比如遭遇威胁，会导致人体内部\n的肾上腺素激增，推动更快、更极端的反应。每个上过心理学概论课的人都知道，\n压力会使社会认可倾向变得更加强大。  \n \n       有一种现象知道的人不少但还没有被充分认识，轻度的压力能够\n轻微地改善人们的表现，比如说在考试中；而沉重的压力则会引发彻底失调。  \n \n       但是除了知道沉重的压力能够引起抑郁症之外，很少人对它有更\n多 的 了 解 。 例 如 ， 大 多 数 人 知 道 “ 急 性 应 激 性 抑 郁 症 ” （ Acute ','2026-07-05 16:55:53.049000',0,2073692323954429952,568,2073692323514028032),(2073692328404586506,'多 的 了 解 。 例 如 ， 大 多 数 人 知 道 “ 急 性 应 激 性 抑 郁 症 ” （ Acute \nStressDepression）会使人们的思维出现紊乱，因为它引起极端的悲观态度，而\n且这种悲观态度往往会持续很长时间，导致人们身心俱疲，什么都不想做。幸运\n的是，正如大多数人所知道的，这种抑郁症是人类较容易治愈的疾病之一。甚至\n早在现代药物尚未出现的时候，许多抑郁症患者，比如塞缪尔·约翰逊和温斯\n顿·丘吉尔等人，就在生活中取得了非凡的成就。  \n \n       大多数人对受到沉重压力影响的非抑郁性精神问题了解无多。但\n至少有个例子不在此列，那跟巴甫洛夫在七八十岁时所做的研究有关。巴甫洛夫\n很早就获得了诺贝尔奖，因为他利用狗成功地阐述了消化功能的生理机制。后来\n他由于让狗养成单纯联想唤起的反应而闻名于世，今天人们通常把各种由单纯联','2026-07-05 16:55:53.049000',0,2073692323954429952,569,2073692323514028032),(2073692328404586507,'很早就获得了诺贝尔奖，因为他利用狗成功地阐述了消化功能的生理机制。后来\n他由于让狗养成单纯联想唤起的反应而闻名于世，今天人们通常把各种由单纯联\n想唤起的反应，包括狗听到铃声就流口水，以及大多数现代广告引起的行为，称\n为“巴甫洛夫条件反射”（Pavlovian Conditioning）。  \n \n       巴甫洛夫后来所做的研究特别有趣。在 20 世纪 20 年代的列宁格\n勒大洪水期间，巴甫洛夫有很多狗被关在笼子里。在“巴甫洛夫条件反射”和标\n准的奖励反应的共同作用之下，这些狗在洪灾之前已经养成了一些特殊的、各不\n相同的行为模式。在洪水上涨和消退期间，这些狗差点被淹死，有一段时间它们\n的鼻子和笼子的顶部只有一点点空间可供呼吸。这导致它们感受到极大的压力。\n洪水退去后，巴甫洛夫立刻发现那些狗的行为变得跟过去不一样了。例如，有只','2026-07-05 16:55:53.049000',0,2073692323954429952,570,2073692323514028032),(2073692328404586508,'的鼻子和笼子的顶部只有一点点空间可供呼吸。这导致它们感受到极大的压力。\n洪水退去后，巴甫洛夫立刻发现那些狗的行为变得跟过去不一样了。例如，有只\n狗原来喜欢它的训练师，现在不喜欢了。这个结果不由让人想起现代某些人的认\n知转变：有的人原本很孝顺，但突然皈依邪教之后，便会仇视他们的父母。巴甫\n洛夫的狗这种突兀的极端转变会让优秀的实验科学家产生极大的好奇心。那确实\n是巴甫洛夫的反应。但没有多少科学家会采取巴甫洛夫接下来的行动。  \n \n       在随后漫长的余生中，巴甫洛夫给许多狗施加压力，让它们的精\n神崩溃，然后再来修复这些崩溃。所有这些他都保存了详细的实验记录。他发现：\n（1）他能够对这些狗进行分类，然后预测具体某只狗有多么容易崩溃；（2）那\n些最不容易崩溃的狗也最不容易恢复到崩溃前的状态；（3）所有狗都可以被弄\n崩溃；（4）除非重新施加压力，否则他无法让崩溃的狗恢复正常。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,571,2073692323514028032),(2073692328404586509,'些最不容易崩溃的狗也最不容易恢复到崩溃前的状态；（3）所有狗都可以被弄\n崩溃；（4）除非重新施加压力，否则他无法让崩溃的狗恢复正常。  \n \n       现在，几乎每个人都会抗议拿狗这种人类的朋友来做实验。  \n \n       除此之外，巴甫洛夫是俄罗斯人，他晚年的研究工作是在共产党\n执政期间完成的。也许正是由于这些原因，现在绝大多数人才会对巴甫洛夫晚年\n的研究一无所知。许多年前，我曾经跟两个信奉弗洛伊德的精神病学家讨论这个\n研究，但他们对此一无所知。实际上，几年前有个主流医学院的院长问我，巴甫\n洛夫的实验是否可以被其他研究人员的实验“重复”。很明显，巴甫洛夫是当今\n医学界被遗忘的英雄。  \n \n       我最早看到描述巴甫洛夫最后研究成果的文字，是在一本平装版\n的通俗作品中，作者是某个得到洛克菲勒基金会资助的精神病学家。当时我正在','2026-07-05 16:55:53.049000',0,2073692323954429952,572,2073692323514028032),(2073692328404586510,' \n       我最早看到描述巴甫洛夫最后研究成果的文字，是在一本平装版\n的通俗作品中，作者是某个得到洛克菲勒基金会资助的精神病学家。当时我正在\n试图弄清楚：（1）邪教是如何造成那些可怕的祸害的；（2）如果父母想让被邪\n教洗过脑、变成行尸走肉的子女重新做人，法律应该作出什么样的规定。当然，\n现在主流的法律法规反对父母把这些行尸走肉抓起来，给他们施加压力，以便消\n除邪教在威逼他们皈依时所施加的压力的影响。  \n \n       我从来没想过要介入目前关于这个问题的法律争议。但我确实认\n为，如果要以最理智的态度来处理这个争议，那么双方必须借鉴巴甫洛夫最后的\n研究成果：施加大量的压力可能是治疗最糟糕的疾病——丧失心智——的惟一方\n法。我在这里谈到巴甫洛夫是因为：（1）我对社会禁忌向来很反感；（2）我的\n讲稿涉及压力，这能让它更加合理、更加完整；（3）我希望有些听众能够继续','2026-07-05 16:55:53.049000',0,2073692323954429952,573,2073692323514028032),(2073692328404586511,'法。我在这里谈到巴甫洛夫是因为：（1）我对社会禁忌向来很反感；（2）我的\n讲稿涉及压力，这能让它更加合理、更加完整；（3）我希望有些听众能够继续\n我的研究，取得更大的成果。 \n十八 错误衡量易得性倾向 \n \n \n       这种倾向和一句歌词相互呼应：“如果我爱的女孩不在身边，\n我就爱身边的女孩。”人类的大脑是有限和不完美的，它很容易满足于容易得到\n的东西。大脑无法使用它记不住或者认识不到的东西，因为它会受到一种或几种\n心理倾向的影响，比如说上述歌曲中那个家伙就受到身边女孩的影响。所以人类\n的大脑会高估容易得到的东西的重要性，因而展现出易得性—错误衡量倾向。  \n \n       避免受易得性—错误衡量倾向影响的主要对策通常是按程序办\n事，包括使用几乎总是很有帮助的检查清单。  \n \n       另外一种对策就是模仿达尔文那种特别重视反面证据的做法。应','2026-07-05 16:55:53.049000',0,2073692323954429952,574,2073692323514028032),(2073692328404586512,'事，包括使用几乎总是很有帮助的检查清单。  \n \n       另外一种对策就是模仿达尔文那种特别重视反面证据的做法。应\n该特别关注的是那些不容易被轻易量化的因素，而不是几乎只考虑可以量化的因\n素。还有另外一种对策，那就是寻找并聘请一些知识渊博、富于怀疑精神、能言\n善辩的人，请他们扮演现有观点的反方角色。  \n \n       这种倾向的一个后果就是，那些极其鲜明的形象，由于便于被记\n住，因而更容易被认知，因此在实验中，应有意低估它们的重要性，而有意高估\n那些不那么形象的证据的重要性。  \n \n       尽管如此，那些极其鲜明的形象在影响大脑方面的特殊威力可以\n被建设性地用于：（1）说服其他人得到正确的结论；或者（2）作为一种提高记\n忆的工具，把鲜明的形象一个接一个地和人们不想忘记的东西联系起来。实际上，\n古希腊和古罗马那些伟大的演说家正是使用鲜明的形象作为记忆辅助手段，才能','2026-07-05 16:55:53.049000',0,2073692323954429952,575,2073692323514028032),(2073692328404586513,'忆的工具，把鲜明的形象一个接一个地和人们不想忘记的东西联系起来。实际上，\n古希腊和古罗马那些伟大的演说家正是使用鲜明的形象作为记忆辅助手段，才能\n够在不用笔记的情况下滔滔不绝而有条有理地发表演讲。  \n \n       应付这种倾向时所需要记住的伟大原理很简单：别只是因为一样\n事实或者一种观念容易得到，就觉得它更为重要。 \n十九 不用就忘倾向 \n \n \n       所有技能都会因为不用而退化。我曾经是个微积分天才，但到了\n20 岁之后，这种才能很快就因为完全没有被使用而消失了。避免这种损失的正\n确对策是使用一些类似于飞行员训练中用到的飞行模拟器那样的东西。这种模拟\n器让飞行员能够持续地操练所有很少用到但必须保证万无一失的技能。  \n \n       明智的人会终身操练他全部有用然而很少用得上的、大多数来自\n其他学科的技能，并把这当做是一种自我提高的责任。如果他减少了他操练的技','2026-07-05 16:55:53.049000',0,2073692323954429952,576,2073692323514028032),(2073692328404586514,' \n       明智的人会终身操练他全部有用然而很少用得上的、大多数来自\n其他学科的技能，并把这当做是一种自我提高的责任。如果他减少了他操练的技\n能的种数，进而减少了他掌握的技能的种数，那么他自然会陷入“铁锤人倾向”\n引起的错误之中。他的学习能力也会下降，因为他需要用来理解新经验的理论框\n架已经出现了裂缝。对于一个善于思考的人而言，把他的技能编排成一张检查清\n单，并常常将这张清单派上用场，也是很重要的。其他操作模式将会让他错过许\n多重要的事物。  \n \n       许多技能惟有天天练习，才能维持在非常高的水平。钢琴演奏家\n帕德雷夫斯（注：Ignacy Jan Paderewski，1860—1941，波兰钢琴家、作曲家、\n外交家和政治家，曾任波兰总理）基曾经说过，如果他有一天不练琴，他就会发\n现自己的演奏技巧下降，如果连续一个星期不练，那就连听众都能察觉了。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,577,2073692323514028032),(2073692328404586515,'外交家和政治家，曾任波兰总理）基曾经说过，如果他有一天不练琴，他就会发\n现自己的演奏技巧下降，如果连续一个星期不练，那就连听众都能察觉了。  \n \n       人们只要勤奋就能降低不用就忘倾向的影响。如果人们能够熟练\n地掌握一种技能，而不是草草学来应付考试，那么这种技能将会较难以丢失，而\n且一旦生疏之后，只要重新学习，很快就能够被重新掌握。这些优势可不算小，\n聪明人在学习重要技能的过程中，如果没有做到真正精通这种技能，他是不会停\n下来的。  \n \n二十 化学物质错误影响倾向 \n \n \n       众所周知，这种倾向的破坏力极大，常常会给认知和生活带来\n悲剧性的结果，所以在这里不需要多说了，请参见前面“简单的、避免痛苦的心\n理否认”那一节里的相关内容。 \n二十一 衰老—错误影响倾向 \n \n \n       年龄的增长自然会造成认知衰退，而每个人认知衰退的时间早晚','2026-07-05 16:55:53.049000',0,2073692323954429952,578,2073692323514028032),(2073692328404586516,'理否认”那一节里的相关内容。 \n二十一 衰老—错误影响倾向 \n \n \n       年龄的增长自然会造成认知衰退，而每个人认知衰退的时间早晚\n和速度快慢不尽相同。基本上没有年纪非常大的人还善于学习复杂的新技能。但\n有些人即使到了晚年，也能够得心应手地运用原来就掌握的技能，这种情况在桥\n牌比赛中屡见不鲜。  \n \n       像我这样的老年人无须刻意，也非常善于掩饰和年龄有关的衰\n退，因为诸如衣着打扮之类的社会习俗掩盖了大多数衰老的痕迹。  \n \n       带着快乐不断地思考和学习在某种程度上能够延缓不可避免的\n衰退过程。  \n \n二十二 权威—错误影响倾向 \n \n \n       和其所有祖先相同，人类也生活在等级分明的权力结构中，所\n以大多数人生下来就要跟随领袖，能够成为领袖的则只有少数人。因此，人类社\n会被正式组织成等级分明的权力结构，这些结构的文化则增强了人类天生就有的','2026-07-05 16:55:53.049000',0,2073692323954429952,579,2073692323514028032),(2073692328404586517,'以大多数人生下来就要跟随领袖，能够成为领袖的则只有少数人。因此，人类社\n会被正式组织成等级分明的权力结构，这些结构的文化则增强了人类天生就有的\n追随领袖的倾向。  \n \n       但由于人类的反应大多数是自动的，追随领袖的倾向也并不例\n外，所以当领袖犯错的时候，或者当领袖的想法并没有得到很好的传达、被大众\n所误解的时候，追随领袖的人就难免会遭受极大的痛苦。所以我们看到的许多例\n子都表明，人类的权威—错误影响倾向会造成认知错误。  \n \n       有些错误影响是很可笑的，就好像西奥迪尼讲过的一个故事。美\n国有个医生给护士留了手写的字条，吩咐她如何治疗病人的耳痛。纸条上写着\n“Two drops, twice a day, r.ear。”（“每天两滴，右耳。”）护士把 r.ear\n（右耳）看成了 rear（屁股），于是让病人翻过身，把滴耳液滴进了病人的肛\n门。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,580,2073692323514028032),(2073692328404586518,'（右耳）看成了 rear（屁股），于是让病人翻过身，把滴耳液滴进了病人的肛\n门。  \n \n       错误地理解权威人物的吩咐有时会造成悲剧性的后果。在第二次\n世界大战期间，部队给某位将军安排了新的飞行员。由于将军就坐在副机长的位\n子上，这个新的飞行员感到特别紧张，他很想取悦这位新老板，乃至把将军在座\n位上挪挪身体的细微动作误解为某种让他去干傻事的命令。于是飞机坠毁了，飞\n行员落得了半身不遂的下场。  \n \n       当然，像巴菲特老板那样深谋远虑的人会注意到这类案例，他坐\n在飞行员旁边时总是表现得像一只过于安静的老鼠。  \n \n       在飞行模拟训练中，人们也注意到这类情况。副机长在模拟训练\n中必须学会忽略机长某些真正愚蠢的命令，因为机长有时会犯严重的错误。然而，\n即使经过这种严格的训练，副机长在模拟飞行中仍然非常频繁地让模拟飞机由于\n机长某些极其明显的严重错误而坠毁。  ','2026-07-05 16:55:53.049000',0,2073692323954429952,581,2073692323514028032),(2073692328404586519,'即使经过这种严格的训练，副机长在模拟飞行中仍然非常频繁地让模拟飞机由于\n机长某些极其明显的严重错误而坠毁。  \n \n       飞黄腾达的陆军下士希特勒成为德国元首之后，带领大批虔诚的\n路德教徒和天主教徒倒行逆施，进行了惨无人道的种族大屠杀和其他大规模的破\n坏活动。后来有个聪明的心理学教授，也就是斯坦利·米尔格拉姆，决定做一个\n实验来弄清楚权威人物到底能够在多大程度上促使普通人去做罪大恶极的坏事。\n在这个实验中， 有个人假扮成权威人物，一个主导这次正规实验的教授。这个\n人能够让许许多多普通人将他们完全信以为真的假电刑用来折磨他们的无辜同\n胞。这个实验确实证明权威—错误影响倾向能够造成可怕的结果，但它也证明第\n二次世界大战刚结束时的心理学界是极其无知的。  \n \n       只要拿着我的心理倾向清单，然后逐项对照，几乎每个聪明人都','2026-07-05 16:55:53.049000',0,2073692323954429952,582,2073692323514028032),(2073692328408780800,'二次世界大战刚结束时的心理学界是极其无知的。  \n \n       只要拿着我的心理倾向清单，然后逐项对照，几乎每个聪明人都\n能明白，米尔格拉姆的实验涉及到六种强大的心理倾向，它们共同发挥作用，造\n成了他那极端的实验结果。例如，那个按下米尔格拉姆的电击按钮的人肯定从在\n场无动于衷的旁观者那里得到许多社会认可，那些人的沉默意味着他的行为是没\n有问题的。然而，在我讨论米尔格拉姆之前，心理学界发表了上千篇相关论文，\n可是这些论文对米尔格拉姆实验的意义，至多理解了 90%。而任何聪明人只要做\n到下面两点，就能立刻完全理解这个实验的意义：（1）按照我在这篇讲稿中谈\n到的方法合理地组织心理学知识；（2）使用核对检查清单的做法。这种情况说\n明那些早已谢世的心理学教授思考方法紊乱，对此需要一种更好的解释。下面我\n会不情愿地谈谈这个话题。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,583,2073692323514028032),(2073692328408780801,'明那些早已谢世的心理学教授思考方法紊乱，对此需要一种更好的解释。下面我\n会不情愿地谈谈这个话题。  \n \n       接下来我要讲的是一个有权威—错误影响倾向的垂钓者的故事。\n我们应该庆幸上一代的心理学家头脑没有错乱到这个垂钓者的地步。  \n \n       我曾经去哥斯达黎加的科罗拉多河垂钓，当时我的向导在震惊中\n告诉了我一个垂钓者的故事。那垂钓者比我早到科罗拉多河，他之前从来没有钓\n过海鲢鱼，像我一样请了一位垂钓向导。那向导既负责开船，也提供许多垂钓建\n议。在这个背景下，向导竖立了绝对权威的身份。那个向导的母语是西班牙语，\n而垂钓者的母语则是英语。垂钓者钓上了一条很大的海鲢鱼，于是开始遵从这位\n被他当成权威人物的向导的各种指示：抬高点，放低点，收线等等。到最后，鱼\n上钩了，垂钓者需要把竿往上提才能把鱼钓起来。但是向导的英语并不好，把收','2026-07-05 16:55:53.049000',0,2073692323954429952,584,2073692323514028032),(2073692328408780802,'被他当成权威人物的向导的各种指示：抬高点，放低点，收线等等。到最后，鱼\n上钩了，垂钓者需要把竿往上提才能把鱼钓起来。但是向导的英语并不好，把收\n竿说成了“给它杆，给它杆”。哇，垂钓者居然把他那根昂贵的钓竿扔给了鱼，\n最后那钓竿沿着科罗拉多河漂向大海去了。这个例子表明，跟随权威人物的心理\n倾向是很强大的，而且能够使人们变得非常糊涂。  \n \n       我最后的例子来自商界。有个心理学博士当上某家大公司的总裁\n之后就发狂了，花很多钱在一个偏僻的地方盖了新的总部大楼，还修了很大的酒\n窖。后来，他的下属汇报说资金快用完了。“从折旧准备金账户提，”这位总裁\n说。那可不太容易，因为折旧准备金账户是负债账户。  \n \n       对权威人物不应该的尊敬造成了这种情况：这位总裁和许多甚至\n比他更糟糕的管理人员明明早就该被革除职务，却继续担任一些重要商业组织的','2026-07-05 16:55:53.049000',0,2073692323954429952,585,2073692323514028032),(2073692328408780803,' \n       对权威人物不应该的尊敬造成了这种情况：这位总裁和许多甚至\n比他更糟糕的管理人员明明早就该被革除职务，却继续担任一些重要商业组织的\n领导人。内中蕴含的意义不言自明：选择将权力交给谁时要很谨慎，因为权威人\n物一旦上台，将会得到权威—错误影响倾向的帮助，那就很难被推翻。 \n二十三 废话倾向 \n \n \n       作为一种拥有语言天赋的社会动物，人类天生就有本事啰里啰\n唆，说出一大堆会给正在专心做正经事的人造成许多麻烦的废话。有些人会制造\n大量的废话，有些人则废话很少。  \n \n       曾经有个很好玩的实验向人们展示了蜜蜂说废话引起的麻烦。在\n正常的情况下，蜜蜂会飞出去找蜜源，然后飞回蜂巢，跳起一种舞蹈，以此来告\n诉其他蜜蜂蜜源的位置。然后其他蜜蜂就会飞出去，找到蜜源。某个科学家——\n他像 B.F.斯金纳那么聪明——决定要看看蜜蜂遇到麻烦之后会怎么办。他把蜜','2026-07-05 16:55:53.049000',0,2073692323954429952,586,2073692323514028032),(2073692328408780804,'诉其他蜜蜂蜜源的位置。然后其他蜜蜂就会飞出去，找到蜜源。某个科学家——\n他像 B.F.斯金纳那么聪明——决定要看看蜜蜂遇到麻烦之后会怎么办。他把蜜\n源放得很高。非常高。大自然中并没有那么高的蜜源，可怜的蜜蜂缺乏一种足以\n传达这个信息的基因程序。你也许认为蜜蜂将会飞回蜂巢，然后缩到角落里，什\n么也不做。但情况不是这样的。蜜蜂回到蜂巢，开始跳起一种莫名其妙的舞来。\n我这辈子总是在跟那些很像这只蜜蜂的人打交道。聪明的行政机构应该采取一种\n非常重要的做法，就是让那些啰里啰唆、喜欢说废话的人远离严肃的工作。加州\n理工学院有个名副其实的著名工程学教授，他有深刻的见解，然而说话比较鲁莽。\n他曾经直言不讳地说：“学术管理机构的首要任务，就是让那些无关紧要的人不\n要去干预那些有关紧要的人的工作。”我引用这句话，部分原因在于，我跟这位\n教授一样直言不讳，经常得罪人。虽然做了大量的努力，我还是没能改掉说话鲁','2026-07-05 16:55:53.049000',0,2073692323954429952,587,2073692323514028032),(2073692328408780805,'要去干预那些有关紧要的人的工作。”我引用这句话，部分原因在于，我跟这位\n教授一样直言不讳，经常得罪人。虽然做了大量的努力，我还是没能改掉说话鲁\n莽的积习，所以我引用这位教授的话，是希望至少和他比起来，我将会显得比较\n委婉。  \n \n二十四 重视理由倾向 \n \n \n       人，尤其是生活在发达文化中的人，天生就热爱准确的认知，\n以及获取准确认知过程中得到的快乐。正是由于这个原因，填字游戏、桥牌、象\n棋、其他智力游戏和所有需要思维技巧的游戏才会如此广受欢迎。  \n \n       这种倾向给人们的启发不言而喻。如果老师在传授知识时讲明正\n确的原因，而非不给任何原因，只是高高在上地把知识罗列出来，那么学生往往\n会学得更好。因此，不仅在发布命令之前要想清楚原因，而且还应该把这些原因\n告诉命令的接受者，没有比这更明智的做法了。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,588,2073692323514028032),(2073692328408780806,'会学得更好。因此，不仅在发布命令之前要想清楚原因，而且还应该把这些原因\n告诉命令的接受者，没有比这更明智的做法了。  \n \n       说到对这个道理的了解，没有人比得上卡尔·布劳恩。他为人正\n直，以过人的技巧设计了许多炼油厂。他掌管的那家德式的大企业有一条非常简\n单的规矩：你必须讲清楚何人将在何时何地因何故做何事。如果你给属下写纸条，\n吩咐他去做事情，却没有交待原因，布劳恩可能会解雇你，因为他非常清楚，人\n们只有一丝不苟地把某个想法的原因都摆出来，这个想法才最容易被接受。  \n \n       总的来讲，如果人们毕生致力于将他们的直接和间接经验悬挂在\n一个解释“为什么”的理论框架之上，那么他们对知识的吸收和使用就会变得更\n加容易。实际上，“为什么”这个问题是一块竖在精神宝库门外的罗塞塔石碑\n（注：RosettaStone，古埃及石碑，因石碑上用希腊文字、古埃及文字和当时的','2026-07-05 16:55:53.049000',0,2073692323954429952,589,2073692323514028032),(2073692328408780807,'加容易。实际上，“为什么”这个问题是一块竖在精神宝库门外的罗塞塔石碑\n（注：RosettaStone，古埃及石碑，因石碑上用希腊文字、古埃及文字和当时的\n通俗体文字等三种不同语言版本刻有埃及国王托勒密五世的诏书而成为今天人\n们研究古埃及史的重要历史文物）。  \n \n       不幸的是，重视理由倾向是如此强大，乃至一个人给出的理由哪\n怕是毫无意义的或者是不准确的，也能使他的命令和要求更容易得到遵从。有个\n心理学实验证明了这一点。在这个实验中，实验人员成功地插队到排在复印机前\n面的长队前头，他给出的理由是：“我要复印几份东西。”重视理由倾向这种不\n幸的副作用其实是一种条件反射，会出现这样的条件反射，是因为大多数人都认\n为有理由的事情是很重要的。自然地，某些商业机构和邪教组织经常利用各种有\n噱头的理由来达到他们不可告人的目的。 \n二十五 lollapalooza 倾向 \n \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,590,2073692323514028032),(2073692328408780808,'为有理由的事情是很重要的。自然地，某些商业机构和邪教组织经常利用各种有\n噱头的理由来达到他们不可告人的目的。 \n二十五 lollapalooza 倾向 \n \n \n       这种倾向在我翻阅过的那几本心理学教科书里是找不到的，至\n少没有得到系统的介绍，然而它在现实生活中却占据着重要的地位。它解释了米\n尔格拉姆的实验结果为什么会那么极端，也解释了某些邪教组织为什么能够极其\n成功地通过各种手段将许多心理倾向引起的压力施加在传教目标身上，从而迫使\n他们皈依。被邪教盯上的目标跟巴甫洛夫晚年研究的那些狗是相同的，他们的抵\n抗力因人而异，但有些被盯上的人在邪教的压力之下顿时变成了行尸走肉。实际\n上，有些邪教管这种皈依现象叫做“咔嚓”（snapping）。  \n \n       从前的心理学教科书作者极其无知，对此我们应该如何解释呢？','2026-07-05 16:55:53.049000',0,2073692323954429952,591,2073692323514028032),(2073692328408780809,'上，有些邪教管这种皈依现象叫做“咔嚓”（snapping）。  \n \n       从前的心理学教科书作者极其无知，对此我们应该如何解释呢？\n哪个曾经在高等学府上过物理学或者化学入门课的人，会不去考虑各种心理倾向\n如何结合并产生什么结果吗？为什么有些人对各种心理倾向之间相互影响的复\n杂关系毫无所知，却自以为他的心理学知识已经足够多了呢？那些心理学教授研\n究的是大脑使用过度简单的运算法则的倾向对认知产生的糟糕影响，而他们本身\n却使用一些过度简单的概念，还有什么比这更具讽刺意味呢？  \n \n       我将会提出几个初步的解释。也许很多早已谢世的心理学教授想\n要通过一种狭隘的可重复的心理学实验来撑起整个心理学学科；这种实验必须能\n够在大学的校园中进行，而且每次只针对一种心理倾向。如果是这样的话，这些\n早期的心理学教授以这样拘束的方法来研究自己的学科就犯了巨大的错误，因为','2026-07-05 16:55:53.049000',0,2073692323954429952,592,2073692323514028032),(2073692328408780810,'够在大学的校园中进行，而且每次只针对一种心理倾向。如果是这样的话，这些\n早期的心理学教授以这样拘束的方法来研究自己的学科就犯了巨大的错误，因为\n他们封死了许多走近心理学的道路。这就好像物理学忽略了（1）天体物理学，\n因为它的实验不可能在物理实验室中进行，（2）所有的复合效应。是哪些心理\n倾向导致早期的心理学教授采用一种非常狭隘的方法来研究他们自己的学科\n呢？其中一个候选的答案是偏好容易控制的资料引发的错误衡量易得性倾向。然\n后这些对研究方法的限制最终将会创造出一种极端的铁锤人倾向。另外一个候选\n的答案可能是艳羡/妒忌倾向：早期的心理学家误解了物理学，并对物理学怀有\n一种怪异的妒忌心态。这种可能性证明学院派心理学完全不研究妒忌绝对是一种\n错误的做法。  \n \n       现在我想把所有这些历史谜团交给比我优秀的人去解决。  \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,593,2073692323514028032),(2073692328408780811,'错误的做法。  \n \n       现在我想把所有这些历史谜团交给比我优秀的人去解决。  \n \n       好啦，我对各种心理学倾向的简短描述就到这里为止。 \n问与答 \n \n \n       现在，正如前面承诺过的，我将会自问自答几个普遍被问到的\n问题。  \n \n       第一个是复合问题：和欧几里得的系统相比，这份心理倾向列表\n是不是显得有点重复？这些倾向之间是否有重叠之处？这个系统能用其他同样\n令人信服的方法排列出来吗？这三个问题的答案都是肯定的；但这些缺点并不算\n严重。进一步提炼这些倾向的做法虽然是可取的，但却会使它们的实用性受到限\n制，因为对于像心理学这样的软科学来讲，有许多含糊之处是没办法弄清楚的。  \n \n       我的第二个问题是：你能否举出一个现实生活中的事例，而不是\n米尔格拉姆式的受到控制的心理学实验，然后用你的系统来令人信服地对各种心','2026-07-05 16:55:53.049000',0,2073692323954429952,594,2073692323514028032),(2073692328408780812,' \n       我的第二个问题是：你能否举出一个现实生活中的事例，而不是\n米尔格拉姆式的受到控制的心理学实验，然后用你的系统来令人信服地对各种心\n理倾向之间的相互作用进行分析？答案是肯定的。我最喜欢的事例是麦道公司的\n飞机乘客撤离测试。政府规定，新型飞机在销售之前，必须通过乘客撤离测试。\n测试要求满载的乘客在一段很短的时间内撤出机舱。政府的指示是，这种测试应\n该和现实的情况贴近。所以你撤离的乘客如果是一些只有 20 岁的运动员，那么\n肯定是通不过测试的。于是麦道安排在某个阴暗的停机库进行撤离测试，请了许\n多老年人来扮演乘客。飞机客舱离停机库的水泥地面大概有二十英尺高，而撤离\n的通道是一些不怎么结实的橡胶滑梯。第一次测试在早晨进行。有二十个人受了\n重伤，而且整个撤离过程耗时超过了测试规定的标准。那么麦道接下来怎么办\n呢？它在当天下午进行第二次测试，这次也失败了，多了二十名严重受伤的人，','2026-07-05 16:55:53.049000',0,2073692323954429952,595,2073692323514028032),(2073692328408780813,'重伤，而且整个撤离过程耗时超过了测试规定的标准。那么麦道接下来怎么办\n呢？它在当天下午进行第二次测试，这次也失败了，多了二十名严重受伤的人，\n其中有一个还落得终身瘫痪。  \n \n       哪些心理倾向对这个可怕的结果作出了贡献呢？把我的心理倾\n向列表作为一张检查清单，我将会作出如下的解释。奖励超级反应倾向驱使麦道\n迅速采取行动。它只有通过乘客撤离测试才能开始销售新飞机。同样驱动该公司\n的还有避免怀疑倾向，这种倾向促使它作出决定，并依照决定去行事。政府的指\n示是测试应该和现实的情况贴近，然而在权威—错误影响倾向的驱动之下，麦道\n过度遵守政府指示，采用了一种显然太过危险的测试方法。到这个时候，整个行\n动的过程已经被确定下来，于是避免不一致性倾向使得这种近乎无脑的计划得以\n继续进行。当麦道的员工看到那么多老人走进阴暗的停机库，看到飞机客舱是那','2026-07-05 16:55:53.049000',0,2073692323954429952,596,2073692323514028032),(2073692328408780814,'动的过程已经被确定下来，于是避免不一致性倾向使得这种近乎无脑的计划得以\n继续进行。当麦道的员工看到那么多老人走进阴暗的停机库，看到飞机客舱是那\n么高，而停机库的水泥地面是那么硬，他们肯定觉得非常不安，但发现其他员工\n和上级对此并没有表示反对。因而，社会认可倾向消除了这种不安的感觉。这使\n得行动能够依照原定的计划进行；而计划能够得以延续，也是受到权威—错误影\n响倾向。接着出现了灾难性的结果：当天早晨的测试失败了，还有许多人受了重\n伤。由于确认偏见，麦道忽略了第一次测试失败中强大的反面证据；而失败则激\n发了强烈的被剥夺超级反应倾向，促使麦道继续原初的计划。被剥夺超级反应倾\n向使麦道就像赌徒，在输掉一大笔钱之后急于扳平，狠狠地赌了最后一把。毕竟，\n如果不能按期通过测试，麦道将会蒙受许多损失。也许还能提出更多基于心理学\n的解释，但我的解释已经足够完整，足够证明我的系统在被当做检查清单来使用','2026-07-05 16:55:53.049000',0,2073692323954429952,597,2073692323514028032),(2073692328408780815,'如果不能按期通过测试，麦道将会蒙受许多损失。也许还能提出更多基于心理学\n的解释，但我的解释已经足够完整，足够证明我的系统在被当做检查清单来使用\n时是很有用的。  \n \n       第三个也是复合问题：这份心理倾向列表中体现的思想系统在现\n实生活中有什么用呢？广义的进化（包括基因的进化和文化的进化）早已将这些\n心理倾向深深地植根在我们的大脑里，这些我们无法摆脱的心理倾向能带来什么\n实际的好处呢？我的答案是，这些心理倾向带来的好处可能比坏处多。不然的话，\n它们就不会存在于人类容量有限的大脑中，而且还对人类的处境产生了很大的作\n用。所以这些倾向不能，也不该，遭到自动地清除。尽管如此，上文描绘的那种\n心理思考系统，如果得到正确的理解和应用，将有助于智慧和端正行为的传播，\n并且有助于避免各种灾难。心理倾向是可以改变的，认识各种心理倾向和防范它','2026-07-05 16:55:53.049000',0,2073692323954429952,598,2073692323514028032),(2073692328408780816,'心理思考系统，如果得到正确的理解和应用，将有助于智慧和端正行为的传播，\n并且有助于避免各种灾难。心理倾向是可以改变的，认识各种心理倾向和防范它\n们的对策通常能够防患于未然。下面列出的这些例子让我们明白一个道理：基本\n的心理学知识是非常有用的：  \n \n       一、卡尔·布劳恩的交流方法。  \n \n       二、飞行员训练中对模拟器的使用。  \n \n       三、酒瘾戒除组织的制度。  \n \n       四、医学院中的临床培训方法。  \n \n       五、美国制宪大会的规则：绝对保密的会议；最终投票之前所有\n的投票都不记名；大会结束前选票随时可以重投；对整部宪法只投一次票。这些\n是非常聪明的、尊重心理学的规则。如果那些开国元勋当时使用的是另外一种表\n决程序，那么许多人将会受到各种心理倾向的影响，从而采用那些互不一致的、','2026-07-05 16:55:53.049000',0,2073692323954429952,599,2073692323514028032),(2073692328408780817,'是非常聪明的、尊重心理学的规则。如果那些开国元勋当时使用的是另外一种表\n决程序，那么许多人将会受到各种心理倾向的影响，从而采用那些互不一致的、\n僵化的立场。那些英明的开国元勋让我们的宪法顺利通过表决，因为他们摸透了\n人们的心理。  \n \n       六、使用祖母的激励机制（注：前文所述“祖母的规矩”），让\n人们约束自己，从而更好地完成自己的任务。  \n \n       七、哈佛大学商学院对决策树的强调。在我年轻而愚蠢的时候，\n我经常嘲笑哈佛大学商学院。我说：“他们居然在教那些 28 岁的人如何在生活\n中应用高中的代数知识？”但后来我变得聪明了，终于明白他们的做法是很重要\n的，有助于预防某些心理倾向引起的糟糕后果。虽然明白得有点晚，但总比始终\n不明白好。  \n \n       八、强生公司所用的类似于尸检的做法。在绝大多数公司，如果','2026-07-05 16:55:53.049000',0,2073692323954429952,600,2073692323514028032),(2073692328408780818,'不明白好。  \n \n       八、强生公司所用的类似于尸检的做法。在绝大多数公司，如果\n你进行了并购，而这次并购成为灾难的话，所有造成这次愚蠢并购的人、文件和\n演说都会很快被忘记。没有人愿意提起这次并购，因为害怕联想到其糟糕的结果。\n但是强生公司规定每个人都要审视已完成的并购，将预测和结果进行比较。这么\n做是非常聪明的。  \n \n       九、查尔斯·达尔文在避免确认偏见方面作出的伟大榜样。美国\n药品管理局（FDA）效仿了达尔文的做法，很明智地要求在开发新药物的研究中\n必须采用反确认偏见的“双盲试验”（Double Blind）方法。  \n \n       十、沃伦·巴菲特关于公开竞拍的原则：别去。  \n \n       我的第四个问题是：在你的列表所展现的思维系统中隐藏着什么\n特殊的知识问题？  \n \n       嗯，答案之一就是悖论。在社会心理学里面，人们对这个系统了','2026-07-05 16:55:53.049000',0,2073692323954429952,601,2073692323514028032),(2073692328408780819,'特殊的知识问题？  \n \n       嗯，答案之一就是悖论。在社会心理学里面，人们对这个系统了\n解得越多，它的真实性就越低，而这恰恰使得这个系统在防止糟糕后果、推动良\n好结果方面具有很大的价值。这个结果是悖论式的，让人没办法把心理学和基础\n物理学联系起来，但这有什么关系呢？就连纯数学都无法摆脱所有的悖论，心理\n学里面有些悖论值得大惊小怪吗？  \n \n       这种认知转变中还有一个悖论：被操控的人即使明知道自己正在\n被操控，也会心甘情愿地被对方牵着鼻子走。这在悖论中创造了悖论，但还是那\n句话，这有什么关系呢？我曾经非常享受这种情况。许多年前，我在晚宴上遇到\n某位漂亮的女士。我以前并不认识她。她先生是洛杉矶一位有头有脸的人物。她\n坐在我旁边，仰起那张美丽的脸庞，对我说：“查理，你能用一个词来说明你在\n生活中取得非凡成就的原因吗？”我明知道她肯定对许多人都这么说，但我还是','2026-07-05 16:55:53.049000',0,2073692323954429952,602,2073692323514028032),(2073692328408780820,'坐在我旁边，仰起那张美丽的脸庞，对我说：“查理，你能用一个词来说明你在\n生活中取得非凡成就的原因吗？”我明知道她肯定对许多人都这么说，但我还是\n觉得很高兴。我每次见到这位美女都会精神一振。顺便说一声，我跟她说的答案\n是我很理性。至于这个答案是不是对的，你就自己判断啦。我可能展现了某些我\n原来不想展现的心理倾向。  \n \n       我的第五个问题是：我们需要将经济学和心理学更加紧密地结合\n起来吗？我的答案是肯定的，好像已经有人开始这么做了。我听说过一个这样的\n例子。加州理工学院的科林·卡米瑞尔（注：科林·卡米瑞尔，1959—，美国行\n为经济学家）研究的是“实验经济学”。他设计出一个有趣的实验，让一些智商\n很高的学生用真钱来模拟炒股票。结果有些学生为某只“股票”付出了 A+B 的价\n格，尽管他们明知道该“股票”当天的“收盘价”是 A。这种愚蠢的行为会发生，','2026-07-05 16:55:53.049000',0,2073692323954429952,603,2073692323514028032),(2073692328408780821,'很高的学生用真钱来模拟炒股票。结果有些学生为某只“股票”付出了 A+B 的价\n格，尽管他们明知道该“股票”当天的“收盘价”是 A。这种愚蠢的行为会发生，\n是因为那些学生被允许在一个流动市场上自由买卖那只股票。有些学生付出 A+B\n的价格，是因为他们希望能够在当天收盘之前以更高的价格卖给其他学生。现在\n我敢自信地预言，大多数经济学教授和公司理财教授将会无视卡米瑞尔的实验结\n果，继续坚定地信奉他们原来那种“严格的有效市场假设”。如果是这样的话，\n那么这种情况将再次证明聪明人在受到心理倾向影响之后会变得多么不理智。  \n \n       我的第六个问题是：这些有关心理倾向的知识难道不会带来道德\n问题和审慎问题吗？我的答案是会的。例如，心理学知识能够用来提高说服力，\n而说服力和其他力量一样，既可以用来做好事，也可以用来做坏事。库克船长曾','2026-07-05 16:55:53.049000',0,2073692323954429952,604,2073692323514028032),(2073692328408780822,'问题和审慎问题吗？我的答案是会的。例如，心理学知识能够用来提高说服力，\n而说服力和其他力量一样，既可以用来做好事，也可以用来做坏事。库克船长曾\n经用心理学花招耍了他的水手，让他们吃酸泡菜来防治坏血病。在我看来，尽管\n库克船长有故意操控那些水手之嫌，但在当时的情况下，这种做法是道德的，也\n是明智的。但更为常见的是，你会利用有关心理倾向的知识来操控别人，以便获\n取他们的信任，达到自己不可告人的目的，这样一来，你就犯了道德的错误和不\n够审慎的错误啦。道德错误很明显，不用多说。这么做之所以犯了不够审慎的错\n误，是因为许多聪明人在成为被操纵的目标之后，会发现你正在试图操纵他们，\n反过来憎恨你的行为。  \n \n       我最后的问题是：这篇演讲稿存在事实上和思考上的错误吗？答\n案是肯定的，几乎是肯定的。这篇稿件是一个 81 岁的老人凭记忆花了大概 50','2026-07-05 16:55:53.049000',0,2073692323954429952,605,2073692323514028032),(2073692328408780823,' \n       我最后的问题是：这篇演讲稿存在事实上和思考上的错误吗？答\n案是肯定的，几乎是肯定的。这篇稿件是一个 81 岁的老人凭记忆花了大概 50\n个小时改定的，而且这个老人从来没有上过一节心理学课，在过去将近 15 年的\n时间里，除了一本发展心理学的著作，没有看过任何心理学的书。即使如此，我\n认为我这篇演讲稿整体上是非常站得住脚的；我希望我的后代和朋友将会认真地\n考虑我所说的话。我甚至希望会有更多的心理学教授和我一起致力于（1）大量\n地采用逆向思维；（2）详尽地描绘心理学系统，让它能够像检查清单那样发挥\n更好的作用；（3）特别强调多种心理倾向共同发挥作用时产生的效应。  \n \n       我的演讲到这里就结束啦。如果你在思考我所讲的内容的过程中\n得到的快乐，有我写下它的时候得到的快乐的十分之一那么多，那么你就是一名\n幸运的听众。 \n重读第十一讲 \n \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,606,2073692323514028032),(2073692328408780824,'得到的快乐，有我写下它的时候得到的快乐的十分之一那么多，那么你就是一名\n幸运的听众。 \n重读第十一讲 \n \n \n       在 2000 年发表的这次演讲中，我称赞了朱迪丝·瑞奇·哈里\n斯那本非常畅销的《教养的迷思》（The Nuture Assumption）。你们应该记得，\n这本著作证明了同辈群体的压力对年轻人来讲是非常重要的，而以往普遍认为很\n重要的父母的教养反而没那么重要。这本具有极大实际意义的成功作品背后的故\n事很有趣：早在这本书出版之前，现年 67 岁的哈里斯女士在哈佛大学攻读心理\n学博士学位，但却被开除了，因为哈佛大学认为她缺乏从事心理学研究必备的理\n想素质。由于罹患了某种无法治愈的自身免疫性疾病，哈里斯女士成年之后大多\n数时间都待在家里。疾病缠身、默默无闻的她发表了一篇学术论文，《教养的迷\n思》就是根据这篇论文的基本观点写成的。这篇论文让她获得了某个声誉很高的','2026-07-05 16:55:53.049000',0,2073692323954429952,607,2073692323514028032),(2073692328408780825,'数时间都待在家里。疾病缠身、默默无闻的她发表了一篇学术论文，《教养的迷\n思》就是根据这篇论文的基本观点写成的。这篇论文让她获得了某个声誉很高的\n大奖，这个奖项由美国心理学协会每年颁发给那些已发表的优秀论文，它恰恰是\n以那个将她开除出哈佛大学的人的名字命名的。  \n \n       从她那本令人难忘的作品中得知这件荒唐的事情之后，我写信给\n哈佛大学——我的母校，敦促它授予我并不认识的哈里斯女士以名誉博士学位，\n或者授予她真正的博士学位，那就更好啦。我引用了牛津大学的例子。这所伟大\n的大学曾经开除了它最优秀的学生——塞缪尔·约翰逊，因为他穷得没办法继续\n缴纳学费。但牛津大学后来作出了体面的改正。在约翰逊战胜疾病，从穷困潦倒\n中逐渐成为著名人物之后，牛津大学授予了他博士学位。我试图说服哈佛在这方\n面效仿牛津的努力完全失败了。但哈佛大学后来确实从麻省理工学院挖来了当世','2026-07-05 16:55:53.049000',0,2073692323954429952,608,2073692323514028032),(2073692328412975104,'中逐渐成为著名人物之后，牛津大学授予了他博士学位。我试图说服哈佛在这方\n面效仿牛津的努力完全失败了。但哈佛大学后来确实从麻省理工学院挖来了当世\n最著名的心理学家史蒂芬·平克，而平克则十分景仰哈里斯女士。从这个举措中\n我们能明白哈佛人文社科学部的声誉为什么比其他大学的要高。该学部的底蕴极\n其深厚，能够部分地改正某些在别的地方放任自流的愚蠢错误。  \n \n       2006 年，在与不治之症作斗争中前行的哈里斯女士出版了第二\n部作品，《没有两个人是相同的》。这个书名很贴切，因为作者要解决的核心问\n题之一就是，同卵双胞胎最终在性格方面为什么会截然不同。带着好奇心周详地\n探讨这个问题的她让我想起了查尔斯·达尔文和歇洛克·福尔摩斯。她从心理学\n文献中收集和解释了许多资料，提出了一种非常可信的答案。她引用了一个有趣\n的案例，有一对同卵双胞胎，其中一个人在生活和事业上都取得了成功，而另外','2026-07-05 16:55:53.049000',0,2073692323954429952,609,2073692323514028032),(2073692328412975105,'文献中收集和解释了许多资料，提出了一种非常可信的答案。她引用了一个有趣\n的案例，有一对同卵双胞胎，其中一个人在生活和事业上都取得了成功，而另外\n一个人则沦落到贫民窟。哈里斯女士对这个核心问题作出了极具概括性的解答，\n在这里我不想透露她的答案，因为对《穷查理宝典》的读者来说，先猜测答案，\n然后再去阅读她的书会更好。如果哈里斯女士大致上是正确的——在我看来非常\n有可能如此——那么处境十分不利的她已经两次提出了在培养教育儿童和其他\n许多方面具有重大实际意义的学术理论。  \n \n       这种罕见而值得钦佩的结果是怎么出现的呢？用哈里斯女士自\n己的话来说，她“为人傲慢而多疑，甚至从小时候起就是这样”，这些性格特征\n加上耐心、决心和技巧，明显让她直到 67 岁还在探求真理的道路上走得很顺利。\n毫无疑问的是，热衷于摧毁自己的观念也是促使她成功的因素之一，我这么说，','2026-07-05 16:55:53.049000',0,2073692323954429952,610,2073692323514028032),(2073692328412975106,'加上耐心、决心和技巧，明显让她直到 67 岁还在探求真理的道路上走得很顺利。\n毫无疑问的是，热衷于摧毁自己的观念也是促使她成功的因素之一，我这么说，\n是因为她现在还在为以前撰写教科书时重复了某些错误的理论而道歉。  \n \n       在这一讲中，我也展示了我的傲慢，因为我对自己所说的话非常\n有信心。这一讲无非就是宣称：（1）学院派心理学是非常重要的；（2）尽管如\n此，这门学科中那些拥有博士学位的学者的心理学理论和他们对心理学的表述往\n往是有毛病的；（3）和绝大多数教科书相比，我对心理学的表述方式在实用性\n方面往往拥有巨大的优势。自然，我相信这些极度自负的宣言是正确的。毕竟我\n收集这一讲中所包含的材料是为了帮助我在实践思维方面取得成功，而不是为了\n通过公布一些貌似聪明的理论来获取好处。  \n \n       如果我的看法是正确的，哪怕只有部分是正确的，未来这个世界','2026-07-05 16:55:53.049000',0,2073692323954429952,611,2073692323514028032),(2073692328412975107,'通过公布一些貌似聪明的理论来获取好处。  \n \n       如果我的看法是正确的，哪怕只有部分是正确的，未来这个世界\n理解心理学的方法，将会跟这一讲所用的办法差不多。如果是这样，我自信地预\n言，这种实践的改变将会普遍地提高人们的竞争力。 \n \n \n \n现金流量贴现法 \n目录 \n•1 现金流量贴现法 \n•2 现金流量贴现法的基本公式 \n•3 现金流量贴现法的优缺点 \n•4 现金流量贴现法的应用[1] \n•5 现金流量贴现法范例 \n•6 参考文献 \n现金流量贴现法  \n  现金流量贴现法就是把企业未来特定期间内的预期现金流量还原为当前现\n值。由于企业价值的真髓还是它未来盈利的能力，只有当企业具备这种能力，它\n的价值才会被市场认同，因此理论界通常把现金流量贴现法作为企业价值评估的\n首选方法，在评估实践中也得到了大量的应用，并且已经日趋完善和成熟。  \n[编辑] \n现金流量贴现法的基本公式  ','2026-07-05 16:55:53.049000',0,2073692323954429952,612,2073692323514028032),(2073692328412975108,'首选方法，在评估实践中也得到了大量的应用，并且已经日趋完善和成熟。  \n[编辑] \n现金流量贴现法的基本公式  \n  p=   \n  式中：P 一企业的评估值；  \n  n 一资产（企业）的寿命；  \n  CFt一资产 (企业)在 t 时刻产生的现金流；  \n  r 一反映预期现金流的折现率  \n  从上述计算公式我们可以看出该方法有两个基本的输入变量：现金流和折现\n率。因此在使用该方法前首先要对现金流做出合理的预测。在评估中要全面考虑\n影响企业未来获利能力的各种因素，客观、公正地对企业未来现金流做出合理预\n测。其次是选择合适的折现率。折现率的选择主要是根据评估人员对企业未来风\n险的判断。由于企业经营的不确定性是客观存在的，因此对企业未来收益风险的\n判断至关重要，当企业未来收益的风险较高时，折现率也应较高，当未来收益的\n风险较低时，折现率也应较低。  \n[编辑] ','2026-07-05 16:55:53.049000',0,2073692323954429952,613,2073692323514028032),(2073692328412975109,'判断至关重要，当企业未来收益的风险较高时，折现率也应较高，当未来收益的\n风险较低时，折现率也应较低。  \n[编辑] \n现金流量贴现法的优缺点  \n  现金流量贴现法作为评估企业内在价值的科学方法更适合并购评估的特点，\n很好的体现了企业价值的本质；与前两种企业价值评估方法相比，现金流量贴现\n法最符合价值理论，能通过各种假设，反映企业管理层的管理水平和经验。但尽\n管如此，现金流量贴现法仍存在一些不足：首先从折现率的角度看，这种方法不\n能反映企业灵活性所带来的收益，这个缺陷也决定了它不能适用于企业的战略领\n域；其次这种方法没有考虑企业项目之间的相互依赖性，也没有考虑到企业投资\n项目之间的时间依赖性；第三，使用这种方法，结果的正确性完全取决于所使用\n的假设条件的正确性，在应用是切不可脱离实际。而且如果遇到企业未来现金流\n量很不稳定、亏损企业等情况，现金流量贴现法就无能为力了。  \n[编辑] ','2026-07-05 16:55:53.049000',0,2073692323954429952,614,2073692323514028032),(2073692328412975110,'的假设条件的正确性，在应用是切不可脱离实际。而且如果遇到企业未来现金流\n量很不稳定、亏损企业等情况，现金流量贴现法就无能为力了。  \n[编辑] \n现金流量贴现法的应用[1]\n \n  现金流量贴现法在网络企业价值评估中的应用不管一个公司生产什么样的\n产品,提供什么样的服务,对投资者来说,最终只生产一种产品———现金。投资者\n之所以持有该公司的证券,是希望这些证券未来为他们产生自由现金流。  \n  因此,评价网络企业最佳的方式还是应该回到这样一个最基本的经济因素上\n来,完全以绩效预测为依据,采用贴现现金流量(DCF)分析方法。  \n  由于贴现现金流量的基础———根据企业未来的风险贴现企业未来的现金\n流———在全世界各地都是一样的,本文将主要探讨如何将网络企业特有的风险\n因素包含到评估模型中来,如技术风险、通货膨胀率、国家有关政策的变动、资','2026-07-05 16:55:53.049000',0,2073692323954429952,615,2073692323514028032),(2073692328412975111,'流———在全世界各地都是一样的,本文将主要探讨如何将网络企业特有的风险\n因素包含到评估模型中来,如技术风险、通货膨胀率、国家有关政策的变动、资\n本控制、经济不稳定等等。在此之前,可以采用两个技巧:  \n  a.从未来的某个特定时间开始预测,并回溯到目前的绩效情况;  \n  b.采用传统的分析技巧,了解公司的潜在经济效益,预测它们未来的绩效。  \n  在现金流量贴现法中,有两种方法可以把网络企业特有的额外风险考虑进去:\n反映在对未来现金流量的预测过程中,即包括在 DCF 公式的分子上;以额外的风\n险溢价加到贴现率中,即包括在 DCF 公式的分母里。本文认为,利用概率加权的\n情景分析(将风险反映到现金流量的预测中)将会为企业的价值评估提供更为坚\n实的理论基础和更加透彻的理解,这主要是因为以下三个原因：  \n  a.投资者可以事先分散网络行业特有的风险,如技术风险、行业政策风险等,','2026-07-05 16:55:53.049000',0,2073692323954429952,616,2073692323514028032),(2073692328412975112,'实的理论基础和更加透彻的理解,这主要是因为以下三个原因：  \n  a.投资者可以事先分散网络行业特有的风险,如技术风险、行业政策风险等,\n尽管这些风险不可能彻底分散。经典的资本资产定价模型(CAPM)明确指出,贴现\n率和资本成本只应反映不可分散风险,那么可分散的风险通过现金流量来反映就\n更加科学,而通过将风险溢价加到贴现率中的做法就有待商榷。  \n  b.即使在同一个国家同一个行业里,各种风险对不同企业的影响不同。如果\n采用调整贴现率的方法,将行业风险溢价并入到贴现率中,就意味着对所有的企业\n采用同样的风险溢价水平,会高估或低估企业价值。  \n  c.网络这一新兴行业中的竞争规则正在发生巨大的变化,技术/运作标准之间\n的竞争将更多地体现在“企业网”之间的竞争。在不久的将来,网络行业之间的竞争\n将更多反映在结构上的竞争、总体价值之间的竞争。“企业网”可以产生一个公司,','2026-07-05 16:55:53.049000',0,2073692323954429952,617,2073692323514028032),(2073692328412975113,'的竞争将更多地体现在“企业网”之间的竞争。在不久的将来,网络行业之间的竞争\n将更多反映在结构上的竞争、总体价值之间的竞争。“企业网”可以产生一个公司,\n也可以毁灭一个公司,尽管它并非垄断,但和垄断一样威力强大。在不久的将来,\n可以预料网络行业将被企业网重塑,这些企业网将相互对抗,并无情地蚕食或吞并\n对方。这种风险通过加权情景分析,将更好地体现网络企业的竞争规则,并将网络\n企业可能面临的风险清楚地勾勒出来,而这是简单地使用一个综合各种风险的\n“风险溢价”参数所无法比拟的。  \n[编辑] \n现金流量贴现法范例  \n  为使大家对现金流量贴现法有更具体的了解，我们假设了一个例子以供参\n考：  \n  第一部份是计算经折算为现值的公司未来五年现金流，首先我们将公司每年\n的现金流折算为现值，即第一年的现金流为￥11.6，经折算后则为￥10.4 (￥11.6 ','2026-07-05 16:55:53.049000',0,2073692323954429952,618,2073692323514028032),(2073692328412975114,'  第一部份是计算经折算为现值的公司未来五年现金流，首先我们将公司每年\n的现金流折算为现值，即第一年的现金流为￥11.6，经折算后则为￥10.4 (￥11.6 \nX 0.89)，第二年的折算后现金流则为 ￥10.7 (￥13.5 X 0.80)，并将其余的三年\n现金流折算起来，然之后再将这些现值加起来，便得出 ￥56 (￥10.4+￥10.7+\n￥11.1+￥11.5+￥11.9)，这就是公司未来五年经折算后的现金流价值。  \n  第二部份则是集中计算经折算为现金值的公司未来五年后的剩余价值。首先\n我们假设公司经过五年达 16%的高速增长，现金流的增长幅度会由 16%下调至\n每年 7%，因此公司未来的第六年现金流则为 ￥26.1 (￥24.4 X 1.07)，而假设\n公司其后的现金流保持每年以 7%稳步上升，并同时假定我们所要求的回报为每','2026-07-05 16:55:53.049000',0,2073692323954429952,619,2073692323514028032),(2073692328412975115,'公司其后的现金流保持每年以 7%稳步上升，并同时假定我们所要求的回报为每\n年 12%(贴现率)，公司剩余价值则可以凭此推算为￥521.4 (￥26.1/(12%-7%))，\n然后我们再将公司五年后的未来余值折算为现值(Present value)，即 ￥295 \n(￥521.4 X 0.57)，便可估算出经折算为现金值的公司未来五年后的剩余价值。\n最后，我们将第一及第二部份计算到的现值加起来，便可得出公司的内在价值为\n￥351 (￥55.6 + ￥295.9)，而投资者便可根据此数字，再除以公司已发行的股\n票数量，便可得出每股的内在价值。若每股内在价值较市价为高，则投资者可以\n考虑购入，反之则予以沽售。  \n \n  第一部分：预测前 5 年的现金流 (Project 5 years Cash flows)  ','2026-07-05 16:55:53.049000',0,2073692323954429952,620,2073692323514028032),(2073692328412975116,'考虑购入，反之则予以沽售。  \n \n  第一部分：预测前 5 年的现金流 (Project 5 years Cash flows)  \n  1. 上年度公司现金流 (Prior year cash flow): 公司上年度现金流的数字  \n  2. 增长率 (Growth rate): 与公司往年盈利对比的盈利增长率  \n  3. 现金流量 (Cash flow): 于公司将所有盈利分发的情况下，股东所得的现\n金流 = 现金流(n-1) X (1+0.16)， n = 1,2, 7, 5  \n  4. 折现参数 (Discount factor): 将未来价值化为现值的数值 = \n1/(1+0.12)^n, n = 1, 2, 7, 5  \n  5. 现值 (Present value): 将未来的价值贴现为第一年时的价值，将未来现\n金流乘以贴现参数所得出的数值 = (3) X (4)  ','2026-07-05 16:55:53.049000',0,2073692323954429952,621,2073692323514028032),(2073692328412975117,'  5. 现值 (Present value): 将未来的价值贴现为第一年时的价值，将未来现\n金流乘以贴现参数所得出的数值 = (3) X (4)  \n  6. 贴现现金流总和  \n  第二部分  \n  剩余价值(Terminal Value/Residual Value): 剩余价值是通过恒定增长模型\n计算得出的，即假设公司从第五年开始以每年 5％的速度恒定增长。  \n  7. 第五年的现金流 (Cash flow in year 5): 在公司将所有盈利分发的情况\n下，股东于第五年所得的现金流  \n  8. 增长率 (Growth rate): 公司于第 5 年后的增长率.  \n  9. 第六年的现金流 (Cash flow in year 6): 在公司将所有盈利分发的情况\n下，股东于第六年所得的现金流  ','2026-07-05 16:55:53.049000',0,2073692323954429952,622,2073692323514028032),(2073692328412975118,'  9. 第六年的现金流 (Cash flow in year 6): 在公司将所有盈利分发的情况\n下，股东于第六年所得的现金流  \n  10. 要求回报率減增长率 (Required rate of return minus growth rate): 要\n求回报率亦作资本成本。以要求回报率与增长率之差作为贴现率将永恒的剩余价\n值转换为于第 6 年时的价值五年后的价值 (Terminal Value)  \n  11. 五年后的价值 (Terminal Value) ：公司五年后的价值  \n  12. 五年后的贴现参数 (Discount factor as of year 5) ： 将公司第五年的\n价值转化为第一年的现值 = (9)/(10)  \n  13. 贴现公司余值：经折算为第一年价值的公司余值  \n  公司的内在价值：前 5 年贴现现金流总和与贴现公司余值之和，其反应公司','2026-07-05 16:55:53.049000',0,2073692323954429952,623,2073692323514028032),(2073692328412975119,'  13. 贴现公司余值：经折算为第一年价值的公司余值  \n  公司的内在价值：前 5 年贴现现金流总和与贴现公司余值之和，其反应公司\n的现在全部价值  \n参考文献 \n1. ↑ 吴月琴 冯耕中.新兴行业中的企业价值\n评估——现金流量贴现法的应用.情报杂\n志.2002 年第 10 期 \n \n巴菲特教你读财报 \n \n目录 \n导读 刘建位 \n序言 \n \n第1章  让巴菲特成为世界首富的两大发现 \n第2章 让巴菲特成为超级富豪的企业类型 \n第3章 巴菲特的淘金之地 \n第4章 “持续性”是巴菲特打开金库的钥匙 \n第5章 财务报表概述：淘金之地 \n第6章 巴菲特在哪里发现财务信息 \n第一部分 损益表 \n第7章 巴菲特从哪里开始着手：损益表 \n第8章 收入－资金来源的渠道 \n第9章 销售成本－对于巴菲特来说越少越好 \n第10章  毛利润/毛利率：巴菲特需求长期赢利的关键指标 ','2026-07-05 16:55:53.049000',0,2073692323954429952,624,2073692323514028032),(2073692328412975120,'第8章 收入－资金来源的渠道 \n第9章 销售成本－对于巴菲特来说越少越好 \n第10章  毛利润/毛利率：巴菲特需求长期赢利的关键指标 \n第11章  营业费用：巴菲特的关注点 \n第12章  销售费用及一般管理费用 \n第13章  研究和开发费用：为什么巴菲特要避而远之 \n第14章  折旧费：巴菲特不能忽视的成本 \n第15章  利息支出：巴菲特不想看到 \n第16章  出售资产收益（损失）及其他 \n第17章  税前利润：巴菲特管用指标 \n第18章  应缴所得税：巴菲特怎么知道谁在说真话 \n第19章  净利润：巴菲特的追求 \n第20章  每股收益：巴菲特怎么辨别成功者和失败者 \n第二部分 资产负债表 \n第21章  资产负债表概述 \n第22章  资产 \n第23章  流动资产周转：钱是如何赚取的 \n第24章  现金和现金等价物：巴菲特的困惑 \n第25章  存货：公司需采购的原料和公司需出售的产品 ','2026-07-05 16:55:53.049000',0,2073692323954429952,625,2073692323514028032),(2073692328412975121,'第23章  流动资产周转：钱是如何赚取的 \n第24章  现金和现金等价物：巴菲特的困惑 \n第25章  存货：公司需采购的原料和公司需出售的产品 \n第26章  应收账款净值：别人欠公司的钱 \n第27章  预付账款和其他流动资产 \n第28章  流动资产合计和流动比率 \n第29章  房产、厂房和机器设备：对巴菲特来说越少越好 \n第30章  商誉 \n第31章  无形资产：衡量不可测量的资产 \n第32章  长期投资：巴菲特成功的秘密之一 \n第33章  其他长期资产 \n第34章  总资产和总资产回报 \n第35章  流动负债 \n第36章  应付账款、预提费用和其他流动负债 \n第37章  短期贷款：它如何摧毁一家金融机构 \n第38章  一年内到期的长期贷款及其可能带来的问题 \n第39章  负债合计和流动比率 \n第40章  长期贷款：优秀公司很少有的东西 \n第41章  递延所得税：少数股东权益和其他负债 ','2026-07-05 16:55:53.049000',0,2073692323954429952,626,2073692323514028032),(2073692328412975122,'第39章  负债合计和流动比率 \n第40章  长期贷款：优秀公司很少有的东西 \n第41章  递延所得税：少数股东权益和其他负债 \n第42章  负债合计和流动比率 \n第43章  股东权益/账面价值 \n第44章  优先股、普通股和资本公积 \n第45章  留存收益：巴菲特变得超级富有的秘密 \n第46章  库存股票：巴菲特喜欢在资产负债表上看到的 \n第47章  股东权益回报率：第一部分 \n第48章  股东权益回报率：第二部分 \n第49章  杠杆问题和可能的骗局 \n     第三部分 现金流量表 \n第50章  现金流量表：巴菲特查看现金之处 \n第51章  资本开支：致富秘诀之一就是减少它 \n第52章  股票回购：巴菲特增加股东财富的免税途径 \n     第四部分 衡量具有持续性竞争优势公司的价值 \n第53章  巴菲特的股权债券创意如何使他致富 \n第54章  持续性竞争优势带来的持续增长回报 ','2026-07-05 16:55:53.049000',0,2073692323954429952,627,2073692323514028032),(2073692328412975123,'     第四部分 衡量具有持续性竞争优势公司的价值 \n第53章  巴菲特的股权债券创意如何使他致富 \n第54章  持续性竞争优势带来的持续增长回报 \n第55章  衡量具有持续性竞争优势公司价值的其他途径 \n第56章  巴菲特如何确定购买一家理想企业的最佳时机 \n第57章  巴菲特如何确定卖出时机 \n \n附录 \n具有持续性竞争优势公司的资产负债表 \n不具有持续性竞争优势公司的资产负债表 \n具有持续性竞争优势公司的损益例表 \n不具有持续性竞争优势公司的损益例表 \n \n术语汇编 \n致谢 \n \n \n导读 \n刘建伟 \n想知道股票值多少钱：首先要知道公司值多少钱 \n   大家都知道巴菲特投资股票的策略是价值投资，什么是价值投资？ \n巴菲特的解释是：“用４０美分购买价值１美元的股票。”股票价格是不是４\n０美分，一看就知道。但股票价值是不是１美元，看不见，摸不着，只能估计。','2026-07-05 16:55:53.049000',0,2073692323954429952,628,2073692323514028032),(2073692328412975124,'巴菲特的解释是：“用４０美分购买价值１美元的股票。”股票价格是不是４\n０美分，一看就知道。但股票价值是不是１美元，看不见，摸不着，只能估计。\n因此，价值投资的前提是估算股票价值的多少。 \n价值估算得越准，投资成功的概率就越高。这里说的准不是准确到几毛几分。\n巴菲特说：“我们只是对于估计一小部分股票的内在价值还有点自信，但这也只\n限于一个价值区间，而绝非那些貌似精确实为谬误的数字。” \n估计价值区间，重要的不是最高价值，二是对这支股票的最低价值估计是否\n准确。 \n如果到商场买东西，尽管不知道东西究竟值多少钱，但如果你知道基本的价\n格，而你买的价格比你估计的最低价值还要便宜许多，你就知道你买的价格到底\n便宜不便宜了。和你买东西一样，最重要是知道价值的下限，这样你就能给自己\n设定一个买入的价格底线。 \n那么，如何知道一只股票值多少呢？ \n简单！前提是你知道这家公司整体值多少钱。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,629,2073692323514028032),(2073692328412975125,'设定一个买入的价格底线。 \n那么，如何知道一只股票值多少呢？ \n简单！前提是你知道这家公司整体值多少钱。 \n股票，是公司所有股权的一小部分。如果说公司的全部股权是一张大饼的话，\n一只股票，就是一小份股权，而且每一只股票都是完全相同的，有相同的利润分\n配的权力。 \n大饼可以分开吃，公司却必须整体存在。但股票的奇妙之处，公司继续整体\n存在，但股权像大饼可以分成很多很多小份，一小块就是一股，公司给你一份拥\n有股份的产权凭证，就是股票。 \n买卖股票，形式是股票过户，但本质是买卖股权。如同你买卖房子一样，形\n式是产权证过户，但本质是房子的产权转移了。因此，巴菲特一再强调，买股票\n就是买公司。 \n要估算每股股票值多少钱，一个方法是知道整个公司值多少钱，然后再除以\n股份总数就行了。如同先算出一张大饼值多少钱，然后除以你总共分了多少份，\n就知道一份值多少钱。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,630,2073692323514028032),(2073692328412975126,'股份总数就行了。如同先算出一张大饼值多少钱，然后除以你总共分了多少份，\n就知道一份值多少钱。 \n可能你又要问了，我怎么估计这家公司值多少钱呢？ \n你首先要知道内在价值的定义和估算方法。 \n巴菲特简单有效的估值方法：想估算债券一样估算股票价值 \n巴菲特对内在价值的定义如下：“内在价值是一个非常重要的概念，他为评\n估投资和企业的相对吸引力提供了唯一的逻辑手段。内在价值可以简单定义如\n下：他是一家企业在余下的寿命可以产生的现金流量的贴现值。” \n“在写于５０年前的《投资价值理论》中，约翰·伯尔·威廉姆斯提出了价\n值计算的数学公式，这里我们将其精炼为：今天任何股票、债券或公司的价值，\n取决于在资产的整个剩余使用寿命期间预期能够产生的、以适当的利率贴现的现\n金流入和流出。请注意这个公式对股票和债券来说完全相同。尽管如此，两者之\n间有一个非常重要的，也是很难对付的差别：债券有一个息票和到期日，从而可','2026-07-05 16:55:53.049000',0,2073692323954429952,631,2073692323514028032),(2073692328412975127,'金流入和流出。请注意这个公式对股票和债券来说完全相同。尽管如此，两者之\n间有一个非常重要的，也是很难对付的差别：债券有一个息票和到期日，从而可\n以确定未来现金流。而对于股票投资，投资分析师则必须自己估计未来的‘息票’。\n另外管理人员的能力和水平对于债券息票的影响甚少，主要是管理人员如此无能\n或不诚实，以至于暂停支付债券利息的时候才有影响。与债券相反，股份公司管\n理人员的能力对股权的‘息票’有巨大的影响。 \n大家应该明白了，在巴菲特看来，股票就是利息不固定的债券而已。 \n估计公司的整体价值、估计股票的的价值和估计债券的价值在方法上一样\n的。公司每年的利润、股票享有的利润如同债券的利息。但在操作上却有很大的\n不同，公司的利润和股票享有的利润每年都是变动的，而债券的利息每年都是固\n定的。 \n而预测公司未来几年的利润究竟会有多少，简直太难了。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,632,2073692323514028032),(2073692328417169408,'不同，公司的利润和股票享有的利润每年都是变动的，而债券的利息每年都是固\n定的。 \n而预测公司未来几年的利润究竟会有多少，简直太难了。 \n一个很笨却很有用的方法是，放弃那些盈利很不稳定、很难预测的公司，只\n寻找未来现金流量十分稳定、十分容易预测的公司，这类公司有三类特点：一个\n是业务简单且稳定，而是持续竞争优势，三是盈利持续稳定。那些过去很多年盈\n利，长期保持持续稳定的公司，未来现金流量也很可能继续保持稳定。 \n这正是巴菲特认为防止错误估计未来现金流量的非常保守，却非常可靠的方\n法是；＂尽管用来评估股票价值的公式并不复杂，但分析师，即使是经验丰富且\n聪明智慧的分析师在估计未来现金流量时也很容易出错，在伯克希尔，我们采用\n两种方法来对付这个问题。第一，我们努力固守我们相信可以了解的公司。这意\n味着这些公司的业务本身通常具有相当简单且稳定的特点，如果企业很复杂，而','2026-07-05 16:55:53.049000',0,2073692323954429952,633,2073692323514028032),(2073692328417169409,'两种方法来对付这个问题。第一，我们努力固守我们相信可以了解的公司。这意\n味着这些公司的业务本身通常具有相当简单且稳定的特点，如果企业很复杂，而\n产业环境也不断在变化，那么我们实在是没有足够的聪明才智去预测其未来现金\n流量，碰巧的是，这个缺点一点也不会让我们感到困扰。对于大多数投资者而言，\n重要的不是他到底知道什么，而是他真正明白自己到底不知道什么。只要能够尽\n量避免犯重大的错误，投资人只需要做很少的几件正确的事情就足可以保证盈利\n了。第二，亦是同等重要的，我们强调在我们的买入价格上留有安全边际，如果\n我们算出一只普通股的价值仅仅略高于它的价格，那么我们不会对买入产生兴\n趣。我们相信这一安全边际原则—格雷厄姆非常强调这一原则—是成功投资的基\n石。 \n既然这些公司的盈利像债券一样稳定，我们就可以用类似于债券的简单估值\n方法进行估值。是不是很简单？这正是巴菲特选股的秘诀。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,634,2073692323514028032),(2073692328417169410,'石。 \n既然这些公司的盈利像债券一样稳定，我们就可以用类似于债券的简单估值\n方法进行估值。是不是很简单？这正是巴菲特选股的秘诀。 \n巴菲特的选股秘诀：寻找利息持续增长的“股权债券” \n２０世纪８０年代末期，巴菲特在哥伦比亚大学做演讲时透漏了他的选股秘\n诀。他只选择那些具有持续性竞争优势的公司，这类公司的股票股权相当于一种\n股权债券。 \n所谓股权债券，就是说本质上是股票，拥有公司部分股权，能够享有相应的\n利润分成。但形式上像债券，每年可以享有的利润就像债券利息一样稳定。公司\n的税前利润相当于债券支付的利息。 \n但不同于普通的债券，股权债券所支付的利息稳定，但并不是固定的，而是\n年复一年的保持增长态势，股权债券的内在价值自然也在不断攀升，最终会推动\n公司股价在长期内持续增长，原因很简单，巴菲特知道，股市长期而言是一台称\n重机，最终会反映公司的内在价值增长。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,635,2073692323514028032),(2073692328417169411,'公司股价在长期内持续增长，原因很简单，巴菲特知道，股市长期而言是一台称\n重机，最终会反映公司的内在价值增长。 \n听起来似乎有些复杂。其实就像你买债券一样，是复利，也就是利滚利。表\n面看起来利率是不变的。但你每年的利息到了第二年，就成了新增的本金，这样\n你的本金总额其实是越来越多，尽管利率不变，其实你的利息总额每年越来越多，\n按照最初的本金来算，你的实际利率越来越高。 \n巴菲特寻找的具有持续性竞争优势的优秀公司，其实就是按照一个复利模\n式，而且利率水平相当高的赚钱机器。 \n举个简单的例子，假如你第一年股票投资 1 美元，每年投资收益率是 20﹪。\n第二年，你的本金就是最初的 1 美元加上第一年的盈利 0.2 美元，一共 1.20 美\n元。第二年底，收益率还是 20﹪， 你新增的盈利就是 1.2 美元乘以 20﹪是 0.24\n美元。就这样，第三年、第四年，利滚利，一直持续滚下去。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,636,2073692323514028032),(2073692328417169412,'元。第二年底，收益率还是 20﹪， 你新增的盈利就是 1.2 美元乘以 20﹪是 0.24\n美元。就这样，第三年、第四年，利滚利，一直持续滚下去。 \n猜一猜，10 年后，你的本利和是多少？6.19 美元。 \n你下一年按 20﹪的收益率新增的盈利是多少？1.238 美元。 \n按你最初的本金 1美元计算，收益率高达 123﹪以上。 \n这样一只一年赚 1.238 美元的股票，值多少钱? \n用一只一年赚 5﹪的长期公司债券或者债券来衡量，其价值为 1.238 美元除\n以 5﹪，等于 24.76 美元。相对于你最初投入的 1美元本金，升值了 24 倍以上。 \n再举一个真实的例子。 \n20 世纪 80 年代末期，巴菲特开始以平均每股 6.5 美元的价格购入可口可乐公\n司的股票，该公司的税前利润为每股 0.70 美元，相当于每股 0.46 美元的税后利','2026-07-05 16:55:53.049000',0,2073692323954429952,637,2073692323514028032),(2073692328417169413,'司的股票，该公司的税前利润为每股 0.70 美元，相当于每股 0.46 美元的税后利\n润。从以往的数据来看，可口可乐公司一直保持着每年 15﹪左右的利润增长率。\n由此，巴菲特认为他买到的是可口可乐公司的股权债券，这种债券能为他每股\n6.5 美元的投资最初带来 10.7﹪的税前回报率，同时他认为该回报率将以每年\n15﹪的速度增长。 \n那巴菲特投资的可口可乐公司的股权债券，结果怎么样呢？ \n可口可乐公司的税前利润以每年大概 9.35﹪的增长率增长，截止 2007 年其每\n股收益为 3.96 美元，相当于税后利润每股 2.57 美元。这意味着，巴菲特初始投\n资的每股 6.5 美元的可口可乐公司的股权债券，在 2007 年支付了每股 3.96 美元\n的税前回报给他，这相当于 60﹪的税前回报率和 40﹪的税后回报率。 \n股票市场一旦看到这些回报率，终有一日会重估巴菲特的股权债券价值，反映','2026-07-05 16:55:53.049000',0,2073692323954429952,638,2073692323514028032),(2073692328417169414,'的税前回报给他，这相当于 60﹪的税前回报率和 40﹪的税后回报率。 \n股票市场一旦看到这些回报率，终有一日会重估巴菲特的股权债券价值，反映\n出其增长价值。 \n2007 年，可口可乐公司赚取 3.96 美元的每股收益，相当于每股 2.57 美元的\n税后利润。按照 6.5﹪的长期公司债券利率计算，其每股股票价格在应在 60 美\n元（＄3.96÷0.065）.2007 年，可口可乐公司的股票市场价格在 45-64 美元间\n波动。 \n巴菲特知道，如果他买入一家具有持续竞争增长优势的公司，随着时间的推移，\n股票市场最终会重估公司的股权债券，其市场价值等以每股盈利除以长期公司债\n券利率。的确，股票市场风云莫测，投资者们有时太过悲观，有时太过乐观，但\n最终决定长期投资实际经济价值的是长期利率。 \n分析股票的前提是分析财务报表。 \n我们已经知道巴菲特想寻找的是什么样的公司，目标确定了，下一步就是如','2026-07-05 16:55:53.049000',0,2073692323954429952,639,2073692323514028032),(2073692328417169415,'最终决定长期投资实际经济价值的是长期利率。 \n分析股票的前提是分析财务报表。 \n我们已经知道巴菲特想寻找的是什么样的公司，目标确定了，下一步就是如\n何找到具有持续竞争优势和持续盈利的公司。 \n唯一的办法就是阅读财务报表。 \n上市公司每年都要向股东公布上一年的年度财务报告，简称年报。在年报中，\n公司向股东回报过去一年公司的经营情况，其中最重要的是财务报表， 所有的\n财务数据在财务报表中反映。 \n巴菲特阅读最多的是企业的年度财务报告。 \n“我阅读我所关注的公司年报，同时我也阅读它的竞争对手的年报，这些是\n我最主要的阅读材料。” \n“你必须阅读无数家公司的年度报告和财务报表。” \n“有些人喜欢看《花花公子》，而我喜欢看公司年报。 \n巴菲特认为分析企业会计报表是进行价值评估的基本功： \n“你必须了解财务会计，并且要懂得其微妙之处。它是企业和外界交流的语','2026-07-05 16:55:53.049000',0,2073692323954429952,640,2073692323514028032),(2073692328417169416,'巴菲特认为分析企业会计报表是进行价值评估的基本功： \n“你必须了解财务会计，并且要懂得其微妙之处。它是企业和外界交流的语\n言，一种完美无暇的语言。除非你愿意花时间去学习它——学习如何分析财务报\n表，你才能够独立的选择投资目标。“ \n“当经理们想要向你解释清楚企业的实际情况时，可以通过会计行业，同样\n也通过报表的规定来进行。如果你不能辨认出其中的差别，那么你不必再资产管\n理行业混下去了。 \n分析财务报表其实很简单 \n分析巴菲特赖以成为世界巨富的投资策略，可以归纳为一句：寻找一家具\n有持续竞争，能够保持盈利持续增长的优秀企业，以低于价值的价格买入。 \n巴菲特选股的成功秘诀在于两大关键点： \n如何辨别一家公司是否具有持续竞争优势的优质企业？ \n如何估算这家具有持续竞争优势的优秀公司值多少钱？ \n学习好不好，用分数说话。 \n公司好不好，用数字说话。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,641,2073692323514028032),(2073692328417169417,'如何辨别一家公司是否具有持续竞争优势的优质企业？ \n如何估算这家具有持续竞争优势的优秀公司值多少钱？ \n学习好不好，用分数说话。 \n公司好不好，用数字说话。 \n要回答这两个价值投资决策的关键问题，必须分析财务报表。 \n巴菲特通过财务报表挖掘出具有持久竞争力的优质企业。企业的财务报表\n可以反映出，这是一个会让你一贫如洗的平庸企业，还是一个拥有持久竞争优势、\n让你腰缠万贯的企业。 \n其实很多投资者都明白分析财务报表的重要性，但大家都担心分析财务报\n表需要很多专业知识，自己根本不懂财务，要学会太难了。 \n其实分析财务报表很简单。 \n第一， 只用小学算术。 \n第二， 只需要看几个关键指标。 \n第三， 只需要分析哪些业务相当简单，报表也相当简单的公司。 \n本书就是用简短的篇幅，告诉你巴菲特分析财务报表选择优秀公司股票的\n简单方法。 \n本书主要分成以下四个部分，前三个部分分别叫你如何阅读损益表、资产','2026-07-05 16:55:53.049000',0,2073692323954429952,642,2073692323514028032),(2073692328417169418,'本书就是用简短的篇幅，告诉你巴菲特分析财务报表选择优秀公司股票的\n简单方法。 \n本书主要分成以下四个部分，前三个部分分别叫你如何阅读损益表、资产\n负债表、现金流量表，一步步教会你如何通过一些简单有效的财务指标分\n析出具有持续竞争优势的优秀企业。而最后一个部分则教你如何用最简单\n的债券估值方法，给这类公司的股票估值，并告诉你根据估值结果决定买\n入和卖出时机的方法。 \n真的非常简单。 \n不信，就让我们一起开始吧。 \n \n专家介绍：刘建位，中央电视台《理财教室》节目主持人、汇添富基金管理有\n限公司的首席投资理财师，著有《学习巴菲特》等畅销书。本书特邀刘建位为\n全书及每部分撰写专家导读。 \n \n \n序言 \n    时间追溯到 1981 年，我嫁给了彼得·巴菲特，成为沃伦·巴菲特的儿媳妇。\n沃伦·巴菲特是世界上最成功的投资大师，如今也是一位伟大的慈善家。12 年','2026-07-05 16:55:53.049000',0,2073692323954429952,643,2073692323514028032),(2073692328417169419,'    时间追溯到 1981 年，我嫁给了彼得·巴菲特，成为沃伦·巴菲特的儿媳妇。\n沃伦·巴菲特是世界上最成功的投资大师，如今也是一位伟大的慈善家。12 年\n后，由于种种原因，我离开了巴菲特家族。 \n    新婚不久，我去奥哈马拜访了巴菲特家族。在那里，我结识了这位投资大师\n的一些忠实学生，他们把自己成为“巴菲特追随者”。戴维·克拉克就是其中最\n成功的追随者之一，他随身携带一个记有巴菲特投资智慧的笔记本，总是一丝不\n苟、孜孜不倦地学习。正是得益于他的笔记本，我与他才合作出版了一系列的投\n资畅销书：《巴菲特之道》、《巴菲特法则》、《巴菲特法则实战手册》以及《新巴\n菲特法则》。这些书被翻译成 17 种不同国家的语言，包括希伯来语、阿拉伯语、\n中文和俄文。 \n    《巴菲特之道》后的巨大成功之后，在 2007 年伯克希尔·哈撒韦公司的年','2026-07-05 16:55:53.049000',0,2073692323954429952,644,2073692323514028032),(2073692328417169420,'中文和俄文。 \n    《巴菲特之道》后的巨大成功之后，在 2007 年伯克希尔·哈撒韦公司的年\n会上，我又碰见了戴维。我们共进午餐讨论了投资分析方法的历史发展情况。他\n指出，在 19 世纪和 20 世纪初，债券投资分析家们关注企业的偿债能力与盈利能\n力。华尔街之父，巴菲特的导师本杰明·格雷厄姆在其股票分析中就沿用了债券\n投资的分析方法。 \n    但是，格雷厄姆从来不会将在同行中具有长期竞争优势的公司与其他平庸之\n辈区别对待。他只关心公司是否有足够的盈利能力助其渡过经济难关，逆转股价\n直线下降的局势。他更不会将公司股票持有 10 年，甚至 20 年的时间，只要手中\n的股票两年内没有起色，他就会毅然抛掉。当然，格雷厄姆也没有错过任何赚钱\n的机会，只是没有搭上那艘驶向世上最高金山的大船，可以同沃伦一样，成为世\n界上最富有的人。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,645,2073692323514028032),(2073692328417169421,'的机会，只是没有搭上那艘驶向世上最高金山的大船，可以同沃伦一样，成为世\n界上最富有的人。 \n    沃伦师从于格雷厄姆，并由此登上了投资舞台。与他的导师不同，沃伦发现\n具有长期相对竞争优势的公司是创造财富的巨大原动力。他认识到，持有这些优\n秀公司股票的时间越长，你就会越富有。格雷厄姆也许会认为这些超级公司的股\n价都过高，但沃伦觉得根本没有必要等到“大削价”的时候才进场，只要支付的\n价格合理，他同样可以从那些优质公司身上赚个盆满钵满。 \n    为辨识出具有长期竞争优势的企业，沃伦设计出了一套独特的分析工具帮助\n他寻找这类超级明星公司。虽然沃伦是格雷厄姆的忠实弟子，但他看待事物的角\n度新颖独特，它能够判断出这家公司是否有能力摆脱困境，是否真的具有长期竞\n争优势，并让他长期获得丰厚收益。 \n午餐结束后，我问戴维我们可不可以写一本关于分析公司财务报表的入门','2026-07-05 16:55:53.049000',0,2073692323954429952,646,2073692323514028032),(2073692328417169422,'争优势，并让他长期获得丰厚收益。 \n午餐结束后，我问戴维我们可不可以写一本关于分析公司财务报表的入门\n书，力求简明扼要、易学易懂，将沃伦用以发现极具发展潜力公司的财务分析工\n具介绍给大家。 \n我希望这本简单易懂的书可以教会投资者如何阅读一家公司的财务报表，识\n别出巴菲特梦寐以求的优质公司。书中不仅解释了资产负债表和损益表中各项内\n容的含义，更重要的是让投资者知道，他们应该去寻找那些具有长期竞争优势的\n杰出企业。 \n戴维十分赞同这个想法，于是我们用一个月的时间完成了现在你所看到的这\n本书。 \n 我们由衷地希望这本书能帮助你跳出过时的格雷厄姆价值模式，发现具有持\n续性竞争优势公司的财富创造力，像沃伦·巴菲特一样在投资道路上取得巨大突\n破。在此过程中，你会发现投身于股海中的自己不会受到于华尔街的喧嚣和躁动，\n而且还有希望成为世界顶级的智慧型投资者。就让我们跟随这位颇具传奇色彩的','2026-07-05 16:55:53.049000',0,2073692323954429952,647,2073692323514028032),(2073692328417169423,'破。在此过程中，你会发现投身于股海中的自己不会受到于华尔街的喧嚣和躁动，\n而且还有希望成为世界顶级的智慧型投资者。就让我们跟随这位颇具传奇色彩的\n投资大师巴菲特的脚步，阔步走向黄金大道吧！ \n \n                                        玛丽  巴菲特 \n                                         2008 年 8 月 \n \n \n第1章 让巴菲特成为世界首富的两大发现 \n     巴菲特年过花甲时，开始重新视本杰明·格雷厄姆的投资策略。他深刻阐\n述了什么样的企业具有投资价值，什么样的企业能够实现长期收益最大化。事实\n上，巴菲特在他的论述中摒弃了已经沿用数年的格雷厄姆式价值投资策略，并在\n这个过程中创造了迄今为止世界上最有价值的投资策略。 \n    本书出版的目的就是为了探讨巴菲特的两大发现—— ','2026-07-05 16:55:53.049000',0,2073692323954429952,648,2073692323514028032),(2073692328417169424,'这个过程中创造了迄今为止世界上最有价值的投资策略。 \n    本书出版的目的就是为了探讨巴菲特的两大发现—— \n如何辨别具有持久竞争优势的优质企业？ \n如何估算具有持久竞争优势的优质企业的价值？ \n我们将详细解释这种独特的投资策略是如何发挥作用的，巴菲特是如何利用\n公司财务报表以实施他的投资策略——而这些策略使他成为世界上最富有的人。 \n \n \n第 2 章 让巴菲特成为超级富豪的企业类型 \n要理解巴菲特的第一重大发现，我们需要了解华尔街的本质及其主要参与\n者。在过去 200 年间，尽管华尔街提供了大量的商业服务，但同时也提供了一个\n大型赌场——在这里，以投机者身份冠名的赌徒在股票价格走势上放置了大量的\n筹码。 \n    早期，这当中部分赌徒取得了巨大的财富和地位，他们成为金融报刊上人们\n关注的焦点。大“钻石”吉姆·布拉迪和伯纳蒂·巴鲁克是少数几个在这个领域','2026-07-05 16:55:53.049000',0,2073692323954429952,649,2073692323514028032),(2073692328417169425,'筹码。 \n    早期，这当中部分赌徒取得了巨大的财富和地位，他们成为金融报刊上人们\n关注的焦点。大“钻石”吉姆·布拉迪和伯纳蒂·巴鲁克是少数几个在这个领域\n以投资大师身份进入公众视野的范例。 \n现代，以共同基金、对冲基金和信托投资基金为代表的机构投资者取代了过\n去的个人投机者。机构投资者以其专业的选股能力向大众推销，并以丰厚的年收\n益率为诱饵不断吸引那些渴望一夜暴富的短视群体。 \n    一般情况下，股票投机者都属于“三心二意”之人，有好消息时就追涨买入，\n有坏消息时则匆匆抛售。如果一只在几个月内几乎纹丝不动，他们就将其卖掉，\n并继续寻找其他股票。 \n新一代赌徒中的佼佼者发明出复杂的计算机程序，用以测算股票价格上涨或\n下跌的速度。如果一个公司的股票正加速上涨，计算机将执行买入命令；若股票\n价格开始加速下跌，计算机则执行卖出命令。这样一来，便会产生数以千计各种\n股票的大量买进卖出情况。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,650,2073692323514028032),(2073692328417169426,'价格开始加速下跌，计算机则执行卖出命令。这样一来，便会产生数以千计各种\n股票的大量买进卖出情况。 \n这些以计算机为工具的投资者今天买入一只股票，第二天就在市场卖出的现\n象已经不足为奇。通过这类计算机系统，对冲基金经理为他的客户创造了巨额利\n润。但这也有圈套：他们也可能令他们的客户赔钱。当他们赔钱时，还有部分遗\n留本金的客户将赎回他们的基金，然后去寻找新的基金经理为他们出谋划策。 \n华尔街随时都充斥着这些主流或非主流选取股票跌宕起伏的故事。 \n这种疯狂的投机性买进卖出一直持续了很长时间，史上最疯狂的买入发生在\n1920 年，一度将股票价格推高到天价。但在 1929 年大崩盘来临时，股票价格又\n被直线打压至最低。 \n20世纪30年代早期，华尔街有一个很富有激情的年轻分析师-------本杰明·格\n雷厄姆，他发现华尔街大多数自命不凡的基金经理在大量买进卖出股票时，根本','2026-07-05 16:55:53.049000',0,2073692323954429952,651,2073692323514028032),(2073692328421363712,'20世纪30年代早期，华尔街有一个很富有激情的年轻分析师-------本杰明·格\n雷厄姆，他发现华尔街大多数自命不凡的基金经理在大量买进卖出股票时，根本\n不考虑公司的长期经济运行情况。他们所关注的只是股票价格在短期内是上涨还\n是下跌。 \n格雷厄姆还发现，这些疯狂投机的主流股票投资者追涨杀跌时，会将股票价\n格推到非常荒唐可笑的地步，与他们所购买股票公司的实际长期基本经济状况完\n全背离，他也认识到，同样是这些投机者，有时会将股票价格打压到非常低的价\n位，完全忽视这家公司良好的长期发展前景。这些严重被低估的股票让格雷厄姆\n看到了一个美妙的赚钱机会。 \n格雷厄姆的理由是，如果他在股价低于其长期内在价值是买入这些处于超卖\n状态的公司股票，终有一日，市场会承认它的错误低估，然后将它们的估价纠正\n过来。一旦价格向上调整后，他可以卖出这些股票，并因此获利。这是我们如今','2026-07-05 16:55:53.049000',0,2073692323954429952,652,2073692323514028032),(2073692328421363713,'状态的公司股票，终有一日，市场会承认它的错误低估，然后将它们的估价纠正\n过来。一旦价格向上调整后，他可以卖出这些股票，并因此获利。这是我们如今\n所熟知的价值投资基本原理，而格雷厄姆就是价值投资的始祖。 \n尽管如此，我们必须明白一点，那就是格雷厄姆并不在意他所买的公司属于\n什么行业。用他的话说，就是所有公司都有一个内在的均衡价格。当他在 30 年\n代后期开始实践价值投资时，他着重寻找那些交易价格比其公司库存现金一半都\n少的公司。他美其名曰“用 50 美分买 1 美元”。此外，他还有其他投资原则，比\n如从不买股票价格超过其每股盈利 10 倍的股票，又如当一只股票股价涨幅超过\n50﹪时就卖出。如果股票价格在两年内没有上涨，他也会坚决卖出。的确，他的\n眼光要比那些华尔街的投机者远一点，但事实上，如果这个公司在 10 年后才有\n表现的话，他将获得零收益。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,653,2073692323514028032),(2073692328421363714,'眼光要比那些华尔街的投机者远一点，但事实上，如果这个公司在 10 年后才有\n表现的话，他将获得零收益。 \n20 世纪 50 年代，当巴菲特在哥伦比亚大学读书时，他就追随格雷厄姆学习\n价值投资，恰值格雷厄姆退休之前，他进入格雷厄姆的华尔街公司开始了分析师\n生涯。在那里，巴菲特工作在著名的价值投资者沃尔特·施洛斯身旁。通过阅读\n成千上万份公司财务报表，刚刚大学毕业的巴菲特练就了一双发现价值低估的慧\n眼。 \n格雷厄姆退休之后，巴菲特回到自己的家乡奥马哈。在那里，巴菲特可以远\n离华尔街的喧嚣嘈杂，潜心思考其导师的投资理论和方法。也就在那时，他发现\n格雷厄姆投资法存在着一些问题。 \n首先，并不是所有“格雷厄姆式”的低估值公司都会实现价值重估上涨，某\n些公司甚至以破产告终。不是所有投资都能“百发百中”，亏损的部分也可能超\n过所有的盈利。格雷厄姆试图通过分散化投资组合以规避这种不利局面，有时这','2026-07-05 16:55:53.049000',0,2073692323954429952,654,2073692323514028032),(2073692328421363715,'些公司甚至以破产告终。不是所有投资都能“百发百中”，亏损的部分也可能超\n过所有的盈利。格雷厄姆试图通过分散化投资组合以规避这种不利局面，有时这\n些组合中含有 100 种以上的公司股票。此外，格雷厄姆还采用了一种策略，即坚\n决地处理掉两年内没有上涨的股票。但当最后期限来临时，大部分“低估股票”\n仍停留在低估状态。 \n巴菲特发现，他和格雷厄姆买入的股票按格雷厄姆“50﹪收益法则”卖出后，\n其中很多股票在随后几年内还继续保持着上涨势头。他发现这些公司的股票价格\n攀升到远远高于格雷厄姆抛售时的价位。这正如他们买了一张开往容易街的列车\n票，但在列车到达站点就下车了，因为他不清楚他最终驶向何方。 \n巴菲特决定对这些“超级明星股”的经济动力进行进一步探究，希望能在他\n导师的投资报酬率上有所提高。于是，他开始研究这些公司的财务报表，探究这\n些公司具有如此美妙的长期投资价值的内在原因。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,655,2073692323514028032),(2073692328421363716,'导师的投资报酬率上有所提高。于是，他开始研究这些公司的财务报表，探究这\n些公司具有如此美妙的长期投资价值的内在原因。 \n巴菲特了解到，所有“超级明星股”都得益于某种竞争优势，这些优势为它\n们带来类似垄断的经济地位，使其产品能要价更高或者增加销售量。在这一过程\n中，它们能比竞争对手赚更多的利润。 \n巴菲特同样认识到，如果一个公司的竞争优势能在很长一段时间内保持不变\n----竞争优势具有稳定持续性，那么公司价值会一直保持增长。既然公司价值会\n保持增长，那么巴菲特理所当然会尽可能长久地持有这些投资，使其有更大的机\n会从这些公司的竞争优势中获取财富。 \n巴菲特还注意到，通过价值投资者或投机者，或二者的综合参与，终有一天，\n华尔街会认识到这些股票价值被严重低估，并推动其股票价格反转上升。看起来，\n正式这些公司的持续性竞争优势让它们的价值投资者成为名副其实的预言家。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,656,2073692323514028032),(2073692328421363717,'华尔街会认识到这些股票价值被严重低估，并推动其股票价格反转上升。看起来，\n正式这些公司的持续性竞争优势让它们的价值投资者成为名副其实的预言家。 \n此外，巴菲特还发现了另外一种更神奇的东西。由于这些公司具有难以置信\n的长期经济优势，所以它们几乎不太可能濒临破产边缘。这意味着华尔街的投机\n者把这些股票的价格压得越低，巴菲特买进这些股票后亏损的风险就越小。越低\n的股价同时意味着越大的潜在上涨获利空间。他在低位持有股票的时间越久，他\n能从这些价值低估公司获利的时间就越长。一旦股票市场最终承认了这些公司即\n将到来的美好前景，随之而来的就是巨额财富。 \n所有这些完全推翻了华尔街的一条格言：要获得更多的利润，你不得不加大\n你所能承受的风险。巴菲特发现了投资的圣杯，他找到了一种使风险最小化，却\n能带来潜在收益增长的投资。 \n令事情更简单的是，巴菲特认识到他不再需要等华尔街提供一个便宜的价','2026-07-05 16:55:53.049000',0,2073692323954429952,657,2073692323514028032),(2073692328421363718,'能带来潜在收益增长的投资。 \n令事情更简单的是，巴菲特认识到他不再需要等华尔街提供一个便宜的价\n格。如果他决定投资足够长的时间，他就可以为这些超级公司的股票支付一个公\n平合理的价格，并且一直持有。锦上添花的是，他发现如果进行长线投资，绝不\n卖掉这些股票的话，他还可以有效地将资本利得税推延至遥远的将来，只要一直\n持有，他的投资就能以复利率速度增长，并且免税。 \n让我们看一个例子：1973 年，巴菲特投资 0.11 亿美元于华盛顿邮报公司，\n一家具有持续竞争优势的报业，并且一直持有到现在。在长达 35 年的时间里，\n他一直持有这项投资，如今，这笔投资价值涨到了天文数字 14 亿美元。投资 0.11\n亿美元能获得 14 亿美元的收益！多么体面的投资报酬率！而且最绝妙的是，巴\n菲特还没有为他的利润支付税费，因为至今为止他没卖出任何一股。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,658,2073692323514028032),(2073692328421363719,'亿美元能获得 14 亿美元的收益！多么体面的投资报酬率！而且最绝妙的是，巴\n菲特还没有为他的利润支付税费，因为至今为止他没卖出任何一股。 \n另一方面，如果格雷厄姆按照他的 50﹪法则，将在 1976 年，以约 0.16 亿\n美元卖出巴菲特的华盛顿邮报公司的股票，为此他还要支付占所有利润 39﹪的\n资本利得税。更糟糕的是，那些华尔街的主流股票投资者在过去的 35 年间可能\n上千次持有这只股票，进进出出偶有 10﹪～20﹪的利润，并且每次卖出时都要\n支付税费。但是，巴菲特累积了 12460%的收益率，并且直到如今，还未对其 14\n亿美元收益支付任何税费。 \n巴菲特懂得，只要投资了一家具有持续性竞争优势的公司，他就最终会成为\n一个坐拥亿万美元资产的超级富翁。 \n \n \n第 3 章 巴菲特的淘金之地 \n当我们开始寻找具有持久竞争优势，并可以让我们发财致富的公司时，如果','2026-07-05 16:55:53.049000',0,2073692323954429952,659,2073692323514028032),(2073692328421363720,'一个坐拥亿万美元资产的超级富翁。 \n \n \n第 3 章 巴菲特的淘金之地 \n当我们开始寻找具有持久竞争优势，并可以让我们发财致富的公司时，如果\n知道从何处着手会大有益处。巴菲特最终得出的结论是，这些顶级公司不外乎三\n种基本商业模式：要么是某种特别商品的卖方，要么是某种特别服务的卖方，要\n么是大众有持续需求的商品或者服务的卖方与低成本买方的统一体。 \n让我们分别就此进行讨论。 \n提供某种特别的商品：诸如可口可乐、百事、箭牌、好时、百威、库斯、卡\n夫、华盛顿邮报、宝洁和菲利普·莫里斯一类的公司。通过客户需求和调研、客\n户经验管理和广告推动效应，生产商把他们的产品理念灌输进我们的脑海中。每\n当我们想要满足自己某方面需求时，我们自然会联想到他们的产品。想要嚼口香\n糖？你会想到箭牌；在一个炎炎夏日的工作结束后，想要来瓶冰镇啤酒？你会想\n到百威；饮可口可乐，万事如意…… ','2026-07-05 16:55:53.049000',0,2073692323954429952,660,2073692323514028032),(2073692328421363721,'糖？你会想到箭牌；在一个炎炎夏日的工作结束后，想要来瓶冰镇啤酒？你会想\n到百威；饮可口可乐，万事如意…… \n巴菲特认为这些公司事实上在消费者心目中已经占有一席之地，此时公司没\n必要去改变自己的产品。你会发现这是件好事情：公司可以一边索要更高的价格，\n一边又可以卖出更多的商品。如此一来，公司的财务状况自然会愈来愈好，最终\n又将体现在财务报表上。 \n提供某种特别的服务：诸如穆迪公司、H&R 布洛克税务公司、美国快递公司、\n服务大师公司、富国银行之类的公司。与律师和医生行业类似，这些公司为大众\n提供生活必须而且消费者愿意为此买单。不同的地方在于，这些公司是以整个机\n构树立服务品牌，而不是以单个的服务人员为主。当缴纳税费时，你会想到 H&R\n布洛克税务公司，而不是处理该项业务的该公司里的某某人。当巴菲特买入所罗\n门兄弟公司——一家投资银行（现隶属于花旗银行）的股票时，他认为他买入的','2026-07-05 16:55:53.049000',0,2073692323954429952,661,2073692323514028032),(2073692328421363722,'布洛克税务公司，而不是处理该项业务的该公司里的某某人。当巴菲特买入所罗\n门兄弟公司——一家投资银行（现隶属于花旗银行）的股票时，他认为他买入的\n是一个机构。后来他又卖了这只股票。原因是，当公司的顶尖人才带着他的高端\n客户跳槽时，巴菲特意识到这是一个以人员为主导的公司。在此种类型的公司里，\n员工可以要求得到公司大部分利润，而公司股东只能获得很少一部分。这样一来，\n投资者当然不会变得富有。 \n提供特别服务的公司盈利模式简单易懂。它无需花费大量资金来重新设计产\n品，也无需建造生产厂房和存储仓库。只要获得良好的口碑，提供特别服务的公\n司可以比销售一般产品的公司获得更多的利润。 \n大众有持续需求的商品或服务的卖方与低成本买方的统一体：比如沃尔玛、\n好市多超市、内布拉斯加家居超市、波仙珠宝店和伯灵顿北方圣太菲铁路运输公\n司。在这里，大宗交易可以创造丰厚的利润，薄利多销所增加的收益远远高于单','2026-07-05 16:55:53.049000',0,2073692323954429952,662,2073692323514028032),(2073692328421363723,'好市多超市、内布拉斯加家居超市、波仙珠宝店和伯灵顿北方圣太菲铁路运输公\n司。在这里，大宗交易可以创造丰厚的利润，薄利多销所增加的收益远远高于单\n价折扣所承受的损失。关键的一点在于，它既是低成本卖家，也是低成本买家。\n正因如此，你的利润空间可以高于竞争对手，同时也可以为消费者提供价格低廉\n的产品或服务。哪里有廉价商品，消费者就会蜂拥而至。在奥马哈，如果你想为\n家里买一个新的烤箱，内布拉斯加家居超市可以为你提供各种品牌的产品，而且\n价格低廉。想运输货物出港吗？伯灵顿北方圣太菲铁路运输公司的运费最便宜。\n生活小镇的你想买到物美价廉的生活用品吗？那就去沃尔玛吧！ \n事情就这么简单：要么是某种特别商品的卖方，要么是某种特别服务的卖方，\n要么是大众有持续需求的商品或服务的卖方与低成本买方的统一体，年复一年，\n你定会收获累累硕果。 \n \n \n第 4 章 “持续性”是巴菲特打开金库的钥匙 ','2026-07-05 16:55:53.049000',0,2073692323954429952,663,2073692323514028032),(2073692328421363724,'要么是大众有持续需求的商品或服务的卖方与低成本买方的统一体，年复一年，\n你定会收获累累硕果。 \n \n \n第 4 章 “持续性”是巴菲特打开金库的钥匙 \n巴菲特十分清楚，竞争优势的“持续性”创造了一切财富。在过去的 122\n年里，可口可乐公司一直销售着同一种产品，并且很可能在未来的 122 年里还会\n继续销售这种产品。 \n产品的一致性为公司创造了稳定的利润。如果公司无需频繁更换产品，它就\n不必在研发方面花费几百万资金，也不必投入几十亿的资本去更新厂房设备。如\n此一来，金库的钱就会累积成山了。同时，公司不必承担繁重的债务，也不必支\n付高额的利息，最终可以节约一大笔钱，用以拓展公司业务或者回购公司股票。\n要知道，回购股票可以提高每股收益和公司股票的价格，使股东更加富有。 \n因此，当巴菲特查看一家公司的财务报表时，他总是在试图寻找这种“持续','2026-07-05 16:55:53.049000',0,2073692323954429952,664,2073692323514028032),(2073692328421363725,'要知道，回购股票可以提高每股收益和公司股票的价格，使股东更加富有。 \n因此，当巴菲特查看一家公司的财务报表时，他总是在试图寻找这种“持续\n性”。这个公司是否保持着较高的毛利率？是否一直承担较少的债务，甚至没有\n债务？是否从来无需在研发方面耗费大量资金？其盈利是否保持稳定，或者持续\n稳定地增长？财务报表所表现出的“持续性”可以让巴菲特了解这个公司竞争优\n势的“持久性”。 \n判断一家公司是否具有“持续性”竞争优势，去看看该公司的财务报表吧。这就\n是巴菲特的做法。 \n \n \n第 5 章  财务报表概述：淘金之地 \n巴菲特通过财务报表，挖掘出具有持久竞争力的优质企业。企业的财务报表\n可以反映出这是一个会让你一贫如洗的平庸企业，还是一个拥有持久竞争优势、\n让你腰缠万贯的企业。 \n财务报表分为三类： \n第一，损益表。损益表反映企业在一定会计期间内的经营成果。一般来说，','2026-07-05 16:55:53.049000',0,2073692323954429952,665,2073692323514028032),(2073692328421363726,'让你腰缠万贯的企业。 \n财务报表分为三类： \n第一，损益表。损益表反映企业在一定会计期间内的经营成果。一般来说，\n在每个会计期间，企业的会计人员会为股东编制季度和年度损益表。通过阅读和\n分析损益表，巴菲特能对企业的财务信息进行判断例如利润率、股权收益、利润\n的稳定性和发展趋势（这一点尤其重要）。在判断一个企业是否得益于持久竞争\n优势时，所有的这些因素是必不可少的。 \n第二，资产负债表。资产负债表反映企业的资产和负债情况。从资产中扣除\n负债，我们就能算出这个企业的净资产。企业可以编制一年中任何一天的资产负\n债表——它能反映出企业在特定日期所持有的资产和承担的负债，以及这天的净\n资产。 \n通常的情况下，企业为股东编制每个季度和每个会计年度的资产负债表。通\n过分析资产负债表中的各个项目。例如，现金资产和长期债务，巴菲特可以判断\n该企业是否具有持续的竞争优势。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,666,2073692323514028032),(2073692328421363727,'过分析资产负债表中的各个项目。例如，现金资产和长期债务，巴菲特可以判断\n该企业是否具有持续的竞争优势。 \n第三，现金流量表。现金流量表反映企业的现金流入和流出情况，有利于我\n们了解企业在改善资本结构方面所花费的资金。它同样能反映出债券和股票的销\n售情况，以及股票回购情况。企业通常会将现金流量表同其他财务报表一起公布。 \n至此，我们已经详细探讨了损益表、资产负债表和现金流量表的科目和指标\n——巴菲特正是通过分析它们，来判断一个企业是否具有持久竞争优势。历经时\n日，企业的持久竞争优势总能给他带来丰厚收益。 \n \n \n第 6 章  巴菲特在哪里发现财务信息 \n如今，互联网十分普及，你不费吹灰之力就可以在很多地方找到一家公司的\n财务报表。其中最便捷的途径就是通过 MSN.com（http：//money central. msn. ','2026-07-05 16:55:53.049000',0,2073692323954429952,667,2073692323514028032),(2073692328421363728,'财务报表。其中最便捷的途径就是通过 MSN.com（http：//money central. msn. \ncom/investor/home. asp）或者雅虎财经网（www.finance.yahoo.com）。 \n我们就是通过这两个网站获取公司财务信息的，相对而言，MSN.com 里的内\n容更加详细。首先，你要找到“搜索”的位置，然后敲进公司名称并点击“搜索”\n这时会弹出一个网页，它将把你带到那家公司的股票报价页面。在网页的左边，\n你会发现一个叫做“财务”标题，下面有三个超链接，分别向你展示这家公司的\n资产负债表、损益表和现金流量表。在“SEC”的标题下，有一个超链接，你可\n以看到美国证券交易委员会所提供的各种文件。所有上市公司每个季度都必须将\n财务报表上报给美国证券交易委员会，这些被称为 8Q；归档报表中还有一个叫','2026-07-05 16:55:53.049000',0,2073692323954429952,668,2073692323514028032),(2073692328425558016,'以看到美国证券交易委员会所提供的各种文件。所有上市公司每个季度都必须将\n财务报表上报给美国证券交易委员会，这些被称为 8Q；归档报表中还有一个叫\n10K 的文件，它是公司的年度报告，包括公司会计年度的财务报表。数年来，巴\n菲特已经翻阅了成千上万份 10K 文件，因为这些数字能够最准确地反映出公司的\n财务信息。 \nBloomberg.com 也可以为投资者提供相同或更多的服务，但需要缴纳一定的\n费用。说实话，除非是买卖债券或货币，当我们要建立一个股票投资组合时，MSN\n和雅虎财经网就能为我们免费提供所有需要的财务信息。这些“免费”的财务信\n息总会使我们满意！ \n \n \n第一部 损益表 \n导读 \n巴菲特在分析公司持久竞争优势时，总是先从公司损益表开始着手，他通过\n分析企业的损益表，能够看出这个企业是否能够创造利润，是否具有持久竞争力。 \n巴菲特分析损益表主要关注以下 8 个指标： ','2026-07-05 16:55:53.049000',0,2073692323954429952,669,2073692323514028032),(2073692328425558017,'分析企业的损益表，能够看出这个企业是否能够创造利润，是否具有持久竞争力。 \n巴菲特分析损益表主要关注以下 8 个指标： \n1.毛利率：巴菲特认为，只有具备某种可持续性竞争优势的公司才能在长期\n运营中一直保持盈利，尤其是毛利率在 40%及以上的公司，我们应该查找公司在\n过去 10 年的年毛利率，以确保是否具有“持续性”。 \n2.销售费用及一般管理费用占销售收入的比例：销售费用及一般管理费用越\n少越好，其占销售毛利的比例保持在 30%以下最好。 \n3.研发开支：巴菲特总是回避那些必须经常花费巨额研发开支的公司，尤其\n是高科技公司。巨额研发一旦失败，其长期经营前景将受到很大影响，这意味着\n公司业务未来长期并不稳定，持续性不强。 \n4.折旧费用：巴菲特发现，那些具有持续性竞争优势的公司相对于那些陷入\n过度竞争困境的公司而言，其折旧费占毛利润的比例较低。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,670,2073692323514028032),(2073692328425558018,'4.折旧费用：巴菲特发现，那些具有持续性竞争优势的公司相对于那些陷入\n过度竞争困境的公司而言，其折旧费占毛利润的比例较低。 \n5.利息费用：具有持续性竞争优势的公司几乎不需要支付利息，甚至没有任\n何利息支出。在消费品类领域，巴菲特所钟爱的那些具有持续性竞争优势的公司，\n其利息支出均小于其营业利润的 15%。 \n6.税前利润：指将所有费用开支扣除之后但在所得税被扣减之前的利润。巴\n菲特经常谈到税前条件下的公司利润，这使他能在同等条件下将一家公司或投资\n与另一项投资进行比较，税前利润也是他计算投资回报率常用的一个指标。 \n7.净利润：净利润是否能保持长期增长态势；净利润占总收入的比例是否明\n显高于它们的竞争对手；净利率是否一直保持在总收入的 20%以上。 \n8.每股收益：连续 10 年的每股收益数据就足以让我们明确判断出公司是否','2026-07-05 16:55:53.049000',0,2073692323954429952,671,2073692323514028032),(2073692328425558019,'显高于它们的竞争对手；净利率是否一直保持在总收入的 20%以上。 \n8.每股收益：连续 10 年的每股收益数据就足以让我们明确判断出公司是否\n具有长期竞争优势。巴菲特所寻找的是那些每股收益连续 10 年或者 10 年以上都\n表现出持续上涨态势的公司。 \n \n \n第 7 章  巴菲特从哪里开始着手：损益表                    \n         \n   损益表     （单位：百万美元） \n总收入                                   10 000 \n   销售成本                              3 000 \n   毛利润                                7 000 \n营业费用 \n   销售费用及一般管理费用                2 100 ','2026-07-05 16:55:53.049000',0,2073692323954429952,672,2073692323514028032),(2073692328425558020,'营业费用 \n   销售费用及一般管理费用                2 100 \n   研发费用                              1 000 \n   折旧费                                 700 \n   营业利润                              3 200 \n    \n利息                                   200 \n   出售资产收益                          1 275 \n   其他                                   225 \n税前利润                              1 500 \n应缴所得税                             525 ','2026-07-05 16:55:53.049000',0,2073692323954429952,673,2073692323514028032),(2073692328425558021,'税前利润                              1 500 \n应缴所得税                             525 \n净利润                                 975 \n巴菲特在分析公司是否具有持久竞争优势时，总是先从公司的损益表着手，\n因为损益表可以让投资者了解该企业在一段时期内的经营状况。一般企业会在每\n个季度末或者年末披露这些信息。每张损益表上总是会标出会计期间，例如，从\n2007 年的 1月 1日到 2007 年的 12 月 31 日。 \n损益表包括三个基本要素：企业的营业收入，需要从收入中扣除的支出，损\n益情况——我们可以看到该企业到底是盈利还是亏损。很简单，是吧？的确如此。 \n在早期的股票分析中，那些顶级分析大师，例如巴菲特的导师本杰明·格雷','2026-07-05 16:55:53.049000',0,2073692323954429952,674,2073692323514028032),(2073692328425558022,'益情况——我们可以看到该企业到底是盈利还是亏损。很简单，是吧？的确如此。 \n在早期的股票分析中，那些顶级分析大师，例如巴菲特的导师本杰明·格雷\n厄姆，只是单纯地关注一个企业是否创造利润，而很少甚至根本没有分析这个企\n业的长期升值能力。如前所述，格雷厄姆不在乎这个企业是否具有强劲的经济动\n力，是否是一家出类拔萃的优质企业，或者是否拥有成千上万普通企业梦寐以求\n的发展态势。如果格雷厄姆认为某只股票的价格足够便宜，即使这家公司业绩平\n平，他也可能会买进它。据巴菲特观察，世界上所有企业分为两类：一类是相对\n其竞争对手而言拥有持久竞争优势的企业。如果投资者以一个合理的价格购买这\n类企业的股票并长期持有，他将变得腰缠万贯。另一种类型的企业，是那些在竞\n争市场上苦苦奋斗了若干年，但仍旧碌碌无为的普通企业。做长线的投资者若持\n有这类企业的股票，他们的财富将日益萎缩。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,675,2073692323514028032),(2073692328425558023,'争市场上苦苦奋斗了若干年，但仍旧碌碌无为的普通企业。做长线的投资者若持\n有这类企业的股票，他们的财富将日益萎缩。 \n在研究那些颇具魅力的优质企业时，巴菲特发现，通过分析企业的损益表能\n够看出这个企业是否能够创造利润，是否具有持久竞争力。企业能否盈利仅仅是\n一方面，还应该分析该企业获得利润的方式，它是否需要靠大量研发以保持竞争\n力，是否需要通过财务杠杆以获得利润。通过从损益表中挖掘的这些信息，可以\n判断这个企业的经济增长原动力。对于巴菲特来说，利润的来源比利润本身更具\n有意义。 \n再接下来的章节中，我们将继续讨论企业财务报表中的各种构成因素以及巴\n菲特的研究成果。他的研究将告诉我们，什么样的企业会使我们贫穷，什么样的\n企业是拥有持久竞争力的优质企业——它们能给我们带来财运，让我们成为世上\n最富有的人。 \n \n \n第 8 章  收入—资金来源的渠道 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,676,2073692323514028032),(2073692328425558024,'企业是拥有持久竞争力的优质企业——它们能给我们带来财运，让我们成为世上\n最富有的人。 \n \n \n第 8 章  收入—资金来源的渠道 \n \n                    损益表      （单位：百万美元） \n→收入                                   10 000 \n销售成本                                3 000 \n毛利润                                  7 000 \n损益表的第一行通常是总收入，是指会计期间所流入的总资金。会计期间一\n般为一个季度或者一年。如果一家制鞋厂上年销售额为 1.2 亿美元，那么该企业\n在年度报告的损益表中所表现出的总收入将为 1.2 亿美元。 \n事实上，即使一个公司有很高的销售收入，也并不意味着赚取了利润。判断','2026-07-05 16:55:53.049000',0,2073692323954429952,677,2073692323514028032),(2073692328425558025,'在年度报告的损益表中所表现出的总收入将为 1.2 亿美元。 \n事实上，即使一个公司有很高的销售收入，也并不意味着赚取了利润。判断\n一个公司是否盈利，你应当从总收入中扣除成本费用。总收入减去成本费用等于\n净收益。总收入这个数字本身并不能说明什么，除非我们把成本费用从总收入中\n扣除，才能得到有价值的财务信息——净收益。 \n当巴菲特浏览了一家企业的总收入之后，他就会花大量时间研究各种成本费\n用。因为巴菲特知道，发财致富的秘诀之一，就是减少开支。 \n \n \n第 9 章  销售成本——对于巴菲特来说越少越好 \n \n                    损益表      （单位：百万美元） \n收入                                   10 000 \n→销售成本                                3 000 ','2026-07-05 16:55:53.049000',0,2073692323954429952,678,2073692323514028032),(2073692328425558026,'→销售成本                                3 000 \n毛利润                                  7 000 \n在损益表中，总收入下面一行指的就是销售成本，也被称为收入成本。销售\n成本可以是一个公司其销售产品的进货成本，也可以是制造此产品的材料成本和\n劳动力成本。如果一个公司提供的是服务而不是产品，我们通常用“收入成本”\n这个词来代替“销售成本”。它们在本质上并无差异，只是前者比后者理解上可\n能稍微晦涩一点。我们应该准确调查出这个公司在计算销售成本或者说收入成本\n时所包含的内容，据此，我们就能清楚地了解管理层是如何进行企业管理的。 \n举个简单的例子吧，一个家具公司是怎样计算其产品成本的呢？首先，从公\n司在年初的家具存货成本入手，将年初的存货成本加上这一年中所增加的存货成','2026-07-05 16:55:53.049000',0,2073692323954429952,679,2073692323514028032),(2073692328425558027,'举个简单的例子吧，一个家具公司是怎样计算其产品成本的呢？首先，从公\n司在年初的家具存货成本入手，将年初的存货成本加上这一年中所增加的存货成\n本，然后再减去剩余家具存货在年底的现值。因此，如果一个公司在年初有 1 000\n万美元的存货，在此后一年中总共购买了 200 万美元的存货，在年末，若剩余存\n货价值为 700 万美元，那么公司在本期的产品成本就是 500 万美元。 \n尽管产品销售成本就其数字本身并不能告诉我们公司是否具有持续的竞争\n力优势，但它却可以告诉我们公司的毛利润大小。毛利润指标相当关键，因为它\n能够帮助巴菲特判断公司是否具有长期竞争优势。我们将在下一章详细讨论这一\n点。 \n \n \n第 10 章 毛利润／毛利率：巴菲特寻求长期赢利的关键指标 \n \n           损益表       （单位：百万美元） \n→收入                    10 000 ','2026-07-05 16:55:53.049000',0,2073692323954429952,680,2073692323514028032),(2073692328425558028,' \n           损益表       （单位：百万美元） \n→收入                    10 000 \n销售成本                  3 000 \n→毛利润                   7 000 \n毛利润 7 000／收益 10 000＝毛利率 70% \n现在，如果我们从公司年度报告的总收入中减去它的销售成本，我们将得\n到公司所报告的毛利润。例如：1 000 万美元的总收入减去 700 万美元的销售生\n产成本，毛利润为 300 万美元。 \n毛利润的金额是总收入减去产品所消耗的原材料成本和制造产品所耗费的\n劳动力成本。它不包括销售和管理费用、直接费用。企业运营的利息成本。 \n就其自身而言，毛利润能提供给我们的信息很少，但是我们能通过这个数据\n去计算公司的毛利率，而毛利率能给我们提供很多关于公司经济运营状况的信\n息。 \n计算毛利率的公式为： ','2026-07-05 16:55:53.049000',0,2073692323954429952,681,2073692323514028032),(2073692328425558029,'去计算公司的毛利率，而毛利率能给我们提供很多关于公司经济运营状况的信\n息。 \n计算毛利率的公式为： \n         毛利润／总收入＝毛利率 \n巴菲特的观点是：只有具备某种可持续性竞争优势的公司，才能在长期运营\n中一直保持赢利。他发现，比起缺乏长期竞争力的公司，那些拥有良好长期经济\n原动力和竞争优势的公司往往具有持续较高的毛利率。让我们来看看下面的数\n据： \n巴菲特认为，具有持续竞争优势而保持较高毛利率的企业包括：可口可乐公\n司一直保持 60%或者更高的毛利率，债券评级公司穆迪的毛利率是 73%，伯灵顿\n北方圣太菲铁路运输公司的毛利率为 61%，箭牌公司的毛利率为 51%。 \n想对于我们所熟知的这些优质企业，那些长期经济运行情况不太良好的公\n司，其毛利率就相形见绌了。例如：濒临破产的美国航空公司，它的毛利率仅为\n14%；陷入困难的汽车制造商——通用汽车制造公司，其毛利率只有 21%；曾经','2026-07-05 16:55:53.049000',0,2073692323954429952,682,2073692323514028032),(2073692328425558030,'司，其毛利率就相形见绌了。例如：濒临破产的美国航空公司，它的毛利率仅为\n14%；陷入困难的汽车制造商——通用汽车制造公司，其毛利率只有 21%；曾经\n陷入困难，但现在已经扭亏为盈的美国钢铁公司的毛利率为 17%；一年四季都在\n运营的顾特异轮胎公司，在经济状况不太良好时，毛利率也只有 20%。 \n在技术领域，巴菲特因为不熟悉这一行业而未提及。微软一直保持着 79%\n的高毛利率，而苹果公司的毛利率只有 33%。两者对比可反映出，销售操作系统\n和软件的微软公司比销售硬件及提供相关服务的苹果公司的经营情况更加出色。 \n公司的可持续竞争优势能够创造高毛利率，因为这种竞争优势可以让企业对\n其产品或服务就行自由定价，让售价远远高于产品成本。倘若缺乏持续竞争优势，\n公司只能通过降低产品及服务价格来保持竞争力。如此一来，公司的毛利率以及\n盈利能力理所当然会下降。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,683,2073692323514028032),(2073692328425558031,'公司只能通过降低产品及服务价格来保持竞争力。如此一来，公司的毛利率以及\n盈利能力理所当然会下降。 \n通用规则（当然也有例外）：毛利率在 40%及以上的公司，一般都具有某种\n可持续性竞争优势；而毛利率低于 40%的公司，则一般都处于高度竞争的行业，\n因为竞争会削弱行业总利润率。如果一个行业的毛利率低于 20%（含 20%），显\n然说明这个行业存在着过度竞争。在此类行业中，没有一家公司能在同行竞争中\n创造出可持续性的竞争优势。处在过度竞争行业的公司，由于缺乏某种特殊竞争\n优势，无法为投资者带来财富。 \n毛利率指标检验并非万无一失，它只是一个早期检验指标，一些陷入困境的\n公司也可能具备持久竞争优势。因此，巴菲特特别强调“持久性”这个词，处于\n妥协考虑，我们应该查找公司在过去 10 年的年毛利率，以确保其具有“持续性”。\n巴菲特知道在寻找稳定竞争优势的公司时，必须注意持续性这一前提。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,684,2073692323514028032),(2073692328429752320,'妥协考虑，我们应该查找公司在过去 10 年的年毛利率，以确保其具有“持续性”。\n巴菲特知道在寻找稳定竞争优势的公司时，必须注意持续性这一前提。 \n毛利率较高的公司也有可能会误入歧途，并且丧失长期竞争优势，一是过高\n的研究费用，其次是过高的销售和管理费用，还有就是过高的债务利息支出。这\n三种费用中的任何一种如果过高，都有可能削弱企业的长期经济原动力。这些被\n称为营业费用，它们是所有公司的眼中钉。 \n \n \n第 11 章  营业费用：巴菲特的关注点 \n \n损益表   （单位：百万美元） \n收入                         10 000 \n销售成本                       3 000 \n毛利润                        7 000 \n \n→营业费用                     ','2026-07-05 16:55:53.049000',0,2073692323954429952,685,2073692323514028032),(2073692328429752321,'毛利润                        7 000 \n \n→营业费用                     \n销售费用及一般管理费用               2 100 \n研发费                       1 000  \n折旧费                       700 \n营业利润                      3 200 \n在损益表中，毛利润一行正下方的一组费用被称为营业费用。所有这些费\n用是公司的刚性支出，包括新产品研发费用、将产品推出市场的销售费用及相\n关管理费用、折旧费和分期摊销费、重 \n置成本和减值损失，以及其他费用，诸如非经营性支出和非经常性支出等。 \n 所有这些费用科目加起来构成总营业费用，将其从公司毛利润中扣除，我们\n就能得到公司的营业利润（或亏损）。这些科目都会影响公司的长期经营业绩，','2026-07-05 16:55:53.049000',0,2073692323954429952,686,2073692323514028032),(2073692328429752322,' 所有这些费用科目加起来构成总营业费用，将其从公司毛利润中扣除，我们\n就能得到公司的营业利润（或亏损）。这些科目都会影响公司的长期经营业绩，\n因此，我们将在之后几个章节中以巴菲特的风格向大家逐一介绍。 \n \n \n第 12 章   销售费用及一般管理费用 \n \n损益表       （单位：百万美元） \n在损益表的“销售费用及一般管理费用”标题下面，披露的是公司在该会\n计期间内发生的所以各项 直接或间接的销售费用成本及一般管理费用成本，包\n括管理人员薪金、广告费用、差旅费、诉讼费、佣金和应付薪酬等。 \n像可口可乐这样的公司，此类花费将达到数十亿，它们对公司的固定成本\n有着重大影响。对不同的公司而言，这些费用占毛利润的比例相差迥异，甚至在\n具有持续性竞争优势的公司之间，比例也不尽相同。例如，可口可乐公司的销售\n费用及一般管理费用占毛利润的比例保持在 59%，穆迪公司的此项比例每年约为','2026-07-05 16:55:53.049000',0,2073692323954429952,687,2073692323514028032),(2073692328429752323,'具有持续性竞争优势的公司之间，比例也不尽相同。例如，可口可乐公司的销售\n费用及一般管理费用占毛利润的比例保持在 59%，穆迪公司的此项比例每年约为\n25%，而宝洁公司在这方面的花费则一直保持在 61%左右。请注意，我们这里讲\n的是“持续水平”。 \n那些处在高度竞争行业，从而缺乏持续竞争优势的公司，销售费用及一般\n管理费用比例也显示出巨大的不同。通用公司在过去 5 年中，此项费用占毛利润\n的比例在 28%－83%间。福特公司过去 5 年内，每年在此项费用上的花费占当期\n毛利润的比例竟然在 89%－780%间，这意味着他们像疯子一样花钱。另一方面，\n福田公司的销售业绩不佳，收入呈下降趋势，但该公司的此项费用却一直保持不\n变。如果公司不尽快减少在这些上的花费，那么，它们将吞噬更多的毛利润。 \n在寻找具有持续竞争优势的公司过程中，公司的销售费用及一般管理费用','2026-07-05 16:55:53.049000',0,2073692323954429952,688,2073692323514028032),(2073692328429752324,'变。如果公司不尽快减少在这些上的花费，那么，它们将吞噬更多的毛利润。 \n在寻找具有持续竞争优势的公司过程中，公司的销售费用及一般管理费用\n越少越好。如果它们能一直保持较低的水平，那当然最好。从目前情况看，倘若\n一家公司能将此项费用比例保持在 30%以下，这真令人欣喜。然而，不少具有持\n续竞争优势的公司，此项费用比例仍在 30%－50%。另一方面，如果我们发现一\n个公司在这方面的花费占毛利润的比例接近，甚至超过 100%，那很可能是在跟\n一个处于高度竞争的公司打交道。要知道，在这类行业里，没有任何公司具有可\n持续的竞争优势。 \n收益                   10 000 \n产品成本                  3 000 \n毛利润                   7 000 \n \n营业费用                     ','2026-07-05 16:55:53.049000',0,2073692323954429952,689,2073692323514028032),(2073692328429752325,'毛利润                   7 000 \n \n营业费用                     \n→销售费用及一般管理费用           2 100 \n研发费                   1 000 \n折旧费                    700 \n营业利润                  3 200 \n此外，虽然有些公司维持着低水平或者中等水平比例的销售费用及一般管\n理费用，但它们却因高额的研究开发费用、资本开支或者过高的贷款利息支出，\n破坏了其良好的长期经营发展前景。 \n英特尔公司就是这样的一个例子，该公司在销售费用及一般管理费用上的\n开支占毛利润的比例较低，但因为过高的研发费用，其长期经营业绩被削弱到仅\n占平均水平。即使英特尔公司停止研发，它目前的这批产品绝对可以在 10 年内\n保持不落伍，但其后可能不得不推出市场。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,690,2073692323514028032),(2073692328429752326,'占平均水平。即使英特尔公司停止研发，它目前的这批产品绝对可以在 10 年内\n保持不落伍，但其后可能不得不推出市场。 \n固特异轮胎公司的销售费用及一般管理费用比例为 72%，但其高昂的资本\n支出，以及为这些资本开支融资而产生的贷款利息支出，在经济衰退时代每次都\n将这个轮胎制造商拖人赤字困境。但如果该公司不增加贷款以维持高额资本开支\n或技术改进，它将不能一直保持其核心竞争力。 \n巴菲特认识到，一定要远离这些总是受困于高额销售费用及一般管理费用\n的公司。他也知道，即使是此项费用保持较低水平的公司，它的长期经营前景也\n可能被其高昂的研发费用、高资本开支和大量债务所破坏。无论股票价格如何，\n他都对这类公司避而远之，因为他知道，它们的内在长期经济实力如此脆弱，即\n使股价较低，也不能使投资者扭转终生平庸的结局。 \n \n \n第 13 章  研究和开发费用：为什么巴菲特要避而远之 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,691,2073692323514028032),(2073692328429752327,'使股价较低，也不能使投资者扭转终生平庸的结局。 \n \n \n第 13 章  研究和开发费用：为什么巴菲特要避而远之 \n \n损益表   （单位：百万美元） \n寻找具有持续性竞争优势企业的“游戏”过程中，这是很重要的一部分内容。\n长期的竞争优势，常常是通过专利权或者技术上的领先地位赋予公司在同行中的相\n对优势。如果公司的竞争优势是专利权带来的，例如那些制药类公司，到一定期限\n之后专利权会过期，公司的竞争优势也由此而消失。 \n收入                    10 000 \n销售成本                   3 000 \n→毛利润                    7 000 \n \n营业费用                     \n销售费用及一般管理费用           2 100 \n→研发费                   １000 ','2026-07-05 16:55:53.049000',0,2073692323954429952,692,2073692323514028032),(2073692328429752328,'销售费用及一般管理费用           2 100 \n→研发费                   １000 \n折旧费                     700 \n营业利润                   3 200 \n如果公司的竞争优势是某种技术革新的结果，那么也经常会面临技术革新将其\n取而代之的威胁。这就是为什么微软公司如此害怕谷歌公司技术进步的原因。今天\n的竞争优势很可能贼明天就变成为过时的技术。 \n这些公司不仅要在研发上花费巨额资金，而且由于必须不断地进行产品创新，\n所以它们也必须不断重新设计和升级其产品销售计划，而这意味着它们不得不同时\n在销售和管理费用上消耗巨资。考虑一下：默克公司必须花费毛利润的 29%在研发\n上，花费毛利润的 49%在销售费用及一般管理费用上，这两者加起来将吞噬其毛利\n润的 78%。更糟的是，如果默克公司放弃发明数十亿美元的畅销新药物，当它的专','2026-07-05 16:55:53.049000',0,2073692323954429952,693,2073692323514028032),(2073692328429752329,'上，花费毛利润的 49%在销售费用及一般管理费用上，这两者加起来将吞噬其毛利\n润的 78%。更糟的是，如果默克公司放弃发明数十亿美元的畅销新药物，当它的专\n利权过期时，其竞争优势也将随之消失。 \n英特尔公司尽管是快节奏技术创新领域中的佼佼者，也必须将约 30%的毛利润\n用在研发方面。如果不这么做，过不了几年，它就将事情竞争优势。 \n穆迪公司是一家债券评级公司，是巴菲特长期投资的最爱，这有很好的理由。\n穆迪公司没有研究开发费用，而且平均只花费 25%的毛利润在销售费用及一般管理\n费用上。可口可乐公司也没有研发费，虽然它必须疯狂进行广告投入，但销售费用\n及一般管理费用比例仍然只有约 59%。持有穆迪公司和可口可乐公司的股票，巴菲\n特不会因为担心某些药物专利过期，或者他持有股票的公司在下一轮技术突破竞争\n中失手而夜不能寐。 \n这是巴菲特的一个原则：那些必须花费巨额研发开支的公司都有在竞争优势上','2026-07-05 16:55:53.049000',0,2073692323954429952,694,2073692323514028032),(2073692328429752330,'中失手而夜不能寐。 \n这是巴菲特的一个原则：那些必须花费巨额研发开支的公司都有在竞争优势上\n的缺陷，这将使它们的长期经营前景置于风险中，意味着它们并不太保险。 \n如果不是一项比较保险的投资，巴菲特是不会对其产生兴趣的。 \n \n \n第 14 章  折旧费：巴菲特不能忽视的成本 \n \n  损益表        （单位：百万美元） \n     收入                                 10 000 \n     销售成本                              3 000 \n   →毛利润                                7 000 \n \n     营业费用                                    \n     销售费用及一般管理费用                2 100 ','2026-07-05 16:55:53.049000',0,2073692323954429952,695,2073692323514028032),(2073692328429752331,'     销售费用及一般管理费用                2 100 \n     研发费                                1 000 \n   →折旧费                                  700 \n     营业利润                              3 200 \n所有的机械设备和房屋建筑物最终都将因损耗而报废，这种损耗在损益表上\n反映为折旧费。通常而言，一项资产在给定年度的折旧数额是对当期收益的一种\n成本分配。这样说更确切：每年的资产折旧费，就是该资产被用在当期生产经营\n活动中，并产生收益的那部分资产额。 \n举个实例：假设 XYZ 印刷公司买入了一台价值 100 万美元的印刷机。这台印\n刷机的使用年限为 10 年。因为该印刷机的使用年限为 10 年，国家税务局不允许','2026-07-05 16:55:53.049000',0,2073692323954429952,696,2073692323514028032),(2073692328429752332,'举个实例：假设 XYZ 印刷公司买入了一台价值 100 万美元的印刷机。这台印\n刷机的使用年限为 10 年。因为该印刷机的使用年限为 10 年，国家税务局不允许\n公司将这 100 万美元的总开支一次性全部计入购买该设备的当期成本，而是将这\n购买成本在其使用的 10 年间分别列入各年的折旧费。10 年的使用年限和初始的\n100 万美元的总开支，意味着 XYZ 公司将在未来 10 年内，在这台印刷机上每年\n计提 10 万美元的折旧费。折旧费是公司运营的一项真实成本，因为这台印刷机\n终有一日会被淘汰报废。 \n这台印刷机买入时，反映在资产负债表上，将导致 100 万美元的现金流出和\n100 万美元的工厂和设备（固定资产）的增加。在未来 10 年间，每年必须计提\n10 万美元的折旧费，并作为一项当期开支反映在损益表中。公司每年将从资产','2026-07-05 16:55:53.049000',0,2073692323954429952,697,2073692323514028032),(2073692328429752333,'100 万美元的工厂和设备（固定资产）的增加。在未来 10 年间，每年必须计提\n10 万美元的折旧费，并作为一项当期开支反映在损益表中。公司每年将从资产\n负债表上的工厂和设备资产账户减去 10 万美元，同时增加 10 万美元到累计折旧\n帐户。购买这台印刷机实际发生的 100 万美元现金流出，将反映在现金流量表的\n资本性开支项目中。我们想再强调一次：购买这台印刷机的 100 万美元开支将作\n为折旧费在未来 10 年里逐年摊销（每年折旧费为 10 万美元），而不是在购买当\n年全部列入购买成本。 \n华尔街那些金融家们想出了一个狡猾的伎俩：这台印刷机一旦购买并完成支\n付，今后每年 10 万美元的折旧费并不会发生任何现金流出，但在未来 10 年间，\n它可以减少公司每年向国家税务局上报的利润总额。这意味着从短期来看，XYZ\n公司虽然有一项成本费用，但事实上，它却不发生任何现金流出。因此，那些华','2026-07-05 16:55:53.049000',0,2073692323954429952,698,2073692323514028032),(2073692328429752334,'它可以减少公司每年向国家税务局上报的利润总额。这意味着从短期来看，XYZ\n公司虽然有一项成本费用，但事实上，它却不发生任何现金流出。因此，那些华\n尔街的金融家们就可以将 10 万美元的折旧费还回到利润中，这就意味着，该公\n司的现金流现在可以偿还更多的负债，从而为杠杆式收购提供融资。华尔街的金\n融家们重新设计出了一个利润指标，简称息税折旧摊销前利润，指在扣除所得税、\n折旧费和摊销费之前的利润。 \n巴菲特指出，那些聪明的金融家们在使用息税折旧摊销前利润指标的同时，\n却忽视了一个问题——这台印刷机最终将报废，公司不得不再花 100 万美元去购\n买一台新的印刷机。但公司如今却背负着因杠杆式收购而产生的巨额债务，很可\n能没有能力去购买一台价值 100 万美元的新印刷机了。 \n巴菲特坚信，折旧费是一项真实的开支，因此不管以何种方式计算利润，必','2026-07-05 16:55:53.049000',0,2073692323954429952,699,2073692323514028032),(2073692328429752335,'能没有能力去购买一台价值 100 万美元的新印刷机了。 \n巴菲特坚信，折旧费是一项真实的开支，因此不管以何种方式计算利润，必\n须将折旧费包括进来。倘若背道而驰，我们就会自欺欺人地认为，公司在短期内\n的利润要比实际利润好得多。一个自欺欺人的人一般是不会发财致富的。 \n巴菲特发现，那些具有持续性竞争优势的公司相对于那些陷入过度竞争困境\n的公司而言，其折旧费占毛利润的比例较低。举个例子，可口可乐公司的折旧费\n用一直保持在毛利润的 6％左右，而箭牌公司同样具有持续性竞争优势，其折旧\n费也大约在毛利润的 7％左右，巴菲特长期钟爱的投资对象宝洁公司，其折旧费\n也只有毛利润的 8％。与之形成鲜明对比的是通用汽车，该公司属于高度竞争的\n资本密集型行业，其折旧费占到毛利润总额的 22％～57％。 \n对那些吞噬公司毛利润的各种费用，巴菲特认为它们越少，就意味着越高的\n保底线。 \n \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,700,2073692323514028032),(2073692328429752336,'资本密集型行业，其折旧费占到毛利润总额的 22％～57％。 \n对那些吞噬公司毛利润的各种费用，巴菲特认为它们越少，就意味着越高的\n保底线。 \n \n \n第 15 章  利息支出：巴菲特不想看到 \n \n损益表        （单位：百万美元） \n     收入                                 10 000 \n     销售成本                              3 000 \n→毛利润                                7 000 \n \n     营业费用                                    \n     销售费用及一般管理费用                2 100 \n     研发费                                1 000 ','2026-07-05 16:55:53.049000',0,2073692323954429952,701,2073692323514028032),(2073692328429752337,'     研发费                                1 000 \n   →折旧费                                  700 \n     营业利润                              3 200 \n \n→利息支出                                200 \n利息支出反映的是公司在该季度或该年度为债务所支付的利息。尽管有些公\n司赚取的利息可能比其支付的利息要多，如银行，但对于大多数制造商和零售企\n业而言，利息支出远远大于其利息所得。 \n利息支出被称为财务成本，而不是运营成本。它之所以被单独列出，是因为\n它与公司的生产和销售过程没有任何直接联系。利息是公司财务报表中总负债的\n反映。公司负债越多，其必须支付的利息就越多。 \n如果利息支出占营业利润的比重较高，公司很可能是属于以下两种类型之','2026-07-05 16:55:53.049000',0,2073692323954429952,702,2073692323514028032),(2073692328429752338,'反映。公司负债越多，其必须支付的利息就越多。 \n如果利息支出占营业利润的比重较高，公司很可能是属于以下两种类型之\n一：其一是处于激烈竞争行业的公司，因为在这类领域要保持竞争力，就必须承\n担高额的资本开支；其二是具有良好的经济发展前景，但在杠杆式收购中承担了\n大量债务的公司。 \n巴菲特指出，那些具有持续性竞争优势的公司几乎不需要支付利息，甚至没\n有任何利息支出。具有长期竞争优势的宝洁公司只需花费营业利润的 8％用于利\n息支出；箭牌公司平均只需将 7％的营业利润用以支付利息；相比之下，固特异\n公司属于过度竞争和资本密集型的轮胎制造业，它平均每年不得不将其营业利润\n的 49％用于支付债务利息。 \n甚至在高度竞争的行业，如航空业，利息支出比例也可以被用来判断公司是\n否具有竞争优势。一直保持盈利的西南航空公司仅花费营业利润的 9％用于支付','2026-07-05 16:55:53.049000',0,2073692323954429952,703,2073692323514028032),(2073692328429752339,'甚至在高度竞争的行业，如航空业，利息支出比例也可以被用来判断公司是\n否具有竞争优势。一直保持盈利的西南航空公司仅花费营业利润的 9％用于支付\n利息，而它的竞争对手联合航空，一家濒临破产的公司，其利息支出占到了营业\n利润的 61％。西南航空公司另一个陷入困境的竞争对手美国航空公司，其利息\n费用比例竟高达 92％。 \n这是一条规律：在消费品领域，巴菲特所钟爱的那些具有持续竞争优势的公\n司，其利息支出均小于其营业利润的 15％。但是，我们要清楚，利息支出占营\n业利润的比重在不同行业领域之间相差甚远。举个例子：富国银行（巴菲特持有\n该银行 14％的股份）将其营业利润的大概 30％用于支付利息，相比于可口可乐\n公司，这看起来过高，但事实上，在美国银行业前 5 名中，富国银行的这一比率\n是最低的，也是最吸引人的。此外，富国银行也是唯一一家被标准普尔公司评为\nAAA 级别的银行。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,704,2073692323514028032),(2073692328433946624,'是最低的，也是最吸引人的。此外，富国银行也是唯一一家被标准普尔公司评为\nAAA 级别的银行。 \n利息支出与营业利润的比率也可以真实反映一家公司的经济危机水平。拿投\n资银行业来说，该行业内的公司平均需花费 70％的营业利润用于支付利息。如\n果细致观察，我们不难发现，2006 年，贝尔斯登银行的资产负债表上所列出的\n利息支出占其营业利润的 70％，但截至 2007 年最后一个季度，其利息支出占营\n业利润的比例已经高达 230％。这意味着它将不得不动用公司所有者的权益去补\n足这个差额。对高度杠杆化运作的贝尔斯登来说，这无疑是一场大灾难。到了\n2008 年 3 月，这个曾经十分强大、股价在一年前还高达每股 170 美元的贝尔斯\n登银行，最终被 J·P·摩根以仅每股 10 美元的价格收购。 \n这是一条极其简单的规律：在任何行业领域，那些利息支出占营业利润比例','2026-07-05 16:55:53.049000',0,2073692323954429952,705,2073692323514028032),(2073692328433946625,'登银行，最终被 J·P·摩根以仅每股 10 美元的价格收购。 \n这是一条极其简单的规律：在任何行业领域，那些利息支出占营业利润比例\n最低的公司，往往是最有可能具有竞争优势的。用巴菲特的话来讲，投资于那些\n具有持续性竞争优势的公司是确保我们能够获取长期财富的唯一途径。 \n \n \n第 16 章  出售资产收益（损失）及其他 \n \n损益表        （单位：百万美元） \n     营业费用                                    \n     销售费用及一般管理费用                2 100 \n     研发费                                1 000 \n     折旧费                                  700 ','2026-07-05 16:55:53.049000',0,2073692323954429952,706,2073692323514028032),(2073692328433946626,'     折旧费                                  700 \n营业利润                              3 200 \n      \n     利息支出                                200 \n   →出售资产收益（损失）                  1 275 \n→其他                                    225 \n一个公司出售一项资产（存货除外）所产生的盈利或亏损，将反映在出售资\n产收益（损失）账户上。这项收益是指出售资产产生的收益与该项资产的账面价\n值之差。如果公司有一栋价值 100 万美元的厂房，在计提一定时间的折旧费用后，\n账面价值降为 50 万美元，现在以 80 万美元售出，公司将记录这项资产出售产生','2026-07-05 16:55:53.049000',0,2073692323954429952,707,2073692323514028032),(2073692328433946627,'值之差。如果公司有一栋价值 100 万美元的厂房，在计提一定时间的折旧费用后，\n账面价值降为 50 万美元，现在以 80 万美元售出，公司将记录这项资产出售产生\n的 30 万美元收益。与之类似，如果该厂房以 40 万美元的价格出售，公司将记录\n10 万美元的出售资产损失。 \n此原理同样适用于“其他”这个账户。该账户将非运营的、偶然的、非经常\n性的收入和支出一并汇总记录，并反映在损益表上。这些业务包括固定资产（如\n财产、工厂和设备）的出售，同时也包括公司正常经营业务范围之外的许可协议\n和专利权出售等。 \n有时候，这些偶然性事件会突然加到公司损益表的最后几行，因为它们都是\n偶然性事件。巴菲特认为，无论用哪种利润指标来确定公司是否具有持续性竞争\n优势，这些偶然事件的影响都应该被排除在外。 \n \n \n第 17 章  税前利润：巴菲特惯用的指标 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,708,2073692323514028032),(2073692328433946628,'优势，这些偶然事件的影响都应该被排除在外。 \n \n \n第 17 章  税前利润：巴菲特惯用的指标 \n \n            损益表        （单位：百万美元） \n     营业费用 \n     销售费用及一般管理费用                2 100 \n     研发费                                1 000 \n     折旧费                                  700 \n     营业利润                              3 200 \n \n     利息支出                                200 \n     出售资产收益（损失）                  1 275 ','2026-07-05 16:55:53.049000',0,2073692323954429952,709,2073692323514028032),(2073692328433946629,'     出售资产收益（损失）                  1 275 \n     其他                                    225 \n   →税前利润                              1 500 \n税前利润是指将所有费用开支扣除之后，但在所得税被扣减之前的利润。巴\n菲特在决定是否要购买一家公司或在公开市场买入一家公司部分股票时，税前利\n润也是他计算投资回报率常用的一个指标。 \n将免税的投资排除在外，所有的投资报酬率都是以税前为基准的。并且，因\n为所有的投资都在相互竞争，所以如果能在相同的前提条件下衡量它们，事情就\n变得更加简单容易。 \n巴菲特当年买入价值 1.39 亿美元的华盛顿公共电力供应系统的免税债券\n（该债券每年支付给他 2 270 万美元的免税利息），其理由是免税的 2 200 万美','2026-07-05 16:55:53.049000',0,2073692323954429952,710,2073692323514028032),(2073692328433946630,'巴菲特当年买入价值 1.39 亿美元的华盛顿公共电力供应系统的免税债券\n（该债券每年支付给他 2 270 万美元的免税利息），其理由是免税的 2 200 万美\n元收益相当于税前的 4 500 万美元收益。如果他购买一家每年赚取 4 500 万美元\n税前利润的公司，估计他需要花费 2.5 亿～3亿美元。因此，他把投资于华盛顿\n公共电力供应系统债券，当作是以 50％的折扣买入了一家具有同样经济发展前\n景的公司。 \n巴菲特经常谈到税前条件下的公司利润，这使他能在同等条件下将一家公司\n的投资与另一项投资进行比较。同时，这也是他价值投资理论启示的基石：持有\n一家具有持续竞争优势的公司，实际上是投资于一种息票利率逐渐增长的“权益\n债券”。我们将在本书结尾部分对他的“权益债券”理论进行更深入详尽的探讨。 \n \n \n第 18 章    应缴所得税：巴菲特怎么知道谁在说真话 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,711,2073692323514028032),(2073692328433946631,'债券”。我们将在本书结尾部分对他的“权益债券”理论进行更深入详尽的探讨。 \n \n \n第 18 章    应缴所得税：巴菲特怎么知道谁在说真话 \n \n损益表              （单位：百万美元） \n    营业费用 \n    销售费用及一般管理费用            2100 \n    研发费                            1000 \n    折旧费                             700 \n  营业利润                          3200 \n \n   \n    利息支出                           200 \n    出售资产收益（损失）              1275 \n    其他                               225 ','2026-07-05 16:55:53.049000',0,2073692323954429952,712,2073692323514028032),(2073692328433946632,'    出售资产收益（损失）              1275 \n    其他                               225 \n    税前利润                          1500 \n  →应缴所得税                         525 \n与其他任何纳税人一样，美国公司必须为它们的收益缴纳所得税。现在在美\n国，公司需缴纳的所得税金额大概为其税前所得的 35%。当税金被支付以后，它\n们将反映在损益表中的“应缴所得税”一栏。 \n有趣的是，应缴所得税项目反映了公司的真实税前利润。有时候，一些公司\n喜欢夸大其词，对外宣称它们赚了很多钱，但事实上并非如此。这让人感到震惊，\n不是吗？有一种途径能够判断出它们所说的是真话还是假话，那就是去查看该公\n司提交给美国证券管理委员会的报表，然后再查出它们的所得税支付情况，将其','2026-07-05 16:55:53.049000',0,2073692323954429952,713,2073692323514028032),(2073692328433946633,'不是吗？有一种途径能够判断出它们所说的是真话还是假话，那就是去查看该公\n司提交给美国证券管理委员会的报表，然后再查出它们的所得税支付情况，将其\n报告的税前营业利润数额从中扣除 35%，如果余额与公司对外报告的税后利润不\n符合，我们最好做进一步了解。 \n多年来，巴菲特发现那些千方百计歪曲事实以欺骗美国国家税务局的公司，\n同样会绞尽脑汁地想出各种方法欺骗它们的股东。真正具有长期竞争优势的优质\n公司，其利润本来就很不错，完全没有必要靠包装来误导他人。 \n \n \n第 19 章  净利润：巴菲特的追求 \n \n损益表          （单位：百万美元） \n    营业费用 \n    销售费用及一般管理费用              2100 \n    研发费                              1000 ','2026-07-05 16:55:53.049000',0,2073692323954429952,714,2073692323514028032),(2073692328433946634,'    销售费用及一般管理费用              2100 \n    研发费                              1000 \n    折旧费                               700 \n  营业利润                            3200 \n \n   \n    利息支出                             200 \n    出售资产收益（损失）                1275 \n    其他                                 225 \n    税前利润                            1500 \n    应缴所得税                           525 ','2026-07-05 16:55:53.049000',0,2073692323954429952,715,2073692323514028032),(2073692328433946635,'    应缴所得税                           525 \n → 净利润                               975 \n  当公司从收入中扣除所有费用开支和税款之后，我们就能得到公司的净\n利润。这个指标可以让我们清楚，公司在缴纳所得税后最终赚了多少钱。当巴菲\n特通过该指标来帮他判断一个公司是否具有持续性竞争优势时，他运用了几个概\n念，我们就从那些概念开始吧。 \n巴菲特首先关心公司净利润是否具有上升趋势。仅仅单独一年的净利润数据\n对巴菲特来讲毫无价值，他感兴趣的是，公司利润是否展现美好前景，是否能保\n持长期增长态势，若是两者兼备，则等同于具有持续性的竞争优势。巴菲特并不\n要求公司一帆风顺，但他希望整个趋势是保持向上的。 \n但在此注明：公司有可能因为股票回购计划而导致净利润的历史走势不同于','2026-07-05 16:55:53.049000',0,2073692323954429952,716,2073692323514028032),(2073692328433946636,'要求公司一帆风顺，但他希望整个趋势是保持向上的。 \n但在此注明：公司有可能因为股票回购计划而导致净利润的历史走势不同于\n每股收益。股票回购方案将减少流通股数量，从而增加每股收益。如果一个公司\n的流通股数量减少了，也就是说，计算每股盈利的公式中分母变小了，每股收益\n反而会增多，但事实上净利润并没有增加。有些极端的例子是，某些公司的净利\n润本来正面临衰减，但通过股票回购计划，则可能使每股收益不减反增。 \n尽管大多数金融分析师都关注公司的每股收益，但巴菲特却关注公司净利润\n的真正走势。 \n巴菲特发现，那些具有持续性竞争优势的公司，其报告净利润占总收入的比\n例会明显高于它们的竞争对手。巴菲特曾经说过，倘若要在一家收入 100 亿美元、\n净利润为 20 亿美元的公司和一家收入 1 000 亿美元但仅赚 50 亿美元的公司之间\n进行选择的话，他将选择拥有前者。因为这家公司所赚取的净利润占其总收入的','2026-07-05 16:55:53.049000',0,2073692323954429952,717,2073692323514028032),(2073692328433946637,'净利润为 20 亿美元的公司和一家收入 1 000 亿美元但仅赚 50 亿美元的公司之间\n进行选择的话，他将选择拥有前者。因为这家公司所赚取的净利润占其总收入的\n20%，而另一家公司只占其总收入的 5%。 \n所以，单独的总收入数据基本不能反映出公司经营业绩状况，但它与净利润\n的比率，却能告诉我们很多关于公司与其他公司对比的业绩状况方面的信息。 \n像可口可乐这样的优质公司能净赚总收入的 21%，举世瞩目的穆迪公司能净\n赚总收入的 31%，这些数据正好反映出这两家公司卓越的基本情况。相比而言，\n西南航空公司只能净赚总收入中微薄的 7%的利润，这反映出航空业的高度竞争\n性质。在这个行业内，没有一家公司能够相对同行具有长期竞争优势。另外，通\n用汽车公司即使在经营情况良好时（当它不亏损时），也只能净赚其总收入的 3%\n的利润，这同样说明过度竞争的汽车制造业糟糕的经济状况。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,718,2073692323514028032),(2073692328433946638,'用汽车公司即使在经营情况良好时（当它不亏损时），也只能净赚其总收入的 3%\n的利润，这同样说明过度竞争的汽车制造业糟糕的经济状况。 \n一条简单规律（当然不乏例外）：如果一家公司的净利润一直保持在总收入\n的 20%以上，很有可能，这家公司具有某种长期的相对竞争优势。反之，如果一\n家公司的净利润持续低于其总收入的 10%，那么它很可能处于一个高度竞争的行\n业，在该行业中没有一家公司能维持其竞争优势。当然，这种绝对量化的观点会\n留下一个巨大的灰色地带——就是那些净利润率在 10%~20%的公司，这一地带\n挤满了目前还未被投资者发现，但时机已经成熟，并等待发掘长期投资财富的公\n司。 \n银行和金融公司不属于上述规律范畴内，这类公司如果出现异常高的净利润\n率，通常意味着其风险管理部门过于松懈。尽管这些数据表面上看起来非常有诱\n惑力，但实际上它们却暗示出公司可能在为所谓的高收益率承担巨大的风险，这','2026-07-05 16:55:53.049000',0,2073692323954429952,719,2073692323514028032),(2073692328433946639,'率，通常意味着其风险管理部门过于松懈。尽管这些数据表面上看起来非常有诱\n惑力，但实际上它们却暗示出公司可能在为所谓的高收益率承担巨大的风险，这\n在贷款业务中通常表现为赚取快钱，但其代价可能是长期的灾难。一个深陷于财\n务危机的公司是不可能让投资者发财致富的。 \n \n \n第 20 章  每股收益：巴菲特怎么辨别成功者和失败者 \n每股收益是会计期间内以股份数为基数，计算公司每股股票所得的净利润。\n在投资领域中，这是一个重量级指标，因为公司的每股收益越多，其股票价格将\n越高，这是一条定律。想知道公司的每股收益，我们将公司的净利润总额除以公\n司流通股数量即可得到。举个例子：如果一家公司今年赚取了 1 000 万美元的净\n利润，而公司总共有 100 万股流通股，那么该公司今年的每股收益为 10 美元。 \n任何单独一年的每股收益不足以用来判断一个公司是否具有持续性竞争优','2026-07-05 16:55:53.049000',0,2073692323954429952,720,2073692323514028032),(2073692328433946640,'利润，而公司总共有 100 万股流通股，那么该公司今年的每股收益为 10 美元。 \n任何单独一年的每股收益不足以用来判断一个公司是否具有持续性竞争优\n势，但是，连续 10 年的每股收益数据就足以让我们明确判断出公司是否具有长\n期竞争优势。巴菲特所寻找的是那些每股收益连续 10 年或者 10 年以上都表现出\n持续上涨态势的公司，例如每股收益情况类似于： \n2008        2、95 美元 \n2007        2、68 美元 \n2006        2、37 美元 \n2005        2、17 美元 \n2004        2、06 美元 \n2003        1、95 美元 \n2002        1、65 美元 \n2001        1、60 美元 \n2000        1、48 美元 \n1999        1、30 美元 ','2026-07-05 16:55:53.049000',0,2073692323954429952,721,2073692323514028032),(2073692328433946641,'2001        1、60 美元 \n2000        1、48 美元 \n1999        1、30 美元 \n1998        1、42 美元 \n这张每股收益趋势表给巴菲特展示出该公司具有持续上涨的每股收益，充分\n说明这家公司具有某种长期竞争优势。持续的利润通常表明公司所销售的产品或\n产品系列都不需要经过一个昂贵的交换过程，或者说销售成本很低。利润的上升\n走势意味着公司强大的经济实力足以支付为扩大市场份额而投入的广告费用，或\n者为扩大生产规模而产生的各种开支，同时公司也有充裕资金进行类似于股票回\n购的投资活动。 \n像下面图表中所列示的每股收益走势不确定的公司，巴菲特通常会避而远\n之： \n2008        2、50 美元 \n2007        0、45 美元（亏损） \n2006        3、89 美元 \n2005        6、05 美元（亏损） ','2026-07-05 16:55:53.049000',0,2073692323954429952,722,2073692323514028032),(2073692328433946642,'2007        0、45 美元（亏损） \n2006        3、89 美元 \n2005        6、05 美元（亏损） \n2004        6、39 美元 \n2003        5、03 美元 \n2002        3、35 美元 \n2001        1、77 美元 \n2000        6、68 美元 \n1999        8、35 美元 \n1998        5、24 美元 \n这张图表显示出该公司每股收益呈下降趋势，其中一些年度甚至亏损，这些\n信息告诉巴菲特，这个公司处于一个激烈竞争行业，时而进入繁荣时期，时而步\n入衰退时期。繁荣时期说明需求大于供给，当需求巨大时，公司就会扩大生产以\n适应需求，而这将增加成本，并最终导致整个行业供给过剩。供给过剩的结果是\n价格下跌，这意味着在下一轮繁荣来临之前，公司将面临亏损。市场上有数以千','2026-07-05 16:55:53.049000',0,2073692323954429952,723,2073692323514028032),(2073692328433946643,'适应需求，而这将增加成本，并最终导致整个行业供给过剩。供给过剩的结果是\n价格下跌，这意味着在下一轮繁荣来临之前，公司将面临亏损。市场上有数以千\n计这样的公司，其每股收益都是如此走势不定，导致其股票价格像翅膀一样忽上\n忽下。这也让很多传统价值投资者误认为到了买入的时机，但殊不知他们买进的\n却是一艘冗长而缓慢、没有明确行驶方向的船只。 \n \n \n第二部 资产负债表 \n导读 \n当巴菲特试图判断一家公司是否具有持续性竞争优势时，他首先会去查看公\n司拥有多少资产，有多少债务，要了解这些信息，他必须查看公司的资产负债表。 \n巴菲特分析资产负债表，主要关注以下指标： \n1、现金和现金等价物：企业经营遇到困难时，现金越多越好。这时最理想\n的状况是，有大量的现金库存而几乎没有什么债务，并且没有出售股份或资产，\n同时公司过去一直保持盈利。 \n2、存货：对于制造类企业，要查看其存货增长的同时净利润是否相应增长。','2026-07-05 16:55:53.049000',0,2073692323954429952,724,2073692323514028032),(2073692328433946644,'同时公司过去一直保持盈利。 \n2、存货：对于制造类企业，要查看其存货增长的同时净利润是否相应增长。\n存货在某些年份迅速增加，而其后又迅速减少的制造类公司，它很有可能处于高\n度竞争、时而繁荣、时而衰退的行业，其中没有任何一家公司能让人变得富有。 \n3、应收账款：如果一家公司持续显示出比其竞争对手更低的应收账款占总\n销售的比率，那么它很可能具有某种相对竞争优势。 \n4、流动比率=流动资产除以流动负债：很多具有持续性竞争优势的公司，其\n流动比率都小于 1，大大异于传统的流动比率指标评判标准。原因是它们的盈利\n能力足够强劲，融资能力强大，能够轻松自如地用盈利或融资来偿还其流动负债。 \n5、房产、厂房和机器设备：优秀公司的产品经常稳定不变，无需为保持竞\n争力而耗费巨额资金去更新厂房和设备。 \n6、无形资产：巴菲特能发现其他人所不能发现的资产负债表之外的无形资','2026-07-05 16:55:53.049000',0,2073692323954429952,725,2073692323514028032),(2073692328433946645,'争力而耗费巨额资金去更新厂房和设备。 \n6、无形资产：巴菲特能发现其他人所不能发现的资产负债表之外的无形资\n产，那就是优秀公司的持续竞争优势，以及由此产生的长期盈利能力。 \n7、资产回报率=净利润除以总资产：大多数分析师认为资产回报率越高越好，\n但巴菲特却发现，过高的资产回报率可能暗示这个公司的竞争优势在持续方面是\n脆弱的。 \n8、短期贷款：当投资于金融机构时，巴菲特通常回避那些短期贷款比长期\n贷款多的公司。 \n9、长期贷款：巴菲特发现，那些具有持续性竞争优势的公司通常负担很少\n的长期贷款，或压根没有长期贷款。这是因为这些公司具有超强的盈利能力，当\n需要扩大生产规模或进行企业并购时，它们完全有能力自我融资。一般而言，它\n们有充足的盈余在 3～4 年时间内偿还所有长期债务。 \n10、债务股权比率=总负债÷股东权益：越是好公司，盈利能力越强，股东','2026-07-05 16:55:53.049000',0,2073692323954429952,726,2073692323514028032),(2073692328438140928,'们有充足的盈余在 3～4 年时间内偿还所有长期债务。 \n10、债务股权比率=总负债÷股东权益：越是好公司，盈利能力越强，股东\n权益越高，总债务较低。除非我们是在寻找金融机构，债务股权比率低于 0.80\n越好，越低越好。 \n11、留存收益：公司留存收益的增长率是判断公司是否得益于某种持续性竞\n争优势的一项好指标。道理很简单：公司留存的收益越多，它的留存收益增长就\n越快，而这又将提高公司未来收益的增长率。 \n12、库存股票：如果资产负债表上出现了库存股票，表明公司曾经回购股票，\n那么这家公司很可能具有一种与之有利的持续性竞争优势。但中国法律规定回购 \n股份必须注销，因此资产负债表中没有库存股票。 \n13、股东权益回报率=净利润除以股东权益：巴菲特发现，那些受益于某种\n持续性或长期竞争优势的公司往往有较高的股东权益回报率。 \n14、财务杠杆：财务杠杆是指公司通过借债来进行投资以扩大利润。巴菲特','2026-07-05 16:55:53.049000',0,2073692323954429952,727,2073692323514028032),(2073692328438140929,'持续性或长期竞争优势的公司往往有较高的股东权益回报率。 \n14、财务杠杆：财务杠杆是指公司通过借债来进行投资以扩大利润。巴菲特\n会尽量避开那些使用大量杠杆来获取利润的公司。 \n \n \n第 21 章   资产负债表概述 \n    当巴菲特试图判断一家公司是否具有可持续竞争优势时，他首先会去查看公\n司拥有多少资产（包括现金和财产），承担多少债务（包括公司对供应商的应付\n款、银行贷款以及债券）。要了解这些信息，他必须去查看公司的资产负债表。 \n    资产负债表不像损益表那样有固定的报表期间，不存在一个年度或一个季度\n的资产负责表这一说法。我们能在一年中的任何一天创建一张资产负债表，但它\n一般只在特别的日子里才会派上用场。公司的会计部门一般会在每个会计期间的\n最后一天编制资产负责表，我们可以把它看作是在那个特定的时刻公司财务状况\n的一张“快照”。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,728,2073692323514028032),(2073692328438140930,'最后一天编制资产负责表，我们可以把它看作是在那个特定的时刻公司财务状况\n的一张“快照”。 \n    资产负债表包括两个部分：第一部分列出所有的资产，其中有很多不同类型\n的资产项目，包括现金、应收账款、存货厂房和机械设备。 \n    资产负债表的第二部分是负债和所有者权益。 \n    负债可以分为两种不同类型的负债：流动负责和长期负债。流动负债指一年\n内到期需要偿还的借款，包括应付账款、预提费用、短期债务、到期长期负债以\n及其他流动负债。 \n  长期负债是指那些一年以后或更长时间到期的负责，包括公司所欠供应商的\n货款、未缴税金、银行贷款以及其他流动负债。 \n    巴菲特寻找具有持续竞争优势的公司，就是要在其资产负债表中查找某种特\n殊的东西，在本书的稍后章节中会进行详细的描述。 \n    现在，如果我们用所有的资产减去所有的负债，将得到公司的净资产，它与','2026-07-05 16:55:53.049000',0,2073692323954429952,729,2073692323514028032),(2073692328438140931,'殊的东西，在本书的稍后章节中会进行详细的描述。 \n    现在，如果我们用所有的资产减去所有的负债，将得到公司的净资产，它与\n公司所有者权益是相等的。举个例子：如果一个公司有价值 10 万美元的资产和\n2.5 万美元的负债，那该公司的所有者权益或者净资产就是 7.5 万美元。但如果\n该公司的资产价值为 10 万美元，而负债为 17.5 万美元的话，公司的净资产或者\n所有者权益就为负的 7.5 万美元。 \n          资产–负债 = 净资产或所有者权益 \n  关于资产负债表概述就讲到这里吧，我们在后面的章节中会看到，巴菲特是如\n何使用资产负债表，以其所有分类去识别一家公司是否具有持续性相对竞争优势\n的。 \n  附：资产负债表 \n       资产负债表  （单位：百万美元） \n资产 \n现金和短期存款      4208 \n存货合计                2 220 ','2026-07-05 16:55:53.049000',0,2073692323954429952,730,2073692323514028032),(2073692328438140932,'       资产负债表  （单位：百万美元） \n资产 \n现金和短期存款      4208 \n存货合计                2 220 \n应收账款合计（净值）    3 317 \n预付账款                2 260 \n其他流动资产合计           0 \n负债 \n应付账款                1 380 \n预提费用                5 535 \n短期借款                5 919 \n到期长期借款              133 \n其他流动负责合计          258 \n流动资产合计           12 005 \n \n \n房产/厂房/设备           8 493 \n商誉（净值）            4 246 \n无形资产（净值）        7 863 ','2026-07-05 16:55:53.049000',0,2073692323954429952,731,2073692323514028032),(2073692328438140933,' \n \n房产/厂房/设备           8 493 \n商誉（净值）            4 246 \n无形资产（净值）        7 863 \n长期投资                7 777 \n其他长期资产            2 675 \n其他资产                   0 \n流动负债合计           13 225 \n长期借款                3 277 \n递延所得税              1 890 \n少数股东权益             0 \n其他负债                3 133 \n负债合计                21 525 \n \n所有者权益 \n优先股                   0 \n普通股                   880 \n资本公积                7 378 ','2026-07-05 16:55:53.049000',0,2073692323954429952,732,2073692323514028032),(2073692328438140934,'优先股                   0 \n普通股                   880 \n资本公积                7 378 \n留存收益                36 235 \n普通国债                -23 375 \n其他权益                  626 \n资产合计               43 059 \n所有者权益总额           21 744 \n \n \n负债和所有者权益合计     43 269  \n \n \n第 22 章   资产 \n \n资产负债表/资产项目     （单位：百万美元） \n现金和短期投资                                  4 208 \n存款合计                                        2 220 ','2026-07-05 16:55:53.049000',0,2073692323954429952,733,2073692323514028032),(2073692328438140935,'存款合计                                        2 220 \n应收账款合计                                    3 317 \n预付账款                                        2 260 \n其他流动资产合计                                    0 \n流动资产合计                                    12 005 \n \n房产/厂房/机械设备                                8 493 \n商誉（净值）                                     4 246 \n无形资产（净值）                                 7 863 ','2026-07-05 16:55:53.049000',0,2073692323954429952,734,2073692323514028032),(2073692328438140936,'无形资产（净值）                                 7 863 \n长期投资                                         7 777 \n其他长期资产                                     2 675 \n其他资产                                             0 \n资产合计                                        43 059 \n    这张表上记录了全部资产，包括现金、厂房和设备、专利权等所有组成公司\n财富的东西，它们都在公司资产负债表中的资产项目下面。 \n    在资产负债表上，以前的会计分类将公司资产分为两大类：流动资产和其他\n资产。 \n    流动资产包括现金和现金等价物、短期投资、净应收账款、存货以及统称的','2026-07-05 16:55:53.049000',0,2073692323954429952,735,2073692323514028032),(2073692328438140937,'    在资产负债表上，以前的会计分类将公司资产分为两大类：流动资产和其他\n资产。 \n    流动资产包括现金和现金等价物、短期投资、净应收账款、存货以及统称的\n其他流动资产。这些资产之所以被称之为流动资产，是因为它们是现金，或者能\n在很短的时间内（一般在一年以内）转化为现金。按规定，它们在资产负债表上\n是按照流动性（代表它们变现的速度）进行列示。流动资产也被称为快速资产、\n不稳定资产或浮动资产。流动资产最重要的功能在于，如果公司的经营状况开始\n恶化，它们能够迅速变现。（如果你无法想想一家公司的营运资本可能一夜之间\n蒸发殆尽，看看贝尔斯登就知道了。） \n    其他所有资产就是指那些流动性不足的资产，换句话说，就是那些一年之内\n都不能变现的资产。作为一个单独分类，它们被列示在资产负债表的正下方，包\n括长期投资、厂房财务和机器设备、商誉、无形资产、累计摊销、其他长期资产','2026-07-05 16:55:53.049000',0,2073692323954429952,736,2073692323514028032),(2073692328438140938,'都不能变现的资产。作为一个单独分类，它们被列示在资产负债表的正下方，包\n括长期投资、厂房财务和机器设备、商誉、无形资产、累计摊销、其他长期资产\n和递延长期资产支付。 \n    这两大类资产合计起来构成了公司总资产。不管是以单独形式还是合计出\n现，通过观察它们的质量和数量，巴菲特从中可以得到很多关于公司经济营运状\n况的信息，并从此分析判断该公司是否是他梦寐以求、能让他成为超级富豪的具\n有持续性竞争优势的公司。 \n    这就是我们为什么要在随后几个章节中分别讨论各类资产，饼分析巴菲特是\n如何运用这些指标去判断公司是否具有持续性竞争优势的原因。接下来，我们将\n详细阐述这些资产类别，通过单独分析和汇总分析，探讨如何利用它们帮助我们\n识别那些优质公司。 \n \n \n第 23 章   流动资产周转：钱是如何赚取的 \n \n资产负债表/资产项目（单位：百万美元） \n→ 现金和短期投资 4 208 ','2026-07-05 16:55:53.049000',0,2073692323954429952,737,2073692323514028032),(2073692328438140939,'识别那些优质公司。 \n \n \n第 23 章   流动资产周转：钱是如何赚取的 \n \n资产负债表/资产项目（单位：百万美元） \n→ 现金和短期投资 4 208 \n→ 存货合计                              2 220 \n→ 应收账款合计（净值）                  3 317 \n预付账款                              2 260 \n其他流动资产合计                          0  \n流动资产合计                          12 550 \n \n  流动资产通常也被称为公司的”运营资产”,因为它们始终循环在生产经营过\n程中：现金用于购买原料并以存货形式存在，经过加工处理的存货又出售给经销\n商，并变现为应收账款，从经销商那里收回的应收账款最后又转化为现金。现金','2026-07-05 16:55:53.049000',0,2073692323954429952,738,2073692323514028032),(2073692328438140940,'程中：现金用于购买原料并以存货形式存在，经过加工处理的存货又出售给经销\n商，并变现为应收账款，从经销商那里收回的应收账款最后又转化为现金。现金\n→存货→应收账款→现金的这个循环反复周转，公司就是在这个周转过程中赚取\n收益的。 \n流动资产在周转中呈现不同形式和内容，提供给巴菲特大量有关公司经营\n状况的信息，巴菲特据此判断这个公司在竞争市场上是否具有持续性相对优势。 \n \n \n第 24 章 现金和现金等价物：巴菲特的困惑 \n \n资产负债表／资产项目  （单位：百万美元） \n→现金和短期投资 ４２０８ \n→存货合计 ２２２０ \n→应收账款合计（净值） ３３１７ \n预付账款 ２２６０ \n其他流动资产合计 ０ \n流动资产合计 １２００５ \n巴菲特在资产负责表上查的第一项内容，就是公司的资产项目下有多少现金\n和现金等价物。这项资产包括现金和现金等价物，如短期银行存款、三月期国债','2026-07-05 16:55:53.049000',0,2073692323954429952,739,2073692323514028032),(2073692328438140941,'巴菲特在资产负责表上查的第一项内容，就是公司的资产项目下有多少现金\n和现金等价物。这项资产包括现金和现金等价物，如短期银行存款、三月期国债\n和其他高流动性资产。一个公司若持有高额的现金或现金等价物，巴菲特由此判\n断该公司可能为以下两种情况之一：其一，公司具有某种竞争优势，并能不断的\n产生大量现金，这是好事；其二，公司刚出售了一部分业务或大量的公司债券，\n这可能不是件好事。底数额或非常短缺的库存现金通常意味着公司经营变得困难\n或趋于平庸。为了更清楚的区分以上各种情况，下面让我们对现金这项资产进行\n更深入的了解。 \n通常情况下，公司会保留一部分现金，从而维持企业的运营，这些库存现\n金被当成一个巨大的支票簿。但是，如果我们一直保持盈利状态，库存现金将不\n断堆积，公司将面临如何处理这些多余现金的相关投资问题——这当然是我们乐\n意接受的事情。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,740,2073692323514028032),(2073692328438140942,'金被当成一个巨大的支票簿。但是，如果我们一直保持盈利状态，库存现金将不\n断堆积，公司将面临如何处理这些多余现金的相关投资问题——这当然是我们乐\n意接受的事情。 \n由于将现金存入银行活期账户或定期存款所带来的投资回报率太微薄，所\n以，最好将现金资产投入到公司运营或具有更高资产回报率的投资项目上。你想\n拥有哪种投资？一张给你带来４％的投资回报率的短期银行存款单，还是一栋可\n能给你带来２０％投资回报的公寓？你毫不犹豫的选择公寓。其道理同样适用于\n公司运作。如果现金比日常营运所消耗的现金流出更快的话，现金将会越积越多。\n一旦现金堆积增多，公司将不得不考虑怎么处理它。公司传统的做法是将多余的\n现金用于扩大生产规模。而羽翼未丰的新兴公司则可能通过股票市场投资其他公\n司，用于回购公司股票，或者给股东派发现金红利。但大多数情况下，它们只是','2026-07-05 16:55:53.049000',0,2073692323954429952,741,2073692323514028032),(2073692328438140943,'现金用于扩大生产规模。而羽翼未丰的新兴公司则可能通过股票市场投资其他公\n司，用于回购公司股票，或者给股东派发现金红利。但大多数情况下，它们只是\n简单的存储现金以备不时之需。这个瞬息万变、充斥着机遇与挑战的世界里，一\n家公司保持在多的现金储备都不为过。 \n对公司而言，通常有三种途径可以产生大量现金。首先，他可以向公众发\n行出售新的债券或股票，所融的的资金在使用之前会形成大量的库存现金；其次，\n公司也可以通过出售部分现有业务或其他资产，出售所获得的资金在公司发现其\n用途之前也会带来大量的库存现金；最后，也可能是公司一直保持着运营收益的\n现金流入大于运营成本的现金流出。正是这种通过持续经营的方式带来大量的现\n金积累的公司才能引起巴菲特的兴趣，这类公司往往具有某种对其有利的持续性\n竞争优势。 \n当巴菲特所关注的公司在短期内面临经营问题时（那些短视的华尔街投资','2026-07-05 16:55:53.049000',0,2073692323954429952,742,2073692323514028032),(2073692328438140944,'金积累的公司才能引起巴菲特的兴趣，这类公司往往具有某种对其有利的持续性\n竞争优势。 \n当巴菲特所关注的公司在短期内面临经营问题时（那些短视的华尔街投资\n者会因此抛售公司股票，从而压低股价），巴菲特会查看公司的现金或有价证券\n总额，由此来判断公司是否具有足够的的财务实力去解决当前的经营困境。 \n因此有这样一条规率：如果我们看到一家公司持有大量现金和有价证券，\n并且几乎没有什么债务的话，那么很可能，这家公司能顺利度过这个黑暗的困难\n时期。但如果这家公司现金紧缺，并且背负着一大堆的债务，那么很可能这家公\n司会倒闭，再有能耐的经历恐怕也救不了它。 \n想弄清公司所有现金的来源，最简单的方法就是查看其过去七年的资产负\n债表。这将给我们届时公司库存现金是由偶然性事件产生（如发行发售新债券或\n股票，或售出公司一项资产或业务），还是有公司持续盈利产生的。如果公司负','2026-07-05 16:55:53.049000',0,2073692323954429952,743,2073692323514028032),(2073692328438140945,'债表。这将给我们届时公司库存现金是由偶然性事件产生（如发行发售新债券或\n股票，或售出公司一项资产或业务），还是有公司持续盈利产生的。如果公司负\n债过多，那么可能不是一家杰出的公司。但如果我们看到大量的库存现金，而几\n乎没没有什么债务，并且没有出售股份或者资产，同时公司过去一直保持盈利的\n话，那么，我们就可以找到一家具有持续性竞争优势的优质公司——巴菲特一直\n追寻的，能让我们长期致富的公司。 \n我们不能忘，当困难来临时“现金为王”，所以，这时如果我们的竞争对手\n没有现金，而我们持有大量现金，那么我们才能步入正轨。步入正轨才能笑到最\n后。 \n \n \n第 25 章  存货：公司需采购的原料和公司需出售的产品 \n \n资产负债表／资产项目  （单位：百万美元） \n现金和短期投资 ４２０８ \n→存货合计 ２２２０ \n应收账款合计 ３３１７ \n预付账款 ２２６０ \n其他流动资产合计 ０ ','2026-07-05 16:55:53.049000',0,2073692323954429952,744,2073692323514028032),(2073692328438140946,'现金和短期投资 ４２０８ \n→存货合计 ２２２０ \n应收账款合计 ３３１７ \n预付账款 ２２６０ \n其他流动资产合计 ０ \n流动资产合计 １２００５ \n存货是公司库存待销售给采购商的产品。因为资产负债表是在某一特定日\n期定制，所以该表上所记录的存活数额就是公司在那天的存货价值。 \n很多公司都存在存货过期作废的风险。但我们之前讨论过，具有持续性竞\n争优势的制造类公司，其销售产品有不变的优势，因此其产品绝不会过时作废。\n这是巴菲特想寻找的一种优势。 \n当我们试图识别一家制造类公司是否具有某种持续性竞争优势时，应查看\n其存货和净利润是否有相应增长。如果答案是肯定的，则意味着该公司能找到一\n种有利可图的方式，从而增加销售，这必然会导致存货相应增加，以满足源源不\n断的订单。 \n存活在某些年份迅速增加，而其后又迅速减少的制造类公司，很可能处于','2026-07-05 16:55:53.049000',0,2073692323954429952,745,2073692323514028032),(2073692328438140947,'种有利可图的方式，从而增加销售，这必然会导致存货相应增加，以满足源源不\n断的订单。 \n存活在某些年份迅速增加，而其后又迅速减少的制造类公司，很可能处于\n高度竞争、时而繁荣、时而衰退的行业，其中没有一家公司能让人变得富有。 \n \n \n第２６章 应收账款净值：别人欠公司的钱 \n \n资产负债表／资产项目（单位：百万美元） \n现金和短期投资 ４２０８ \n存货合计 ２２２０ \n→应收账款合计（净值） ３３１７ \n预付账款 ２２６０ \n其他流动资产合计 ０ \n流动资产合计 １２００５ \n当公司出售其产品给购买者时，购买者有两种基本付款方式，要么货到付\n款，要么等收到货物后延期３０天支付，有些公司可能需要更久的时间才能支付\n现金。产品销售处于这种现金延期支付的状态时，叫做应收账款。这是采购商欠\n公司的钱。因为有一定比例的采购商可能赖账不付，所以必须估算出一定数量的','2026-07-05 16:55:53.049000',0,2073692323954429952,746,2073692323514028032),(2073692328438140948,'现金。产品销售处于这种现金延期支付的状态时，叫做应收账款。这是采购商欠\n公司的钱。因为有一定比例的采购商可能赖账不付，所以必须估算出一定数量的\n坏账，并从应收账款中扣除，得到的就是应收账款的净值。 \n应收账款减去坏账等于应收账款的净值。 \n单独的应收账款净值指标并不能告诉我们多少关于公司长期竞争优势的信\n息。但是，将其对比同行业的其他公司，从这一指标上，我们能得知很多信息。\n在激烈竞争的行业，有些公司试图通过提供更有利的支付方式来获取竞争优势\n（公司可以给采购商或承销商１２０天的付款期限）。而这导致销售额增加的同\n时，应收账款也随之增加。 \n如果一家公司持续显示出比其他竞争对手更低的应收账款占总销售额的比\n率，那么很可能具有某种相对竞争优势。 \n \n \n第２７章 预付账款和其他流动资产 \n \n资产负债表／资产项目（单位：百万美元） \n现金和短期投资 ４２０８ \n存货合计 ２２２０ ','2026-07-05 16:55:53.049000',0,2073692323954429952,747,2073692323514028032),(2073692328438140949,' \n \n第２７章 预付账款和其他流动资产 \n \n资产负债表／资产项目（单位：百万美元） \n现金和短期投资 ４２０８ \n存货合计 ２２２０ \n应收账款合计（净值） ３３１７ \n→预付账款 ２２６０ \n→其他流动资产合计 ０ \n流动资产合计 １２００５ \n公司有时候会先支付他们在不远将来才能收到的商品或服务，尽管当时他\n们还没有货的商品的所有权，或未享受该服务带来的利益。即使公司还没有收到\n这些商品或服务，然而，一旦支付款项后，它就变成公司的资产。公司将其记录\n到流动资产下面的预付账款账户里。比如，为来年实现与之保险费就是预付账款\n的一个典型例子。预付账款能提供给我们有关公司经营状况方面的信息很少，也\n不能帮助我们判断公司是否获益于持续性竞争的优势。 \n其他流动资产指那些将在一年内到期；但公司还未持有的非现金资产。这\n类资产包括递延所得税回收，这项资产可在一年内收回，但目前未能转化为手中','2026-07-05 16:55:53.049000',0,2073692323954429952,748,2073692323514028032),(2073692328442335232,'其他流动资产指那些将在一年内到期；但公司还未持有的非现金资产。这\n类资产包括递延所得税回收，这项资产可在一年内收回，但目前未能转化为手中\n的现金。 \n \n \n第 28 章  流动资产合计和流动比率 \n资产负债表/资产项目（单位：百万美元） \n现金和短期投资 4208 \n存货合计 2220 \n应收账款合计（净值） 3317 \n预付账款 2260 \n其他流动资产合计 0 \n流动资产合计 12005 \n在财务分析中，流动资产合计一直扮演着举足轻重的作用。分析师们通常认\n为，将公司的流动资产减去它的流动负债所得到的结余能告知他们该公司是否有\n能力偿还短期负债。他们建立了流动比率这一指标，它等于流动资产除以流动负\n债。流动比率越高，公司的流动性越好。流动比率大于 1被认为是好现象，流动\n比率小于 1则被认为是坏现象，因为，小于 1 的流动比率说明公司可能在偿还短\n期债务方面存在一定困难。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,749,2073692323514028032),(2073692328442335233,'比率小于 1则被认为是坏现象，因为，小于 1 的流动比率说明公司可能在偿还短\n期债务方面存在一定困难。 \n有趣的是，对于很多具有持续性竞争优势的公司来说，其流动比率常常低于\n这个神奇的分水岭数字 1。穆迪公司的流动比率为 0.64 ，可口可乐公司的流动\n比率为0.95，宝洁公司的流动比率为0.82，安海斯-布什公司的流动比率为0.88。\n按那些守旧派分析师的观点，这意味着它们将面临偿还短期流动债务的困难。而\n实际上，它们的盈利能力足够强劲，能够轻松自如的偿还流动负债。并且，因为\n它们具有优异的盈利能力，如果需要额外的短期现金，这些公司可以毫无障碍地\n进入短期商业票据市场进行融资。 \n凭借强大的盈利能力，它们还可以向股东派发丰厚的红利或者进行股票回\n购，这两种情况都会减少现金储备，从而使它们的流动比率小于 1。然而，也正','2026-07-05 16:55:53.049000',0,2073692323954429952,750,2073692323514028032),(2073692328442335234,'凭借强大的盈利能力，它们还可以向股东派发丰厚的红利或者进行股票回\n购，这两种情况都会减少现金储备，从而使它们的流动比率小于 1。然而，也正\n是他们的持续盈利能力(由于具有某种持续性竞争优势)，才能确保它们有能力偿\n还其短期流动债务，不至于沦为变化无常的商业周期和经济衰退的牺牲品。 \n简而言之，很多具有持续性竞争优势的公司，其流动比率都小于 1，不同于\n传统的流动比率指标评判标准。因此，我们在判断一家公司是否具有持续性竞争\n优势时，流动比率指标会显得毫无用处。 \n \n \n第 29 章  房产、厂房和机器设备：对巴菲特来说越少越好 \n \n资产负债项目/资产项目 \n流动资产合计 12005 \n房产/厂房/机器设备 8493 \n商誉（净值） 4246 \n无形资产（净值） 7863 \n长期资产 7777 \n其他长期资产 2675 \n其他资产 0 \n资产合计 43059 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,751,2073692323514028032),(2073692328442335235,'商誉（净值） 4246 \n无形资产（净值） 7863 \n长期资产 7777 \n其他长期资产 2675 \n其他资产 0 \n资产合计 43059 \n \n公司的房产、生产厂房和机械设备的总价值在资产负债表上显示为一项资\n产。它们是以其初始购置成本减去累计折旧后的价值记录。折旧是在厂房和设备\n不断损耗过程中累计产生的。每年，这部分消耗的价值必须从厂房和设备中计提\n出来。 \n那些不具备长期竞争优势的公司可能时刻面临着竞争，这意味着它们往往不\n得不在其生产设备报废之前不断地进行更新，以保持其竞争力。这必然会产生一\n种持续的隐形开支，使公司资产负债表上的厂房和设备的价值数额一直在增长。 \n一家具有持续竞争优势的公司无需不断更新其厂房和设备以保持竞争力。已\n著名的口香糖生产商箭牌公司为例，如果它建造一间用于建造口香糖的厂房，以\n这间厂房和其中设备报废毁损之前，它不需要更新其厂房和设备。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,752,2073692323514028032),(2073692328442335236,'著名的口香糖生产商箭牌公司为例，如果它建造一间用于建造口香糖的厂房，以\n这间厂房和其中设备报废毁损之前，它不需要更新其厂房和设备。 \n所以具有持续竞争优势的公司一般在厂房和设备报废时才进行更新，而那些\n不具备持续竞争优势的公司为了在竞争中不至于落后，不得不经常更新其厂房和\n设备。 \n一家具有持续竞争优势的公司完全有能力使用其内部资金去购买新厂房和\n设备，但是一家没有持续竞争优势的公司为了保持相对于同行的竞争力，可能被\n迫举债，去满足不断更新设备而产生的资金需求。 \n我们仍然以具有长期竞争优势的箭牌公司为例，它可以充分证明以上论断。\n箭牌公司的厂房和设备总价值为 14 亿美元，其负担的债务有 10 亿美元，但它每\n年却赚取大概 5亿美元的利润。相对于箭牌公司，没有持续竞争优势的通用汽车\n厂房和设备价值达 560 亿美元，负担的债务 400 亿美元，该公司在过去两年中财\n务状况均为亏损状态。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,753,2073692323514028032),(2073692328442335237,'厂房和设备价值达 560 亿美元，负担的债务 400 亿美元，该公司在过去两年中财\n务状况均为亏损状态。 \n口香糖不是一种经常需要更新的产品，而且箭牌公司的品牌确保了它在行业\n内的相对竞争优势。但是，通用汽车公司必须面临全球汽车制造商的激烈竞争，\n其产品组合必须不断进行升级和重新设计，才能保持在竞争中的领先地位。这意\n味着通用汽车公司的生产线需要不断地进行重新改装配置，以确保生产新款产品\n满足消费者的需求。 \n对于这两家公司的股东来说，生产口香糖相比起制造汽车更好、盈利更多。\n设想一下：早在 1990 年投资 10 万美元在箭牌公司，到 2008 年，其价值能达到\n大约 54.7 万美元。但如果同年投资 10 万美元于通用汽车公司的话，到 2008 年，\n其价值仅为 9.7 万美元。也就是说，箭牌公司的股东比通用汽车的股东多获取了','2026-07-05 16:55:53.049000',0,2073692323954429952,754,2073692323514028032),(2073692328442335238,'其价值仅为 9.7 万美元。也就是说，箭牌公司的股东比通用汽车的股东多获取了\n46 万美元的收益。他们愉悦地享受着箭牌公司给其带来的丰厚收益，并由此发\n财致富，而通用汽车公司的股东则不得不面对财富日益蒸发的风险。 \n如巴菲特所说，生产那些不需要经营更新设备和厂房的“持续性产品”就能\n赚取持续的利润。“持续性产品”是指无需为保持竞争力而耗费巨额资金去更新\n厂房和设备的产品，这样能节约出大量的资金用于其他有利可图的投资。想要发\n财致富，首先我们必须赚钱，赚钱越多当然越好。有一种方式能让你赚更多的钱，\n那就是：经营那些无需花费大量资金用于产品更新的生意。 \n \n \n第 30 章  商誉 \n \n资产负债表/资产项目（单位：百万项目） \n流动资产合计 12006 \n房产/厂房/机器设备 8493 \n商誉（净值） 4245 \n无形资产（净值） 7863 \n长期投资 7777 \n其他长期资产 2675 ','2026-07-05 16:55:53.049000',0,2073692323954429952,755,2073692323514028032),(2073692328442335239,'房产/厂房/机器设备 8493 \n商誉（净值） 4245 \n无形资产（净值） 7863 \n长期投资 7777 \n其他长期资产 2675 \n资产合计 43090 \n \n当埃克森美孚石油公司收购 XYZ 石油公司时，它支付的购买价格超过 XYZ\n公司的账面价值，这超出的部分在埃克森美孚石油公司的资产负债表上就体现为\n商誉。如果我们的购买价格超过被收购公司的账面价值，这样的收购越多，我们\n资产负债表上所体现的商誉数额就越大。 \n以前，商誉一般从公司的利润中逐渐勾销，也就是说，商誉有一个摊销的过\n程，这导致损益表上增加了一项商誉摊销开支，净利润也会由此而减少。现阶段，\n美国财务会计准则委员会决定，除非商誉附属的公司确实存在价值贬值，否则商\n誉不需要进行摊销处理。 \n只要看到公司的商誉连续几年都在增加，我们就可以断定这家公司在不断地','2026-07-05 16:55:53.049000',0,2073692323954429952,756,2073692323514028032),(2073692328442335240,'誉不需要进行摊销处理。 \n只要看到公司的商誉连续几年都在增加，我们就可以断定这家公司在不断地\n并购其他公司。如果公司所并购的企业也具有持续竞争优势的话，那将是锦上添\n花。如果一家公司的商誉账户每年都保持不变，那要么是因为公司以低于账面价\n值的价格并购其他公司，要么就是公司在这期间内没有任何并购行为。 \n那些得益于某种持续性竞争优势的公司基本上不会以低于其账面价值的价\n格出售。当然，也不排除偶尔会有这种情况发生，倘若确有其事，那是一次终生\n难得的买入的好机会。 \n \n \n第 31 章  无形资产：衡量不可测量的资产 \n \n资产负债表/资产项目（单位：百万美元） \n流动资产合计 12005 \n房产/厂房/机器设备 8493 \n商誉（净值） 4246 \n无形资产（净值） 7863 \n长期投资 7777 \n其他长期资产 2675 \n资产合计 43059 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,757,2073692323514028032),(2073692328442335241,'商誉（净值） 4246 \n无形资产（净值） 7863 \n长期投资 7777 \n其他长期资产 2675 \n资产合计 43059 \n \n无形资产是那些我们无法用身体感受的资产，它们包括专利权、版权、商标\n权、专营权、品牌等。很久以前，一家公司可以随时对其无形资产进行估值，因\n此，产生了不少荒诞可笑的无形资产估值和大量无形资产价值被滥估的现象。而\n现在，公司不允许将内部形成的无形资产计入其资产负债表，从而结束了用浮夸\n的无形资产估值“包装”资产负债表的公司行为。 \n但是由第三方收购所产生的无形资产应以合理的价值计入公司的资产负债\n表。如果一项资产有使用期限，例如专利权，它将在其使用期限内进行摊销，每\n年分摊一定费用，并计入当期损益表和资产负债表。 \n这样一来，那些得益于持续性竞争优势的公司发生了意见奇怪的事情。拿可\n口可乐公司来说，该公司的品牌价值超过 1000 亿美元，但由于这只是公司内部','2026-07-05 16:55:53.049000',0,2073692323954429952,758,2073692323514028032),(2073692328442335242,'这样一来，那些得益于持续性竞争优势的公司发生了意见奇怪的事情。拿可\n口可乐公司来说，该公司的品牌价值超过 1000 亿美元，但由于这只是公司内部\n形成的品牌，它作为无形资产的真实价值并不能反映在公司的资产负债表上，同\n样的事发生在箭牌、百事、麦当劳，甚至是沃尔玛这些公司身上。这些公司都受\n益于由其品牌带来的持续性竞争优势，但是，尽管它们的无形资产价值非常巨大，\n却并没有反映在其资产负债表上。 \n这就是为什么持续性竞争优势能给股东带来财富，但长久以来却一直未被大\n众投资者所发现的原因之一。不善于比较公司过去 10 年的损益表，不深入分析\n其资产负债表反映的真实价值，大众投资者永远不知道财富在哪儿，也不会发现\n其潜在的致富能力。这也是为什么巴菲特能够在其他人还坐观其变的时候，却大\n量吃进像可口可乐这类公司股票的原因。而此时，整个世界并不明白他为什么要','2026-07-05 16:55:53.049000',0,2073692323954429952,759,2073692323514028032),(2073692328442335243,'其潜在的致富能力。这也是为什么巴菲特能够在其他人还坐观其变的时候，却大\n量吃进像可口可乐这类公司股票的原因。而此时，整个世界并不明白他为什么要\n这么做。可口可乐公司高昂的股价使那些追随格雷厄姆的价值投资者对其并不感\n兴趣，同时，其股价也不具备足够的波动性去吸引那些华尔街的投机者。尽管如\n此，巴菲特却能发现其他人所不能发现的秘密，那就是可口可乐的持续性竞争优\n势以及由此产生的长期盈利能力。有朝一日，可口可乐公司的盈利能力将帮助他\n成为这个世界最富有的人。 \n \n \n第 32 章  长期投资：巴菲特成功的秘密之一 \n \n资产负债表/资产项目  (单位：百万美元) \n流动资产合计                     12 005 \n \n房产/厂房/机器设备                 8 493 \n商誉(净值)                         4 246 ','2026-07-05 16:55:53.049000',0,2073692323954429952,760,2073692323514028032),(2073692328442335244,' \n房产/厂房/机器设备                 8 493 \n商誉(净值)                         4 246 \n无形资产(净值)                     7 863 \n→长期投资                          7 777 \n  其他长期资产                      2 675 \n  资产合计                         43 059 \n   \n长期投资属于公司资产负债表上的一项资产，该账户记录了公司的全部长期\n投资（一年期以上），如股票、债券和房地产投资的价值。它还包括公司对附属\n子公司和分支机构的投资。关于长期投资账户，有意思的地方在于，这项资产的\n入账价值为该项投资的成本价值或者市场价值，哪个价值更低，资产负债表上就','2026-07-05 16:55:53.049000',0,2073692323954429952,761,2073692323514028032),(2073692328442335245,'子公司和分支机构的投资。关于长期投资账户，有意思的地方在于，这项资产的\n入账价值为该项投资的成本价值或者市场价值，哪个价值更低，资产负债表上就\n记录哪个价值。因此，即使这项投资价值发生大幅增值，也不能以高于成本的价\n格入账。这意味着，一家公司有些价值不菲的资产，其入账价值可能远远低于其\n实际的市场价格。 \n一个公司的长期投资情况可以反映出很多关于公司管理高层投资心态的信\n息。他们投资的是那些具有持续性竞争优势的公司，还是处于那些高度竞争行业\n的公司？有时候，我们看到一些优质公司的管理层花费巨额资金投资于那些平庸\n的公司，仅仅是因为他们觉得大规模公司就是最好的。有时我们也能看到一些平\n庸公司的开明经理投资于那些具有持续性竞争优势的公司。这就是为什么巴菲特\n能将他控股的伯克希尔·哈撒韦公司发展到如今的投资领域帝王地位的原因。伯','2026-07-05 16:55:53.049000',0,2073692323954429952,762,2073692323514028032),(2073692328442335246,'庸公司的开明经理投资于那些具有持续性竞争优势的公司。这就是为什么巴菲特\n能将他控股的伯克希尔·哈撒韦公司发展到如今的投资领域帝王地位的原因。伯\n克希尔曾经只是在高度竞争的纺织业中一家平庸的企业。巴菲特买入其控股权\n后，暂停了分红并累积现金，然后将公司的运营资本投资买入了一家保险公司。\n四十多年间，他用这家保险公司的资产不停地疯狂购买诸多具有持续性竞争优势\n的公司。 \n就像白雪公主亲吻青蛙一般，以持续性竞争优势亲吻一家像青蛙般平庸的公\n司，只要亲吻次数足够多，它最终会变成像王子一样尊贵的公司。或许，就拿巴\n菲特的投资实例来说，他持有的伯克希尔公司，其股票价值如今高达 600 亿美元。 \n \n \n第 33 章  其他长期资产 \n \n资产负债表/资产项目  (单位：百万美元) \n流动资产合计                     12 005 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,763,2073692323514028032),(2073692328442335247,' \n第 33 章  其他长期资产 \n \n资产负债表/资产项目  (单位：百万美元) \n流动资产合计                     12 005 \n \n房产/厂房/机器设备                 8 493 \n商誉(净值)                         4 246 \n无形资产(净值)                     7 863 \n长期投资                          7 777 \n→其他长期资产                      2 675 \n  资产合计                         43 059 \n可以把“其他长期资产”看成是那些没有归入房屋设备、商誉、无形资产和\n长期投资账户的长期资产（生命周期超过一年的资产）的集合。待摊费用就属于\n其他长期资产。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,764,2073692323514028032),(2073692328442335248,'可以把“其他长期资产”看成是那些没有归入房屋设备、商誉、无形资产和\n长期投资账户的长期资产（生命周期超过一年的资产）的集合。待摊费用就属于\n其他长期资产。 \n其他长期资产在判断公司是否具有持续性竞争优势方面所提供的信息不多，\n所以，请大家直接翻到下一章吧。 \n \n \n第 34 章  总资产和总资产回报 \n \n资产负债表/资产项目  (单位：百万美元) \n流动资产合计                     12 005 \n房产/厂房/机器设备                 8 493 \n商誉(净值)                         4 246 \n无形资产(净值)                     7 863 \n长期投资                          7 777 \n其他长期资产                      2 675 ','2026-07-05 16:55:53.049000',0,2073692323954429952,765,2073692323514028032),(2073692328442335249,'长期投资                          7 777 \n其他长期资产                      2 675 \n→资产合计                         43 059 \n将流动资产和长期资产相加，我们就能得到这个公司的总资产。公司的总资\n产等于它的总负债加上股东权益。他们之间是相互平衡的，因此，资产负债表也\n被称为平衡表。 \n在判断公司的资产使用效率方面，总资产是十分重要的。为了衡量公司效率，\n分析师们创建出资产回报率这个指标，它等于净利润除以总资产。 \n然而，资本通常是进入一个行业的屏障，因此，行业进入所需的资产成本是\n帮助公司维持竞争优势的保证之一。可可可乐公司总资产为 430 亿美元，其资产\n回报率为 12%；宝洁公司总资产高达 1 430 亿美元，而其资产回报率为 7%；奥','2026-07-05 16:55:53.049000',0,2073692323954429952,766,2073692323514028032),(2073692328442335250,'回报率为 12%；宝洁公司总资产高达 1 430 亿美元，而其资产回报率为 7%；奥\n驰亚集团股份有限公司的 520 亿美元总资产能带来 24%的资产回报率。但穆迪公\n司总资产只有 17 亿美元，其资产回报率却高达 43%。 \n大多数分析师认为资产回报率越高越好，但巴菲特却发现，过高的资产回报\n率可能暗示着这个公司的竞争优势在持续性方面是脆弱的。拿 430 亿美元去撼动\n可可可乐的地位几乎是不可能完成的任务，而且这根本不可能发生。但是拿 17\n亿美元去与穆迪公司抗衡则完全有实现的可能。尽管穆迪公司相比可可可乐公司\n有更好的盈利能力，但穆迪公司的竞争优势在持续性方面相对较弱，因为进入该\n行业的相对成本较低。 \n从这里我们得知，有时候现在的多往意味着将来的少。 \n \n \n第 35 章  流动负债 \n \n资产负债表/负债项目  (单位：百万美元) ','2026-07-05 16:55:53.049000',0,2073692323954429952,767,2073692323514028032),(2073692328442335251,'行业的相对成本较低。 \n从这里我们得知，有时候现在的多往意味着将来的少。 \n \n \n第 35 章  流动负债 \n \n资产负债表/负债项目  (单位：百万美元) \n应付账款                          1 380 \n预提费用                          5 535 \n短期贷款                          5 919 \n一年内到期的长期贷款               133 \n其他流动负债                       258 \n流动负债合计                     13 225 \n流动负债指公司在当期会计年度到期应该偿还的债务或应履行的义务。它们\n在资产负债表上体现为应付账款、预提费用、短期贷款、一年内到期的长期贷款\n和其他流动负债。接下来，让我们对这些账户逐一进行分析，看它们是否能提供','2026-07-05 16:55:53.049000',0,2073692323954429952,768,2073692323514028032),(2073692328442335252,'在资产负债表上体现为应付账款、预提费用、短期贷款、一年内到期的长期贷款\n和其他流动负债。接下来，让我们对这些账户逐一进行分析，看它们是否能提供\n一些信息，以便帮助我们判断公司是否具有某种持续性的相对竞争优势。 \n \n \n第 36 章  应付账款、预提费用和其他流动负债 \n \n资产负债表/负债项目  (单位：百万美元) \n→应付账款                          1 380 \n→预提费用                          5 535 \n短期贷款                          5 919 \n一年内到期的长期贷款               133 \n→其他流动负债                       258 \n流动负债合计                     13 225 ','2026-07-05 16:55:53.049000',0,2073692323954429952,769,2073692323514028032),(2073692328446529536,'→其他流动负债                       258 \n流动负债合计                     13 225 \n应付账款指公司以赊销的方式购买材料、商品或接受劳务供应等发生的债\n务。我们预定了 1 000 磅咖啡，供应商将 1 000 磅咖啡连同这笔贷款的发票一起\n给我们。这 1 000 磅咖啡贷款的发票就是一项应付账款。 \n预提费用指已经发生但还没有支付的负债。这些费用包括应缴营业税、应付\n工资和计提的应付租金。我们雇用了某人，并告诉他我们会在月底发薪水，到月\n底结算公司前，我们该付给他的工作报酬就是预提费用。 \n其他流动负债指未纳入上述流动负债的所有短期负债的集合。 \n应付账款、预提费用和其他流动负债能告诉我们很多关于公司当期营业状况\n的信息，但单个账户能给我们提供的关于公司长期经营状况的信息有限，不足以','2026-07-05 16:55:53.049000',0,2073692323954429952,770,2073692323514028032),(2073692328446529537,'应付账款、预提费用和其他流动负债能告诉我们很多关于公司当期营业状况\n的信息，但单个账户能给我们提供的关于公司长期经营状况的信息有限，不足以\n判断公司是否具有持续性竞争优势。然而，一个公司负担的短期贷款和长期贷款\n数额能反映很多关于公司长期经营状况的信息，并能由此判断这家公司是否具有\n持续性竞争优势。 \n \n \n第 38 章  一年内到期的长期贷款及其可能带来的影响 \n \n          资产负债表/负债项目（单位：百万美元） \n应付账款                   1 380 \n预提费用                         5 535 \n短期贷款                         5 919 \n一年内到期的长期贷款               133 \n其他流动负债                       258 ','2026-07-05 16:55:53.049000',0,2073692323954429952,771,2073692323514028032),(2073692328446529538,'一年内到期的长期贷款               133 \n其他流动负债                       258 \n流动负债合计                    13 225 \n \n这一章我们将关注长期贷款，它是一年内即将到期的、必须偿还的债务。对\n大多数公司而言，长期贷款并不是一项流动负债。但一些大型公司会把部分即将\n到期的长期贷款计人到当年的流动负债。这样的做法会产生一些问题，人们误认\n为公司的短期贷款负担过重，但实际上并非如此。 \n通常来说，那些具有持续性竞争优势的公司不怎么需要，甚至完全不需要长\n期贷款去维持起公司经营，因此，它们基本上很少有到期的长期贷款。所以，当\n我们看到一家公司负担着大量即将到期的长期贷款时，它可能不是一家具有持续\n性竞争优势的公司。 \n每当我们打算买人一家具有持续性竞争优势，但因某些偶然性事件(例如公','2026-07-05 16:55:53.049000',0,2073692323954429952,772,2073692323514028032),(2073692328446529539,'我们看到一家公司负担着大量即将到期的长期贷款时，它可能不是一家具有持续\n性竞争优势的公司。 \n每当我们打算买人一家具有持续性竞争优势，但因某些偶然性事件(例如公\n司在其他行业的附属子公司需要现金补给)正处于困境时期的公司时，我们最好\n查看一下公司到底有多少长期贷款在明年即将到期。仅仅是单独一年的过多到期\n债务可能会令众多投资者感到不 \n安，这样就会留给我们一个绝佳的购买时机。 \n对于一家陷入严重困境的平庸公司来说，过多的到期债务可能会导致现金流\n中断，这必定会导致破产，对投资者而言，这也意味着失败。 \n拥有一项垂死挣扎的投资是不会让我们发财致富的。 \n \n \n第 39 章  负债合计和流动比率 \n \n资产负债表／负债项目（单位：百万单位） \n应付账款                   1 380 \n预提费用                         5 535 ','2026-07-05 16:55:53.049000',0,2073692323954429952,773,2073692323514028032),(2073692328446529540,'应付账款                   1 380 \n预提费用                         5 535 \n短期贷款                         5 919 \n一年内到期的长期贷款               133 \n其他流动负债                       258 \n流动负债合计                    13 225 \n \n将流动资产除以总负债，我们可以确定公司的流动性——流动率越高，公\n司流动性就越高，因此它偿还大气流动负债的能力就越强。一个公司的流动比\n率大于 1 被认为运营良好，小于 1则说明情况糟糕。如果流动比率小于 1，该\n公司可能会陷入偿还债权人短期负债的困境。但是，就像我们在第 2 8 章所讨\n论的那样, 那 些 具 \n持续性竞争优势的公司，其流动比率通常都小于 1。公司的持续性竞争优势所','2026-07-05 16:55:53.049000',0,2073692323954429952,774,2073692323514028032),(2073692328446529541,'论的那样, 那 些 具 \n持续性竞争优势的公司，其流动比率通常都小于 1。公司的持续性竞争优势所\n产生的巨大盈利能力是导致这一异常现象的原因。简而言之，这些公司可以保\n持当前的良好经营状况，所以不需要像平庸公司那样需要流动性来保护。(如果\n需要更深入的分析，请重温第 28 章)确定那些处于平均水平公司的流动性和流\n动比率至关重要，但是它在帮我们判断一个公司是否具有某种持续性竞争优势\n方面几乎没什么作用。 \n \n \n第 40 章  长期贷款：优秀公司很少有的东西 \n \n资产负债表／负债项目（单位：百万单位） \n流动负债合计                   13 225 \n长期贷款                        3 277 \n递延所得税                      1 890 \n少数股东权益                        0 ','2026-07-05 16:55:53.049000',0,2073692323954429952,775,2073692323514028032),(2073692328446529542,'递延所得税                      1 890 \n少数股东权益                        0 \n其他长期负债                    3 133 \n负债合计                       21 525 \n长期贷款是指那些一年以上才到期的债务，它被列在资产负债表中的长期负\n债项目下。如果这笔债务在一年内到期，那它将被视为短期借款并放在流动负债\n账户下。巴菲特在寻求具有长期竞争优势的杰出公司过程中，公司账簿上所记录\n的长期贷款能告知他很多关于该公司的经济状况信息。 \n巴菲特发现，那些具有持续性竞争优势的通常负担很少的长期贷款，或者压\n根儿就没有长期贷款。这是因为这些公司具有超强的盈利能力，当需要扩大生产\n规模或进行企业并购时，它们完全有能力自 \n我融资，所以它们完全没有必要大量举债。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,776,2073692323514028032),(2073692328446529543,'根儿就没有长期贷款。这是因为这些公司具有超强的盈利能力，当需要扩大生产\n规模或进行企业并购时，它们完全有能力自 \n我融资，所以它们完全没有必要大量举债。 \n有一种方法可以帮我们辨识那些优秀公司，就是查看其资产负债 \n表，看它负担多少长期贷款。我们不仅要关注当年的数据，还要查看 \n过去 10 年来公司的长期负债情况。如果资产负债表反映出该公司在 \n过去 10 年中一直保持少量甚至没有长期贷款，那么这个公司很可能 \n具有某种有利的强大竞争优势。 \n巴菲特的投资实例表明，在任何一年，公司都应该有充足的盈余在 3～4 年\n间偿还所有长期债务。具有长期竞争优势的可口可乐公司和穆迪公司仅在一个年\n度内就能偿清所有的长期贷款，箭牌公司和华盛顿邮报公司用其两年的净利润就\n可以偿还全部的长期贷款。 \n但像通用汽车和福特汽车这样处于高度竞争汽车行业的公司，就是花光它们','2026-07-05 16:55:53.049000',0,2073692323954429952,777,2073692323514028032),(2073692328446529544,'可以偿还全部的长期贷款。 \n但像通用汽车和福特汽车这样处于高度竞争汽车行业的公司，就是花光它们\n在过去 10 年所赚取的全部净利润，也不能偿清资产负债表上那巨额的长期贷款。 \n我们在寻求具有持续性竞争优势的过程中，那些具有超强盈利利能力，能在\n3年或 4年内偿还全部长期贷款的公司都是很好的候选者，这是最起码的要求。 \n但请注意：因为这些公司具有如此强大的盈利能力，并只负担少 \n量的负债，甚至完全没有负债，它们经常成为杠杆式收购的目标。在 \n这个过程中，购买方凭借这些公司充裕的现金流借人大量资金以促成 \n收购。在完成杠杆式收购后，公司则背负着巨额债务。20 世纪 80 年代末的雷诺\n兹-纳贝斯克收购就是这方面的一个典型案例。 \n如果其他所有方面都表明这是一家具有持续性竞争优势的公司，但其债务负\n担较重的话，可能是由于杠杆式收购产生的。在这种情况下，公司的债券通常是','2026-07-05 16:55:53.049000',0,2073692323954429952,778,2073692323514028032),(2073692328446529545,'如果其他所有方面都表明这是一家具有持续性竞争优势的公司，但其债务负\n担较重的话，可能是由于杠杆式收购产生的。在这种情况下，公司的债券通常是\n个不错的投资选择，因为此时公司的全部盈利将被用于偿还债务，而不是用于公\n司发展。 \n一条简单的规律：少量或没有长期贷款通常意味着一项很好的长期投资。 \n \n \n第 41 章  递延所得税、少数股东权益和其他负债 \n \n资产负债表／负债项目（单位：百万单位） \n流动负债合计                   13 225 \n长期贷款                        3 277 \n递延所得税                      1 890 \n少数股东权益                        0 \n其他长期负债                    3 133 ','2026-07-05 16:55:53.049000',0,2073692323954429952,779,2073692323514028032),(2073692328446529546,'少数股东权益                        0 \n其他长期负债                    3 133 \n负债合计                       21 525 \n \n递延所得税指已到期但未支付的税款。这个数据能告诉我们有关公司是否具\n有持续性竞争优势的信息很少。 \n资产负债表上的少数股东权益非常有意思。当一个公司收购另一个公司的股\n份肘，收购这些股份所支付的款项将被计入“长期投资”账户。但当公司收购的\n股票份额超过被收购公司总资本 80%时，被 \n收购公司的资产负债表就可以合并在自己公司的资产负债表上，损益表也同样如\n此。举个例于：伯克希尔收购内布拉斯加家具超市 90%的股份。因为伯克希尔收\n购了内布拉斯加家具超市超过 80％的股份，所以伯克希尔可以将内布拉斯加家\n具超市 100％的利润计人自已的损益表上，同时，可将内布拉斯加家具超市 l00％','2026-07-05 16:55:53.049000',0,2073692323954429952,780,2073692323514028032),(2073692328446529547,'购了内布拉斯加家具超市超过 80％的股份，所以伯克希尔可以将内布拉斯加家\n具超市 100％的利润计人自已的损益表上，同时，可将内布拉斯加家具超市 l00％\n的资产和负债增加到自身的资产负债表上。少数股东权益账户代表的就是那不为\n伯克希尔所有的内布拉斯加家具超市 10％的股份价值。它作为一种负债，其目\n的是为了平衡资产负债表，因为伯克希尔记录了内布拉斯加家具超市 100％的资\n产和负债，尽管它只拥有其 90％的股份。这与判断一家公司是否具有持续性竞\n争优势有什么关系呢?没多少关系，但我们要清楚，在寻找具有持续性竞争优势\n公司的过程中，到底什么指标有用，什么指标没用。 \n  “其他负债”用于记录公司其他各种负债，包括公司非当期收益、税赋利息、\n未交罚款和各种衍生工具等。所有这些对我们寻找具有持续性竞争优势的公司均\n没有作用。 \n \n \n第 42 章  负债合计和债务股权比率 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,781,2073692323514028032),(2073692328446529548,'未交罚款和各种衍生工具等。所有这些对我们寻找具有持续性竞争优势的公司均\n没有作用。 \n \n \n第 42 章  负债合计和债务股权比率 \n \n资产负债表/债务股权比例 \n                                     （ 单位：百万美元） \n流动负债合计                       13 225  \n长期贷款                            3 277 \n递延所得税                          1 890 \n少数股东权益                            0 \n其他负债                            3 133 \n→负债合计                           21 525 \n负债合计是公司所有负债的总和。这是被用来计算债务股权比率的一个重要','2026-07-05 16:55:53.049000',0,2073692323954429952,782,2073692323514028032),(2073692328446529549,'→负债合计                           21 525 \n负债合计是公司所有负债的总和。这是被用来计算债务股权比率的一个重要\n数据，而对债务股权比率稍微加以修改，可以用来帮我们判断一家公司是否具有\n持续性竞争优势。 \n债务股权比率曾经一度被用于帮助我们判断一家公司是以债务融资还是以\n股权（包括留存收益）融资为主。具有持续性竞争优势的公司一般会利用其盈利\n作为运作资金，因此从理论上讲，它们的股东权益较高，总债务较低。而那些没\n有持续性竞争优势的公司一般得靠债务为其提供运作资金，因此它们反而显示出\n较低的股东权益和较高的债务负担。 \n债务股权比率的计算公式为： \n                债务股权比率＝总负债÷股东权益 \n使用债务股权比率作为判断公司是否具有持续性竞争优势的依据，其为题在\n于：一些具有持续性竞争优势公司的经济实力是如此强大，以至于它们根本不必','2026-07-05 16:55:53.049000',0,2073692323954429952,783,2073692323514028032),(2073692328446529550,'使用债务股权比率作为判断公司是否具有持续性竞争优势的依据，其为题在\n于：一些具有持续性竞争优势公司的经济实力是如此强大，以至于它们根本不必\n使用大量的股东权益或留存收益就能提供公司正常的运作资金，有些公司甚至完\n全不需要这些收益。因为其强大的盈利能力，它们通常会将积累起来的股东权益\n和留存收益用于回购公司股票，这样会减少其股东权益或留存收益的总量。如此\n一来，公司的债务股权比率反而会增高，通常与那些没有持续性竞争优势的平庸\n公司具有相同的债务股权比率水平。 \n巴菲特偏好的穆迪公司就是很好的一个例证。它具有如此强大的经济运作能\n力，以至于它可以不需要保留任何股东权益。事实上，公司一直在将它所有的股\n东权益用于回购公司股票，公司账面上的股东权益居然还未负。如果仅仅从债务\n股权比率来看，它更像一家没有持续性竞争优势的公司（例如净资产为负的通用','2026-07-05 16:55:53.049000',0,2073692323954429952,784,2073692323514028032),(2073692328446529551,'东权益用于回购公司股票，公司账面上的股东权益居然还未负。如果仅仅从债务\n股权比率来看，它更像一家没有持续性竞争优势的公司（例如净资产为负的通用\n汽车），而不像具有持续性竞争优势的公司（例如可口可乐公司）。 \n \n \n然而，如果我们将穆迪公司所有的库存股票价值加回到其股东权益中，穆迪\n公司的债务股权比率将降至 0.63，与可口可乐公司库存股票调整后的债务股权比\n率（0.51）在同一水平。通用汽车公司即使加上其库存股票价值，其净资产仍然\n为负数，再说，通用汽车没有资金实力去回购公司股票，库存股票根本就不存在。 \n使用调整后的债务股权比率去区分具有持续性竞争优势的公司和那些没有\n持续性竞争优势的公司，就变得简单容易了。具有持续性竞争优势的宝洁公司，\n其库存股票调整后的债务股权比率为 0.71;箭牌公司调整后的债务股权比率为','2026-07-05 16:55:53.049000',0,2073692323954429952,785,2073692323514028032),(2073692328446529552,'持续性竞争优势的公司，就变得简单容易了。具有持续性竞争优势的宝洁公司，\n其库存股票调整后的债务股权比率为 0.71;箭牌公司调整后的债务股权比率为\n0.68——这意味着箭牌公司每 1 美元的股东权益负担着 68 美分的债务。相对于\n宝洁公司和箭牌公司，固特异轮胎公司调整后的债务股权比率为 4.35，而福特公\n司的比率更是高达 38.0 。这意味着福特公司每 1 美元的股东权益负担着 38 美元\n的债务——相当于 72 亿美元的股东权益负担 2750 亿美元的债务。 \n对金融机构，如银行来说，其平均债务股权比率要比同规模的制造类公司高\n的多。银行借入大量的资金，然后将它们全部贷出，贷出资金的利息收益和借入\n资金的利息成本之间的差价就是银行的利润来源。这将导致巨额负债，这些负债\n同时又被巨额资产所抵消。平均来讲，美国金融中心的大型银行每 1 美元的股东','2026-07-05 16:55:53.049000',0,2073692323954429952,786,2073692323514028032),(2073692328446529553,'资金的利息成本之间的差价就是银行的利润来源。这将导致巨额负债，这些负债\n同时又被巨额资产所抵消。平均来讲，美国金融中心的大型银行每 1 美元的股东\n权益大概对应着 10 美元的负债。巴菲特说银行是高度杠杆化运营公司，其实就\n是指这方面。当然也有个别例外，巴菲特一直看好的 M&T 银行就是其中之一。\nM&T 银行的债务股权比率只有 7.7，这反映出其管理高层偏于保守的贷款策略。 \n这里有个简单的规律，就是除非我们是在寻找金融机构，否则一旦我们看到\n一家公司调整后的债务股权比率低于 0.80（越低越好）的话，那很可能这家公司\n就是我们梦寐以求的、具有持续性竞争优势的公司。 \n能找到自己一直苦苦寻求的东西通常是件令人愉悦之事，特别是当你一直梦\n想成为富豪的时候。 \n \n \n第 43 章  股东权益/账面价值 \n \n                资产负债表/股东权益（单位：百万美元） ','2026-07-05 16:55:53.049000',0,2073692323954429952,787,2073692323514028032),(2073692328446529554,'想成为富豪的时候。 \n \n \n第 43 章  股东权益/账面价值 \n \n                资产负债表/股东权益（单位：百万美元） \n流动负债合计                     21 525 \n \n优先股                                0 \n普通股                              880 \n资本公积                           7 378 \n留存收益                          36 235 \n库存股票-普通                    -23 375 \n其他权益                             626 \n→股东权益合计                      21 774 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,788,2073692323514028032),(2073692328446529555,'其他权益                             626 \n→股东权益合计                      21 774 \n \n负债合计和股东权益                43 269 \n将你的资产减去你所有的负债，就能得到你的财富净值。同样的道理，将公\n司总负债从总资产中减去，也能得到公司净资产（也叫股东权益或公司的账面价\n值）。这是公司所有者或者股东初始投入并留在公司保持其运营的那部分资金。\n股东权益记录在股票资本的账户下，它包括优先股和普通股、资本公积和留存收\n益。将总负债和总股东权益合计相加得到的总和应该等于总资产，这就是为什么\n它叫资产负债平衡表的原因——两边永远保持平衡。 \n为什么股东权益对我们来说是一个非常重要的指标？因为通过它，我们能计\n算出股东权益报酬率，后者是我们判断公司是否具有对它有利的持续性竞争优势\n的方法之一。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,789,2073692323514028032),(2073692328446529556,'为什么股东权益对我们来说是一个非常重要的指标？因为通过它，我们能计\n算出股东权益报酬率，后者是我们判断公司是否具有对它有利的持续性竞争优势\n的方法之一。 \n接下来让我们深入详细地分析。 \n \n \n第 44 章  优先股、普通股和资本公积 \n \n             资产负债表/股东权益（单位：百万美元） \n→优先股                            0 \n→普通股                          880 \n→资本公积                      7 378 \n  留存收益                     36 235 \n  库存股票-普通               -23 375 \n  其他权益                        626 \n  股东权益合计                 21 774 ','2026-07-05 16:55:53.049000',0,2073692323954429952,790,2073692323514028032),(2073692328446529557,'  其他权益                        626 \n  股东权益合计                 21 774 \n一个公司可以通过向公众发行债券或股票来筹集新的资本。通过发行债券筹\n集的资金在将来的某一时间必须偿还，它是借来的资金。但是当公司通过向公众\n发行优先股或普通股筹集资金时，它永远不需要偿还。这些资金将永远为公司所\n有，可以任意使用它们。 \n普通股代表对公司的所有权。普通股持有者是公司的所有人，并拥有选举公\n司董事会的权力，而董事会按照规定聘请一名首席执行官来经营公司。如果董事\n会投票通过分红方案，普通股股东将获得相应的分红。如果整个公司被出售的话，\n普通股股东将得到这其中所有的利益。 \n股权的第二种类别叫优先股。优先股股东没有公司经营的投票表决权，但他\n们在普通股股东获得分红之前，就能获得固定或浮动的红利。此外，优先股股东','2026-07-05 16:55:53.049000',0,2073692323954429952,791,2073692323514028032),(2073692328446529558,'股权的第二种类别叫优先股。优先股股东没有公司经营的投票表决权，但他\n们在普通股股东获得分红之前，就能获得固定或浮动的红利。此外，优先股股东\n在公司陷入破产时，还拥有优先于普通股股东的追述权。 \n在次产负债表上，优先股和普通股均以其票面价值计入其相应账户。如果公\n司溢价发行（发行价股超过票面价值）股票，由此而多获得的资金将记录在资本\n公积账户里。例如，公司发行的优先股票面价值为每股 100 美元，而公司以每股\n120 美元的价格对公众发售的话，其每股 100 美元的价值将记录到优先股账户，\n而每股 20 美元的价值，则被记录到资本公积账户。 \n这同样适用于普通股，比如说其票面价值为每股 1 美元，如果公司以每股\n10 美元的价格向公众发售的话，那每股 1 美元的价值将记录在资产负债表上的\n普通股账户，而每股 9美元的价值将记录到资本公积账户。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,792,2073692323514028032),(2073692328446529559,'10 美元的价格向公众发售的话，那每股 1 美元的价值将记录在资产负债表上的\n普通股账户，而每股 9美元的价值将记录到资本公积账户。 \n关于优先股，奇怪的事情是，那些具有持续性竞争优势的公司基本上没有多\n少优先股。其中一个原因是它们基本上不需要任何债务。它们赚取的丰厚利润完\n全可以“自给自足”。尽管优先股是原始投入到公司，并且永远不需要偿还的资\n金，在会计表上表现为一项权益，但实际上它更像需要支付红利的负债。不同之\n处在于，为负债支付的利息可以从税前利润中扣除，而为优先股支付的红利是不\n能扣减税费的，这样就使得通过发行优先股筹集资金的成本比较昂贵。由于它是\n一种昂贵的筹资方式，如果可能的话，公司一般会选择避而远之。因此，当我们\n搜寻具有持续性竞争优势的公司时，一个重要的标志就是在公司的资本结构中找\n不到优先股的身影。 \n \n \n第 45 章  留存收益：巴菲特变得超级富有的秘密 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,793,2073692323514028032),(2073692328450723840,'搜寻具有持续性竞争优势的公司时，一个重要的标志就是在公司的资本结构中找\n不到优先股的身影。 \n \n \n第 45 章  留存收益：巴菲特变得超级富有的秘密 \n \n资产负债表/股东权益（单位：百万美元） \n优先股                           0 \n普通股                         880 \n资本公积                     7 378 \n留存收益                    36 235 \n→库存股票-普通               -23 375 \n其他权益                       626 \n股东权益合计                21 774 \n    到了年底，一个公司的净利润可以用于派发分红，也可以用于回购公司的股\n份，或者将它们保留下来去维护公司的运营。当它们被留着用于公司运营时，将','2026-07-05 16:55:53.049000',0,2073692323954429952,794,2073692323514028032),(2073692328450723841,'    到了年底，一个公司的净利润可以用于派发分红，也可以用于回购公司的股\n份，或者将它们保留下来去维护公司的运营。当它们被留着用于公司运营时，将\n记录在资产负债表上股东权益下的留存收益账户。 \n如果将收益留存用于可盈利的投资，那它们将极大地改善公司的 \n长期经济前景。正是由于巴菲特采取了留存伯克希尔公司 100％净利润的策略，\n公司股东权益从 1965 年的每股 19 美元提高到 2007 年的每股 78 000 美元。 \n要想知道公司每年会有多少净利润进入到留存收益，我们可以将公司的税\n后净利润减去派发的红利，再减去公司当年用于股票回购的开支。2007 年，可\n口可乐公司赚取了 59 亿美元的税后净利润，其中 31 亿美元被用于派发红利和股\n票回购。这样，剩下的大概 28 亿美元利润将被增加到留存利润储备中。 \n留存收益是一项累计数据，也就是说，每年新增的留存收益将被累加到以','2026-07-05 16:55:53.049000',0,2073692323954429952,795,2073692323514028032),(2073692328450723842,'票回购。这样，剩下的大概 28 亿美元利润将被增加到留存利润储备中。 \n留存收益是一项累计数据，也就是说，每年新增的留存收益将被累加到以\n前年度的留存收益中。同样，如果公司发生亏损，将从公司过去所累积的留存收\n益中扣减当年的亏损额。如果公司亏损的金额比其累积的留存利益还要多，其留\n存收益将以负数表示。 \n在资产负债表上，所有能帮我们判断一家公司是否具有持续性竞争优势的\n指标当中，留存收益是最重要的指标之一。其原因是，如果一家公司不能保持其\n留存收益一致增加的话，它的净资产是不会增长的。如果公司的净资产不能增长，\n那么从长远看，我们不会成为超级富翁。 \n简而言之，公司留存收益的增长率是判断公司是否得益于某种持续性竞争\n优势的一项好指标。让我们看看那些巴菲特所偏爱的具有持续性竞争优势的公\n司；可口可乐公司在过去 5 年一直保持留存收益为 7.9%的年增长率；箭牌公司','2026-07-05 16:55:53.049000',0,2073692323954429952,796,2073692323514028032),(2073692328450723843,'优势的一项好指标。让我们看看那些巴菲特所偏爱的具有持续性竞争优势的公\n司；可口可乐公司在过去 5 年一直保持留存收益为 7.9%的年增长率；箭牌公司\n一直保持 10.9%的留存收益增长率；伯灵顿北方圣太菲铁路运输公司则一直保持\n在 15.6％的水平；而巴菲特 \n所拥有的伯克希尔公司，其留存收益增长率高达到 23％。 \n并不是所有的留存收益增长都归因于产品销售量的增加，它也可能是收购\n其他公司所导致。当两家公司合并时，它们的留存收益将合并起来形成更大的储\n备。例如，当宝洁公司在 2005 年收购吉利公司时，它的留存收益从 130 亿美元\n一跃上升为 310 亿美元。 \n更有趣的是，通用汽车公司和微软公司显示的留存收益都为负值。通用汽\n车公司的留存收益为负债，主要是因为汽车行业一直的不景气导致公司亏损数十\n亿美元。微软公司负的留存收益，主要是因为它有足够强大的经济动力，它不需','2026-07-05 16:55:53.049000',0,2073692323954429952,797,2073692323514028032),(2073692328450723844,'车公司的留存收益为负债，主要是因为汽车行业一直的不景气导致公司亏损数十\n亿美元。微软公司负的留存收益，主要是因为它有足够强大的经济动力，它不需\n要留存在过去几年所积累的大量资本，所以，它更愿意将积累的留存收益，甚至\n更多的资金用于回购公司股票和给股东派发红利。 \n巴菲特在伯克希尔·哈撒韦取得巨大成功的超级秘诀之一，就是他在取得\n该公司控股权后停止了派发分红，将公司全部年度净利润增加到留存收益储备当\n中。当机会来临时，他将公司的留存收益投资于那些收益率更高的公司，由此赚\n得的利润又全部汇入到公司的留存收益，然后又投资于更能赚钱的公司，如此循\n环。随着时间的推移，伯克希尔不断增长的留存收益储备使其盈利能力也不断地\n增长，他赚取的利润也越来越多。1965～2007 年间，由于留存收益的扩张，伯\n克希尔的税前利润从 1965 年的每股 4 美元增长到 2007 年的每股 13 023 美元，','2026-07-05 16:55:53.049000',0,2073692323954429952,798,2073692323514028032),(2073692328450723845,'克希尔的税前利润从 1965 年的每股 4 美元增长到 2007 年的每股 13 023 美元，\n这大约相当于 21％的年均增长率。 \n其中的道理很简单：公司留存的收益越多，它的留存收益增长就越快，而\n这又将提高公司未来收益的增长率。当然，这里有个前提条 \n件，公司必须持续买入那些具有持续性竞争优势的公司。这恰恰就是巴菲特在伯\n克希尔·哈撒韦一直所做的。伯克希尔就像是一只不断产下金蛋的鹅，而且它下\n的每一个金蛋都能孵出一只会下金蛋的鹅，所有这些下金蛋的鹅不断地孵出更多\n的金蛋。巴菲特发现，如果你能将这个过程保持足够长的时间，到最后，当你清\n点自己的财富时，计量单位将会以 10 亿计算，而不是以百万计算。 \n \n \n第 46 章  库存股票：巴菲特喜欢在资产负债表中看到的 \n \n          资产负债表／股东权益（单位：百万美元） ','2026-07-05 16:55:53.049000',0,2073692323954429952,799,2073692323514028032),(2073692328450723846,' \n \n第 46 章  库存股票：巴菲特喜欢在资产负债表中看到的 \n \n          资产负债表／股东权益（单位：百万美元） \n优先股                           0 \n普通股                         880 \n资本公积                     7 378 \n留存收益                    36 235 \n→库存股票-普通               -23 375 \n其他权益                       626 \n股东权益合计                21 774 \n \n当一个公司回购自身的股票时，有两种处理方式，要么直接将回购的股份注\n销，要么保留它们，以备今后可能再发行时使用。如果直接将它们注销的话，这\n部分股份就不复存在了。但是如果保留它们以备日后可能再发行时使用，它们将','2026-07-05 16:55:53.049000',0,2073692323954429952,800,2073692323514028032),(2073692328450723847,'销，要么保留它们，以备今后可能再发行时使用。如果直接将它们注销的话，这\n部分股份就不复存在了。但是如果保留它们以备日后可能再发行时使用，它们将\n被记录在资产负债表股东权益下的库存股票账户里。以库存股票方式存在的股份\n既没有投票表决权，也不享有分红的权力。尽管它可以定义为一项资产，但只能\n以负值的权益体现在资产负债表上，因为它代表股东权益的减少。 \n那些具有持续性竞争优势的公司因其强大的经济实力，更易于获得充裕的资\n金用来回购它们自身的股票。所以，一家公司具有持续性竞争优势的主要标志之\n一，就是其资产负债表上出现库存股票。 \n关于库存股票，还有一些财务方面的原因必须让大家清楚。其一，当一个公\n司回购自身股票并以库存股票形式持有时，它将有效地减少公司权益，从而增加\n股东权益回报率。因为高水平的股东权益回报率是持续性竞争优势的一个标志，','2026-07-05 16:55:53.049000',0,2073692323954429952,801,2073692323514028032),(2073692328450723848,'司回购自身股票并以库存股票形式持有时，它将有效地减少公司权益，从而增加\n股东权益回报率。因为高水平的股东权益回报率是持续性竞争优势的一个标志，\n所以，最好弄明白高股东权益回报率是财务处理的结果，还是因为公司杰出的业\n绩，或者两者皆有。为了区分各自的作用，我们将库存股票的负值转化为正值，\n并加到股东权益上（并不是从中减去），然后用这个新的股东权益除以公司的净\n利润，这样计算的股东权益回报率就剔除了财务处理方面的影响。 \n另一方面，美国规定库存股票在确定公司的控制权时不能作为流通股的一部\n分，这会直接影响到个人控股公司税费的适用问题。一些不择手段的公司股东可\n能向美国国家税务局汇报他们只拥有公司所有流通股的 49％。但如果减去库存\n股票（法律上也有规定），他们实际控股则超过 50％，并且拥有公司的控股权，\n因此他们有义务缴纳个人控股公司税。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,802,2073692323514028032),(2073692328450723849,'股票（法律上也有规定），他们实际控股则超过 50％，并且拥有公司的控股权，\n因此他们有义务缴纳个人控股公司税。 \n让我们以一个简单的原理结束本章：如果资产负债表上出现了库存股票，表\n明公司曾经回购股票，那么，这家公司很可能具有一种与之有利的持续性竞争优\n势。 \n \n \n第 47 章  股东权益回报率：第一部分 \n \n资产负债表／股东权益（单位：百万美元） \n优先股                           0 \n普通股                         880 \n资本公积                     7 378 \n留存收益                    36 235 \n→库存股票-普通               -23 375 \n其他权益                       626 ','2026-07-05 16:55:53.049000',0,2073692323954429952,803,2073692323514028032),(2073692328450723850,'→库存股票-普通               -23 375 \n其他权益                       626 \n股东权益合计                21 774 \n股东权益等于公司总资产减去公司总负债，也等于优先股和普通股的总和\n再加上资本公积和留存收益，然后减去库存股票所得到的值。 \n股东权益有三个来源，第一部分来源于最初对公众发行优先股和普通股所\n募集的资金；第二部分来源于公司上市运营后对社会公众增 \n加发行优先股和普通股筹措的资金；第三部分，也是对我们来说最重要的部分，\n来源于公司积累的留存收益。 \n因为所有者权益都是属于公司的，而公司又为普通股股东所有，所以权益\n实际上属于普通股股东，这也是为什么它叫做股东权益的原因。 \n假如我们是一个公司的股东，我们将非常关注该公司的经理人在合理分配\n资金方面表现是否优秀，能否为我们赚取更多的利润。如果他们在这方面表现糟','2026-07-05 16:55:53.049000',0,2073692323954429952,804,2073692323514028032),(2073692328450723851,'假如我们是一个公司的股东，我们将非常关注该公司的经理人在合理分配\n资金方面表现是否优秀，能否为我们赚取更多的利润。如果他们在这方面表现糟\n糕，我们会感到不安，甚至有可能出售股份，将资金投到其他有利可图的地方。\n但是，如果他们在这方面表现优异，我们可能会追加资金，买入公司更多的股份，\n那些被公司管理层的优秀能力所打动的投资者也会随之而来。为此，金额分析师\n们发明了股东权益回报率公式，以衡量管理层在分配股东资金方面的效率。巴菲\n特在寻求具有持续性竞争优势的公司时，会将那些杰出的候选公司放入上述公式\n进行检验，这就是我们下一章的主题。 \n \n \n第 48 章  股东权益回报率：第二部分 \n计算公式：净利润除以股东权益等于股东权益回报率。 \n巴菲特发现，那些受益于某种持续性或长期竞争优势的公司往往有较高的股\n东权益回报率。巴菲特钟爱的可口可乐公司，其股东权益回报率高达 30％；箭','2026-07-05 16:55:53.049000',0,2073692323954429952,805,2073692323514028032),(2073692328450723852,'巴菲特发现，那些受益于某种持续性或长期竞争优势的公司往往有较高的股\n东权益回报率。巴菲特钟爱的可口可乐公司，其股东权益回报率高达 30％；箭\n牌公司的股东权益回报率也达到了 24％；好时食品公司的股东权益回报率竟达\n到 33％；百事公司更是高达 34％。 \n让我们将目光转向高度竞争的航空业。该行业没有一家公司拥有可持续的竞\n争优势，因此它们的股东权益回报率相形见绌。联合航空公司在繁荣时期的股东\n权益回报率仅为 15％，美国航空公司的股东权益回报率只有 4％。德尔塔航空公\n司和西北航空公司压根儿就没有赚取过任何利润，其股东权益回报率为零，甚至\n为负值。 \n高股东权益回报率意味着公司有效地利用了留存收益。随着时间的推移，这\n些高额的股东权益回报总会累积起来，并增加公司的内在价值，有朝一日股票市\n场会认可其价值，并将股价推向高位。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,806,2073692323514028032),(2073692328450723853,'些高额的股东权益回报总会累积起来，并增加公司的内在价值，有朝一日股票市\n场会认可其价值，并将股价推向高位。 \n请注意：有些公司的盈利能力非常强劲，使得它们不需要留存任何利润，它\n们将利润以红利形式全部分派给股东。这种情况下，公司的股东权益有时会显示\n为负数。需要警觉的是，那些濒临破产的公司股东权益同样也为负数。如果公司\n显示出一贯强劲的净利润，但却拥有负的股东权益，那么该公司可能是一家具有\n持续性竞争优势的公司。但是如果公司显示的股东权益为负数，并且长期以来都\n是亏损状态，那么我们遇到的很可能是一家在竞争中落败的平庸公司。 \n所以规律就是：高股东权益回报率意味着“近玩”，而低股东权益回报率意\n味着“远观”。 \n明白了吗？好的，让我们继续下一章。 \n \n \n第 49 章  杠杆问题和可能的骗局 \n杠杆就是利用负债去增加公司利润。公司以 7%的利息借入 1 亿美元，然后','2026-07-05 16:55:53.049000',0,2073692323954429952,807,2073692323514028032),(2073692328450723854,'明白了吗？好的，让我们继续下一章。 \n \n \n第 49 章  杠杆问题和可能的骗局 \n杠杆就是利用负债去增加公司利润。公司以 7%的利息借入 1 亿美元，然后\n将它投入公司运营中，并赚的 12%的回报。这意味着在扣除成本后，公司还可以\n赚取 5%的利润，也就是 500 万美元的最终收益。这将增加公司的利润和股东权\n益回报率。 \n杠杆的问题在于，它可能使公司表面上看起来具有某种竞争优势，但实际上\n只是利用了大量的债务来增加利润。华尔街的那些投资银行就是因为大量运用杠\n杆原理二臭名昭著的。比方说，它们以 6%的利息借入 1000 亿美元，然后以 7%\n的利息将其贷出，这意味着它们将从中赚取这 1000 亿美元的 1%，也就是 10 亿\n美元。如果每年能赚取 10 亿美元，这可能令公司看来具有某种持续性竞争优势，\n但实际上并非如此。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,808,2073692323514028032),(2073692328450723855,'美元。如果每年能赚取 10 亿美元，这可能令公司看来具有某种持续性竞争优势，\n但实际上并非如此。 \n尽管这些投资银行看起来有源源不断的利润流入，但公司实际的利润来源\n（贷款利息）可能会出现问题。这种情况在最近的次贷危机中就发生了，并造成\n了这些银行数千亿美元的损失。比如说，它们以 6%的利息借入数十亿美元，然\n后以 8%的利息贷款给次级购房者（还款能力稍差的购房者），银行由此可以赚取\n巨额利润。但当经济不景气时，次级购房者可是出现违约的情况，停止支付贷款\n利息。由于那些次级贷款人没有稳定收入，最终将导致这些投资银行无法持续盈\n利，甚至出现亏损的情况。 \n在评估一个公司竞争优势的质量和持续性方面，巴菲特会尽量避免开那些使\n用大量杠杆来获取利润的公司。从短期来看，这些公司可能是只下金蛋的鹅，但\n最终它们将一无是处。 \n \n \n第三部  现金流量表 \n导读 ','2026-07-05 16:55:53.049000',0,2073692323954429952,809,2073692323514028032),(2073692328450723856,'用大量杠杆来获取利润的公司。从短期来看，这些公司可能是只下金蛋的鹅，但\n最终它们将一无是处。 \n \n \n第三部  现金流量表 \n导读 \n巴菲特发现，当我们判断公司是否得益于某种持续性竞争优势时，现金流量\n表所提供的信息非常有帮助。 \n巴菲特分析现金流量表时最关注两个指标： \n1.资本开支：指购买厂房和设备等长期资产（持有时间超过一年以上）的现\n金或现金等价物支出。我们可以简单地将公司 10 年来的累计资本开支与该公司\n同期的累计净利润进行比较，以真实的反映公司的长期发展前景。经验告诉我们，\n那些具有持续性竞争优势的公司，其资本开支占净利润的比率都非常小。巴菲特\n发现，如果一家公司将领利润用于资本开支的比例一直保持在 50%之下，那么你\n可以把它列入具有持续性竞争优势公司的候选者名单。如果该比例保持低于 25%\n的水平，那这家公司很可能具有与之有利的持续性竞争优势。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,810,2073692323514028032),(2073692328450723857,'可以把它列入具有持续性竞争优势公司的候选者名单。如果该比例保持低于 25%\n的水平，那这家公司很可能具有与之有利的持续性竞争优势。 \n2.回购股票：巴菲特发现，一个公司具有持续性竞争优势的特征是公司曾经\n回购过自身股票。通过使用公司多余的闲置资金用于回购股票，会减少流通股数\n量，从而提高每股收益，最终推动公司股票价格上涨。在现金流量表上仔细查看\n其投资活动产生的现金流。在那里你将看到名为“发行（回购）股票，净值”的\n一个账户。该账户列出了公司发行和回购股票的净额。如果一家公司每年都进行\n股票回购，那么很可能这是一家具有持续性竞争优势的公司，因为只有这样的公\n司才有充裕的资金从事股票回购。 \n \n \n第 50 章  现金流量表：巴菲特查看现金之处 \n在会计处理方法上，大多数公司使用的是权责发生制，而不是收付实现制。\n权责发生制是指产品一旦发货，就会被记录到销售收入账目，不管购买者何时支','2026-07-05 16:55:53.049000',0,2073692323954429952,811,2073692323514028032),(2073692328450723858,'在会计处理方法上，大多数公司使用的是权责发生制，而不是收付实现制。\n权责发生制是指产品一旦发货，就会被记录到销售收入账目，不管购买者何时支\n付货款。但在收付实现制下，公司要受到货款现金之后才能入账。几乎所有的公\n司都会给它们的产品购买者提供各种信用，它们发现使用权责发生制更具有优越\n性，因为这种方法允许它们将赊销作为收入记录在损益表上，同时在资产负债表\n上也增加应收账款。 \n既然权责发生制允许赊销作为收入记账，那么对公司来说，就有必要将实际\n发生的现金流入和现金流出单独列示。为此，会计师们就发明了现金流量表。 \n一家公司可能通过发行股票或者债券获取大量现金，但它不能产生盈利。（同\n理，一家公司有大量的赊销而没有任何现金流入，它也可能产生盈利。）现金流\n量表将告诉我们，这家公司是现金流入大于现金流出（“正的净现金流”），还是\n现金流入小于现金流出（“负的净现金流”）。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,812,2073692323514028032),(2073692328450723859,'量表将告诉我们，这家公司是现金流入大于现金流出（“正的净现金流”），还是\n现金流入小于现金流出（“负的净现金流”）。 \n现金流量表同损益表一样，反映的是某段时期的情况。公司的会计部门每个\n季度和每个会计年度都会编制一份现金流量表。 \n现金流量表可分为三个部分： \n第一部分，经营活动产生的现金流。这部分以净利润开始，加上折旧费和待\n摊费用。从会计角度看，尽管这些都是实际的费用支出，但它们并不消耗任何现\n金，因为它们代表的是多年前已经支付的现金。最后，我们得到的是经营活动产\n生的现金流合计值。 \n                                        （单位：百万美元） \n净利润                                     5 981 \n折旧费                                     1 163 ','2026-07-05 16:55:53.049000',0,2073692323954429952,813,2073692323514028032),(2073692328450723860,'折旧费                                     1 163 \n待摊费用                                     125 \n经营活动产生的现金流量合计                 7 269 \n第二部分，投资活动产生的现金流。这部分包括报表期间内所有的资本开支。\n资本开支项目通常是负值，因为它是一项内耗现金的开支。 \n资本开支下面是其他投资活动现金流量项目，这个项目是购买和出售盈利资\n产的费用和收益合计。如果花费的现金比收入的现金要多的话，该项目为负值。\n如果现金收入比现金花费多，则为正值。 \n将以上两类账户相加，我们将得到投资活动产生的现金流量合计。 \n                                        （单位：百万美元） ','2026-07-05 16:55:53.049000',0,2073692323954429952,814,2073692323514028032),(2073692328454918144,'                                        （单位：百万美元） \n资本开支                                  （1 648） \n其他投资活动现金流量项目                  （5 071） \n投资活动产生的现金流量合计                （6 719） \n最后一个部分，融资活动产生的现金流。这部分用于核算公司由于融资活动\n产生的现金流入和流出，其中包括支付红利的现金流出，也包括发行和回购公司\n股票产生的现金流入和流出。当公司为修建新厂房融资而发行股票时，现金将流\n入公司；当公司回购自身股票时，现金则流出公司。债券融资也是如此：发行债\n券产生现金流入，偿还债券产生现金流出。将所有这三个项目加总起来，就得到\n融资活动产生的现金流量合计。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,815,2073692323514028032),(2073692328454918145,'券产生现金流入，偿还债券产生现金流出。将所有这三个项目加总起来，就得到\n融资活动产生的现金流量合计。 \n                                        （单位：百万美元） \n支付现金红利                              （3 149） \n发行（回购）股票【净值】                    （219） \n发行（回购）债券【净值】                    4 341 \n融资活动产生的现金流量合计                    973 \n现在，如果我们将经营活动产生的现金流加上投资活动产生的现金流，再加\n上融资活动产生的现金流，我们将得到公司现金流量净额。 \n                                       （单位：百万美元） ','2026-07-05 16:55:53.049000',0,2073692323954429952,816,2073692323514028032),(2073692328454918146,'上融资活动产生的现金流，我们将得到公司现金流量净额。 \n                                       （单位：百万美元） \n经营活动产生的现金流量合计                  7 269 \n投资活动产生的现金流量合计                （6 719） \n融资活动产生的现金流量合计                    973 \n现金流量净额                                1 523 \n巴菲特发现，当我们判断公司是否得益于蓝  19:15:12 \n我看看你上午拍的某种持续性竞争优势时，现金流量表所提供的信息非常有\n帮助。因此，让我们卷起衣袖，一头栽进现金流量表，仔细查看一下巴菲特在寻\n找赚取下一个 10 亿利润的目标公司所关注的东西。 \n \n \n第 51 章  资本开支：致富秘诀之一就是减少它 ','2026-07-05 16:55:53.049000',0,2073692323954429952,817,2073692323514028032),(2073692328454918147,'找赚取下一个 10 亿利润的目标公司所关注的东西。 \n \n \n第 51 章  资本开支：致富秘诀之一就是减少它 \n         \n 现金流量表         （单位：百万美元） \n   →资本开支                                  （1 648） \n     其他投资活动现金流量项目                  （5 071） \n     投资活动产生的现金流量合计                （6 719） \n资本开支是购买长期资产（持有时间超过一年以上）的现金或现金等价物支\n出，如房屋、厂房、机器设备。它们同样包括无形资产，如专利权的花费。从本\n质上讲，它们是通过多期折旧或摊销费用的资产，而不是一次性耗费的资产。在\n现金流量表中，资本开支被记录在投资活动产生的现金流账户里。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,818,2073692323514028032),(2073692328454918148,'质上讲，它们是通过多期折旧或摊销费用的资产，而不是一次性耗费的资产。在\n现金流量表中，资本开支被记录在投资活动产生的现金流账户里。 \n为你的公司买辆汽车是一项资本开支，汽车的费用将在其使用年限（假定为\n6年）内每年计提折旧进行摊销，但是这辆汽车消耗的汽油是一项当期费用，它\n将在当期利润中被扣除掉。 \n在资本开支方面，不同的公司有不同的需求。很多公司为了能保持行业中的\n龙头地位，必须大量投入资本开支。如果一家公司连续几年都维持着高额的资本\n投入，这必将严重影响公司的利润。巴菲特说过，这就是他不愿意投资通讯类公\n司的原因，因为通讯类公司需要花费巨额资本开支用于建设室外通信网络，这严\n重阻碍了其长期经济发展前景。 \n通常情况下，一个具有持续性竞争优势的公司为维持其正常经营，其净收益\n中用于资本开支的比例比那些没有竞争优势的公司要小得多。让我们看一些实\n例。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,819,2073692323514028032),(2073692328454918149,'通常情况下，一个具有持续性竞争优势的公司为维持其正常经营，其净收益\n中用于资本开支的比例比那些没有竞争优势的公司要小得多。让我们看一些实\n例。 \n巴菲特一直钟爱的可口可乐公司，过去 10 年每股收益总计赚取了 20.21 美\n元的利润，而同期内每股只使用了 4.01 美元（也就是总利润的 19%）用于资本\n开支。穆迪公司，一个巴菲特认定具有持续性竞争优势的公司，过去 10 年每股\n收益总共赚取了 14.24 美元的利润，但只使用了微不足道的 0.84 美元（也就是\n总利润的 5%）用于资本开支。 \n相比于可口可乐公司和穆迪公司，通用汽车公司在过去 10 年内的累计每股\n收益（扣减了亏损部分）为 31.64 美元，但资本开支的耗费高达每股 140.42 美\n元。轮胎制造商固特异公司在过去 10 年内的累积每股收益（扣除亏损后）为 3.67','2026-07-05 16:55:53.049000',0,2073692323954429952,820,2073692323514028032),(2073692328454918150,'元。轮胎制造商固特异公司在过去 10 年内的累积每股收益（扣除亏损后）为 3.67\n美元，但却要花费总计每股 34.88 美元用于资本开支。 \n也就是说，通用汽车公司使用了超过其利润的 444%用于资本开支，而固特\n异公司的资本开支超过了利润额的 950%。那么，多余的钱从何而来呢？它们来\n自银行贷款或向公众新发行的公司债券。这些活动必将使公司的资产负债表上增\n加更多的负债，从而增加公司用于支付利息的费用，所有这一切并不是件好事。 \n然而，可口可乐公司和穆迪公司都有充裕的收益用于股票回购，这将减少普\n通股数量，同时减少长期贷款或者保持较低水平的长期贷款。这两种行为对巴菲\n特来说，都能显现出极大的正效应，并且都是具有持续性竞争优势的公司。 \n当分析资本开支与净利润之间的关系时，我们简单的将公司 10 年来的累计\n资本开支，与该公司同期的累积净利润进行比较。我们之所以分析 10 年期的数','2026-07-05 16:55:53.049000',0,2073692323954429952,821,2073692323514028032),(2073692328454918151,'当分析资本开支与净利润之间的关系时，我们简单的将公司 10 年来的累计\n资本开支，与该公司同期的累积净利润进行比较。我们之所以分析 10 年期的数\n据，是因为只有这样才能真实地反映公司的长期发展前景，帮助我们判断公司的\n最终走向。 \n经验告诉我们，那些具有持续性竞争优势的公司，其资本开支与净利润的比\n率都非常小。例如，箭牌公司每年使用大概 49%的净利润用于资本开支；奥驰亚\n集团大概使用 20%的净利润用于资本开支；宝洁的这一比例为 28%；百事可乐为\n36%；美国运通为 23%；可口可乐为 19%；穆迪公司为 5%。 \n巴菲特发现，如果一家公司将净利润用于资本开支的比例一直保持在 50%以\n下，那么你可以把它列入具有持续性竞争优势公司的候选者名单。如果该比例保\n持在低于 25%的水平，那这家公司就很可能具有有利的持续性竞争优势。 \n对我们来说有利的持续性竞争优势就代表着所有的一切。 \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,822,2073692323514028032),(2073692328454918152,'持在低于 25%的水平，那这家公司就很可能具有有利的持续性竞争优势。 \n对我们来说有利的持续性竞争优势就代表着所有的一切。 \n \n \n第５２章  股票回购：巴菲特增加股东财富的免税途径 \n \n现金流量表 \n融资活动产生的现金流量项目 \n                      （单位：百万美元） \n支付现金红利             （3149） \n发行（回购）股票【净值】       （219） \n发行（回购）债券【净值】       4341  \n融资活动产生的现金流量合计        937 \n  从上面的现金流量表可以看到，公司支付了 31.49 亿美元的现金红利，回\n购了 2.19 亿美元的自身股票，并新发行了 43.41 亿美元公司债券。所有这些融\n资活动给公司增加了总共 9.37 亿美元的现金流入。 \n  那些具有持续性竞争优势的公司赚取了大把的钞票，喜笑颜开的它们开始','2026-07-05 16:55:53.049000',0,2073692323954429952,823,2073692323514028032),(2073692328454918153,'资活动给公司增加了总共 9.37 亿美元的现金流入。 \n  那些具有持续性竞争优势的公司赚取了大把的钞票，喜笑颜开的它们开始\n考虑这些钱的处理问题。如果不想这些钱闲置，又不能把它们投资于公司现有的\n业务，或者未能找到好的投资项目，那么它们可以将这些钱给股东们支付现金股\n利，或者用于回购公司股票。但因为股东们得为红利支付所得税，巴菲特从来就\n不怎么喜欢通过派发红利来增加股东的财富，其实，股东也不喜欢将部分财富白\n白送给美国国家税务。巴菲特想出了一个巧妙的办法：将公司多余的闲置资金用\n于回购公司股票。这会减少公司的流通股数量（公司持股股东的利益将增加），\n从而提高每股收益，最终导致公司股票价格上涨。 \n让我们看一个例子：如果一家公司赚取 1000 万美元的利润并有 100 万的流\n通股，那么公司每股收益为 10 美元。如果我们将流通股的数量增加到 200 万，','2026-07-05 16:55:53.049000',0,2073692323954429952,824,2073692323514028032),(2073692328454918154,'让我们看一个例子：如果一家公司赚取 1000 万美元的利润并有 100 万的流\n通股，那么公司每股收益为 10 美元。如果我们将流通股的数量增加到 200 万，\n那公司的每股收益将降至每股５美元。同理，我们将流通股的数量降至 50 万股，\n那么公司的每股收益将增加到每股 20 美元。流通股数量越多，意味着每股收益\n越低，流通股数量越少意味着每股收益越高。因此，一个公司回购它自身的股票\n将增加它的每股收益，尽管净利润实际上并没有增加。最为奇妙的是，股东们在\n出售他们的股票之前，他们的财富增加了，却不需要为之赋税。就把它当作源源\n不断的免费礼物吧！ \n  巴菲特试着向金融工程的忠实爱好者。在他投资的优质公司中，他都说服\n董事会去回购公司股票，而不是扩大派发红利。他在美国政府雇员保险公司就运\n用了这个策略，在华盛顿邮报公司也是这样。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,825,2073692323514028032),(2073692328454918155,'董事会去回购公司股票，而不是扩大派发红利。他在美国政府雇员保险公司就运\n用了这个策略，在华盛顿邮报公司也是这样。 \n  要想知道一家公司是否在回购自身的股票，可以到现金流量表上仔细查看\n其投资活动所产生的现金流，在那里，你将看到名为“发行（回购）股票【净值】”\n的一个账户。 \n  该账户列出了发行和回购股票的净额。如果一家公司每年都进行股票回\n购，那么这很可能是一家具有持续性竞争优势的公司，因为只有这样的公司才有\n充裕的资金从事股票回购。 \n  换句话说，一家具有持续性竞争优势的公司的表象特征之一，就是公司曾\n经回购过自身的股票。 \n \n \n第四部 衡量具有持续性竞争优势公司的价值 \n导读 \n巴菲特选股的秘诀是：只选择买入那些具有持续性竞争优势的公司。这种\n公司的股票相当于一种股权债券，公司的税前利润就是债券所支付的息票利率。','2026-07-05 16:55:53.049000',0,2073692323954429952,826,2073692323514028032),(2073692328454918156,'导读 \n巴菲特选股的秘诀是：只选择买入那些具有持续性竞争优势的公司。这种\n公司的股票相当于一种股权债券，公司的税前利润就是债券所支付的息票利率。\n但不同于普通的债券，股权债券所支付的息票利率不是固定的，而是年复一年地\n保持增长态势，股权债券内在价值自然也在不断地攀升。 \n  估算股票的市场价值的简单方法是，用每股盈利除以长期公司债券利率。\n尽管股市估值水平短期有涨有跌，但最终会回归于长期投资的实际价值水平，也\n就是长期债券利率。巴菲特知道，如果他买入一家具有持续性竞争优势的公司，\n随着时间的推移，股票市场最终会重估公司的股权债券，市场价格最终会回归于\n内在价值。 \n  巴菲特非常重视买入价格的高低，因为你支付的成本价将直接影响到你的\n投资回报率，因此一定要把握好买入的时机以降低成本。最好是在熊市中开始买\n入。尽管相比于其它“熊市便宜货”，它们的价格似乎仍然偏高，但从长远看，','2026-07-05 16:55:53.049000',0,2073692323954429952,827,2073692323514028032),(2073692328454918157,'投资回报率，因此一定要把握好买入的时机以降低成本。最好是在熊市中开始买\n入。尽管相比于其它“熊市便宜货”，它们的价格似乎仍然偏高，但从长远看，\n它们绝对是不错的买卖。非熊市时期也有买入的机会。巴菲特曾说过，当一家优\n质公司面临一个偶然的，可解决的困难时，一个完美的买入奇迹就从天而降。请\n注意，公司面临的困境是可解决的。但是在牛市的高点，再好的公司也不要买入。\n当这些超级公司以创历史新高的市盈率交易时，如果投资者以高价跟进的话，即\n使是一家受益于持续性竞争优势的公司，未来很长时间内它也可能仅为投资者带\n来平平业绩。 \n  巴菲特强调要长期持有，如果一家公司一直保持其竞争优势，那么你就不\n要卖出它们中的任何一家。道理很简单，你持它们越久，你获得的税后回报越多。\n但在三种情况下，卖出也是有利的选择。第一种情况是你需要资金投资于一个更','2026-07-05 16:55:53.049000',0,2073692323954429952,828,2073692323514028032),(2073692328454918158,'要卖出它们中的任何一家。道理很简单，你持它们越久，你获得的税后回报越多。\n但在三种情况下，卖出也是有利的选择。第一种情况是你需要资金投资于一个更\n优秀的、价值更便宜的公司时。第二种是这个公司看起来将要失去其持续性竞争\n优势的时候，第三种情况在牛市期间其股价远远超过了其长期内在经济价值时。\n一个简单的法则：当我们看到这些优质的公司达到了４０倍甚至更高的市盈率时\n（这确实偶有发生），就到该卖出的时候了。 \n \n \n第 53 章  巴菲特的股权债券创意如何使他致富 \n 20 世纪 80 年代末，巴菲特在哥伦比亚大学进行过一场演讲，内容是那些具\n有持续性竞争优势的公司为何有如此强大的，可预测的利润增长，使其股票变成\n一种息票利率不断增长的股权债券。这些债券就是公司的股票，而它的“息票利\n率”就是公司的税前利率，它不是公司派发的红利，而是公司实际的税前利润。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,829,2073692323514028032),(2073692328454918159,'一种息票利率不断增长的股权债券。这些债券就是公司的股票，而它的“息票利\n率”就是公司的税前利率，它不是公司派发的红利，而是公司实际的税前利润。 \n  下面是巴菲特购买一家公司的过程；他查看公司的税前利润，将公司潜在\n的经济发展动力所所体现的盈利能力与公司的市场价值进行比较，以此来判断这\n是否是一项好买卖。他在股票市场买下某家公司的部分股票时，其方法也相同。 \n  巴菲特之所以将公司股票转化为股权债券的概念，是因为他看到了持续性\n竞争优势所产生的强大的潜在经济动力，它能给公司带来持续的利润增长。当股\n票市场承认公司的内在价值时，利润的持续增长最终将使公司的股票价格上扬。 \n  允许我再重复一次：对于巴菲特来说，一家具有持续性竞争优势的公司，\n其股票相当于一种股权债券，公司的税前利润相当于普通债权的息票或它所支付\n的利息。但不同于普通债权，股权债券所支付的息票利率是不固定的，而是年复','2026-07-05 16:55:53.049000',0,2073692323954429952,830,2073692323514028032),(2073692328454918160,'其股票相当于一种股权债券，公司的税前利润相当于普通债权的息票或它所支付\n的利息。但不同于普通债权，股权债券所支付的息票利率是不固定的，而是年复\n一年的保持增长态势，股权债券的价值自然也就不断地攀升。 \n  这是巴菲特买入一家具有持续性竞争优势的公司时所发生的情况：每股收\n益一直不断保持增长——或者是通过销售业绩的改善、运营规模的扩大、收购新\n公司，或者是公司用积累的库存资金进行股票回购。随着公司利润的增长，巴菲\n特最初投资在这些股权债券上的回报也将随之增加。 \n  让我们通过一个实际案例来分析他的理论是如何产生作用的。 \n  20 世纪 80 年代末期，巴菲特开始以平均每股 6.5 美元的价格购入可口可\n乐公司的股票，该公司的税前利润是每股 0.70 美元，相当于每股 0.46 美元的税\n后利润。从以往的数据看，可口可乐公司一直保持着每年 15%左右的利润增长率。','2026-07-05 16:55:53.049000',0,2073692323954429952,831,2073692323514028032),(2073692328454918161,'后利润。从以往的数据看，可口可乐公司一直保持着每年 15%左右的利润增长率。\n由此，巴菲特认为他买到的是可口可乐公司的股权债券，这种债券能为他最初\n6.5 美元的投资带来 10.7%的税前回报率，同时，他也认为该回报率今后将以 15%\n的速度增长。 \n  不同于格雷厄姆式的价值投资者，巴菲特并不是因为预期可口可乐公司的\n股票价值应为每股 60 美元，而是因为认为每股 40 美元的价值存在“价值低估”\n而买入。他考虑的是，以每股 6.5 美元的价格买入后，将获得相对无风险的的初\n始税前回报率，并且认为这一回报率在今后 20 年将以 15%左右的年增长率不断\n升高。接下来，他会将之与其他投资的风险与回报进行比较，看看这项投资是否\n真正具有吸引力。 \n  对那些格雷厄姆式的价值投资者而言，税前 10.7%并以每年 15%的增长率','2026-07-05 16:55:53.049000',0,2073692323954429952,832,2073692323514028032),(2073692328454918162,'真正具有吸引力。 \n  对那些格雷厄姆式的价值投资者而言，税前 10.7%并以每年 15%的增长率\n增长的年投资回报率不会打动他们，公司未来发生的事也无关紧要因为他们只对\n股票价格感兴趣，并且从来没打算长期持有。但对于做长线投资的巴菲特来说，\n持有这类股权债券就是他梦寐以求的。 \n为什么这是他的理想投资呢？因为时间每过一年，他最初的投资回报率就会\n增长一些，今后，这些数据就会像金字塔一样越垒越高。请看下面的例子：巴菲\n特最初投资华盛顿邮报的股票成本为每股 6.36 美元。34 年后（也就是 2007 年），\n这家传媒公司的税前利润为每股 54 美元，相当于每股税后 344 美元的回报。巴\n菲特投资于华盛顿邮报公司的股权债券，其税前回报率高达 849%，等同于税后\n534%的投资回报率。你可以想象巴菲特为何如此富有！ \n 那巴菲特投资于可口可乐公司的股权债券怎么样呢？ ','2026-07-05 16:55:53.049000',0,2073692323954429952,833,2073692323514028032),(2073692328454918163,'534%的投资回报率。你可以想象巴菲特为何如此富有！ \n 那巴菲特投资于可口可乐公司的股权债券怎么样呢？ \n可口可乐公司的税前利润以大概每年 9.35%的增长率增长，截至 2007 年，\n其每股收益为 3.96 美元，相当于税后每股 2.57 美元，这意味着巴菲特初始投资\n的每股 6.5 美元的可口可乐公司的股权债券，在 2007 年支付了每股 3.96 美元的\n税前回报给他，这相当于 60％的税前年回报率和 40％税后回报率。 \n  股票市场一旦看到这些回报率，终有一日会重估巴菲特的股权债券价值，\n反映出其增长价值。 \n考虑一下：2007 年公司长期债券利率大概是 6.5％，巴菲特持有的华盛顿邮\n报公司的的股权债券的税前每股收益为 54 美元，那么该公司的股票价值大约为\n830 美元（＄54÷0.065＝＄830）。2007 年，巴菲特持有的华盛顿邮报公司的的','2026-07-05 16:55:53.049000',0,2073692323954429952,834,2073692323514028032),(2073692328454918164,'830 美元（＄54÷0.065＝＄830）。2007 年，巴菲特持有的华盛顿邮报公司的的\n股权债券价格一直徘徊在每股 726-855 美元之间，刚好在该股权债券的资本价值\n830 美元上下浮动。 \n我们同样可以见证巴菲特持有的可口可乐公司股权债券在股票市场的价值\n回归。2007 年，该公司赚取了每股 3.96 美元的收益，相当于每股 2.57 美元的\n税后利润。可口可乐的税前每股收益是 3.96 美元，按照 6.5％的长期公司债券\n利率计算，其每股股票价格应该在 60 美元（＄3.96÷0.065＝＄60）。2007 年，\n可口可乐公司的股票价格在 45－64 美元间波动。 \n股票市场最终将承认公司的内在价值增长，令股票价格大幅上涨，其原因之\n一就在于，它们的利润可以一直保持增长态势，以至于极易成为杠杆式的收购目\n标。如果一家公司负担很少的公司债务，并且保持强势的历史盈利记录，那么当','2026-07-05 16:55:53.049000',0,2073692323954429952,835,2073692323514028032),(2073692328459112448,'一就在于，它们的利润可以一直保持增长态势，以至于极易成为杠杆式的收购目\n标。如果一家公司负担很少的公司债务，并且保持强势的历史盈利记录，那么当\n它的股价跌倒历史足够低时，其他公司会马上介入并收购它，而收购资金则来源\n于以被收购公司为基础的融资。所以当利率下降时，该公司的利润更值钱，因为\n它们可以支持更多的债务，而这又会进一步推升公司的股价。当利率上升时，公\n司的利润将贬值，因为它们能支持的债务减少了，公司的股价也因此而贬值。 \n巴菲特知道，如果他买入一家具有持续性竞争优势的公司，随着时间的推移，\n股票市场最终会重估公司的股权债券，其市场价值大约等于每股盈利除以长期公\n司债券利率。的确，股票市场风云莫测，投资者们有时太过悲观，有时又太过乐\n观，但最终决定长期投资实际经济价值的就是长期利率。 \n \n \n第 54 章  持续性竞争优势带来的持续增长回报 ','2026-07-05 16:55:53.049000',0,2073692323954429952,836,2073692323514028032),(2073692328459112449,'观，但最终决定长期投资实际经济价值的就是长期利率。 \n \n \n第 54 章  持续性竞争优势带来的持续增长回报 \n     为了反复说明这一点（因为它确实需要再次强调），让我们看看巴菲特偏爱\n的其他一些具有持续性竞争优势的公司，看它们的股权收益债券收益率是否一直\n在增长。 \n    1998 年，穆迪公司报告的税后利润是每股 0.41 美元，截至 2007 年，穆迪公\n司税后利润已增加到每股 2.58 美元。巴菲特当时购买穆迪公司股权债券的支付\n价格为每股 10.38 美元，如今，他正享受着 24%的税后投资回报率，相当于 38%\n的税后投资回报率。 \n    1998 年，美国运通赚取的税后利润为每股 1.54 美元。2008 年，其税后利润\n已增加到每股 3.39 美元。巴菲特为美国运通的股权债券的支付买价为每股 8.48','2026-07-05 16:55:53.049000',0,2073692323954429952,837,2073692323514028032),(2073692328459112450,'已增加到每股 3.39 美元。巴菲特为美国运通的股权债券的支付买价为每股 8.48\n美元，这意味着他在 2008 年获得了 40%的税后投资回报率，相当于 61%的税前\n投资回报率。 \n    巴菲特长期偏爱的宝洁公司在 1998 年赚取的税后利润为每股 1.28 美元。到\n了 2007 年，其税后净利润达到每股 3.31 美元。巴菲特购买宝洁公司股权债券的\n成本价为每股 10.15 美元，该股权债券在 2008 年的税后投资回报率为 32%，相\n当于 49%的税前投资回报率。 \n    早在 1972 年，巴菲特就以 2500 万美元买下了整个希斯糖果公司。2007 年，\n它的税前利润为 8200 万美元，这意味着巴菲特在希斯股权债券上原始投资如今\n能获得 328%的税前年投资收益率。 \n对所有这些公司来说，它们的持续性竞争优势促使其净利润年复一年地增','2026-07-05 16:55:53.049000',0,2073692323954429952,838,2073692323514028032),(2073692328459112451,'能获得 328%的税前年投资收益率。 \n对所有这些公司来说，它们的持续性竞争优势促使其净利润年复一年地增\n长，而这反过来又会增加公司的内在价值。的确，股票市场会随着时间的增长承\n认这些价值，这最终会变成现实，而且巴菲特也已经见证过很多次了。  \n \n \n第 55 章  衡量具有持续性竞争优势公司价值的其他途径 \n    前面的章节提到，从 1987 年起，巴菲特开始以平均每股 6.50 美元的价格买\n入可口可乐公司股票，该公司的税前利润为每股 0.70 美元（相当于每股 0.46\n美元的税后利润），而且其利润年增长率一直保持在 10%左右。 \n    看到这些数据，巴菲特认为他买入了可口可乐公司的一种股权债券，该债券\n最初每年支付给他 10.7%的税前利润率，同时他还认为这个税前回报率将随时间\n而增高，预计每年增长率为 10%（从 1987 年开始，可口可乐公司近 10 年的平均','2026-07-05 16:55:53.049000',0,2073692323954429952,839,2073692323514028032),(2073692328459112452,'而增高，预计每年增长率为 10%（从 1987 年开始，可口可乐公司近 10 年的平均\n年利润增长率为 10%）。 \n    假设巴菲特在 1987 年预计公司的利润年增长率为 10%，那他可就此推算，\n到 2007 年时，可口可乐公司将获得每股 4.35 美元德法尔税前收益或每股 2.82\n美元的税后收益。这就意味着，到 2007 年，可口可乐公司股权债券的税前回报\n率将增长到 66%，相当于 43%的税后投资回报率。 \n每股 6.5 美元，税前收益为 66%的股权债券在 2007 年的价值相当于 1987 年价值\n的多少呢？这由我们可以使用的贴现率决定。如果我们使用 7%的贴现率（1987\n年长期利润率的水平），那么贴现回报率就为 17%左右。用 17%乘以每股 6.5 美元\n的支持价格，我们就得到 1.10 美元的每股税前收益。再以 1.10 美元乘以可口可','2026-07-05 16:55:53.049000',0,2073692323954429952,840,2073692323514028032),(2073692328459112453,'的支持价格，我们就得到 1.10 美元的每股税前收益。再以 1.10 美元乘以可口可\n乐公司在 1987 年的市盈率（P/E 值）14，我们得到每股股票价值应为 15.40 美\n元。因此巴菲特可推算，他在 1987 年以每股 6.5 美元买入一份可口可乐公司股\n权债券，并持有 20 年，那么这份股权债券的内在价值将为 15.40 美元。 \n    到 2007年，可口可乐的税前利润以9.35%的年增长率攀升至每股3.96美元，\n相当于税后的每股 2.57 美元。这意味着，巴菲特认为他以每股 6.50 美元买入的\n可口可乐股权债券，如今能带给他每股 3.96 美元的税前回报，这相当于 60%的\n税前投资回报率和 40%的税后回报率。 \n    2007 年，巴菲特持有的可口可乐公司股权债券价格在每股 45-64 美元间。','2026-07-05 16:55:53.049000',0,2073692323954429952,841,2073692323514028032),(2073692328459112454,'税前投资回报率和 40%的税后回报率。 \n    2007 年，巴菲特持有的可口可乐公司股权债券价格在每股 45-64 美元间。\n同年，可口可乐公司转圈的税前利润为每股 3.96 美元。相当于税后利润为 2.57\n美元。以 2007 年的公司长期利率 6.5%为基准进行资本定价，可口可乐公司每股\n3.96 美元的税前收益折算出其股票价值为每股 60 美元（$3.96÷0.065=$60）。\n这与可口可乐公司在 2007 年的股票市场价格（45-64 美元之间）相符。 \n    按照可口可乐公司股权债券的市场价格——每股 64 美元。巴菲特可计算出\n他的初始投资为他带来了 12.11%的复利回报率，而且到目前为止不用上缴任何\n所得税。你可以把它当成以后总能获得 12.11%的免税年回报率的债券。不过如\n此，你还可以将收益追加投资到这些回报率为 12.11%的债券上。是的，总有一','2026-07-05 16:55:53.049000',0,2073692323954429952,842,2073692323514028032),(2073692328459112455,'所得税。你可以把它当成以后总能获得 12.11%的免税年回报率的债券。不过如\n此，你还可以将收益追加投资到这些回报率为 12.11%的债券上。是的，总有一\n天，你将出卖你的股权债券并缴纳所得税，但是如果你选择不出卖它们的话，你\n就能年复一年地保持赚取免税年回报率的 12.11%。 \n   不相信吗？想一想：巴菲特在伯克希尔公司股票上收获的资本高达 640 亿美\n元。但却没有为之缴纳任何税费。他成为这个世界上积累私人财富最多的人，却\n没有向收税员缴纳一分钱。 \n    有比这更棒的事情吗？ \n \n \n  第 56 章  巴菲特如何确定购买一家理想企业的最佳时机 \n     巴菲特认为，你支付的成本价将直接影响你的投资回报率。比如他将一家\n具有持续性竞争优势的公司股票当作一种股权债券，为之支付的价格越高，出事\n投资回报率和投资该公司未来 10 年的利润回报率也就越低。让我们看一个例子：','2026-07-05 16:55:53.049000',0,2073692323954429952,843,2073692323514028032),(2073692328459112456,'具有持续性竞争优势的公司股票当作一种股权债券，为之支付的价格越高，出事\n投资回报率和投资该公司未来 10 年的利润回报率也就越低。让我们看一个例子：\n20 世纪 80 年代末，巴菲特开始以平均每股 6.50 美元的价格购买可口可乐公司\n股票，该公司的每股收益为 0.46 美元，巴菲特认为这相当于 7%的初始回报率。\n到 2007 年，可口可乐公司每股收益为 2.57 美元，巴菲特认为，可口可乐公司股\n权债券如今为他每股 6.50 美元的初始投资支付了每股 2.57 美元的回报，相当于\n39.9%的投资回报率。但如果他当初支付可口可乐公司股票的成本价为每股 21\n美元的话，他的初始投资回报率仅为 2.2%。到 2007 年，这一投资回报率也只能\n增长到 12%（$2.57÷$21=12%），这显然不如 39.9%那样具有吸引力。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,844,2073692323514028032),(2073692328459112457,'增长到 12%（$2.57÷$21=12%），这显然不如 39.9%那样具有吸引力。 \n    因此，你为一家具有持续性竞争又是的公司所支付的价格越低，那你的长期\n回报将越高。要知道，巴菲特一直都在做长线投资。然而，这些公司很少（如果\n有的话）以老派格雷厄姆主义所认为的低价出售。这就是为什么那些鼓吹价值理\n论的格雷厄姆追随者们从来未曾持有过这些优质公司的原因，因为他们觉得这些\n公司的股价太高了。 \n    那你该在什么时候买入它们呢？在熊市中开始买入。尽管相比于其他的“熊\n市便宜货”，它们的价格似乎仍然偏高，但从长远来看，它们绝对是不错的买卖。 \n    一家具有持续竞争优势的公司偶尔也可能会搞砸或做出一些愚蠢的事情，这\n在短期内将迫使其股价大跌。新可乐案例就是其中之一。巴菲特曾说过，当一家\n优质公司面临一个偶然的、可解决的困难时，一个完美的买入契机就从天而降。','2026-07-05 16:55:53.049000',0,2073692323954429952,845,2073692323514028032),(2073692328459112458,'在短期内将迫使其股价大跌。新可乐案例就是其中之一。巴菲特曾说过，当一家\n优质公司面临一个偶然的、可解决的困难时，一个完美的买入契机就从天而降。\n请注意，公司所面临的困难是可以解决的。 \n什么时候你应该与这些优质公司保持距离呢？应该是在牛市的高点。当这\n些优质公司以创历史新高的市盈率交易时，如果投资者以高价跟进的话，即使是\n一家受益于某种持续性竞争优势的公司，它也可能仅为投资者带来平庸的业绩。 \n \n \n第58章  巴菲特如何确定卖出时机 \n   在巴菲特的投资理念中，如果一个公司一直保持其竞争优势，那你就不要将\n它们卖出。道理很简单，你持有它们的时间越久，你获得的回报将越多。此外，\n如果有朝一日，你将这些绝佳的投资卖出，这就意味着你不得不邀请收税员分一\n杯羹。如果收税员分的蛋糕越多，你想成为富翁就变得比登天还难。想一想：通','2026-07-05 16:55:53.049000',0,2073692323954429952,846,2073692323514028032),(2073692328459112459,'如果有朝一日，你将这些绝佳的投资卖出，这就意味着你不得不邀请收税员分一\n杯羹。如果收税员分的蛋糕越多，你想成为富翁就变得比登天还难。想一想：通\n过投资那些具有持续性竞争优势的公司，巴菲特获得了将近 360 亿美元的资本回\n报，而到目前为止，他还从未为这些财富缴纳任何税费。而且，如果他一直坚持\n这种投资方式，他永远也不用缴税。 \n    当然，有时候你出卖一些优质公司也是有利的选择。第一种情况是当你需要\n资金投资于一个更优秀的，价格更便宜的公司时，这种机会偶然会有。 \n   第二种是当这个公司看起来将要失去其持续性竞争优势的时候。这样的情况\n会周期性地发生，例如报业和电视业就是这样。它们都曾是比较理想的行业，但\n在互联网到来之后，突然间，它们的竞争优势开始面临着威胁。竞争优势即将消\n退的公司不是你投入长期资金的宝地。 ','2026-07-05 16:55:53.049000',0,2073692323954429952,847,2073692323514028032),(2073692328459112460,'在互联网到来之后，突然间，它们的竞争优势开始面临着威胁。竞争优势即将消\n退的公司不是你投入长期资金的宝地。 \n    第三种情况发生在牛市期间。当处与疯狂购买热潮的股市将这些公司的股票\n价格推至顶峰时，股票的当前售价远远超过了其长期内在价值。一家公司的长期\n内在价值可能直线下降，而它的股价在牛市中可能攀升到惊人的天价，但最终，\n其内在价值会将股价托回到应有的水平。如果股价攀升太高，将股票出售并将这\n些收益再投入到其他投资，这其中得到的收益远远超过继续持有这家公司的股\n票。不如这样考虑：如果我们预计自己持有的公司股票在未来 20 年内能赚 1000\n万美元，而今天有人愿意支付 500 万美元投资到年复利回报率仅为 2%的项目，\n我们可能不会卖出，按照 2%的年复利回报率计算，当前投资的 500 万美元在 20\n年后，其价值仅为 740 万美元。对我们来说，这并不划算。但如果我能获得 8%','2026-07-05 16:55:53.049000',0,2073692323954429952,848,2073692323514028032),(2073692328459112461,'年后，其价值仅为 740 万美元。对我们来说，这并不划算。但如果我能获得 8%\n的年利率回报率的话，那我们手上的 500 万美元在 20 年后的价值将增长至 2300\n万美元。这样一来，出卖股票还是个不错的选择。 \n    一个简单法则：当我们看到这些优质公司达到 40 倍，甚至更高的市盈率时\n（这确实偶有发生），就到该卖出的时候了。但是，如果我们在疯狂的牛市中卖\n出了股票，不能马上将这些资金投出去，因为此时市场上所有股票的市盈率都高\n得惊人。我们能做的就是稍稍休息 \n一下，把手上的钱投资美国国债，然后静静等待。 \n    下一个熊市的到来。总会有另一个熊市在某处等着我们，让我们有机会买到\n一些廉价的、令人惊叹的、具有持续性竞争优势公司的股票。在长期的将来，我\n们将成为超级富翁。 \n    像沃伦·巴菲特一样去实现你的投资梦想吧！ \n \n \n \n \n \n \n \n \n \n \n \n \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,849,2073692323514028032),(2073692328459112462,'们将成为超级富翁。 \n    像沃伦·巴菲特一样去实现你的投资梦想吧！ \n \n \n \n \n \n \n \n \n \n \n \n \n \n                         附录 \n     具有持续性竞争优势公司的资产负债例表  \n \n \n \n \n \n \n                  资产负债表     (单位：百万美元) \n资产 \n现金和短期投资      4208 \n存货合计            2220 \n应收账款合计（净值）33517 \n预付账款            2260 \n其他流动资产合计       0 \n  \n \n负债 \n应 付 账 款           \n1380 \n预 提 费 用           \n5535 \n短 期 借 款           \n5919 \n到 期 长 期 借 款      \n133 \n其 他 流 动 负 债        ','2026-07-05 16:55:53.049000',0,2073692323954429952,850,2073692323514028032),(2073692328459112463,'5535 \n短 期 借 款           \n5919 \n到 期 长 期 借 款      \n133 \n其 他 流 动 负 债        \n258 \n \n流动资产合计        12005 \n \n \n房 产 / 厂 房 / 设 备        \n8493 \n商誉（净值）         4246 \n无形资产（净值）     7863 \n长期投资             7777 \n其他长期资产         2675 \n流 动 负 债 合 计       \n13225 \n \n \n长 期 借 款            \n3277 \n递 延 所 得 税          \n1890 \n少 数 股 东 权 益           \n其他资产                0 \n \n0 \n其 他 负 债            \n3133 \n \n负 债 合 计           ','2026-07-05 16:55:53.049000',0,2073692323954429952,851,2073692323514028032),(2073692328459112464,'其他资产                0 \n \n0 \n其 他 负 债            \n3133 \n \n负 债 合 计           \n21525 \n \n所有者权益 \n优 先 股                 \n0 \n普 通 股               \n880 \n资 本 公 积            \n7378 \n留 存 收 益           \n36235 \n普 通 国 债         \n（23375 \n其 他 权 益             \n626 \n所 有 者 权 益 总 额     \n21744 \n负债和所有者权益合计\n43269 \n \n \n资产合计            43059 \n \n \n \n \n \n                            附录 \n不具有持续性竞争优势公司的资产负债表例表 \n \n \n \n ','2026-07-05 16:55:53.049000',0,2073692323954429952,852,2073692323514028032),(2073692328459112465,' \n \n \n \n \n                            附录 \n不具有持续性竞争优势公司的资产负债表例表 \n \n \n \n \n                    资产负债表           （单位：百万美元） \n资产 \n现 金 和 短 期 投 资         \n28000 \n存 货 合 计               \n10190 \n应 收 账 款 合 计 （ 净 值 ）   \