(7600046, '{"content": "【每日语录 · 彼得·林奇】买你熟悉的股票，避开你不熟悉的。"}', 0, '每日语录推送 46', 'text', 7500046, '2025-11-01 22:53:00'),
(7600047, '{"content": "【每日语录 · 彼得·林奇】如果连一家公司的业务你都无法用一支蜡笔说清楚，那就别买。"}', 0, '每日语录推送 47', 'text', 7500047, '2024-03-28 00:34:52'),
(7600048, '{"content": "【每日语录 · 费雪】投资的最好时机是找到伟大企业时。"}', 0, '每日语录推送 48', 'text', 7500048, '2026-02-19 07:19:21'),
(7600049, '{"content": "【每日语录 · 邓普顿】在极度悲观的时候买入，在极度乐观的时候卖出。"}', 0, '每日语录推送 49', 'text', 7500049, '2025-01-17 03:32:42'),
(7600050, '{"content": "【每日语录 · 段永平】做对的事情，把事情做对。"}', 0, '每日语录推送 50', 'text', 7500050, '2025-01-16 02:43:54'),
(7600051, '{"content": "【每日语录 · 段永平】本分比聪明重要。"}', 0, '每日语录推送 51', 'text', 7500051, '2025-05-22 21:14:42'),
(7600052, '{"content": "【每日语录 · 段永平】长期视角看，好生意最终会给股东回报。"}', 0, '每日语录推送 52', 'text', 7500052, '2025-03-27 16:00:43'),
(7600053, '{"content": "【每日语录 · 林园】看得见摸得着的消费股，才是能陪你一辈子的股票。"}', 0, '每日语录推送 53', 'text', 7500053, '2025-12-26 13:52:24'),
(7600054, '{"content": "【每日语录 · 但斌】时间的玫瑰只献给坚守的人。"}', 0, '每日语录推送 54', 'text', 7500054, '2024-08-31 06:17:04'),
(7600055, '{"content": "【每日语录 · 章盟主】情绪是短线的燃料，但价值是长线的锚。"}', 0, '每日语录推送 55', 'text', 7500055, '2025-07-20 08:43:03'),
(7600056, '{"content": "【每日语录 · 李录】在中国做价值投资，需要更长的时间维度。"}', 0, '每日语录推送 56', 'text', 7500056, '2024-10-25 12:18:44'),
(7600057, '{"content": "【每日语录 · 赵丹阳】绝对收益是价值投资者的自我修养。"}', 0, '每日语录推送 57', 'text', 7500057, '2025-01-29 18:51:01'),
(7600058, '{"content": "【每日语录 · 格雷厄姆】价格是你付出的，价值才是你得到的。"}', 0, '每日语录推送 58', 'text', 7500058, '2026-03-22 04:30:03'),
(7600059, '{"content": "【每日语录 · 巴菲特】投资的第一条原则是永远不要亏损；第二条原则是永远不要忘记第一条。"}', 0, '每日语录推送 59', 'text', 7500059, '2025-01-25 17:55:53'),
(7600060, '{"content": "【每日语录 · 巴菲特】买股票就是买公司。"}', 0, '每日语录推送 60', 'text', 7500060, '2025-06-12 03:57:25');
